// ═══════════════════════════════════════════════════════════════════════════
// 🏢 [TENANT] عزل بيانات كل عميل (Multi-tenant SaaS)
// كل بيانات التطبيق تحت ledger/* تُعاد توجيهها تلقائياً إلى tenants/{tid}/ledger/*
// النطاق العام (userIndex، tenants/*/meta) يُوصَل عبر _rawRef مباشرةً.
// الحاجز الأمني الحقيقي هو قواعد قاعدة البيانات (database.rules.json) — لا الواجهة.
// ═══════════════════════════════════════════════════════════════════════════
let currentTenantId = null;
window.currentTenantId = null;
function ref(database, path) {
    if (typeof path === 'string' && currentTenantId &&
        (path === 'ledger' || path.startsWith('ledger/'))) {
        path = 'tenants/' + currentTenantId + '/' + path;
    }
    return _rawRef(database, path);
}
window.ref = ref;            // الملفات الثانوية تستخدم window.ref (الغلاف الواعي بالمستأجر)
window._rawRef = _rawRef;    // للوصول للنطاق العام عند الحاجة

// التحديثات متعددة المسارات (update(ref(db), {'ledger/..': ..})) تُكتب من الجذر، فمفاتيحها
// المطلقة لا تمر عبر غلاف ref. نعزلها هنا: أي مفتاح يبدأ بـ ledger/ يُسبَق ببادئة المستأجر.
function scopeUpdates(values) {
    if (!currentTenantId || !values || typeof values !== 'object') return values;
    const out = {};
    for (const k in values) {
        const clean = String(k).replace(/^\/+/, '');
        out[(clean === 'ledger' || clean.startsWith('ledger/')) ? ('tenants/' + currentTenantId + '/' + clean) : k] = values[k];
    }
    return out;
}
// 👁️ وضع دعم المالك (impersonation): يتصفّح المالك شركة للقراءة فقط — نمنع أي كتابة من الواجهة.
// (الخادم أصلاً يمنع كتابة المالك لعدم وجود دور له داخل الشركة؛ هذا حاجز إضافي ورسالة أوضح.)
function _blockWriteIfSupport() {
    if (!window.__impersonating) return false;
    const t = Date.now();
    if (t - (window.__roToastAt || 0) > 2500) { window.__roToastAt = t; try { toast('👁️ وضع الدعم: العرض للقراءة فقط — لا يمكن التعديل', 'er', 3000); } catch (e) { } }
    return true;
}
// غلاف update: التحديثات أحادية العقدة مفاتيحها أسماء حقول (تُترك كما هي)؛ متعددة المسارات تُعزَل.
function update(reference, values) { if (_blockWriteIfSupport()) return Promise.reject(new Error('support-readonly')); return _rawUpdate(reference, scopeUpdates(values)); }
function set(reference, value) { if (_blockWriteIfSupport()) return Promise.reject(new Error('support-readonly')); return _rawSet(reference, value); }
function remove(reference) { if (_blockWriteIfSupport()) return Promise.reject(new Error('support-readonly')); return _rawRemove(reference); }
window.update = update;
window.set = set;
window.remove = remove;
window.scopeUpdates = scopeUpdates;

