// 🛡️ تنقية أي نص قبل إدراجه في innerHTML — يمنع XSS من الحقول الحرة (ملاحظات، أسماء...)
const esc = s => String(s ?? '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
