        cmaguide: 'cmag', ifrsguide: 'ifrsg', cmaexam: 'cmaex', conaccguide: 'conaccg',
        conacccalc: 'n-conacccalc', conaccquiz: 'n-conaccquiz',
        conaccjournals: 'n-conaccjrn', conaccglossary: 'n-conaccglos',
        conaccmindmap: 'n-conaccmap', conacccontracts: 'n-conacccmp',
        subcontractors: 'n-subc', substatement: 'n-subst', subcanalytics: 'n-subcana',
        quickquiz: 'qquiz', formulas: 'formcalc', studyplan: 'studyplan', flashcards: 'flashcards', progress: 'progress',
        pomodoro: 'pomodoro', matching: 'matching', ifrsflash: 'ifrsflash',
        boq: 'boq', progressbillings: 'pb', projectdetail: 'pjd',
        auditlog: 'aud', aging: 'agn', bankrec: 'bnk', vatreturn: 'vat', incometax: 'itx', zakat: 'zakat', wht: 'wht', closing: 'closing', taxcenter: 'taxcenter', glbudget: 'glbudget', fsg: 'fsg', acctanalysis: 'acctanalysis', paymentrun: 'paymentrun', workingcapital: 'workingcapital', segmentpl: 'segmentpl', jrntemplates: 'jrntemplates',
        periodlock: 'plk', yearclosing: 'yc', warehouses: 'wh',
        prjtasks: 'pjt', empstatement: 'ems', deferredreport: 'dfr',
