// ║   📊  [DBD]   ━━━━   DASHBOARD   ━━━━                                       ║
// ║                لوحة التحكم                                                 ║
// ╚══════════════════════════════════════════════════════════════════════════╝
function renderDB() {
    if (!$('pg-dashboard').classList.contains('act')) return;
    const ta = Object.values(tr); let gD = 0, gC = 0;
    ta.forEach(t => { gD += (t.debit || 0); gC += (t.credit || 0) });
    $('k1').textContent = Object.keys(sup).length;
    $('k2').textContent = fmt(gD); $('k3').textContent = fmt(gC);
    const net = gD - gC;
    $('k4').textContent = fmt(Math.abs(net)); $('k4s').textContent = net > 0 ? 'رصيد مدين' : net < 0 ? 'رصيد دائن' : 'متوازن';
    $('k5').textContent = ta.length; $('k6').textContent = Object.keys(us).length;
    buildMC(); buildSC(); buildTS(); buildRA();
    renderDashboardAlerts();
    if (typeof renderCRMWidget === 'function') renderCRMWidget();
    if (typeof renderTreasuryWidget === 'function') renderTreasuryWidget();
}

// ── تنبيهات لوحة التحكم الذكية ─────────────
function renderDashboardAlerts() {
    const section = $('alertsSection'); if (!section) return;
    const alerts = collectAllAlerts();
    if (!alerts.length) {
        section.style.display = 'none';
        return;
    }
    section.style.display = 'block';

    // تصنيف حسب الخطورة
    const critical = alerts.filter(a => a.severity === 'critical'); // منتهي
    const urgent = alerts.filter(a => a.severity === 'urgent'); // 30 يوم
    const warning = alerts.filter(a => a.severity === 'warning'); // 90 يوم

    const totalCount = alerts.length;
    const criticalCount = critical.length;
    const urgentCount = urgent.length;

    // بطاقة ملخص + قائمة بأهم 5 تنبيهات
    const top5 = [...critical, ...urgent, ...warning].slice(0, 5);

    section.innerHTML = `
        <div style="background:linear-gradient(135deg,${criticalCount>0?'#fff5f5,#fff':urgentCount>0?'#fffaf0,#fff':'#fffde7,#fff'});border:1.5px solid ${criticalCount>0?'#fecaca':urgentCount>0?'#fed7aa':'#fef08a'};border-radius:14px;padding:18px 22px;box-shadow:0 4px 14px rgba(0,0,0,.05)">
            <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:12px;margin-bottom:14px">
                <div style="display:flex;align-items:center;gap:12px">
                    <div style="font-size:28px">${criticalCount>0?'🚨':urgentCount>0?'⚠️':'🔔'}</div>
                    <div>
                        <div style="font-size:16px;font-weight:800;color:#1a3a5c">تنبيهات تحتاج اهتمامك</div>
                        <div style="font-size:12px;color:#666;margin-top:3px">
                            ${criticalCount>0?`<span style="color:#c62828;font-weight:700">${criticalCount} منتهية</span> · `:''}
                            ${urgentCount>0?`<span style="color:#e65100;font-weight:700">${urgentCount} تنتهي خلال 30 يوم</span> · `:''}
                            ${warning.length>0?`<span style="color:#f57c00;font-weight:700">${warning.length} تنتهي خلال 90 يوم</span>`:''}
                        </div>
                    </div>
                </div>
                <button class="btn b-b" style="padding:7px 14px;font-size:12px" onclick="nav('docalerts',document.getElementById('n-da'))">📋 عرض جميع التنبيهات (${totalCount})</button>
            </div>
            <div style="display:grid;gap:8px">
                ${top5.map(a => `
                    <div style="display:flex;align-items:center;gap:12px;padding:10px 14px;background:white;border-radius:10px;border-right:4px solid ${a.color};cursor:pointer;transition:transform .15s" onmouseover="this.style.transform='translateX(-4px)'" onmouseout="this.style.transform=''" onclick="${a.action}">
                        <div style="font-size:22px">${a.icon}</div>
                        <div style="flex:1;min-width:0">
                            <div style="font-size:13px;font-weight:700;color:#1a3a5c">${a.title}</div>
                            <div style="font-size:11px;color:#666;margin-top:2px">${a.subtitle}</div>
                        </div>
                        <div style="background:${a.bg};color:${a.color};padding:5px 12px;border-radius:10px;font-size:11px;font-weight:700;white-space:nowrap">${a.label}</div>
                    </div>
                `).join('')}
            </div>
            ${totalCount > 5 ? `<div style="text-align:center;margin-top:10px;font-size:11px;color:#888">و ${totalCount - 5} تنبيه آخر — اضغط الزر أعلاه لعرض الكل</div>` : ''}
        </div>
    `;
}

// جمع كل التنبيهات من مصادرها (مستندات، إقامة، عقود)
function collectAllAlerts() {
    const alerts = [];

    // 1) تنبيهات المستندات المرفوعة في تبويب المستندات
    Object.entries(emp).forEach(([empKey, eData]) => {
        if (eData.status === 'inactive') return; // تجاهل الموظفين الموقوفين
        if (eData.documents) {
            Object.entries(eData.documents).forEach(([dk, d]) => {
                const st = docStatus(d.expiry);
                if (['expired', 'urgent', 'warning'].includes(st.code)) {
                    const days = daysUntil(d.expiry);
                    alerts.push({
                        severity: st.code === 'expired' ? 'critical' : st.code === 'urgent' ? 'urgent' : 'warning',
                        icon: (DOC_TYPE_LABELS[d.type] || '📎').split(' ')[0],
                        title: `${eData.name || 'موظف'} — ${DOC_TYPE_LABELS[d.type] || d.type}${d.name ? ' ('+d.name+')' : ''}`,
                        subtitle: `📅 تاريخ الانتهاء: ${d.expiry}${eData.dept ? ' · ' + eData.dept : ''}`,
                        label: st.code === 'expired' ? `🚨 منتهي منذ ${Math.abs(days)}ي` : `⏰ ${days}ي متبقي`,
                        color: st.color, bg: st.bg,
                        daysLeft: days,
                        action: `openDocFromAlert('${empKey}')`
                    });
                }
            });
        }

        // 2) تاريخ انتهاء الإقامة المسجل في البيانات الأساسية
        if (eData.iqamaExp) {
            const st = docStatus(eData.iqamaExp);
            if (['expired', 'urgent', 'warning'].includes(st.code)) {
                // تجنب التكرار إذا كان مرفوعاً في المستندات
                const alreadyInDocs = eData.documents && Object.values(eData.documents).some(d => d.type === 'iqama' && d.expiry === eData.iqamaExp);
                if (!alreadyInDocs) {
                    const days = daysUntil(eData.iqamaExp);
                    alerts.push({
                        severity: st.code === 'expired' ? 'critical' : st.code === 'urgent' ? 'urgent' : 'warning',
                        icon: '🆔',
                        title: `${eData.name || 'موظف'} — الإقامة`,
                        subtitle: `📅 تاريخ الانتهاء: ${eData.iqamaExp}${eData.dept ? ' · ' + eData.dept : ''}`,
                        label: st.code === 'expired' ? `🚨 منتهية منذ ${Math.abs(days)}ي` : `⏰ ${days}ي متبقي`,
                        color: st.color, bg: st.bg,
                        daysLeft: days,
                        action: `openEmpM('${empKey}')`
                    });
                }
            }
        }

        // 3) نهاية العقد (إذا كان موجوداً في الحقل)
        if (eData.contractEnd) {
            const st = docStatus(eData.contractEnd);
            if (['expired', 'urgent', 'warning'].includes(st.code)) {
                const days = daysUntil(eData.contractEnd);
                alerts.push({
                    severity: st.code === 'expired' ? 'critical' : st.code === 'urgent' ? 'urgent' : 'warning',
                    icon: '📄',
                    title: `${eData.name || 'موظف'} — عقد العمل`,
                    subtitle: `📅 تاريخ انتهاء العقد: ${eData.contractEnd}${eData.dept ? ' · ' + eData.dept : ''}`,
                    label: st.code === 'expired' ? `🚨 منتهي منذ ${Math.abs(days)}ي` : `⏰ ${days}ي متبقي`,
                    color: st.color, bg: st.bg,
                    daysLeft: days,
                    action: `openEmpM('${empKey}')`
                });
            }
        }
    });

    // 4) فواتير الموردين المتأخرة السداد
    alerts.push(...collectInvoiceAlerts());

    // 5) تجاوز موازنة المشاريع
    alerts.push(...collectBudgetAlerts());

    // 6) تنبيهات الأصول (ضمان/تأمين/صيانة دورية)
    if (typeof collectAssetAlerts === 'function') {
        collectAssetAlerts(90).forEach(al => {
            alerts.push({
                severity: al.days < 0 ? 'critical' : al.days <= 30 ? 'urgent' : 'warning',
                icon: al.icon,
                title: `${al.name || 'أصل'} — ${al.lbl}`,
                subtitle: `📅 التاريخ: ${al.date}${al.code ? ' · ' + al.code : ''}`,
                label: al.days < 0 ? `🚨 متأخر ${Math.abs(al.days)}ي` : `⏰ ${al.days}ي متبقي`,
                color: al.days < 0 ? '#c62828' : al.days <= 30 ? '#e65100' : '#f57c00',
                bg: al.days < 0 ? '#ffebee' : al.days <= 30 ? '#fff3e0' : '#fffde7',
                daysLeft: al.days,
                action: `openAssetView('${al.id}')`
            });
        });
    }

    // 7) تنبيهات الضرائب والامتثال (استقطاع، قيمة مضافة، زكاة، دخل)
    if (typeof collectTaxAlerts === 'function') alerts.push(...collectTaxAlerts());

    // ترتيب: الأخطر ثم الأقرب انتهاءً
    const severityOrder = { critical: 0, urgent: 1, warning: 2 };
    alerts.sort((a, b) => {
        const sa = severityOrder[a.severity], sb = severityOrder[b.severity];
        if (sa !== sb) return sa - sb;
        return (a.daysLeft ?? 999) - (b.daysLeft ?? 999);
    });

    return alerts;
}

// 🧮 تنبيهات الضرائب والامتثال — تُغذّي الجرس ولوحة التحكم من بيانات [ACC-TAXC]
function collectTaxAlerts() {
    const alerts = [];
    const today = new Date(); today.setHours(0, 0, 0, 0);
    const y = today.getFullYear(), m = today.getMonth(), dom = today.getDate();
    const daysTo = dt => Math.round((dt - today) / 86400000);
    const sev = days => days < 0 ? 'critical' : days <= 7 ? 'urgent' : 'warning';
    const colr = days => days < 0 ? { color: '#c62828', bg: '#ffebee' } : days <= 7 ? { color: '#e65100', bg: '#fff3e0' } : { color: '#f57c00', bg: '#fffde7' };

    // أ) ضريبة الاستقطاع غير المورّدة
    let whtUnremitted = 0, whtCount = 0;
    Object.values(window.whtRecords || {}).forEach(r => { if (r.status !== 'remitted') { whtUnremitted += parseFloat(r.wht) || 0; whtCount++; } });
    if (whtUnremitted > 0.01) {
        const due = dom <= 10 ? new Date(y, m, 10) : new Date(y, m + 1, 10);
        const days = daysTo(due); const c = colr(days);
        alerts.push({ severity: sev(days), icon: '🌐', title: `توريد ضريبة الاستقطاع — ${fmt(whtUnremitted)} ر`, subtitle: `${whtCount} عملية بانتظار التوريد · الموعد ${due.toISOString().slice(0, 10)}`, label: days < 0 ? `🚨 متأخر ${Math.abs(days)}ي` : `⏰ ${days}ي متبقي`, color: c.color, bg: c.bg, daysLeft: days, action: `nav('wht')` });
    }
    // ب) إقرار قيمة مضافة محفوظ كمسودة بحاجة اعتماد
    const vatArr = Object.values(window.vatReturns || {}).sort((a, b) => (b.to || '').localeCompare(a.to || ''));
    const vatLatest = vatArr[0];
    if (vatLatest && vatLatest.status !== 'filed' && (vatLatest.figures?.net || 0) > 0.01) {
        alerts.push({ severity: 'warning', icon: '🧾', title: `إقرار قيمة مضافة بحاجة اعتماد — ${fmt(vatLatest.figures.net)} ر`, subtitle: `الفترة: ${vatLatest.label || vatLatest.to} (مسودة)`, label: '📝 لم يُعتمد', color: '#f57c00', bg: '#fffde7', daysLeft: 30, action: `nav('vatreturn')` });
    }
    // ج) اقتراب موعد إقرار القيمة المضافة (خلال 10 أيام)
    const vatDue = new Date(y, m + 2, 0); const vatDays = daysTo(vatDue);
    if (vatDays >= 0 && vatDays <= 10) {
        const c = colr(vatDays);
        alerts.push({ severity: sev(vatDays), icon: '🧾', title: 'اقترب موعد إقرار ضريبة القيمة المضافة', subtitle: `الموعد التقديري ${vatDue.toISOString().slice(0, 10)}`, label: `⏰ ${vatDays}ي متبقي`, color: c.color, bg: c.bg, daysLeft: vatDays, action: `nav('taxcenter')` });
    }
    // د) الإقرارات السنوية (الزكاة/الدخل) — نافذة يناير حتى 30 أبريل عن السنة المنتهية
    if (m <= 3) {
        const apr30 = new Date(y, 3, 30); const days = daysTo(apr30); const c = colr(days); const fy = y - 1;
        const zFiled = Object.values(window.zakatReturns || {}).some(r => r.year === fy && r.status === 'filed');
        if (!zFiled) alerts.push({ severity: sev(days), icon: '🕌', title: `إقرار الزكاة لسنة ${fy} مستحق`, subtitle: `الموعد النهائي ${apr30.toISOString().slice(0, 10)} (خلال 120 يوم من نهاية السنة)`, label: days < 0 ? `🚨 متأخر ${Math.abs(days)}ي` : `⏰ ${days}ي متبقي`, color: c.color, bg: c.bg, daysLeft: days, action: `nav('zakat')` });
        const hasITData = Object.keys(window.incomeTaxReturns || {}).length > 0;
        const iFiled = Object.values(window.incomeTaxReturns || {}).some(r => r.year === fy && r.status === 'filed');
        if (hasITData && !iFiled) alerts.push({ severity: sev(days), icon: '💰', title: `إقرار ضريبة الدخل لسنة ${fy} مستحق`, subtitle: `الموعد النهائي ${apr30.toISOString().slice(0, 10)}`, label: days < 0 ? `🚨 متأخر ${Math.abs(days)}ي` : `⏰ ${days}ي متبقي`, color: c.color, bg: c.bg, daysLeft: days, action: `nav('incometax')` });
    }
    return alerts;
}

// تنبيهات فواتير الموردين المتأخرة السداد
function collectInvoiceAlerts() {
    const alerts = [];
    const today = new Date(); today.setHours(0, 0, 0, 0);
    Object.entries(supplierInvoices).forEach(([k, inv]) => {
        if (inv.status === 'paid' || !inv.dueDate) return;
        const due = new Date(inv.dueDate);
        const days = Math.round((due - today) / (1000 * 60 * 60 * 24));
        if (days > 7) return; // لم يحن وقت التنبيه بعد
        const severity = days < 0 ? 'critical' : days <= 3 ? 'urgent' : 'warning';
        const color = severity === 'critical' ? '#c62828' : severity === 'urgent' ? '#e65100' : '#f57c00';
        const bg = severity === 'critical' ? '#fdecea' : severity === 'urgent' ? '#fff3e0' : '#fff8e1';
        alerts.push({
            severity, icon: '🧾',
            title: `فاتورة ${inv.invoiceNumber || k} — ${inv.supplierName || 'مورد'}`,
            subtitle: `📅 تاريخ الاستحقاق: ${inv.dueDate} · المبلغ: ${fmt(inv.grandTotal || 0)}`,
            label: days < 0 ? `🚨 متأخرة ${Math.abs(days)}ي` : `⏰ تستحق بعد ${days}ي`,
            color, bg,
            daysLeft: days,
            action: `nav('invoices')`
        });
    });
    return alerts;
}

// تنبيهات تجاوز موازنة المشاريع
function collectBudgetAlerts() {
    const alerts = [];
    Object.entries(projects).forEach(([k, p]) => {
        if (p.status === 'completed' || p.status === 'cancelled') return;
        const budget = calcProjectBudget(k);
        if (!budget.totalBudget) return;
        const actual = calcProjectActualCosts(k);
        const spendPct = (actual.total / budget.totalBudget) * 100;
        if (spendPct <= 75) return;
        const severity = spendPct > 100 ? 'critical' : spendPct > 90 ? 'urgent' : 'warning';
        const color = severity === 'critical' ? '#c62828' : severity === 'urgent' ? '#e65100' : '#f57c00';
        const bg = severity === 'critical' ? '#fdecea' : severity === 'urgent' ? '#fff3e0' : '#fff8e1';
        alerts.push({
            severity, icon: '📊',
            title: `${p.name || 'مشروع'} — تجاوز الموازنة`,
            subtitle: `الصرف: ${fmt(actual.total)} من ${fmt(budget.totalBudget)} (${spendPct.toFixed(0)}%)`,
            label: `${spendPct.toFixed(0)}% من الموازنة`,
            color, bg,
            daysLeft: 100 - spendPct,
            action: `openProjectFinanceReport('${k}')`
        });
    });
    return alerts;
}

function buildMC() {
    const now = new Date(), ms = [];
    for (let i = 11; i >= 0; i--) { const d = new Date(now.getFullYear(), now.getMonth() - i, 1); ms.push({ lb: d.toLocaleString('ar-SA', { month: 'short', year: '2-digit' }), ky: d.toISOString().slice(0, 7) }) }
    const dA = ms.map(() => 0), cA = ms.map(() => 0);
    Object.values(tr).forEach(t => { const idx = ms.findIndex(m => m.ky === (t.date || '').slice(0, 7)); if (idx >= 0) { dA[idx] += (t.debit || 0); cA[idx] += (t.credit || 0) } });
    if (charts.m) charts.m.destroy();
    charts.m = new Chart($('mCh'), { type: 'bar', data: { labels: ms.map(m => m.lb), datasets: [{ label: 'مدين', data: dA, backgroundColor: 'rgba(231,76,60,.7)', borderColor: '#e74c3c', borderWidth: 2, borderRadius: 4 }, { label: 'دائن', data: cA, backgroundColor: 'rgba(39,174,96,.7)', borderColor: '#27ae60', borderWidth: 2, borderRadius: 4 }] }, options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'top' } }, scales: { y: { beginAtZero: true, ticks: { callback: v => fmt(v) } } } } });
}

function buildSC() {
    const sd = {}; Object.values(tr).forEach(t => { const sn = sup[t.supplierId]?.name || 'غير محدد'; sd[sn] = (sd[sn] || 0) + (t.debit || 0) });
    const en = Object.entries(sd).sort((a, b) => b[1] - a[1]).slice(0, 6);
    const cols = ['#3498db', '#e74c3c', '#27ae60', '#f39c12', '#8e44ad', '#1abc9c'];
    if (charts.s) charts.s.destroy();
    charts.s = new Chart($('sCh'), { type: 'doughnut', data: { labels: en.map(e => e[0]), datasets: [{ data: en.map(e => e[1]), backgroundColor: cols, borderWidth: 2 }] }, options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { font: { size: 11 } } } } } });
}

function buildTS() {
    const st = {}; Object.values(tr).forEach(t => { const k = t.supplierId; if (k) st[k] = (st[k] || 0) + (t.debit || 0) + (t.credit || 0) });
    const sr = Object.entries(st).sort((a, b) => b[1] - a[1]).slice(0, 5);
    const mx = sr[0]?.[1] || 1;
    if (!sr.length) { $('topS').innerHTML = '<div class="empty"><div class="ei">🏢</div><p>لا توجد بيانات</p></div>'; return }
    $('topS').innerHTML = sr.map(([k, v], i) => `<div class="sr-it"><div class="sr-n">${i + 1}</div><div class="sr-i"><div class="sr-nm">${sup[k]?.name || k}</div><div class="sr-bw"><div class="sr-b" style="width:${(v / mx * 100).toFixed(0)}%"></div></div></div><div class="sr-v">${fmt(v)}</div></div>`).join('');
}

function buildRA() {
    const ar = Object.entries(tr).sort((a, b) => (b[1].createdAt || b[1].date || '').localeCompare(a[1].createdAt || a[1].date || '')).slice(0, 8);
    if (!ar.length) { $('recA').innerHTML = '<div class="empty"><div class="ei">📋</div><p>لا توجد حركات</p></div>'; return }
    $('recA').innerHTML = ar.map(([, t]) => { const d = (t.debit || 0) > 0; return `<div class="ac-it"><div class="ac-d ${d ? 'db' : 'cr'}"></div><div class="ac-i"><div class="ac-dc">${t.desc || '-'}</div><div class="ac-mt">${sup[t.supplierId]?.name || '-'} | ${t.date || ''}</div></div><div class="ac-am ${d ? 'db' : 'cr'}">${d ? '+' + fmt(t.debit) : '-' + fmt(t.credit)}</div></div>` }).join('');
}

