// ║   🏢  [SUP]   ━━━━   SUPPLIERS   ━━━━                                       ║
// ║                الموردون                                                    ║
// ╚══════════════════════════════════════════════════════════════════════════╝
function fillSupDrp() {
    const fs = $('fS'), mt = $('mTS'); const pv = fs.value;
    fs.innerHTML = '<option value="">-- الجميع --</option>'; mt.innerHTML = '';
    Object.entries(sup).sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar')).forEach(([k, s]) => { fs.innerHTML += `<option value="${k}">${s.name}</option>`; mt.innerHTML += `<option value="${k}">${s.name}</option>` });
    if (pv) fs.value = pv;
}

window.openSpM = function (key = null) {
    if (!can(key ? 'edit_supplier' : 'add_supplier')) { toast('ليس لديك صلاحية', 'er'); return }
    $('mSpK').value = key || ''; $('mSpT').textContent = key ? '✏️ تعديل المورد' : '🏢 إضافة مورد جديد';
    if (key && sup[key]) { const s = sup[key]; $('mSN').value = s.name || ''; $('mSAc').value = s.account || ''; $('mSId').value = s.supId || ''; $('mSOD').value = s.openingDebit || 0; $('mSOC').value = s.openingCredit || 0; $('mSNt').value = s.notes || '' }
    else { ['mSN', 'mSAc', 'mSId', 'mSNt'].forEach(id => $(id).value = ''); $('mSOD').value = $('mSOC').value = '0' }
    ov('mSp');
};

window.saveSp = async function () {
    const nm = $('mSN').value.trim(); if (!nm) { toast('اسم المورد مطلوب', 'er'); return }
    const key = $('mSpK').value;
    const data = { name: nm, account: $('mSAc').value.trim(), supId: $('mSId').value.trim(), openingDebit: parseFloat($('mSOD').value) || 0, openingCredit: parseFloat($('mSOC').value) || 0, notes: $('mSNt').value.trim(), updatedAt: new Date().toISOString() };
    try { if (key) { await update(ref(db, `ledger/suppliers/${key}`), data); toast('تم التحديث ✓', 'ok') } else { data.createdAt = new Date().toISOString(); await push(R.sup, data); toast('تم الإضافة ✓', 'ok') } cov('mSp') }
    catch (e) { toast('خطأ: ' + e.message, 'er') }
};

window.delSp = function (key) {
    if (!can('del_supplier')) { toast('ليس لديك صلاحية', 'er'); return }
    cf2(`حذف المورد "${sup[key]?.name}"؟ ستُحذف جميع حركاته.`, async () => {
        try { const upd = {}; Object.keys(tr).forEach(tk => { if (tr[tk].supplierId === key) upd[`ledger/transactions/${tk}`] = null }); upd[`ledger/suppliers/${key}`] = null; await update(ref(db), upd); toast('تم الحذف ✓', 'ok') }
        catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

function renderSpL() {
    const pg = $('pg-suppliers'); if (!pg || !pg.classList.contains('act')) return;
    const canEdit = can('edit_supplier'), canDel = can('del_supplier'), canAdd = can('add_supplier');
    const supArr = Object.entries(sup).sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar'));

    // ── حساب بيانات كل مورد ──
    const supData = supArr.map(([k, s]) => {
        const txs = Object.values(tr).filter(t => t.supplierId === k);
        const totalDebit   = (parseFloat(s.openingDebit) || 0)  + txs.reduce((sm, t) => sm + (parseFloat(t.debit)  || 0), 0);
        const totalCredit  = (parseFloat(s.openingCredit) || 0) + txs.reduce((sm, t) => sm + (parseFloat(t.credit) || 0), 0);
        const balance      = totalCredit - totalDebit; // موجب = نحن مدينون للمورد
        const lastTx = txs.sort((a, b) => (b.date || '').localeCompare(a.date || ''))[0];
        return { k, s, txCount: txs.length, totalDebit, totalCredit, balance, lastTx };
    });

    const totalSuppliers = supArr.length;
    const totalPayable   = supData.reduce((sm, d) => sm + Math.max(0, d.balance), 0);
    const totalReceive   = supData.reduce((sm, d) => sm + Math.max(0, -d.balance), 0);
    const totalTx        = supData.reduce((sm, d) => sm + d.txCount, 0);

    // ── فلترة البحث ──
    const searchVal = $('spSearch')?.value?.toLowerCase() || '';
    const filtered  = searchVal
        ? supData.filter(d => (d.s.name || '').toLowerCase().includes(searchVal) || (d.s.account || '').toLowerCase().includes(searchVal) || (d.s.supId || '').toLowerCase().includes(searchVal))
        : supData;

    pg.innerHTML = `
    <!-- Hero -->
    <div style="background:linear-gradient(135deg,#7d4e00,#e67e22);border-radius:16px;padding:20px;margin-bottom:16px;color:white;box-shadow:0 6px 20px rgba(231,126,34,.3)">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:12px">
            <div>
                <div style="font-size:11px;opacity:.8;letter-spacing:1px;text-transform:uppercase">SUPPLIERS</div>
                <h1 style="margin:4px 0 0;font-size:24px;font-weight:900">🏢 قائمة الموردين</h1>
                <p style="margin:6px 0 0;font-size:12px;opacity:.9">إدارة بيانات الموردين وكشف الحسابات وحركة المدفوعات</p>
            </div>
            <div style="display:flex;gap:8px;flex-wrap:wrap">
                ${canAdd ? `<button class="btn" onclick="openSpM()" style="background:white;color:#7d4e00;padding:10px 18px;font-weight:800;font-size:14px">➕ إضافة مورد</button>` : ''}
                <button class="btn" onclick="exportSuppliersExcel()" style="background:rgba(255,255,255,.2);color:white;padding:10px 16px;font-weight:700;border:1.5px solid rgba(255,255,255,.4)">📤 Excel</button>
                <button class="btn" onclick="downloadSupplierTemplate()" style="background:rgba(255,255,255,.15);color:white;padding:10px 16px;font-weight:700;border:1.5px solid rgba(255,255,255,.4)" title="تحميل نموذج Excel">📥 نموذج</button>
                <label style="background:rgba(255,255,255,.15);color:white;padding:10px 16px;font-weight:700;border-radius:8px;cursor:pointer;border:1.5px solid rgba(255,255,255,.4);font-size:13px;display:flex;align-items:center">
                    📂 استيراد
                    <input type="file" accept=".xlsx,.xls" style="display:none" onchange="importSuppliersExcel(this.files[0]);this.value=''">
                </label>
            </div>
        </div>
    </div>

    <!-- KPIs -->
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(175px,1fr));gap:10px;margin-bottom:16px">
        <div style="background:white;border-radius:12px;padding:13px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid #1a3a5c">
            <div style="font-size:10px;color:#666;font-weight:600">🏢 إجمالي الموردين</div>
            <div style="font-size:26px;font-weight:900;color:#1a3a5c;margin:4px 0">${totalSuppliers}</div>
            <div style="font-size:11px;color:#888">${totalTx} حركة مالية</div>
        </div>
        <div style="background:#fff8f0;border-radius:12px;padding:13px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid #e67e22">
            <div style="font-size:10px;color:#7d4e00;font-weight:600">💸 إجمالي المستحق للموردين</div>
            <div style="font-size:20px;font-weight:900;color:#e67e22;margin:4px 0">${fmt(totalPayable)}</div>
            <div style="font-size:11px;color:#888">ذمم دائنة</div>
        </div>
        <div style="background:#e8f8f5;border-radius:12px;padding:13px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid #27ae60">
            <div style="font-size:10px;color:#0e6655;font-weight:600">💰 المستحق لنا من الموردين</div>
            <div style="font-size:20px;font-weight:900;color:#27ae60;margin:4px 0">${fmt(totalReceive)}</div>
            <div style="font-size:11px;color:#888">ذمم مدينة</div>
        </div>
        <div style="background:white;border-radius:12px;padding:13px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid #8e44ad">
            <div style="font-size:10px;color:#5b2c6f;font-weight:600">📊 الصافي (مدين - دائن)</div>
            <div style="font-size:20px;font-weight:900;color:${totalPayable > totalReceive ? '#e67e22' : '#27ae60'};margin:4px 0">${fmt(Math.abs(totalPayable - totalReceive))}</div>
            <div style="font-size:11px;color:#888">${totalPayable > totalReceive ? 'لصالح الموردين' : 'لصالح الشركة'}</div>
        </div>
    </div>

    <!-- قائمة الموردين -->
    <div class="card">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;flex-wrap:wrap;gap:8px">
            <div style="font-size:14px;font-weight:800;color:#1a3a5c">🏢 قائمة الموردين (${supArr.length})</div>
            <input type="text" id="spSearch" placeholder="🔍 ابحث بالاسم، رقم الحساب، المعرّف..." oninput="renderSpL()"
                style="padding:8px 14px;border:1.5px solid #d0d7e0;border-radius:8px;font-family:inherit;font-size:12px;min-width:280px">
        </div>

        ${!supArr.length ? `
        <div style="text-align:center;padding:60px 20px">
            <div style="font-size:70px;margin-bottom:14px">🏢</div>
            <div style="font-size:16px;font-weight:800;color:#888;margin-bottom:8px">لا يوجد موردون بعد</div>
            <div style="font-size:13px;color:#aaa;margin-bottom:18px">أضف موردين لتتبع المدفوعات والأرصدة</div>
            ${canAdd ? `<button class="btn b-g" onclick="openSpM()" style="padding:12px 24px;font-size:14px">➕ إضافة مورد</button>` : ''}
        </div>` : `
        <div style="overflow-x:auto">
            <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:900px">
                <thead style="background:#1a3a5c;color:white">
                    <tr>
                        <th style="padding:10px 8px;text-align:right">#</th>
                        <th style="padding:10px 8px;text-align:right">🏢 اسم المورد</th>
                        <th style="padding:10px 8px;text-align:right">📂 رقم الحساب</th>
                        <th style="padding:10px 8px;text-align:right">🆔 المعرّف</th>
                        <th style="padding:10px 8px;text-align:center">📊 الحركات</th>
                        <th style="padding:10px 8px;text-align:left">مدين</th>
                        <th style="padding:10px 8px;text-align:left">دائن</th>
                        <th style="padding:10px 8px;text-align:left">💵 الرصيد الحالي</th>
                        <th style="padding:10px 8px;text-align:center">⚙️ إجراءات</th>
                    </tr>
                </thead>
                <tbody>
                ${filtered.map((d, i) => {
                    const { k, s, txCount, totalDebit, totalCredit, balance } = d;
                    const balColor = balance > 0 ? '#e67e22' : balance < 0 ? '#27ae60' : '#888';
                    const balLabel = balance > 0 ? `(دائن)` : balance < 0 ? `(مدين)` : '';
                    return `<tr style="border-bottom:1px solid #f0f0f0;${i % 2 ? 'background:#fafbfc' : ''}" data-sp-search="${esc((s.name||'').toLowerCase())} ${esc((s.account||'').toLowerCase())} ${esc((s.supId||'').toLowerCase())}">
                        <td style="padding:10px 8px;color:#888;font-weight:600">${i + 1}</td>
                        <td style="padding:10px 8px">
                            <div style="font-weight:700;color:#1a3a5c">${esc(s.name) || '—'}</div>
                            ${s.notes ? `<div style="font-size:10px;color:#999;margin-top:2px">${esc(s.notes.substring(0, 40))}</div>` : ''}
                        </td>
                        <td style="padding:10px 8px;color:#555">${esc(s.account) || '—'}</td>
                        <td style="padding:10px 8px;color:#555">${esc(s.supId) || '—'}</td>
                        <td style="padding:10px 8px;text-align:center">
                            <span style="background:#e8f4fd;color:#1a5276;padding:3px 10px;border-radius:10px;font-size:11px;font-weight:700;cursor:pointer" onclick="$('fS').value='${k}';renderSt();bcNav('statement')" title="عرض كشف الحساب">
                                ${txCount} حركة
                            </span>
                        </td>
                        <td style="padding:10px 8px;color:#c0392b;font-weight:600;text-align:left">${totalDebit > 0 ? fmt(totalDebit) : '—'}</td>
                        <td style="padding:10px 8px;color:#27ae60;font-weight:600;text-align:left">${totalCredit > 0 ? fmt(totalCredit) : '—'}</td>
                        <td style="padding:10px 8px;text-align:left">
                            <span style="font-weight:800;color:${balColor}">${fmt(Math.abs(balance))}</span>
                            <span style="font-size:10px;color:${balColor};margin-right:3px">${balLabel}</span>
                        </td>
                        <td style="padding:8px;text-align:center">
                            <div style="display:flex;gap:4px;justify-content:center">
                                <button onclick="$('fS').value='${k}';renderSt();bcNav('statement')" style="background:#2d6a9f;color:white;border:none;border-radius:6px;padding:5px 9px;cursor:pointer;font-size:11px" title="كشف الحساب">📋</button>
                                ${canEdit ? `<button onclick="openTrM()" style="background:#27ae60;color:white;border:none;border-radius:6px;padding:5px 9px;cursor:pointer;font-size:11px" title="إضافة حركة">➕</button>` : ''}
                                ${canEdit ? `<button onclick="openSpM('${k}')" style="background:#f39c12;color:white;border:none;border-radius:6px;padding:5px 9px;cursor:pointer;font-size:11px" title="تعديل">✏️</button>` : ''}
                                ${canDel  ? `<button onclick="delSp('${k}')" style="background:#e74c3c;color:white;border:none;border-radius:6px;padding:5px 9px;cursor:pointer;font-size:11px" title="حذف">🗑️</button>` : ''}
                            </div>
                        </td>
                    </tr>`;
                }).join('')}
                ${filtered.length === 0 ? `<tr><td colspan="9" style="text-align:center;padding:30px;color:#aaa">لا توجد نتائج مطابقة للبحث</td></tr>` : ''}
                </tbody>
                <tfoot style="background:#f0f5fa">
                    <tr>
                        <td colspan="5" style="padding:10px 8px;font-weight:800;color:#1a3a5c">الإجمالي</td>
                        <td style="padding:10px 8px;font-weight:800;color:#c0392b;text-align:left">${fmt(supData.reduce((s, d) => s + d.totalDebit, 0))}</td>
                        <td style="padding:10px 8px;font-weight:800;color:#27ae60;text-align:left">${fmt(supData.reduce((s, d) => s + d.totalCredit, 0))}</td>
                        <td style="padding:10px 8px;font-weight:800;color:#e67e22;text-align:left">${fmt(totalPayable)} <small style="font-size:10px">(دائن)</small></td>
                        <td></td>
                    </tr>
                </tfoot>
            </table>
        </div>`}
    </div>`;
}

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   💱  [TRX]   ━━━━   TRANSACTIONS   ━━━━                                    ║
// ║                الحركات المالية                                             ║
// ╚══════════════════════════════════════════════════════════════════════════╝
window.openTrM = function (key = null) {
    if (!can(key ? 'edit_transaction' : 'add_transaction')) { toast('ليس لديك صلاحية', 'er'); return }
    if (!Object.keys(sup).length) { toast('أضف موردًا أولًا', 'wn'); return }
    fillSupDrp(); $('mTrK').value = key || ''; $('mTrT').textContent = key ? '✏️ تعديل الحركة' : '➕ إضافة حركة جديدة';
    // 🎯 قوائم مركز التكلفة والمشروع للحركة
    const tCc = (key && tr[key]) ? (tr[key].costCenter || '') : '';
    const tPj = (key && tr[key]) ? (tr[key].projectId || '') : '';
    if ($('mTCc')) $('mTCc').innerHTML = (typeof window.ccOnlyOptions === 'function') ? window.ccOnlyOptions(tCc, '— بدون —') : '<option value="">— بدون —</option>';
    if ($('mTPj')) $('mTPj').innerHTML = (typeof window.projOnlyOptions === 'function') ? window.projOnlyOptions(tPj, '— بدون —') : '<option value="">— بدون —</option>';
    if (key && tr[key]) { const t = tr[key]; $('mTS').value = t.supplierId || ''; $('mTD').value = t.date || today(); $('mTE').value = t.entry || ''; $('mTR').value = t.ref || ''; $('mTEm').value = t.employee || ''; $('mTDes').value = t.desc || ''; $('mTTg').value = t.tags || '-'; $('mTDb').value = t.debit || 0; $('mTCr').value = t.credit || 0 }
    else { $('mTD').value = today();['mTE', 'mTR', 'mTEm', 'mTDes'].forEach(id => $(id).value = ''); $('mTTg').value = '-'; $('mTDb').value = $('mTCr').value = '0' }
    ov('mTr');
};

window.saveTr = async function () {
    const sId = $('mTS').value, dt = $('mTD').value, ds = $('mTDes').value.trim();
    const db2 = parseFloat($('mTDb').value) || 0, cr = parseFloat($('mTCr').value) || 0;
    if (!sId) { toast('اختر المورد', 'er'); return } if (!dt) { toast('التاريخ مطلوب', 'er'); return }
    if (!ds) { toast('الوصف مطلوب', 'er'); return } if (!db2 && !cr) { toast('أدخل قيمة مدين أو دائن', 'er'); return }
    const key = $('mTrK').value;
    const data = { supplierId: sId, date: dt, entry: $('mTE').value.trim(), ref: $('mTR').value.trim(), employee: $('mTEm').value.trim() || myP?.name || '', desc: ds, tags: $('mTTg').value.trim() || '-', costCenter: $('mTCc')?.value || '', projectId: $('mTPj')?.value || '', debit: db2, credit: cr, updatedAt: new Date().toISOString(), updatedBy: curU?.uid || '' };
    try { if (key) { await update(ref(db, `ledger/transactions/${key}`), data); toast('تم التحديث ✓', 'ok') } else { data.createdAt = new Date().toISOString(); data.createdBy = curU?.uid || ''; await push(R.tr, data); toast('تم الإضافة ✓', 'ok') } cov('mTr') }
    catch (e) { toast('خطأ: ' + e.message, 'er') }
};

window.delTr = function (key) {
    if (!can('del_transaction')) { toast('ليس لديك صلاحية', 'er'); return }
    cf2('حذف هذه الحركة؟', async () => { try { await remove(ref(db, `ledger/transactions/${key}`)); toast('تم الحذف ✓', 'ok') } catch (e) { toast('خطأ: ' + e.message, 'er') } });
};

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   📋  [STM]   ━━━━   STATEMENT   ━━━━                                       ║
// ║                كشف الحساب                                                  ║
// ╚══════════════════════════════════════════════════════════════════════════╝
window.renderSt = function () {
    if (!$('pg-statement').classList.contains('act')) return;
    // 🎯 تعبئة فلتري مركز التكلفة والمشروع (مع الحفاظ على الاختيار الحالي)
    const fCcEl = $('fCc'), fPjEl = $('fPj');
    if (fCcEl && typeof window.ccOnlyOptions === 'function') { const v = fCcEl.value; fCcEl.innerHTML = window.ccOnlyOptions(v, '-- الجميع --'); }
    if (fPjEl && typeof window.projOnlyOptions === 'function') { const v = fPjEl.value; fPjEl.innerHTML = window.projOnlyOptions(v, '-- الجميع --'); }
    const fCc = fCcEl?.value || '', fPj = fPjEl?.value || '';
    const fS = $('fS').value, fF = $('fFr').value, fT = $('fTo').value, fD = $('fDe').value.toLowerCase(), cur = cfg.currency || 'SAR';
    const sks = fS ? (sup[fS] ? [fS] : []) : Object.keys(sup);
    $('ph1').textContent = `من ${fF || '---'} إلى ${fT || '---'}`; $('ph2').textContent = cfg.companyAr;
    if (!sks.length) { $('stW').innerHTML = '<div class="empty"><div class="ei">📂</div><p>لا توجد بيانات</p></div>'; updS(0, 0, 0, 0, 0); return }
    let gD = 0, gC = 0, gBD = 0, gBC = 0, tot = 0;
    let h = `<table class="st"><thead><tr class="h1"><th>رقم</th><th>رقم القيد</th><th>رقم التحويل</th><th>التاريخ</th><th>موظف</th><th>الوصف</th><th>وسوم</th><th colspan="2">العملية</th><th colspan="2">الرصيد</th><th class="no-p">إجراءات</th></tr><tr class="h2"><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th>مدين(${cur})</th><th>دائن(${cur})</th><th>مدين(${cur})</th><th>دائن(${cur})</th><th class="no-p"></th></tr></thead><tbody>`;
    sks.filter(k => sup[k]).sort((a, b) => (sup[a].name || '').localeCompare(sup[b].name || '', 'ar')).forEach(sk => {
        const s = sup[sk];
        const txs = Object.entries(tr).filter(([, t]) => { if (t.supplierId !== sk) return false; if (fF && t.date < fF) return false; if (fT && t.date > fT) return false; if (fD && !(t.desc || '').toLowerCase().includes(fD)) return false; if (fCc && (t.costCenter || '') !== fCc) return false; if (fPj && (t.projectId || '') !== fPj) return false; return true }).sort((a, b) => (a[1].date || '').localeCompare(b[1].date || ''));
        h += `<tr class="tr-sp"><td colspan="12" style="text-align:right">${esc(s.name)}${s.account ? ` <span style="opacity:.65;font-size:11px">(${esc(s.account)})</span>` : ''}</td></tr>`;
        h += `<tr class="tr-op"><td colspan="7" style="text-align:right;padding-right:14px">الرصيد قبل</td><td>${fmt(s.openingDebit || 0)}</td><td>${fmt(s.openingCredit || 0)}</td><td colspan="3"></td></tr>`;
        let rD = s.openingDebit || 0, rC = s.openingCredit || 0, rN = 0;
        txs.forEach(([tk, t]) => {
            rN++; tot++; gD += (t.debit || 0); gC += (t.credit || 0);
            const net = (rD + (t.debit || 0)) - (rC + (t.credit || 0)); rD = net >= 0 ? net : 0; rC = net < 0 ? -net : 0;
            h += `<tr><td>${rN}</td><td>${esc(t.entry) || '-'}</td><td>${esc(t.ref) || '-'}</td><td style="white-space:nowrap">${esc(t.date) || ''}</td><td style="white-space:nowrap;font-size:11px">${esc(t.employee) || '-'}</td><td class="td-dc">${esc(t.desc) || ''}${(t.costCenter || t.projectId) ? `<div style="font-size:10px;color:#8e44ad;margin-top:2px">${t.costCenter && window.ccDisplayName ? '🎯 ' + esc(ccDisplayName(t.costCenter)) : ''} ${t.projectId && window.ccDisplayName ? '🏗️ ' + esc(ccDisplayName(t.projectId)) : ''}</div>` : ''}</td><td>${esc(t.tags) || '-'}</td><td class="${(t.debit || 0) > 0 ? 'td-db' : ''}">${(t.debit || 0) > 0 ? fmt(t.debit) : ''}</td><td class="${(t.credit || 0) > 0 ? 'td-cr' : ''}">${(t.credit || 0) > 0 ? fmt(t.credit) : ''}</td><td class="td-n">${fmt(rD)}</td><td class="td-n">${fmt(rC)}</td><td class="no-p"><div class="ab">${can('edit_transaction') ? `<button class="bx bx-e" onclick="openTrM('${tk}')">✏️</button>` : ''} ${can('del_transaction') ? `<button class="bx bx-d" onclick="delTr('${tk}')">🗑️</button>` : ''}</div></td></tr>`;
        });
        if (!txs.length) h += `<tr><td colspan="12" style="text-align:center;color:#bbb;padding:14px">لا توجد حركات</td></tr>`;
        gBD += rD; gBC += rC;
        h += `<tr class="tr-tt"><td colspan="7" style="text-align:right">المجموع</td><td class="td-db">${fmt(gD)}</td><td class="td-cr">${fmt(gC)}</td><td class="td-n">${fmt(rD)}</td><td class="td-n">${fmt(rC)}</td><td class="no-p"></td></tr>`;
    });
    h += `<tr class="tr-gd"><td colspan="7" style="text-align:right">الإجمالي (${cur})</td><td>${fmt(gD)}</td><td>${fmt(gC)}</td><td>${fmt(gBD)}</td><td>${fmt(gBC)}</td><td class="no-p"></td></tr></tbody></table>`;
    $('stW').innerHTML = h; $('rB').textContent = tot; updS(tot, gD, gC, gBD, gBC);
};

function updS(r, d, c, bd, bc) { $('s0').textContent = r; $('s1').textContent = fmt(d); $('s2').textContent = fmt(c); $('s3').textContent = fmt(bd); $('s4').textContent = fmt(bc) }
window.rstF = () => { $('fS').value = $('fFr').value = $('fTo').value = $('fDe').value = ''; if ($('fCc')) $('fCc').value = ''; if ($('fPj')) $('fPj').value = ''; renderSt() };

// ── تصدير الموردين Excel ──────────────────────────────────────────────────
window.exportSuppliersExcel = function () {
    const supArr = Object.entries(sup);
    if (!supArr.length) { toast('لا يوجد موردون', 'er'); return; }
    const rows = supArr.map(([k, s]) => {
        const txs = Object.values(tr).filter(t => t.supplierId === k);
        const td = (parseFloat(s.openingDebit)||0) + txs.reduce((sm, t) => sm + (parseFloat(t.debit)||0), 0);
        const tc = (parseFloat(s.openingCredit)||0) + txs.reduce((sm, t) => sm + (parseFloat(t.credit)||0), 0);
        return { 'اسم المورد': s.name||'', 'رقم الحساب': s.account||'', 'رقم التعريف': s.supId||'',
            'رصيد مدين افتتاحي': s.openingDebit||0, 'رصيد دائن افتتاحي': s.openingCredit||0,
            'إجمالي المدين': td, 'إجمالي الدائن': tc, 'الرصيد الحالي': tc - td,
            'عدد الحركات': txs.length, 'ملاحظات': s.notes||'' };
    });
    try {
        const ws = XLSX.utils.json_to_sheet(rows);
        ws['!cols'] = Array(10).fill({ wch: 16 });
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'الموردون');
        XLSX.writeFile(wb, `الموردون_${new Date().toISOString().substring(0,10)}.xlsx`);
        toast('✅ تم التصدير', 'ok');
    } catch (e) { toast('❌ ' + e.message, 'er'); }
};

// ── تحميل نموذج Excel للموردين (نظام المشتريات القديم) ──────────────────
window.downloadSupplierTemplate = function () {
    const headers = ['اسم المورد *', 'رقم الحساب', 'رقم التعريف', 'رصيد مدين افتتاحي', 'رصيد دائن افتتاحي', 'ملاحظات'];
    const sample  = ['شركة المثال للمقاولات', '1010', 'SP-001', '0', '50000', 'مورد رئيسي'];
    const ws = XLSX.utils.aoa_to_sheet([headers, sample]);
    ws['!cols'] = [28, 16, 14, 18, 18, 22].map(w => ({ wch: w }));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'الموردون');
    XLSX.writeFile(wb, `نموذج_استيراد_الموردين_مشتريات.xlsx`);
    toast('✅ تم تحميل نموذج الموردين', 'ok', 4000);
};

// ── استيراد الموردين من Excel (نظام المشتريات القديم) ───────────────────
window.importSuppliersExcel = async function (file) {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (e) => {
        try {
            const wb = XLSX.read(e.target.result, { type: 'array' });
            const ws = wb.Sheets[wb.SheetNames[0]];
            const rows = XLSX.utils.sheet_to_json(ws, { defval: '' });
            if (!rows.length) { toast('الملف فارغ', 'er'); return; }
            let added = 0, skipped = 0;
            const now = new Date().toISOString();
            for (const row of rows) {
                const name = String(row['اسم المورد *'] || row['اسم المورد'] || '').trim();
                if (!name) { skipped++; continue; }
                const data = {
                    name,
                    account: String(row['رقم الحساب'] || '').trim(),
                    supId: String(row['رقم التعريف'] || '').trim(),
                    openingDebit:  parseFloat(row['رصيد مدين افتتاحي']  || 0) || 0,
                    openingCredit: parseFloat(row['رصيد دائن افتتاحي'] || 0) || 0,
                    notes: String(row['ملاحظات'] || '').trim(),
                    createdAt: now, updatedAt: now
                };
                try { await push(R.sup, data); added++; } catch (err) { skipped++; }
            }
            toast(`✅ تم الاستيراد: ${added} مورد مضاف${skipped ? `، ${skipped} متجاهَل` : ''}`, 'ok', 6000);
        } catch (err) { toast('❌ خطأ: ' + err.message, 'er'); }
    };
    reader.readAsArrayBuffer(file);
};

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🤝  كشف حساب العملاء — Customer Account Statement                      ║
// ╚══════════════════════════════════════════════════════════════════════════╝
window._cstState = { custId: '', from: '', to: '', search: '', projectId: '' };

// هل يخص السند المشروع؟ (مباشرة أو عبر الفاتورة المرتبطة)
function cstRcptMatchesProj(r, pid) {
    if (!pid) return true;
    if (r.projectId === pid) return true;
    const inv = (window.salesInvoices || {})[r.invoiceKey || r.salesInvoiceKey || ''];
    return !!inv && inv.projectId === pid;
}

window.renderCustStatement = function () {
    const pg = $('pg-custstatement'); if (!pg || !pg.classList.contains('act')) return;
    const customers = window.customers || {};
    const salesInvoices = window.salesInvoices || {};
    const receipts_ = window.receipts || {};
    const { custId, from, to, search, projectId: cstPid } = window._cstState;

    // بناء قائمة العملاء للفلتر
    const custList = Object.entries(customers).sort((a, b) => (a[1].nameAr || '').localeCompare(b[1].nameAr || '', 'ar'));

    // اختيار العملاء المطلوبين
    const selectedCusts = custId ? (customers[custId] ? [[custId, customers[custId]]] : []) : custList;

    let totalInvoiced = 0, totalReceived = 0, totalBalance = 0, grandRows = 0;

    const rows = selectedCusts.map(([cid, c]) => {
        // ── فقط الفواتير المرحّلة أو المدفوعة (لا مسودات ولا ملغاة) ──
        const allInvAll = Object.entries(salesInvoices)
            .filter(([, inv]) => inv.customerId === cid && (inv.status === 'posted' || inv.status === 'paid'))
            .filter(([, inv]) => !cstPid || inv.projectId === cstPid)
            .sort((a, b) => (a[1].date || '').localeCompare(b[1].date || ''));

        const allRcptAll = Object.entries(receipts_)
            .filter(([, r]) => (r.customerId === cid || r.partyId === cid) && r.status !== 'cancelled')
            .filter(([, r]) => cstRcptMatchesProj(r, cstPid))
            .sort((a, b) => (a[1].date || '').localeCompare(b[1].date || ''));

        // ── حساب الرصيد السابق قبل تاريخ البدء ──
        // عند التصفية بمشروع لا يُحتسب الرصيد الافتتاحي العام للعميل (غير مرتبط بمشروع)
        const openingBalance = cstPid ? 0 : (parseFloat(c.openingBalance) || 0);
        let carriedForward = openingBalance;
        if (from) {
            allInvAll.forEach(([, inv]) => {
                if ((inv.date || '') < from) carriedForward += parseFloat(inv.grandTotal) || 0;
            });
            allRcptAll.forEach(([, r]) => {
                if ((r.date || '') < from) carriedForward -= parseFloat(r.amount) || 0;
            });
        }

        // ── تصفية الحركات بالفترة والبحث ──
        const invEntries = allInvAll.filter(([, inv]) =>
            (!from || (inv.date || '') >= from) && (!to || (inv.date || '') <= to)
            && (!search || (inv.number || '').toLowerCase().includes(search) || (inv.subject || '').toLowerCase().includes(search)));

        const rcptEntries = allRcptAll.filter(([, r]) =>
            (!from || (r.date || '') >= from) && (!to || (r.date || '') <= to)
            && (!search || (r.number || '').toLowerCase().includes(search)));

        if (!invEntries.length && !rcptEntries.length && !carriedForward && !custId) return '';

        let balance = carriedForward;
        let custTotalDr = 0, custTotalCr = 0;

        // دمج وترتيب الحركات بالتاريخ
        const allEntries = [
            ...invEntries.map(([k, inv]) => ({
                date: inv.date,
                type: inv.billingKey ? 'billing-invoice' : 'invoice',
                ref: inv.number,
                desc: inv.subject || `فاتورة ${inv.number}`,
                debit: parseFloat(inv.grandTotal) || 0, credit: 0, key: k,
                billingKey: inv.billingKey || null
            })),
            ...rcptEntries.map(([k, r]) => ({
                date: r.date, type: 'receipt', ref: r.number || r.receiptNumber || '',
                desc: r.description || `سند قبض`,
                debit: 0, credit: parseFloat(r.amount) || 0, key: k
            }))
        ].sort((a, b) => (a.date || '').localeCompare(b.date || ''));

        if (!allEntries.length && !openingBalance && custId !== cid) return '';

        grandRows += allEntries.length;
        let rowsHtml = allEntries.map((e, i) => {
            balance += e.debit - e.credit;
            custTotalDr += e.debit;
            custTotalCr += e.credit;
            const balColor = balance > 0 ? '#c0392b' : balance < 0 ? '#27ae60' : '#888';
            // رابط قابل للنقر حسب النوع
            const refLink = e.type === 'receipt'
                ? `<span onclick="viewVoucher && viewVoucher('${e.key}','receipt')" style="color:#16a085;cursor:pointer;font-weight:700;text-decoration:underline;white-space:nowrap" title="عرض سند القبض">
                      💵 ${e.ref || '—'}
                   </span>`
                : e.type === 'billing-invoice'
                ? `<div style="display:flex;align-items:center;gap:5px">
                      <span onclick="viewSInv && viewSInv('${e.key}')" style="color:#2d6a9f;cursor:pointer;font-weight:700;text-decoration:underline;white-space:nowrap" title="عرض الفاتورة">🧾 ${e.ref || '—'}</span>
                      <span style="background:#8e44ad;color:white;font-size:9px;padding:1px 6px;border-radius:5px;font-weight:700;white-space:nowrap">مستخلص</span>
                   </div>`
                : `<span onclick="viewSInv && viewSInv('${e.key}')" style="color:#2d6a9f;cursor:pointer;font-weight:700;text-decoration:underline;white-space:nowrap" title="عرض الفاتورة">
                      🧾 ${e.ref || '—'}
                   </span>`;
            return `<tr style="${i % 2 ? 'background:#fafbfc' : ''}">
                <td style="color:#888;padding:8px">${i + 1}</td>
                <td style="white-space:nowrap;padding:8px">${e.date || '—'}</td>
                <td style="padding:8px">${refLink}</td>
                <td style="padding:8px;max-width:200px;color:#444">${e.desc}</td>
                <td style="padding:8px;color:#c0392b;font-weight:700;text-align:left">${e.debit > 0 ? fmt(e.debit) : ''}</td>
                <td style="padding:8px;color:#27ae60;font-weight:700;text-align:left">${e.credit > 0 ? fmt(e.credit) : ''}</td>
                <td style="padding:8px;font-weight:700;color:${balColor};text-align:left">${fmt(Math.abs(balance))} <small style="font-size:10px">${balance > 0 ? 'مدين' : balance < 0 ? 'دائن' : ''}</small></td>
            </tr>`;
        }).join('');

        totalInvoiced += custTotalDr;
        totalReceived += custTotalCr;
        totalBalance += balance;

        return `
        <div style="border:1.5px solid #e0e8f0;border-radius:10px;overflow:hidden;margin-bottom:14px">
            <!-- رأس العميل -->
            <div style="background:linear-gradient(135deg,#1a3a5c,#2d6a9f);color:white;padding:10px 16px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
                <div>
                    <div style="font-size:14px;font-weight:800">🤝 ${c.nameAr || '—'}</div>
                    <div style="font-size:11px;opacity:.8;margin-top:2px">${c.code || ''} ${c.phone ? '· ' + c.phone : ''} ${c.vatNumber ? '· ضريبي: ' + c.vatNumber : ''}</div>
                </div>
                <div style="display:flex;gap:12px;text-align:center">
                    <div><div style="font-size:10px;opacity:.75">رصيد افتتاحي</div><div style="font-weight:800">${fmt(openingBalance)}</div></div>
                    <div><div style="font-size:10px;opacity:.75">إجمالي الفواتير</div><div style="font-weight:800;color:#f9ca74">${fmt(custTotalDr)}</div></div>
                    <div><div style="font-size:10px;opacity:.75">إجمالي المحصَّل</div><div style="font-weight:800;color:#7dcea0">${fmt(custTotalCr)}</div></div>
                    <div style="background:rgba(255,255,255,.15);padding:4px 10px;border-radius:8px"><div style="font-size:10px;opacity:.8">الرصيد</div><div style="font-weight:900;font-size:15px">${fmt(Math.abs(balance))} ${balance > 0 ? '🔴' : balance < 0 ? '🟢' : '✅'}</div></div>
                </div>
            </div>
            <!-- جدول الحركات -->
            ${allEntries.length === 0
                ? `<div style="padding:16px;text-align:center;color:#aaa">لا توجد حركات في هذه الفترة${openingBalance ? ` — رصيد افتتاحي: ${fmt(openingBalance)}` : ''}</div>`
                : `<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px">
                    <thead>
                        <tr style="background:#f0f5fa">
                            <th style="padding:8px;text-align:right;border-bottom:2px solid #e0e8f0">#</th>
                            <th style="padding:8px;text-align:right;border-bottom:2px solid #e0e8f0">التاريخ</th>
                            <th style="padding:8px;text-align:right;border-bottom:2px solid #e0e8f0">المرجع</th>
                            <th style="padding:8px;text-align:right;border-bottom:2px solid #e0e8f0">البيان</th>
                            <th style="padding:8px;text-align:left;border-bottom:2px solid #e0e8f0;color:#c0392b">مدين</th>
                            <th style="padding:8px;text-align:left;border-bottom:2px solid #e0e8f0;color:#27ae60">دائن</th>
                            <th style="padding:8px;text-align:left;border-bottom:2px solid #e0e8f0">الرصيد</th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr style="background:#fff8f0">
                            <td colspan="3" style="padding:8px 10px;font-size:11px;color:#7d4e00;font-weight:700">${from ? `الرصيد المرحّل (قبل ${from})` : 'الرصيد الافتتاحي'}</td>
                            <td style="padding:8px;font-size:11px;color:#888">${from && carriedForward !== openingBalance ? `يشمل رصيد افتتاحي ${fmt(openingBalance)}` : ''}</td>
                            <td style="padding:8px;font-weight:700;color:${carriedForward > 0 ? '#c0392b' : '#27ae60'};text-align:left">${carriedForward > 0 ? fmt(carriedForward) : ''}</td>
                            <td style="padding:8px;font-weight:700;color:${carriedForward < 0 ? '#27ae60' : ''};text-align:left">${carriedForward < 0 ? fmt(Math.abs(carriedForward)) : ''}</td>
                            <td style="padding:8px;font-weight:800;text-align:left">${fmt(Math.abs(carriedForward))} <small style="font-size:10px">${carriedForward > 0 ? 'مدين' : carriedForward < 0 ? 'دائن' : ''}</small></td>
                        </tr>
                        ${rowsHtml}
                        <tr style="background:#f0f5fa;font-weight:800">
                            <td colspan="4" style="padding:8px 10px;color:#1a3a5c">المجموع</td>
                            <td style="color:#c0392b">${fmt(custTotalDr)}</td>
                            <td style="color:#27ae60">${fmt(custTotalCr)}</td>
                            <td style="color:${balance > 0 ? '#c0392b' : '#27ae60'}">${fmt(Math.abs(balance))} ${balance > 0 ? '(مدين)' : '(دائن)'}</td>
                        </tr>
                    </tbody>
                </table></div>`}
        </div>`;
    }).join('');

    pg.innerHTML = `
    <!-- رأس الصفحة -->
    <div style="background:linear-gradient(135deg,#0e6655,#16a085);color:white;border-radius:14px;padding:18px 22px;margin-bottom:16px">
        <div style="font-size:20px;font-weight:900;margin-bottom:4px">📋 كشف حساب العملاء</div>
        <div style="font-size:12px;opacity:.85">يعرض الفواتير المرحّلة وسندات القبض فقط — المسودات والمستخلصات غير المرحّلة مستثناة</div>
    </div>

    <!-- KPIs -->
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:10px;margin-bottom:14px">
        <div style="background:white;border-radius:10px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.05);border-right:4px solid #c0392b">
            <div style="font-size:10px;color:#666;font-weight:600">🧾 إجمالي الفواتير</div>
            <div style="font-size:18px;font-weight:900;color:#c0392b;margin:4px 0">${fmt(totalInvoiced)}</div>
            <div style="font-size:10px;color:#aaa">ذمم مدينة</div>
        </div>
        <div style="background:white;border-radius:10px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.05);border-right:4px solid #27ae60">
            <div style="font-size:10px;color:#666;font-weight:600">💵 إجمالي المحصَّل</div>
            <div style="font-size:18px;font-weight:900;color:#27ae60;margin:4px 0">${fmt(totalReceived)}</div>
            <div style="font-size:10px;color:#aaa">مدفوعات مستلمة</div>
        </div>
        <div style="background:white;border-radius:10px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.05);border-right:4px solid #e67e22">
            <div style="font-size:10px;color:#666;font-weight:600">⏳ الرصيد المستحق</div>
            <div style="font-size:18px;font-weight:900;color:#e67e22;margin:4px 0">${fmt(Math.abs(totalBalance))}</div>
            <div style="font-size:10px;color:#aaa">غير محصَّل</div>
        </div>
        <div style="background:white;border-radius:10px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.05);border-right:4px solid #2d6a9f">
            <div style="font-size:10px;color:#666;font-weight:600">📊 عدد الحركات</div>
            <div style="font-size:18px;font-weight:900;color:#2d6a9f;margin:4px 0">${grandRows}</div>
            <div style="font-size:10px;color:#aaa">فاتورة + قبض</div>
        </div>
    </div>

    <!-- فلاتر -->
    <div style="background:white;border-radius:10px;padding:14px;margin-bottom:14px;box-shadow:0 2px 8px rgba(0,0,0,.04)">
        <div style="display:grid;grid-template-columns:2fr 1fr 1fr 1fr auto;gap:10px;align-items:end;flex-wrap:wrap">
            <div><label style="font-size:11px;font-weight:700;color:#555;display:block;margin-bottom:4px">🤝 العميل</label>
                <select id="cst-cust" onchange="window._cstState.custId=this.value;renderCustStatement()" style="width:100%;padding:9px;border:1.5px solid #d0d7e0;border-radius:8px;font-size:13px;font-family:inherit">
                    <option value="">-- كل العملاء --</option>
                    ${custList.map(([k, c]) => `<option value="${k}" ${k === custId ? 'selected' : ''}>${c.nameAr}</option>`).join('')}
                </select>
            </div>
            <div><label style="font-size:11px;font-weight:700;color:#555;display:block;margin-bottom:4px">📅 من تاريخ</label>
                <select id="cst-proj" onchange="window._cstState.projectId=this.value;renderCustStatement()" style="width:100%;padding:9px;border:1.5px solid #d0d7e0;border-radius:8px;font-size:13px;font-family:inherit;margin-bottom:8px">
                    ${typeof window.projOnlyOptions === 'function' ? window.projOnlyOptions(cstPid, '🏗️ كل المشاريع') : '<option value="">🏗️ كل المشاريع</option>'}
                </select>
                <input type="date" id="cst-from" value="${from}" onchange="window._cstState.from=this.value;renderCustStatement()" style="width:100%;padding:9px;border:1.5px solid #d0d7e0;border-radius:8px;font-size:13px;font-family:inherit">
            </div>
            <div><label style="font-size:11px;font-weight:700;color:#555;display:block;margin-bottom:4px">📅 إلى تاريخ</label>
                <input type="date" id="cst-to" value="${to}" onchange="window._cstState.to=this.value;renderCustStatement()" style="width:100%;padding:9px;border:1.5px solid #d0d7e0;border-radius:8px;font-size:13px;font-family:inherit">
            </div>
            <div><label style="font-size:11px;font-weight:700;color:#555;display:block;margin-bottom:4px">🔍 بحث</label>
                <input type="text" id="cst-search" value="${search}" placeholder="رقم فاتورة أو بيان..." oninput="window._cstState.search=this.value.toLowerCase();renderCustStatement()" style="width:100%;padding:9px;border:1.5px solid #d0d7e0;border-radius:8px;font-size:13px;font-family:inherit">
            </div>
            <button onclick="window._cstState={custId:'',from:'',to:'',search:'',projectId:''};renderCustStatement()" style="padding:9px 14px;background:#f8fafc;color:#666;border:1.5px solid #d0d7e0;border-radius:8px;cursor:pointer;font-size:12px">🔄</button>
        </div>
    </div>

    <!-- كشوف العملاء -->
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;flex-wrap:wrap;gap:8px">
        <div style="font-size:13px;font-weight:700;color:#1a3a5c">${selectedCusts.length} عميل</div>
        <div style="display:flex;gap:8px">
            <button onclick="printCustStatement()" style="padding:6px 14px;background:#f8fafc;color:#666;border:1.5px solid #d0d7e0;border-radius:8px;cursor:pointer;font-size:12px">🖨️ طباعة</button>
            <button onclick="bcNav('customers')" style="padding:6px 14px;background:#16a085;color:white;border:none;border-radius:8px;cursor:pointer;font-size:12px;font-weight:700">🤝 إدارة العملاء</button>
        </div>
    </div>

    ${!Object.keys(customers).length
        ? `<div style="text-align:center;padding:60px;color:#aaa"><div style="font-size:60px;margin-bottom:12px">🤝</div><div style="font-size:16px">لا يوجد عملاء — أضف عملاء من صفحة <a onclick="bcNav('customers')" style="color:#16a085;cursor:pointer">العملاء</a> أولاً</div></div>`
        : rows || `<div style="text-align:center;padding:40px;color:#aaa">لا توجد حركات مطابقة</div>`}
    `;
};

window.printCustStatement = function () {
    const customers   = window.customers   || {};
    const salesInvoices = window.salesInvoices || {};
    const receipts_   = window.receipts    || {};
    const { custId, from, to, projectId: cstPid } = window._cstState;
    const cA = cfg.companyAr || 'اسم الشركة';
    const cE = cfg.companyEn || 'Company';
    const ph = cfg.phone || '', ad = cfg.address || '', vt = cfg.vat || '';
    const pc = '#1a3a5c';

    const custList = Object.entries(customers).sort((a,b) => (a[1].nameAr||'').localeCompare(b[1].nameAr||'','ar'));
    const selectedCusts = custId ? (customers[custId] ? [[custId, customers[custId]]] : []) : custList;

    let suppHTML = '';
    let grandDr = 0, grandCr = 0;

    selectedCusts.forEach(([cid, c]) => {
        const allInvAll = Object.entries(salesInvoices)
            .filter(([, inv]) => inv.customerId === cid && (inv.status === 'posted' || inv.status === 'paid'))
            .filter(([, inv]) => !cstPid || inv.projectId === cstPid)
            .sort((a,b) => (a[1].date||'').localeCompare(b[1].date||''));
        const allRcptAll = Object.entries(receipts_)
            .filter(([, r]) => (r.customerId === cid || r.partyId === cid) && r.status !== 'cancelled')
            .filter(([, r]) => cstRcptMatchesProj(r, cstPid))
            .sort((a,b) => (a[1].date||'').localeCompare(b[1].date||''));

        const openingBalance = cstPid ? 0 : (parseFloat(c.openingBalance) || 0);
        let carriedForward = openingBalance;
        if (from) {
            allInvAll.forEach(([, inv]) => { if ((inv.date||'') < from) carriedForward += parseFloat(inv.grandTotal)||0; });
            allRcptAll.forEach(([, r])  => { if ((r.date||'')   < from) carriedForward -= parseFloat(r.amount)||0; });
        }

        const invEntries  = allInvAll.filter(([, inv]) => (!from||(inv.date||'')>=from) && (!to||(inv.date||'')<=to));
        const rcptEntries = allRcptAll.filter(([, r])  => (!from||(r.date||'')>=from)   && (!to||(r.date||'')<=to));

        if (!invEntries.length && !rcptEntries.length && !carriedForward) return;

        const allEntries = [
            ...invEntries.map(([k, inv]) => ({ date:inv.date, ref:inv.number, desc:inv.subject||`فاتورة ${inv.number}`, debit:parseFloat(inv.grandTotal)||0, credit:0 })),
            ...rcptEntries.map(([k, r]) => ({ date:r.date, ref:r.number||r.receiptNumber||'', desc:r.description||'سند قبض', debit:0, credit:parseFloat(r.amount)||0 }))
        ].sort((a,b) => (a.date||'').localeCompare(b.date||''));

        let balance = carriedForward, custDr = 0, custCr = 0;
        const tRows = allEntries.map((e, i) => {
            balance += e.debit - e.credit;
            custDr += e.debit; custCr += e.credit;
            const bal = Math.abs(balance);
            const balLabel = balance > 0 ? 'مدين' : balance < 0 ? 'دائن' : '';
            return `<tr class="${i%2?'even':''}">
                <td>${i+1}</td><td>${e.date||'—'}</td><td>${e.ref||'—'}</td>
                <td style="text-align:right">${e.desc}</td>
                <td style="color:#c0392b">${e.debit>0?e.debit.toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2}):''}</td>
                <td style="color:#27ae60">${e.credit>0?e.credit.toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2}):''}</td>
                <td>${bal.toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2})} <small>${balLabel}</small></td>
            </tr>`;
        }).join('');

        grandDr += custDr; grandCr += custCr;

        suppHTML += `
        <div class="cust-section">
            <div class="cust-hdr">
                <span>🤝 ${c.nameAr||'—'} &nbsp;<small style="opacity:.7">${c.code||''}</small></span>
                <span>الرصيد: ${Math.abs(balance).toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2})} ${balance>0?'(مدين)':balance<0?'(دائن)':''}</span>
            </div>
            <table>
                <thead><tr><th>#</th><th>التاريخ</th><th>المرجع</th><th>البيان</th><th>مدين</th><th>دائن</th><th>الرصيد</th></tr></thead>
                <tbody>
                    <tr class="opening"><td colspan="4">الرصيد المرحّل${from?' (قبل '+from+')':' الافتتاحي'}</td>
                        <td style="color:#c0392b">${carriedForward>0?carriedForward.toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2}):''}</td>
                        <td style="color:#27ae60">${carriedForward<0?Math.abs(carriedForward).toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2}):''}</td>
                        <td>${Math.abs(carriedForward).toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2})}</td></tr>
                    ${tRows}
                    <tr class="total"><td colspan="4">المجموع</td>
                        <td>${custDr.toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2})}</td>
                        <td>${custCr.toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2})}</td>
                        <td>${Math.abs(balance).toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2})} ${balance>0?'(مدين)':balance<0?'(دائن)':''}</td></tr>
                </tbody>
            </table>
        </div>`;
    });

    const printHTML = `<!DOCTYPE html>
<html lang="ar" dir="rtl">
<head>
<meta charset="UTF-8">
<title>كشف حساب العملاء</title>
<style>
  @import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700&display=swap');
  * { margin:0; padding:0; box-sizing:border-box }
  body { font-family:'Cairo',Arial,sans-serif; direction:rtl; color:#333; font-size:10pt; background:white }
  .page-header { background:linear-gradient(135deg,${pc},#2d6a9f); color:white; padding:16px 22px; display:flex; justify-content:space-between; align-items:center }
  .company-name { font-size:17px; font-weight:700 }
  .company-sub { font-size:9.5px; opacity:.85; margin-top:3px }
  .info-bar { background:#f5f7fa; padding:6px 22px; font-size:9pt; color:#555; border-bottom:1px solid #e0e0e0; text-align:center }
  .content { padding:14px 18px }
  .cust-section { margin-bottom:22px; page-break-inside:avoid }
  .cust-hdr { background:#e8f0f8; padding:7px 10px; font-weight:700; font-size:10pt; display:flex; justify-content:space-between; border-radius:4px 4px 0 0; border:1px solid #c9d8e8 }
  table { width:100%; border-collapse:collapse; font-size:9pt; border:1px solid #dde3ec }
  th { padding:6px; background:#f0f5fa; font-weight:700; text-align:center; border-bottom:2px solid #c9d8e8 }
  td { padding:5px 6px; text-align:center; border-bottom:1px solid #f0f0f0 }
  tr.even td { background:#fafbfc }
  tr.opening td { background:#fffbf0; color:#7d6400; font-weight:600 }
  tr.total td { font-weight:800; background:#f0f5fa }
  .footer { margin-top:18px; padding-top:10px; border-top:2px solid ${pc}; display:flex; justify-content:space-between; font-size:8pt; color:#999 }
  .grand { background:#1a3a5c; color:white; border-radius:6px; padding:8px 14px; display:flex; gap:30px; margin-bottom:14px; font-size:10pt }
  .grand span { font-weight:700 }
  @media print {
    body { -webkit-print-color-adjust:exact; print-color-adjust:exact }
    .cust-section { page-break-inside:avoid }
  }
</style>
</head>
<body>
<div class="page-header">
  <div>
    <div class="company-name">${cA}</div>
    <div class="company-sub">📋 كشف حساب العملاء — الفواتير المرحّلة وسندات القبض</div>
    <div class="company-sub">${from||'البداية'} ← ${to||'النهاية'} ${ph?'| '+ph:''} ${vt?'| ضريبي: '+vt:''}</div>
  </div>
  <div style="font-size:24px">📋</div>
</div>
<div class="content">
  <div class="grand">
    <span>🧾 إجمالي الفواتير: ${grandDr.toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2})}</span>
    <span>💵 إجمالي المحصَّل: ${grandCr.toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2})}</span>
    <span>⏳ الرصيد المستحق: ${Math.abs(grandDr-grandCr).toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2})}</span>
  </div>
  ${suppHTML || '<p style="text-align:center;color:#aaa;padding:40px">لا توجد حركات في هذه الفترة</p>'}
  <div class="footer">
    <span>تاريخ الإصدار: ${new Date().toLocaleDateString('ar-SA')}</span>
    <span>${cA}</span>
    <span>هذا المستند سري للاستخدام الداخلي فقط</span>
  </div>
</div>
</body>
</html>`;

    const w = window.open('', '_blank');
    w.document.write(printHTML);
    w.document.close();
    // طباعة مرة واحدة فقط: onload هو الأساس، والمؤقّت احتياط إن لم يعمل — مع حارس يمنع التكرار
    let _printed = false;
    const _doPrint = () => { if (_printed || w.closed) return; _printed = true; w.focus(); w.print(); };
    w.onload = () => setTimeout(_doPrint, 400);
    setTimeout(_doPrint, 1200);
};

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   👥  [USR]   ━━━━   USERS & PERMISSIONS   ━━━━                             ║
// ║                المستخدمون والصلاحيات                                       ║
// ╚══════════════════════════════════════════════════════════════════════════╝
function buildPrmS(cid, sel = []) {
    $(cid).innerHTML = PG.map(g => `<div class="perm-sec"><div class="perm-sec-t">${g.t}</div><div class="perm-gr">${g.p.map(p => `<div class="perm-it ${sel.includes(p.k) ? 'act' : ''}" onclick="togPrm(this,'${p.k}','${cid}')"><input type="checkbox" id="${cid}_${p.k}" ${sel.includes(p.k) ? 'checked' : ''}><span>${p.l}</span></div>`).join('')}</div></div>`).join('');
}
window.togPrm = function (el, k, cid) { const ch = $(cid + '_' + k); ch.checked = !ch.checked; el.classList.toggle('act', ch.checked) };
function getSel(cid) { return ALL_P.filter(k => $(cid + '_' + k)?.checked) }
function applyPre(pre, cid) { const p = PRESETS[pre] || []; ALL_P.forEach(k => { const el = $(cid + '_' + k); const it = el?.closest('.perm-it'); if (el) el.checked = p.includes(k); if (it) it.classList.toggle('act', p.includes(k)) }) }
window.apPre = p => applyPre(p, 'auPS');
window.apPreE = p => applyPre(p, 'euPS');

window.openAUM = function () {
    if (myP?.role !== 'admin') { toast('للمدير فقط', 'er'); return }
    $('auNm').value = $('auEm').value = $('auPs').value = '';
    buildPrmS('auPS', PRESETS.viewer); ov('mAU');
};

window.saveNU = async function () {
    const nm = $('auNm').value.trim(), em = $('auEm').value.trim(), ps = $('auPs').value;
    if (!nm || !em || !ps) { toast('جميع الحقول مطلوبة', 'er'); return }
    if (ps.length < 6) { toast('كلمة المرور 6 أحرف على الأقل', 'er'); return }
    const perms = getSel('auPS');
    // اكتشف الدور المطابق من البريسيتات
    let role = 'viewer';
    const matchesPreset = (preset) => {
        const presetSet = new Set(PRESETS[preset] || []);
        const permSet = new Set(perms);
        if (presetSet.size !== permSet.size) return false;
        return [...presetSet].every(p => permSet.has(p));
    };
    if (perms.length === ALL_P.length) role = 'admin';
    else if (matchesPreset('finance_manager')) role = 'finance_manager';
    else if (matchesPreset('executive_director')) role = 'executive_director';
    else if (matchesPreset('hr_officer')) role = 'hr_officer';
    else if (matchesPreset('admin_officer')) role = 'admin_officer';
    else if (matchesPreset('project_manager')) role = 'project_manager';
    else if (matchesPreset('purchasing_officer')) role = 'purchasing_officer';
    else if (matchesPreset('site_engineer')) role = 'site_engineer';
    else if (matchesPreset('site_receiver')) role = 'site_receiver';
    else if (matchesPreset('accountant')) role = 'accountant';
    else if (matchesPreset('engineer')) role = 'engineer';
    else if (perms.includes('add_transaction')) role = 'accountant';
    try {
        const sec = initializeApp(fbApp.options, 'sec_' + Date.now());
        const sAuth = getAuth(sec);
        const cr = await createUserWithEmailAndPassword(sAuth, em, ps);
        await fbUpP(cr.user, { displayName: nm });
        const uid = cr.user.uid; await signOut(sAuth);
        await set(ref(db, `ledger/users/${uid}`), { name: nm, email: em, role, permissions: perms, active: true, createdAt: new Date().toISOString() });
        // 🏢 اربط المستخدم بشركة المدير الحالي في الفهرس العام (يتطلبه تسجيل الدخول)
        await set(_rawRef(db, `userIndex/${uid}`), { tenantId: currentTenantId });
        toast(`تم إضافة "${nm}" بنجاح ✓`, 'ok'); cov('mAU');
    } catch (e) { toast('خطأ: ' + authEr(e.code), 'er') }
};

window.openEU = function (uid) {
    if (myP?.role !== 'admin') { toast('للمدير فقط', 'er'); return }
    const u = us[uid]; if (!u) return;
    $('euK').value = uid; $('euNm').value = u.name || ''; $('euEm').value = u.email || '';
    $('euAc').value = String(u.active !== false);
    if ($('euNewPwd')) $('euNewPwd').value = '';
    buildPrmS('euPS', u.permissions || []); ov('mEU');
};

window.saveEU = async function () {
    const uid = $('euK').value, nm = $('euNm').value.trim(), ac = $('euAc').value === 'true';
    const perms = getSel('euPS');
    const matchesPreset = (preset) => {
        const presetSet = new Set(PRESETS[preset] || []);
        const permSet = new Set(perms);
        if (presetSet.size !== permSet.size) return false;
        return [...presetSet].every(p => permSet.has(p));
    };
    let role = 'viewer';
    if (perms.length === ALL_P.length) role = 'admin';
    else if (matchesPreset('finance_manager')) role = 'finance_manager';
    else if (matchesPreset('executive_director')) role = 'executive_director';
    else if (matchesPreset('hr_officer')) role = 'hr_officer';
    else if (matchesPreset('admin_officer')) role = 'admin_officer';
    else if (matchesPreset('project_manager')) role = 'project_manager';
    else if (matchesPreset('purchasing_officer')) role = 'purchasing_officer';
    else if (matchesPreset('site_engineer')) role = 'site_engineer';
    else if (matchesPreset('site_receiver')) role = 'site_receiver';
    else if (matchesPreset('accountant')) role = 'accountant';
    else if (matchesPreset('engineer')) role = 'engineer';
    else if (perms.includes('add_transaction')) role = 'accountant';
    try { await update(ref(db, `ledger/users/${uid}`), { name: nm, role, permissions: perms, active: ac, updatedAt: new Date().toISOString() }); toast('تم التحديث ✓', 'ok'); cov('mEU') }
    catch (e) { toast('خطأ: ' + e.message, 'er') }
};

window.delU = function (uid) {
    if (uid === curU?.uid) { toast('لا يمكنك حذف حسابك', 'er'); return }
    cf2(`حذف "${us[uid]?.name}"؟`, async () => { try { await remove(ref(db, `ledger/users/${uid}`)); try { await remove(_rawRef(db, `userIndex/${uid}`)); } catch (e2) { } toast('تم الحذف ✓', 'ok') } catch (e) { toast('خطأ: ' + e.message, 'er') } });
};

// 🔑 إعادة تعيين كلمة مرور مستخدم — يُرسل رابطاً آمناً لبريده (الطريقة المتاحة من المتصفح؛ الضبط المباشر يتطلب خادماً/Blaze)
window.resetUserPwd = function (uid) {
    if (myP?.role !== 'admin') { toast('للمدير فقط', 'er'); return }
    const u = us[uid]; if (!u || !u.email) { toast('لا يوجد بريد لهذا المستخدم', 'er'); return }
    cf2(`إرسال رابط إعادة تعيين كلمة المرور إلى:\n${u.email}؟\n\nسيصل للمستخدم بريد يضبط منه كلمة مرور جديدة.`, async () => {
        try { await sendPasswordResetEmail(auth, u.email); toast('✅ أُرسل رابط إعادة التعيين إلى ' + u.email, 'ok', 5000); if (typeof logAudit === 'function') logAudit('إعادة تعيين كلمة مرور', 'المستخدمون', `إرسال رابط لـ ${u.email}`); }
        catch (e) { toast('❌ ' + (typeof authEr === 'function' && e.code ? authEr(e.code) : (e.message || e)), 'er'); }
    });
};

// 🔒 ضبط كلمة مرور مستخدم مباشرةً (للمستخدمين بلا بريد) — عبر دالة خادمية آمنة (تتطلب تفعيل الخادم/Blaze)
window.adminSetPassword = async function (uid) {
    if (myP?.role !== 'admin') { toast('للمدير فقط', 'er'); return; }
    const u = us[uid]; if (!u) { toast('المستخدم غير موجود', 'er'); return; }
    const inp = $('euNewPwd'); const np = (inp && inp.value || '').trim();
    if (np.length < 6) { toast('كلمة المرور 6 أحرف على الأقل', 'er'); return; }
    if (!(await cf2(`ضبط كلمة مرور جديدة مباشرةً للمستخدم "${u.name || u.email}"؟\n\nستُطبَّق فوراً، وأبلغ المستخدم بها.`))) return;
    try {
        await httpsCallable(fns, 'adminSetUserPassword')({ uid, newPassword: np });
        if (inp) inp.value = '';
        toast('✅ تم ضبط كلمة المرور بنجاح', 'ok', 5000);
        if (typeof logAudit === 'function') logAudit('ضبط كلمة مرور مباشر', 'المستخدمون', `للمستخدم ${u.email || uid}`);
    } catch (e) {
        const code = (e && e.code) || '', msg = (e && e.message) || '';
        if (/not-found|unavailable|internal|functions\//i.test(code) || /not[\s-]?found|CORS|Failed to fetch|does not exist/i.test(msg)) {
            toast('⚙️ الضبط المباشر يتطلب تفعيل الخادم: ترقية الخطة إلى Blaze ثم «firebase deploy --only functions». حتى ذلك استخدم «🔑 إعادة تعيين» (رابط بريد).', 'er', 9000);
        } else if (/permission-denied/i.test(code)) { toast('🚫 ' + (msg || 'غير مصرّح'), 'er'); }
        else { toast('❌ ' + (msg || e), 'er'); }
    }
};

window.togUAc = async function (uid) {
    const u = us[uid]; if (!u) return; if (uid === curU?.uid) { toast('لا يمكنك إيقاف نفسك', 'er'); return }
    const nA = !(u.active !== false);
    try { await update(ref(db, `ledger/users/${uid}`), { active: nA }); toast(nA ? 'تم التفعيل ✓' : 'تم الإيقاف ✓', 'ok') }
    catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// ══ 🔐 صفحة مصفوفة صلاحيات المستخدمين (كل الصلاحيات × كل المستخدمين) ═══════════════
const PERM_ROLE_AR = { admin: 'مدير', finance_manager: 'مدير مالي', accountant: 'محاسب', hr_officer: 'موظف HR', admin_officer: 'موظف إداري', project_manager: 'مدير مشروع', executive_director: 'مدير تنفيذي', procurement_officer: 'موظف مشتريات', warehouse_keeper: 'أمين مخزن', viewer: 'مشاهد', employee: 'موظف' };
window._permsState = window._permsState || { perms: {}, dirty: new Set(), q: '' };
function permsUsersSorted() { return Object.entries(window.us || {}).filter(([, u]) => u).sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar')); }

window.renderPermsMatrix = function (rebuild) {
    const pg = $('pg-perms'); if (!pg) return;
    if (!(myP && myP.role === 'admin')) { pg.innerHTML = '<div class="card" style="padding:30px;text-align:center;color:#c0392b">🚫 هذه الصفحة متاحة للمدير فقط</div>'; return; }
    const st = window._permsState; const users = permsUsersSorted();
    if (rebuild || !st.perms || !Object.keys(st.perms).length) { st.perms = {}; st.dirty = new Set(); users.forEach(([uid, u]) => st.perms[uid] = new Set(u.permissions || [])); }
    else users.forEach(([uid, u]) => { if (!st.perms[uid]) st.perms[uid] = new Set(u.permissions || []); });
    if (!users.length) { pg.innerHTML = '<div class="card" style="padding:30px;text-align:center;color:#888">لا يوجد مستخدمون بعد. أضِف مستخدمين من صفحة «المستخدمون».</div>'; return; }
    pg.innerHTML = `
        <div class="card" style="margin-bottom:14px">
            <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px">
                <div>
                    <div style="font-size:16px;font-weight:900;color:#1a3a5c">🔐 مصفوفة صلاحيات المستخدمين</div>
                    <div style="font-size:12px;color:#666;margin-top:3px">امنح أو امنع أي صلاحية لأي مستخدم عبر كل أقسام البرنامج (${ALL_P.length} صلاحية). المدير يملك كل الصلاحيات تلقائياً بحكم دوره.</div>
                </div>
                <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">
                    <input id="permsSearch" type="text" value="${(st.q || '').replace(/"/g, '&quot;')}" oninput="permsSearch(this.value)" placeholder="🔍 ابحث في الصلاحيات..." style="padding:8px 12px;border:1.5px solid #d0d7e0;border-radius:8px;font-family:inherit;font-size:12px;min-width:200px">
                    <button class="btn b-g" onclick="permsSave()" style="font-weight:800">💾 حفظ التغييرات</button>
                </div>
            </div>
        </div>
        ${users.filter(([, u]) => u.role !== 'admin').length ? '' : `<div class="card" style="margin-bottom:14px;background:#fef9e7;border:1.5px solid #f0c419">
            <div style="font-weight:800;color:#7d4e00;font-size:14px">ℹ️ لا يوجد مستخدمون لتخصيص صلاحياتهم بعد</div>
            <div style="font-size:12.5px;color:#7d4e00;margin-top:6px;line-height:1.9">حسابك الحالي بدور <b>مدير النظام</b>، ويملك <b>كل الصلاحيات تلقائياً</b> — ولا يمكن تقييده حتى لا تُغلق على نفسك، لذا تظهر خاناته بعلامة ✓ مقفلة.<br>لتفعيل التحكم بالصلاحيات فعلياً: <b>أضِف مستخدماً بدور غير المدير</b> (محاسب، موظف موارد بشرية، مشاهد…). عندها يظهر له عمود بخانات قابلة للتفعيل والإلغاء هنا، وتتحكّم في كل ما يراه ويفعله.</div>
            <button class="btn b-g" onclick="nav('users');setTimeout(function(){ if(typeof openAUM==='function') openAUM(); },250)" style="margin-top:11px;font-weight:800">➕ إضافة مستخدم جديد</button>
        </div>`}
        <div class="card" style="padding:0;overflow:hidden">
            <div id="permsTableWrap" style="overflow:auto;max-height:72vh"></div>
        </div>`;
    permsPaintTable();
};
window.permsPaintTable = function () {
    const wrap = $('permsTableWrap'); if (!wrap) return;
    const st = window._permsState, esc = s => String(s == null ? '' : s).replace(/[&<>]/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' }[c]));
    const users = permsUsersSorted();
    const q = (st.q || '').trim().toLowerCase();
    const roleAr = r => PERM_ROLE_AR[r] || r || '';
    const cnt = uid => (st.perms[uid] ? st.perms[uid].size : 0);
    // رأس الأعمدة: عمود الصلاحية + عمود لكل مستخدم
    const uHead = users.map(([uid, u]) => {
        const isAdm = u.role === 'admin';
        const presetSel = isAdm ? '' : `<select onchange="permApplyPreset('${uid}',this.value);this.value=''" style="margin-top:4px;font-size:10px;padding:3px;border:1px solid #d7dde5;border-radius:5px;max-width:110px"><option value="">تطبيق دور…</option>${Object.keys(PRESETS).map(r => `<option value="${r}">${esc(roleAr(r))}</option>`).join('')}</select>`;
        const allBtns = isAdm ? '' : `<div style="margin-top:3px;display:flex;gap:3px;justify-content:center"><button onclick="permUserAll('${uid}',true)" title="منح كل الصلاحيات" style="background:#eafaf1;color:#1e8449;border:none;border-radius:4px;padding:2px 6px;font-size:10px;cursor:pointer">✓ الكل</button><button onclick="permUserAll('${uid}',false)" title="إلغاء كل الصلاحيات" style="background:#fdecea;color:#c0392b;border:none;border-radius:4px;padding:2px 6px;font-size:10px;cursor:pointer">✗ الكل</button></div>`;
        return `<th style="padding:8px 6px;min-width:120px;text-align:center;vertical-align:top;border-right:1px solid #eef2f6">
            <div style="font-weight:800;color:#1a3a5c;font-size:12px">${esc(u.name || '—')}</div>
            <div style="font-size:10px;color:#8e44ad;margin-top:2px">${esc(roleAr(u.role))}${isAdm ? ' 👑' : ''}</div>
            <div style="font-size:9.5px;color:#aaa">${isAdm ? 'كل الصلاحيات' : cnt(uid) + ' صلاحية'}</div>
            ${allBtns}${presetSel}
        </th>`;
    }).join('');
    // الصفوف حسب المجموعات
    let body = '';
    PG.forEach((g, gi) => {
        const rows = g.p.filter(p => !q || (p.l || '').toLowerCase().includes(q) || (p.k || '').toLowerCase().includes(q));
        if (!rows.length) return;
        // صف عنوان المجموعة + أزرار منح/إلغاء المجموعة لكل مستخدم
        const grpCells = users.map(([uid, u]) => {
            if (u.role === 'admin') return `<td style="text-align:center;background:#f4f7fa;border-right:1px solid #eef2f6;color:#27ae60">✓</td>`;
            return `<td style="text-align:center;background:#f4f7fa;border-right:1px solid #eef2f6;white-space:nowrap"><button onclick="permGroupUser('${uid}',${gi},true)" title="منح كل صلاحيات هذا القسم" style="background:none;border:none;color:#1e8449;cursor:pointer;font-size:12px">✓</button><button onclick="permGroupUser('${uid}',${gi},false)" title="إلغاء كل صلاحيات هذا القسم" style="background:none;border:none;color:#c0392b;cursor:pointer;font-size:12px">✗</button></td>`;
        }).join('');
        body += `<tr><td style="position:sticky;right:0;background:#eef3f8;padding:8px 12px;font-weight:900;color:#1a3a5c;z-index:1;border-top:6px solid #fff">${esc(g.t)}</td>${grpCells}</tr>`;
        rows.forEach(p => {
            const cells = users.map(([uid, u]) => {
                if (u.role === 'admin') return `<td style="text-align:center;border-right:1px solid #eef2f6;color:#27ae60;font-weight:700">✓</td>`;
                const has = st.perms[uid] && st.perms[uid].has(p.k);
                return `<td style="text-align:center;border-right:1px solid #eef2f6;padding:5px"><input type="checkbox" ${has ? 'checked' : ''} onchange="permToggle('${uid}','${p.k}')" style="width:16px;height:16px;cursor:pointer"></td>`;
            }).join('');
            body += `<tr style="border-bottom:1px solid #f2f5f8"><td style="position:sticky;right:0;background:#fff;padding:7px 12px;font-size:12px;color:#333;z-index:1">${esc(p.l)}</td>${cells}</tr>`;
        });
    });
    const dirtyNote = st.dirty.size ? `<div style="padding:8px 14px;background:#fef9e7;color:#b9770e;font-size:12px;font-weight:700;border-bottom:1px solid #f0e6c0">⚠️ لديك تغييرات غير محفوظة على ${st.dirty.size} مستخدم — اضغط «💾 حفظ التغييرات».</div>` : '';
    wrap.innerHTML = dirtyNote + `<table style="width:100%;border-collapse:collapse;font-size:12px">
        <thead style="position:sticky;top:0;z-index:2;background:#f8fafc"><tr><th style="position:sticky;right:0;background:#f8fafc;padding:8px 12px;text-align:right;color:#888;font-size:11px;z-index:3;min-width:260px">الصلاحية / القسم</th>${uHead}</tr></thead>
        <tbody>${body || `<tr><td colspan="${users.length + 1}" style="padding:30px;text-align:center;color:#888">لا صلاحيات مطابقة للبحث</td></tr>`}</tbody>
    </table>`;
};
window.permToggle = function (uid, key) { const s = window._permsState.perms[uid]; if (!s) return; if (s.has(key)) s.delete(key); else s.add(key); window._permsState.dirty.add(uid); permsPaintTable(); };
window.permGroupUser = function (uid, gi, val) { const g = PG[gi], s = window._permsState.perms[uid]; if (!g || !s) return; g.p.forEach(p => { if (val) s.add(p.k); else s.delete(p.k); }); window._permsState.dirty.add(uid); permsPaintTable(); };
window.permUserAll = function (uid, val) { window._permsState.perms[uid] = new Set(val ? ALL_P : []); window._permsState.dirty.add(uid); permsPaintTable(); };
window.permApplyPreset = function (uid, role) { if (!role || !PRESETS[role]) return; window._permsState.perms[uid] = new Set(PRESETS[role]); window._permsState.dirty.add(uid); permsPaintTable(); };
window.permsSearch = function (v) { window._permsState.q = v; permsPaintTable(); };
window.permsSave = async function () {
    if (!(myP && myP.role === 'admin')) { toast('🚫 للمدير فقط', 'er'); return; }
    const st = window._permsState;
    if (!st.dirty.size) { toast('لا توجد تغييرات للحفظ', 'wn'); return; }
    let ok = 0, fail = 0;
    for (const uid of [...st.dirty]) {
        if ((window.us || {})[uid] && window.us[uid].role === 'admin') { continue; } // المدير لا تُحفظ له قائمة (دوره يتجاوزها)
        try { await update(ref(db, `ledger/users/${uid}`), { permissions: [...(st.perms[uid] || [])], updatedAt: new Date().toISOString() }); ok++; }
        catch (e) { fail++; }
    }
    if (typeof logAudit === 'function') logAudit('تعديل صلاحيات', 'المستخدمون', `تحديث صلاحيات ${ok} مستخدم`);
    toast(`✅ حُفظت صلاحيات ${ok} مستخدم${fail ? ` — فشل ${fail}` : ''}`, fail ? 'er' : 'ok');
    st.dirty.clear(); permsPaintTable();
};

function renderUsL() {
    if (!$('pg-users').classList.contains('act')) return;
    const w = $('usL'), ks = Object.keys(us);
    if (!ks.length) { w.innerHTML = '<div class="empty"><div class="ei">👥</div><p>لا يوجد مستخدمون</p></div>'; return }
    const rl = { admin: 'مدير النظام', accountant: 'محاسب', finance_manager: '💰 مدير مالي', hr_officer: '👥 شؤون الموظفين', admin_officer: '📋 الشؤون الإدارية', site_engineer: '🔧 مهندس موقع', project_manager: '📋 مدير مشاريع', purchasing_officer: '🛒 موظف مشتريات', executive_director: '👔 مدير تنفيذي', site_receiver: '📦 مستلم بضاعة', viewer: 'مشاهد' };
    const rb = { admin: 'rb-a', accountant: 'rb-ac', finance_manager: 'rb-a', viewer: 'rb-v' };
    w.innerHTML = ks.map(uid => {
        const u = us[uid], isMe = uid === curU?.uid, ac = u.active !== false;
        return `<div class="uc"><div class="u-av" style="background:${avCol(u.name || '')}">${(u.name || '?').charAt(0).toUpperCase()}</div><div class="u-if"><div class="u-nm">${u.name || '-'} ${isMe ? '<span style="font-size:11px;background:#ebf5fb;color:#2d6a9f;padding:1px 7px;border-radius:10px;margin-right:5px">أنا</span>' : ''}</div><div class="u-em">${u.email || '-'}</div><div class="u-mt">الصلاحيات: ${(u.permissions || []).length}/${ALL_P.length} | ${u.createdAt ? new Date(u.createdAt).toLocaleDateString('ar-SA') : '-'}</div></div><span class="urb ${rb[u.role] || 'rb-v'}">${rl[u.role] || u.role}</span><span class="ust ${ac ? 'st-on' : 'st-off'}">${ac ? '✅ نشط' : '🚫 موقوف'}</span><div class="u-ac"><button class="btn b-b" onclick="openEU('${uid}')">✏️ تعديل</button>${!isMe ? `<button class="btn" onclick="resetUserPwd('${uid}')" title="إرسال رابط إعادة تعيين كلمة المرور إلى بريد المستخدم" style="background:#8e44ad;color:#fff">🔑 كلمة المرور</button><button class="btn ${ac ? 'b-o' : 'b-g'}" onclick="togUAc('${uid}')">${ac ? '🚫 إيقاف' : '✅ تفعيل'}</button><button class="btn b-r" onclick="delU('${uid}')">🗑️</button>` : ''}</div></div>`;
    }).join('');
}

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   ⚙️  [STG]   ━━━━   SETTINGS   ━━━━                                       ║
// ║                الإعدادات                                                   ║
// ╚══════════════════════════════════════════════════════════════════════════╝
window.saveSettings = async function () {
    if (!can('edit_settings')) { toast('ليس لديك صلاحية', 'er'); return }
    const data = { companyAr: $('sAr').value || cfg.companyAr, companyEn: $('sEn').value || cfg.companyEn, currency: $('sCur').value, phone: $('sPhone').value, email: $('sEmail').value, address: $('sAddr').value, reg: $('sReg').value, vat: $('sVat').value };
    // الإبقاء على الإعدادات الفرعية (العملات/التكاملات) كي لا يمسحها الاستبدال
    if (cfg.currencies) data.currencies = cfg.currencies;
    data.cloudinaryCloud = ($('sCloudinaryCloud')?.value || cfg.cloudinaryCloud || '').trim();
    data.cloudinaryPreset = ($('sCloudinaryPreset')?.value || cfg.cloudinaryPreset || '').trim();
    // 🧾 مسار اعتماد القيود اليدوية
    if ($('sJrnApprovalEnabled') || cfg.jrnApproval) {
        data.jrnApproval = {
            enabled: $('sJrnApprovalEnabled') ? !!$('sJrnApprovalEnabled').checked : !!cfg.jrnApproval?.enabled,
            threshold: ($('sJrnApprovalThreshold') ? (parseFloat($('sJrnApprovalThreshold').value) || 0) : (cfg.jrnApproval?.threshold || 0))
        };
    }
    // 📧 إعدادات EmailJS (تُقرأ من الحقول إن وُجدت، وإلا تُبقى القيم السابقة)
    if ($('sEmailjsService') || cfg.emailjs) {
        const prev = cfg.emailjs || {};
        data.emailjs = {
            serviceId: ($('sEmailjsService')?.value ?? prev.serviceId ?? '').trim(),
            templateId: ($('sEmailjsTemplate')?.value ?? prev.templateId ?? '').trim(),
            publicKey: ($('sEmailjsKey')?.value ?? prev.publicKey ?? '').trim(),
            to: ($('sEmailjsTo')?.value ?? prev.to ?? '').trim(),
            autoDaily: $('sEmailjsAuto') ? !!$('sEmailjsAuto').checked : !!prev.autoDaily
        };
    }
    try { await set(R.cfg, data); cfg = { ...cfg, ...data }; window.gbrCfg = cfg; toast('تم الحفظ ✓', 'ok') } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

function loadCfgUI() {
    $('sAr').value = cfg.companyAr; $('sEn').value = cfg.companyEn; $('sCur').value = cfg.currency;
    $('sPhone').value = cfg.phone || ''; $('sEmail').value = cfg.email || ''; $('sAddr').value = cfg.address || '';
    $('sReg').value = cfg.reg || ''; $('sVat').value = cfg.vat || '';
    if ($('sCloudinaryCloud')) $('sCloudinaryCloud').value = cfg.cloudinaryCloud || '';
    if ($('sCloudinaryPreset')) $('sCloudinaryPreset').value = cfg.cloudinaryPreset || '';
    const ej = cfg.emailjs || {};
    if ($('sEmailjsService')) $('sEmailjsService').value = ej.serviceId || '';
    if ($('sEmailjsTemplate')) $('sEmailjsTemplate').value = ej.templateId || '';
    if ($('sEmailjsKey')) $('sEmailjsKey').value = ej.publicKey || '';
    if ($('sEmailjsTo')) $('sEmailjsTo').value = ej.to || '';
    if ($('sEmailjsAuto')) $('sEmailjsAuto').checked = !!ej.autoDaily;
    const ja = cfg.jrnApproval || {};
    if ($('sJrnApprovalEnabled')) $('sJrnApprovalEnabled').checked = !!ja.enabled;
    if ($('sJrnApprovalThreshold')) $('sJrnApprovalThreshold').value = ja.threshold || '';
}

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🧩  [MODULES]  مفاتيح الوحدات (باقات) — تفعيل/إخفاء أقسام كاملة لكل عميل    ║
// ║   يُخزَّن في ledger/settings/modules (يُحدَّد للمدير). يُخفي مجموعات القائمة.   ║
// ║   الافتراضي: كل الوحدات مُفعّلة — فلا يتغيّر سلوك العملاء الحاليين.            ║
// ╚══════════════════════════════════════════════════════════════════════════╝
const MODULE_DEFS = {
    hr:          { label: '👷 الموارد البشرية', bodies: ['grpEmp'] },
    projects:    { label: '📁 المشاريع والمقاولون', bodies: ['grpProjectsBody', 'grpSubcBody'] },
    procurement: { label: '🛒 المشتريات والموردون', bodies: ['grpProcurementBody'] },
    accounting:  { label: '💰 المحاسبة والتحليل المالي', bodies: ['grpAccountingBody', 'grpFinAnalysisBody'] },
    sales:       { label: '🧾 المبيعات وإدارة العملاء (CRM)', bodies: ['grpSalesBody'] },
    inventory:   { label: '📦 المخزون والمخازن', bodies: ['grpInventoryBody'] },
    assets:      { label: '🏭 الأصول الثابتة', bodies: ['grpAssetsBody'] },
    study:       { label: '📚 أدوات الدراسة والاختبارات (CMA)', bodies: ['grpStudyBody', 'grpExamsBody'] }
};
const MODULE_DEFAULTS = Object.fromEntries(Object.keys(MODULE_DEFS).map(k => [k, true]));
window.appModules = { ...MODULE_DEFAULTS };

// إخفاء مجموعات القائمة للوحدات المعطّلة فقط (لا نُظهر شيئاً حتى لا نتعارض مع إخفاء الصلاحيات)
// تُخفي مجموعات الوحدات المعطّلة في الباقة للجميع (الباقة يحدّدها المالك، وتُفرَض حتى على مدير العميل).
// لا تُظهر شيئاً — الإظهار يبقى محكوماً بإخفاء الصلاحيات لكل مستخدم.
function applyModuleVisibility() {
    const mods = window.appModules || MODULE_DEFAULTS;
    Object.entries(MODULE_DEFS).forEach(([key, def]) => {
        if (mods[key] !== false) return; // مُفعّلة → لا تلمسها
        def.bodies.forEach(bid => {
            const body = document.getElementById(bid); if (!body) return;
            const grp = body.closest('.sb-grp'); if (!grp) return;
            grp.style.display = 'none';
            const prev = grp.previousElementSibling;
            if (prev && prev.classList.contains('sb-sec')) prev.style.display = 'none';
        });
    });
}
window.applyModuleVisibility = applyModuleVisibility;

// خريطة الصفحة → الوحدة (تُبنى مرة من عناصر التنقّل داخل مجموعات كل وحدة)
function buildPageModuleMap() {
    const map = {};
    Object.entries(MODULE_DEFS).forEach(([key, def]) => {
        def.bodies.forEach(bid => {
            const body = document.getElementById(bid); if (!body) return;
            body.querySelectorAll('[onclick*="nav("]').forEach(el => {
                const m = String(el.getAttribute('onclick') || '').match(/nav\('([^']+)'/);
                if (m) map[m[1]] = key;
            });
        });
    });
    return map;
}
// حارس التنقّل: يمنع فتح صفحة تابعة لوحدة معطّلة (لغير المدير) من أي مسار
window.isPageModuleEnabled = function (pg) {
    if (!window._pageModuleMap) window._pageModuleMap = buildPageModuleMap();
    const mod = window._pageModuleMap[pg];
    if (!mod) return true; // صفحة غير تابعة لوحدة (رئيسية/إدارة) — مسموحة دائماً
    return (window.appModules || MODULE_DEFAULTS)[mod] !== false;
};

window.updProfile = async function () {
    const nm = $('myNm').value.trim(), np = $('myPs').value;
    if (!nm) { toast('الاسم مطلوب', 'er'); return }
    try {
        await fbUpP(curU, { displayName: nm });
        await update(ref(db, `ledger/users/${curU.uid}`), { name: nm });
        myP.name = nm; $('sbNm').textContent = nm; $('sbAv').textContent = nm.charAt(0).toUpperCase();
        if (np) { if (np.length < 6) { toast('كلمة المرور 6 أحرف على الأقل', 'er'); return } await updatePassword(curU, np) }
        toast('تم التحديث ✓', 'ok');
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

window.clearAll = function () {
    if (myP?.role !== 'admin') { toast('للمدير فقط', 'er'); return }
    cf2('حذف جميع البيانات نهائيًا؟ لا يمكن التراجع!', async () => {
        try { await set(ref(db, 'ledger'), { settings: cfg, suppliers: {}, transactions: {}, users }); toast('تم الحذف ✓', 'ok') }
        catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

// ── 💾 نسخة احتياطية كاملة (تصدير/استعادة JSON) — تقرأ كل مجموعات R للمدير ─────
window.exportFullBackup = async function () {
    if (myP?.role !== 'admin') { toast('النسخ الاحتياطي للمدير فقط', 'er'); return; }
    toast('⏳ جاري تجهيز النسخة الاحتياطية...', 'wn', 4000);
    const data = {};
    for (const k of Object.keys(R)) {
        if (k === 'con') continue; // .info/connected ليس بيانات
        try { const sn = await get(R[k]); if (sn.exists()) data[k] = sn.val(); } catch (e) { /* تخطّي ما لا يُقرأ */ }
    }
    const payload = { app: 'GBR-Ledger-Backup', version: 1, exportedAt: new Date().toISOString(), tenantId: window.currentTenantId || '', company: window.currentTenantName || '', collections: Object.keys(data).length, data };
    const a = Object.assign(document.createElement('a'), {
        href: URL.createObjectURL(new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' })),
        download: `backup_${(window.currentTenantName || 'company').replace(/\s+/g, '_')}_${today()}.json`
    });
    a.click(); URL.revokeObjectURL(a.href);
    toast(`✅ تم تنزيل النسخة الاحتياطية (${payload.collections} مجموعة)`, 'ok');
};
window.triggerImportBackup = function () {
    if (myP?.role !== 'admin') { toast('الاستعادة للمدير فقط', 'er'); return; }
    const inp = $('backupFileInput'); if (inp) { inp.value = ''; inp.click(); }
};
window.importFullBackup = async function (input) {
    if (myP?.role !== 'admin') { toast('الاستعادة للمدير فقط', 'er'); return; }
    const file = input.files && input.files[0]; if (!file) return;
    let payload;
    try { payload = JSON.parse(await file.text()); } catch (e) { toast('❌ الملف غير صالح (JSON)', 'er'); return; }
    if (!payload || payload.app !== 'GBR-Ledger-Backup' || !payload.data) { toast('❌ هذا ليس ملف نسخة احتياطية صالحاً', 'er'); return; }
    const cnt = Object.keys(payload.data).length;
    const ok = await cf2(`استعادة نسخة احتياطية بتاريخ ${(payload.exportedAt || '').slice(0, 10)} (شركة: ${payload.company || '—'})؟\n\nستُدمج ${cnt} مجموعة مع بياناتك الحالية: تُعاد المحذوفات وتُحدَّث المعدّلات، ولا تُمسح الإضافات الجديدة.\n\nيُنصح بأخذ نسخة احتياطية حالية أولاً.`);
    if (!ok) return;
    let done = 0, failed = 0;
    for (const k of Object.keys(payload.data)) {
        if (k === 'con' || !R[k] || payload.data[k] == null || typeof payload.data[k] !== 'object') continue;
        try { await update(R[k], payload.data[k]); done++; } catch (e) { failed++; }
    }
    toast(`✅ تمت الاستعادة: ${done} مجموعة${failed ? ` (تعذّر ${failed})` : ''}`, 'ok', 6000);
};

// ── ☁️ رفع الملفات عبر Cloudinary (مجاني، من المتصفح مباشرة بدون backend) ──────
window.isCloudinaryConfigured = function () { return !!(cfg && cfg.cloudinaryCloud && cfg.cloudinaryPreset); };
window.cloudinaryUpload = async function (file) {
    const cloud = ((cfg && cfg.cloudinaryCloud) || '').trim();
    const preset = ((cfg && cfg.cloudinaryPreset) || '').trim();
    if (!cloud || !preset) throw new Error('لم تُضبط بيانات Cloudinary في الإعدادات (اسم السحابة + Upload Preset)');
    const fd = new FormData();
    fd.append('file', file);
    fd.append('upload_preset', preset);
    const res = await fetch(`https://api.cloudinary.com/v1_1/${cloud}/auto/upload`, { method: 'POST', body: fd });
    const data = await res.json().catch(() => ({}));
    if (!res.ok) throw new Error((data && data.error && data.error.message) || 'فشل الرفع — تأكد من اسم السحابة و Upload Preset (يجب أن يكون Unsigned)');
    return { url: data.secure_url, name: data.original_filename || file.name, size: data.bytes || file.size, format: data.format || '', publicId: data.public_id || '' };
};

// ── 📧 التنبيهات البريدية عبر EmailJS (مجاني، من المتصفح مباشرة بدون backend) ──
window.isEmailJSConfigured = function () { const e = cfg && cfg.emailjs; return !!(e && e.serviceId && e.templateId && e.publicKey); };
let _emailjsLoading = null;
function loadEmailJSSDK() {
    if (window.emailjs) return Promise.resolve(window.emailjs);
    if (_emailjsLoading) return _emailjsLoading;
    _emailjsLoading = new Promise((resolve, reject) => {
        const s = document.createElement('script');
        s.src = 'https://cdn.jsdelivr.net/npm/@emailjs/browser@4/dist/email.min.js';
        s.onload = () => resolve(window.emailjs);
        s.onerror = () => { _emailjsLoading = null; reject(new Error('تعذّر تحميل مكتبة EmailJS — تحقّق من الاتصال')); };
        document.head.appendChild(s);
    });
    return _emailjsLoading;
};
window.emailjsSend = async function ({ subject, message, toEmail }) {
    if (!isEmailJSConfigured()) throw new Error('لم تُضبط بيانات EmailJS في الإعدادات');
    const e = cfg.emailjs;
    const to = (toEmail || e.to || '').trim();
    if (!to) throw new Error('لا يوجد بريد مستلِم — اضبط بريد المحاسب في الإعدادات');
    const sdk = await loadEmailJSSDK();
    sdk.init({ publicKey: e.publicKey });
    const params = { to_email: to, subject: subject || 'إشعار من بنيان للمقاولات', message: message || '', company: (window.currentTenantName || cfg.companyAr || 'بُنيان') };
    return sdk.send(e.serviceId, e.templateId, params);
};
window.sendTaxReminderEmail = async function (silent) {
    if (!isEmailJSConfigured()) { if (!silent) toast('⚠️ اضبط بيانات EmailJS في الإعدادات أولاً', 'er'); return false; }
    const tax = (typeof collectTaxAlerts === 'function') ? collectTaxAlerts() : [];
    if (!tax.length) { if (!silent) toast('✅ لا توجد تذكيرات ضريبية مستحقة حالياً', 'ok'); return false; }
    const company = window.currentTenantName || cfg.companyAr || 'منشأتك';
    const lines = tax.map((a, i) => `${i + 1}) ${a.title}\n   ${a.subtitle}\n   (${(a.label || '').replace(/[⏰🚨📝]/g, '').trim()})`).join('\n\n');
    const message = `تذكير بالالتزامات الضريبية والامتثال لـ${company}:\n\n${lines}\n\n— أُرسلت تلقائياً من بنيان للمقاولات لإدارة المقاولات.`;
    const subject = `🧮 تذكير ضريبي (${tax.length}) — ${company}`;
    try {
        if (!silent) toast('⏳ جاري إرسال التذكير البريدي...', 'wn', 3000);
        await emailjsSend({ subject, message });
        toast('✅ أُرسل التذكير البريدي بنجاح', 'ok');
        return true;
    } catch (err) { if (!silent) toast('❌ فشل الإرسال: ' + (err?.text || err?.message || err), 'er', 7000); return false; }
};
// إرسال يومي تلقائي (مرة/يوم) عند وجود التزامات عاجلة — يُستدعى عند الدخول
window.maybeSendDailyTaxEmail = async function () {
    try {
        if (!cfg?.emailjs?.autoDaily || !isEmailJSConfigured()) return;
        const tax = (typeof collectTaxAlerts === 'function') ? collectTaxAlerts() : [];
        const hot = tax.filter(a => a.severity === 'critical' || a.severity === 'urgent');
        if (!hot.length) return;
        const key = 'bunyan_taxmail_' + (window.currentTenantId || 'default');
        const today = new Date().toISOString().slice(0, 10);
        if (localStorage.getItem(key) === today) return; // أُرسل اليوم بالفعل
        localStorage.setItem(key, today);
        await sendTaxReminderEmail(true);
    } catch (e) { /* صامت */ }
};

