// ║   🔄  [IMP]   ━━━━   EXPORT / IMPORT   ━━━━                                 ║
// ║                استيراد / تصدير JSON                                        ║
// ╚══════════════════════════════════════════════════════════════════════════╝
window.doExport = function () {
    if (!can('export_data')) { toast('ليس لديك صلاحية', 'er'); return }
    const data = { settings: cfg, suppliers: sup, transactions: tr, at: new Date().toISOString() };
    const a = Object.assign(document.createElement('a'), { href: URL.createObjectURL(new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' })), download: `ledger_${today()}.json` });
    a.click(); URL.revokeObjectURL(a.href); toast('تم التصدير ✓', 'ok');
};

window.doImport = function (e) {
    if (!can('import_data')) { toast('ليس لديك صلاحية', 'er'); return }
    const file = e.target.files[0]; if (!file) return;
    const fr = new FileReader();
    fr.onload = async ev => {
        try {
            const p = JSON.parse(ev.target.result); if (!p.suppliers || !p.transactions) throw new Error('بيانات غير صالحة');
            await set(ref(db, 'ledger'), { settings: p.settings || cfg, suppliers: p.suppliers, transactions: p.transactions, users });
            toast('تم الاستيراد ✓', 'ok')
        }
        catch (err) { toast('خطأ: ' + err.message, 'er') }
    };
    fr.readAsText(file); e.target.value = '';
};

