window.pdfTab = function (id, btn) {
    document.querySelectorAll('.pt-pane').forEach(p => p.classList.remove('act'));
    document.querySelectorAll('.pt-btn').forEach(b => b.classList.remove('act'));
    $(id).classList.add('act'); btn.classList.add('act');
    if (id === 'pd4') refreshPrv();
};

window.togOpt = function (el, key) {
    el.classList.toggle('act');
    if (key.startsWith('c')) pdfState.cols[key] = el.classList.contains('act');
    else pdfState.opts[key] = el.classList.contains('act');
};

window.selTmpl = function (nm, el) {
    pdfState.template = nm;
    document.querySelectorAll('.tmpl-c').forEach(c => c.classList.remove('act'));
    el.classList.add('act');
};

window.selClr = function (el, tp, val) {
    pdfState.colors[tp] = val;
    if (el) { const p = el.closest('.col-row'); p.querySelectorAll('.cb').forEach(b => b.classList.remove('act')); el.classList.add('act') }
};

function fillPdfSups() {
    const sel = $('pdfSup'), pv = sel.value;
    sel.innerHTML = '<option value="">-- جميع الموردين --</option>';
    Object.entries(sup).sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar')).forEach(([k, s]) => sel.innerHTML += `<option value="${k}">${s.name}</option>`);
    if (pv) sel.value = pv;
}

window.pdfFilter = function () {
    const fS = $('pdfSup').value, fF = $('pdfFr').value, fT = $('pdfTo').value;
    pdfState.filtered = Object.entries(tr).filter(([, t]) => {
        if (fS && t.supplierId !== fS) return false;
        if (fF && t.date < fF) return false;
        if (fT && t.date > fT) return false;
        return true;
    }).sort((a, b) => (a[1].date || '').localeCompare(b[1].date || ''));
    const sSet = new Set(pdfState.filtered.map(([, t]) => t.supplierId));
    let gD = 0, gC = 0; pdfState.filtered.forEach(([, t]) => { gD += (t.debit || 0); gC += (t.credit || 0) });
    $('pS0').textContent = sSet.size; $('pS1').textContent = fmt(gD); $('pS2').textContent = fmt(gC);
    $('pS3').textContent = fmt(Math.abs(gD - gC)); $('pDC').textContent = pdfState.filtered.length;
    renderPdfDT();
};

function renderPdfDT() {
    const w = $('pDT');
    if (!pdfState.filtered.length) { w.innerHTML = '<div class="empty"><div class="ei">📂</div><p>اضبط الفلاتر لعرض البيانات</p></div>'; return }
    let h = `<table class="st"><thead><tr class="h1"><th>#</th><th>التاريخ</th><th>المورد</th><th>الوصف</th><th>مدين</th><th>دائن</th></tr></thead><tbody>`;
    pdfState.filtered.slice(0, 25).forEach(([, t], i) => {
        h += `<tr><td>${i + 1}</td><td>${t.date}</td><td style="max-width:140px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${sup[t.supplierId]?.name || '-'}</td><td style="max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${t.desc}</td><td class="td-db">${(t.debit || 0) > 0 ? fmt(t.debit) : ''}</td><td class="td-cr">${(t.credit || 0) > 0 ? fmt(t.credit) : ''}</td></tr>`;
    });
    if (pdfState.filtered.length > 25) h += `<tr><td colspan="6" style="text-align:center;color:#aaa;padding:10px">... و ${pdfState.filtered.length - 25} حركة أخرى ستظهر في PDF</td></tr>`;
    h += '</tbody></table>'; w.innerHTML = h;
}

// ── Preview ────────────────────────────────
window.refreshPrv = function () {
    const pp = $('prvPP'), cl = pdfState.colors, tmpl = pdfState.template;
    const cA = cfg.companyAr || 'اسم الشركة', cE = cfg.companyEn || 'Company';
    const fF = $('pdfFr').value || '---', fT = $('pdfTo').value || '---', cur = cfg.currency || 'SAR';
    const hds = {
        classic: `<div style="background:${cl.pc};color:white;padding:16px 20px;display:flex;justify-content:space-between;align-items:center"><div style="background:rgba(255,255,255,.15);width:48px;height:48px;border-radius:10px;display:flex;align-items:center;justify-content:center;font-weight:900;font-size:14px">${cE.split(' ').map(w => w[0]).join('') || 'GBR'}</div><div style="text-align:right"><div style="font-size:18px;font-weight:800">بُنيان</div><div style="font-size:11px;opacity:.8">${cA}</div><div style="font-size:10px;opacity:.65">من ${fF} إلى ${fT}</div></div></div>`,
        modern: `<div style="background:linear-gradient(135deg,${cl.pc},${cl.sc});color:white;padding:18px 20px;display:flex;justify-content:space-between;align-items:center"><div style="background:rgba(255,255,255,.15);padding:8px 14px;border-radius:10px;font-weight:900;font-size:16px;letter-spacing:2px">${cE.split(' ').map(w => w[0]).join('') || 'GBR'}</div><div style="text-align:right"><div style="font-size:18px;font-weight:800">بُنيان</div><div style="font-size:11px;opacity:.8">${cA}</div></div></div>`,
        green: `<div style="background:linear-gradient(135deg,#27ae60,#2ecc71);color:white;padding:16px 20px;display:flex;justify-content:space-between;align-items:center"><div style="font-size:20px;font-weight:900">${cE.split(' ').map(w => w[0]).join('') || 'B'}</div><div style="text-align:right"><div style="font-size:18px;font-weight:800">بُنيان</div><div style="font-size:11px;opacity:.85">${cA}</div></div></div>`,
        warm: `<div style="background:linear-gradient(135deg,#e67e22,#f39c12);color:white;padding:16px 20px;border-bottom:5px solid #d35400;display:flex;justify-content:space-between;align-items:center"><div style="font-size:20px;font-weight:900">${cE.split(' ').map(w => w[0]).join('') || 'B'}</div><div style="text-align:right"><div style="font-size:18px;font-weight:800">بُنيان</div><div style="font-size:11px;opacity:.9">${cA}</div></div></div>`,
        minimal: `<div style="border-bottom:3px solid ${cl.pc};padding:16px 20px;display:flex;justify-content:space-between;align-items:flex-end"><div style="font-size:28px;font-weight:900;color:${cl.pc}">${cE.split(' ').map(w => w[0]).join('') || 'GBR'}</div><div style="text-align:right"><div style="font-size:18px;font-weight:800;color:${cl.pc}">بُنيان</div><div style="font-size:11px;color:#888">${cA}</div></div></div>`
    };
    let tblHTML = '', rD = 0, rC = 0;
    pdfState.filtered.slice(0, 6).forEach(([, t], i) => {
        const net = (rD + (t.debit || 0)) - (rC + (t.credit || 0)); rD = net >= 0 ? net : 0; rC = net < 0 ? -net : 0;
        tblHTML += `<tr><td style="text-align:center;padding:5px 4px;border:1px solid #eee;font-size:10px">${i + 1}</td><td style="text-align:center;padding:5px 4px;border:1px solid #eee;font-size:10px">${t.date}</td><td style="text-align:right;padding:5px 4px;border:1px solid #eee;font-size:10px;max-width:150px">${t.desc?.slice(0, 25) || ''}</td><td style="text-align:center;padding:5px 4px;border:1px solid #eee;font-size:10px;color:${cl.dc};font-weight:700">${(t.debit || 0) > 0 ? fmt(t.debit) : ''}</td><td style="text-align:center;padding:5px 4px;border:1px solid #eee;font-size:10px;color:${cl.cc};font-weight:700">${(t.credit || 0) > 0 ? fmt(t.credit) : ''}</td><td style="text-align:center;padding:5px 4px;border:1px solid #eee;font-size:10px;font-weight:700;color:${cl.pc}">${fmt(rD > 0 ? rD : rC)}</td></tr>`;
    });
    pp.innerHTML = `<div style="font-family:'Segoe UI',Arial,sans-serif;direction:rtl">${hds[tmpl] || hds.classic}<div style="padding:14px"><div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:12px;background:#f8fafc;padding:10px;border-radius:8px;font-size:11px"><div><span style="color:#888;font-weight:700">الفترة:</span> <span style="color:${cl.pc};font-weight:600">من ${fF} إلى ${fT}</span></div><div><span style="color:#888;font-weight:700">العملة:</span> <span style="color:${cl.pc};font-weight:600">${cur}</span></div><div><span style="color:#888;font-weight:700">الحركات:</span> <span style="color:${cl.pc};font-weight:600">${pdfState.filtered.length}</span></div><div><span style="color:#888;font-weight:700">تاريخ الإصدار:</span> <span style="color:${cl.pc};font-weight:600">${today()}</span></div></div>${tblHTML ? `<table style="width:100%;border-collapse:collapse"><thead><tr style="background:${cl.pc};color:white"><th style="padding:6px 4px;text-align:center;font-size:10px">رقم</th><th style="padding:6px 4px;text-align:center;font-size:10px">التاريخ</th><th style="padding:6px 4px;text-align:right;font-size:10px">الوصف</th><th style="padding:6px 4px;text-align:center;font-size:10px">مدين</th><th style="padding:6px 4px;text-align:center;font-size:10px">دائن</th><th style="padding:6px 4px;text-align:center;font-size:10px">الرصيد</th></tr></thead><tbody>${tblHTML}</tbody></table>${pdfState.filtered.length > 6 ? `<div style="text-align:center;color:#aaa;font-size:10px;padding:6px">... ${pdfState.filtered.length - 6} حركة أخرى</div>` : ''}` : `<div style="text-align:center;color:#bbb;padding:20px;font-size:12px">لا توجد بيانات محددة</div>`}${pdfState.opts.oSig ? `<div style="display:flex;justify-content:space-between;margin-top:16px;padding-top:10px;border-top:1px solid #eee">${[$('sg1N')?.value || 'المحاسب', $('sg2N')?.value || 'مدير المالية', $('sg3N')?.value || 'المدير العام'].map(s => `<div style="text-align:center;width:30%"><div style="border-top:1px solid #333;height:25px;margin-bottom:4px"></div><div style="font-size:9px;color:#888">${s}</div></div>`).join('')}</div>` : ''}</div></div>`;
};

// ── Generate PDF ───────────────────────────
// تحميل الخطوط العربية مرة واحدة وتخزينها
let fontsLoaded = false;
let regularFontB64 = null;
let boldFontB64 = null;

function arrayBufferToBase64(buffer) {
    const bytes = new Uint8Array(buffer);
    let binary = '';
    const chunk = 0x8000;
    for (let i = 0; i < bytes.length; i += chunk) {
        binary += String.fromCharCode.apply(null, bytes.subarray(i, i + chunk));
    }
    return btoa(binary);
}

// مصادر بديلة للخط العربي - يجب أن تكون TTF فقط (jsPDF لا يدعم woff/woff2)
const FONT_SOURCES = [
    {
        regular: 'https://cdn.jsdelivr.net/gh/aymanbagabas/Amiri-font@master/fonts/ttf/Amiri-Regular.ttf',
        bold: 'https://cdn.jsdelivr.net/gh/aymanbagabas/Amiri-font@master/fonts/ttf/Amiri-Bold.ttf',
        name: 'Amiri'
    },
    {
        regular: 'https://cdn.jsdelivr.net/gh/rastikerdar/vazir-font@v30.1.0/dist/Vazir.ttf',
        bold: 'https://cdn.jsdelivr.net/gh/rastikerdar/vazir-font@v30.1.0/dist/Vazir-Bold.ttf',
        name: 'Vazir'
    },
    {
        regular: 'https://github.com/google/fonts/raw/main/ofl/cairo/Cairo%5Bslnt%2Cwght%5D.ttf',
        bold: 'https://github.com/google/fonts/raw/main/ofl/cairo/Cairo%5Bslnt%2Cwght%5D.ttf',
        name: 'Cairo-VF'
    }
];

async function loadArabicFonts() {
    if (fontsLoaded && regularFontB64 && boldFontB64) return true;

    for (const src of FONT_SOURCES) {
        try {
            console.log('جاري تحميل الخط:', src.name);
            const r1 = await fetch(src.regular);
            if (!r1.ok) { console.warn('فشل Regular:', src.name, r1.status); continue; }
            const b1 = await r1.arrayBuffer();
            // التحقق من أن الملف هو TTF صالح (يبدأ بـ 0x00010000 أو 'true' أو 'OTTO')
            const magic = new Uint8Array(b1.slice(0, 4));
            const isTTF = (magic[0] === 0x00 && magic[1] === 0x01) ||
                (magic[0] === 0x74 && magic[1] === 0x72) ||
                (magic[0] === 0x4F && magic[1] === 0x54);
            if (!isTTF) { console.warn('ليس ملف TTF صالح:', src.name); continue; }

            regularFontB64 = arrayBufferToBase64(b1);

            // تحميل Bold - إذا فشل نستخدم Regular للبold أيضاً
            try {
                const r2 = await fetch(src.bold);
                if (r2.ok) {
                    const b2 = await r2.arrayBuffer();
                    boldFontB64 = arrayBufferToBase64(b2);
                } else {
                    boldFontB64 = regularFontB64;
                }
            } catch {
                boldFontB64 = regularFontB64;
            }

            fontsLoaded = true;
            console.log('✅ تم تحميل الخط بنجاح:', src.name);
            return true;
        } catch (e) {
            console.warn('فشل تحميل الخط من المصدر:', src.name, e);
        }
    }
    console.error('فشل تحميل جميع الخطوط العربية - سيتم استخدام الخط الافتراضي');
    return false;
}

// للتوافق مع الكود القديم
async function loadArabicFont() {
    await loadArabicFonts();
    return regularFontB64;
}

// دالة معالجة النص العربي - تعيد ترتيب الحروف وعكس الاتجاه
function arabicText(text) {
    if (text === null || text === undefined) return '';
    const str = String(text);
    // إذا لم يحتوِ على عربية، أعده كما هو
    if (!/[\u0600-\u06FF]/.test(str)) return str;
    try {
        // استخدام ArabicReshaper إذا كان متاحاً
        if (window.ArabicReshaper) {
            const reshaper = new window.ArabicReshaper();
            const reshaped = reshaper.convert(str);
            // عكس الكلمات للـ RTL
            return reshaped.split('').reverse().join('');
        }
    } catch (e) { }
    // fallback: عكس النص فقط
    return str.split('').reverse().join('');
}

// تطبيق arabicText على كل نص عربي قبل إرساله لـ jsPDF
function arTxt(text) {
    return arabicText(text);
}

// ============ تسجيل الخطوط في jsPDF (مدمجة في genPDF) ============
window.genPDF = async function () {
    if (!pdfState.filtered.length) { toast('لا توجد بيانات للتصدير', 'er'); return }
    const btn = $('genBtn'); btn.disabled = true;
    $('pbW').style.display = 'block';
    const setPrg = (p, t) => { $('pbB').style.width = p + '%'; $('pbT').textContent = t };
    try {
        setPrg(20, 'تجهيز البيانات...');

        const cur = cfg.currency || 'SAR';
        const cl = pdfState.colors;
        const opts = pdfState.opts;
        const cols = pdfState.cols;
        const fF = $('pdfFr').value || '---';
        const fT = $('pdfTo').value || '---';
        const rf = $('pdfRef').value || 'AUTO-' + Date.now().toString().slice(-6);
        const pc = cl.pc || '#1a3a5c';
        const dc = cl.dc || '#e74c3c';
        const cc = cl.cc || '#27ae60';
        const cA = cfg.companyAr || 'اسم الشركة';
        const cE = cfg.companyEn || 'Company';
        const ph = cfg.phone || '', em = cfg.email || '', ad = cfg.address || '';
        const rg = cfg.reg || '', vt = cfg.vat || '';

        // تجميع البيانات حسب المورد
        const grp = {};
        pdfState.filtered.forEach(([k, t]) => {
            if (!grp[t.supplierId]) grp[t.supplierId] = [];
            grp[t.supplierId].push([k, t]);
        });

        setPrg(50, 'بناء التقرير...');

        // بناء أعمدة الجدول
        const colDefs = [];
        if (cols.cNum) colDefs.push({ k: 'num', h: '#', w: '5%' });
        if (cols.cDt) colDefs.push({ k: 'date', h: 'التاريخ', w: '10%' });
        if (cols.cEn) colDefs.push({ k: 'entry', h: 'ق.القيد', w: '8%' });
        if (cols.cRf) colDefs.push({ k: 'ref', h: 'التحويل', w: '10%' });
        if (cols.cDs) colDefs.push({ k: 'desc', h: 'الوصف', w: 'auto' });
        if (cols.cEm) colDefs.push({ k: 'emp', h: 'الموظف', w: '10%' });
        if (cols.cDb) colDefs.push({ k: 'debit', h: `مدين (${cur})`, w: '12%' });
        if (cols.cCr) colDefs.push({ k: 'credit', h: `دائن (${cur})`, w: '12%' });
        if (cols.cBl && opts.oRun) colDefs.push({ k: 'bal', h: `رصيد (${cur})`, w: '12%' });

        let suppliersHTML = '';

        for (const [sKey, txList] of Object.entries(grp)) {
            const s = sup[sKey] || { name: sKey, openingDebit: 0, openingCredit: 0 };
            let gD = 0, gC = 0;
            txList.forEach(([, t]) => { gD += (t.debit || 0); gC += (t.credit || 0); });
            const netBal = Math.abs(gD - gC);

            // ملخص الأرصدة
            let summaryHTML = '';
            if (opts.oSum) {
                summaryHTML = `
            <div class="summary-box">
                <div class="summary-item">
                    <div class="s-label">إجمالي المدين</div>
                    <div class="s-value" style="color:${dc}">${fmt(gD)} ${cur}</div>
                </div>
                <div class="summary-item">
                    <div class="s-label">إجمالي الدائن</div>
                    <div class="s-value" style="color:${cc}">${fmt(gC)} ${cur}</div>
                </div>
                <div class="summary-item">
                    <div class="s-value" style="color:${pc}">${fmt(netBal)} ${cur}</div>
                    <div class="s-label">صافي الرصيد</div>
                </div>
                <div class="summary-item">
                    <div class="s-value" style="color:${pc}">${txList.length}</div>
                    <div class="s-label">عدد الحركات</div>
                </div>
            </div>`;
            }

            // بناء صفوف الجدول
            let rD = s.openingDebit || 0, rC = s.openingCredit || 0;

            // صف الرصيد الافتتاحي
            let rowsHTML = `<tr class="opening-row">`;
            colDefs.forEach(c => {
                if (c.k === 'desc') rowsHTML += `<td>الرصيد الافتتاحي</td>`;
                else if (c.k === 'debit') rowsHTML += `<td>${fmt(s.openingDebit || 0)}</td>`;
                else if (c.k === 'credit') rowsHTML += `<td>${fmt(s.openingCredit || 0)}</td>`;
                else if (c.k === 'bal') rowsHTML += `<td style="color:${pc};font-weight:700">${fmt(s.openingDebit || 0)}</td>`;
                else rowsHTML += `<td></td>`;
            });
            rowsHTML += `</tr>`;

            txList.forEach(([, t], i) => {
                const net = (rD + (t.debit || 0)) - (rC + (t.credit || 0));
                rD = net >= 0 ? net : 0; rC = net < 0 ? -net : 0;
                rowsHTML += `<tr>`;
                colDefs.forEach(c => {
                    if (c.k === 'num') rowsHTML += `<td>${i + 1}</td>`;
                    else if (c.k === 'date') rowsHTML += `<td>${t.date || ''}</td>`;
                    else if (c.k === 'entry') rowsHTML += `<td>${t.entry || '-'}</td>`;
                    else if (c.k === 'ref') rowsHTML += `<td>${t.ref || '-'}</td>`;
                    else if (c.k === 'desc') rowsHTML += `<td style="text-align:right">${t.desc || ''}</td>`;
                    else if (c.k === 'emp') rowsHTML += `<td>${t.employee || '-'}</td>`;
                    else if (c.k === 'debit') rowsHTML += `<td style="color:${dc};font-weight:700">${(t.debit || 0) > 0 ? fmt(t.debit) : ''}</td>`;
                    else if (c.k === 'credit') rowsHTML += `<td style="color:${cc};font-weight:700">${(t.credit || 0) > 0 ? fmt(t.credit) : ''}</td>`;
                    else if (c.k === 'bal') rowsHTML += `<td style="color:${pc};font-weight:700">${fmt(rD > 0 ? rD : rC)}</td>`;
                    else rowsHTML += `<td></td>`;
                });
                rowsHTML += `</tr>`;
            });

            // صف المجموع الكلي
            rowsHTML += `<tr class="total-row" style="background:${pc};color:white">`;
            colDefs.forEach(c => {
                if (c.k === 'desc') rowsHTML += `<td>المجموع الكلي</td>`;
                else if (c.k === 'debit') rowsHTML += `<td>${fmt(gD)}</td>`;
                else if (c.k === 'credit') rowsHTML += `<td>${fmt(gC)}</td>`;
                else if (c.k === 'bal') rowsHTML += `<td>${fmt(netBal)}</td>`;
                else rowsHTML += `<td></td>`;
            });
            rowsHTML += `</tr>`;

            // معلومات المورد
            const supDetails = [];
            if (s.account) supDetails.push(`رقم الحساب: ${s.account}`);
            if (s.supId) supDetails.push(`رقم التعريف: ${s.supId}`);
            supDetails.push(`الفترة: ${fF} → ${fT}`);
            supDetails.push(`المرجع: ${rf}`);

            suppliersHTML += `
        <div class="supplier-section">
            <div class="supplier-bar" style="background:${pc}10;border:1px solid ${pc}30;border-radius:6px;padding:10px 14px;margin-bottom:12px;display:flex;justify-content:space-between;align-items:center">
                <div style="font-size:11px;color:#666">${supDetails.join(' &nbsp;|&nbsp; ')}</div>
                <div style="font-size:14px;font-weight:700;color:${pc}">${s.name || 'جميع الموردين'}</div>
            </div>
            ${summaryHTML}
            <table>
                <thead>
                    <tr style="background:${pc};color:white">
                        ${colDefs.map(c => `<th style="width:${c.w}">${c.h}</th>`).join('')}
                    </tr>
                </thead>
                <tbody>${rowsHTML}</tbody>
            </table>
        </div>`;
        }

        // التوقيعات
        let sigsHTML = '';
        if (opts.oSig) {
            const sigs = [
                { n: $('sg1N')?.value || 'المحاسب', t: $('sg1T')?.value || 'توقيع المحاسب' },
                { n: $('sg2N')?.value || 'مدير المالية', t: $('sg2T')?.value || 'اعتماد المدير المالي' },
                { n: $('sg3N')?.value || 'المدير العام', t: $('sg3T')?.value || 'اعتماد المدير العام' }
            ];
            sigsHTML = `<div class="signatures">
            ${sigs.map(sg => `
            <div class="sig-box">
                <div class="sig-line"></div>
                <div class="sig-name" style="color:${pc}">${sg.n}</div>
                <div class="sig-title">${sg.t}</div>
            </div>`).join('')}
        </div>`;
        }

        // الملاحظات
        let notesHTML = '';
        const ntVal = $('pdfNt')?.value?.trim();
        if (opts.oNts && ntVal) {
            notesHTML = `<div class="notes-box">ملاحظة: ${ntVal}</div>`;
        }

        // بناء صفحة HTML للطباعة
        const infoItems = [];
        if (ph) infoItems.push(`📞 ${ph}`);
        if (em) infoItems.push(`📧 ${em}`);
        if (ad) infoItems.push(`📍 ${ad}`);
        if (rg) infoItems.push(`س.ت: ${rg}`);
        if (vt) infoItems.push(`الرقم الضريبي: ${vt}`);

        const printHTML = `<!DOCTYPE html>
<html lang="ar" dir="rtl">
<head>
<meta charset="UTF-8">
<title>كشف حساب - ${cA}</title>
<style>
  @import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700&display=swap');
  * { margin:0; padding:0; box-sizing:border-box }
  body { font-family:'Cairo',Arial,sans-serif; direction:rtl; color:#333; font-size:10pt; background:white }
  .page-header { background:linear-gradient(135deg,${pc},${pc}cc); color:white; padding:18px 24px; display:flex; justify-content:space-between; align-items:center; margin-bottom:0 }
  .company-logo { width:50px; height:50px; background:rgba(255,255,255,0.2); border-radius:10px; display:flex; align-items:center; justify-content:center; font-size:16px; font-weight:900; letter-spacing:1px }
  .company-info { text-align:right }
  .company-name { font-size:18px; font-weight:700; margin-bottom:3px }
  .company-sub { font-size:10px; opacity:0.85 }
  .info-bar { background:#f5f7fa; padding:7px 24px; font-size:9pt; color:#555; border-bottom:1px solid #e0e0e0; text-align:center }
  .content { padding:16px 20px }
  .supplier-section { margin-bottom:24px; page-break-inside:avoid }
  .summary-box { display:flex; gap:10px; margin-bottom:12px }
  .summary-item { flex:1; background:#f8fafc; border:1px solid #e5e7eb; border-radius:6px; padding:8px 10px; text-align:center }
  .s-label { font-size:8pt; color:#888; margin-bottom:3px }
  .s-value { font-size:11pt; font-weight:700 }
  table { width:100%; border-collapse:collapse; font-size:9pt; margin-bottom:8px }
  th { padding:7px 6px; text-align:center; font-weight:600; font-size:9pt }
  td { padding:5px 6px; text-align:center; border-bottom:1px solid #f0f0f0 }
  tr:nth-child(even) { background:#fafbfc }
  .opening-row td { background:#eaf4fb; color:#506480 }
  .total-row td { font-weight:700; font-size:9.5pt }
  .signatures { display:flex; justify-content:space-around; margin-top:24px; padding-top:16px; border-top:1px solid #ddd }
  .sig-box { text-align:center; width:28% }
  .sig-line { border-top:1px solid #555; margin-bottom:6px; margin-top:30px }
  .sig-name { font-weight:700; font-size:9pt }
  .sig-title { font-size:8pt; color:#888 }
  .notes-box { margin-top:16px; background:#fff8e6; border:1px solid #f39c12; border-radius:6px; padding:8px 12px; font-size:9pt; color:#7d6400 }
  .footer { margin-top:20px; padding-top:10px; border-top:2px solid ${pc}; display:flex; justify-content:space-between; font-size:8pt; color:#999 }
  @media print {
    body { -webkit-print-color-adjust:exact; print-color-adjust:exact }
    .supplier-section { page-break-inside:avoid }
    .page-header { -webkit-print-color-adjust:exact }
  }
</style>
</head>
<body>
<div class="page-header">
  <div class="company-logo">${cE.split(' ').map(w => w[0]).join('').slice(0, 3) || 'GBR'}</div>
  <div class="company-info">
    <div class="company-name">${cA}</div>
    <div class="company-sub">كشف حساب المورد — من ${fF} إلى ${fT}</div>
    ${infoItems.length ? `<div class="company-sub" style="margin-top:3px">${infoItems.join(' | ')}</div>` : ''}
  </div>
</div>
<div class="content">
  ${suppliersHTML}
  ${sigsHTML}
  ${notesHTML}
  <div class="footer">
    <span>تاريخ الإصدار: ${today()}</span>
    <span>${cA}</span>
    <span>هذا المستند سري للاستخدام الداخلي فقط</span>
  </div>
</div>
</body>
</html>`;

        setPrg(80, 'فتح نافذة الطباعة...');

        // فتح نافذة طباعة
        const printWin = window.open('', '_blank');
        printWin.document.write(printHTML);
        printWin.document.close();

        // انتظار تحميل الخط ثم طباعة
        printWin.onload = function () {
            setTimeout(() => {
                printWin.focus();
                printWin.print();
            }, 600);
        };
        // fallback إذا لم يتحمل onload
        setTimeout(() => {
            if (!printWin.closed) {
                printWin.focus();
                printWin.print();
            }
        }, 1200);

        setPrg(100, 'تم!');
        setTimeout(() => { $('pbW').style.display = 'none'; setPrg(0, '') }, 2000);
        toast('✅ تم فتح نافذة الطباعة — اختر "حفظ كـ PDF" من إعدادات الطابعة', 'ok');

    } catch (e) {
        console.error(e);
        toast('خطأ: ' + e.message, 'er');
        $('pbW').style.display = 'none';
    }
    btn.disabled = false;
};

