// ── Helper: compute all employee financial figures ──
function empFinance(e) {
    const sal = parseFloat(e.salary) || 0;
    const house = parseFloat(e.houseAllow) || 0;
    const trans = parseFloat(e.transAllow) || 0;
    const phone = parseFloat(e.phoneAllow) || 0;
    const nature = parseFloat(e.natureAllow) || 0;
    const rep = parseFloat(e.repAllow) || 0;
    const car = parseFloat(e.carAllow) || 0;   // 🚗 بدل السيارة/إضافي — غير خاضع لخصم الغياب/التأخير، ولا يُصرف أثناء الإجازة السنوية
    const perf = parseFloat(e.perfBonus) || 0;
    const bonus = parseFloat(e.otherBonus) || 0;
    const otHours = parseFloat(e.otHours) || 0;
    const otRate = parseFloat(e.otRate) || 0;
    const ot = otHours * otRate;
    const workDaysPerMonth = parseFloat(e.workDaysPerMonth) || 26;
    const dailyHours = parseFloat(e.dailyHours) || 8;

    const grossSalary = sal + house + trans + phone + nature + rep + car + perf + bonus + ot;

    // Deductions from employee
    const socialEmpPct = parseFloat(e.socialEmp) || 0;
    const socialDeductAmt = (sal * socialEmpPct / 100);           // GOSI employee share on basic
    const advance = parseFloat(e.advanceDeduct) || 0;
    const absence = parseFloat(e.absenceDeduct) || 0;
    const late = parseFloat(e.lateDeduct) || 0;
    const penalty = parseFloat(e.penaltyDeduct) || 0;
    const loan = parseFloat(e.loanDeduct) || 0;
    const otherDeduct = parseFloat(e.otherDeduct) || 0;
    const totalDeductions = socialDeductAmt + advance + absence + late + penalty + loan + otherDeduct;

    const netSalary = grossSalary - totalDeductions;

    // 🚗 قاعدة الخصم (غياب/تأخير/أذونات) تستثني البدل غير الخاضع للخصم
    const deductibleGross = grossSalary - car;
    const deductibleNet = netSalary - car;

    // Company costs
    const socialCompPct = parseFloat(e.socialComp) || 0;
    const socialCompAmt = (sal * socialCompPct / 100);
    const medIns = parseFloat(e.medIns) || 0;
    const profIns = parseFloat(e.profIns) || 0;
    const iqamaRenew = parseFloat(e.iqamaRenew) || 0;          // annual → /12
    const sponsorship = parseFloat(e.sponsorship) || 0;          // one-off → /12
    const levyFee = parseFloat(e.levyFee) || 0;
    const airTicket = parseFloat(e.airTicket) || 0;            // annual → /12
    const vacAllow = parseFloat(e.vacAllow) || 0;             // annual → /12
    const gratuity = parseFloat(e.gratuity) || 0;
    const training = parseFloat(e.training) || 0;
    const otherCost = parseFloat(e.otherCost) || 0;

    const monthlyCosts = socialCompAmt + medIns + profIns
        + (iqamaRenew / 12) + (sponsorship / 12) + levyFee
        + (airTicket / 12) + (vacAllow / 12) + gratuity + training + otherCost;

    const totalCost = grossSalary + monthlyCosts;

    return {
        sal, house, trans, phone, nature, rep, car, perf, bonus, ot, grossSalary, deductibleGross, deductibleNet,
        socialEmpPct, socialDeductAmt, advance, absence, late, penalty, loan, otherDeduct, totalDeductions, netSalary,
        socialCompPct, socialCompAmt, medIns, profIns, iqamaRenew, sponsorship, levyFee, airTicket, vacAllow, gratuity, training, otherCost,
        monthlyCosts, totalCost, workDaysPerMonth, dailyHours
    };
}

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🏛️  [HR-GOSI]   ━━━━   GOSI ENGINE   ━━━━                               ║
// ║        محرّك التأمينات الاجتماعية — احتساب آلي وفق النظام السعودي            ║
// ╚══════════════════════════════════════════════════════════════════════════╝
// أساس الاشتراك = الراتب الأساسي + بدل السكن، بحدّ أدنى/أقصى قابلين للتعديل.
//   • سعودي:      خصم موظف (تقاعد 9% + ساند 0.75% = 9.75%) + حصة شركة (9% + 0.75% + أخطار مهنية 2% = 11.75%).
//   • غير سعودي:  لا خصم من الموظف، حصة شركة = أخطار مهنية 2% فقط.
// ⚠️ المعادلة الحالية في empFinance تحسب: sal(الأساسي) × النسبة% ÷ 100.
//    لذلك نحسب المبلغ الصحيح (على أساس الأساسي+السكن المحدود) ثم نعكسه إلى «نسبة مكافئة من الأساسي»
//    تُعطي نفس المبلغ داخل المعادلة القائمة — فلا نكسر المسيرات المحفوظة ولا نغيّر منطق الحساب.
const GOSI_DEFAULTS = { empRate: 9.75, compRate: 11.75, nonSaudiCompRate: 2, minBase: 1500, maxBase: 45000 };
window.gosiRates = { ...GOSI_DEFAULTS };

// هل الجنسية سعودية؟ (يُبنى عليه تطبيق التقاعد/ساند مقابل الأخطار المهنية فقط)
function isSaudiNat(nat) { return /^\s*(سعودي|سعوديه|سعودية|saudi|ksa)/i.test(String(nat || '')); }

// احتساب GOSI لموظف — يُرجع المبلغ الصحيح + النسبة المكافئة من الأساسي
function gosiCalc(nationality, basic, housing, rates) {
    const r = rates || window.gosiRates || GOSI_DEFAULTS;
    basic = parseFloat(basic) || 0; housing = parseFloat(housing) || 0;
    const saudi = isSaudiNat(nationality);
    // بلا راتب أساسي = لا يمكن عكس المبلغ إلى نسبة داخل المعادلة الحالية → يُتجاوَز
    if (basic <= 0) return { base: 0, isSaudi: saudi, empAmt: 0, compAmt: 0, empPct: 0, compPct: 0, empRate: 0, compRate: 0 };
    let base = basic + housing;
    if (base < (r.minBase || 0)) base = r.minBase || 0;
    if (r.maxBase && base > r.maxBase) base = r.maxBase;
    const empRate = saudi ? (r.empRate || 0) : 0;
    const compRate = saudi ? (r.compRate || 0) : (r.nonSaudiCompRate || 0);
    const empAmt = base * empRate / 100;
    const compAmt = base * compRate / 100;
    // عكس المبلغ إلى نسبة من الأساسي (المعادلة الحالية تضربها في الأساسي)
    const empPct = basic > 0 ? +(empAmt / basic * 100).toFixed(4) : 0;
    const compPct = basic > 0 ? +(compAmt / basic * 100).toFixed(4) : 0;
    return { base, isSaudi: saudi, empAmt, compAmt, empPct, compPct, empRate, compRate };
}
window.gosiCalc = gosiCalc;

// زر داخل نموذج الموظف: احتساب GOSI من قيم النموذج الحالية
window.autoFillGosiEmp = function () {
    const basic = parseFloat($('eSalary')?.value) || 0;
    if (basic <= 0) { toast('أدخل الراتب الأساسي أولاً لاحتساب GOSI', 'er'); return; }
    const g = gosiCalc($('eNat')?.value, basic, $('eHouseAllow')?.value);
    if ($('eSocialEmp')) $('eSocialEmp').value = g.empPct;
    if ($('eSocialComp')) $('eSocialComp').value = g.compPct;
    if (typeof calcEmpSummary === 'function') calcEmpSummary();
    toast(`GOSI (${g.isSaudi ? 'سعودي' : 'غير سعودي'}) — أساس ${fmt(g.base)}: خصم موظف ${fmt(g.empAmt)} / شركة ${fmt(g.compAmt)}`, 'ok');
};

// قراءة النِسَب من حقول مودال الاحتساب الجماعي
function gosiRatesFromForm() {
    return {
        empRate: parseFloat($('gbEmpRate')?.value) || 0,
        compRate: parseFloat($('gbCompRate')?.value) || 0,
        nonSaudiCompRate: parseFloat($('gbNonSaudiRate')?.value) || 0,
        minBase: parseFloat($('gbMinBase')?.value) || 0,
        maxBase: parseFloat($('gbMaxBase')?.value) || 0
    };
}

// فتح مودال الاحتساب الجماعي
window.openGosiBulk = function () {
    const r = window.gosiRates || GOSI_DEFAULTS;
    if ($('gbEmpRate')) $('gbEmpRate').value = r.empRate;
    if ($('gbCompRate')) $('gbCompRate').value = r.compRate;
    if ($('gbNonSaudiRate')) $('gbNonSaudiRate').value = r.nonSaudiCompRate;
    if ($('gbMinBase')) $('gbMinBase').value = r.minBase;
    if ($('gbMaxBase')) $('gbMaxBase').value = r.maxBase;
    renderGosiPreview();
    ov('ovGosiBulk');
};

// إعادة بناء جدول المعاينة (يُستدعى عند تغيير أي نسبة)
window.renderGosiPreview = function () {
    const rates = gosiRatesFromForm();
    const onlyActive = $('gbOnlyActive')?.checked;
    const list = Object.entries(emp).filter(([, e]) => !onlyActive || (e.status || 'active') === 'active');
    let totEmp = 0, totComp = 0, noBasic = 0;
    const rows = list.map(([, e]) => {
        const basic = parseFloat(e.salary) || 0;
        const g = gosiCalc(e.nationality, basic, e.houseAllow, rates);
        totEmp += g.empAmt; totComp += g.compAmt;
        if (basic <= 0) noBasic++;
        const curEmp = parseFloat(e.socialEmp) || 0;
        const changed = Math.abs(curEmp - g.empPct) > 0.01;
        return `<tr style="${basic <= 0 ? 'opacity:.45' : ''}">
            <td style="padding:5px 8px;border-bottom:1px solid #f0f0f0">${e.name || '-'}</td>
            <td style="padding:5px 8px;text-align:center;border-bottom:1px solid #f0f0f0">${g.isSaudi ? '🇸🇦 سعودي' : (e.nationality || '—')}</td>
            <td style="padding:5px 8px;text-align:left;border-bottom:1px solid #f0f0f0">${fmt(basic)}</td>
            <td style="padding:5px 8px;text-align:left;border-bottom:1px solid #f0f0f0">${fmt(g.base)}</td>
            <td style="padding:5px 8px;text-align:left;color:#c0392b;border-bottom:1px solid #f0f0f0">${fmt(g.empAmt)}</td>
            <td style="padding:5px 8px;text-align:left;color:#e67e22;border-bottom:1px solid #f0f0f0">${fmt(g.compAmt)}</td>
            <td style="padding:5px 8px;text-align:center;color:#999;font-size:11px;border-bottom:1px solid #f0f0f0">${curEmp.toFixed(2)} ← <b style="color:${changed ? '#1a3a5c' : '#bbb'}">${g.empPct.toFixed(2)}%</b></td>
        </tr>`;
    }).join('');
    if ($('gbPreviewBody')) $('gbPreviewBody').innerHTML = rows || '<tr><td colspan="7" style="padding:14px;text-align:center;color:#999">لا يوجد موظفون</td></tr>';
    if ($('gbTotals')) $('gbTotals').innerHTML = `العدد: <b>${list.length}</b> · إجمالي خصم الموظفين: <b style="color:#c0392b">${fmt(totEmp)}</b> · إجمالي حصة الشركة: <b style="color:#e67e22">${fmt(totComp)}</b>${noBasic ? ` · <span style="color:#c0392b">${noBasic} بلا راتب أساسي (تُتجاوز)</span>` : ''}`;
};

// تطبيق الاحتساب على كل الموظفين + حفظ النِسَب كإعداد
window.applyGosiBulk = async function () {
    const rates = gosiRatesFromForm();
    const onlyActive = $('gbOnlyActive')?.checked;
    const updates = {}; let n = 0;
    Object.entries(emp).forEach(([k, e]) => {
        if (onlyActive && (e.status || 'active') !== 'active') return;
        const g = gosiCalc(e.nationality, e.salary, e.houseAllow, rates);
        updates[`${k}/socialEmp`] = g.empPct;
        updates[`${k}/socialComp`] = g.compPct;
        n++;
    });
    try {
        await update(R.emp, updates);
        await set(ref(db, 'ledger/settings/gosi'), rates);
        window.gosiRates = { ...rates };
        toast(`✅ تم احتساب GOSI لـ ${n} موظف وحفظ النِسَب`, 'ok');
        cov('ovGosiBulk');
    } catch (err) { toast('خطأ: ' + err.message, 'er'); }
};

function updateEmpKPIs() {
    const ea = Object.values(emp);
    const active = ea.filter(e => (e.status || 'active') === 'active');
    const inactive = ea.filter(e => e.status === 'inactive').length;
    let totalNet = 0, totalCost = 0, totalDeduct = 0;
    active.forEach(e => {
        const f = empFinance(e);
        totalNet += f.netSalary;
        totalCost += f.totalCost;
        totalDeduct += f.totalDeductions;
    });
    $('ek1').textContent = ea.length;
    $('ek2').textContent = active.length;
    $('ek3').textContent = inactive;
    $('ek4').textContent = fmt(totalNet);
    $('ek5').textContent = fmt(totalCost);
    $('ek6').textContent = fmt(totalDeduct);
}

function updateDeptFilter() {
    const depts = [...new Set(Object.values(emp).map(e => e.dept).filter(Boolean))].sort();
    const sel = $('empDeptFilter'); const cur = sel.value;
    sel.innerHTML = '<option value="">-- جميع الأقسام --</option>';
    depts.forEach(d => sel.innerHTML += `<option value="${d}">${d}</option>`);
    if (cur) sel.value = cur;
    const dl = $('deptsList'); if (dl) { dl.innerHTML = ''; depts.forEach(d => { const o = document.createElement('option'); o.value = d; dl.appendChild(o) }) }
    // فلتر المشاريع
    const projSel = $('empProjectFilter');
    if (projSel) {
        const curProj = projSel.value;
        // المشاريع التي بها موظفون
        const projectIds = [...new Set(Object.values(emp).map(e => e.projectId).filter(Boolean))];
        projSel.innerHTML = '<option value="">-- جميع المشاريع --</option>';
        projectIds.forEach(pid => {
            const name = (typeof projects !== 'undefined' && projects[pid]?.name) || 'مشروع';
            projSel.innerHTML += `<option value="${pid}">${name}</option>`;
        });
        if (curProj) projSel.value = curProj;
    }
}

window.empTab = function (id, btn) {
    document.querySelectorAll('#mEmp .pt-pane').forEach(p => p.classList.remove('act'));
    document.querySelectorAll('#mEmp .pt-btn').forEach(b => b.classList.remove('act'));
    $(id).classList.add('act'); btn.classList.add('act');
};

window.calcEmpSummary = function () {
    const e = {
        salary: $('eSalary')?.value || 0, houseAllow: $('eHouseAllow')?.value || 0,
        transAllow: $('eTransAllow')?.value || 0, phoneAllow: $('ePhoneAllow')?.value || 0,
        natureAllow: $('eNatureAllow')?.value || 0, repAllow: $('eRepAllow')?.value || 0,
        perfBonus: $('ePerfBonus')?.value || 0, otherBonus: $('eOtherBonus')?.value || 0,
        otHours: $('eOTHours')?.value || 0, otRate: $('eOTRate')?.value || 0,
        socialComp: $('eSocialComp')?.value || 0, socialEmp: $('eSocialEmp')?.value || 0,
        medIns: $('eMedIns')?.value || 0, profIns: $('eProfIns')?.value || 0,
        iqamaRenew: $('eIqamaRenew')?.value || 0, sponsorship: $('eSponsorship')?.value || 0,
        levyFee: $('eLevyFee')?.value || 0, airTicket: $('eAirTicket')?.value || 0,
        vacAllow: $('eVacAllow')?.value || 0, gratuity: $('eGratuity')?.value || 0,
        training: $('eTraining')?.value || 0, otherCost: $('eOtherCost')?.value || 0,
        advanceDeduct: $('eAdvanceDeduct')?.value || 0, absenceDeduct: $('eAbsenceDeduct')?.value || 0,
        lateDeduct: $('eLateDeduct')?.value || 0, penaltyDeduct: $('ePenaltyDeduct')?.value || 0,
        loanDeduct: $('eLoanDeduct')?.value || 0, otherDeduct: $('eOtherDeduct')?.value || 0,
    };
    const f = empFinance(e);
    // Update disabled social deduct field
    if ($('eSocialDeduct')) $('eSocialDeduct').value = f.socialDeductAmt.toFixed(2);

    // Salary summary rows
    const salRows = [
        { l: 'الراتب الأساسي', v: f.sal, c: '#1a3a5c' },
        f.house > 0 ? { l: 'بدل السكن', v: f.house } : null,
        f.trans > 0 ? { l: 'بدل المواصلات', v: f.trans } : null,
        f.phone > 0 ? { l: 'بدل الاتصالات', v: f.phone } : null,
        f.nature > 0 ? { l: 'بدل الطبيعة / الخطورة', v: f.nature } : null,
        f.rep > 0 ? { l: 'بدل التمثيل', v: f.rep } : null,
        f.car > 0 ? { l: 'بدل السيارة / إضافي (غير خاضع للخصم)', v: f.car, c: '#e67e22' } : null,
        f.perf > 0 ? { l: 'مكافأة الأداء', v: f.perf } : null,
        f.bonus > 0 ? { l: 'مكافأة أخرى', v: f.bonus } : null,
        f.ot > 0 ? { l: `عمل إضافي (${f.ot > 0 ? parseFloat($('eOTHours')?.value || 0).toFixed(1) : 0} ساعة)`, v: f.ot } : null,
    ].filter(Boolean);
    const deductRows = [
        f.socialDeductAmt > 0 ? { l: `تأمينات اجتماعية موظف (${f.socialEmpPct}%)`, v: -f.socialDeductAmt, c: '#e74c3c' } : null,
        f.advance > 0 ? { l: 'سلفة / مقدمة', v: -f.advance, c: '#e74c3c' } : null,
        f.absence > 0 ? { l: 'خصم غياب', v: -f.absence, c: '#e74c3c' } : null,
        f.late > 0 ? { l: 'خصم تأخير', v: -f.late, c: '#e74c3c' } : null,
        f.penalty > 0 ? { l: 'مخالفات وجزاءات', v: -f.penalty, c: '#e74c3c' } : null,
        f.loan > 0 ? { l: 'قسط قرض', v: -f.loan, c: '#e74c3c' } : null,
        f.otherDeduct > 0 ? { l: 'خصومات أخرى', v: -f.otherDeduct, c: '#e74c3c' } : null,
    ].filter(Boolean);

    let html = salRows.map(r => `<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid #f0f0f0"><span style="color:#555">${r.l}</span><span style="font-weight:600;color:${r.c || '#27ae60'}">${fmt(r.v)}</span></div>`).join('');
    html += `<div style="display:flex;justify-content:space-between;padding:6px 0;margin-top:4px;background:#e8f5e9;border-radius:6px;padding:8px 10px"><span style="font-weight:700;color:#1a3a5c">إجمالي الراتب</span><span style="font-weight:800;color:#27ae60;font-size:15px">${fmt(f.grossSalary)}</span></div>`;
    if (deductRows.length) {
        html += '<div style="margin-top:10px;font-size:12px;font-weight:700;color:#e74c3c;margin-bottom:4px">✂️ الخصومات</div>';
        html += deductRows.map(r => `<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid #ffeaea"><span style="color:#555">${r.l}</span><span style="font-weight:600;color:${r.c || '#e74c3c'}">${fmt(r.v)}</span></div>`).join('');
    }
    html += `<div style="display:flex;justify-content:space-between;margin-top:8px;background:#1a3a5c;color:white;border-radius:8px;padding:10px 12px"><span style="font-weight:700">💵 الراتب الصافي</span><span style="font-weight:800;font-size:16px">${fmt(f.netSalary)}</span></div>`;
    const dh = parseFloat($('eDailyHours')?.value) || 8;
    // أيام الشهر الحالي الفعلية + أيام الراحة
    const nowD = new Date();
    const currentMonth = `${nowD.getFullYear()}-${String(nowD.getMonth()+1).padStart(2,'0')}`;
    const monthDays = getMonthTotalDays(currentMonth);
    let weekendCount = 0;
    for (let d = 1; d <= monthDays; d++) {
        const dow = new Date(nowD.getFullYear(), nowD.getMonth(), d).getDay();
        if (dow === 5 || dow === 6) weekendCount++;
    }
    const workingExpected = monthDays - weekendCount;
    // قيمة اليوم/الساعة تُحسب على القاعدة الخاضعة للخصم (تستثني بدل السيارة/الإضافي)
    const dailyRate = monthDays > 0 ? f.deductibleNet / monthDays : 0;
    const hourlyRate = workingExpected > 0 ? f.deductibleNet / (workingExpected * dh) : 0;
    const monthName = ['يناير','فبراير','مارس','أبريل','مايو','يونيو','يوليو','أغسطس','سبتمبر','أكتوبر','نوفمبر','ديسمبر'][nowD.getMonth()];
    html += `<div style="margin-top:8px;background:#f0f8ff;border-radius:8px;padding:10px 12px;font-size:12px;color:#2d6a9f">
        <div style="font-size:10px;color:#888;text-align:center;margin-bottom:6px">📅 الاحتساب لشهر ${monthName} (${monthDays} يوم — ${workingExpected} عمل + ${weekendCount} راحة أسبوعية)</div>
        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;text-align:center">
            <div><div style="font-size:10px;color:#888">ساعات الدوام/يوم</div><div style="font-weight:700">${dh} س</div></div>
            <div><div style="font-size:10px;color:#888">قيمة اليوم</div><div style="font-weight:700">${fmt(dailyRate)} ر</div></div>
            <div><div style="font-size:10px;color:#888">قيمة الساعة</div><div style="font-weight:700">${fmt(hourlyRate)} ر</div></div>
        </div>
    </div>`;
    if ($('empSalRows')) $('empSalRows').innerHTML = html;

    // Cost summary rows
    const costRows = [
        { l: 'إجمالي الراتب (يدفعه الموظف)', v: f.grossSalary, c: '#1a3a5c' },
        f.socialCompAmt > 0 ? { l: `تأمينات اجتماعية شركة (${f.socialCompPct}%)`, v: f.socialCompAmt } : null,
        f.medIns > 0 ? { l: 'التأمين الطبي', v: f.medIns } : null,
        f.profIns > 0 ? { l: 'تأمين المسؤولية المهنية', v: f.profIns } : null,
        f.iqamaRenew > 0 ? { l: 'تجديد الإقامة (شهرياً)', v: f.iqamaRenew / 12 } : null,
        f.sponsorship > 0 ? { l: 'نقل الكفالة (شهرياً)', v: f.sponsorship / 12 } : null,
        f.levyFee > 0 ? { l: 'رسوم العمالة الوافدة', v: f.levyFee } : null,
        f.airTicket > 0 ? { l: 'تذكرة السفر (شهرياً)', v: f.airTicket / 12 } : null,
        f.vacAllow > 0 ? { l: 'بدل الإجازة (شهرياً)', v: f.vacAllow / 12 } : null,
        f.gratuity > 0 ? { l: 'مخصص نهاية الخدمة', v: f.gratuity } : null,
        f.training > 0 ? { l: 'تدريب وتأهيل', v: f.training } : null,
        f.otherCost > 0 ? { l: 'تكاليف أخرى', v: f.otherCost } : null,
    ].filter(Boolean);

    let chtml = costRows.map(r => `<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid #f0f0f0"><span style="color:#555">${r.l}</span><span style="font-weight:600;color:${r.c || '#f39c12'}">${fmt(r.v)}</span></div>`).join('');
    chtml += `<div style="display:flex;justify-content:space-between;margin-top:8px;background:#e67e22;color:white;border-radius:8px;padding:10px 12px"><span style="font-weight:700">🏢 إجمالي تكلفة الموظف على الشركة</span><span style="font-weight:800;font-size:16px">${fmt(f.totalCost)}</span></div>`;
    if ($('empCostRows')) $('empCostRows').innerHTML = chtml;
};

window.renderEmps = function () {
    if (!$('pg-employees').classList.contains('act')) return;
    const search = ($('empSearch')?.value || '').toLowerCase();
    const deptF = $('empDeptFilter')?.value || '';
    const projectF = $('empProjectFilter')?.value || '';
    const statusF = $('empStatusFilter')?.value || '';
    let items = Object.entries(emp);
    if (search) items = items.filter(([, e]) => (e.name || '').toLowerCase().includes(search) || (e.job || '').toLowerCase().includes(search) || (e.empId || '').toLowerCase().includes(search));
    if (deptF) items = items.filter(([, e]) => e.dept === deptF);
    if (projectF) items = items.filter(([, e]) => e.projectId === projectF);
    if (statusF) items = items.filter(([, e]) => (e.status || 'active') === statusF);
    items.sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar'));
    if (!items.length) { $('empL').innerHTML = '<div class="empty"><div class="ei">👷</div><p>لا توجد نتائج</p></div>'; return }
    const canEdit = myP?.role === 'admin' || can('edit_supplier');
    $('empL').innerHTML = `<table class="st">
        <thead><tr>
            <th>#</th><th>الموظف</th><th>الوظيفة</th><th>التبعية</th><th>الراتب الإجمالي</th>
            <th>إجمالي الخصومات</th><th>الراتب الصافي</th><th>تكلفة الشركة</th><th>الحالة</th><th>إجراءات</th>
        </tr></thead>
        <tbody>
        ${items.map(([k, e], i) => {
        const f = empFinance(e);
        const isActive = (e.status || 'active') === 'active';
        const statusBadge = isActive
            ? '<span style="background:#d4edda;color:#155724;padding:3px 10px;border-radius:12px;font-size:11px;font-weight:700">✅ نشط</span>'
            : '<span style="background:#f8d7da;color:#721c24;padding:3px 10px;border-radius:12px;font-size:11px;font-weight:700">⏸️ موقوف</span>';
        const av = avCol(e.name || '');
        // Iqama expiry warning
        let iqamaWarn = '';
        if (e.iqamaExp) {
            const daysLeft = Math.ceil((new Date(e.iqamaExp) - new Date()) / 86400000);
            if (daysLeft <= 30) iqamaWarn = ` <span title="الإقامة تنتهي خلال ${daysLeft} يوم" style="color:#e74c3c;font-size:11px">⚠️${daysLeft}د</span>`;
        }
        const affDisplay = e.affiliationType === 'project' && e.projectId
            ? `<span style="background:#fef5e7;color:#7d4e00;padding:2px 8px;border-radius:10px;font-size:11px">📁 ${esc(e.projectName || (projects && projects[e.projectId]?.name) || 'مشروع')}</span>`
            : e.dept ? `<span style="background:#e8f4fd;color:#1a5276;padding:2px 8px;border-radius:10px;font-size:11px">🏢 ${esc(e.dept)}</span>` : '-';
        return `<tr>
                <td style="font-weight:700;color:#888">${i + 1}</td>
                <td><div style="display:flex;align-items:center;gap:8px">
                    <div style="width:32px;height:32px;border-radius:50%;background:${av};color:white;display:flex;align-items:center;justify-content:center;font-weight:700;font-size:13px;flex-shrink:0">${esc((e.name || '?').charAt(0))}</div>
                    <div><div style="font-weight:600;color:#1a3a5c">${esc(e.name) || '-'}${iqamaWarn}</div><div style="font-size:11px;color:#888">${esc(e.empId) || ''}${e.hireDate ? ' | ' + esc(e.hireDate) : ''}</div></div>
                </div></td>
                <td>${esc(e.job) || '-'}</td>
                <td>${affDisplay}</td>
                <td style="font-weight:700;color:#2d6a9f">${fmt(f.grossSalary)}</td>
                <td style="font-weight:700;color:#e74c3c">${f.totalDeductions > 0 ? '(' + fmt(f.totalDeductions) + ')' : '-'}</td>
                <td style="font-weight:800;color:#27ae60">${fmt(f.netSalary)}</td>
                <td style="font-weight:700;color:#e67e22">${fmt(f.totalCost)}</td>
                <td>${statusBadge}</td>
                <td><div style="display:flex;gap:4px;justify-content:center">
                    <button class="btn b-b" style="padding:4px 8px;font-size:11px" onclick="openEmpM('${k}')">✏️</button>
                    <button class="btn b-o" style="padding:4px 8px;font-size:11px" onclick="viewEmp('${k}')">👁️</button>
                    ${canEdit ? `<button class="btn b-r" style="padding:4px 8px;font-size:11px" onclick="delEmp('${k}')">🗑️</button>` : ''}
                </div></td>
            </tr>`;
    }).join('')}
        </tbody>
    </table>`;
};

// ──── تبعية الموظف (إدارة / مشروع) ────────
window.toggleAffiliationType = function () {
    const type = $('eAffiliationType')?.value || 'dept';
    const deptWrap = $('eDeptWrap');
    const projWrap = $('eProjectWrap');
    if (deptWrap && projWrap) {
        if (type === 'project') {
            deptWrap.style.display = 'none';
            projWrap.style.display = '';
            fillEmpProjectsSelect();
        } else {
            deptWrap.style.display = '';
            projWrap.style.display = 'none';
        }
    }
};

window.fillEmpProjectsSelect = function () {
    const sel = $('eProjectId'); if (!sel) return;
    const cur = sel.value;
    sel.innerHTML = '<option value="">-- اختر مشروعاً --</option>';
    // أضف فقط المشاريع النشطة
    Object.entries(projects || {})
        .filter(([, p]) => p && (p.status || 'active') !== 'closed' && (p.status || 'active') !== 'archived')
        .sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar'))
        .forEach(([k, p]) => { sel.innerHTML += `<option value="${esc(k)}">${esc(p.name || k)}</option>`; });
    if (cur) sel.value = cur;
};

window.openEmpM = function (key = null) {
    $('mEmpK').value = key || '';
    $('mEmpT').textContent = key ? '✏️ تعديل الموظف' : '👷 إضافة موظف جديد';
    // Reset tab to first
    document.querySelectorAll('#mEmp .pt-pane').forEach(p => p.classList.remove('act'));
    document.querySelectorAll('#mEmp .pt-btn').forEach(b => b.classList.remove('act'));
    $('et1').classList.add('act');
    document.querySelectorAll('#mEmp .pt-btn')[0].classList.add('act');

    const numFields = ['eSalary', 'eHouseAllow', 'eTransAllow', 'ePhoneAllow', 'eNatureAllow', 'eRepAllow', 'eCarAllow', 'ePerfBonus', 'eOtherBonus', 'eOTHours', 'eOTRate',
        'eSocialComp', 'eSocialEmp', 'eMedIns', 'eProfIns', 'eIqamaRenew', 'eSponsorship', 'eLevyFee', 'eAirTicket', 'eVacAllow', 'eGratuity', 'eTraining', 'eOtherCost',
        'eAdvanceDeduct', 'eAbsenceDeduct', 'eLateDeduct', 'ePenaltyDeduct', 'eLoanDeduct', 'eOtherDeduct', 'eDailyHours', 'eWorkDays'];
    const txtFields = ['eNm', 'eId', 'eJob', 'eDept', 'eNat', 'eNatId', 'ePhone', 'eEmail', 'eIban', 'eNotes'];

    if (key && emp[key]) {
        const e = emp[key];
        const fMap = { eNm: 'name', eId: 'empId', eJob: 'job', eDept: 'dept', eNat: 'nationality', eNatId: 'natId', ePhone: 'phone', eEmail: 'email', eIban: 'iban', eNotes: 'notes' };
        // اضمن أن قائمة الإدارات معبأة قبل وضع قيمة eDept
        fillDeptDatalist();
        txtFields.forEach(f => {
            if (f === 'eDept' && e.dept) {
                // إذا الإدارة المحفوظة غير موجودة في القائمة، أضفها كخيار يدوي
                const sel = $('eDept');
                if (sel && !Array.from(sel.options).some(o => o.value === e.dept)) {
                    const opt = document.createElement('option');
                    opt.value = e.dept; opt.textContent = e.dept + ' (غير مسجلة)';
                    sel.appendChild(opt);
                }
                if (sel) sel.value = e.dept;
            } else {
                $(f).value = e[fMap[f]] || '';
            }
        });
        $('eHireDate').value = e.hireDate || '';
        $('eIqamaExp').value = e.iqamaExp || '';
        $('eContractEnd').value = e.contractEnd || '';
        $('eStatus').value = e.status || 'active';
        if ($('eLvAnnual')) $('eLvAnnual').value = e.leaveAnnual ?? 21;
        if ($('eLvSick')) $('eLvSick').value = e.leaveSick ?? 30;
        if ($('eLvEmergency')) $('eLvEmergency').value = e.leaveEmergency ?? 5;
        // التبعية
        fillEmpProjectsSelect();
        if ($('eAffiliationType')) {
            $('eAffiliationType').value = e.affiliationType || (e.projectId ? 'project' : 'dept');
            if ($('eProjectId')) $('eProjectId').value = e.projectId || '';
            toggleAffiliationType();
        }
        const nMap = {
            eSalary: 'salary', eHouseAllow: 'houseAllow', eTransAllow: 'transAllow', ePhoneAllow: 'phoneAllow', eNatureAllow: 'natureAllow', eRepAllow: 'repAllow', eCarAllow: 'carAllow',
            ePerfBonus: 'perfBonus', eOtherBonus: 'otherBonus', eOTHours: 'otHours', eOTRate: 'otRate',
            eSocialComp: 'socialComp', eSocialEmp: 'socialEmp', eMedIns: 'medIns', eProfIns: 'profIns',
            eIqamaRenew: 'iqamaRenew', eSponsorship: 'sponsorship', eLevyFee: 'levyFee', eAirTicket: 'airTicket',
            eVacAllow: 'vacAllow', eGratuity: 'gratuity', eTraining: 'training', eOtherCost: 'otherCost',
            eAdvanceDeduct: 'advanceDeduct', eAbsenceDeduct: 'absenceDeduct', eLateDeduct: 'lateDeduct',
            ePenaltyDeduct: 'penaltyDeduct', eLoanDeduct: 'loanDeduct', eOtherDeduct: 'otherDeduct',
            eDailyHours: 'dailyHours', eWorkDays: 'workDaysPerMonth'
        };
        numFields.forEach(f => { $(f).value = e[nMap[f]] || 0 });
    } else {
        fillDeptDatalist();
        txtFields.forEach(f => $(f).value = '');
        numFields.forEach(f => $(f).value = 0);
        $('eHireDate').value = today();
        $('eIqamaExp').value = '';
        if ($('eContractEnd')) $('eContractEnd').value = '';
        $('eStatus').value = 'active';
        if ($('eLvAnnual')) $('eLvAnnual').value = 21;
        if ($('eLvSick')) $('eLvSick').value = 30;
        if ($('eLvEmergency')) $('eLvEmergency').value = 5;
        if ($('eDailyHours')) $('eDailyHours').value = 8;
        if ($('eWorkDays')) $('eWorkDays').value = 26;
        fillEmpProjectsSelect();
        if ($('eAffiliationType')) { $('eAffiliationType').value = 'dept'; toggleAffiliationType(); }
    }
    // ملء قائمة المستخدمين للربط
    const userSel = $('eUserId');
    if (userSel) {
        const currentLinkedUid = key && emp[key]?.userId || '';
        // اجلب الموظفين الآخرين المرتبطين بمستخدمين (لتجنبهم)
        const usedUids = new Set();
        Object.entries(emp).forEach(([k, e]) => { if (k !== key && e.userId) usedUids.add(e.userId); });
        userSel.innerHTML = '<option value="">-- بدون ربط (لا يستطيع تسجيل حضوره بنفسه) --</option>';
        Object.entries(us).sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar'))
            .forEach(([uid, u]) => {
                const isUsed = usedUids.has(uid);
                userSel.innerHTML += `<option value="${uid}" ${isUsed?'disabled':''}>${u.name || u.email} ${isUsed ? '⛔ (مرتبط بموظف آخر)' : ''}</option>`;
            });
        userSel.value = currentLinkedUid;
    }

    calcEmpSummary();
    // تحميل بيانات التبويبات الإضافية
    const curKey = $('mEmpK').value;
    if (curKey) { loadEmpMonthlyDeductions(curKey); loadEmpLoans(curKey); loadEmpDocuments(curKey); loadEmpLeaves(curKey); calcLeaveBalances(); loadEmpPerformance(curKey); initPerfMonth(); }
    else { $('mdList') && ($('mdList').innerHTML = '<div style="text-align:center;padding:20px;color:#aaa;font-size:13px">احفظ الموظف أولاً لإضافة خصومات</div>'); $('loanList') && ($('loanList').innerHTML = '<div style="text-align:center;padding:20px;color:#aaa;font-size:13px">احفظ الموظف أولاً لإضافة سلف</div>'); $('docList') && ($('docList').innerHTML = '<div style="text-align:center;padding:20px;color:#aaa;font-size:13px">احفظ الموظف أولاً لرفع المستندات</div>'); $('leaveList') && ($('leaveList').innerHTML = '<div style="text-align:center;padding:20px;color:#aaa;font-size:13px">احفظ الموظف أولاً لتسجيل الإجازات</div>'); $('perfList') && ($('perfList').innerHTML = '<div style="text-align:center;padding:20px;color:#aaa;font-size:13px">احفظ الموظف أولاً لإضافة التقييمات</div>'); }
    ov('mEmp');
};

window.saveEmp = async function () {
    const nm = $('eNm').value.trim(); if (!nm) { toast('اسم الموظف مطلوب', 'er'); return }
    const job = $('eJob').value.trim(); if (!job) { toast('المسمى الوظيفي مطلوب', 'er'); return }

    // التحقق من التبعية الإلزامية
    const affType = $('eAffiliationType')?.value || 'dept';
    const deptVal = $('eDept').value.trim();
    const projectId = $('eProjectId')?.value || '';
    if (affType === 'dept' && !deptVal) {
        toast('⚠️ اختر الإدارة/القسم — التبعية إلزامية', 'er');
        empTab('et1', document.querySelector('#mEmp .pt-btn'));
        $('eDept').focus();
        return;
    }
    if (affType === 'project' && !projectId) {
        toast('⚠️ اختر المشروع — التبعية إلزامية', 'er');
        empTab('et1', document.querySelector('#mEmp .pt-btn'));
        $('eProjectId').focus();
        return;
    }

    const key = $('mEmpK').value;
    const n = id => parseFloat($(id)?.value) || 0;
    // اسم المشروع للعرض السهل
    const projectName = projectId && (typeof projects !== 'undefined' && projects[projectId])
        ? (projects[projectId].name || '')
        : '';
    const data = {
        name: nm, empId: $('eId').value.trim(), job,
        affiliationType: affType,
        dept: affType === 'dept' ? deptVal : '',
        projectId: affType === 'project' ? projectId : '',
        projectName: affType === 'project' ? projectName : '',
        nationality: $('eNat').value.trim(),
        natId: $('eNatId').value.trim(), phone: $('ePhone').value.trim(),
        email: $('eEmail').value.trim(), hireDate: $('eHireDate').value,
        iqamaExp: $('eIqamaExp').value,
        contractEnd: $('eContractEnd')?.value || '',
        leaveAnnual: parseFloat($('eLvAnnual')?.value) || 21,
        leaveSick: parseFloat($('eLvSick')?.value) || 30,
        leaveEmergency: parseFloat($('eLvEmergency')?.value) || 5,
        iban: $('eIban').value.trim(), notes: $('eNotes').value.trim(),
        userId: $('eUserId')?.value || '',
        status: $('eStatus').value,
        // Salary & Allowances
        salary: n('eSalary'), houseAllow: n('eHouseAllow'), transAllow: n('eTransAllow'),
        phoneAllow: n('ePhoneAllow'), natureAllow: n('eNatureAllow'), repAllow: n('eRepAllow'),
        carAllow: n('eCarAllow'),
        perfBonus: n('ePerfBonus'), otherBonus: n('eOtherBonus'),
        otHours: n('eOTHours'), otRate: n('eOTRate'),
        // Insurance & Fees
        socialComp: n('eSocialComp'), socialEmp: n('eSocialEmp'),
        medIns: n('eMedIns'), profIns: n('eProfIns'),
        iqamaRenew: n('eIqamaRenew'), sponsorship: n('eSponsorship'),
        levyFee: n('eLevyFee'), airTicket: n('eAirTicket'),
        vacAllow: n('eVacAllow'), gratuity: n('eGratuity'),
        training: n('eTraining'), otherCost: n('eOtherCost'),
        // Deductions
        advanceDeduct: n('eAdvanceDeduct'), absenceDeduct: n('eAbsenceDeduct'),
        lateDeduct: n('eLateDeduct'), penaltyDeduct: n('ePenaltyDeduct'),
        loanDeduct: n('eLoanDeduct'), otherDeduct: n('eOtherDeduct'),
        dailyHours: n('eDailyHours') || 8,
        workDaysPerMonth: n('eWorkDays') || 26,
        updatedAt: new Date().toISOString()
    };
    try {
        if (key) {
            // 🕓 توثيق تغيّر الراتب (Salary Revision History) قبل الحفظ
            const oldE = emp[key] || {};
            const oldGross = empFinance(oldE).grossSalary;
            const newGross = empFinance(data).grossSalary;
            const oldBasic = parseFloat(oldE.salary) || 0, newBasic = parseFloat(data.salary) || 0;
            if (Math.abs(oldGross - newGross) > 0.001 || Math.abs(oldBasic - newBasic) > 0.001) {
                const rev = { date: new Date().toISOString().slice(0, 10), at: new Date().toISOString(), byName: myP?.name || curU?.email || '', oldBasic, newBasic, oldGross, newGross, diff: parseFloat((newGross - oldGross).toFixed(2)) };
                await push(ref(db, 'ledger/employees/' + key + '/salaryRevisions'), rev);
            }
            await update(ref(db, 'ledger/employees/' + key), data); toast('✅ تم تحديث الموظف', 'ok');
        }
        else { data.createdAt = new Date().toISOString(); await push(R.emp, data); toast('✅ تم إضافة الموظف', 'ok') }
        cov('mEmp');
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

window.delEmp = function (key) {
    cf2('هل تريد حذف هذا الموظف نهائياً؟', async () => {
        try { await remove(ref(db, 'ledger/employees/' + key)); toast('🗑️ تم الحذف', 'ok') }
        catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

window.viewEmp = function (key) {
    const e = emp[key]; if (!e) return;
    const f = empFinance(e);
    const av = avCol(e.name || '');
    const row = (l, v, c = '#333') => v ? `<tr><td style="color:#888;padding:6px 10px;border-bottom:1px solid #f5f5f5;font-size:12px;white-space:nowrap">${l}</td><td style="font-weight:600;color:${c};padding:6px 10px;border-bottom:1px solid #f5f5f5;font-size:12px">${v}</td></tr>` : '';
    const sec = (title, bg = '#f8fafc') => `<tr><td colspan="2" style="background:${bg};font-weight:700;padding:8px 10px;font-size:12px;color:#1a3a5c">${title}</td></tr>`;
    const win = window.open('', '_blank');
    win.document.write(`<!DOCTYPE html><html lang="ar" dir="rtl"><head><meta charset="UTF-8"><title>ملف الموظف - ${e.name || ''}</title>
<style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',Tahoma,sans-serif;background:#f0f2f5;color:#333;direction:rtl;padding:16px}
.wrap{max-width:640px;margin:0 auto}.hd{background:linear-gradient(135deg,#1a3a5c,#2d6a9f);color:white;border-radius:14px 14px 0 0;padding:20px 24px;display:flex;align-items:center;gap:16px}
.av{width:60px;height:60px;border-radius:50%;background:${av};color:white;display:flex;align-items:center;justify-content:center;font-size:26px;font-weight:700;flex-shrink:0;border:3px solid rgba(255,255,255,.3)}
.nm{font-size:20px;font-weight:800}.jb{font-size:12px;opacity:.8;margin-top:3px}
.bd{background:white;border-radius:0 0 14px 14px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,.1)}
table{width:100%;border-collapse:collapse}
.fin-grid{display:grid;grid-template-columns:1fr 1fr 1fr;gap:0}
.fin-box{padding:14px;text-align:center;border:1px solid #e8ecf0}.fin-v{font-size:18px;font-weight:800;margin-bottom:3px}.fin-l{font-size:10px;color:#888}
.footer{padding:12px 16px;text-align:center;font-size:11px;color:#aaa;border-top:1px solid #eee}
@media print{body{background:white;padding:0}.hd{-webkit-print-color-adjust:exact;print-color-adjust:exact}}</style></head>
<body><div class="wrap">
<div class="hd">
  <div class="av">${(e.name || '?').charAt(0)}</div>
  <div><div class="nm">${e.name || '-'}</div><div class="jb">${e.job || ''}${e.dept ? ' | ' + e.dept : ''}</div>
  <div style="margin-top:6px;display:flex;gap:8px;flex-wrap:wrap">
    <span style="background:${(e.status || 'active') === 'active' ? '#27ae60' : '#e74c3c'};padding:2px 10px;border-radius:10px;font-size:11px;font-weight:700">${(e.status || 'active') === 'active' ? '✅ نشط' : '⏸️ موقوف'}</span>
    ${e.empId ? `<span style="background:rgba(255,255,255,.2);padding:2px 10px;border-radius:10px;font-size:11px">${e.empId}</span>` : ''}
  </div></div>
</div>
<div class="bd">
  <!-- Financial Summary -->
  <div class="fin-grid">
    <div class="fin-box" style="background:#e8f5e9"><div class="fin-v" style="color:#27ae60">${fmt(f.netSalary)}</div><div class="fin-l">💵 الراتب الصافي</div></div>
    <div class="fin-box" style="background:#fff8e1"><div class="fin-v" style="color:#f39c12">${fmt(f.totalCost)}</div><div class="fin-l">🏢 تكلفة الشركة</div></div>
    <div class="fin-box" style="background:#fdecea"><div class="fin-v" style="color:#e74c3c">${fmt(f.totalDeductions)}</div><div class="fin-l">✂️ إجمالي الخصومات</div></div>
  </div>
  <table>
    ${sec('👤 البيانات الشخصية')}
    ${row('الاسم الكامل', e.name)}
    ${row('رقم الهوية / الإقامة', e.natId)}
    ${row('الجنسية', e.nationality)}
    ${row('تاريخ انتهاء الإقامة', e.iqamaExp)}
    ${row('رقم الجوال', e.phone)}
    ${row('البريد الإلكتروني', e.email)}
    ${row('تاريخ التعيين', e.hireDate)}
    ${row('رقم الآيبان', e.iban)}
    ${sec('💰 الراتب والبدلات', '#f0faf4')}
    ${row('الراتب الأساسي', fmt(f.sal) + ' ريال', '#1a3a5c')}
    ${f.house > 0 ? row('بدل السكن', fmt(f.house) + ' ريال') : ''}
    ${f.trans > 0 ? row('بدل المواصلات', fmt(f.trans) + ' ريال') : ''}
    ${f.phone > 0 ? row('بدل الاتصالات', fmt(f.phone) + ' ريال') : ''}
    ${f.nature > 0 ? row('بدل الطبيعة / الخطورة', fmt(f.nature) + ' ريال') : ''}
    ${f.rep > 0 ? row('بدل التمثيل', fmt(f.rep) + ' ريال') : ''}
    ${f.car > 0 ? row('بدل السيارة / إضافي (غير خاضع للخصم)', fmt(f.car) + ' ريال') : ''}
    ${f.perf > 0 ? row('مكافأة الأداء', fmt(f.perf) + ' ريال') : ''}
    ${f.bonus > 0 ? row('مكافأة أخرى', fmt(f.bonus) + ' ريال') : ''}
    ${f.ot > 0 ? row('عمل إضافي', fmt(f.ot) + ' ريال') : ''}
    <tr style="background:#e8f5e9"><td colspan="2" style="padding:8px 10px;font-weight:800;color:#27ae60;font-size:13px">إجمالي الراتب: ${fmt(f.grossSalary)} ريال</td></tr>
    ${sec('✂️ خصومات الموظف', '#fdecea')}
    ${f.socialDeductAmt > 0 ? row(`تأمينات اجتماعية (${f.socialEmpPct}%)`, fmt(f.socialDeductAmt) + ' ريال', '#e74c3c') : ''}
    ${f.advance > 0 ? row('سلفة / مقدمة', fmt(f.advance) + ' ريال', '#e74c3c') : ''}
    ${f.absence > 0 ? row('خصم غياب', fmt(f.absence) + ' ريال', '#e74c3c') : ''}
    ${f.late > 0 ? row('خصم تأخير', fmt(f.late) + ' ريال', '#e74c3c') : ''}
    ${f.penalty > 0 ? row('مخالفات وجزاءات', fmt(f.penalty) + ' ريال', '#e74c3c') : ''}
    ${f.loan > 0 ? row('قسط قرض', fmt(f.loan) + ' ريال', '#e74c3c') : ''}
    ${f.otherDeduct > 0 ? row('خصومات أخرى', fmt(f.otherDeduct) + ' ريال', '#e74c3c') : ''}
    ${f.totalDeductions > 0 ? `<tr style="background:#fdecea"><td colspan="2" style="padding:8px 10px;font-weight:800;color:#e74c3c;font-size:13px">إجمالي الخصومات: ${fmt(f.totalDeductions)} ريال</td></tr>` : ''}
    <tr style="background:#1a3a5c"><td colspan="2" style="padding:10px 14px;font-weight:800;color:white;font-size:15px">💵 الراتب الصافي: ${fmt(f.netSalary)} ريال</td></tr>
    ${sec('🏢 تكاليف الشركة الإضافية', '#fff8e1')}
    ${f.socialCompAmt > 0 ? row(`تأمينات اجتماعية شركة (${f.socialCompPct}%)`, fmt(f.socialCompAmt) + ' ريال', '#e67e22') : ''}
    ${f.medIns > 0 ? row('التأمين الطبي', fmt(f.medIns) + ' ريال/شهر') : ''}
    ${f.profIns > 0 ? row('تأمين المسؤولية المهنية', fmt(f.profIns) + ' ريال/شهر') : ''}
    ${f.iqamaRenew > 0 ? row('تجديد الإقامة', fmt(f.iqamaRenew) + ' ريال/سنة (' + fmt(f.iqamaRenew / 12) + '/شهر)') : ''}
    ${f.sponsorship > 0 ? row('نقل الكفالة', fmt(f.sponsorship) + ' ريال') : ''}
    ${f.levyFee > 0 ? row('رسوم العمالة الوافدة', fmt(f.levyFee) + ' ريال/شهر') : ''}
    ${f.airTicket > 0 ? row('تذكرة السفر السنوية', fmt(f.airTicket) + ' ريال (' + fmt(f.airTicket / 12) + '/شهر)') : ''}
    ${f.vacAllow > 0 ? row('بدل الإجازة السنوي', fmt(f.vacAllow) + ' ريال (' + fmt(f.vacAllow / 12) + '/شهر)') : ''}
    ${f.gratuity > 0 ? row('مخصص نهاية الخدمة', fmt(f.gratuity) + ' ريال/شهر') : ''}
    ${f.training > 0 ? row('تدريب وتأهيل', fmt(f.training) + ' ريال/شهر') : ''}
    ${f.otherCost > 0 ? row('تكاليف أخرى', fmt(f.otherCost) + ' ريال/شهر') : ''}
    <tr style="background:#e67e22"><td colspan="2" style="padding:10px 14px;font-weight:800;color:white;font-size:15px">🏢 إجمالي تكلفة الموظف على الشركة: ${fmt(f.totalCost)} ريال/شهر</td></tr>
    ${e.notes ? `<tr><td colspan="2" style="padding:10px;background:#fff8e1;color:#7d6400;font-size:12px">📝 ${e.notes}</td></tr>` : ''}
  </table>
  <div class="footer">تاريخ التعيين: ${e.hireDate || '-'} &nbsp;|&nbsp; آخر تحديث: ${e.updatedAt ? new Date(e.updatedAt).toLocaleDateString('ar-SA') : '-'}
  <br><button onclick="window.print()" style="margin-top:8px;padding:7px 20px;background:#1a3a5c;color:white;border:none;border-radius:7px;cursor:pointer;font-size:12px">🖨️ طباعة</button></div>
</div></div></body></html>`);
    win.document.close();
};

