// ║   📁  [PR1]   ━━━━   PROJECTS CORE   ━━━━                                   ║
// ║                المشاريع - الوحدة الأساسية                                  ║
// ╚══════════════════════════════════════════════════════════════════════════╝

let projects = {};
let projEmpAssignments = {}; // Stores project-employee assignments
let materials = {};
let matRequests = {};
let matPurchases = {};

window.renderProjects = function () {
    if (!$('pg-projects').classList.contains('act')) return;
    const search = ($('prjSearch')?.value || '').toLowerCase();
    const statusF = $('prjStatusFilter')?.value || '';
    let items = Object.entries(projects);
    if (search) items = items.filter(([, p]) => (p.name || '').toLowerCase().includes(search) || (p.description || '').toLowerCase().includes(search));
    if (statusF) items = items.filter(([, p]) => p.status === statusF);
    items.sort((a, b) => new Date(b[1].createdAt) - new Date(a[1].createdAt));
    if (!items.length) { $('prjL').innerHTML = '<div class="empty"><div class="ei">📁</div><p>لا توجد نتائج</p></div>'; return }
    $('prjL').innerHTML = `<table class="st">
        <thead><tr>
            <th>#</th><th>المشروع</th><th>المدير</th><th>التاريخ</th><th>قيمة العقد</th><th>المستخلَص</th><th>الذمة</th><th>الموظفون</th><th>الحالة</th><th>إجراءات</th>
        </tr></thead>
        <tbody>
        ${items.map(([k, p], i) => {
        const statusMap = {
            'planning': '📋 في التخطيط',
            'active': '⚙️ قيد التنفيذ',
            'completed': '✅ مكتمل',
            'on-hold': '⏸️ موقوف'
        };
        const empCount = Object.values(projEmpAssignments).filter(a => a.projectId === k).length;
        const bd = calcProjectBillings(k);
        const contractValue = window.getProjectContractValue(k);
        const billingPct = contractValue > 0 ? Math.round((bd.totalBilled / contractValue) * 100) : 0;
        return `<tr>
                <td style="font-weight:700;color:#888">${i + 1}</td>
                <td><div style="font-weight:600;color:#1a3a5c">${esc(p.name) || '-'}</div>
                    <div style="font-size:11px;color:#888">${p.description ? esc(p.description.substring(0, 50)) + '...' : ''}</div>
                    ${p.customerId ? `<div style="font-size:11px;margin-top:2px"><span style="background:#e8f4fd;color:#1a5276;padding:2px 7px;border-radius:8px">🤝 ${esc((window.customers||{})[p.customerId]?.nameAr || p.ownerName || '')}</span></div>` : (p.ownerName ? `<div style="font-size:11px;color:#888;margin-top:2px">👤 ${esc(p.ownerName)}</div>` : '')}
                </td>
                <td>${esc(p.manager) || '-'}</td>
                <td><div style="font-size:12px">${esc(p.startDate) || '-'}</div>${p.endDate ? `<div style="font-size:11px;color:#888">→ ${esc(p.endDate)}</div>` : ''}</td>
                <td style="font-weight:700;color:#2d6a9f">${contractValue ? fmt(contractValue) : '-'}</td>
                <td>
                    ${bd.count > 0 ? `<div style="font-weight:700;color:#16a085">${fmt(bd.totalBilled)}</div>
                    <div style="background:#e0e8f0;border-radius:3px;height:4px;margin-top:3px;overflow:hidden">
                        <div style="width:${billingPct}%;background:#16a085;height:100%"></div>
                    </div>
                    <div style="font-size:10px;color:#888;margin-top:2px">${billingPct}% — ${bd.count} مستخلص</div>` : '<span style="color:#aaa;font-size:11px">لا مستخلصات</span>'}
                </td>
                <td style="font-weight:700;color:${bd.totalReceivable > 0 ? '#c0392b' : '#27ae60'}">
                    ${bd.totalReceivable > 0 ? fmt(bd.totalReceivable) : '<span style="color:#27ae60;font-size:11px">✅ محصَّل</span>'}
                </td>
                <td><span style="background:#e8f4fd;color:#1a5276;padding:3px 10px;border-radius:10px;font-size:12px;font-weight:600">${empCount} موظف</span></td>
                <td><span style="background:${p.status === 'active' ? '#d4edda' : p.status === 'completed' ? '#cfe2ff' : p.status === 'on-hold' ? '#f8d7da' : '#fff3cd'};color:${p.status === 'active' ? '#155724' : p.status === 'completed' ? '#084298' : p.status === 'on-hold' ? '#721c24' : '#664d03'};padding:3px 10px;border-radius:10px;font-size:11px;font-weight:700">${statusMap[p.status] || p.status}</span></td>
                <td><div style="display:flex;gap:4px;justify-content:center;flex-wrap:wrap">
                    <button class="btn" style="padding:4px 10px;font-size:11px;background:#1a3a5c;color:white;font-weight:700" onclick="pdOpen('${k}')" title="فتح ملف المشروع الكامل">📂 الملف</button>
                    <button class="btn b-b" style="padding:4px 8px;font-size:11px" onclick="openPrjM('${k}')">✏️</button>
                    <button class="btn b-s" data-prj-key="${k}" style="padding:4px 8px;font-size:11px">🧾</button>
                    <button class="btn" style="padding:4px 8px;font-size:11px;background:#27ae60;color:white" onclick="openProjectFinanceReport('${k}')" title="تقرير مالي تفصيلي">📊</button>
                    <button class="btn b-r" style="padding:4px 8px;font-size:11px" onclick="delPrj('${k}')">🗑️</button>
                </div></td>
            </tr>`;
    }).join('')}
        </tbody>
    </table>`;
    // attach delegated listeners for project material buttons
    if (window.attachProjectMatBtns) attachProjectMatBtns();
    updateProjectKPIs();
};

window.openPrjM = function (key = null, tab = 'pt1') {
    $('mPrjK').value = key || '';
    $('mPrjT').textContent = key ? '✏️ تعديل المشروع' : '📁 إضافة مشروع جديد';
    // Reset tab selection
    document.querySelectorAll('#mPrj .pt-pane').forEach(p => p.classList.remove('act'));
    document.querySelectorAll('#mPrj .pt-btn').forEach(b => b.classList.remove('act'));
    const targetTab = $(tab) || $('pt1');
    if (targetTab) targetTab.classList.add('act');
    const targetBtn = Array.from(document.querySelectorAll('#mPrj .pt-btn')).find(b => (b.getAttribute('onclick') || '').includes(tab));
    if (targetBtn) {
        targetBtn.classList.add('act');
    } else if (window.prjTab) {
        const fallbackBtn = document.querySelector('#mPrj .pt-btn');
        if (fallbackBtn) prjTab(tab, fallbackBtn);
    }

    // ─── تعبئة قائمة العملاء (إجباري) ───
    fillPrjCustomerSelect();

    // Populate employee select
    const select = $('prjEmpSelect');
    select.innerHTML = '<option value="">-- اختر موظفاً --</option>';
    Object.entries(emp).forEach(([k, e]) => {
        const option = document.createElement('option');
        option.value = k;
        option.textContent = e.name || 'موظف بدون اسم';
        select.appendChild(option);
    });
    // Populate materials select
    fillMatDrp();

    if (key && projects[key]) {
        const p = projects[key];
        $('prjNm').value = p.name || '';
        $('prjCode').value = p.code || '';
        $('prjType').value = p.type || '';
        $('prjDesc').value = p.description || '';
        $('prjStatus').value = p.status || 'planning';
        // Customer link (ربط إجباري بالعميل)
        if ($('prjCustomerId')) {
            $('prjCustomerId').value = p.customerId || '';
            setTimeout(() => { if (p.customerId) onPrjCustomerChange(); }, 150);
        }
        // Owner info (legacy hidden fields)
        $('prjOwnerName').value = p.ownerName || '';
        $('prjOwnerType').value = p.ownerType || 'individual';
        $('prjOwnerContact').value = p.ownerContact || '';
        $('prjOwnerPhone').value = p.ownerPhone || '';
        $('prjOwnerEmail').value = p.ownerEmail || '';
        // Location & contract
        $('prjCity').value = p.city || '';
        $('prjArea').value = p.area || '';
        $('prjAddress').value = p.address || '';
        $('prjContractNo').value = p.contractNo || '';
        $('prjContractDate').value = p.contractDate || '';
        $('prjStart').value = p.startDate || '';
        $('prjEnd').value = p.endDate || '';
        $('prjFinalHandover').value = p.finalHandover || '';
        // Finances
        $('prjContractValue').value = p.contractValue || p.budget || 0;
        $('prjAdvancePayment').value = p.advancePayment || 0;
        $('prjTargetMargin').value = p.targetMargin ?? 20;
        $('prjMatBudget').value = p.matBudgetEstimate ?? (typeof p.matBudget === 'number' ? p.matBudget : 0);
        $('prjLaborCost').value = p.laborCost || 0;
        $('prjEquipCost').value = p.equipCost || 0;
        $('prjSubcontractors').value = p.subcontractors || 0;
        $('prjIndirectCost').value = p.indirectCost || 0;
        $('prjContingency').value = p.contingency ?? 5;
        // 🆕 IPC Settings
        if ($('prjClientName')) $('prjClientName').value = p.clientName || '';
        if ($('prjClientAddress')) $('prjClientAddress').value = p.clientAddress || '';
        if ($('prjClientVATNumber')) $('prjClientVATNumber').value = p.clientVATNumber || '';
        if ($('prjContractRef')) $('prjContractRef').value = p.contractRef || '';
        if ($('prjManager')) $('prjManager').value = p.projectManagerNote || '';
        if ($('prjSiteName')) $('prjSiteName').value = p.siteName || '';
        if ($('prjDeliveryDate')) $('prjDeliveryDate').value = p.deliveryDate || '';
        if ($('prjRetentionPct')) $('prjRetentionPct').value = p.retentionPct ?? 10;
        if ($('prjAdvancePct')) $('prjAdvancePct').value = p.advancePct ?? 0;
        if ($('prjAdvRecoveryPct')) $('prjAdvRecoveryPct').value = p.advRecoveryPct ?? 0;
        if ($('prjVATPct')) $('prjVATPct').value = p.vatPct ?? 15;
        if ($('prjWarrantyMonths')) $('prjWarrantyMonths').value = p.warrantyMonths ?? 12;
        // Approval limits
        $('prjLimitPM').value = p.approvalLimits?.projectManager ?? 5000;
        $('prjLimitPurchasing').value = p.approvalLimits?.purchasing ?? 20000;
        $('prjLimitOps').value = p.approvalLimits?.operations ?? 50000;
        // Team
        fillTeamMemberSelects();
        setTimeout(() => {
            if ($('prjProjectManager')) $('prjProjectManager').value = p.team?.projectManagerId || '';
            if ($('prjSiteEngineer')) $('prjSiteEngineer').value = p.team?.siteEngineerId || '';
            if ($('prjSupervisor')) $('prjSupervisor').value = p.team?.supervisorId || '';
            if ($('prjFinanceManager')) $('prjFinanceManager').value = p.team?.financeManagerId || '';
        }, 100);

        calcProjectMargins();
        calcProjectDuration();
        renderBOQList(key);
        renderMatBudgetList(key);
        renderProjectEmps(key);
        renderProjectMatLists(key);
    } else {
        // مشروع جديد - تصفير الحقول
        ['prjNm','prjCode','prjDesc','prjOwnerName','prjOwnerContact','prjOwnerPhone','prjOwnerEmail',
         'prjCity','prjArea','prjAddress','prjContractNo','prjType'].forEach(id => { if($(id)) $(id).value = '' });
        $('prjStatus').value = 'planning';
        $('prjOwnerType').value = 'individual';
        $('prjStart').value = today();
        $('prjEnd').value = ''; $('prjContractDate').value = ''; $('prjFinalHandover').value = '';
        ['prjContractValue','prjAdvancePayment','prjMatBudget','prjLaborCost','prjEquipCost',
         'prjSubcontractors','prjIndirectCost'].forEach(id => { if($(id)) $(id).value = 0 });
        $('prjTargetMargin').value = 20;
        $('prjContingency').value = 5;
        $('prjLimitPM').value = 5000;
        $('prjLimitPurchasing').value = 20000;
        $('prjLimitOps').value = 50000;
        fillTeamMemberSelects();
        calcProjectMargins();
        $('prjEmpList').innerHTML = '<div style="font-size:13px;color:#999;padding:20px;text-align:center">لا يوجد موظفون معينون بعد</div>';
        if ($('boqList')) $('boqList').innerHTML = '<div style="padding:30px;text-align:center;color:#999;font-size:13px">لا توجد بنود بعد — أضف أول بند</div>';
        if ($('matBudgetList')) $('matBudgetList').innerHTML = '<div style="padding:30px;text-align:center;color:#999;font-size:13px">لا توجد مواد متوقعة بعد — أضف أول مادة</div>';
        if ($('prjMatReqList')) $('prjMatReqList').innerHTML = '<div style="padding:20px;text-align:center;color:#999">لا توجد طلبات حتى الآن</div>';
        if ($('prjMatPurList')) $('prjMatPurList').innerHTML = '<div style="padding:20px;text-align:center;color:#999">لا توجد مشتريات مسجلة</div>';
        if ($('prjMatSummary')) $('prjMatSummary').innerHTML = '';
    }
    ov('mPrj');
};

// Attach click handlers to material tab buttons in project rows (robust to re-renders)
window.attachProjectMatBtns = function () {
    document.querySelectorAll('#prjL .btn.b-s').forEach(btn => {
        if (btn._pmAttached) return; btn._pmAttached = true;
        btn.addEventListener('click', e => {
            const pk = btn.dataset.prjKey || (btn.getAttribute('onclick') || '').match(/openPrjM\(['\"]([^'\",]+)['\"]/)?.[1];
            if (!pk) { toast('خطأ: لم يتم تحديد المشروع', 'er'); return; }
            try { openPrjM(pk, 'pt3'); } catch (err) { console.error(err); toast('خطأ عند فتح تبويب المواد', 'er'); }
        });
    });
};
// ensure listeners are attached if projects already rendered
try { if (document.querySelector('#prjL')) attachProjectMatBtns(); } catch (e) { console.error('attachProjectMatBtns init error', e) }

window.renderProjectEmps = function (projectKey) {
    const assignments = Object.entries(projEmpAssignments).filter(([, a]) => a.projectId === projectKey);
    if (!assignments.length) {
        $('prjEmpList').innerHTML = '<div style="font-size:13px;color:#999;padding:20px;text-align:center">لا يوجد موظفون معينون بعد</div>';
        return;
    }
    $('prjEmpList').innerHTML = `<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:12px">
        ${assignments.map(([aKey, a]) => {
        const empData = emp[a.empId];
        return `<div style="background:white;border:1px solid #e0e8f0;border-radius:10px;padding:12px">
                <div style="font-weight:600;color:#1a3a5c">${empData?.name || 'موظف غير معروف'}</div>
                <div style="font-size:11px;color:#888;margin-bottom:8px">${empData?.job || ''}</div>
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;font-size:11px;margin-bottom:8px">
                    <div><span style="color:#666">الدور:</span> <span style="font-weight:600">${a.role || '-'}</span></div>
                    <div><span style="color:#666">الساعات:</span> <span style="font-weight:600">${a.hoursAllocated || 0} س</span></div>
                </div>
                ${a.notes ? `<div style="font-size:11px;background:#f8fafc;padding:6px;border-radius:6px;color:#555;margin-bottom:8px">📝 ${a.notes}</div>` : ''}
                <button class="btn b-r" style="width:100%;padding:6px;font-size:11px" onclick="delEmpFromPrj('${projectKey}', '${aKey}')">🗑️ إزالة</button>
            </div>`;
    }).join('')}
    </div>`;
};

window.addEmpToProj = function () {
    const empId = $('prjEmpSelect')?.value;
    if (!empId) { toast('اختر موظفاً أولاً', 'er'); return; }
    const role = prompt('أدخل دور الموظف في المشروع:');
    if (role === null) return;
    const hours = prompt('أدخل عدد الساعات المخصصة (اختياري):') || 0;
    const projKey = $('mPrjK').value;
    if (!projKey) { toast('احفظ المشروع أولاً', 'er'); return; }

    const assignKey = projKey + '_' + empId + '_' + Date.now();
    projEmpAssignments[assignKey] = {
        projectId: projKey,
        empId: empId,
        role: role,
        hoursAllocated: parseFloat(hours),
        notes: ''
    };
    renderProjectEmps(projKey);
    $('prjEmpSelect').value = '';
    toast('✅ تم إضافة الموظف', 'ok');
};

window.delEmpFromPrj = function (projectKey, assignKey) {
    cf2('هل تريد إزالة هذا الموظف من المشروع؟', () => {
        delete projEmpAssignments[assignKey];
        renderProjectEmps(projectKey);
        toast('🗑️ تم الإزالة', 'ok');
    });
};

window.savePrj = async function () {
    const nm = $('prjNm').value.trim();
    if (!nm) { toast('اسم المشروع مطلوب', 'er'); return; }

    // ── التحقق من ربط العميل (إجباري) ──
    const customerId = $('prjCustomerId')?.value?.trim();
    if (!customerId) {
        toast('⚠️ يجب اختيار العميل من القائمة قبل الحفظ', 'er');
        // الانتقال لأول تبويب
        const firstBtn = document.querySelector('#mPrj .pt-btn');
        if (firstBtn) prjTab('pt1', firstBtn);
        $('prjCustomerId')?.focus();
        return;
    }
    const customer = (window.customers || {})[customerId] || {};
    const ownerName = customer.nameAr || $('prjOwnerName')?.value?.trim() || '';
    if (!ownerName) { toast('⚠️ اسم المالك / الجهة المتعاقدة مطلوب', 'er'); prjTab('pt1', document.querySelector('#mPrj .pt-btn')); $('prjOwnerName').focus(); return }
    const contractValue = parseFloat($('prjContractValue')?.value) || 0;
    if (contractValue <= 0) { toast('⚠️ قيمة العقد مطلوبة', 'er'); prjTab('pt1', document.querySelector('#mPrj .pt-btn')); $('prjContractValue').focus(); return }
    const key = $('mPrjK').value;
    const matBudgetEstimate = parseFloat($('prjMatBudget')?.value) || 0;
    const laborCost = parseFloat($('prjLaborCost')?.value) || 0;
    const equipCost = parseFloat($('prjEquipCost')?.value) || 0;
    const subcontractors = parseFloat($('prjSubcontractors')?.value) || 0;
    const indirectCost = parseFloat($('prjIndirectCost')?.value) || 0;
    const contingencyPct = parseFloat($('prjContingency')?.value) || 0;
    const subTotal = matBudgetEstimate + laborCost + equipCost + subcontractors + indirectCost;
    const contingencyAmt = subTotal * (contingencyPct / 100);
    const totalEstimatedCost = subTotal + contingencyAmt;

    // أسماء أعضاء الفريق
    const pmId = $('prjProjectManager')?.value || '';
    const seId = $('prjSiteEngineer')?.value || '';
    const svId = $('prjSupervisor')?.value || '';
    const fmId = $('prjFinanceManager')?.value || '';

    const data = {
        name: nm,
        code: $('prjCode')?.value?.trim() || '',
        type: $('prjType')?.value || '',
        description: $('prjDesc')?.value?.trim() || '',
        status: $('prjStatus').value,
        // ─── ربط العميل (الجديد) ───
        customerId,
        // Owner (متوافق مع الكود القديم + مشتق من العميل)
        ownerName: customer.nameAr || ownerName,
        ownerType: customer.type || $('prjOwnerType')?.value || 'company',
        ownerContact: customer.nameAr || '',
        ownerPhone: customer.phone || '',
        ownerEmail: customer.email || '',
        clientName: customer.nameAr || ownerName,
        clientAddress: customer.address || '',
        clientVATNumber: customer.vatNumber || '',
        // Location & contract
        city: $('prjCity')?.value?.trim() || '',
        area: $('prjArea')?.value?.trim() || '',
        address: $('prjAddress')?.value?.trim() || '',
        contractNo: $('prjContractNo')?.value?.trim() || '',
        contractDate: $('prjContractDate')?.value || '',
        startDate: $('prjStart').value,
        endDate: $('prjEnd').value,
        finalHandover: $('prjFinalHandover')?.value || '',
        // Financial
        contractValue, budget: contractValue,
        vat: parseFloat($('prjVAT')?.value) || 0,
        totalWithVAT: parseFloat($('prjTotalWithVAT')?.value) || 0,
        advancePayment: parseFloat($('prjAdvancePayment')?.value) || 0,
        targetMargin: parseFloat($('prjTargetMargin')?.value) || 0,
        targetCost: parseFloat($('prjTargetCost')?.value) || 0,
        matBudgetEstimate, laborCost, equipCost, subcontractors, indirectCost,
        contingency: contingencyPct, contingencyAmt,
        totalEstimatedCost,
        // 🆕 IPC Settings (المستخلصات)
        clientName: $('prjClientName')?.value?.trim() || customer.nameAr || ownerName,
        clientAddress: $('prjClientAddress')?.value?.trim() || customer.address || '',
        clientVATNumber: $('prjClientVATNumber')?.value?.trim() || customer.vatNumber || '',
        contractRef: $('prjContractRef')?.value?.trim() || '',
        projectManagerNote: $('prjManager')?.value?.trim() || '',
        siteName: $('prjSiteName')?.value?.trim() || '',
        deliveryDate: $('prjDeliveryDate')?.value || '',
        retentionPct: parseFloat($('prjRetentionPct')?.value) || 0,
        advancePct: parseFloat($('prjAdvancePct')?.value) || 0,
        advRecoveryPct: parseFloat($('prjAdvRecoveryPct')?.value) || 0,
        vatPct: parseFloat($('prjVATPct')?.value) || 15,
        warrantyMonths: parseInt($('prjWarrantyMonths')?.value) || 12,
        // Team
        team: {
            projectManagerId: pmId,
            projectManagerName: pmId && emp[pmId]?.name || '',
            siteEngineerId: seId,
            siteEngineerName: seId && emp[seId]?.name || '',
            supervisorId: svId,
            supervisorName: svId && emp[svId]?.name || '',
            financeManagerId: fmId,
            financeManagerName: fmId && emp[fmId]?.name || ''
        },
        manager: pmId && emp[pmId]?.name || '', // للتوافق مع الكود القديم
        // Approval limits
        approvalLimits: {
            projectManager: parseFloat($('prjLimitPM')?.value) || 5000,
            purchasing: parseFloat($('prjLimitPurchasing')?.value) || 20000,
            operations: parseFloat($('prjLimitOps')?.value) || 50000
        },
        updatedAt: new Date().toISOString()
    };
    try {
        if (key) {
            await update(ref(db, 'ledger/projects/' + key), data);
            toast('✅ تم تحديث المشروع', 'ok');
        } else {
            data.createdAt = new Date().toISOString();
            const newRef = push(R.prj);
            data.id = newRef.key;
            await set(ref(db, 'ledger/projects/' + newRef.key), data);
            toast('✅ تم إضافة المشروع', 'ok');
        }
        cov('mPrj');
        renderProjects();
    } catch (e) {
        toast('خطأ: ' + e.message, 'er');
    }
};

window.delPrj = function (key) {
    cf2('هل تريد حذف هذا المشروع نهائياً؟', async () => {
        try {
            await remove(ref(db, 'ledger/projects/' + key));
            // حذف جميع تعيينات الموظفين للمشروع
            Object.keys(projEmpAssignments).forEach(k => {
                if (projEmpAssignments[k].projectId === key) delete projEmpAssignments[k];
            });
            toast('🗑️ تم الحذف', 'ok');
            renderProjects();
        } catch (e) {
            toast('خطأ: ' + e.message, 'er');
        }
    });
};

window.viewPrj = function (key) {
    const p = projects[key];
    if (!p) return;
    const assignments = Object.entries(projEmpAssignments).filter(([, a]) => a.projectId === key);
    const win = window.open('', '_blank');
    win.document.write(`<!DOCTYPE html><html lang="ar" dir="rtl"><head><meta charset="UTF-8"><title>تفاصيل المشروع - ${p.name}</title>
<style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',Tahoma,sans-serif;background:#f0f2f5;color:#333;direction:rtl;padding:16px}
.wrap{max-width:900px;margin:0 auto}.hd{background:linear-gradient(135deg,#1a3a5c,#2d6a9f);color:white;border-radius:14px 14px 0 0;padding:20px 24px;display:flex;justify-content:space-between;align-items:flex-start}
.hd-l{flex:1}.nm{font-size:24px;font-weight:800;margin-bottom:8px}.desc{font-size:13px;opacity:.9;margin-bottom:8px}.bd{background:white;border-radius:0 0 14px 14px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,.1);padding:20px}
.sec-title{font-size:15px;font-weight:800;color:#1a3a5c;margin-top:16px;margin-bottom:12px;padding-bottom:8px;border-bottom:2px solid #e0e8f0}
.info-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px}
.info-box{background:#f8fafc;border:1px solid #e0e8f0;border-radius:10px;padding:12px}
.info-label{font-size:11px;color:#666;font-weight:700;text-transform:uppercase;margin-bottom:4px}
.info-value{font-size:14px;font-weight:600;color:#1a3a5c}
.emp-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(250px,1fr));gap:12px}
.emp-card{background:#f8fafc;border:1px solid #e0e8f0;border-radius:10px;padding:14px}
.emp-name{font-weight:600;color:#1a3a5c;margin-bottom:6px}
.emp-detail{font-size:11px;color:#666;margin-bottom:3px}
.footer{padding:12px 16px;text-align:center;font-size:11px;color:#aaa;border-top:1px solid #eee;margin-top:20px}
@media print{body{background:white;padding:0}.hd{-webkit-print-color-adjust:exact;print-color-adjust:exact}}</style></head>
<body><div class="wrap">
<div class="hd">
  <div class="hd-l">
    <div class="nm">📁 ${p.name || '-'}</div>
    <div class="desc">${p.description || ''}</div>
  </div>
  <div style="text-align:left">
    <span style="display:inline-block;background:#1a3a5c;color:white;padding:6px 12px;border-radius:8px;font-size:12px;font-weight:700">${{
            'planning': '📋 في التخطيط',
            'active': '⚙️ قيد التنفيذ',
            'completed': '✅ مكتمل',
            'on-hold': '⏸️ موقوف'
        }[p.status] || p.status}</span>
  </div>
</div>
<div class="bd">
  <div class="sec-title">📊 معلومات المشروع</div>
  <div class="info-grid">
    <div class="info-box">
      <div class="info-label">المدير</div>
      <div class="info-value">${p.manager || '-'}</div>
    </div>
    <div class="info-box">
      <div class="info-label">الميزانية</div>
      <div class="info-value">${p.budget ? fmt(p.budget) + ' ريال' : '-'}</div>
    </div>
    <div class="info-box">
      <div class="info-label">تاريخ البدء</div>
      <div class="info-value">${p.startDate || '-'}</div>
    </div>
    <div class="info-box">
      <div class="info-label">تاريخ الانتهاء</div>
      <div class="info-value">${p.endDate || '-'}</div>
    </div>
  </div>

  <div class="sec-title">👥 الموظفون المعينون (${assignments.length})</div>
  ${assignments.length ? `<div class="emp-grid">
    ${assignments.map(([, a]) => {
            const empData = emp[a.empId];
            return `<div class="emp-card">
    <div class="emp-name">${empData?.name || 'موظف غير معروف'}</div>
    <div class="emp-detail"><strong>الوظيفة:</strong> ${empData?.job || '-'}</div>
    <div class="emp-detail"><strong>القسم:</strong> ${empData?.dept || '-'}</div>
    <div class="emp-detail"><strong>الدور:</strong> ${a.role || '-'}</div>
    <div class="emp-detail"><strong>الساعات:</strong> ${a.hoursAllocated || 0} ساعة</div>
    ${a.notes ? `<div class="emp-detail"><strong>ملاحظات:</strong> ${a.notes}</div>` : ''}
</div>`;
        }).join('')}
  </div>` : '<div style="padding:20px;text-align:center;color:#999">لا يوجد موظفون معينون</div>'}

  <div class="sec-title">🔧 ملخص التكلفة</div>
  <div class="info-grid">
    <div class="info-box">
      <div class="info-label">تكلفة العمالة المقدرة</div>
      <div class="info-value">${p.laborCost ? fmt(p.laborCost) + ' ريال' : '-'} </div>
    </div>
    <div class="info-box">
      <div class="info-label">التكاليف غير المباشرة المقدرة</div>
      <div class="info-value">${p.indirectCost ? fmt(p.indirectCost) + ' ريال' : '-'} </div>
    </div>
    <div class="info-box">
      <div class="info-label">الميزانية</div>
      <div class="info-value">${p.budget ? fmt(p.budget) + ' ريال' : '-'} </div>
    </div>
  </div>
  <div class="sec-title">🧾 تفاصيل المواد والمشتريات</div>
  ${(() => {
            const approved = Object.values(matRequests).filter(r => r.projectId === key || (r.project && r.project.id === key)).filter(r => r.status === 'approved');
            const purchased = Object.values(matPurchases).filter(p => p.projectId === key || (p.project && p.project.id === key));
            const approvedTotal = approved.reduce((s, r) => s + ((parseFloat(r.approvedQty) || 0) * (parseFloat(r.approvedUnitPrice) || 0)), 0);
            const purchasedTotal = purchased.reduce((s, p) => s + ((parseFloat(p.purchasedQty) || 0) * (parseFloat(p.purchasedUnitPrice) || 0)), 0);
            const diff = purchasedTotal - approvedTotal;
            const diffColor = diff > 0 ? '#e74c3c' : '#1a3a5c';
            return `<div class="info-grid">
<div class="info-box"><div class="info-label">تكلفة المواد الموافق عليها</div><div class="info-value">${fmt(approvedTotal)} ريال</div></div>
<div class="info-box"><div class="info-label">تكلفة المواد المشتراة</div><div class="info-value" style="color:${diffColor}">${fmt(purchasedTotal)} ريال</div></div>
<div class="info-box"><div class="info-label">الفرق</div><div class="info-value" style="color:${diffColor}">${fmt(diff)} ريال</div></div>
      </div>`;
        })()}
  <div class="footer">تاريخ الإنشاء: ${p.createdAt ? new Date(p.createdAt).toLocaleDateString('ar-SA') : '-'} &nbsp;|&nbsp; آخر تحديث: ${p.updatedAt ? new Date(p.updatedAt).toLocaleDateString('ar-SA') : '-'}
  <br><button onclick="window.print()" style="margin-top:8px;padding:7px 20px;background:#1a3a5c;color:white;border:none;border-radius:7px;cursor:pointer;font-size:12px">🖨️ طباعة</button></div>
</div></div></body></html>`);
    win.document.close();
};

// Backwards-compatible report button handler
window.viewProjectReport = function (key) {
    // If a dedicated report view exists later, replace this implementation.
    try {
        viewPrj(key);
    } catch (e) {
        console.error('viewProjectReport error', e);
        toast('تعذر فتح تقرير المشروع', 'er');
    }
};

// ── فتح نموذج فاتورة مبيعات جديدة مربوطة بالمشروع ──────────────────────
window.pdOpenNewInvoiceForProject = function (projectId) {
    const p = (window.projects || {})[projectId];
    if (!p) { toast('المشروع غير موجود', 'er'); return; }
    if (!p.customerId) {
        toast('⚠️ يجب ربط المشروع بعميل أولاً — افتح تعديل المشروع وحدد العميل', 'wn', 6000);
        return;
    }
    if (typeof openSInvEditor !== 'function') {
        toast('⚠️ صفحة فواتير المبيعات لم تُحمَّل بعد', 'wn');
        return;
    }
    // فتح نموذج الفاتورة
    openSInvEditor();
    // تعبئة بيانات المشروع والعميل بعد فتح المودال
    setTimeout(() => {
        // العميل
        const custSel = document.getElementById('mSInvCustomer');
        if (custSel) {
            custSel.value = p.customerId;
            if (typeof onSInvCustomerChange === 'function') onSInvCustomerChange();
        }
        // المشروع
        const prjSel = document.getElementById('mSInvProject');
        if (prjSel) prjSel.value = projectId;

        // الموضوع
        const subjEl = document.getElementById('mSInvSubject');
        if (subjEl && !subjEl.value) subjEl.value = `خدمات مشروع ${p.name || ''}`;

        // المرجع
        const refEl = document.getElementById('mSInvRef');
        if (refEl && !refEl.value) refEl.value = p.contractNo || '';

        // تحديث العنوان
        const titleEl = document.getElementById('mSInvTitle');
        if (titleEl) titleEl.textContent = `🧾 فاتورة جديدة — ${p.name || ''}`;

        toast(`✅ تم تعبئة بيانات المشروع والعميل تلقائياً`, 'ok', 3000);
    }, 250);
};

window.pdOpen = function (projectId) {
    const p = projects[projectId]; if (!p) return;
    // أظهر عنصر nav وحدّث اسمه
    const navEl = $('n-pd');
    const labelEl = $('n-pd-label');
    if (navEl) navEl.style.display = '';
    if (labelEl) labelEl.textContent = p.name || 'ملف المشروع';
    window._pd = window._pd || {};
    window._pd.projectId = projectId;
    nav('projectdetail', navEl);
    // breadcrumb يعرف اسم المشروع
    updateBreadcrumb('projectdetail', p.name || 'ملف المشروع');
    if (typeof renderProjectDetail === 'function') renderProjectDetail();
};

// ── تعبئة قائمة العملاء في نموذج المشروع ─────────────────────────────
window.fillPrjCustomerSelect = function () {
    const sel = $('prjCustomerId'); if (!sel) return;
    const cur = sel.value;
    const custs = Object.entries(window.customers || {})
        .filter(([, c]) => c.active !== false)
        .sort((a, b) => (a[1].nameAr || '').localeCompare(b[1].nameAr || '', 'ar'));
    sel.innerHTML = '<option value="">-- اختر عميلاً (إجباري) --</option>' +
        custs.map(([k, c]) => `<option value="${k}" ${k === cur ? 'selected' : ''}>${c.code ? c.code + ' — ' : ''}${c.nameAr || c.nameEn || k}</option>`).join('');
    if (cur) sel.value = cur;
};

// ── عند تغيير العميل — اعرض بياناته ─────────────────────────────────
window.onPrjCustomerChange = function () {
    const sel = $('prjCustomerId'); if (!sel) return;
    const customerId = sel.value;
    const infoDiv = $('prjCustomerInfo');
    const hintDiv = $('prjCustomerHint');
    if (!customerId) {
        if (infoDiv) infoDiv.style.display = 'none';
        if (hintDiv) hintDiv.style.display = '';
        return;
    }
    const c = (window.customers || {})[customerId];
    if (!c) return;
    if (infoDiv) {
        infoDiv.style.display = '';
        document.getElementById('ci-name')?.setAttribute('textContent', c.nameAr || '—');
        if (document.getElementById('ci-name')) document.getElementById('ci-name').textContent = c.nameAr || '—';
        if (document.getElementById('ci-phone')) document.getElementById('ci-phone').textContent = c.phone || '—';
        if (document.getElementById('ci-vat')) document.getElementById('ci-vat').textContent = c.vatNumber || '—';
        if (document.getElementById('ci-cr')) document.getElementById('ci-cr').textContent = c.crNumber || '—';
        if (document.getElementById('ci-terms')) document.getElementById('ci-terms').textContent = (c.paymentTerms || 30) + ' يوم';
        if (document.getElementById('ci-balance')) document.getElementById('ci-balance').textContent = fmt(c.openingBalance || 0) + ' ر';
    }
    if (hintDiv) hintDiv.style.display = 'none';
    // ملء الحقول المخفية القديمة تلقائياً
    if ($('prjOwnerName')) $('prjOwnerName').value = c.nameAr || '';
    if ($('prjOwnerPhone')) $('prjOwnerPhone').value = c.phone || '';
    if ($('prjOwnerEmail')) $('prjOwnerEmail').value = c.email || '';
};

// ── فتح نموذج إضافة عميل جديد من داخل المشروع ───────────────────────
window.openCustMFromProject = function () {
    if (typeof openCustomerEditor !== 'function') {
        toast('انتقل لصفحة العملاء لإضافة عميل', 'wn'); return;
    }
    // احفظ callback لتحديث القائمة بعد الحفظ واختيار العميل الجديد تلقائياً
    window._postCustSave = () => {
        // تأخير بسيط حتى يحدّث مستمع Firebase قائمة العملاء المحلية
        setTimeout(() => {
            fillPrjCustomerSelect();
            const keys = Object.keys(window.customers || {});
            const lastKey = keys[keys.length - 1];
            if (lastKey && $('prjCustomerId')) { $('prjCustomerId').value = lastKey; onPrjCustomerChange(); }
        }, 250);
    };
    openCustomerEditor();
    // 🔝 ارفع نافذة العميل فوق نافذة المشروع (كلاهما z-index:10000 افتراضياً)
    const mc = $('mCustomer'); if (mc) mc.style.zIndex = '10002';
    toast('أضف بيانات العميل واحفظ — سيُختار تلقائياً في المشروع', 'ok', 4000);
};

window.updateProjectKPIs = function () {
    const total = Object.keys(projects).length;
    const active = Object.values(projects).filter(p => p.status === 'active').length;
    const completed = Object.values(projects).filter(p => p.status === 'completed').length;
    const totalBudget = Object.values(projects).reduce((sum, p) => sum + (parseFloat(p.budget) || 0), 0);
    $('pk1').textContent = total;
    $('pk2').textContent = active;
    $('pk3').textContent = completed;
    $('pk4').textContent = fmt(totalBudget);
};

window.prjTab = function (tabId, btn) {
    document.querySelectorAll('#mPrj .pt-pane').forEach(p => p.classList.remove('act'));
    document.querySelectorAll('#mPrj .pt-btn').forEach(b => b.classList.remove('act'));
    $(tabId).classList.add('act');
    btn.classList.add('act');
};

// ── Materials / Requests handling ─────────────────
function fillMatDrp() {
    const sel = $('prjMatSelect'); if (!sel) return;
    sel.innerHTML = '<option value="">-- اختر مادة --</option>';
    Object.entries(materials).forEach(([k, m]) => { const o = document.createElement('option'); o.value = k; o.textContent = (m.name || '-') + (m.unit ? ' (' + m.unit + ')' : ''); sel.appendChild(o); });
}

window.renderProjectMatLists = function (projectKey) {
    // Requests
    const reqs = Object.entries(matRequests).filter(([, r]) => r.projectId === projectKey || (r.project && r.project.id === projectKey));
    if (!reqs.length) {
        $('prjMatReqList').innerHTML = '<div style="padding:20px;text-align:center;color:#999">لا توجد طلبات حتى الآن</div>';
    } else {
        $('prjMatReqList').innerHTML = reqs.map(([k, r]) => {
            const m = materials[r.materialId || (r.material && r.material.id)];
            const requesterName = (emp[r.requesterId] || (r.requester && r.requester.name) || {}).name || (r.requester && r.requester.id) || '-';
            const status = r.status || 'pending';
            const statusBadge = status === 'approved' ? '<span style="background:#d4edda;color:#155724;padding:4px 8px;border-radius:8px;font-weight:700;font-size:12px">✅ موافق</span>' : status === 'rejected' ? '<span style="background:#f8d7da;color:#721c24;padding:4px 8px;border-radius:8px;font-weight:700;font-size:12px">🚫 مرفوض</span>' : '<span style="background:#fff3cd;color:#664d03;padding:4px 8px;border-radius:8px;font-weight:700;font-size:12px">⏳ قيد الانتظار</span>';
            return `<div style="background:white;border:1px solid #e0e8f0;border-radius:8px;padding:10px;margin-bottom:8px">
                <div style="display:flex;justify-content:space-between;align-items:center"><div><div style="font-weight:700">${m?.name || (r.material && r.material.name) || 'مادة غير معروفة'}</div><div style="font-size:12px;color:#666">المطلوب: ${r.requestedQty || 0} ${m?.unit || ''} × ${r.requestedUnitPrice ? fmt(r.requestedUnitPrice) + ' / وحدة' : '-'}</div></div><div>${statusBadge}</div></div>
                <div style="font-size:12px;color:#666;margin-top:8px">الطالب: ${requesterName} • ${r.createdAt ? new Date(r.createdAt).toLocaleString('ar-SA') : ''}</div>
                <div style="margin-top:8px;display:flex;gap:8px">
                    ${can('approve_material_request') && status === 'pending' ? `<button class="btn b-g" onclick="approveMatRequest('${k}')">✅ قبول</button><button class="btn b-r" onclick="approveMatRequest('${k}','rejected')">🚫 رفض</button>` : ''}
                    <button class="btn b-b" onclick="openRecordPurchase('${k}')">🛒 تسجيل شراء</button>
                </div>
            </div>`;
        }).join('');
    }

    // Purchases
    const purs = Object.entries(matPurchases).filter(([, p]) => p.projectId === projectKey || (p.project && p.project.id === projectKey));
    if (!purs.length) {
        $('prjMatPurList').innerHTML = '<div style="padding:20px;text-align:center;color:#999">لا توجد مشتريات مسجلة</div>';
    } else {
        $('prjMatPurList').innerHTML = purs.map(([k, p]) => {
            const m = materials[p.materialId || (p.material && p.material.id)];
            return `<div style="background:white;border:1px solid #e0e8f0;border-radius:8px;padding:10px;margin-bottom:8px">
                <div style="font-weight:700">${m?.name || (p.material && p.material.name) || 'مادة'}</div>
                <div style="font-size:12px;color:#666">الكمية المشتراة: ${p.purchasedQty || 0} ${m?.unit || ''} • السعر: ${fmt(p.purchasedUnitPrice || 0)} / وحدة</div>
                <div style="font-size:11px;color:#888;margin-top:6px">تاريخ: ${p.createdAt ? new Date(p.createdAt).toLocaleString('ar-SA') : ''}</div>
            </div>`;
        }).join('');
    }

    // Summary: compare approved vs purchased
    const totalApproved = Object.values(matRequests).filter(r => (r.projectId === projectKey || (r.project && r.project.id === projectKey)) && r.status === 'approved').reduce((s, r) => s + ((parseFloat(r.approvedQty) || 0) * (parseFloat(r.approvedUnitPrice) || (parseFloat(r.requestedUnitPrice) || 0))), 0);
    const totalPurchased = Object.values(matPurchases).filter(p => (p.projectId === projectKey || (p.project && p.project.id === projectKey))).reduce((s, p) => s + ((parseFloat(p.purchasedQty) || 0) * (parseFloat(p.purchasedUnitPrice) || 0)), 0);
    // show in modal summary area
    const sumHtml = `<div style="margin-top:12px;background:#f8fafc;border:1px solid #e0e8f0;padding:10px;border-radius:8px">تكلفة المواد (الموافق عليها): ${fmt(totalApproved)} ريال • التكلفة المشتراة: <span style="color:${totalPurchased > totalApproved ? '#e74c3c' : '#1a3a5c'};font-weight:800">${fmt(totalPurchased)} ريال</span></div>`;
    if ($('prjMatSummary')) $('prjMatSummary').innerHTML = sumHtml;
};

window.requestMaterial = async function () {
    const matId = $('prjMatSelect')?.value; if (!matId) { toast('اختر مادة', 'er'); return; }
    const qty = parseFloat($('reqQty').value) || 0; if (qty <= 0) { toast('الكمية مطلوبة', 'er'); return; }
    const unitPrice = parseFloat($('reqPrice').value) || 0;
    const notes = $('reqNotes').value || '';
    const reqDateVal = $('reqDate')?.value || '';
    const requestedDate = reqDateVal ? new Date(reqDateVal).toISOString() : new Date().toISOString();
    const projKey = $('mPrjK').value; if (!projKey) { toast('احفظ المشروع أولاً', 'er'); return; }
    const data = { projectId: projKey, materialId: matId, requesterId: curU?.uid || '', requestedQty: qty, requestedUnitPrice: unitPrice, requestedDate, notes, status: 'pending', createdAt: new Date().toISOString() };
    try { await push(R.mreq, data); toast('✅ تم إرسال الطلب', 'ok'); $('reqQty').value = ''; $('reqPrice').value = ''; $('reqNotes').value = ''; renderProjectMatLists(projKey); } catch (e) { toast('خطأ: ' + e.message, 'er'); }
};

window.approveMatRequest = async function (reqKey, reject = '') {
    const r = matRequests[reqKey]; if (!r) return; const projKey = r.projectId || (r.project && r.project.id);
    if (reject === 'rejected') {
        try { await update(ref(db, 'ledger/materialRequests/' + reqKey), { status: 'rejected', managerDecisionBy: curU?.uid || '', managerDecisionAt: new Date().toISOString() }); toast('تم الرفض', 'ok'); renderProjectMatLists(projKey); } catch (e) { toast('خطأ: ' + e.message, 'er'); }
        return;
    }
    const approvedQty = parseFloat(prompt('أدخل الكمية الموافق عليها:', r.requestedQty || 0)); if (approvedQty === null) return;
    const approvedUnitPrice = parseFloat(prompt('أدخل سعر الوحدة الموافق عليه:', r.requestedUnitPrice || 0)); if (approvedUnitPrice === null) return;
    try { await update(ref(db, 'ledger/materialRequests/' + reqKey), { status: 'approved', approvedQty, approvedUnitPrice, managerDecisionBy: curU?.uid || '', managerDecisionAt: new Date().toISOString() }); toast('✅ تم الموافقة', 'ok'); renderProjectMatLists(projKey); } catch (e) { toast('خطأ: ' + e.message, 'er'); }
};

window.openRecordPurchase = function (requestKey) {
    const r = matRequests[requestKey]; const projKey = r?.projectId || (r?.project && r.project.id) || $('mPrjK').value;
    const qty = parseFloat(prompt('كمية الشراء:', r?.approvedQty || r?.requestedQty || 0)); if (qty === null) return;
    const unitPrice = parseFloat(prompt('سعر الوحدة الفعلي:', r?.approvedUnitPrice || r?.requestedUnitPrice || 0)); if (unitPrice === null) return;
    (async () => {
        try {
            const data = { projectId: projKey, materialId: r?.materialId || (r?.material && r.material.id), purchasedQty: qty, purchasedUnitPrice: unitPrice, purchasedById: curU?.uid || '', relatedRequestId: requestKey || null, notes: '', createdAt: new Date().toISOString() };
            await push(R.mpur, data);
            toast('✅ تم تسجيل الشراء', 'ok');
            renderProjectMatLists(projKey);
        } catch (e) { toast('خطأ: ' + e.message, 'er'); }
    })();
};

window.printApprovedMatReport = function () {
    const projKey = $('mPrjK')?.value; if (!projKey) { toast('احفظ المشروع أولاً', 'er'); return; }
    const fromVal = $('prjMatReportFrom')?.value; const toVal = $('prjMatReportTo')?.value;
    if (!fromVal || !toVal) { toast('اختر نطاق التاريخ (من وإلى)', 'er'); return; }
    const from = new Date(fromVal); from.setHours(0, 0, 0, 0);
    const to = new Date(toVal); to.setHours(23, 59, 59, 999);
    if (from > to) { toast('تأكد أن تاريخ البداية قبل النهاية', 'er'); return; }
    const approved = Object.entries(matRequests).filter(([, r]) => {
        if (!(r.projectId === projKey || (r.project && r.project.id === projKey))) return false;
        if (r.status !== 'approved') return false;
        if (!r.managerDecisionAt) return false;
        const md = new Date(r.managerDecisionAt);
        return md >= from && md <= to;
    }).map(([k, r]) => ({ key: k, ...r }));
    const rows = approved.map(a => {
        const m = materials[a.materialId || (a.material && a.material.id)];
        const name = m?.name || (a.material && a.material.name) || '—';
        const qty = parseFloat(a.approvedQty) || 0;
        const price = parseFloat(a.approvedUnitPrice) || 0;
        const line = qty * price;
        return `<tr><td style="padding:6px;border:1px solid #e8eef6">${name}</td><td style="padding:6px;border:1px solid #e8eef6;text-align:right">${qty}</td><td style="padding:6px;border:1px solid #e8eef6;text-align:right">${fmt(price)}</td><td style="padding:6px;border:1px solid #e8eef6;text-align:right">${fmt(line)}</td></tr>`;
    }).join('');
    const total = approved.reduce((s, a) => s + ((parseFloat(a.approvedQty) || 0) * (parseFloat(a.approvedUnitPrice) || 0)), 0);
    const p = projects[projKey] || {};
    const win = window.open('', '_blank');
    const html = `<!doctype html><html lang="ar" dir="rtl"><head><meta charset="utf-8"><title>تقرير المواد الموافق عليها - ${p.name || ''}</title><style>body{font-family:Arial,Helvetica,sans-serif;padding:16px;direction:rtl}table{width:100%;border-collapse:collapse}th,td{border:1px solid #e8eef6;padding:8px}th{background:#f0f6fb}</style></head><body><h2>تقرير المواد الموافق عليها</h2><div>المشروع: ${p.name || '-'} • النطاق: ${fromVal} → ${toVal}</div><table style="margin-top:12px"><thead><tr><th>المادة</th><th>الكمية</th><th>سعر الوحدة</th><th>الإجمالي</th></tr></thead><tbody>${rows || '<tr><td colspan="4" style="padding:12px;text-align:center;color:#777">لا توجد مواد الموافق عليها ضمن هذا النطاق</td></tr>'}</tbody></table><div style="margin-top:12px;font-weight:800">الإجمالي: ${fmt(total)} ريال</div><div style="margin-top:18px"><button onclick="window.print()" style="padding:8px 14px;background:#1a3a5c;color:#fff;border:none;border-radius:6px;cursor:pointer">طباعة</button></div></body></html>`;
    win.document.write(html); win.document.close();
};

window.openAddMaterialM = function () {
    if (!can('add_material')) { toast('ليس لديك صلاحية إضافة مواد', 'er'); return; }
    if ($('mMatName')) {
        $('mMatName').value = '';
        $('mMatSku').value = '';
        $('mMatUnit').value = '';
        $('mMatCost').value = '0';
        ov('mMat');
    } else {
        // fallback to prompt if modal not available
        const name = prompt('اسم المادة:'); if (!name) return; const sku = prompt('SKU (اختياري):') || ''; const unit = prompt('الوحدة (مثال: m, kg, pcs):') || ''; const cost = parseFloat(prompt('سعر الوحدة الافتراضي:') || 0);
        (async () => { try { await push(R.mat, { name, sku, unit, unitCost: cost || 0, createdAt: new Date().toISOString() }); toast('✅ تم إضافة المادة', 'ok'); fillMatDrp(); } catch (e) { toast('خطأ: ' + e.message, 'er'); } })();
    }
};

window.saveMaterial = async function () {
    const name = $('mMatName').value.trim(); if (!name) { toast('اسم المادة مطلوب', 'er'); return; }
    const sku = $('mMatSku').value.trim(); const unit = $('mMatUnit').value.trim(); const cost = parseFloat($('mMatCost').value) || 0;
    try {
        const pRef = await push(R.mat, { name, sku, unit, unitCost: cost || 0, createdAt: new Date().toISOString(), createdBy: curU?.uid || '' });
        const newKey = pRef.key || pRef?.name || null;
        toast('✅ تم إضافة المادة', 'ok');
        cov('mMat');
        // refresh materials dropdown
        fillMatDrp();
        // if project material select exists, set it to the newly created material
        if ($('prjMatSelect') && newKey) {
            // set value and trigger focus to qty for quick request
            $('prjMatSelect').value = newKey;
            if ($('reqQty')) $('reqQty').focus();
        }
        // if project modal is open and a project is selected, refresh its material lists
        const pk = $('mPrjK')?.value;
        if (pk) renderProjectMatLists(pk);
    } catch (e) { toast('خطأ: ' + e.message, 'er'); }
};

// Load projects from database
onValue(ref(db, 'ledger/projects'), sn => {
    projects = sn.exists() ? sn.val() : {};
    if ($('pg-projects').classList.contains('act')) renderProjects();
});

