// إضافة خصم شهري للموظف
window.addMonthlyDeduction = async function () {
    const key = $('mEmpK')?.value; if (!key) return;
    const month = $('mdMonth')?.value;
    const reason = $('mdReason')?.value?.trim();
    const type = $('mdType')?.value;
    const amount = parseFloat($('mdAmount')?.value) || 0;
    if (!month) { toast('اختر الشهر', 'er'); return }
    if (!reason) { toast('أدخل سبب الخصم', 'er'); return }
    if (amount <= 0) { toast('أدخل مبلغاً صحيحاً', 'er'); return }
    const typeLabels = { absence: '🔴 غياب', late: '🟡 تأخير', penalty: '⚫ جزاء', other: '⚪ أخرى' };
    try {
        await push(ref(db, `ledger/employees/${key}/monthlyDeductions`), {
            month, reason, type, amount,
            createdBy: myP?.name || '', createdAt: new Date().toISOString()
        });
        toast(`✅ تم إضافة الخصم: ${typeLabels[type]} — ${fmt(amount)} ر`, 'ok');
        $('mdMonth').value = ''; $('mdReason').value = ''; $('mdAmount').value = '';
        loadEmpMonthlyDeductions(key);
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// تحميل وعرض الخصومات الشهرية
window.loadEmpMonthlyDeductions = async function (key) {
    const container = $('mdList'); if (!container) return;
    const eData = emp[key];
    const deductions = eData?.monthlyDeductions ? Object.entries(eData.monthlyDeductions) : [];
    if (!deductions.length) { container.innerHTML = '<div style="text-align:center;padding:20px;color:#aaa;font-size:13px">لا توجد خصومات شهرية</div>'; return }
    deductions.sort((a, b) => b[1].month?.localeCompare(a[1].month));
    const typeLabels = { absence: '🔴 غياب', late: '🟡 تأخير', penalty: '⚫ جزاء', other: '⚪ أخرى' };
    const total = deductions.reduce((s, [, d]) => s + (d.amount || 0), 0);
    container.innerHTML = `
        <div style="background:#fdecea;border-radius:8px;padding:8px 14px;margin-bottom:10px;display:flex;justify-content:space-between;align-items:center">
            <span style="font-size:13px;color:#7b1c1c;font-weight:700">إجمالي الخصومات المسجلة</span>
            <span style="font-size:16px;font-weight:900;color:#c62828">${fmt(total)} ريال</span>
        </div>
        <table style="width:100%;border-collapse:collapse;font-size:12px">
            <thead><tr style="background:#f8fafc;color:#1a3a5c">
                <th style="padding:8px;text-align:right;border-bottom:2px solid #e0e8f0">الشهر</th>
                <th style="padding:8px;text-align:right;border-bottom:2px solid #e0e8f0">النوع</th>
                <th style="padding:8px;text-align:right;border-bottom:2px solid #e0e8f0">السبب</th>
                <th style="padding:8px;text-align:right;border-bottom:2px solid #e0e8f0">المبلغ</th>
                <th style="padding:8px;text-align:right;border-bottom:2px solid #e0e8f0">بواسطة</th>
                <th style="padding:8px;border-bottom:2px solid #e0e8f0"></th>
            </tr></thead>
            <tbody>${deductions.map(([dk, d], i) => `<tr style="${i%2?'background:#fafcff':''}">
                <td style="padding:8px;font-weight:700">${formatMonthLabel(d.month)}</td>
                <td style="padding:8px">${typeLabels[d.type] || d.type}</td>
                <td style="padding:8px;color:#555">${d.reason}</td>
                <td style="padding:8px;color:#c62828;font-weight:700">${fmt(d.amount)}</td>
                <td style="padding:8px;color:#888;font-size:11px">${d.createdBy || '-'}</td>
                <td style="padding:8px"><button class="btn b-r" style="padding:3px 8px;font-size:11px" onclick="deleteMonthlyDeduction('${key}','${dk}')">🗑️</button></td>
            </tr>`).join('')}</tbody>
        </table>`;
};

window.deleteMonthlyDeduction = function (empKey, dk) {
    cf2('حذف هذا الخصم؟', async () => {
        try { await remove(ref(db, `ledger/employees/${empKey}/monthlyDeductions/${dk}`)); loadEmpMonthlyDeductions(empKey); toast('تم الحذف', 'ok') }
        catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

