// ║   💳  [HR3]   ━━━━   LOANS / ADVANCES   ━━━━                                ║
// ║                السلف والقروض                                               ║
// ╚══════════════════════════════════════════════════════════════════════════╝

// حساب القسط الشهري
window.calcLoanInstalment = function () {
    const amt = parseFloat($('lnAmount')?.value) || 0;
    const inst = parseInt($('lnInstallments')?.value) || 1;
    const monthly = inst > 0 ? amt / inst : 0;
    if ($('lnMonthly')) $('lnMonthly').value = monthly > 0 ? fmt(monthly) + ' ريال' : '';
};

// إضافة سلفة جديدة
window.addLoan = async function () {
    const key = $('mEmpK')?.value; if (!key) return;
    const amount = parseFloat($('lnAmount')?.value) || 0;
    const date = $('lnDate')?.value;
    const installments = parseInt($('lnInstallments')?.value) || 1;
    const note = $('lnNote')?.value?.trim() || '';
    if (amount <= 0) { toast('أدخل مبلغ السلفة', 'er'); return }
    if (!date) { toast('اختر تاريخ الاستلام', 'er'); return }
    const monthly = parseFloat((amount / installments).toFixed(2));
    // بناء جدول الأقساط
    const schedule = [];
    const startDate = new Date(date);
    for (let i = 0; i < installments; i++) {
        const d = new Date(startDate.getFullYear(), startDate.getMonth() + i + 1, 1);
        schedule.push({ month: `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`, amount: monthly, paid: false, deferred: false });
    }
    try {
        const loanData = {
            empKey: key, empName: emp[key]?.name || '',
            amount, date, installments, monthly, note,
            remaining: amount, status: 'active',
            schedule,
            createdBy: myP?.name || '', createdAt: new Date().toISOString()
        };
        await push(R.loans, loanData);
        toast(`✅ تم تسجيل سلفة ${fmt(amount)} ريال — ${installments} قسط`, 'ok');
        $('lnAmount').value = ''; $('lnDate').value = ''; $('lnInstallments').value = 1; $('lnMonthly').value = ''; $('lnNote').value = '';
        if ($('lnStatus')) $('lnStatus').textContent = '';
        loadEmpLoans(key);
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// تحميل سلف الموظف في تبويب السلف
window.loadEmpLoans = function (key) {
    const container = $('loanList'); if (!container) return;
    const empLoans = Object.entries(loans).filter(([, l]) => l.empKey === key);
    if (!empLoans.length) { container.innerHTML = '<div style="text-align:center;padding:20px;color:#aaa;font-size:13px">لا توجد سلف</div>'; return }
    empLoans.sort((a, b) => b[1].createdAt?.localeCompare(a[1].createdAt));
    container.innerHTML = empLoans.map(([lk, l]) => {
        const paid = (l.schedule || []).filter(s => s.paid).length;
        const total = (l.schedule || []).length;
        const remaining = (l.schedule || []).filter(s => !s.paid).reduce((s, x) => s + x.amount, 0);
        const pct = total > 0 ? Math.round((paid / total) * 100) : 0;
        const statusBadge = l.status === 'settled'
            ? `<span style="background:#d5f5e3;color:#1e8449;padding:2px 10px;border-radius:10px;font-size:11px;font-weight:700">✅ مسددة</span>`
            : `<span style="background:#fff3e0;color:#e67e22;padding:2px 10px;border-radius:10px;font-size:11px;font-weight:700">⏳ ${paid}/${total} قسط</span>`;
        const scheduleRows = (l.schedule || []).map((s, idx) => {
            const paidByPayroll = s.paymentMethod === 'payroll_deduction' && s.paidByPayrollMonth;
            return `
            <tr style="${s.paid ? 'background:#f0fff4;color:#888' : ''}">
                <td style="padding:5px 8px">${formatMonthLabel(s.month)}</td>
                <td style="padding:5px 8px;font-weight:${s.paid?'400':'700'}">${fmt(s.amount)}</td>
                <td style="padding:5px 8px">
                    ${s.paid ? '✅ مدفوع' : s.deferred ? '⏸️ مؤجل' : '⏳ قادم'}
                    ${paidByPayroll ? `<div style="font-size:9px;color:#0e6655;font-weight:700;margin-top:2px;background:#e8f8f5;padding:1px 5px;border-radius:3px;display:inline-block" title="تم خصم القسط من راتب ${formatMonthLabel(s.paidByPayrollMonth)}">💵 من مسير ${formatMonthLabel(s.paidByPayrollMonth)}</div>` : ''}
                </td>
                <td style="padding:5px 8px;display:flex;gap:4px;flex-wrap:wrap">
                    ${!s.paid && !l.schedule.every(x=>x.paid) ? `
                        <button class="btn b-g" style="padding:2px 7px;font-size:10px" onclick="payLoanInstalment('${lk}',${idx})">✅ دفع</button>
                        <button class="btn" style="padding:2px 7px;font-size:10px;background:#f39c12;color:white" onclick="deferLoanInstalment('${lk}',${idx})">⏸️ تأجيل</button>
                    ` : ''}
                    ${paidByPayroll ? `<button class="btn b-b" style="padding:2px 7px;font-size:10px" onclick="goToPayrollFromLoan('${s.paidByPayrollKey}')" title="عرض المسير">🔍 المسير</button>` : ''}
                </td>
            </tr>`;
        }).join('');
        return `<div style="border:1.5px solid #e0e8f0;border-radius:10px;padding:14px;margin-bottom:12px;border-right:4px solid ${l.status==='settled'?'#27ae60':'#f39c12'}">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:6px;margin-bottom:10px">
                <div>
                    <div style="font-size:14px;font-weight:800;color:#1a3a5c">💳 ${fmt(l.amount)} ريال — ${l.note || 'سلفة'}</div>
                    <div style="font-size:11px;color:#888;margin-top:2px">تاريخ الاستلام: ${l.date} | ${l.installments} قسط شهري ${fmt(l.monthly)} ريال</div>
                </div>
                <div style="display:flex;gap:6px;align-items:center">${statusBadge}
                    <button class="btn b-b" style="padding:2px 8px;font-size:10px" onclick="loanStatement('${lk}')">📄 كشف</button>
                    ${l.status !== 'settled' ? `<button class="btn b-r" style="padding:2px 8px;font-size:10px" onclick="deleteLoan('${lk}')">🗑️</button>` : ''}
                </div>
            </div>
            <div style="background:#f0f4f8;border-radius:6px;height:6px;margin-bottom:10px">
                <div style="background:#27ae60;height:100%;border-radius:6px;width:${pct}%;transition:width .4s"></div>
            </div>
            <div style="font-size:11px;color:#888;margin-bottom:8px">متبقي: <strong style="color:#e74c3c">${fmt(remaining)} ريال</strong> | مدفوع: ${paid} من ${total} قسط</div>
            <div style="max-height:220px;overflow-y:auto">
            <table style="width:100%;border-collapse:collapse;font-size:12px">
                <thead><tr style="background:#f8fafc"><th style="padding:5px 8px;text-align:right;border-bottom:1px solid #e0e8f0">الشهر</th><th style="padding:5px 8px;text-align:right;border-bottom:1px solid #e0e8f0">المبلغ</th><th style="padding:5px 8px;text-align:right;border-bottom:1px solid #e0e8f0">الحالة</th><th style="padding:5px 8px;border-bottom:1px solid #e0e8f0"></th></tr></thead>
                <tbody>${scheduleRows}</tbody>
            </table></div>
        </div>`;
    }).join('');
};

// دفع قسط
window.payLoanInstalment = async function (lk, idx) {
    const l = loans[lk]; if (!l) return;
    const schedule = [...(l.schedule || [])];
    schedule[idx] = { ...schedule[idx], paid: true, paidAt: new Date().toISOString() };
    const allPaid = schedule.every(s => s.paid);
    try {
        await update(ref(db, `ledger/loans/${lk}`), {
            schedule, status: allPaid ? 'settled' : 'active',
            remaining: schedule.filter(s => !s.paid).reduce((s, x) => s + x.amount, 0)
        });
        toast('✅ تم تسجيل القسط كمدفوع', 'ok');
        const key = $('mEmpK')?.value; if (key) loadEmpLoans(key);
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// تأجيل قسط للشهر القادم
window.deferLoanInstalment = async function (lk, idx) {
    const l = loans[lk]; if (!l) return;
    const schedule = [...(l.schedule || [])];
    const current = schedule[idx];
    if (current.deferred) { toast('⚠️ هذا القسط مؤجل مسبقاً', 'wn'); return }
    // أجّل الشهر الحالي وأضف قسطاً في نهاية الجدول
    schedule[idx] = { ...current, deferred: true };
    const lastMonth = schedule[schedule.length - 1]?.month || current.month;
    const [y, m] = lastMonth.split('-').map(Number);
    const nextDate = new Date(y, m, 1); // شهر بعد آخر قسط
    schedule.push({ month: `${nextDate.getFullYear()}-${String(nextDate.getMonth() + 1).padStart(2, '0')}`, amount: current.amount, paid: false, deferred: false, deferredFrom: current.month });
    try {
        await update(ref(db, `ledger/loans/${lk}`), { schedule, installments: schedule.length });
        toast('⏸️ تم تأجيل القسط للشهر القادم', 'ok');
        const key = $('mEmpK')?.value; if (key) loadEmpLoans(key);
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// حذف سلفة
window.deleteLoan = function (lk) {
    cf2('حذف هذه السلفة بالكامل؟', async () => {
        try {
            await remove(ref(db, `ledger/loans/${lk}`));
            toast('🗑️ تم الحذف', 'ok');
            const key = $('mEmpK')?.value; if (key) loadEmpLoans(key);
        } catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

// كشف حساب السلفة
window.loanStatement = function (lk) {
    const l = loans[lk]; if (!l) return;
    const paid = (l.schedule || []).filter(s => s.paid).length;
    const remaining = (l.schedule || []).filter(s => !s.paid).reduce((s, x) => s + x.amount, 0);
    const win = window.open('', '_blank', 'width=720,height:600');
    const rows = (l.schedule || []).map((s, i) => `<tr style="${s.paid ? 'background:#f0fff4' : s.deferred ? 'background:#fffde7' : ''}">
        <td>${i + 1}</td>
        <td>${formatMonthLabel(s.month)}</td>
        <td>${fmt(s.amount)}</td>
        <td>${s.paid ? '✅ مدفوع' : s.deferred ? '⏸️ مؤجل' : '⏳ قادم'}</td>
        <td>${s.paidAt ? new Date(s.paidAt).toLocaleDateString('ar-SA') : (s.deferredFrom ? 'مؤجل من ' + formatMonthLabel(s.deferredFrom) : '-')}</td>
    </tr>`).join('');
    win.document.write(`<!DOCTYPE html><html lang="ar" dir="rtl"><head><meta charset="UTF-8"><title>كشف سلفة</title>
<style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',Tahoma,sans-serif;background:#f0f2f5;direction:rtl;padding:20px}
.wrap{max-width:700px;margin:0 auto;background:white;border-radius:12px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,.1)}
.hd{background:linear-gradient(135deg,#1a3a5c,#2d6a9f);color:white;padding:20px 24px}
.bd{padding:20px}
.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:16px}
.st{background:#f8fafc;border-radius:8px;padding:12px;text-align:center;border:1px solid #e0e8f0}
.sv{font-size:17px;font-weight:800;margin-bottom:3px}.sl{font-size:11px;color:#888}
table{width:100%;border-collapse:collapse;font-size:13px}
th{padding:10px 8px;background:#f0f5fa;color:#1a3a5c;text-align:center;border-bottom:2px solid #dce8f0}
td{padding:9px 8px;text-align:center;border-bottom:1px solid #f0f4f8}
@media print{body{background:white;padding:0}.hd{-webkit-print-color-adjust:exact;print-color-adjust:exact}}</style></head>
<body><div class="wrap">
<div class="hd">
    <div style="font-size:18px;font-weight:800">💳 كشف حساب السلفة</div>
    <div style="margin-top:4px;opacity:.85;font-size:13px">الموظف: ${l.empName} | ${l.note || 'سلفة'}</div>
</div>
<div class="bd">
    <div class="stats">
<div class="st"><div class="sv" style="color:#2d6a9f">${fmt(l.amount)}</div><div class="sl">إجمالي السلفة</div></div>
<div class="st"><div class="sv" style="color:#27ae60">${fmt(l.amount - remaining)}</div><div class="sl">المسدد</div></div>
<div class="st"><div class="sv" style="color:#e74c3c">${fmt(remaining)}</div><div class="sl">المتبقي</div></div>
<div class="st"><div class="sv" style="color:#f39c12">${paid}/${l.schedule?.length || 0}</div><div class="sl">أقساط مدفوعة</div></div>
    </div>
    <table><thead><tr><th>#</th><th>الشهر</th><th>مبلغ القسط</th><th>الحالة</th><th>ملاحظات</th></tr></thead>
    <tbody>${rows}</tbody></table>
    <div style="margin-top:14px;text-align:left"><button onclick="window.print()" style="background:#1a3a5c;color:white;border:none;padding:8px 18px;border-radius:8px;cursor:pointer;font-size:13px">🖨️ طباعة</button></div>
</div></div></body></html>`);
    win.document.close();
};

// ── صفحة السلف الكاملة ─────────────────────
function fillLoanEmpFilter() {
    const sel = $('lnFilterEmp'); if (!sel) return;
    const cur = sel.value;
    sel.innerHTML = '<option value="">-- جميع الموظفين --</option>';
    const empInLoans = [...new Set(Object.values(loans).map(l => l.empKey))];
    empInLoans.forEach(k => {
        const name = emp[k]?.name || k;
        sel.innerHTML += `<option value="${k}">${name}</option>`;
    });
    if (cur) sel.value = cur;
}

window.renderLoansPage = function () {
    fillLoanEmpFilter();
    const container = $('loansPageList'); if (!container) return;
    const empF = $('lnFilterEmp')?.value || '';
    const statusF = $('lnFilterStatus')?.value || '';
    let rows = Object.entries(loans);
    if (empF) rows = rows.filter(([, l]) => l.empKey === empF);
    if (statusF) rows = rows.filter(([, l]) => l.status === statusF);
    rows.sort((a, b) => b[1].createdAt?.localeCompare(a[1].createdAt));
    if (!rows.length) { container.innerHTML = '<div class="empty"><div class="ei">💳</div><p>لا توجد سلف</p></div>'; return }
    container.innerHTML = rows.map(([lk, l]) => {
        const paid = (l.schedule || []).filter(s => s.paid).length;
        const total = (l.schedule || []).length;
        const remaining = (l.schedule || []).filter(s => !s.paid).reduce((s, x) => s + x.amount, 0);
        const pct = total > 0 ? Math.round((paid / total) * 100) : 0;
        const statusBadge = l.status === 'settled'
            ? `<span style="background:#d5f5e3;color:#1e8449;padding:2px 10px;border-radius:10px;font-size:11px;font-weight:700">✅ مسددة</span>`
            : `<span style="background:#fff3e0;color:#e67e22;padding:2px 10px;border-radius:10px;font-size:11px;font-weight:700">⏳ قيد السداد</span>`;
        return `<div style="border:1.5px solid #e0e8f0;border-radius:10px;padding:14px;margin-bottom:10px;border-right:4px solid ${l.status==='settled'?'#27ae60':'#f39c12'}">
            <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
                <div>
                    <div style="font-size:14px;font-weight:800;color:#1a3a5c">👤 ${l.empName || '-'} — ${fmt(l.amount)} ريال</div>
                    <div style="font-size:11px;color:#888;margin-top:2px">${l.note || 'سلفة'} | تاريخ الاستلام: ${l.date} | ${l.installments} قسط</div>
                </div>
                <div style="display:flex;gap:6px;align-items:center">
                    ${statusBadge}
                    <button class="btn b-b" style="padding:3px 10px;font-size:11px" onclick="loanStatement('${lk}')">📄 كشف</button>
                </div>
            </div>
            <div style="display:flex;gap:16px;margin-top:10px;align-items:center;flex-wrap:wrap">
                <div style="flex:1;min-width:140px">
                    <div style="background:#f0f4f8;border-radius:6px;height:6px"><div style="background:#27ae60;height:100%;border-radius:6px;width:${pct}%"></div></div>
                    <div style="font-size:11px;color:#888;margin-top:3px">${paid}/${total} قسط مدفوع (${pct}%)</div>
                </div>
                <div style="font-size:13px;font-weight:700;color:#e74c3c">متبقي: ${fmt(remaining)} ريال</div>
            </div>
        </div>`;
    }).join('');
};

function updateLoansKPIs() {
    const all = Object.values(loans);
    $('lnk1') && ($('lnk1').textContent = all.length);
    $('lnk2') && ($('lnk2').textContent = all.filter(l => l.status === 'active').length);
    $('lnk3') && ($('lnk3').textContent = all.filter(l => l.status === 'settled').length);
    const totalRemaining = all.reduce((s, l) => s + ((l.schedule || []).filter(x => !x.paid).reduce((a, x) => a + x.amount, 0)), 0);
    $('lnk4') && ($('lnk4').textContent = fmt(totalRemaining));
}

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   ╰─  نهاية القسم [HR3]  ─  السلف والقروض                                  ║
// ╚══════════════════════════════════════════════════════════════════════════╝


// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   💵  [HR4]   ━━━━   PAYROLL   ━━━━                                       ║
// ║                مسير الرواتب                                                ║
// ╚══════════════════════════════════════════════════════════════════════════╝

function initPayrollMonth() {
    const inp = $('prMonth');
    if (inp && !inp.value) {
        const now = new Date();
        inp.value = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
    }
    // تهيئة الفلاتر
    if (typeof onPRMonthChange === 'function') onPRMonthChange();
    if (typeof onPRScopeChange === 'function') onPRScopeChange();
}

// احتساب راتب موظف واحد بناءً على وضع الاحتساب
function calcEmpPayForMonth(empKey, eData, month, calcMode, fromDate, toDate, deductAbsence, payCarAllow) {
    payCarAllow = payCarAllow !== false; // افتراضياً يُصرف البدل غير الخاضع للخصم ما لم يُوقَف صراحةً لهذا المسير
    const f = empFinance(eData);
    const dailyHours = parseFloat(eData.dailyHours) || 8;
    const [yy, mm] = month.split('-').map(Number);

    // 🆕 تحديد نطاق التاريخ الفعلي للاحتساب
    const useCustomRange = !!(fromDate && toDate);
    const monthFirstDay = `${yy}-${String(mm).padStart(2, '0')}-01`;
    const monthLastDayNum = new Date(yy, mm, 0).getDate();
    const monthLastDay = `${yy}-${String(mm).padStart(2, '0')}-${String(monthLastDayNum).padStart(2, '0')}`;
    const rangeStart = useCustomRange ? fromDate : monthFirstDay;
    const rangeEnd = useCustomRange ? toDate : monthLastDay;
    const rangeStartDate = new Date(rangeStart);
    const rangeEndDate = new Date(rangeEnd);

    // عدد الأيام في النطاق المحدد (شامل اليومين)
    const rangeDaysTotal = Math.max(1, Math.floor((rangeEndDate - rangeStartDate) / (1000 * 60 * 60 * 24)) + 1);

    // أيام الراحة الأسبوعية ضمن النطاق
    let weekendDays = 0;
    for (let d = new Date(rangeStartDate); d <= rangeEndDate; d.setDate(d.getDate() + 1)) {
        const dow = d.getDay();
        if (dow === 5 || dow === 6) weekendDays++;
    }
    const workingDaysExpected = rangeDaysTotal - weekendDays;
    const expectedMonthlyHours = workingDaysExpected * dailyHours;
    // للتوافق العكسي
    const monthDaysTotal = rangeDaysTotal;

    // سجلات الحضور ضمن النطاق
    const monthRecs = Object.values(attendance).filter(a => a.employeeId === empKey && a.date >= rangeStart && a.date <= rangeEnd);
    const actualDays = monthRecs.length;
    const actualHours = monthRecs.reduce((s, a) => s + (a.totalHours || 0), 0);

    // الإجازات المعتمدة المتداخلة مع النطاق
    const paidLeaveTypes = ['annual', 'sick', 'emergency', 'maternity', 'hajj', 'bereavement', 'other'];
    let paidLeaveDays = 0, unpaidLeaveDays = 0, annualLeaveDays = 0;
    Object.values(leaves).forEach(lv => {
        if (lv.empKey !== empKey || lv.status !== 'approved') return;
        const lvFrom = new Date(lv.from), lvTo = new Date(lv.to);
        const overlapStart = lvFrom > rangeStartDate ? lvFrom : rangeStartDate;
        const overlapEnd = lvTo < rangeEndDate ? lvTo : rangeEndDate;
        if (overlapEnd < overlapStart) return;
        const overlapDays = Math.floor((overlapEnd - overlapStart) / (1000 * 60 * 60 * 24)) + 1;
        if (paidLeaveTypes.includes(lv.type)) paidLeaveDays += overlapDays;
        else if (lv.type === 'unpaid') unpaidLeaveDays += overlapDays;
        if (lv.type === 'annual') annualLeaveDays += overlapDays; // 🚗 لخصم نصيب بدل السيارة أثناء الإجازة السنوية
    });

    const absentDays = Math.max(0, workingDaysExpected - actualDays - paidLeaveDays);

    // 🆕 الراتب المحسوب يتناسب مع طول الفترة:
    // إذا الفترة = شهر كامل → الراتب الكامل
    // إذا الفترة < شهر → الراتب × (أيام الفترة ÷ أيام الشهر الكامل)
    const fullMonthDays = new Date(yy, mm, 0).getDate();
    const periodFactor = useCustomRange ? (rangeDaysTotal / fullMonthDays) : 1;
    const periodNetSalary = parseFloat((f.netSalary * periodFactor).toFixed(2));
    const periodGrossSalary = parseFloat((f.grossSalary * periodFactor).toFixed(2));
    // 🚗 القاعدة الخاضعة للخصم (تستثني بدل السيارة/الإضافي) + البدل نفسه منفصلاً
    const periodDeductibleNet = parseFloat((f.deductibleNet * periodFactor).toFixed(2));
    const periodCar = parseFloat((f.car * periodFactor).toFixed(2));

    // 🚗 بدل السيارة/الإضافي — ثابت شهري، يُخصم منه نصيب أيام الإجازة السنوية فقط، وقابل للإيقاف لكل مسير
    let carPaid = 0;
    if (payCarAllow && periodCar > 0) {
        const carEligibleDays = Math.max(0, rangeDaysTotal - annualLeaveDays);
        carPaid = parseFloat((periodCar * (carEligibleDays / rangeDaysTotal)).toFixed(2));
    }

    // قيمة اليوم والساعة لهذه الفترة — على القاعدة الخاضعة للخصم
    const dailyRateMonth = rangeDaysTotal > 0 ? periodDeductibleNet / rangeDaysTotal : 0;
    const hourlyRate = expectedMonthlyHours > 0 ? periodDeductibleNet / expectedMonthlyHours : 0;

    let earnedBase = periodDeductibleNet;
    let earnedNet = earnedBase + carPaid;
    let calcNote = useCustomRange ? `راتب جزئي (${rangeDaysTotal}/${fullMonthDays} يوم) = ${fmt(periodDeductibleNet)}` : 'راتب ثابت';

    if (calcMode === 'hours') {
        const paidLeaveHours = paidLeaveDays * dailyHours;
        const weekendHours = weekendDays * dailyHours;
        const effectiveHours = actualHours + paidLeaveHours + weekendHours;
        earnedBase = hourlyRate * effectiveHours;
        earnedNet = earnedBase + carPaid;
        calcNote = `${actualHours.toFixed(1)}س حضور${paidLeaveDays>0?` + ${paidLeaveHours}س إجازة`:''} + ${weekendHours}س راحة × ${fmt(hourlyRate)} ر/س = ${fmt(earnedBase)}`;
    } else if (calcMode === 'days') {
        const effectivePaidDays = actualDays + paidLeaveDays + weekendDays;
        earnedBase = dailyRateMonth * effectivePaidDays;
        earnedNet = earnedBase + carPaid;
        calcNote = `${actualDays}ي حضور${paidLeaveDays>0?` + ${paidLeaveDays}ي إجازة`:''} + ${weekendDays}ي راحة = ${effectivePaidDays}ي × ${fmt(dailyRateMonth)} ر/ي${useCustomRange?` (${fmt(periodDeductibleNet)}÷${rangeDaysTotal})`:` (${fmt(f.deductibleNet)}÷${monthDaysTotal})`} = ${fmt(earnedBase)}`;
    }
    if (carPaid > 0) calcNote += ` + 🚗 بدل ${fmt(carPaid)}${annualLeaveDays > 0 ? ` (بعد خصم ${annualLeaveDays}ي إجازة)` : ''} = ${fmt(earnedNet)}`;

    // الخصومات الشهرية المؤقتة
    const monthDeductions = Object.values(eData.monthlyDeductions || {}).filter(d => d.month === month);
    const monthDeductTotal = monthDeductions.reduce((s, d) => s + (d.amount || 0), 0);
    const monthDeductNote = monthDeductions.map(d => `${d.reason}: ${fmt(d.amount)}`).join(' | ');

    const unpaidLeaveDeduct = unpaidLeaveDays > 0 ? parseFloat((dailyRateMonth * unpaidLeaveDays).toFixed(2)) : 0;

    // 🆕 خصم الغياب (اختياري) — يُطبَّق فقط في «الراتب الثابت» عند تفعيله؛ الوضعان الآخران يخصمان الغياب أصلاً بطبيعتهما
    const absenceDeduct = (deductAbsence && calcMode === 'fixed' && absentDays > 0) ? parseFloat((dailyRateMonth * absentDays).toFixed(2)) : 0;
    // ⚠️ تنبيه: غياب مرتفع في الراتب الثابت بلا خصم (نصف أيام العمل أو أكثر)
    const absenceWarn = calcMode === 'fixed' && !deductAbsence && absentDays >= Math.ceil(workingDaysExpected / 2);

    // 🕘 خصم ساعات الأذونات المعتمدة القابلة للخصم — فقط في «الراتب الثابت» (الوضعان الآخران يخصمانها عبر الحضور، فتفادي الازدواج)
    let permHoursTotal = 0;
    if (calcMode === 'fixed') {
        Object.values(window.permissions || {}).forEach(pm => {
            if (pm.empKey === empKey && pm.status === 'approved' && pm.deductible !== false && (pm.date || '') >= rangeStart && (pm.date || '') <= rangeEnd) permHoursTotal += (parseFloat(pm.hours) || 0);
        });
    }
    permHoursTotal = Math.round(permHoursTotal * 100) / 100;
    const permDeduct = permHoursTotal > 0 ? parseFloat((hourlyRate * permHoursTotal).toFixed(2)) : 0;

    // أقساط السلف المستحقة (تبقى شهرية كاملة)
    const empLoans = Object.values(loans).filter(l => l.empKey === empKey && l.status === 'active');
    const loanDeductTotal = empLoans.reduce((s, l) => {
        const instalment = (l.schedule || []).find(x => x.month === month && !x.paid && !x.deferred);
        return s + (instalment ? instalment.amount : 0);
    }, 0);

    // مكافأة الأداء
    const perfEval = Object.values(performance).find(p => p.empKey === empKey && p.month === month);
    const perfBonusAmt = perfEval ? (parseFloat(perfEval.bonusAmt) || 0) : 0;
    const perfBonusNote = perfEval
        ? `⭐ ${getPerfRating(perfEval.avgScore).label} (${perfEval.avgScore?.toFixed(1)}/10) = ${fmt(perfBonusAmt)}${(perfEval.manualBonus||0)!==0?` [يدوي: ${perfEval.manualBonus>0?'+':''}${fmt(perfEval.manualBonus)}${perfEval.manualReason?' - '+perfEval.manualReason:''}]`:''}`
        : '';

    const totalDeductions = monthDeductTotal + loanDeductTotal + unpaidLeaveDeduct + absenceDeduct + permDeduct;
    const finalNet = Math.max(0, parseFloat((earnedNet - totalDeductions + perfBonusAmt).toFixed(2)));

    const leavesNote = paidLeaveDays > 0 || unpaidLeaveDays > 0
        ? `${paidLeaveDays>0?`🌴 ${paidLeaveDays}ي إجازة مدفوعة`:''}${paidLeaveDays>0&&unpaidLeaveDays>0?' | ':''}${unpaidLeaveDays>0?`📭 ${unpaidLeaveDays}ي بدون راتب (خصم ${fmt(unpaidLeaveDeduct)})`:''}`
        : '';
    const absenceNote = absenceDeduct > 0 ? `➖ خصم غياب ${absentDays}ي = ${fmt(absenceDeduct)}` : (absenceWarn ? `⚠️ غياب ${absentDays}ي بلا خصم — راجع` : '');
    const permNote = permDeduct > 0 ? `🕘 خصم أذونات ${permHoursTotal}س = ${fmt(permDeduct)}` : '';
    const carNote = f.car > 0
        ? (!payCarAllow ? `🚗 بدل السيارة موقوف هذا المسير` : (carPaid < periodCar ? `🚗 بدل سيارة ${fmt(carPaid)} (خُصم نصيب ${annualLeaveDays}ي إجازة سنوية)` : `🚗 بدل سيارة ${fmt(carPaid)}`))
        : '';
    const combinedNote = [monthDeductNote, leavesNote, perfBonusNote, absenceNote, permNote, carNote].filter(Boolean).join(' | ');

    return {
        empKey, name: eData.name || '', job: eData.job || '', dept: eData.dept || '',
        projectId: eData.projectId || '', projectName: eData.projectName || (eData.projectId && window.projects?.[eData.projectId]?.name) || '',
        affiliationType: eData.affiliationType || (eData.projectId ? 'project' : 'dept'),
        grossSalary: periodGrossSalary, totalDeductions: f.totalDeductions,
        netSalary: periodNetSalary, earnedNet: parseFloat(earnedNet.toFixed(2)),
        fullGrossSalary: f.grossSalary, fullNetSalary: f.netSalary,
        periodFactor, useCustomRange,
        rangeStart: useCustomRange ? rangeStart : '', rangeEnd: useCustomRange ? rangeEnd : '',
        monthDeductTotal: monthDeductTotal + unpaidLeaveDeduct + absenceDeduct + permDeduct, loanDeductTotal, totalExtraDeductions: totalDeductions,
        absenceDeduct, absenceWarn, permDeduct, permHours: permHoursTotal,
        carPaid, carAllow: periodCar, payCarAllow, annualLeaveDays,
        // 💰 تفصيل مكوّنات الراتب (لأعمدة العرض القابلة للإظهار/الإخفاء)
        sal: f.sal, house: f.house, trans: f.trans, phone: f.phone, nature: f.nature, rep: f.rep, perf: f.perf, bonus: f.bonus, ot: f.ot,
        perfBonusAmt, perfRating: perfEval?.rating || null, perfScore: perfEval?.avgScore || null,
        finalNet,
        monthDaysTotal, weekendDays, workingDaysExpected, dailyHours, expectedMonthlyHours,
        actualDays, actualHours: parseFloat(actualHours.toFixed(2)), absentDays,
        paidLeaveDays, unpaidLeaveDays, unpaidLeaveDeduct,
        dailyRate: parseFloat(dailyRateMonth.toFixed(2)),
        hourlyRate: parseFloat(hourlyRate.toFixed(2)),
        calcMode, calcNote, monthDeductNote: combinedNote, iban: eData.iban || ''
    };
}

// 🆕 فحص حالة الموظف في مسيرات الشهر الحالي (لمنع التكرار)
// ترجع: { hasPayroll: true/false, isDeferred: true/false, deferReason: '', payrollKey: '', payrollLabel: '' }
function getPRExistingStatus(empKey, month) {
    const result = { hasPayroll: false, isDeferred: false, deferReason: '', payrollKey: '', payrollLabel: '' };
    if (!month || !empKey) return result;

    // ابحث في كل مسيرات هذا الشهر (بأي نطاق)
    for (const [pKey, p] of Object.entries(payrolls || {})) {
        if (p.month !== month) continue;
        if (p.status === 'cancelled') continue;

        // 1. هل الموظف ضمن items (تم احتساب راتبه)؟
        const inItems = (p.items || []).find(i => i.empKey === empKey);
        if (inItems) {
            result.hasPayroll = true;
            result.payrollKey = pKey;
            const scopeLabel = p.scope === 'project' ? `📁 ${p.projectName || ''}` :
                               p.scope === 'dept' ? `🏢 ${p.dept || ''}` :
                               '👥 شامل';
            result.payrollLabel = `${scopeLabel}${p.scopeLabel || ''}`;
            return result; // وجدناه، خلاص
        }

        // 2. هل تم تأجيله في مسير سابق؟
        const deferred = (p.deferredEmployees || []).find(d => d.empKey === empKey);
        if (deferred) {
            // لو تأجل في مسير سابق ولم يُسدَّد في مسير آخر، نعتبره مُؤجَّلاً
            result.isDeferred = true;
            result.deferReason = deferred.reason || '';
            result.payrollKey = pKey;
        }
    }
    return result;
}

// ╔══════════════════════════════════════════════════════════════════╗
// ║   📅 دوال فلترة المسير + جدول الموظفين التفاعلي                      ║
// ╚══════════════════════════════════════════════════════════════════╝

// State لتتبع اختيارات الموظفين + أسباب التأجيل
window.prEmpsState = {
    selected: new Set(),   // مفاتيح الموظفين المُختارين
    deferReasons: {}       // { empKey: 'سبب التأجيل' }
};

// عند تغيير الشهر: حدّث الفترة الافتراضية + ملء قوائم المشاريع/الإدارات
window.onPRMonthChange = function () {
    const month = $('prMonth')?.value;
    if (!month) return;
    const [y, m] = month.split('-').map(Number);
    const firstDay = `${y}-${String(m).padStart(2, '0')}-01`;
    const lastDay = new Date(y, m, 0).getDate();
    const lastDayStr = `${y}-${String(m).padStart(2, '0')}-${String(lastDay).padStart(2, '0')}`;
    if ($('prFromDate') && !$('prFromDate').value) $('prFromDate').value = firstDay;
    if ($('prToDate') && !$('prToDate').value) $('prToDate').value = lastDayStr;
    fillPRProjects();
    fillPRDepts();
    renderPREmployeesTable();
};

// عند تغيير النطاق
window.onPRScopeChange = function () {
    const scope = $('prScope')?.value || 'all';
    if ($('prProjectWrap')) $('prProjectWrap').style.display = scope === 'project' ? 'block' : 'none';
    if ($('prDeptWrap')) $('prDeptWrap').style.display = scope === 'dept' ? 'block' : 'none';
    if (scope === 'project') fillPRProjects();
    if (scope === 'dept') fillPRDepts();
    renderPREmployeesTable();
};

// عند تغيير الفترة المخصصة
window.onPRCustomRangeToggle = function () {
    const use = $('prUseCustomRange')?.checked;
    if ($('prCustomRangeFields')) $('prCustomRangeFields').style.display = use ? 'grid' : 'none';
    if (use) onPRMonthChange();
    renderPREmployeesTable();
};

// ملء قائمة المشاريع المتاحة
function fillPRProjects() {
    const sel = $('prProject'); if (!sel) return;
    const current = sel.value;
    sel.innerHTML = '<option value="">-- اختر المشروع --</option>';
    const empProjectIds = new Set(Object.values(emp || {})
        .filter(e => (e.status || 'active') === 'active' && e.projectId)
        .map(e => e.projectId));
    Object.entries(window.projects || {}).forEach(([k, p]) => {
        if (empProjectIds.has(k)) {
            const count = Object.values(emp || {}).filter(e => (e.status || 'active') === 'active' && e.projectId === k).length;
            sel.innerHTML += `<option value="${k}">${p.name || k} (${count} موظف)</option>`;
        }
    });
    if (current) sel.value = current;
}

// ملء قائمة الإدارات
function fillPRDepts() {
    const sel = $('prDept'); if (!sel) return;
    const current = sel.value;
    sel.innerHTML = '<option value="">-- اختر الإدارة --</option>';
    const depts = [...new Set(Object.values(emp || {})
        .filter(e => (e.status || 'active') === 'active' && e.dept)
        .map(e => e.dept))].sort();
    depts.forEach(d => {
        const count = Object.values(emp || {}).filter(e => (e.status || 'active') === 'active' && e.dept === d).length;
        sel.innerHTML += `<option value="${d}">${d} (${count} موظف)</option>`;
    });
    if (current) sel.value = current;
}

// إرجاع قائمة الموظفين بعد تطبيق فلتر النطاق (قبل اختيار يدوي)
function getPRScopeFilteredEmployees() {
    const scope = $('prScope')?.value || 'all';
    let activeEmps = Object.entries(emp || {}).filter(([, e]) => (e.status || 'active') === 'active');
    if (scope === 'project') {
        const projId = $('prProject')?.value;
        if (!projId) return [];
        activeEmps = activeEmps.filter(([, e]) => e.projectId === projId);
    } else if (scope === 'dept') {
        const dept = $('prDept')?.value;
        if (!dept) return [];
        activeEmps = activeEmps.filter(([, e]) => e.dept === dept);
    }
    return activeEmps;
}

// فحص هل الموظف في إجازة خلال الفترة
function isEmpOnLeaveDuringPeriod(empKey, fromDate, toDate) {
    const from = new Date(fromDate), to = new Date(toDate);
    let totalLeaveDays = 0;
    Object.values(leaves || {}).forEach(lv => {
        if (lv.empKey !== empKey || lv.status !== 'approved') return;
        const lvFrom = new Date(lv.from), lvTo = new Date(lv.to);
        const overlapStart = lvFrom > from ? lvFrom : from;
        const overlapEnd = lvTo < to ? lvTo : to;
        if (overlapEnd < overlapStart) return;
        totalLeaveDays += Math.floor((overlapEnd - overlapStart) / (1000 * 60 * 60 * 24)) + 1;
    });
    const totalPeriodDays = Math.floor((to - from) / (1000 * 60 * 60 * 24)) + 1;
    // إذا كان في إجازة >= 80% من الفترة، نعتبره "في إجازة"
    return totalLeaveDays >= totalPeriodDays * 0.8 ? totalLeaveDays : 0;
}

// رسم جدول الموظفين التفاعلي
window.renderPREmployeesTable = function () {
    const section = $('prEmployeesSection'); if (!section) return;
    const month = $('prMonth')?.value;
    const scope = $('prScope')?.value || 'all';

    // إخفاء الجدول إذا الشهر فارغ أو لم يُحدد النطاق المطلوب
    if (!month || (scope === 'project' && !$('prProject')?.value) || (scope === 'dept' && !$('prDept')?.value)) {
        section.style.display = 'none';
        updatePRPreview();
        return;
    }

    const allScopeEmps = getPRScopeFilteredEmployees();

    // 🆕 تصنيف الموظفين:
    // - "مع مسير سابق" → إخفاء (لمنع التكرار)
    // - "مُؤجَّل سابقاً" → إظهار مع شارة خاصة
    // - "متاح" → إظهار عادي
    const empsList = [];           // الموظفون القابلون للاختيار (متاح + مؤجل سابقاً)
    const alreadyPaidEmps = [];    // الموظفون الذين لهم مسير بالفعل
    const previouslyDeferred = {}; // { empKey: { reason, payrollKey } }

    allScopeEmps.forEach(([k, e]) => {
        const status = getPRExistingStatus(k, month);
        if (status.hasPayroll) {
            alreadyPaidEmps.push({ key: k, emp: e, status });
        } else {
            if (status.isDeferred) {
                previouslyDeferred[k] = status;
            }
            empsList.push([k, e]);
        }
    });

    section.style.display = 'block';

    if (!empsList.length) {
        const msg = alreadyPaidEmps.length > 0
            ? `✅ جميع موظفي هذا النطاق (${alreadyPaidEmps.length}) تم إنشاء مسير لهم بالفعل في ${month}`
            : '⚠️ لا يوجد موظفون يطابقون النطاق المحدد';
        $('prEmpsTableBody').innerHTML = `<tr><td colspan="7" style="text-align:center;padding:30px;color:${alreadyPaidEmps.length > 0 ? '#27ae60' : '#888'};font-weight:700">${msg}</td></tr>`;
        $('prEmpsStats').innerHTML = alreadyPaidEmps.length > 0
            ? `<div style="background:#e8f8f5;padding:8px 14px;border-radius:6px;border-right:3px solid #27ae60;width:100%"><span style="color:#0e6655;font-weight:700">✅ ${alreadyPaidEmps.length} موظف تم إنشاء مسير لهم بالفعل في هذا الشهر</span></div>`
            : '';
        updatePRPreview();
        return;
    }

    // الفترة الحالية للفحص (للإجازات)
    const useCustom = $('prUseCustomRange')?.checked;
    const [y, m] = month.split('-').map(Number);
    const periodFrom = useCustom && $('prFromDate')?.value ? $('prFromDate').value : `${y}-${String(m).padStart(2, '0')}-01`;
    const lastDay = new Date(y, m, 0).getDate();
    const periodTo = useCustom && $('prToDate')?.value ? $('prToDate').value : `${y}-${String(m).padStart(2, '0')}-${String(lastDay).padStart(2, '0')}`;

    // إذا state.selected فارغ تماماً → اختر الكل افتراضياً (ما عدا من في إجازة كاملة)
    const currentEmpKeys = empsList.map(([k]) => k);
    const stateKeysInList = [...window.prEmpsState.selected].filter(k => currentEmpKeys.includes(k));
    if (stateKeysInList.length === 0) {
        window.prEmpsState.selected = new Set();
        empsList.forEach(([k]) => {
            const leaveDays = isEmpOnLeaveDuringPeriod(k, periodFrom, periodTo);
            if (!leaveDays) window.prEmpsState.selected.add(k);
        });
    }

    // بناء الصفوف
    const rows = empsList.map(([k, e]) => {
        const f = empFinance(e);
        const isSelected = window.prEmpsState.selected.has(k);
        const leaveDays = isEmpOnLeaveDuringPeriod(k, periodFrom, periodTo);
        const wasPreviouslyDeferred = !!previouslyDeferred[k];
        const prevDeferReason = previouslyDeferred[k]?.deferReason || '';

        const affLabel = e.projectId && window.projects?.[e.projectId]
            ? `<span style="background:#fef5e7;color:#7d4e00;padding:2px 6px;border-radius:4px;font-size:10px;font-weight:600">📁 ${window.projects[e.projectId].name || ''}</span>`
            : e.dept ? `<span style="background:#e8f4fd;color:#1a5276;padding:2px 6px;border-radius:4px;font-size:10px;font-weight:600">🏢 ${e.dept}</span>`
            : '<span style="color:#888">—</span>';

        let statusBadge = '';
        if (wasPreviouslyDeferred) {
            statusBadge = `<span style="background:#8e44ad;color:white;padding:3px 8px;border-radius:6px;font-size:10px;font-weight:700" title="${prevDeferReason}">🔄 مُؤجَّل سابقاً</span>`;
        } else if (leaveDays > 0) {
            statusBadge = `<span style="background:#fff3cd;color:#7d4e00;padding:3px 8px;border-radius:6px;font-size:10px;font-weight:700">🌴 في إجازة (${leaveDays}ي)</span>`;
        } else if (isSelected) {
            statusBadge = `<span style="background:#27ae60;color:white;padding:3px 8px;border-radius:6px;font-size:10px;font-weight:700">✅ سيتم إنشاء مسير</span>`;
        } else {
            statusBadge = `<span style="background:#e74c3c;color:white;padding:3px 8px;border-radius:6px;font-size:10px;font-weight:700">⏸️ مُؤجَّل</span>`;
        }

        // إذا كان مؤجلاً سابقاً، اعرض سبب التأجيل القديم
        const deferReason = window.prEmpsState.deferReasons[k] || (wasPreviouslyDeferred ? prevDeferReason : '');

        // لون الخلفية للصفوف:
        let rowBg = '';
        if (wasPreviouslyDeferred) rowBg = 'background:#f4ecf7';
        else if (!isSelected) rowBg = 'background:#fef9e7';

        return `<tr style="${rowBg}" data-emp-key="${k}">
            <td style="padding:8px;text-align:center">
                <input type="checkbox" class="prEmpCb" data-emp-key="${k}" ${isSelected ? 'checked' : ''} onchange="prToggleEmp('${k}', this.checked)" style="width:16px;height:16px;cursor:pointer">
            </td>
            <td style="padding:8px">
                <div style="font-weight:700;color:#1a3a5c">${e.name || '—'}</div>
                ${e.id ? `<div style="font-size:10px;color:#888;font-family:monospace">${e.id}</div>` : ''}
                ${wasPreviouslyDeferred ? `<div style="font-size:9px;color:#8e44ad;font-weight:700;margin-top:2px">🔄 مُؤجَّل من مسير سابق</div>` : ''}
            </td>
            <td style="padding:8px">${affLabel}</td>
            <td style="padding:8px;font-size:11px;color:#666">${e.job || '—'}</td>
            <td style="padding:8px;text-align:center;font-weight:700;color:#2d6a9f">${fmt(f.netSalary)}</td>
            <td style="padding:8px;text-align:center">${statusBadge}</td>
            <td style="padding:8px">
                <input type="text" placeholder="${isSelected ? 'لا حاجة لسبب' : 'مثلاً: في إجازة، تأجيل لاحق...'}" value="${deferReason}" oninput="prSetDeferReason('${k}', this.value)" ${isSelected ? 'disabled' : ''} style="width:100%;padding:5px 8px;border:1px solid #d0d7e0;border-radius:4px;font-size:11px;background:${isSelected ? '#f8f9fa' : 'white'};color:${isSelected ? '#aaa' : '#333'}">
            </td>
        </tr>`;
    }).join('');
    $('prEmpsTableBody').innerHTML = rows;

    // تحديث checkbox الرئيسي
    const allSelected = empsList.length > 0 && empsList.every(([k]) => window.prEmpsState.selected.has(k));
    if ($('prEmpSelectAll')) $('prEmpSelectAll').checked = allSelected;

    // الإحصائيات
    const selectedCount = empsList.filter(([k]) => window.prEmpsState.selected.has(k)).length;
    const deferredCount = empsList.length - selectedCount;
    const selectedSalaryTotal = empsList
        .filter(([k]) => window.prEmpsState.selected.has(k))
        .reduce((s, [, e]) => s + empFinance(e).netSalary, 0);
    const onLeaveCount = empsList.filter(([k]) => isEmpOnLeaveDuringPeriod(k, periodFrom, periodTo) > 0).length;
    const prevDeferredCount = Object.keys(previouslyDeferred).length;

    $('prEmpsStats').innerHTML = `
        <div style="background:#e8f8f5;padding:8px 14px;border-radius:6px;border-right:3px solid #27ae60">
            <div style="font-size:10px;color:#0e6655">✅ سيُولَّد لهم مسير</div>
            <div style="font-size:16px;font-weight:900;color:#27ae60">${selectedCount}</div>
        </div>
        ${deferredCount > 0 ? `<div style="background:#fef5e7;padding:8px 14px;border-radius:6px;border-right:3px solid #e67e22">
            <div style="font-size:10px;color:#7d4e00">⏸️ لن يُنشأ لهم مسير الآن</div>
            <div style="font-size:16px;font-weight:900;color:#e67e22">${deferredCount}</div>
        </div>` : ''}
        ${onLeaveCount > 0 ? `<div style="background:#fff3cd;padding:8px 14px;border-radius:6px;border-right:3px solid #f39c12">
            <div style="font-size:10px;color:#7d4e00">🌴 في إجازة</div>
            <div style="font-size:16px;font-weight:900;color:#f39c12">${onLeaveCount}</div>
        </div>` : ''}
        ${prevDeferredCount > 0 ? `<div style="background:#f4ecf7;padding:8px 14px;border-radius:6px;border-right:3px solid #8e44ad">
            <div style="font-size:10px;color:#5b2c6f">🔄 مُؤجَّل سابقاً</div>
            <div style="font-size:16px;font-weight:900;color:#8e44ad">${prevDeferredCount}</div>
        </div>` : ''}
        ${alreadyPaidEmps.length > 0 ? `<div style="background:#e8f4fd;padding:8px 14px;border-radius:6px;border-right:3px solid #2d6a9f">
            <div style="font-size:10px;color:#0d4f7c">💵 تم سدادهم بالفعل (مخفيون)</div>
            <div style="font-size:16px;font-weight:900;color:#2d6a9f">${alreadyPaidEmps.length}</div>
        </div>` : ''}
        <div style="background:#fef5e7;padding:8px 14px;border-radius:6px;border-right:3px solid #e67e22;flex:1;min-width:180px">
            <div style="font-size:10px;color:#7d4e00">💰 إجمالي الرواتب المُختارة</div>
            <div style="font-size:16px;font-weight:900;color:#e67e22">${fmt(selectedSalaryTotal)}</div>
        </div>
    `;

    updatePRPreview();
};

// تبديل اختيار موظف
window.prToggleEmp = function (empKey, checked) {
    if (checked) window.prEmpsState.selected.add(empKey);
    else window.prEmpsState.selected.delete(empKey);
    renderPREmployeesTable();
};

// اختيار الكل / إلغاء الكل
window.prSelectAllEmps = function (selectAll) {
    const empsList = getPRScopeFilteredEmployees();
    if (selectAll) {
        empsList.forEach(([k]) => window.prEmpsState.selected.add(k));
    } else {
        empsList.forEach(([k]) => window.prEmpsState.selected.delete(k));
    }
    renderPREmployeesTable();
};

// استبعاد من في إجازة
window.prSelectByLeaveStatus = function () {
    const month = $('prMonth')?.value; if (!month) return;
    const useCustom = $('prUseCustomRange')?.checked;
    const [y, m] = month.split('-').map(Number);
    const periodFrom = useCustom && $('prFromDate')?.value ? $('prFromDate').value : `${y}-${String(m).padStart(2, '0')}-01`;
    const lastDay = new Date(y, m, 0).getDate();
    const periodTo = useCustom && $('prToDate')?.value ? $('prToDate').value : `${y}-${String(m).padStart(2, '0')}-${String(lastDay).padStart(2, '0')}`;

    const empsList = getPRScopeFilteredEmployees();
    let excluded = 0;
    empsList.forEach(([k]) => {
        const leaveDays = isEmpOnLeaveDuringPeriod(k, periodFrom, periodTo);
        if (leaveDays > 0) {
            window.prEmpsState.selected.delete(k);
            if (!window.prEmpsState.deferReasons[k]) {
                window.prEmpsState.deferReasons[k] = `🌴 في إجازة (${leaveDays} يوم) — تأجيل تلقائي`;
            }
            excluded++;
        }
    });
    if (excluded > 0) toast(`⏸️ تم استبعاد ${excluded} موظف بسبب الإجازة`, 'wn');
    else toast('لا يوجد موظفون في إجازة خلال الفترة', 'ok');
    renderPREmployeesTable();
};

// تعديل سبب التأجيل
window.prSetDeferReason = function (empKey, reason) {
    if (reason && reason.trim()) {
        window.prEmpsState.deferReasons[empKey] = reason.trim();
    } else {
        delete window.prEmpsState.deferReasons[empKey];
    }
};

// تحديث معاينة عدد الموظفين المُحددين
function updatePRPreview() {
    const scope = $('prScope')?.value || 'all';
    const month = $('prMonth')?.value || '';
    const empsList = getPRScopeFilteredEmployees();
    const selectedEmps = empsList.filter(([k]) => window.prEmpsState.selected.has(k));
    const deferredCount = empsList.length - selectedEmps.length;
    const useCustom = $('prUseCustomRange')?.checked;
    const from = useCustom ? $('prFromDate')?.value : '';
    const to = useCustom ? $('prToDate')?.value : '';

    const previewEl = $('prPreviewInfo'); const textEl = $('prPreviewText');
    if (!previewEl || !textEl) return;

    if (!month) { previewEl.style.display = 'none'; return; }

    let scopeText = '';
    if (scope === 'all') scopeText = '👥 جميع الموظفين';
    else if (scope === 'project') {
        const projId = $('prProject')?.value;
        const projName = projId && window.projects?.[projId] ? window.projects[projId].name : '';
        scopeText = projId ? `📁 ${projName}` : '⚠️ لم تختر مشروعاً';
    } else if (scope === 'dept') {
        const dept = $('prDept')?.value;
        scopeText = dept ? `🏢 ${dept}` : '⚠️ لم تختر إدارة';
    }

    const periodText = useCustom && from && to ? `📅 ${from} → ${to}` : `📅 الشهر كاملاً`;
    previewEl.style.display = 'block';
    textEl.innerHTML = `<strong>✅ ${selectedEmps.length} موظف سيُولَّد لهم مسير</strong>${deferredCount > 0 ? ` · <span style="color:#e67e22;font-weight:700">⏸️ ${deferredCount} مُؤجَّل</span>` : ''} · ${scopeText} · ${periodText}`;
}

// 🆕 فتح مسير جديد للموظفين المُؤجَّلين من مسير سابق
window.reopenDeferredPayroll = function (sourcePayrollKey) {
    const sourceP = payrolls[sourcePayrollKey];
    if (!sourceP || !sourceP.deferredEmployees || !sourceP.deferredEmployees.length) {
        toast('⚠️ لا يوجد موظفون مُؤجَّلون في هذا المسير', 'er'); return;
    }
    // املأ الفلاتر بنفس بيانات المسير الأصلي
    if ($('prMonth')) $('prMonth').value = sourceP.month;
    if ($('prCalcMode')) $('prCalcMode').value = sourceP.calcMode || 'fixed';
    if ($('prDeductAbsence')) $('prDeductAbsence').checked = !!sourceP.deductAbsence;
    if ($('prPayCarAllow')) $('prPayCarAllow').checked = sourceP.payCarAllow !== false;
    if ($('prScope')) $('prScope').value = sourceP.scope || 'all';
    if (sourceP.scope === 'project' && $('prProject')) {
        onPRScopeChange();
        setTimeout(() => { $('prProject').value = sourceP.projectId || ''; renderPREmployeesTable(); }, 100);
    } else if (sourceP.scope === 'dept' && $('prDept')) {
        onPRScopeChange();
        setTimeout(() => { $('prDept').value = sourceP.dept || ''; renderPREmployeesTable(); }, 100);
    } else {
        onPRScopeChange();
    }
    // الفترة المخصصة
    if (sourceP.useCustomRange && $('prUseCustomRange')) {
        $('prUseCustomRange').checked = true;
        onPRCustomRangeToggle();
        if ($('prFromDate')) $('prFromDate').value = sourceP.fromDate || '';
        if ($('prToDate')) $('prToDate').value = sourceP.toDate || '';
    }
    // ✅ اختر فقط الموظفين المُؤجَّلين
    setTimeout(() => {
        window.prEmpsState.selected = new Set(sourceP.deferredEmployees.map(d => d.empKey));
        window.prEmpsState.deferReasons = {};
        renderPREmployeesTable();
        // مرر للصفحة لأعلى لرؤية الفلاتر
        const card = $('prMonth')?.closest('.card');
        if (card) card.scrollIntoView({ behavior: 'smooth', block: 'start' });
        toast(`✅ تم تجهيز مسير لـ ${sourceP.deferredEmployees.length} موظف مُؤجَّل — راجع البيانات واضغط "توليد المسير"`, 'ok', 6000);
    }, 250);
};

// توليد مسير جديد (نسخة محدثة بدعم الاختيار الفردي)
window.generatePayroll = async function () {
    if (myP?.role !== 'admin' && !can('create_payroll')) { toast('ليس لديك صلاحية إنشاء مسير', 'er'); return }
    const month = $('prMonth')?.value;
    const calcMode = $('prCalcMode')?.value || 'fixed';
    const deductAbsence = !!$('prDeductAbsence')?.checked;
    const payCarAllow = $('prPayCarAllow') ? !!$('prPayCarAllow').checked : true; // 🚗 صرف البدلات غير الخاضعة للخصم لهذا المسير
    if (!month) { toast('اختر الشهر أولاً', 'er'); return }

    const scope = $('prScope')?.value || 'all';
    const projectId = scope === 'project' ? $('prProject')?.value : '';
    const dept = scope === 'dept' ? $('prDept')?.value : '';
    const useCustom = !!$('prUseCustomRange')?.checked;
    const fromDate = useCustom ? $('prFromDate')?.value : '';
    const toDate = useCustom ? $('prToDate')?.value : '';

    if (scope === 'project' && !projectId) { toast('⚠️ يجب اختيار المشروع', 'er'); return }
    if (scope === 'dept' && !dept) { toast('⚠️ يجب اختيار الإدارة', 'er'); return }
    if (useCustom && (!fromDate || !toDate)) { toast('⚠️ يجب تحديد من/إلى للفترة المخصصة', 'er'); return }
    if (useCustom && fromDate > toDate) { toast('⚠️ تاريخ "من" يجب أن يسبق "إلى"', 'er'); return }

    // الموظفون في النطاق
    const scopeEmps = getPRScopeFilteredEmployees();
    if (!scopeEmps.length) {
        toast(scope === 'all' ? 'لا يوجد موظفون نشطون' : '⚠️ لا يوجد موظفون يطابقون النطاق', 'er');
        return;
    }

    // 🆕 الموظفون المُختارون فعلياً (مع استبعاد من لديه مسير في هذا الشهر)
    const selectedEmps = scopeEmps.filter(([k]) => {
        if (!window.prEmpsState.selected.has(k)) return false;
        // فحص مزدوج: تأكد من عدم وجود مسير سابق
        const existing = getPRExistingStatus(k, month);
        if (existing.hasPayroll) {
            return false; // استبعد تلقائياً
        }
        return true;
    });

    if (!selectedEmps.length) {
        toast('⚠️ لم تختر أي موظف صالح! تأكد من اختيار موظفين ليس لديهم مسير سابق في هذا الشهر', 'er');
        return;
    }

    // تحقق إضافي: إذا كان هناك موظفون في الاختيار لكنهم لديهم مسير سابق، حذرهم
    const skippedDueToExisting = [...window.prEmpsState.selected].filter(k => {
        const existing = getPRExistingStatus(k, month);
        return existing.hasPayroll;
    });
    if (skippedDueToExisting.length > 0) {
        const names = skippedDueToExisting.map(k => emp[k]?.name || k).join('، ');
        toast(`⚠️ تم تجاهل ${skippedDueToExisting.length} موظف لأن لديهم مسير في ${month}: ${names}`, 'wn', 8000);
    }

    // الموظفون المُؤجَّلون (من النطاق وليس لديهم مسير وليسوا مُختارين)
    const deferredEmps = scopeEmps
        .filter(([k]) => {
            const existing = getPRExistingStatus(k, month);
            if (existing.hasPayroll) return false; // ليس مُؤجَّلاً، بل لديه مسير
            return !window.prEmpsState.selected.has(k);
        })
        .map(([k, e]) => ({
            empKey: k,
            name: e.name || '',
            job: e.job || '',
            dept: e.dept || '',
            projectId: e.projectId || '',
            projectName: e.projectId && window.projects?.[e.projectId]?.name || '',
            reason: window.prEmpsState.deferReasons[k] || 'بدون سبب محدد'
        }));

    // احتساب رواتب المُختارين
    const items = selectedEmps.map(([k, e]) => calcEmpPayForMonth(k, e, month, calcMode, fromDate, toDate, deductAbsence, payCarAllow));
    const totalNet = items.reduce((s, i) => s + i.finalNet, 0);
    const totalGross = items.reduce((s, i) => s + i.grossSalary, 0);

    // تسمية المسير
    let scopeLabel = '';
    if (scope === 'project') {
        scopeLabel = ` — 📁 ${window.projects?.[projectId]?.name || ''}`;
    } else if (scope === 'dept') {
        scopeLabel = ` — 🏢 ${dept}`;
    }
    if (deferredEmps.length > 0) scopeLabel += ` (⏸️ ${deferredEmps.length} مُؤجَّل)`;

    const payrollData = {
        month, calcMode, deductAbsence, payCarAllow, status: 'draft',
        scope, projectId, dept,
        projectName: scope === 'project' && projectId ? (window.projects?.[projectId]?.name || '') : '',
        fromDate: fromDate || '', toDate: toDate || '',
        useCustomRange: useCustom,
        scopeLabel,
        deferredEmployees: deferredEmps,   // 🆕 سجل المُؤجَّلين
        totalScopeEmployees: scopeEmps.length, // عدد كل من في النطاق
        totalDeferred: deferredEmps.length,
        createdBy: curU?.uid || '', createdByName: myP?.name || '',
        createdAt: new Date().toISOString(),
        totalEmployees: items.length,
        totalGross: parseFloat(totalGross.toFixed(2)),
        totalNet: parseFloat(totalNet.toFixed(2)),
        items
    };

    try {
        await push(R.pay, payrollData);
        const periodMsg = useCustom ? ` (${fromDate} → ${toDate})` : '';
        const deferMsg = deferredEmps.length > 0 ? ` · ⏸️ ${deferredEmps.length} مُؤجَّل` : '';
        toast(`✅ تم إنشاء مسير ${month}${scopeLabel}${periodMsg} — ${items.length} موظف${deferMsg}`, 'ok');
        // ⚠️ تنبيه غياب مرتفع بلا خصم (راتب ثابت) — يذكّر المدير أن الغياب لم يُخصم وقد تكون بيانات الحضور غير مُدخَلة
        const warnCount = items.filter(it => it.absenceWarn).length;
        if (warnCount > 0) toast(`⚠️ ${warnCount} موظف بغياب مرتفع في الراتب الثابت بلا خصم — تأكد من إدخال الحضور أو فعّل «خصم أيام الغياب» أو استخدم «حسب أيام الحضور».`, 'wn', 10000);
        // مسح state بعد الحفظ
        window.prEmpsState = { selected: new Set(), deferReasons: {} };
        renderPREmployeesTable();
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// عرض قائمة المسيرات
window.renderPayrolls = function () {
    const container = $('payrollList'); if (!container) return;
    const search = ($('prSearch')?.value || '').toLowerCase();
    let rows = Object.entries(payrolls);
    if (search) rows = rows.filter(([, p]) => p.month?.includes(search));
    rows.sort((a, b) => b[1].month?.localeCompare(a[1].month));

    if (!rows.length) {
        container.innerHTML = '<div class="empty"><div class="ei">💵</div><p>لا توجد مسيرات</p></div>';
        return;
    }

    const statusMap = {
        draft: { label: '📝 مسودة', bg: '#f0f4ff', color: '#2d6a9f', nextBtn: `<button class="btn" style="background:#f39c12;color:white;padding:4px 10px;font-size:11px" onclick="advancePayroll('{k}','review')">→ إرسال للمراجعة</button>` },
        review: { label: '🔍 قيد المراجعة', bg: '#fff8e1', color: '#f39c12', nextBtn: `<button class="btn" style="background:#27ae60;color:white;padding:4px 10px;font-size:11px" onclick="advancePayroll('{k}','approved')">→ اعتماد نهائي</button>` },
        approved: { label: '✅ معتمد', bg: '#d5f5e3', color: '#1e8449', nextBtn: '' }
    };

    container.innerHTML = rows.map(([k, p]) => {
        const sm = statusMap[p.status] || statusMap.draft;
        const mLabel = formatMonthLabel(p.month);
        const nextBtn = sm.nextBtn.replace('{k}', k);
        // حساب إجماليات الخصومات الشهرية وأقساط السلف ومكافآت الأداء من الـ items
        const totalMonth = (p.items || []).reduce((s, i) => s + (i.monthDeductTotal || 0), 0);
        const totalLoan = (p.items || []).reduce((s, i) => s + (i.loanDeductTotal || 0), 0);
        const totalPerf = (p.items || []).reduce((s, i) => s + (i.perfBonusAmt || 0), 0);
        const empsWithDeductions = (p.items || []).filter(i => (i.monthDeductTotal || 0) > 0 || (i.loanDeductTotal || 0) > 0 || (i.perfBonusAmt || 0) !== 0);

        // 🆕 شارة النطاق
        const scope = p.scope || 'all';
        let scopeBadge = '';
        if (scope === 'project' && p.projectName) {
            scopeBadge = `<span style="background:#fef5e7;color:#7d4e00;padding:3px 10px;border-radius:8px;font-size:11px;font-weight:700;margin-right:6px">📁 ${esc(p.projectName)}</span>`;
        } else if (scope === 'dept' && p.dept) {
            scopeBadge = `<span style="background:#e8f4fd;color:#1a5276;padding:3px 10px;border-radius:8px;font-size:11px;font-weight:700;margin-right:6px">🏢 ${esc(p.dept)}</span>`;
        } else if (scope === 'custom') {
            scopeBadge = `<span style="background:#f4ecf7;color:#5b2c6f;padding:3px 10px;border-radius:8px;font-size:11px;font-weight:700;margin-right:6px">✋ اختيار يدوي</span>`;
        } else {
            scopeBadge = `<span style="background:#e8f8f5;color:#0e6655;padding:3px 10px;border-radius:8px;font-size:11px;font-weight:700;margin-right:6px">👥 جميع الموظفين</span>`;
        }
        // 🆕 شارة الفترة المخصصة
        const periodBadge = p.useCustomRange && p.fromDate && p.toDate
            ? `<span style="background:#fff8e1;color:#7d4e00;padding:3px 10px;border-radius:8px;font-size:11px;font-weight:700;margin-right:6px">📅 ${p.fromDate} → ${p.toDate}</span>`
            : '';

        // 🆕 احسب المُؤجَّلين الفعليين (الذين لم يُنشأ لهم مسير بعد)
        const actualDeferred = (p.deferredEmployees || []).filter(d => {
            for (const [otherKey, otherP] of Object.entries(payrolls || {})) {
                if (otherKey === k) continue;
                if (otherP.month !== p.month) continue;
                if (otherP.status === 'cancelled') continue;
                if ((otherP.items || []).find(i => i.empKey === d.empKey)) return false;
            }
            return true;
        });
        // عنوان نظيف بدون ذكر العدد القديم
        const baseScopeLabel = (p.scopeLabel || '').replace(/\s*\(⏸️\s*\d+\s*مُؤجَّل\)/g, '');
        const dynamicTitle = baseScopeLabel + (actualDeferred.length > 0 ? ` (⏸️ ${actualDeferred.length} مُؤجَّل)` : '');

        return `<div style="background:white;border:1.5px solid #e0e8f0;border-radius:12px;padding:16px;margin-bottom:12px;border-right:5px solid ${sm.color}">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:8px">
                <div>
                    <div style="font-size:16px;font-weight:800;color:#1a3a5c">💵 مسير ${mLabel}${dynamicTitle}</div>
                    <div style="margin-top:6px;display:flex;flex-wrap:wrap;align-items:center">
                        ${scopeBadge}${periodBadge}
                    </div>
                    <div style="font-size:12px;color:#888;margin-top:6px">أُنشئ بواسطة: ${esc(p.createdByName) || '-'} | ${p.createdAt ? new Date(p.createdAt).toLocaleDateString('ar-SA') : ''}</div>
                </div>
                <span style="background:${sm.bg};color:${sm.color};padding:4px 14px;border-radius:12px;font-size:12px;font-weight:700">${sm.label}</span>
            </div>
            <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(150px,1fr));gap:8px;margin:12px 0">
                <div style="background:#f8fafc;border-radius:8px;padding:10px;text-align:center"><div style="font-size:11px;color:#888">عدد الموظفين</div><div style="font-size:17px;font-weight:800;color:#1a3a5c">${p.totalEmployees || 0}</div></div>
                <div style="background:#f8fafc;border-radius:8px;padding:10px;text-align:center"><div style="font-size:11px;color:#888">إجمالي الرواتب</div><div style="font-size:17px;font-weight:800;color:#2d6a9f">${fmt(p.totalGross)}</div></div>
                ${totalMonth > 0 ? `<div style="background:#fdecea;border-radius:8px;padding:10px;text-align:center"><div style="font-size:11px;color:#7b1c1c">خصومات شهرية</div><div style="font-size:17px;font-weight:800;color:#c0392b">${fmt(totalMonth)}</div></div>` : ''}
                ${totalLoan > 0 ? `<div style="background:#fef5e7;border-radius:8px;padding:10px;text-align:center"><div style="font-size:11px;color:#7d4e00">أقساط سلف</div><div style="font-size:17px;font-weight:800;color:#d68910">${fmt(totalLoan)}</div></div>` : ''}
                ${totalPerf !== 0 ? `<div style="background:${totalPerf>0?'#f0fff4':'#fff5f5'};border-radius:8px;padding:10px;text-align:center"><div style="font-size:11px;color:#666">⭐ مكافآت الأداء</div><div style="font-size:17px;font-weight:800;color:${totalPerf>0?'#27ae60':'#e74c3c'}">${totalPerf>0?'+':''}${fmt(totalPerf)}</div></div>` : ''}
                <div style="background:#e8f5e9;border-radius:8px;padding:10px;text-align:center"><div style="font-size:11px;color:#888">الصافي النهائي</div><div style="font-size:17px;font-weight:800;color:#27ae60">${fmt(p.totalNet)}</div></div>
            </div>
            ${empsWithDeductions.length ? `<div style="background:#fff8e1;border-radius:8px;padding:10px 14px;margin-bottom:10px;font-size:12px;color:#7d4e00">
                <strong>📋 تفاصيل خاصة لبعض الموظفين:</strong><br>
                ${empsWithDeductions.map(e => `• <strong>${esc(e.name)}</strong>${(e.monthDeductTotal||0)>0?` — خصم شهري: <span style="color:#c0392b;font-weight:700">${fmt(e.monthDeductTotal)} ر</span>`:''}${(e.loanDeductTotal||0)>0?` — قسط سلفة: <span style="color:#d68910;font-weight:700">${fmt(e.loanDeductTotal)} ر</span>`:''}${(e.perfBonusAmt||0)!==0?` — ⭐ أداء: <span style="color:${e.perfBonusAmt>0?'#27ae60':'#e74c3c'};font-weight:700">${e.perfBonusAmt>0?'+':''}${fmt(e.perfBonusAmt)} ر</span>`:''}`).join('<br>')}
            </div>` : ''}

            ${actualDeferred.length === 0 ? '' : `<div style="background:#fef5e7;border-radius:8px;padding:10px 14px;margin-bottom:10px;border:1.5px solid #e67e22">
                <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;margin-bottom:8px">
                    <div style="font-size:12px;color:#7d4e00;font-weight:700">⏸️ موظفون لم يُنشأ لهم مسير (${actualDeferred.length}):</div>
                    <button class="btn" style="padding:4px 10px;font-size:11px;background:#27ae60;color:white" onclick="reopenDeferredPayroll('${k}')">➕ إنشاء مسير لهم</button>
                </div>
                <div style="font-size:12px;color:#7d4e00;line-height:1.8">
                    ${actualDeferred.map(d => `• <strong>${esc(d.name)}</strong>${d.job ? ` (${esc(d.job)})` : ''} — <span style="color:#c0392b">${esc(d.reason)}</span>`).join('<br>')}
                </div>
            </div>`}

            ${(() => {
                // 🆕 احسب أقساط السلف المسددة بهذا المسير
                if (p.status !== 'approved') return '';
                const paidLoans = []; // { empName, loanKey, amount, allPaid, originalAmount }
                Object.entries(loans || {}).forEach(([lKey, l]) => {
                    (l.schedule || []).forEach(s => {
                        if (s.paid && s.paidByPayrollKey === k) {
                            const empItem = (p.items || []).find(i => i.empKey === l.empKey);
                            if (empItem) {
                                paidLoans.push({
                                    empName: empItem.name,
                                    loanKey: lKey,
                                    amount: s.amount,
                                    allPaid: (l.schedule || []).every(x => x.paid),
                                    originalAmount: l.amount,
                                    loanNote: l.note || 'سلفة'
                                });
                            }
                        }
                    });
                });
                if (paidLoans.length === 0) return '';
                const totalPaid = paidLoans.reduce((s, x) => s + x.amount, 0);
                const settledCount = paidLoans.filter(x => x.allPaid).length;
                return `<div style="background:linear-gradient(135deg,#fef5e7,#fff);border-radius:8px;padding:10px 14px;margin-bottom:10px;border:1.5px solid #d68910">
                    <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;margin-bottom:8px">
                        <div>
                            <div style="font-size:12px;color:#7d4e00;font-weight:700">💳 أقساط سلف مسدَّدة من هذا المسير</div>
                            <div style="font-size:10px;color:#7d4e00;margin-top:2px">${paidLoans.length} قسط بإجمالي <strong>${fmt(totalPaid)} ر</strong>${settledCount > 0 ? ` · 🎉 ${settledCount} سلفة سُدِّدت بالكامل` : ''}</div>
                        </div>
                        <button class="btn" style="padding:5px 10px;font-size:11px;background:#d68910;color:white;font-weight:700" onclick="nav('loans', document.getElementById('n-ln'))">عرض السلف →</button>
                    </div>
                    <div style="font-size:11px;color:#7d4e00;line-height:1.8">
                        ${paidLoans.map(d => `• <strong>${d.empName}</strong> — ${d.loanNote}: <span style="color:#d68910;font-weight:700">${fmt(d.amount)} ر</span>${d.allPaid ? ' <span style="background:#27ae60;color:white;padding:1px 6px;border-radius:4px;font-size:9px;font-weight:700">✅ سُدِّدت بالكامل</span>' : ''}`).join('<br>')}
                    </div>
                </div>`;
            })()}

            ${p.journalEntryNumber ? `<div style="background:linear-gradient(135deg,#e8f8f5,#fff);border-radius:8px;padding:10px 14px;margin-bottom:10px;border:1.5px solid #27ae60">
                <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
                    <div>
                        <div style="font-size:12px;color:#0e6655;font-weight:700">📒 القيد المحاسبي المرتبط</div>
                        <div style="font-size:13px;font-weight:800;color:#1a3a5c;font-family:monospace;margin-top:3px">${p.journalEntryNumber}</div>
                        <div style="font-size:10px;color:#0e6655;margin-top:2px">
                            ${p.journalEntryStatus === 'draft' ? '📝 مسودة — في انتظار المراجعة والترحيل' :
                              p.journalEntryStatus === 'posted' ? '✅ مرحَّل في دفتر الأستاذ' :
                              p.journalEntryStatus === 'cancelled' ? '❌ ملغى' : ''}
                        </div>
                    </div>
                    <button class="btn" style="padding:6px 12px;font-size:11px;background:#27ae60;color:white;font-weight:700" onclick="goToPayrollJournal('${p.journalEntryKey}')">📋 عرض القيد</button>
                </div>
            </div>` : ''}

            ${p.paymentVoucherNumber ? `<div style="background:linear-gradient(135deg,#fef5e7,#fff);border-radius:8px;padding:10px 14px;margin-bottom:10px;border:1.5px solid #e67e22">
                <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
                    <div>
                        <div style="font-size:12px;color:#7d4e00;font-weight:700">💸 سند الصرف المرتبط</div>
                        <div style="font-size:13px;font-weight:800;color:#1a3a5c;font-family:monospace;margin-top:3px">${p.paymentVoucherNumber}</div>
                        <div style="font-size:10px;color:#7d4e00;margin-top:2px">
                            💰 ${fmt(p.paymentAmount || p.totalNet)} ر · 🏦 ${p.paymentAccountName || ''} · 📅 ${p.paymentDate || ''}
                        </div>
                    </div>
                    <span style="background:#27ae60;color:white;padding:5px 12px;border-radius:6px;font-size:11px;font-weight:800">✅ مدفوع</span>
                </div>
            </div>` : ''}

            <div style="display:flex;gap:8px;flex-wrap:wrap">
                <button class="btn b-b" style="padding:4px 10px;font-size:11px" onclick="viewPayrollDetail('${k}')">👁️ تفاصيل</button>
                ${p.status === 'draft' && (myP?.role === 'admin' || can('review_payroll')) ? sm.nextBtn.replace('{k}', k) : ''}
                ${p.status === 'review' && (myP?.role === 'admin' || can('approve_payroll')) ? sm.nextBtn.replace('{k}', k) : ''}
                ${(p.status === 'approved' && p.journalEntryStatus === 'posted' && !p.paymentVoucherKey && (myP?.role === 'admin' || can('create_payment')))
                    ? `<button class="btn" style="padding:5px 14px;font-size:12px;background:linear-gradient(135deg,#196f3d,#27ae60);color:white;font-weight:800;border:2px solid #196f3d" onclick="openPayrollPaymentModal('${k}')">💸 دفع وإنشاء سند صرف</button>`
                    : ''}
                ${(p.status !== 'approved' && (myP?.role === 'admin' || can('delete_payroll'))) || (p.status === 'approved' && (myP?.role === 'admin' || can('delete_approved_payroll')))
                    ? `<button class="btn b-r" style="padding:4px 10px;font-size:11px${p.status === 'approved' ? ';border:2px solid #c0392b' : ''}" onclick="deletePayroll('${k}','${mLabel}')">🗑️ ${p.status === 'approved' ? 'حذف المعتمد ⚠️' : 'حذف'}</button>`
                    : ''}
                <button class="btn b-gr" style="padding:4px 10px;font-size:11px" onclick="printPayroll('${k}')">🖨️ طباعة</button>
                <button class="btn" style="padding:4px 10px;font-size:11px;background:#1e7e34;color:white" onclick="exportPayrollToExcel('${k}')">📊 تصدير Excel</button>
                <button class="btn" style="padding:4px 10px;font-size:11px;background:#5b2c6f;color:white" onclick="exportPayrollWPS('${k}')" title="ملف حماية الأجور — مِدد/البنك">📤 WPS/مِدد</button>
                <button class="btn" style="padding:4px 10px;font-size:11px;background:#16a085;color:white" onclick="generatePayrollShareLink('${k}')">🔗 رابط للاعتماد</button>
                <button class="btn b-b" style="padding:4px 10px;font-size:11px" onclick="openPayrollSettings('${k}')">⚙️ إعدادات العرض</button>
            </div>
        </div>`;
    }).join('');
};

// 🆕 الانتقال لعرض القيد المحاسبي المرتبط بالمسير
window.goToPayrollJournal = function (journalKey) {
    if (!journalKey) { toast('⚠️ لا يوجد قيد مرتبط', 'er'); return; }
    nav('journalentries', document.getElementById('n-jrn'));
    setTimeout(() => {
        // ابحث عن القيد في الجدول وميّزه
        const row = document.querySelector(`[data-jrn-key="${journalKey}"]`);
        if (row) {
            row.scrollIntoView({ behavior: 'smooth', block: 'center' });
            row.style.background = '#fff3cd';
            row.style.outline = '3px solid #f39c12';
            setTimeout(() => {
                row.style.background = '';
                row.style.outline = '';
            }, 3000);
        }
    }, 400);
};

// 🆕 listener لتحديث حالة القيد في المسير عند تغير حالة القيد
// (يجب أن يُربط في مكان loadData أو onValue للقيود)
function syncPayrollJournalStatus() {
    if (!window.journalEntries || !window.payrolls) return;
    let anyChange = false;
    Object.entries(window.payrolls).forEach(([pKey, p]) => {
        if (!p.journalEntryKey) return;
        const jrn = window.journalEntries[p.journalEntryKey];
        if (!jrn) return;
        if (p.journalEntryStatus !== jrn.status) {
            anyChange = true;
            // حدّث في DB (سيُعيد listener المسير الرسم تلقائياً)
            update(ref(db, 'ledger/payrolls/' + pKey), {
                journalEntryStatus: jrn.status
            }).catch(() => {});
        }
    });
    // إعادة الرسم إذا صفحة المسيرات مفتوحة
    if (anyChange && $('pg-payroll')?.classList.contains('act') && typeof renderPayrolls === 'function') {
        setTimeout(() => renderPayrolls(), 100);
    }
}

// تغيير حالة المسير (draft → review → approved)
// 🆕 الانتقال من قسط سلفة لعرض المسير الذي سدده
window.goToPayrollFromLoan = function (payrollKey) {
    if (!payrollKey) { toast('⚠️ المسير غير موجود', 'er'); return; }
    nav('payroll', document.getElementById('n-pr2'));
    setTimeout(() => {
        // أبرز بطاقة المسير
        const cards = document.querySelectorAll('#payrollList > div');
        cards.forEach(card => {
            if (card.innerHTML.includes(payrollKey)) {
                card.scrollIntoView({ behavior: 'smooth', block: 'center' });
                card.style.outline = '3px solid #f39c12';
                card.style.boxShadow = '0 0 20px rgba(243,156,18,.4)';
                setTimeout(() => {
                    card.style.outline = '';
                    card.style.boxShadow = '';
                }, 3000);
            }
        });
    }, 400);
};

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   💳  ربط أقساط السلف بمسير الرواتب                                       ║
// ╚══════════════════════════════════════════════════════════════════════════╝

// 🆕 سداد أقساط السلف المرتبطة بمسير (يُستدعى عند اعتماد المسير)
// يضع كل قسط مستحق لهذا الشهر على paid=true ويربطه بالمسير
async function payLoanInstallmentsForPayroll(payrollKey, payroll) {
    if (!payroll.items || !payroll.items.length) return { updated: 0, details: [] };
    const month = payroll.month;
    const now = new Date().toISOString();
    const userId = curU?.uid || 'system';
    const userName = myP?.name || userId;
    const batchUpd = {};
    const details = []; // { empName, loanKey, instalmentIdx, amount, allPaid }
    let updatedCount = 0;

    payroll.items.forEach(item => {
        if (!item.empKey) return;
        // ابحث عن سلف الموظف النشطة
        Object.entries(loans || {}).forEach(([lKey, l]) => {
            if (l.empKey !== item.empKey || l.status !== 'active') return;
            const schedule = [...(l.schedule || [])];
            let changed = false;

            schedule.forEach((s, idx) => {
                if (s.month !== month) return;
                if (s.paid) return;
                if (s.deferred) return;

                // سدد القسط
                schedule[idx] = {
                    ...s,
                    paid: true,
                    paidAt: now,
                    paidByPayrollKey: payrollKey,
                    paidByPayrollMonth: month,
                    paidByPayrollScope: payroll.scopeLabel || '',
                    paidBy: userId,
                    paidByName: userName,
                    paymentMethod: 'payroll_deduction'  // مصدر السداد
                };
                changed = true;
                updatedCount++;
                details.push({
                    empName: item.name,
                    loanKey: lKey,
                    loanOriginal: l.amount,
                    instalmentIdx: idx,
                    amount: s.amount,
                    allPaid: false  // ستُحدَّث لاحقاً
                });
            });

            if (changed) {
                const allPaid = schedule.every(s => s.paid);
                const remaining = schedule.filter(s => !s.paid).reduce((sum, x) => sum + x.amount, 0);
                batchUpd[`ledger/loans/${lKey}/schedule`] = schedule;
                batchUpd[`ledger/loans/${lKey}/status`] = allPaid ? 'settled' : 'active';
                batchUpd[`ledger/loans/${lKey}/remaining`] = parseFloat(remaining.toFixed(2));
                if (allPaid) {
                    batchUpd[`ledger/loans/${lKey}/settledAt`] = now;
                    batchUpd[`ledger/loans/${lKey}/settledByPayrollKey`] = payrollKey;
                }
                // ضع علامة allPaid على التفاصيل
                details.forEach(d => { if (d.loanKey === lKey) d.allPaid = allPaid; });
            }
        });
    });

    if (Object.keys(batchUpd).length > 0) {
        await update(ref(db), batchUpd);
    }
    return { updated: updatedCount, details };
}

// 🆕 عكس سداد أقساط السلف (يُستدعى عند حذف/إلغاء المسير)
async function reverseLoanInstallmentsForPayroll(payrollKey, payroll) {
    if (!payroll.items || !payroll.items.length) return { reversed: 0 };
    const batchUpd = {};
    let reversedCount = 0;

    // ابحث في كل السلف عن أقساط مسددة بواسطة هذا المسير
    Object.entries(loans || {}).forEach(([lKey, l]) => {
        const schedule = [...(l.schedule || [])];
        let changed = false;

        schedule.forEach((s, idx) => {
            if (s.paid && s.paidByPayrollKey === payrollKey) {
                // عكس السداد
                schedule[idx] = {
                    ...s,
                    paid: false,
                    paidAt: null,
                    paidByPayrollKey: null,
                    paidByPayrollMonth: null,
                    paidByPayrollScope: null,
                    paidBy: null,
                    paidByName: null,
                    paymentMethod: null
                };
                changed = true;
                reversedCount++;
            }
        });

        if (changed) {
            const allPaid = schedule.every(s => s.paid);
            const remaining = schedule.filter(s => !s.paid).reduce((sum, x) => sum + x.amount, 0);
            batchUpd[`ledger/loans/${lKey}/schedule`] = schedule;
            // إذا كانت settled بسبب هذا المسير، أعدها active
            batchUpd[`ledger/loans/${lKey}/status`] = allPaid ? 'settled' : 'active';
            batchUpd[`ledger/loans/${lKey}/remaining`] = parseFloat(remaining.toFixed(2));
            if (!allPaid) {
                batchUpd[`ledger/loans/${lKey}/settledAt`] = null;
                batchUpd[`ledger/loans/${lKey}/settledByPayrollKey`] = null;
            }
        }
    });

    if (Object.keys(batchUpd).length > 0) {
        await update(ref(db), batchUpd);
    }
    return { reversed: reversedCount };
}

window.advancePayroll = async function (key, newStatus) {
    const p = payrolls[key]; if (!p) return;
    // التحقق من الصلاحية حسب المرحلة
    if (newStatus === 'review' && myP?.role !== 'admin' && !can('review_payroll')) { toast('ليس لديك صلاحية إرسال المسير للمراجعة', 'er'); return }
    if (newStatus === 'approved' && myP?.role !== 'admin' && !can('approve_payroll')) { toast('ليس لديك صلاحية الاعتماد النهائي للمسير', 'er'); return }
    const labels = { review: 'إرسال للمراجعة', approved: 'الاعتماد النهائي' };
    cf2(`تأكيد ${labels[newStatus] || ''} لمسير ${formatMonthLabel(p.month)}؟${newStatus === 'approved' ? '\n\n📒 سيُنشأ قيد محاسبي تلقائي (مسودة) يحتاج مراجعة وترحيل في صفحة "قيود اليومية"' : ''}`, async () => {
        const upd = { status: newStatus, [`${newStatus}By`]: curU?.uid || '', [`${newStatus}ByName`]: myP?.name || '', [`${newStatus}At`]: new Date().toISOString() };
        try {
            await update(ref(db, 'ledger/payrolls/' + key), upd);
            // إذا اعتُمد — احفظ في سجل كل موظف
            if (newStatus === 'approved' && p.items) {
                const batchUpd = {};
                p.items.forEach(item => {
                    if (item.empKey) {
                        const salKey = `${p.month}_${key}`;
                        batchUpd[`ledger/employees/${item.empKey}/salaryHistory/${salKey}`] = {
                            month: p.month, payrollKey: key,
                            grossSalary: item.grossSalary, earnedNet: item.earnedNet,
                            actualDays: item.actualDays, actualHours: item.actualHours,
                            absentDays: item.absentDays, calcMode: item.calcMode,
                            approvedAt: new Date().toISOString()
                        };
                    }
                });
                if (Object.keys(batchUpd).length) await update(ref(db), batchUpd);

                // 🆕 سداد أقساط السلف المرتبطة بهذا المسير
                let loanResult = { updated: 0, details: [] };
                if (typeof payLoanInstallmentsForPayroll === 'function') {
                    try {
                        loanResult = await payLoanInstallmentsForPayroll(key, { ...p, ...upd });
                    } catch (loanErr) {
                        console.error('Loan installment payment error:', loanErr);
                    }
                }

                // 🆕 إنشاء قيد محاسبي تلقائي
                if (typeof createJournalForPayroll === 'function') {
                    const updatedPayroll = { ...p, ...upd };
                    const result = await createJournalForPayroll(key, updatedPayroll);
                    if (result) {
                        let msg = `✅ تم اعتماد المسير + إنشاء قيد محاسبي (${result.number})`;
                        if (loanResult.updated > 0) {
                            msg += ` + سداد ${loanResult.updated} قسط سلفة`;
                            const settledLoans = loanResult.details.filter(d => d.allPaid).length;
                            if (settledLoans > 0) msg += ` (${settledLoans} سلفة سُدِّدت بالكامل! 🎉)`;
                        }
                        msg += ` — راجعه وارحّله من 📒 قيود اليومية`;
                        toast(msg, 'ok', 9000);
                        return;
                    }
                }
                // إذا لم يُنشأ القيد، لكن سُددت الأقساط
                if (loanResult.updated > 0) {
                    toast(`✅ تم ${labels[newStatus]} + سداد ${loanResult.updated} قسط سلفة`, 'ok', 6000);
                    return;
                }
            }
            toast(`✅ تم ${labels[newStatus]}`, 'ok');
        } catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

// حذف مسير
window.deletePayroll = function (key, label) {
    const p = payrolls[key]; if (!p) return;
    const isApproved = p.status === 'approved';

    // التحقق من الصلاحية
    if (isApproved) {
        if (myP?.role !== 'admin' && !can('delete_approved_payroll')) {
            toast('⛔ حذف المسير المعتمد يتطلب صلاحية خاصة', 'er'); return
        }
    } else {
        if (myP?.role !== 'admin' && !can('delete_payroll')) {
            toast('ليس لديك صلاحية حذف المسير', 'er'); return
        }
    }

    // 🆕 فحص القيد المحاسبي المرتبط
    const journalKey = p.journalEntryKey;
    const journal = journalKey && window.journalEntries ? window.journalEntries[journalKey] : null;
    const journalStatus = journal?.status;
    const journalNum = p.journalEntryNumber || journal?.number || '';

    // 🆕 فحص سند الصرف المرتبط
    const voucherKey = p.paymentVoucherKey;
    const voucherNum = p.paymentVoucherNumber || '';
    const paymentJrnKey = p.paymentJournalKey;
    const paymentJrnNum = p.paymentJournalNumber || '';
    const isPaid = !!voucherKey;

    // بناء رسالة التحذير حسب حالة القيد
    let warnMsg = '';
    let journalAction = ''; // 'delete' | 'cancel' | 'none'
    let paymentAction = 'none'; // 'cancel' (سند الصرف يبقى للتدقيق دائماً) | 'none'

    if (!isApproved) {
        warnMsg = `حذف مسير "${label}"؟ لا يمكن التراجع.`;
        journalAction = 'none';
        if (journal && journalStatus === 'draft') journalAction = 'delete';
    } else if (!journal) {
        warnMsg = `⚠️ تحذير: سيُحذف مسير "${label}" المعتمد وسيُزال من سجلات رواتب الموظفين. هل أنت متأكد؟\n\n(ملاحظة: لا يوجد قيد محاسبي مرتبط)`;
        journalAction = 'none';
    } else if (journalStatus === 'draft') {
        warnMsg = `⚠️ تحذير: سيُحذف مسير "${label}" المعتمد + سجلات رواتب الموظفين.\n\n📒 سيُحذف أيضاً القيد المحاسبي المرتبط (${journalNum}) لأنه ما زال مسودة.\n\nهل أنت متأكد؟`;
        journalAction = 'delete';
    } else if (journalStatus === 'posted') {
        let extraMsg = '';
        if (isPaid) {
            extraMsg = `\n\n💸 المسير مدفوع! سيتم أيضاً:\n   ↩️ إلغاء سند الصرف ${voucherNum}\n   ↩️ إلغاء قيد سند الصرف ${paymentJrnNum}\n   ⚠️ رصيد حساب الصرف سيرجع كما كان قبل الدفع`;
            paymentAction = 'cancel';
        }
        warnMsg = `⚠️ تحذير مهم: سيُحذف مسير "${label}" المعتمد + سجلات رواتب الموظفين.\n\n📒 القيد المحاسبي المرتبط (${journalNum}) مُرحَّل في دفتر الأستاذ!\n   ✅ سيتم إلغاؤه (cancelled) — يبقى للتدقيق، لكن لا يؤثر في الحسابات.${extraMsg}\n\n⚠️ تذكّر: ميزان المراجعة سيتغير!\n\nهل أنت متأكد؟`;
        journalAction = 'cancel';
    } else if (journalStatus === 'cancelled') {
        warnMsg = `حذف مسير "${label}" المعتمد؟\n\n📒 القيد المحاسبي المرتبط (${journalNum}) ملغى مسبقاً.`;
        journalAction = 'none';
        if (isPaid) {
            warnMsg += `\n💸 سند الصرف ${voucherNum} سيُلغى أيضاً.`;
            paymentAction = 'cancel';
        }
    } else {
        warnMsg = `حذف مسير "${label}" المعتمد؟`;
        journalAction = 'none';
    }

    cf2(warnMsg, async () => {
        try {
            const now = new Date().toISOString();
            const userId = curU?.uid || 'system';
            const userName = myP?.name || userId;
            const batchUpd = {};

            // 🆕 عكس سداد أقساط السلف (إذا كان معتمداً)
            let loanReverseResult = { reversed: 0 };
            if (isApproved && typeof reverseLoanInstallmentsForPayroll === 'function') {
                try {
                    loanReverseResult = await reverseLoanInstallmentsForPayroll(key, p);
                } catch (loanErr) {
                    console.error('Loan reversal error:', loanErr);
                }
            }

            // 🆕 معالجة القيد المحاسبي للمسير
            if (journalAction === 'delete') {
                batchUpd[`ledger/journalEntries/${journalKey}`] = null;
            } else if (journalAction === 'cancel') {
                batchUpd[`ledger/journalEntries/${journalKey}/status`] = 'cancelled';
                batchUpd[`ledger/journalEntries/${journalKey}/cancelledAt`] = now;
                batchUpd[`ledger/journalEntries/${journalKey}/cancelledBy`] = userId;
                batchUpd[`ledger/journalEntries/${journalKey}/cancelledByName`] = userName;
                batchUpd[`ledger/journalEntries/${journalKey}/cancelReason`] = `إلغاء تلقائي — تم حذف المسير المصدر (${label})`;
            }

            // 🆕 معالجة سند الصرف وقيده
            if (paymentAction === 'cancel') {
                if (voucherKey) {
                    batchUpd[`ledger/payments/${voucherKey}/status`] = 'cancelled';
                    batchUpd[`ledger/payments/${voucherKey}/cancelledAt`] = now;
                    batchUpd[`ledger/payments/${voucherKey}/cancelledBy`] = userId;
                    batchUpd[`ledger/payments/${voucherKey}/cancelReason`] = `إلغاء تلقائي — حذف المسير (${label})`;
                }
                if (paymentJrnKey) {
                    batchUpd[`ledger/journalEntries/${paymentJrnKey}/status`] = 'cancelled';
                    batchUpd[`ledger/journalEntries/${paymentJrnKey}/cancelledAt`] = now;
                    batchUpd[`ledger/journalEntries/${paymentJrnKey}/cancelledBy`] = userId;
                    batchUpd[`ledger/journalEntries/${paymentJrnKey}/cancelledByName`] = userName;
                    batchUpd[`ledger/journalEntries/${paymentJrnKey}/cancelReason`] = `إلغاء تلقائي — حذف المسير (${label})`;
                }
            }

            // إذا كان معتمداً — احذف من سجلات رواتب الموظفين أيضاً
            if (isApproved && p.items) {
                p.items.forEach(item => {
                    if (item.empKey) {
                        const salKey = `${p.month}_${key}`;
                        batchUpd[`ledger/employees/${item.empKey}/salaryHistory/${salKey}`] = null;
                    }
                });
            }

            // حذف المسير
            batchUpd[`ledger/payrolls/${key}`] = null;

            // تنفيذ كل التحديثات دفعة واحدة (atomic)
            await update(ref(db), batchUpd);

            // رسالة نجاح مفصلة
            let successMsg = '🗑️ تم حذف المسير';
            if (journalAction === 'delete') successMsg += ` + حذف القيد ${journalNum}`;
            else if (journalAction === 'cancel') successMsg += ` + إلغاء القيد ${journalNum}`;
            if (paymentAction === 'cancel') successMsg += ` + إلغاء سند الصرف ${voucherNum}`;
            if (loanReverseResult.reversed > 0) successMsg += ` + استرجاع ${loanReverseResult.reversed} قسط سلفة`;
            toast(successMsg, 'ok', 7000);
        } catch (e) {
            console.error('Delete payroll error:', e);
            toast('❌ خطأ في الحذف: ' + e.message, 'er');
        }
    });
};

// عرض تفاصيل المسير في نافذة
window.viewPayrollDetail = function (key) {
    const p = payrolls[key]; if (!p) return;
    const statusMap = { draft: '📝 مسودة', review: '🔍 قيد المراجعة', approved: '✅ معتمد' };
    const calcMap = { fixed: 'راتب ثابت', hours: 'حسب ساعات الحضور', days: 'حسب أيام الحضور' };
    const items = p.items || [];
    const settings = getPayrollSettings(key);
    const visibleCols = settings.cols.filter(c => c.visible);
    const fontSize = settings.fontSize;

    // ألوان الأعمدة الخاصة
    const colStyles = {
        grossSalary: 'color:#2d6a9f;font-weight:600',
        totalDeductions: 'color:#e74c3c',
        netSalary: 'color:#1a3a5c;font-weight:600',
        actualDays: '',
        actualHours: '',
        absentDays: 'color:#e74c3c',
        paidLeaveDays: 'color:#27ae60',
        unpaidLeaveDays: 'color:#e67e22',
        earnedNet: 'font-weight:600;color:#1a3a5c',
        monthDeductTotal: '',
        loanDeductTotal: '',
        perfBonusAmt: '',
        finalNet: 'font-weight:800;color:#27ae60;background:#f0fff4'
    };

    const colHeaderStyles = {
        monthDeductTotal: 'background:#fdecea;color:#c0392b',
        loanDeductTotal: 'background:#fef5e7;color:#d68910',
        perfBonusAmt: 'background:#fef9e7;color:#7d4e00',
        finalNet: 'background:#e8f5e9;color:#1e8449'
    };

    // بناء الصفوف ديناميكياً
    const rows = items.map((it, i) => {
        const cells = visibleCols.map(c => {
            const val = getCellValue(c, it, i);
            let style = colStyles[c.key] || '';
            let cls = '';
            let display;

            if (c.key === 'idx') display = val;
            else if (c.key === 'name') { cls = 'name-cell'; display = `<strong>${val||'-'}</strong>${it.job?`<br><small style="color:#888">${it.job}</small>`:''}<br><button class="no-print" onclick="openPayslipLocal('${it.empKey}')" style="margin-top:3px;padding:2px 8px;font-size:${fontSize-2}px;background:#eef5fb;color:#23577f;border:1px solid #d5e6f3;border-radius:5px;cursor:pointer;font-family:inherit">🧾 قسيمة</button>`; }
            else if (c.key === 'calcNote') { cls = 'note-cell'; display = `${val||'-'}${it.monthDeductNote?`<br><span style="color:#c0392b;font-size:${fontSize-1.5}px;display:inline-block;margin-top:3px">📋 ${it.monthDeductNote}</span>`:''}`; }
            else if (typeof val === 'number') {
                if (c.key === 'perfBonusAmt' && val !== 0) {
                    style = `color:${val>0?'#27ae60':'#e74c3c'};font-weight:700;background:${val>0?'#f0fff4':'#fff5f5'}`;
                    display = `${val>0?'+':''}${fmt(val)}${it.perfScore?`<br><small style="font-size:${fontSize-2.5}px;font-weight:400;color:#888">${it.perfScore.toFixed(1)}/10</small>`:''}`;
                } else if (c.key === 'monthDeductTotal' && val > 0) {
                    const tip = it.monthDeductNote ? ` title="${it.monthDeductNote.replace(/"/g,'&quot;')}"` : '';
                    style = 'color:#c0392b;font-weight:700;background:#fff5f5;cursor:help';
                    display = `${fmt(val)} ⓘ`;
                    return `<td class="${cls}" style="${style}"${tip}>${display}</td>`;
                } else if (c.key === 'loanDeductTotal' && val > 0) {
                    style = 'color:#d68910;font-weight:700;background:#fffbf0';
                    display = fmt(val);
                } else if (val === 0 && ['monthDeductTotal','loanDeductTotal','perfBonusAmt'].includes(c.key)) {
                    style = 'color:#bbb';
                    display = c.key === 'perfBonusAmt' ? '—' : '0.00';
                } else if (['grossSalary','totalDeductions','netSalary','earnedNet','finalNet','basic','house','trans','phone','nature','rep','car','perfFixed','otherBonus','overtime'].includes(c.key)) {
                    if (val === 0 && ['basic','house','trans','phone','nature','rep','car','perfFixed','otherBonus','overtime'].includes(c.key)) { style = 'color:#bbb'; display = '0.00'; }
                    else display = fmt(val);
                } else {
                    display = val;
                }
            } else {
                display = val || '-';
            }

            return `<td class="${cls}" style="${style}">${display}</td>`;
        }).join('');
        return `<tr style="${i%2?'background:#fafbfc':''}">${cells}</tr>`;
    }).join('');

    // بناء colgroup ديناميكياً
    const colgroup = visibleCols.map(c => `<col style="width:${c.width}px">`).join('');

    // بناء الـ headers ديناميكياً
    const headers = visibleCols.map(c => {
        const hStyle = colHeaderStyles[c.key] || '';
        return `<th style="${hStyle}">${c.label}</th>`;
    }).join('');

    // بناء صف الإجمالي ديناميكياً — ضع كلمة "الإجمالي" في عمود نصّي واسع (الموظف) بدل عمود # الضيّق
    const totLabelIdx = visibleCols.findIndex(c => ['name', 'job', 'dept'].includes(c.key));
    const labelAt = totLabelIdx >= 0 ? totLabelIdx : 0;
    const totalsRow = visibleCols.map((c, i) => {
        if (i === labelAt) return '<td style="text-align:right;white-space:nowrap;font-weight:800">الإجمالي</td>';
        if (i === 0) return '<td></td>';
        if (['name','job','dept','iban','calcNote'].includes(c.key)) return '<td></td>';
        if (['grossSalary','totalDeductions','netSalary','earnedNet','monthDeductTotal','loanDeductTotal','perfBonusAmt','finalNet','basic','house','trans','phone','nature','rep','car','perfFixed','otherBonus','overtime'].includes(c.key)) {
            const sum = items.reduce((s, it) => s + (parseFloat(getCellValue(c, it, 0)) || 0), 0);
            return `<td>${c.key==='perfBonusAmt' && sum>0?'+':''}${fmt(sum)}</td>`;
        }
        if (['actualDays','absentDays','actualHours','paidLeaveDays','unpaidLeaveDays'].includes(c.key)) {
            const sum = items.reduce((s, it) => s + (parseFloat(getCellValue(c, it, 0)) || 0), 0);
            return `<td>${sum}</td>`;
        }
        return '<td></td>';
    }).join('');

    // إجماليات للإحصائيات
    const totalMonthDeduct = items.reduce((s, i) => s + (i.monthDeductTotal || 0), 0);
    const totalLoanDeduct = items.reduce((s, i) => s + (i.loanDeductTotal || 0), 0);
    const totalPerfBonus = items.reduce((s, i) => s + (i.perfBonusAmt || 0), 0);
    const totalFinal = items.reduce((s, i) => s + (i.finalNet != null ? i.finalNet : i.earnedNet), 0);

    // العرض الإجمالي للجدول
    const totalTableWidth = visibleCols.reduce((s, c) => s + c.width, 0);

    // 🧾 بناء قسائم الرواتب مسبقاً وحقنها في نافذة المسير — لتُفتح بنقرة مباشرة (تفادي حجب النوافذ)
    const payslipMap = {};
    items.forEach(x => { payslipMap[x.empKey] = buildPayslipHTML(p, x, emp[x.empKey] || {}); });
    const payslipMapJSON = JSON.stringify(payslipMap).replace(/</g, '\\u003c');

    const win = window.open('', '_blank');   // تبويب كامل بدل نافذة منبثقة صغيرة
    win.document.write(`<!DOCTYPE html><html lang="ar" dir="rtl"><head><meta charset="UTF-8"><title>مسير ${formatMonthLabel(p.month)}</title>
<style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',Tahoma,sans-serif;background:#f0f2f5;direction:rtl;padding:16px}
.wrap{max-width:1400px;margin:0 auto}.hd{background:linear-gradient(135deg,#1a3a5c,#2d6a9f);color:white;padding:16px 24px;border-radius:12px 12px 0 0;display:flex;justify-content:space-between;align-items:center}
.bd{background:white;border-radius:0 0 12px 12px;box-shadow:0 4px 20px rgba(0,0,0,.1);overflow:hidden}
.stats{display:flex;gap:0;border-bottom:2px solid #eef2f7;flex-wrap:wrap}
.st-box{flex:1;min-width:120px;padding:14px;text-align:center;border-left:1px solid #eef2f7}.st-v{font-size:20px;font-weight:800;margin-bottom:3px}.st-l{font-size:11px;color:#888}
.tw{padding:0 10px;overflow-x:auto}
table{border-collapse:collapse;font-size:${fontSize}px;table-layout:fixed;width:${totalTableWidth}px;max-width:100%}
th{padding:8px 3px;background:#f0f5fa;color:#1a3a5c;text-align:center;border-bottom:2px solid #dce8f0;font-size:${fontSize-0.5}px;white-space:normal;word-wrap:break-word;line-height:1.3}
td{padding:7px 3px;text-align:center;border-bottom:1px solid #f0f4f8;font-size:${fontSize}px;vertical-align:middle;word-wrap:break-word;overflow-wrap:break-word}
td.note-cell{text-align:right;white-space:normal;word-break:break-word;overflow-wrap:anywhere;line-height:1.6;font-size:${fontSize-0.5}px;padding:8px 10px}
td.name-cell{text-align:right;padding:7px 6px;font-size:${fontSize-0.5}px}
.tot{background:#1a3a5c;color:white;font-weight:800}
.signatures{margin-top:40px;padding:30px 20px 24px;border-top:2px solid #1a3a5c;background:#fafbfc}
.signatures::before{content:'التوقيعات والاعتمادات';display:block;text-align:center;font-size:14px;font-weight:800;color:#1a3a5c;margin-bottom:30px;letter-spacing:1.5px}
.sig-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:50px;padding:0 30px}
.sig-box{text-align:center;padding:0 10px}
.sig-title{font-size:13px;font-weight:700;color:#1a3a5c;margin-bottom:55px}
.sig-line{border-bottom:1.5px solid #1a3a5c;margin-bottom:10px;height:1px}
.sig-name{font-size:14px;font-weight:700;color:#1a3a5c;min-height:22px}
.sig-date{font-size:11px;color:#888;margin-top:5px}
@media print{
  *{-webkit-print-color-adjust:exact !important;print-color-adjust:exact !important}
  @page{size:A4 landscape;margin:6mm}
  html,body{background:white;padding:0;margin:0;width:100%}
  .wrap{max-width:100%;width:100%;margin:0}
  .hd{-webkit-print-color-adjust:exact;print-color-adjust:exact;border-radius:0;padding:8px 14px}
  .hd > div:first-child > div:first-child{font-size:14px}
  .bd{box-shadow:none;border-radius:0}
  .stats{border-bottom:1.5px solid #eef2f7}
  .st-box{padding:8px 6px;min-width:auto}
  .st-v{font-size:14px}.st-l{font-size:9px}
  .tw{padding:0;overflow:visible}
  table{width:100% !important}
  .signatures{page-break-inside:avoid;margin-top:18px;padding:18px 14px 14px;border-top:1.5px solid #1a3a5c}
  .signatures::before{font-size:12px;margin-bottom:20px}
  .sig-grid{gap:30px;padding:0 16px}
  .sig-title{font-size:11px;margin-bottom:40px}
  .sig-name{font-size:12px}.sig-date{font-size:9px}
  .no-print{display:none !important}
}</style></head>
<body><div class="wrap"><div class="hd">
  <div><div style="font-size:20px;font-weight:800">مسير رواتب ${formatMonthLabel(p.month)}</div>
  <div style="font-size:12px;opacity:.8;margin-top:3px">${statusMap[p.status]||''} | ${calcMap[p.calcMode]||''}</div></div>
  <div style="text-align:left;display:flex;gap:8px" class="no-print">
    <button onclick="window.print()" style="background:rgba(255,255,255,.2);color:white;border:1px solid rgba(255,255,255,.4);padding:7px 16px;border-radius:8px;cursor:pointer;font-size:12px">🖨️ طباعة</button>
  </div>
</div>
<div class="bd"><div class="stats">
  <div class="st-box"><div class="st-v" style="color:#2d6a9f">${p.totalEmployees}</div><div class="st-l">عدد الموظفين</div></div>
  <div class="st-box"><div class="st-v" style="color:#e67e22">${fmt(p.totalGross)}</div><div class="st-l">إجمالي الرواتب</div></div>
  <div class="st-box"><div class="st-v" style="color:#c0392b">${fmt(totalMonthDeduct)}</div><div class="st-l">خصومات شهرية</div></div>
  <div class="st-box"><div class="st-v" style="color:#d68910">${fmt(totalLoanDeduct)}</div><div class="st-l">أقساط سلف</div></div>
  <div class="st-box"><div class="st-v" style="color:${totalPerfBonus>=0?'#27ae60':'#e74c3c'}">${totalPerfBonus>0?'+':''}${fmt(totalPerfBonus)}</div><div class="st-l">مكافآت الأداء</div></div>
  <div class="st-box"><div class="st-v" style="color:#27ae60">${fmt(totalFinal)}</div><div class="st-l">الصافي النهائي</div></div>
</div>
<div class="tw">
<table>
<colgroup>${colgroup}</colgroup>
<thead><tr>${headers}</tr></thead>
<tbody>${rows}<tr class="tot">${totalsRow}</tr></tbody>
</table>
</div>
<div class="no-print" style="margin:10px;font-size:11px;color:#888;padding:8px 12px;background:#fafbfc;border-radius:6px"><strong>💡 ملاحظة:</strong> مرر مؤشر الفأرة على رقم الخصومات الشهرية لمعرفة سبب الخصم بالتفصيل</div>
<div class="signatures">
    <div class="sig-grid">
<div class="sig-box">
    <div class="sig-title">📝 أنشئ بواسطة</div>
    <div class="sig-line"></div>
    <div class="sig-name">${p.createdByName || '—'}</div>
    <div class="sig-date">${p.createdAt ? new Date(p.createdAt).toLocaleDateString('ar-SA') : '—'}</div>
</div>
<div class="sig-box">
    <div class="sig-title">🔍 روجع بواسطة</div>
    <div class="sig-line"></div>
    <div class="sig-name">${p.reviewByName || (p.status === 'draft' ? 'لم تتم المراجعة بعد' : '—')}</div>
    <div class="sig-date">${p.reviewAt ? new Date(p.reviewAt).toLocaleDateString('ar-SA') : '—'}</div>
</div>
<div class="sig-box">
    <div class="sig-title">✅ اعتُمد بواسطة</div>
    <div class="sig-line"></div>
    <div class="sig-name">${p.approvedByName || (p.status !== 'approved' ? 'لم يُعتمد بعد' : '—')}</div>
    <div class="sig-date">${p.approvedAt ? new Date(p.approvedAt).toLocaleDateString('ar-SA') : '—'}</div>
</div>
    </div>
</div>
</div></div>
<script>
window.__PS = ${payslipMapJSON};
function openPayslipLocal(k){ var h=window.__PS&&window.__PS[k]; if(!h){alert('لا توجد قسيمة لهذا الموظف');return;} var w=window.open('','_blank'); if(!w){alert('اسمح بالنوافذ المنبثقة لعرض القسيمة');return;} w.document.write(h); w.document.close(); }
</script>
</body></html>`);
    win.document.close();
};

// طباعة مسير
window.printPayroll = function (key) { viewPayrollDetail(key) };

// 🧾 قسيمة الراتب الفردية (Payslip) — يبني HTML قابلاً لإعادة الاستخدام (يُستدعى من الصفحة الأم أو يُحقن داخل نافذة المسير لتفادي حجب النوافذ)
function buildPayslipHTML(p, it, e) {
    e = e || {};
    const cA = window.currentTenantName || cfg.companyAr || 'اسم الشركة';
    const cE = window.currentTenantName ? '' : (cfg.companyEn || '');
    const ad = cfg.address || '', ph = cfg.phone || '', rg = cfg.reg || '', vt = cfg.vat || '';
    const monthLbl = formatMonthLabel(p.month);
    const statusMap = { draft: '📝 مسودة', review: '🔍 قيد المراجعة', approved: '✅ معتمد' };

    // الاشتقاق من بيانات الموظف كاحتياطي للمسيرات القديمة التي لا تحمل تفصيل البدلات
    const f = empFinance(e);
    const g = (v, fb) => (v != null ? v : (fb || 0));
    // المستحقات — البدل غير الخاضع للخصم يُعرض بقيمته المصروفة فعلاً (carPaid)
    const carShown = it.carPaid != null ? it.carPaid : g(it.carAllow, f.car);
    const earnItems = [
        ['الراتب الأساسي', g(it.sal, f.sal)],
        ['بدل السكن', g(it.house, f.house)],
        ['بدل المواصلات', g(it.trans, f.trans)],
        ['بدل الاتصالات', g(it.phone, f.phone)],
        ['بدل الطبيعة / الخطورة', g(it.nature, f.nature)],
        ['بدل التمثيل / الإدارة', g(it.rep, f.rep)],
        ['بدل السيارة / إضافي', carShown],
        ['مكافأة الأداء الثابتة', g(it.perf, f.perf)],
        ['مكافأة أخرى / سنوية', g(it.bonus, f.bonus)],
        ['العمل الإضافي', g(it.ot, f.ot)],
        ['⭐ مكافأة الأداء (تقييم)', it.perfBonusAmt]
    ].filter(([, v]) => v && Math.abs(v) > 0.001);
    const earnTotal = earnItems.reduce((s, [, v]) => s + v, 0);

    // الخصومات — نحاول تفصيل الخصومات الثابتة من بيانات الموظف إن طابقت الإجمالي المخزَّن
    const standing = it.totalDeductions || 0;
    let dedItems = [];
    if (Math.abs((f.totalDeductions || 0) - standing) < 0.5) {
        dedItems = [
            [`التأمينات الاجتماعية (${f.socialEmpPct || 0}%)`, f.socialDeductAmt],
            ['سلفة / مقدمة ثابتة', f.advance],
            ['خصم تأخير', f.late],
            ['مخالفات وجزاءات', f.penalty],
            ['خصومات أخرى ثابتة', f.otherDeduct]
        ].filter(([, v]) => v && v > 0.001);
    } else if (standing > 0.001) {
        dedItems = [['خصومات ثابتة (تأمينات/أخرى)', standing]];
    }
    // الخصومات الشهرية المتغيّرة (من العنصر)
    const manualMonthly = (it.monthDeductTotal || 0) - (it.absenceDeduct || 0) - (it.permDeduct || 0) - (it.unpaidLeaveDeduct || 0);
    const varItems = [
        ['خصم أيام الغياب', it.absenceDeduct],
        ['خصم أذونات', it.permDeduct],
        ['إجازة بدون راتب', it.unpaidLeaveDeduct],
        ['خصومات شهرية أخرى', manualMonthly],
        ['أقساط سلف', it.loanDeductTotal]
    ].filter(([, v]) => v && v > 0.001);
    const allDed = [...dedItems, ...varItems];
    const dedTotal = allDed.reduce((s, [, v]) => s + v, 0);
    const netFinal = it.finalNet != null ? it.finalNet : (it.earnedNet || 0);

    const money = v => `${fmt(v)} ريال`;
    const rowE = (l, v, strong) => `<tr><td style="padding:6px 12px;border-bottom:1px solid #eef2f6;font-size:12px;color:${strong ? '#0e6655' : '#444'};font-weight:${strong ? '800' : '500'}">${l}</td><td style="padding:6px 12px;border-bottom:1px solid #eef2f6;font-size:12px;text-align:left;font-weight:${strong ? '800' : '600'};color:${strong ? '#0e6655' : '#1a3a5c'}">${money(v)}</td></tr>`;
    const rowD = (l, v, strong) => `<tr><td style="padding:6px 12px;border-bottom:1px solid #eef2f6;font-size:12px;color:${strong ? '#c0392b' : '#444'};font-weight:${strong ? '800' : '500'}">${l}</td><td style="padding:6px 12px;border-bottom:1px solid #eef2f6;font-size:12px;text-align:left;font-weight:${strong ? '800' : '600'};color:#c0392b">${money(v)}</td></tr>`;
    const info = (l, v) => v ? `<div style="font-size:11px"><span style="color:#8a97a5">${l}:</span> <b style="color:#1a3a5c">${v}</b></div>` : '';

    return `<!DOCTYPE html><html lang="ar" dir="rtl"><head><meta charset="UTF-8"><title>قسيمة راتب — ${e.name || ''} — ${monthLbl}</title>
<style>
body{font-family:'Segoe UI',Tahoma,Arial,sans-serif;background:#eef1f4;padding:20px;color:#222;margin:0}
.wrap{max-width:720px;margin:0 auto;background:white;border-radius:14px;overflow:hidden;box-shadow:0 6px 26px rgba(0,0,0,.12)}
.hd{background:linear-gradient(135deg,#1a3a5c,#2d6a9f);color:white;padding:20px 26px;display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:10px}
.hd .co{font-size:19px;font-weight:900}.hd .coe{font-size:11px;opacity:.8;margin-top:2px}
.hd .meta{text-align:left;font-size:11px;opacity:.9;line-height:1.7}
.title{background:#f8fafc;padding:12px 26px;border-bottom:2px solid #eef2f6;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px}
.title h2{margin:0;font-size:16px;color:#1a3a5c}
.badge{background:#eef5fb;color:#23577f;padding:3px 12px;border-radius:20px;font-size:12px;font-weight:700}
.emp{padding:16px 26px;display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:8px 20px;border-bottom:1px solid #eef2f6}
.cols{display:grid;grid-template-columns:1fr 1fr;gap:0}
@media(max-width:620px){.cols{grid-template-columns:1fr}}
.col-h{background:#1a3a5c;color:white;padding:8px 12px;font-size:13px;font-weight:800}
.col-h.d{background:#7d2d2d}
table{width:100%;border-collapse:collapse}
.net{background:linear-gradient(135deg,#0e6655,#27ae60);color:white;padding:16px 26px;display:flex;justify-content:space-between;align-items:center;font-size:18px;font-weight:900}
.att{padding:12px 26px;background:#fafbfc;border-top:1px solid #eef2f6;display:grid;grid-template-columns:repeat(auto-fit,minmax(110px,1fr));gap:8px;text-align:center}
.att div div:first-child{font-size:10px;color:#8a97a5}.att div div:last-child{font-size:15px;font-weight:800;color:#1a3a5c}
.sig{display:flex;justify-content:space-between;padding:26px;gap:20px}
.sig div{text-align:center;flex:1}.sig .line{border-top:1px solid #333;margin-bottom:5px;height:30px}
.foot{padding:12px 26px;text-align:center;font-size:10.5px;color:#aaa;border-top:1px solid #eee}
.note{padding:10px 26px;font-size:11px;color:#8a6d3b;background:#fcf8e3;border-top:1px solid #f5e79e}
@media print{*{-webkit-print-color-adjust:exact !important;print-color-adjust:exact !important}body{background:white;padding:0}.wrap{box-shadow:none;border-radius:0}.noprint{display:none}}
</style></head><body>
<div class="wrap">
  <div class="hd">
    <div><div class="co">${cA}</div>${cE ? `<div class="coe">${cE}</div>` : ''}</div>
    <div class="meta">${ad ? ad + '<br>' : ''}${ph ? '📞 ' + ph : ''}${rg ? ' — س.ت ' + rg : ''}${vt ? '<br>الرقم الضريبي: ' + vt : ''}</div>
  </div>
  <div class="title"><h2>🧾 قسيمة راتب — ${monthLbl}</h2><span class="badge">${statusMap[p.status] || p.status || ''}</span></div>
  <div class="emp">
    ${info('الموظف', e.name)}
    ${info('المسمى الوظيفي', e.job || it.job)}
    ${info('القسم', e.dept || it.dept)}
    ${info('رقم الموظف', e.empId)}
    ${info('رقم الهوية/الإقامة', e.natId)}
    ${info('الآيبان', e.iban)}
  </div>
  <div class="cols">
    <div>
      <div class="col-h">💵 المستحقات</div>
      <table>${earnItems.map(([l, v]) => rowE(l, v)).join('')}${rowE('إجمالي المستحقات', earnTotal, true)}</table>
    </div>
    <div>
      <div class="col-h d">➖ الخصومات</div>
      <table>${allDed.length ? allDed.map(([l, v]) => rowD(l, v)).join('') : `<tr><td colspan="2" style="padding:10px 12px;color:#aaa;font-size:12px;text-align:center">لا توجد خصومات</td></tr>`}${rowD('إجمالي الخصومات', dedTotal, true)}</table>
    </div>
  </div>
  <div class="net"><span>💰 صافي الراتب المستحق</span><span>${money(netFinal)}</span></div>
  <div class="att">
    <div><div>أيام الحضور</div><div>${it.actualDays ?? '-'}</div></div>
    <div><div>ساعات الحضور</div><div>${it.actualHours ?? '-'}</div></div>
    <div><div>أيام الغياب</div><div>${it.absentDays ?? '-'}</div></div>
    <div><div>إجازة مدفوعة</div><div>${it.paidLeaveDays ?? 0}</div></div>
  </div>
  ${it.calcNote ? `<div class="note">🧮 ${it.calcNote}</div>` : ''}
  <div class="sig">
    <div><div class="line"></div><div style="font-size:11px;color:#888">توقيع الموظف</div></div>
    <div><div class="line"></div><div style="font-size:11px;color:#888">المحاسب / الموارد البشرية</div></div>
  </div>
  <div class="foot">صدرت آلياً بتاريخ ${new Date().toLocaleDateString('ar-SA')} — هذه القسيمة بيان بمكوّنات الراتب لشهر ${monthLbl}
  <br><button class="noprint" onclick="window.print()" style="margin-top:8px;padding:7px 22px;background:#1a3a5c;color:white;border:none;border-radius:7px;cursor:pointer;font-size:12px">🖨️ طباعة / حفظ PDF</button></div>
</div></body></html>`;
}
window.openPayslip = function (payrollKey, empKey) {
    const p = payrolls[payrollKey]; if (!p) { toast('المسير غير موجود', 'er'); return }
    const it = (p.items || []).find(i => i.empKey === empKey); if (!it) { toast('لم يُعثر على الموظف في المسير', 'er'); return }
    const w = window.open('', '_blank'); if (!w) { toast('مانع النوافذ حجب القسيمة — اسمح بالنوافذ المنبثقة', 'er'); return }
    w.document.write(buildPayslipHTML(p, it, emp[empKey] || {})); w.document.close();
};

// تنسيق اسم الشهر
function formatMonthLabel(m) {
    if (!m) return '-';
    const [y, mo] = m.split('-');
    const months = ['يناير','فبراير','مارس','أبريل','مايو','يونيو','يوليو','أغسطس','سبتمبر','أكتوبر','نوفمبر','ديسمبر'];
    return `${months[parseInt(mo)-1] || mo} ${y}`;
}

// KPIs مسير الرواتب
function updatePayrollKPIs() {
    const rows = Object.values(payrolls);
    $('prk1') && ($('prk1').textContent = rows.length);
    $('prk2') && ($('prk2').textContent = rows.filter(p => p.status === 'approved').length);
    $('prk3') && ($('prk3').textContent = rows.filter(p => p.status === 'review').length);
    // آخر مسير معتمد
    const last = rows.filter(p => p.status === 'approved').sort((a, b) => b.month?.localeCompare(a.month))[0];
    $('prk4') && ($('prk4').textContent = last ? fmt(last.totalNet) : '0.00');
}

// تحميل سجل رواتب موظف (من تبويب سجل الرواتب)
window.loadEmpSalaryHistory = function () {
    const key = $('mEmpK')?.value; if (!key) return;
    const from = $('eSalHisFrom')?.value || '';
    const to = $('eSalHisTo')?.value || '';
    const eData = emp[key];
    // ابحث في salaryHistory المحفوظة في بيانات الموظف
    const hist = eData?.salaryHistory ? Object.values(eData.salaryHistory) : [];
    // أيضاً ابحث في payrolls المعتمدة
    const fromPayrolls = Object.values(payrolls)
        .filter(p => p.status === 'approved' && p.items)
        .flatMap(p => p.items.filter(i => i.empKey === key).map(i => ({ ...i, month: p.month, payrollKey: p.id })));

    let combined = [...hist, ...fromPayrolls];
    // إزالة التكرار بالشهر
    const seen = new Set();
    combined = combined.filter(r => { if (seen.has(r.month)) return false; seen.add(r.month); return true });
    combined.sort((a, b) => b.month?.localeCompare(a.month));

    if (from) combined = combined.filter(r => r.month >= from.slice(0, 7));
    if (to) combined = combined.filter(r => r.month <= to.slice(0, 7));

    const container = $('empSalHisBody');
    if (!combined.length) { container.innerHTML = '<div style="text-align:center;padding:24px;color:#aaa">لا توجد رواتب في هذه الفترة</div>'; return }

    const totalEarned = combined.reduce((s, r) => s + (r.earnedNet || 0), 0);
    container.innerHTML = `
        <div style="background:#e8f5e9;border-radius:8px;padding:10px 14px;margin-bottom:12px;display:flex;justify-content:space-between;align-items:center">
            <span style="font-size:13px;color:#1a3a5c;font-weight:700">📊 إجمالي الرواتب في الفترة</span>
            <span style="font-size:18px;font-weight:900;color:#27ae60">${fmt(totalEarned)} ريال</span>
        </div>
        <table style="width:100%;border-collapse:collapse;font-size:12px">
            <thead><tr style="background:#f0f5fa;color:#1a3a5c">
                <th style="padding:8px 10px;text-align:right;border-bottom:2px solid #dce8f0">الشهر</th>
                <th style="padding:8px 10px;text-align:right;border-bottom:2px solid #dce8f0">إجمالي الراتب</th>
                <th style="padding:8px 10px;text-align:right;border-bottom:2px solid #dce8f0">الراتب المستحق</th>
                <th style="padding:8px 10px;text-align:right;border-bottom:2px solid #dce8f0">أيام الحضور</th>
                <th style="padding:8px 10px;text-align:right;border-bottom:2px solid #dce8f0">ساعات الحضور</th>
                <th style="padding:8px 10px;text-align:right;border-bottom:2px solid #dce8f0">أيام الغياب</th>
            </tr></thead>
            <tbody>${combined.map((r, i) => `<tr style="${i%2?'background:#fafcff':''}">
                <td style="padding:8px 10px;font-weight:700;color:#1a3a5c">${formatMonthLabel(r.month)}</td>
                <td style="padding:8px 10px;color:#2d6a9f;font-weight:600">${fmt(r.grossSalary||0)}</td>
                <td style="padding:8px 10px;color:#27ae60;font-weight:800">${fmt(r.earnedNet||0)}</td>
                <td style="padding:8px 10px">${r.actualDays||0}</td>
                <td style="padding:8px 10px">${(r.actualHours||0).toFixed(1)}</td>
                <td style="padding:8px 10px;color:${(r.absentDays||0)>0?'#e74c3c':'#888'};font-weight:${(r.absentDays||0)>0?'700':'400'}">${r.absentDays||0}</td>
            </tr>`).join('')}
            <tr style="background:#1a3a5c">
                <td style="padding:9px 10px;color:white;font-weight:800">الإجمالي</td>
                <td colspan="2" style="padding:9px 10px;color:white;font-weight:900;font-size:14px">${fmt(totalEarned)} ريال</td>
                <td colspan="3"></td>
            </tr>
            </tbody>
        </table>`;
};

