const DOC_TYPE_LABELS = {
    iqama: '🆔 الإقامة', passport: '📔 جواز السفر', contract: '📄 عقد العمل',
    license: '🚗 رخصة القيادة', medical: '🏥 الفحص الطبي', certificate: '🎓 شهادة',
    visa: '✈️ التأشيرة', health_card: '💚 البطاقة الصحية', other: '📎 أخرى'
};

function daysUntil(dateStr) {
    if (!dateStr) return null;
    const td = new Date(); td.setHours(0, 0, 0, 0);
    const target = new Date(dateStr); target.setHours(0, 0, 0, 0);
    return Math.ceil((target - td) / (1000 * 60 * 60 * 24));
}

function docStatus(expiryDate) {
    const days = daysUntil(expiryDate);
    if (days === null) return { code: 'unknown', label: 'بدون تاريخ', color: '#888', bg: '#f5f5f5' };
    if (days < 0) return { code: 'expired', label: `🚨 منتهي منذ ${Math.abs(days)} يوم`, color: '#c62828', bg: '#ffebee' };
    if (days <= 30) return { code: 'urgent', label: `⚠️ ينتهي خلال ${days} يوم`, color: '#e65100', bg: '#fff3e0' };
    if (days <= 90) return { code: 'warning', label: `🟡 ينتهي خلال ${days} يوم`, color: '#f57c00', bg: '#fffde7' };
    return { code: 'ok', label: `✅ ساري — ${days} يوم متبقي`, color: '#1e8449', bg: '#e8f5e9' };
}

function readFileAsBase64(file) {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => resolve(reader.result);
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });
}

window.addEmpDocument = async function () {
    const key = $('mEmpK')?.value;
    if (!key) { toast('احفظ الموظف أولاً قبل رفع المستندات', 'er'); return }
    const type = $('docType')?.value;
    const name = $('docName')?.value?.trim();
    const issue = $('docIssue')?.value;
    const expiry = $('docExpiry')?.value;
    const note = $('docNote')?.value?.trim();
    const file = $('docFile')?.files?.[0];
    const statusDiv = $('docStatus');
    if (!type) { statusDiv.textContent = '⚠️ اختر نوع المستند'; return }
    if (!expiry) { statusDiv.textContent = '⚠️ أدخل تاريخ الانتهاء'; return }
    if (file && file.size > 2 * 1024 * 1024) { statusDiv.textContent = '❌ الملف كبير جداً (الحد 2MB)'; return }
    statusDiv.textContent = '⏳ جارٍ الرفع...';
    try {
        let fileData = null, fileName = null, fileMime = null;
        if (file) {
            fileData = await readFileAsBase64(file);
            fileName = file.name;
            fileMime = file.type;
        }
        await push(ref(db, `ledger/employees/${key}/documents`), {
            type, name, issue, expiry, note,
            fileData, fileName, fileMime,
            uploadedBy: myP?.name || '', uploadedAt: new Date().toISOString()
        });
        statusDiv.textContent = '✅ تم رفع المستند بنجاح';
        toast('✅ تم رفع المستند', 'ok');
        $('docType').value = 'iqama'; $('docName').value = ''; $('docIssue').value = '';
        $('docExpiry').value = ''; $('docNote').value = ''; $('docFile').value = '';
        loadEmpDocuments(key);
    } catch (e) { statusDiv.textContent = '❌ خطأ: ' + e.message; toast('خطأ: ' + e.message, 'er') }
};

window.loadEmpDocuments = function (key) {
    const container = $('docList'); if (!container) return;
    const eData = emp[key];
    const docs = eData?.documents ? Object.entries(eData.documents) : [];
    if (!docs.length) { container.innerHTML = '<div style="text-align:center;padding:20px;color:#aaa;font-size:13px">لا توجد مستندات</div>'; return }
    docs.sort((a, b) => {
        const da = daysUntil(a[1].expiry); const db_ = daysUntil(b[1].expiry);
        if (da === null) return 1; if (db_ === null) return -1;
        return da - db_;
    });
    container.innerHTML = docs.map(([dk, d]) => {
        const st = docStatus(d.expiry);
        const hasFile = !!d.fileData;
        return `<div style="border:1.5px solid #e0e8f0;border-radius:10px;padding:12px;margin-bottom:10px;border-right:4px solid ${st.color};background:${st.bg}">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:8px;margin-bottom:8px">
                <div>
                    <div style="font-size:14px;font-weight:800;color:#1a3a5c">${DOC_TYPE_LABELS[d.type] || d.type}${d.name ? ' — ' + d.name : ''}</div>
                    <div style="font-size:11px;color:#666;margin-top:3px">
                        ${d.issue ? '📅 الإصدار: ' + d.issue + ' | ' : ''}
                        ⏰ الانتهاء: <strong>${d.expiry}</strong>
                    </div>
                    ${d.note ? `<div style="font-size:11px;color:#888;margin-top:3px;font-style:italic">📝 ${d.note}</div>` : ''}
                </div>
                <span style="background:white;color:${st.color};padding:4px 12px;border-radius:10px;font-size:11px;font-weight:700;border:1.5px solid ${st.color}">${st.label}</span>
            </div>
            <div style="display:flex;gap:6px;flex-wrap:wrap">
                ${hasFile ? `<button class="btn b-b" style="padding:4px 10px;font-size:11px" onclick="viewDocFile('${key}','${dk}')">👁️ عرض الملف</button>` : ''}
                ${hasFile ? `<button class="btn b-gr" style="padding:4px 10px;font-size:11px" onclick="downloadDocFile('${key}','${dk}')">⬇️ تحميل</button>` : ''}
                <button class="btn" style="padding:4px 10px;font-size:11px;background:#3498db;color:white" onclick="openEditDoc('${key}','${dk}')">✏️ تعديل</button>
                <button class="btn" style="padding:4px 10px;font-size:11px;background:#27ae60;color:white" onclick="renewDocument('${key}','${dk}')">🔄 تجديد</button>
                <button class="btn b-r" style="padding:4px 10px;font-size:11px" onclick="deleteEmpDocument('${key}','${dk}')">🗑️ حذف</button>
            </div>
        </div>`;
    }).join('');
};

window.viewDocFile = function (key, dk) {
    const d = emp[key]?.documents?.[dk]; if (!d?.fileData) return;
    const win = window.open('', '_blank');
    if (d.fileMime?.startsWith('image/')) {
        win.document.write(`<html><head><title>${DOC_TYPE_LABELS[d.type]} — ${d.name || ''}</title></head><body style="margin:0;background:#222;display:flex;align-items:center;justify-content:center;min-height:100vh"><img src="${d.fileData}" style="max-width:100%;max-height:100vh"></body></html>`);
    } else {
        win.document.write(`<html><head><title>${d.name || 'مستند'}</title></head><body style="margin:0"><iframe src="${d.fileData}" style="width:100%;height:100vh;border:none"></iframe></body></html>`);
    }
    win.document.close();
};

window.downloadDocFile = function (key, dk) {
    const d = emp[key]?.documents?.[dk]; if (!d?.fileData) return;
    const a = document.createElement('a');
    a.href = d.fileData;
    a.download = d.fileName || `${d.type}_${d.name || 'document'}`;
    a.click();
};

window.deleteEmpDocument = function (key, dk) {
    cf2('حذف هذا المستند؟', async () => {
        try { await remove(ref(db, `ledger/employees/${key}/documents/${dk}`)); loadEmpDocuments(key); toast('🗑️ تم الحذف', 'ok') }
        catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

// فتح مودال تعديل المستند
window.openEditDoc = function (empKey, dk) {
    const d = emp[empKey]?.documents?.[dk]; if (!d) return;
    $('mDocEmpKey').value = empKey;
    $('mDocKey').value = dk;
    $('mDocTypeName').value = DOC_TYPE_LABELS[d.type] || d.type;
    $('mDocName').value = d.name || '';
    $('mDocIssue').value = d.issue || '';
    $('mDocExpiry').value = d.expiry || '';
    $('mDocNote').value = d.note || '';
    $('mDocFile').value = '';
    $('mDocCurrentFile').innerHTML = d.fileName
        ? `📎 الملف الحالي: <strong>${d.fileName}</strong>`
        : '<em>لا يوجد ملف مرفق حالياً</em>';
    ov('mDocEdit');
};

// حفظ التعديل
window.saveDocEdit = async function () {
    const empKey = $('mDocEmpKey').value;
    const dk = $('mDocKey').value;
    const name = $('mDocName').value.trim();
    const issue = $('mDocIssue').value;
    const expiry = $('mDocExpiry').value;
    const note = $('mDocNote').value.trim();
    const file = $('mDocFile')?.files?.[0];
    if (!expiry) { toast('تاريخ الانتهاء مطلوب', 'er'); return }
    if (file && file.size > 2 * 1024 * 1024) { toast('الملف كبير جداً (الحد 2MB)', 'er'); return }
    try {
        const upd = { name, issue, expiry, note, editedBy: myP?.name || '', editedAt: new Date().toISOString() };
        if (file) {
            upd.fileData = await readFileAsBase64(file);
            upd.fileName = file.name;
            upd.fileMime = file.type;
        }
        await update(ref(db, `ledger/employees/${empKey}/documents/${dk}`), upd);
        cov('mDocEdit');
        toast('✅ تم تحديث المستند', 'ok');
        loadEmpDocuments(empKey);
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// تجديد سريع: يفتح مودال التعديل مع اقتراح تاريخ انتهاء جديد (+ سنة من اليوم)
window.renewDocument = function (empKey, dk) {
    const d = emp[empKey]?.documents?.[dk]; if (!d) return;
    openEditDoc(empKey, dk);
    // تعيين تاريخ الإصدار = اليوم، وتاريخ الانتهاء = اليوم + سنة افتراضياً
    const today = new Date();
    const nextYear = new Date(today.getFullYear() + 1, today.getMonth(), today.getDate());
    setTimeout(() => {
        $('mDocIssue').value = today.toISOString().split('T')[0];
        $('mDocExpiry').value = nextYear.toISOString().split('T')[0];
        $('mDocExpiry').focus();
        toast('💡 تم اقتراح تاريخ جديد — عدّله ثم احفظ', 'ok', 4000);
    }, 200);
};

// ── صفحة تنبيهات المستندات ─────────────────
window.renderDocAlerts = function () {
    const container = $('docAlertsList'); if (!container) return;
    const statusF = $('daFilterStatus')?.value || '';
    const typeF = $('daFilterType')?.value || '';
    const allDocs = [];
    Object.entries(emp).forEach(([empKey, eData]) => {
        if (eData.documents) {
            Object.entries(eData.documents).forEach(([dk, d]) => {
                allDocs.push({ empKey, empName: eData.name || '', empJob: eData.job || '', empDept: eData.dept || '', dk, ...d, status: docStatus(d.expiry) });
            });
        }
    });
    const allWithExpiry = allDocs.filter(d => d.expiry);
    if ($('dak1')) $('dak1').textContent = allDocs.length;
    if ($('dak2')) $('dak2').textContent = allWithExpiry.filter(d => d.status.code === 'urgent').length;
    if ($('dak3')) $('dak3').textContent = allWithExpiry.filter(d => d.status.code === 'expired').length;
    if ($('dak4')) $('dak4').textContent = allWithExpiry.filter(d => d.status.code === 'ok').length;

    let filtered = allDocs;
    if (statusF) filtered = filtered.filter(d => d.status.code === statusF);
    if (typeF) filtered = filtered.filter(d => d.type === typeF);
    filtered.sort((a, b) => {
        const da = daysUntil(a.expiry); const db_ = daysUntil(b.expiry);
        if (da === null) return 1; if (db_ === null) return -1;
        return da - db_;
    });

    if (!filtered.length) {
        container.innerHTML = '<div class="empty"><div class="ei">✅</div><p>لا توجد مستندات تطابق الفلتر</p></div>';
        return;
    }

    container.innerHTML = filtered.map(d => `
        <div style="border:1.5px solid #e0e8f0;border-radius:10px;padding:14px;margin-bottom:10px;border-right:5px solid ${d.status.color};background:white">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:10px">
                <div style="flex:1;min-width:200px">
                    <div style="font-size:14px;font-weight:800;color:#1a3a5c">👤 ${d.empName} ${d.empDept ? `<span style="font-size:11px;color:#888;font-weight:400">— ${d.empDept}</span>` : ''}</div>
                    <div style="margin-top:6px;font-size:13px;color:#444"><strong>${DOC_TYPE_LABELS[d.type] || d.type}</strong>${d.name ? ' — ' + d.name : ''}</div>
                    <div style="font-size:11px;color:#666;margin-top:4px">⏰ تاريخ الانتهاء: <strong>${d.expiry || '-'}</strong></div>
                </div>
                <div style="text-align:center">
                    <span style="background:${d.status.bg};color:${d.status.color};padding:6px 14px;border-radius:12px;font-size:12px;font-weight:700;display:inline-block">${d.status.label}</span>
                    <div style="margin-top:6px"><button class="btn b-b" style="padding:3px 10px;font-size:11px" onclick="openDocFromAlert('${d.empKey}')">📂 فتح ملف الموظف</button></div>
                </div>
            </div>
        </div>
    `).join('');
};

// فتح ملف الموظف من صفحة التنبيهات والانتقال لتبويب المستندات
window.openDocFromAlert = function (empKey) {
    openEmpM(empKey);
    setTimeout(() => {
        const btn = document.querySelector('#mEmp button[onclick*="et8"]');
        if (btn) empTab('et8', btn);
    }, 350);
};

// تحديث شارة التنبيهات في الشريط الجانبي
function updateDocAlertBadge() {
    const btn = $('n-da'); if (!btn) return;
    let count = 0;
    Object.values(emp).forEach(e => {
        if (e.documents) {
            Object.values(e.documents).forEach(d => {
                const st = docStatus(d.expiry);
                if (st.code === 'expired' || st.code === 'urgent') count++;
            });
        }
    });
    // أزل الشارة القديمة إن وُجدت
    const oldBadge = btn.querySelector('.alert-badge');
    if (oldBadge) oldBadge.remove();
    if (count > 0) {
        const badge = document.createElement('span');
        badge.className = 'alert-badge';
        badge.textContent = count;
        badge.style.cssText = 'background:#e74c3c;color:white;font-size:10px;font-weight:800;padding:2px 7px;border-radius:10px;margin-right:auto;min-width:18px;text-align:center';
        btn.appendChild(badge);
    }
    refreshNotifBell();
}

