    sick: { lb: '🏥 مرضية', col: '#3498db', bg: '#d6eaf8', deductsFromBalance: 'leaveSick' },
    emergency: { lb: '⚡ اضطرارية', col: '#e67e22', bg: '#fef5e7', deductsFromBalance: 'leaveEmergency' },
    maternity: { lb: '👶 وضع/أمومة', col: '#9b59b6', bg: '#f4ecf7' },
    hajj: { lb: '🕋 حج', col: '#16a085', bg: '#d1f2eb' },
