// تصدير الموظفين إلى Excel
window.exportEmpsToExcel = function () {
    if (typeof XLSX === 'undefined') { toast('مكتبة Excel لم تُحمَّل بعد', 'er'); return }
    const empArr = Object.entries(emp);
    if (!empArr.length) { toast('لا يوجد موظفون للتصدير', 'er'); return }
    // الفلاتر النشطة
    const search = ($('empSearch')?.value || '').toLowerCase();
    const deptF = $('empDeptFilter')?.value || '';
    const statusF = $('empStatusFilter')?.value || '';
    let filtered = empArr;
    if (search) filtered = filtered.filter(([, e]) => (e.name || '').toLowerCase().includes(search) || (e.empId || '').toLowerCase().includes(search) || (e.job || '').toLowerCase().includes(search));
    if (deptF) filtered = filtered.filter(([, e]) => e.dept === deptF);
    if (statusF) filtered = filtered.filter(([, e]) => (e.status || 'active') === statusF);
    if (!filtered.length) { toast('لا يوجد موظفون يطابقون الفلتر', 'er'); return }

    // ميتاداتا
    const metadata = [
        [`قائمة الموظفين — ${cfg.companyAr || ''}`],
        [`عدد الموظفين: ${filtered.length}`],
        [`تاريخ التصدير: ${new Date().toLocaleDateString('ar-SA')}`],
        []
    ];
    const headers = EMP_EXCEL_COLS.map(c => c.label);
    const dataRows = filtered.map(([, e]) =>
        EMP_EXCEL_COLS.map(c => e[c.key] !== undefined && e[c.key] !== null ? e[c.key] : '')
    );
    const aoa = [...metadata, headers, ...dataRows];
    const ws = XLSX.utils.aoa_to_sheet(aoa);
    ws['!cols'] = EMP_EXCEL_COLS.map(c => ({ wpx: c.key === 'name' || c.key === 'email' || c.key === 'iban' ? 160 : c.key === 'notes' ? 200 : 100 }));
    ws['!sheetView'] = [{ rightToLeft: true }];
    ws['!merges'] = [{ s: { r: 0, c: 0 }, e: { r: 0, c: headers.length - 1 } }, { s: { r: 1, c: 0 }, e: { r: 1, c: headers.length - 1 } }, { s: { r: 2, c: 0 }, e: { r: 2, c: headers.length - 1 } }];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'الموظفون');
    XLSX.writeFile(wb, `قائمة_الموظفين_${today()}.xlsx`);
    toast(`✅ تم تصدير ${filtered.length} موظف`, 'ok');
};

// تصدير الموظفين إلى PDF
window.exportEmpsToPdf = function () {
    const empArr = Object.entries(emp);
    if (!empArr.length) { toast('لا يوجد موظفون للتصدير', 'er'); return }
    const search = ($('empSearch')?.value || '').toLowerCase();
    const deptF = $('empDeptFilter')?.value || '';
    const statusF = $('empStatusFilter')?.value || '';
    let filtered = empArr;
    if (search) filtered = filtered.filter(([, e]) => (e.name || '').toLowerCase().includes(search) || (e.empId || '').toLowerCase().includes(search) || (e.job || '').toLowerCase().includes(search));
    if (deptF) filtered = filtered.filter(([, e]) => e.dept === deptF);
    if (statusF) filtered = filtered.filter(([, e]) => (e.status || 'active') === statusF);
    if (!filtered.length) { toast('لا يوجد موظفون يطابقون الفلتر', 'er'); return }

    // افتح نافذة طباعة بسيطة بصيغة HTML
    const win = window.open('', '_blank');
    const rows = filtered.map(([, e], i) => {
        const f = empFinance(e);
        const st = e.status === 'inactive' ? '<span style="color:#c0392b;font-weight:700">⏸ موقوف</span>' : '<span style="color:#27ae60;font-weight:700">✅ نشط</span>';
        return `<tr style="${i%2?'background:#fafbfc':''}">
            <td>${i+1}</td>
            <td style="font-weight:700;text-align:right">${e.name || '-'}</td>
            <td>${e.empId || '-'}</td>
            <td style="text-align:right">${e.job || '-'}</td>
            <td>${e.dept || '-'}</td>
            <td>${e.phone || '-'}</td>
            <td>${e.hireDate || '-'}</td>
            <td style="font-weight:700">${fmt(f.netSalary)}</td>
            <td>${st}</td>
        </tr>`;
    }).join('');
    const totalSalaries = filtered.reduce((s, [, e]) => s + empFinance(e).netSalary, 0);
    win.document.write(`<!DOCTYPE html><html lang="ar" dir="rtl"><head><meta charset="UTF-8"><title>قائمة الموظفين</title>
<style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',Tahoma,sans-serif;background:#f0f2f5;direction:rtl;padding:16px}
.wrap{max-width:1100px;margin:0 auto;background:white;border-radius:12px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,.1)}
.hd{background:linear-gradient(135deg,#1a3a5c,#2d6a9f);color:white;padding:18px 24px;display:flex;justify-content:space-between;align-items:center}
.bd{padding:20px}
table{width:100%;border-collapse:collapse;font-size:12px}
th{padding:10px 6px;background:#f0f5fa;color:#1a3a5c;text-align:center;border-bottom:2px solid #dce8f0;font-weight:700}
td{padding:8px 6px;text-align:center;border-bottom:1px solid #f0f4f8}
.tot{background:#1a3a5c;color:white;font-weight:800}
@media print{body{background:white;padding:0}.hd{-webkit-print-color-adjust:exact;print-color-adjust:exact}@page{size:A4 landscape;margin:8mm}.no-print{display:none}}</style></head>
<body><div class="wrap">
<div class="hd">
    <div><div style="font-size:20px;font-weight:800">👷 قائمة الموظفين</div>
    <div style="font-size:12px;opacity:.85;margin-top:3px">${cfg.companyAr || ''} | ${new Date().toLocaleDateString('ar-SA')} | ${filtered.length} موظف</div></div>
    <button onclick="window.print()" class="no-print" style="background:rgba(255,255,255,.2);color:white;border:1px solid rgba(255,255,255,.4);padding:7px 16px;border-radius:8px;cursor:pointer;font-size:13px">🖨️ طباعة / حفظ PDF</button>
</div>
<div class="bd">
<table>
<thead><tr><th>#</th><th>الاسم</th><th>الرقم الوظيفي</th><th>الوظيفة</th><th>القسم</th><th>الجوال</th><th>تاريخ التعيين</th><th>الراتب الصافي</th><th>الحالة</th></tr></thead>
<tbody>${rows}
<tr class="tot"><td colspan="7">الإجمالي</td><td>${fmt(totalSalaries)}</td><td></td></tr>
</tbody></table>
</div></div></body></html>`);
    win.document.close();
};

// تحميل قالب Excel فارغ
window.downloadEmpTemplate = function () {
    if (typeof XLSX === 'undefined') { toast('مكتبة Excel لم تُحمَّل بعد', 'er'); return }
    const headers = EMP_EXCEL_COLS.map(c => c.label);
    // صف مثال
    const example = EMP_EXCEL_COLS.map(c => {
        switch (c.key) {
            case 'name': return 'محمد أحمد علي';
            case 'empId': return 'EMP001';
            case 'job': return 'محاسب';
            case 'dept': return 'الإدارة المالية';
            case 'nationality': return 'سعودي';
            case 'natId': return '1234567890';
            case 'phone': return '+966500000000';
            case 'email': return 'mohamed@company.com';
            case 'hireDate': return '2025-01-01';
            case 'iqamaExp': return '';
            case 'contractEnd': return '2027-01-01';
            case 'iban': return 'SA00000000000000000';
            case 'status': return 'active';
            case 'dailyHours': return 8;
            case 'workDaysPerMonth': return 26;
            case 'salary': return 5000;
            case 'houseAllow': return 1000;
            case 'transAllow': return 500;
            case 'phoneAllow': return 100;
            case 'natureAllow': return 0;
            case 'repAllow': return 0;
            case 'perfBonus': return 0;
            case 'otherBonus': return 0;
            case 'socialEmp': return 9.75;
            case 'socialComp': return 11.75;
            case 'medIns': return 200;
            case 'leaveAnnual': return 21;
            case 'leaveSick': return 30;
            case 'leaveEmergency': return 5;
            case 'notes': return 'صف توضيحي — احذفه قبل الرفع';
            default: return '';
        }
    });
    const instructions = [
        ['📋 قالب استيراد بيانات الموظفين'],
        ['ملاحظات مهمة:'],
        ['• الحقول التي بها * إجبارية'],
        ['• حذف الصف التوضيحي قبل الرفع'],
        ['• التواريخ بصيغة YYYY-MM-DD (مثال: 2025-12-31)'],
        ['• حقل الحالة يقبل: active أو inactive فقط'],
        ['• الموظف يُعرَّف بـ name + empId (إذا وُجد empId يُحدّث، وإلا يُضاف جديد)'],
        ['• الأرقام بدون فواصل (5000 وليس 5,000)'],
        []
    ];
    const aoa = [...instructions, headers, example];
    const ws = XLSX.utils.aoa_to_sheet(aoa);
    ws['!cols'] = EMP_EXCEL_COLS.map(c => ({ wpx: c.key === 'name' || c.key === 'email' || c.key === 'iban' || c.key === 'notes' ? 180 : 110 }));
    ws['!sheetView'] = [{ rightToLeft: true }];
    ws['!merges'] = [{ s: { r: 0, c: 0 }, e: { r: 0, c: headers.length - 1 } }];
    for (let i = 1; i <= 7; i++) ws['!merges'].push({ s: { r: i, c: 0 }, e: { r: i, c: headers.length - 1 } });
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'قالب الموظفين');
    XLSX.writeFile(wb, `قالب_بيانات_الموظفين.xlsx`);
    toast('✅ تم تحميل القالب — افتحه واملأه ثم استورده', 'ok', 5000);
};

// فتح حوار اختيار ملف الاستيراد
window.openEmpImportDialog = function () {
    if (myP?.role !== 'admin' && !can('add_employee')) { toast('ليس لديك صلاحية إضافة موظفين', 'er'); return }
    $('empImportFile').click();
};

// معالجة الملف المرفوع
window.handleEmpImport = async function (input) {
    const file = input.files?.[0];
    if (!file) return;
    if (typeof XLSX === 'undefined') { toast('مكتبة Excel لم تُحمَّل بعد', 'er'); return }
    try {
        const buffer = await file.arrayBuffer();
        const wb = XLSX.read(buffer);
        const wsName = wb.SheetNames[0];
        const ws = wb.Sheets[wsName];
        const aoa = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' });

        // ابحث عن صف الرؤوس
        const headerRowIdx = aoa.findIndex(row => row.some(cell => String(cell).includes('الاسم الكامل')));
        if (headerRowIdx === -1) { toast('❌ لم يتم العثور على صف الرؤوس — تأكد من استخدام القالب الصحيح', 'er'); input.value = ''; return }
        const headerRow = aoa[headerRowIdx].map(c => String(c).trim());

        // خريطة العمود → key
        const colMap = {};
        EMP_EXCEL_COLS.forEach(c => {
            const idx = headerRow.findIndex(h => h === c.label || h.replace(/[*\s]/g, '') === c.label.replace(/[*\s]/g, ''));
            if (idx !== -1) colMap[c.key] = idx;
        });

        if (colMap.name === undefined) { toast('❌ عمود "الاسم الكامل" غير موجود', 'er'); input.value = ''; return }

        // قراءة البيانات (الصفوف بعد رأس الجدول)
        const dataRows = aoa.slice(headerRowIdx + 1).filter(row => row[colMap.name] && String(row[colMap.name]).trim());
        if (!dataRows.length) { toast('❌ الملف لا يحتوي على بيانات', 'er'); input.value = ''; return }

        const confirmed = await new Promise(resolve => {
            cf2(`سيتم استيراد ${dataRows.length} موظف. الموظفون الموجودون (بنفس الرقم الوظيفي) سيُحدَّثون. متابعة؟`,
                () => resolve(true), () => resolve(false));
        });
        if (!confirmed) { input.value = ''; return }

        // جهّز batch
        const batchUpd = {};
        let created = 0, updated = 0, skipped = 0;
        for (const row of dataRows) {
            const data = {};
            EMP_EXCEL_COLS.forEach(c => {
                if (colMap[c.key] !== undefined) {
                    let v = row[colMap[c.key]];
                    if (v === '' || v === null || v === undefined) return;
                    // تحويل القيم الرقمية
                    const numericKeys = ['dailyHours', 'workDaysPerMonth', 'salary', 'houseAllow', 'transAllow', 'phoneAllow', 'natureAllow', 'repAllow', 'carAllow', 'perfBonus', 'otherBonus', 'socialEmp', 'socialComp', 'medIns', 'leaveAnnual', 'leaveSick', 'leaveEmergency'];
                    if (numericKeys.includes(c.key)) v = parseFloat(v) || 0;
                    else v = String(v).trim();
                    data[c.key] = v;
                }
            });
            if (!data.name) { skipped++; continue }
            if (!['active', 'inactive'].includes(data.status)) data.status = 'active';
            // ابحث عن موظف موجود بنفس empId
            let existingKey = null;
            if (data.empId) {
                const found = Object.entries(emp).find(([, e]) => e.empId === data.empId);
                if (found) existingKey = found[0];
            }
            if (existingKey) {
                data.updatedAt = new Date().toISOString();
                batchUpd[`ledger/employees/${existingKey}`] = { ...emp[existingKey], ...data };
                updated++;
            } else {
                const newKey = push(R.emp).key;
                data.createdAt = new Date().toISOString();
                batchUpd[`ledger/employees/${newKey}`] = data;
                created++;
            }
        }
        await update(ref(db), batchUpd);
        toast(`✅ تم الاستيراد: ${created} جديد | ${updated} محدّث${skipped>0?` | ${skipped} متخطى`:''}`, 'ok', 7000);
        input.value = '';
    } catch (e) {
        toast('❌ خطأ في الاستيراد: ' + e.message, 'er', 6000);
        console.error(e);
        input.value = '';
    }
};

