// ملء قائمة المديرين
window.fillDeptManagerSelect = function () {
    const sel = $('dpManager'); if (!sel) return;
    const cur = sel.value;
    sel.innerHTML = '<option value="">-- اختر مديراً --</option>';
    Object.entries(emp)
        .filter(([, e]) => (e.status || 'active') === 'active')
        .sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar'))
        .forEach(([k, e]) => {
            sel.innerHTML += `<option value="${k}">${e.name || k}${e.job ? ' — ' + e.job : ''}</option>`;
        });
    if (cur) sel.value = cur;
};

// ملء قائمة الإدارات المنسدلة في مودال الموظف
window.fillDeptDatalist = function () {
    const sel = $('eDept'); if (!sel) return;
    const cur = sel.value;
    // اجمع الإدارات: من جدول الإدارات + من الموظفين (للتوافق مع البيانات القديمة)
    const allDepts = new Set();
    Object.values(departments).forEach(d => { if (d.name) allDepts.add(d.name) });
    Object.values(emp).forEach(e => { if (e.dept) allDepts.add(e.dept) });
    const sortedDepts = [...allDepts].sort((a, b) => a.localeCompare(b, 'ar'));
    sel.innerHTML = '<option value="">-- اختر الإدارة --</option>' +
        sortedDepts.map(d => `<option value="${d}">${d}</option>`).join('');
    // استعد القيمة السابقة إن وُجدت
    if (cur && sortedDepts.includes(cur)) sel.value = cur;
    // حدّث أيضاً فلتر صفحة الموظفين (إذا كان موجوداً)
    const dl = document.querySelector('datalist#deptsList');
    if (dl) { dl.innerHTML = ''; sortedDepts.forEach(d => { const o = document.createElement('option'); o.value = d; dl.appendChild(o) }) }
};

// إضافة إدارة سريعة من مودال الموظف
window.quickAddDept = async function () {
    const name = prompt('اسم الإدارة الجديدة:');
    if (!name || !name.trim()) return;
    const trimmed = name.trim();
    // تحقق من التكرار
    if (Object.values(departments).some(d => d.name === trimmed)) {
        toast('⚠️ هذه الإدارة موجودة بالفعل', 'wn');
        if ($('eDept')) $('eDept').value = trimmed;
        return;
    }
    try {
        await push(R.depts, {
            name: trimmed, code: '', managerId: '', managerName: '', desc: '',
            createdBy: myP?.name || '', createdAt: new Date().toISOString()
        });
        toast(`✅ تمت إضافة "${trimmed}"`, 'ok');
        // الانتظار قليلاً ثم اختيارها
        setTimeout(() => {
            fillDeptDatalist();
            if ($('eDept')) $('eDept').value = trimmed;
        }, 400);
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// إضافة إدارة جديدة
window.addDepartment = async function () {
    if (myP?.role !== 'admin' && !can('manage_departments')) { toast('ليس لديك صلاحية', 'er'); return }
    const name = $('dpName')?.value?.trim();
    const code = $('dpCode')?.value?.trim();
    const managerId = $('dpManager')?.value;
    const desc = $('dpDesc')?.value?.trim();
    const status = $('dpStatus');
    if (!name) { status.textContent = '⚠️ اسم الإدارة مطلوب'; return }
    // تحقق من عدم التكرار
    const exists = Object.values(departments).some(d => d.name === name);
    if (exists) { status.textContent = '⚠️ هذه الإدارة موجودة مسبقاً'; return }
    try {
        const managerName = managerId && emp[managerId] ? emp[managerId].name : '';
        await push(R.depts, {
            name, code, managerId: managerId || '', managerName,
            desc,
            createdBy: myP?.name || '', createdAt: new Date().toISOString()
        });
        status.textContent = `✅ تم إضافة الإدارة "${name}"`;
        toast('✅ تم إضافة الإدارة', 'ok');
        $('dpName').value = ''; $('dpCode').value = ''; $('dpManager').value = ''; $('dpDesc').value = '';
        renderDepartments();
    } catch (e) { status.textContent = '❌ خطأ: ' + e.message; toast('خطأ: ' + e.message, 'er') }
};

// عرض قائمة الإدارات
window.renderDepartments = function () {
    const container = $('deptsList2'); if (!container) return;
    const deptsArr = Object.entries(departments);
    if (!deptsArr.length) {
        container.innerHTML = '<div class="empty"><div class="ei">🏢</div><p>لا توجد إدارات — أضف إدارة جديدة من الأعلى</p></div>';
        return;
    }
    deptsArr.sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar'));
    container.innerHTML = `<div style="display:grid;gap:10px;grid-template-columns:repeat(auto-fill,minmax(320px,1fr))">${deptsArr.map(([dk, d]) => {
        const empsInDept = Object.values(emp).filter(e => e.dept === d.name && (e.status||'active')==='active');
        const totalSalaries = empsInDept.reduce((s, e) => s + empFinance(e).netSalary, 0);
        const isAdmin = myP?.role === 'admin' || can('manage_departments');
        return `<div style="background:white;border:1.5px solid #e0e8f0;border-radius:12px;padding:14px;border-right:4px solid #2d6a9f">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;margin-bottom:10px">
                <div style="flex:1;min-width:0">
                    <div style="font-size:15px;font-weight:800;color:#1a3a5c">🏢 ${esc(d.name)}${d.code ? ` <span style="font-size:11px;color:#888;font-weight:400">(${esc(d.code)})</span>` : ''}</div>
                    ${d.desc ? `<div style="font-size:11px;color:#666;margin-top:4px">${esc(d.desc)}</div>` : ''}
                    ${d.managerName ? `<div style="font-size:11px;color:#555;margin-top:4px">👤 المدير: <strong>${esc(d.managerName)}</strong></div>` : ''}
                </div>
                ${isAdmin ? `<div style="display:flex;gap:4px">
                    <button class="btn b-b" style="padding:4px 8px;font-size:11px" onclick="openEditDept('${dk}')">✏️</button>
                    <button class="btn b-r" style="padding:4px 8px;font-size:11px" onclick="deleteDepartment('${dk}')">🗑️</button>
                </div>` : ''}
            </div>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;background:#f8fafc;border-radius:8px;padding:10px">
                <div style="text-align:center">
                    <div style="font-size:10px;color:#888">عدد الموظفين</div>
                    <div style="font-size:18px;font-weight:800;color:#27ae60">${empsInDept.length}</div>
                </div>
                <div style="text-align:center;border-right:1px solid #e0e8f0">
                    <div style="font-size:10px;color:#888">إجمالي الرواتب الصافية</div>
                    <div style="font-size:15px;font-weight:800;color:#2d6a9f">${fmt(totalSalaries)}</div>
                </div>
            </div>
            ${empsInDept.length ? `<div style="margin-top:8px;font-size:10px;color:#888"><strong>الموظفون:</strong> ${empsInDept.slice(0, 5).map(e => esc(e.name)).join('، ')}${empsInDept.length > 5 ? ` و${empsInDept.length - 5} آخرون...` : ''}</div>` : ''}
        </div>`;
    }).join('')}</div>`;
};

// KPIs للإدارات
function updateDeptKPIs() {
    const deptsCount = Object.keys(departments).length;
    $('dpk1') && ($('dpk1').textContent = deptsCount);
    const empsWithDept = Object.values(emp).filter(e => e.dept && (e.status||'active')==='active');
    $('dpk2') && ($('dpk2').textContent = empsWithDept.length);
    // إدارات فارغة
    const emptyDepts = Object.values(departments).filter(d => {
        return !Object.values(emp).some(e => e.dept === d.name);
    }).length;
    $('dpk3') && ($('dpk3').textContent = emptyDepts);
    const totalSalaries = empsWithDept.reduce((s, e) => s + empFinance(e).netSalary, 0);
    $('dpk4') && ($('dpk4').textContent = fmt(totalSalaries));
}

// فتح مودال تعديل الإدارة
window.openEditDept = function (dk) {
    const d = departments[dk]; if (!d) return;
    // استخدم الإضافة نفسها كنموذج تعديل (تعبئة الحقول وتغيير الزر)
    $('dpName').value = d.name || '';
    $('dpCode').value = d.code || '';
    $('dpDesc').value = d.desc || '';
    fillDeptManagerSelect();
    setTimeout(() => { if ($('dpManager')) $('dpManager').value = d.managerId || ''; }, 100);
    // علّم الزر
    window._editingDeptKey = dk;
    const btn = document.querySelector('button[onclick="addDepartment()"]');
    if (btn) {
        btn.textContent = '💾 حفظ التعديل';
        btn.setAttribute('onclick', `saveEditDept()`);
    }
    $('dpStatus').innerHTML = `📝 وضع التعديل: <strong>${d.name}</strong> — <a href="#" onclick="cancelEditDept();return false" style="color:#e74c3c">إلغاء</a>`;
    $('dpName').focus();
    $('dpName').scrollIntoView({ behavior: 'smooth', block: 'center' });
};

// حفظ التعديل
window.saveEditDept = async function () {
    const dk = window._editingDeptKey; if (!dk) return;
    const name = $('dpName')?.value?.trim();
    const code = $('dpCode')?.value?.trim();
    const managerId = $('dpManager')?.value;
    const desc = $('dpDesc')?.value?.trim();
    if (!name) { $('dpStatus').textContent = '⚠️ اسم الإدارة مطلوب'; return }
    const oldDept = departments[dk];
    const oldName = oldDept?.name;
    try {
        const managerName = managerId && emp[managerId] ? emp[managerId].name : '';
        await update(ref(db, `ledger/departments/${dk}`), {
            name, code, managerId: managerId || '', managerName, desc,
            updatedAt: new Date().toISOString()
        });
        // إذا تغير اسم الإدارة، حدّث كل الموظفين المرتبطين بها
        if (oldName && oldName !== name) {
            const empsToUpdate = Object.entries(emp).filter(([, e]) => e.dept === oldName);
            if (empsToUpdate.length) {
                const batchUpd = {};
                empsToUpdate.forEach(([k]) => { batchUpd[`ledger/employees/${k}/dept`] = name; });
                await update(ref(db), batchUpd);
                toast(`✅ تم تحديث الإدارة + ${empsToUpdate.length} موظف مرتبط بها`, 'ok', 4000);
            } else toast('✅ تم تحديث الإدارة', 'ok');
        } else toast('✅ تم تحديث الإدارة', 'ok');
        cancelEditDept();
        renderDepartments();
    } catch (e) { $('dpStatus').textContent = '❌ خطأ: ' + e.message; toast('خطأ: ' + e.message, 'er') }
};

// إلغاء التعديل
window.cancelEditDept = function () {
    window._editingDeptKey = null;
    $('dpName').value = ''; $('dpCode').value = ''; $('dpManager').value = ''; $('dpDesc').value = '';
    const btn = document.querySelector('button[onclick="saveEditDept()"]');
    if (btn) {
        btn.textContent = '💾 إضافة الإدارة';
        btn.setAttribute('onclick', `addDepartment()`);
    }
    $('dpStatus').textContent = '';
};

// حذف إدارة
window.deleteDepartment = function (dk) {
    const d = departments[dk]; if (!d) return;
    const empsInDept = Object.values(emp).filter(e => e.dept === d.name);
    if (empsInDept.length) {
        toast(`❌ لا يمكن حذف الإدارة — يوجد ${empsInDept.length} موظف مرتبط بها. غيّر إدارتهم أولاً`, 'er', 6000);
        return;
    }
    cf2(`حذف الإدارة "${d.name}"؟`, async () => {
        try { await remove(ref(db, `ledger/departments/${dk}`)); toast('🗑️ تم الحذف', 'ok'); renderDepartments(); }
        catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

