// متغيرات لحفظ الـ Charts (لتدميرها قبل إعادة الإنشاء)
let hrCharts = {};

window.renderHRDashboard = function () {
    try {
        // الحصول على الفترة المختارة
        const period = $('hrPeriodFilter')?.value || 'month';

        // === KPI Cards ===
        renderHRKPIs(period);

        // === Charts ===
        setTimeout(() => {
            renderChartDept();
            renderChartAffiliation();
            renderChartNationality();
            renderChartSalaryTrend();
            renderChartAttendance();
            renderChartPerf();
            renderChartLeaves();
            renderChartCostByDept();
        }, 100);

        // === Tables ===
        renderTopPerformers();
        renderLatestHires();
        renderCriticalDocs();
        renderCelebrations();
    } catch (e) {
        console.error('HR Dashboard render error:', e);
    }
};

// === KPI Calculations ===
function renderHRKPIs(period) {
    const emps = Object.values(emp);
    const activeEmps = emps.filter(e => (e.status || 'active') === 'active');
    const inactiveEmps = emps.filter(e => e.status === 'inactive' || e.status === 'terminated');

    // Total employees
    $('hrkTotalEmp') && ($('hrkTotalEmp').textContent = emps.length);
    $('hrkActiveEmp') && ($('hrkActiveEmp').textContent = activeEmps.length);
    $('hrkInactiveEmp') && ($('hrkInactiveEmp').textContent = inactiveEmps.length);

    // Total salaries
    const totalSalaries = activeEmps.reduce((s, e) => s + empFinance(e).netSalary, 0);
    const avgSalary = activeEmps.length ? totalSalaries / activeEmps.length : 0;
    $('hrkTotalSalaries') && ($('hrkTotalSalaries').textContent = fmt(totalSalaries));
    $('hrkAvgSalary') && ($('hrkAvgSalary').textContent = fmt(avgSalary));

    // Attendance rate (current month)
    const currentMonth = new Date().toISOString().substring(0, 7);
    const monthAtt = Object.values(attendance).filter(a => (a.date || '').startsWith(currentMonth));
    const monthDays = new Date(new Date().getFullYear(), new Date().getMonth() + 1, 0).getDate();
    // أيام العمل (نخصم الجمع والسبت)
    let workDays = 0;
    for (let d = 1; d <= monthDays; d++) {
        const day = new Date(new Date().getFullYear(), new Date().getMonth(), d).getDay();
        if (day !== 5 && day !== 6) workDays++; // 5=Friday, 6=Saturday
    }
    const expectedAtt = workDays * activeEmps.length;
    const attRate = expectedAtt ? ((monthAtt.length / expectedAtt) * 100).toFixed(1) : 0;
    $('hrkAttendance') && ($('hrkAttendance').textContent = attRate + '%');
    $('hrkAttendanceDetail') && ($('hrkAttendanceDetail').textContent = `${monthAtt.length} / ${expectedAtt} يوم`);

    // Average performance
    const perfs = Object.values(performance);
    if (perfs.length) {
        const avgPerf = (perfs.reduce((s, p) => s + (parseFloat(p.avgScore) || 0), 0) / perfs.length).toFixed(1);
        $('hrkAvgPerf') && ($('hrkAvgPerf').textContent = avgPerf);
        $('hrkPerfCount') && ($('hrkPerfCount').textContent = `${perfs.length} تقييم`);
    } else {
        $('hrkAvgPerf') && ($('hrkAvgPerf').textContent = '—');
    }

    // Pending leaves
    const pendingLeaves = Object.values(leaves).filter(l => l.status === 'pending').length;
    $('hrkLeavesPending') && ($('hrkLeavesPending').textContent = pendingLeaves);
    $('hrkLeavesPendingBadge') && ($('hrkLeavesPendingBadge').textContent = pendingLeaves);

    // Active loans
    const activeLoans = Object.values(loans).filter(l => l.status !== 'paid' && l.status !== 'cancelled');
    const loansTotal = activeLoans.reduce((s, l) => {
        const sched = l.schedule || [];
        const remaining = sched.filter(i => i.status !== 'paid').reduce((sum, i) => sum + (parseFloat(i.amount) || 0), 0);
        return s + remaining;
    }, 0);
    $('hrkActiveLoans') && ($('hrkActiveLoans').textContent = activeLoans.length);
    $('hrkLoansTotal') && ($('hrkLoansTotal').textContent = fmt(loansTotal));

    // Critical documents
    const today_ = new Date();
    let expiredDocs = 0, urgentDocs = 0;
    emps.forEach(e => {
        // وثائق الموظف
        const docs = e.documents ? Object.values(e.documents) : [];
        docs.forEach(d => {
            if (!d.expiry) return;
            const diff = Math.ceil((new Date(d.expiry) - today_) / (1000 * 60 * 60 * 24));
            if (diff < 0) expiredDocs++;
            else if (diff <= 30) urgentDocs++;
        });
        // الإقامة وانتهاء العقد كحقول مستقلة
        if (e.iqamaExp) {
            const diff = Math.ceil((new Date(e.iqamaExp) - today_) / (1000 * 60 * 60 * 24));
            if (diff < 0) expiredDocs++;
            else if (diff <= 30) urgentDocs++;
        }
        if (e.contractEnd) {
            const diff = Math.ceil((new Date(e.contractEnd) - today_) / (1000 * 60 * 60 * 24));
            if (diff < 0) expiredDocs++;
            else if (diff <= 30) urgentDocs++;
        }
    });
    $('hrkExpiredDocs') && ($('hrkExpiredDocs').textContent = expiredDocs);
    $('hrkUrgentDocs') && ($('hrkUrgentDocs').textContent = urgentDocs);

    // Birthdays + Anniversaries (this month)
    const currentMonthNum = today_.getMonth();
    let birthdays = 0, anniversaries = 0;
    emps.forEach(e => {
        if (e.birthDate) {
            const bd = new Date(e.birthDate);
            if (bd.getMonth() === currentMonthNum) birthdays++;
        }
        if (e.hireDate) {
            const hd = new Date(e.hireDate);
            if (hd.getMonth() === currentMonthNum && hd.getFullYear() < today_.getFullYear()) anniversaries++;
        }
    });
    $('hrkBirthdays') && ($('hrkBirthdays').textContent = birthdays);
    $('hrkAnniversaries') && ($('hrkAnniversaries').textContent = anniversaries);
}

// === Chart Helpers ===
function destroyChart(id) {
    if (hrCharts[id]) {
        try { hrCharts[id].destroy(); } catch (e) { }
        delete hrCharts[id];
    }
}

const CHART_COLORS = ['#2d6a9f', '#27ae60', '#f39c12', '#e67e22', '#8e44ad', '#c0392b', '#16a085', '#d35400', '#7f8c8d', '#1abc9c', '#3498db', '#e74c3c'];

// === Chart 1: Department Distribution ===
function renderChartDept() {
    const ctx = $('hrChartDept'); if (!ctx) return;
    destroyChart('dept');
    const activeEmps = Object.values(emp).filter(e => (e.status || 'active') === 'active');
    const byDept = {};
    activeEmps.forEach(e => {
        const d = e.dept || 'غير محدد';
        byDept[d] = (byDept[d] || 0) + 1;
    });
    const labels = Object.keys(byDept);
    const data = Object.values(byDept);

    if (!data.length) { ctx.parentElement.innerHTML = '<div style="padding:60px 20px;text-align:center;color:#999;font-size:13px">لا توجد بيانات</div>'; return; }

    $('hrChartDeptInfo') && ($('hrChartDeptInfo').textContent = `${labels.length} إدارة`);

    hrCharts.dept = new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels,
            datasets: [{
                data,
                backgroundColor: CHART_COLORS.slice(0, labels.length),
                borderColor: 'white',
                borderWidth: 2
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: { position: 'bottom', labels: { font: { family: 'Tahoma', size: 11 }, padding: 8, boxWidth: 12 } },
                tooltip: { rtl: true, bodyFont: { family: 'Tahoma' } }
            }
        }
    });
}

