// === Chart 4: Salary Trend (last 6 months) ===
function renderChartSalaryTrend() {
    const ctx = $('hrChartSalaryTrend'); if (!ctx) return;
    destroyChart('salaryTrend');

    const monthLabels = [];
    const monthValues = [];
    const today_ = new Date();
    for (let i = 5; i >= 0; i--) {
        const d = new Date(today_.getFullYear(), today_.getMonth() - i, 1);
        const monthStr = d.toISOString().substring(0, 7);
        const monthLabel = d.toLocaleDateString('ar-SA', { month: 'short', year: 'numeric' });
        monthLabels.push(monthLabel);
        // مجموع المسيرات لهذا الشهر
        const monthPayrolls = Object.values(payrolls).filter(p => p.month === monthStr && p.status === 'approved');
        const monthTotal = monthPayrolls.reduce((s, p) => {
            const items = Object.values(p.items || {});
            return s + items.reduce((sum, it) => sum + (parseFloat(it.netPay) || 0), 0);
        }, 0);
        monthValues.push(monthTotal);
    }

    hrCharts.salaryTrend = new Chart(ctx, {
        type: 'line',
        data: {
            labels: monthLabels,
            datasets: [{
                label: 'إجمالي الرواتب المعتمدة',
                data: monthValues,
                borderColor: '#27ae60',
                backgroundColor: 'rgba(39, 174, 96, .1)',
                tension: 0.35,
                fill: true,
                pointBackgroundColor: '#27ae60',
                pointRadius: 5,
                pointHoverRadius: 7,
                borderWidth: 3
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: { display: false },
                tooltip: { rtl: true, bodyFont: { family: 'Tahoma' }, callbacks: { label: ctx => 'ريال: ' + fmt(ctx.parsed.y) } }
            },
            scales: {
                y: { ticks: { callback: v => fmt(v), font: { family: 'Tahoma', size: 10 } }, grid: { color: '#eef2f7' } },
                x: { ticks: { font: { family: 'Tahoma', size: 11 } }, grid: { display: false } }
            }
        }
    });
}

// === Chart 5: Attendance vs Absence (last 6 months) ===
function renderChartAttendance() {
    const ctx = $('hrChartAttendance'); if (!ctx) return;
    destroyChart('attendance');

    const monthLabels = [];
    const attendanceData = [];
    const absenceData = [];
    const today_ = new Date();
    const activeEmps = Object.values(emp).filter(e => (e.status || 'active') === 'active');

    for (let i = 5; i >= 0; i--) {
        const d = new Date(today_.getFullYear(), today_.getMonth() - i, 1);
        const monthStr = d.toISOString().substring(0, 7);
        const monthLabel = d.toLocaleDateString('ar-SA', { month: 'short' });
        monthLabels.push(monthLabel);

        // أيام العمل في الشهر
        const monthDays = new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
        let workDays = 0;
        for (let dd = 1; dd <= monthDays; dd++) {
            const day = new Date(d.getFullYear(), d.getMonth(), dd).getDay();
            if (day !== 5 && day !== 6) workDays++;
        }
        const expectedAtt = workDays * activeEmps.length;
        const monthAtt = Object.values(attendance).filter(a => (a.date || '').startsWith(monthStr)).length;
        const absent = Math.max(0, expectedAtt - monthAtt);
        attendanceData.push(monthAtt);
        absenceData.push(absent);
    }

    hrCharts.attendance = new Chart(ctx, {
        type: 'bar',
        data: {
            labels: monthLabels,
            datasets: [
                {
                    label: 'حضور',
                    data: attendanceData,
                    backgroundColor: '#27ae60',
                    borderRadius: 6,
                    maxBarThickness: 40
                },
                {
                    label: 'غياب',
                    data: absenceData,
                    backgroundColor: '#e74c3c',
                    borderRadius: 6,
                    maxBarThickness: 40
                }
            ]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: { position: 'top', labels: { font: { family: 'Tahoma', size: 11 } } },
                tooltip: { rtl: true, bodyFont: { family: 'Tahoma' } }
            },
            scales: {
                y: { stacked: false, ticks: { font: { family: 'Tahoma', size: 10 } }, grid: { color: '#eef2f7' } },
                x: { ticks: { font: { family: 'Tahoma', size: 11 } }, grid: { display: false } }
            }
        }
    });
}

