// === Top Performers ===
function renderTopPerformers() {
    const container = $('hrTopPerformers'); if (!container) return;
    const perfs = Object.values(performance).sort((a, b) => (parseFloat(b.avgScore) || 0) - (parseFloat(a.avgScore) || 0)).slice(0, 5);
    if (!perfs.length) {
        container.innerHTML = '<div style="padding:20px;text-align:center;color:#999;font-size:12px">لا توجد تقييمات بعد</div>';
        return;
    }
    container.innerHTML = perfs.map((p, i) => {
        const e = emp[p.empKey] || {};
        const medal = ['🥇', '🥈', '🥉', '⭐', '⭐'][i] || '⭐';
        const color = ['#f1c40f', '#bdc3c7', '#d35400', '#888', '#888'][i] || '#888';
        const ratingLabel = { excellent: 'ممتاز', vgood: 'جيد جداً', good: 'جيد', weak: 'ضعيف' }[p.rating] || '-';
        return `<div style="display:flex;align-items:center;gap:10px;padding:10px;border-bottom:1px solid #f0f5fa">
            <div style="font-size:24px;width:36px;text-align:center">${medal}</div>
            <div style="flex:1;min-width:0">
                <div style="font-size:13px;font-weight:700;color:#1a3a5c">${e.name || p.empName || '-'}</div>
                <div style="font-size:10px;color:#666">${p.month || '-'} · ${ratingLabel}${p.bonusAmt ? ' · مكافأة: ' + fmt(p.bonusAmt) + ' ر' : ''}</div>
            </div>
            <div style="text-align:center;background:#f8fafc;border-radius:8px;padding:4px 10px;min-width:50px">
                <div style="font-size:18px;font-weight:900;color:${color}">${(parseFloat(p.avgScore) || 0).toFixed(1)}</div>
                <div style="font-size:9px;color:#888">/ 10</div>
            </div>
        </div>`;
    }).join('');
}

// === Latest Hires ===
function renderLatestHires() {
    const container = $('hrLatestHires'); if (!container) return;
    const emps = Object.entries(emp).filter(([, e]) => e.hireDate).sort((a, b) => (b[1].hireDate || '').localeCompare(a[1].hireDate || '')).slice(0, 5);
    if (!emps.length) {
        container.innerHTML = '<div style="padding:20px;text-align:center;color:#999;font-size:12px">لا توجد بيانات تعيين</div>';
        return;
    }
    container.innerHTML = emps.map(([k, e]) => {
        const hireDate = new Date(e.hireDate);
        const daysAgo = Math.ceil((new Date() - hireDate) / (1000 * 60 * 60 * 24));
        const isNew = daysAgo <= 90;
        return `<div style="display:flex;align-items:center;gap:10px;padding:10px;border-bottom:1px solid #f0f5fa">
            <div style="background:${isNew ? '#27ae60' : '#888'};color:white;border-radius:50%;width:38px;height:38px;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:14px">${(e.name || '?').charAt(0)}</div>
            <div style="flex:1;min-width:0">
                <div style="font-size:13px;font-weight:700;color:#1a3a5c">${e.name || '-'}${isNew ? ' 🆕' : ''}</div>
                <div style="font-size:10px;color:#666">${e.job || '-'} · ${e.dept || (projects[e.projectId]?.name) || '-'}</div>
            </div>
            <div style="text-align:left">
                <div style="font-size:11px;color:#1a3a5c;font-weight:700">${hireDate.toLocaleDateString('ar-SA')}</div>
                <div style="font-size:10px;color:#888">منذ ${daysAgo} يوم</div>
            </div>
        </div>`;
    }).join('');
}

// === Critical Documents ===
function renderCriticalDocs() {
    const container = $('hrCriticalDocs'); if (!container) return;
    const critical = [];
    const today_ = new Date();

    Object.entries(emp).forEach(([k, e]) => {
        if ((e.status || 'active') !== 'active') return;
        // iqama
        if (e.iqamaExp) {
            const diff = Math.ceil((new Date(e.iqamaExp) - today_) / (1000 * 60 * 60 * 24));
            if (diff <= 30) critical.push({ emp: e, type: 'إقامة', expiry: e.iqamaExp, daysLeft: diff });
        }
        // contract
        if (e.contractEnd) {
            const diff = Math.ceil((new Date(e.contractEnd) - today_) / (1000 * 60 * 60 * 24));
            if (diff <= 30) critical.push({ emp: e, type: 'عقد العمل', expiry: e.contractEnd, daysLeft: diff });
        }
        // documents
        const docs = e.documents ? Object.values(e.documents) : [];
        docs.forEach(d => {
            if (!d.expiry) return;
            const diff = Math.ceil((new Date(d.expiry) - today_) / (1000 * 60 * 60 * 24));
            if (diff <= 30) critical.push({ emp: e, type: d.docName || d.docType || 'مستند', expiry: d.expiry, daysLeft: diff });
        });
    });

    critical.sort((a, b) => a.daysLeft - b.daysLeft);
    $('hrCriticalCount') && ($('hrCriticalCount').textContent = critical.length);

    if (!critical.length) {
        container.innerHTML = '<div style="padding:20px;text-align:center;color:#27ae60;font-size:12px">🎉 لا توجد مستندات حرجة</div>';
        return;
    }
    container.innerHTML = critical.slice(0, 6).map(c => {
        const color = c.daysLeft < 0 ? '#c0392b' : c.daysLeft <= 7 ? '#e67e22' : '#f39c12';
        const status = c.daysLeft < 0 ? `منتهي منذ ${Math.abs(c.daysLeft)} يوم` : `${c.daysLeft} يوم متبقي`;
        return `<div style="display:flex;align-items:center;gap:10px;padding:8px;border-bottom:1px solid #fadbd8">
            <div style="background:${color};color:white;border-radius:6px;padding:3px 8px;font-size:10px;font-weight:800;white-space:nowrap">${c.daysLeft < 0 ? '🔴' : c.daysLeft <= 7 ? '🟠' : '🟡'}</div>
            <div style="flex:1;min-width:0">
                <div style="font-size:12px;font-weight:700;color:#1a3a5c">${c.emp.name || '-'}</div>
                <div style="font-size:10px;color:#666">${c.type} · ${status}</div>
            </div>
            <div style="font-size:11px;color:${color};font-weight:700">${new Date(c.expiry).toLocaleDateString('ar-SA')}</div>
        </div>`;
    }).join('') + (critical.length > 6 ? `<div style="text-align:center;padding:8px;font-size:11px;color:#c0392b;font-weight:700;cursor:pointer" onclick="nav('docalerts')">عرض كل المستندات الحرجة (${critical.length}) ←</div>` : '');
}

// === Upcoming Celebrations ===
function renderCelebrations() {
    const container = $('hrCelebrations'); if (!container) return;
    const celebrations = [];
    const today_ = new Date();
    const currentMonth = today_.getMonth();
    const currentDate = today_.getDate();

    Object.values(emp).forEach(e => {
        if ((e.status || 'active') !== 'active') return;
        // birthdays
        if (e.birthDate) {
            const bd = new Date(e.birthDate);
            if (bd.getMonth() === currentMonth) {
                const daysUntil = bd.getDate() - currentDate;
                celebrations.push({
                    type: 'birthday', emp: e, date: bd, daysUntil,
                    label: '🎂 عيد ميلاد', age: today_.getFullYear() - bd.getFullYear()
                });
            }
        }
        // anniversaries
        if (e.hireDate) {
            const hd = new Date(e.hireDate);
            if (hd.getMonth() === currentMonth && hd.getFullYear() < today_.getFullYear()) {
                const daysUntil = hd.getDate() - currentDate;
                celebrations.push({
                    type: 'anniversary', emp: e, date: hd, daysUntil,
                    label: '🎉 ذكرى التعيين', years: today_.getFullYear() - hd.getFullYear()
                });
            }
        }
    });

    celebrations.sort((a, b) => a.daysUntil - b.daysUntil);

    if (!celebrations.length) {
        container.innerHTML = '<div style="padding:20px;text-align:center;color:#999;font-size:12px">لا توجد احتفالات هذا الشهر</div>';
        return;
    }
    container.innerHTML = celebrations.slice(0, 6).map(c => {
        const isPast = c.daysUntil < 0;
        const isToday = c.daysUntil === 0;
        const statusText = isToday ? '🎊 اليوم!' : isPast ? `قبل ${Math.abs(c.daysUntil)} يوم` : `بعد ${c.daysUntil} يوم`;
        const color = isToday ? '#27ae60' : isPast ? '#888' : '#2d6a9f';
        const detail = c.type === 'birthday' ? `سيكمل ${c.age} عاماً` : `${c.years} سنة في الشركة`;
        return `<div style="display:flex;align-items:center;gap:10px;padding:10px;border-bottom:1px solid #f0f5fa;${isToday ? 'background:linear-gradient(135deg,#e8f5e9,#fff)' : ''}">
            <div style="font-size:22px">${c.type === 'birthday' ? '🎂' : '🎉'}</div>
            <div style="flex:1;min-width:0">
                <div style="font-size:13px;font-weight:700;color:#1a3a5c">${c.emp.name || '-'}</div>
                <div style="font-size:10px;color:#666">${detail}</div>
            </div>
            <div style="text-align:left">
                <div style="font-size:11px;color:${color};font-weight:700">${statusText}</div>
                <div style="font-size:10px;color:#888">${c.date.toLocaleDateString('ar-SA', { day: 'numeric', month: 'short' })}</div>
            </div>
        </div>`;
    }).join('');
}

