// حساب VAT وهامش الربح تلقائياً
window.calcProjectMargins = function () {
    const cv = parseFloat($('prjContractValue')?.value) || 0;
    const vat = cv * 0.15;
    const total = cv + vat;
    const targetMargin = parseFloat($('prjTargetMargin')?.value) || 0;
    const targetCost = cv * (1 - targetMargin / 100);
    if ($('prjVAT')) $('prjVAT').value = vat.toFixed(2);
    if ($('prjTotalWithVAT')) $('prjTotalWithVAT').value = total.toFixed(2);
    if ($('prjTargetCost')) $('prjTargetCost').value = targetCost.toFixed(2);
};

// حساب مدة المشروع تلقائياً
window.calcProjectDuration = function () {
    const start = $('prjStart')?.value;
    const end = $('prjEnd')?.value;
    if (start && end) {
        const days = Math.ceil((new Date(end) - new Date(start)) / (1000 * 60 * 60 * 24));
        if ($('prjDuration')) $('prjDuration').value = days > 0 ? days : 0;
    }
};
// ربط الحساب التلقائي للمدة
document.addEventListener('DOMContentLoaded', () => {
    ['prjStart', 'prjEnd'].forEach(id => {
        document.addEventListener('input', e => {
            if (e.target?.id === id) calcProjectDuration();
        });
    });

});

// ملء قوائم أعضاء الفريق من الموظفين
window.fillTeamMemberSelects = function () {
    const selects = ['prjProjectManager', 'prjSiteEngineer', 'prjSupervisor', 'prjFinanceManager'];
    const activeEmps = Object.entries(emp)
        .filter(([, e]) => (e.status || 'active') === 'active')
        .sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar'));
    selects.forEach(selId => {
        const sel = $(selId); if (!sel) return;
        const cur = sel.value;
        sel.innerHTML = '<option value="">-- اختر --</option>';
        activeEmps.forEach(([k, e]) => {
            sel.innerHTML += `<option value="${k}">${e.name || k}${e.job ? ' — ' + e.job : ''}</option>`;
        });
        if (cur) sel.value = cur;
    });
};

