// حساب إجمالي بند BOQ تلقائياً
document.addEventListener('input', e => {
    if (['boqQty', 'boqUnitPrice'].includes(e.target?.id)) {
        const q = parseFloat($('boqQty')?.value) || 0;
        const p = parseFloat($('boqUnitPrice')?.value) || 0;
        if ($('boqTotal')) $('boqTotal').value = (q * p).toFixed(2);
    }
    if (['mbQty', 'mbUnitPrice'].includes(e.target?.id)) {
        const q = parseFloat($('mbQty')?.value) || 0;
        const p = parseFloat($('mbUnitPrice')?.value) || 0;
        if ($('mbTotal')) $('mbTotal').value = (q * p).toFixed(2);
    }
});

// إضافة بند BOQ
window.addBOQItem = async function () {
    const prjKey = $('mPrjK').value;
    if (!prjKey) { toast('احفظ المشروع أولاً ثم أضف البنود', 'er'); return }
    const no = $('boqNo')?.value?.trim();
    const desc = $('boqDesc')?.value?.trim();
    const unit = $('boqUnit')?.value?.trim();
    const qty = parseFloat($('boqQty')?.value) || 0;
    const unitPrice = parseFloat($('boqUnitPrice')?.value) || 0;
    if (!desc) { toast('أدخل وصف البند', 'er'); return }
    if (qty <= 0) { toast('أدخل كمية صحيحة', 'er'); return }
    try {
        await push(ref(db, `ledger/projects/${prjKey}/boq`), {
            no, desc, unit, qty, unitPrice, total: qty * unitPrice,
            createdAt: new Date().toISOString(), createdBy: myP?.name || ''
        });
        $('boqNo').value = ''; $('boqDesc').value = ''; $('boqUnit').value = '';
        $('boqQty').value = ''; $('boqUnitPrice').value = ''; $('boqTotal').value = '';
        renderBOQList(prjKey);
        toast('✅ تم إضافة البند', 'ok');
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// عرض قائمة BOQ
