window.openMatCatalog = function (matKey = null) {
    $('mcK').value = matKey || '';
    $('mMatCatT').textContent = matKey ? '✏️ تعديل مادة في الكتالوج' : '📦 إضافة مادة للكتالوج';
    $('mcDelBtn').style.display = matKey ? '' : 'none';

    // ملء قائمة الموردين
    fillMatSupplierSelect();

    if (matKey && materials[matKey]) {
        const m = materials[matKey];
        $('mcName').value = m.name || '';
        $('mcSKU').value = m.sku || '';
        $('mcCategory').value = m.category || '';
        $('mcUnit').value = m.unit || '';
        $('mcBrand').value = m.brand || '';
        $('mcSpecs').value = m.specs || '';
        renderMatSuppliers(matKey);
    } else {
        ['mcName', 'mcSKU', 'mcUnit', 'mcBrand', 'mcSpecs'].forEach(id => $(id).value = '');
        $('mcCategory').value = '';
        $('mcSuppliersList').innerHTML = '<div style="padding:20px;text-align:center;color:#999;font-size:12px">لا توجد موردون مرتبطون بهذه المادة بعد</div>';
    }
    // مسح حقول إضافة المورد
    $('mcSupplierSel').value = '';
    $('mcSupplierPrice').value = '';
    $('mcSupplierNote').value = '';
    $('mcPreferred').checked = false;

    ov('mMatCat');
};

// ملء قائمة الموردين في مودال المادة
function fillMatSupplierSelect() {
    const sel = $('mcSupplierSel'); if (!sel) return;
    sel.innerHTML = '<option value="">-- اختر مورداً --</option>';
    Object.entries(sup)
        .sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar'))
        .forEach(([k, s]) => {
            sel.innerHTML += `<option value="${k}">${s.name || k}</option>`;
        });
}

// إضافة مورد للمادة الحالية
window.addSupplierToMaterial = async function () {
    const matKey = $('mcK').value;
    if (!matKey) { toast('احفظ المادة أولاً ثم أضف الموردين', 'er'); return }
    const supId = $('mcSupplierSel').value;
    const price = parseFloat($('mcSupplierPrice').value) || 0;
    const note = $('mcSupplierNote').value.trim();
    const preferred = $('mcPreferred').checked;
    if (!supId) { toast('اختر المورد', 'er'); return }
    if (price <= 0) { toast('أدخل السعر', 'er'); return }
    try {
        const supplier = sup[supId];
        // إذا كان هذا المفضل، ألغِ المفضلين السابقين
        if (preferred) {
            const m = materials[matKey];
            if (m?.suppliers) {
                const updates = {};
                Object.entries(m.suppliers).forEach(([sk, s]) => {
                    if (s.isPreferred) updates[`ledger/materials/${matKey}/suppliers/${sk}/isPreferred`] = false;
                });
                if (Object.keys(updates).length) await update(ref(db), updates);
            }
        }
        await push(ref(db, `ledger/materials/${matKey}/suppliers`), {
            supplierId: supId,
            supplierName: supplier?.name || '',
            price, note,
            isPreferred: preferred,
            addedAt: new Date().toISOString(),
            addedBy: myP?.name || ''
        });
        // أضف للأسعار التاريخية
        await push(ref(db, `ledger/materials/${matKey}/priceHistory`), {
            supplierId: supId, supplierName: supplier?.name || '',
            price, date: today(), recordedBy: myP?.name || ''
        });
        $('mcSupplierSel').value = '';
        $('mcSupplierPrice').value = '';
        $('mcSupplierNote').value = '';
        $('mcPreferred').checked = false;
        renderMatSuppliers(matKey);
        toast('✅ تمت إضافة المورد', 'ok');
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// عرض قائمة الموردين الخاصين بمادة
function renderMatSuppliers(matKey) {
    const container = $('mcSuppliersList'); if (!container) return;
    const m = materials[matKey];
    if (!m?.suppliers) {
        container.innerHTML = '<div style="padding:20px;text-align:center;color:#999;font-size:12px">لا توجد موردون مرتبطون بهذه المادة بعد</div>';
        return;
    }
    const list = Object.entries(m.suppliers).sort((a, b) => (a[1].price || 0) - (b[1].price || 0));
    const minPrice = list[0]?.[1].price || 0;
    container.innerHTML = `<table style="width:100%;border-collapse:collapse;font-size:12px">
        <thead style="background:#f8fafc"><tr>
            <th style="padding:8px;text-align:right">المورد</th>
            <th style="padding:8px;text-align:center">السعر/${m.unit||'وحدة'}</th>
            <th style="padding:8px;text-align:center">الفرق</th>
            <th style="padding:8px;text-align:right">ملاحظة</th>
            <th style="padding:8px;text-align:center"></th>
        </tr></thead>
        <tbody>${list.map(([sk, s], i) => {
            const diff = s.price - minPrice;
            const diffPct = minPrice > 0 ? ((diff / minPrice) * 100).toFixed(1) : 0;
            return `<tr style="${i%2?'background:#fafbfc':''}">
                <td style="padding:7px;font-weight:600">${s.isPreferred?'⭐ ':''}${s.supplierName}</td>
                <td style="padding:7px;text-align:center;font-weight:700;color:${i===0?'#27ae60':'#1a3a5c'}">${fmt(s.price)}${i===0?' 🏆':''}</td>
                <td style="padding:7px;text-align:center;font-size:11px;color:${diff===0?'#27ae60':'#e74c3c'}">${diff===0?'الأقل':'+'+fmt(diff)+' (+'+diffPct+'%)'}</td>
                <td style="padding:7px;font-size:11px;color:#666">${s.note||'-'}</td>
                <td style="padding:7px;text-align:center">
                    <button class="btn b-r" style="padding:3px 8px;font-size:10px" onclick="removeMatSupplier('${matKey}','${sk}')">🗑️</button>
                </td>
            </tr>`;
        }).join('')}</tbody>
    </table>`;
}

// إزالة مورد من المادة
window.removeMatSupplier = function (matKey, sk) {
    cf2('إزالة هذا المورد من قائمة موردي المادة؟', async () => {
        try {
            await remove(ref(db, `ledger/materials/${matKey}/suppliers/${sk}`));
            renderMatSuppliers(matKey);
            toast('🗑️ تم الحذف', 'ok');
        } catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

// حفظ المادة في الكتالوج
window.saveMatCatalog = async function () {
    const name = $('mcName').value.trim();
    const category = $('mcCategory').value;
    const unit = $('mcUnit').value.trim();
    if (!name) { toast('اسم المادة مطلوب', 'er'); return }
    if (!category) { toast('اختر التصنيف', 'er'); return }
    if (!unit) { toast('الوحدة مطلوبة', 'er'); return }

    const matKey = $('mcK').value;
    const data = {
        name, category, unit,
        sku: $('mcSKU').value.trim(),
        brand: $('mcBrand').value.trim(),
        specs: $('mcSpecs').value.trim(),
        updatedAt: new Date().toISOString()
    };
    // احسب unitCost كمتوسط أسعار الموردين
    const existing = matKey ? materials[matKey] : null;
    if (existing?.suppliers) {
        const prices = Object.values(existing.suppliers).map(s => s.price).filter(p => p > 0);
        if (prices.length) data.unitCost = parseFloat((prices.reduce((s, p) => s + p, 0) / prices.length).toFixed(2));
        const preferred = Object.values(existing.suppliers).find(s => s.isPreferred);
        if (preferred) data.preferredSupplierId = preferred.supplierId;
    }
    try {
        if (matKey) {
            await update(ref(db, `ledger/materials/${matKey}`), data);
            toast('✅ تم تحديث المادة', 'ok');
        } else {
            data.createdAt = new Date().toISOString();
            data.createdBy = myP?.name || '';
            const newRef = await push(R.mat, data);
            $('mcK').value = newRef.key;
            $('mMatCatT').textContent = '✏️ تعديل مادة في الكتالوج';
            $('mcDelBtn').style.display = '';
            toast('✅ تم إضافة المادة — يمكنك الآن إضافة موردين لها', 'ok');
            return; // لا تغلق المودال — اسمح بإضافة الموردين
        }
        cov('mMatCat');
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// حذف مادة من الكتالوج
window.deleteMatCatalog = function () {
    const matKey = $('mcK').value;
    if (!matKey) return;
    const m = materials[matKey];
    cf2(`حذف المادة "${m?.name||''}" نهائياً من الكتالوج؟`, async () => {
        try {
            await remove(ref(db, `ledger/materials/${matKey}`));
            cov('mMatCat');
            toast('🗑️ تم الحذف', 'ok');
        } catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

// عرض قائمة المواد في الكتالوج
window.renderMaterialsCatalog = function () {
    const container = $('matCatList'); if (!container) return;
    const search = ($('matSearch')?.value || '').toLowerCase();
    const catF = $('matCategoryFilter')?.value || '';
    let items = Object.entries(materials);
    if (search) items = items.filter(([, m]) => (m.name||'').toLowerCase().includes(search) || (m.sku||'').toLowerCase().includes(search) || (m.brand||'').toLowerCase().includes(search));
    if (catF) items = items.filter(([, m]) => m.category === catF);
    items.sort((a, b) => (a[1].name||'').localeCompare(b[1].name||'', 'ar'));

    if (!items.length) {
        container.innerHTML = '<div class="empty"><div class="ei">📦</div><p>لا توجد مواد في الكتالوج — أضف مادة جديدة</p></div>';
        return;
    }

    container.innerHTML = `<div style="display:grid;gap:10px;grid-template-columns:repeat(auto-fill,minmax(340px,1fr));margin-top:10px">${items.map(([mk, m]) => {
        const suppliers = m.suppliers ? Object.values(m.suppliers) : [];
        const prices = suppliers.map(s => s.price).filter(p => p > 0);
        const minPrice = prices.length ? Math.min(...prices) : 0;
        const maxPrice = prices.length ? Math.max(...prices) : 0;
        const avgPrice = prices.length ? prices.reduce((s, p) => s + p, 0) / prices.length : (m.unitCost || 0);
        const preferred = suppliers.find(s => s.isPreferred);
        return `<div style="background:white;border:1.5px solid #e0e8f0;border-radius:12px;padding:14px;border-right:4px solid #2d6a9f">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;margin-bottom:8px">
                <div style="flex:1;min-width:0">
                    <div style="font-size:14px;font-weight:800;color:#1a3a5c">${esc(m.name)}</div>
                    <div style="font-size:11px;color:#888;margin-top:2px">
                        ${m.sku ? `<span style="background:#f0f5fa;padding:2px 8px;border-radius:6px;margin-left:4px">${esc(m.sku)}</span>` : ''}
                        <span style="background:#f0f5fa;padding:2px 8px;border-radius:6px">${esc(MAT_CATEGORIES[m.category]||m.category||'-')}</span>
                    </div>
                    ${m.brand ? `<div style="font-size:11px;color:#666;margin-top:3px">🏷️ ${esc(m.brand)}</div>` : ''}
                </div>
                <button class="btn b-b" style="padding:4px 10px;font-size:11px" onclick="openMatCatalog('${mk}')">✏️</button>
            </div>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;background:#f8fafc;border-radius:8px;padding:10px;margin-top:8px">
                <div style="text-align:center;border-left:1px solid #e0e8f0">
                    <div style="font-size:10px;color:#888">الوحدة</div>
                    <div style="font-size:13px;font-weight:700;color:#1a3a5c">${esc(m.unit)||'-'}</div>
                </div>
                <div style="text-align:center">
                    <div style="font-size:10px;color:#888">الموردون</div>
                    <div style="font-size:13px;font-weight:700;color:#1a3a5c">${suppliers.length}</div>
                </div>
            </div>
            ${prices.length ? `<div style="margin-top:8px;padding:8px;background:linear-gradient(135deg,#e8f5e9,#fff);border-radius:8px;border:1px solid #d5f5e3">
                <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:4px;text-align:center;font-size:11px">
                    <div><div style="color:#666">أدنى</div><div style="font-weight:800;color:#27ae60">${fmt(minPrice)}</div></div>
                    <div><div style="color:#666">المتوسط</div><div style="font-weight:800;color:#2d6a9f">${fmt(avgPrice)}</div></div>
                    <div><div style="color:#666">أعلى</div><div style="font-weight:800;color:#e74c3c">${fmt(maxPrice)}</div></div>
                </div>
            </div>` : ''}
            ${preferred ? `<div style="margin-top:6px;font-size:11px;color:#7d4e00"><strong>⭐ المفضل:</strong> ${esc(preferred.supplierName)} (${fmt(preferred.price)} ر)</div>` : ''}
        </div>`;
    }).join('')}</div>`;
};

// KPIs المواد
function updateMaterialsKPIs() {
    const items = Object.values(materials);
    $('mck1') && ($('mck1').textContent = items.length);
    const cats = new Set(items.map(m => m.category).filter(Boolean));
    $('mck2') && ($('mck2').textContent = cats.size);
    const withSup = items.filter(m => m.suppliers && Object.keys(m.suppliers).length > 0).length;
    $('mck3') && ($('mck3').textContent = withSup);
    const allPrices = [];
    items.forEach(m => {
        if (m.suppliers) Object.values(m.suppliers).forEach(s => { if (s.price > 0) allPrices.push(s.price) });
    });
    const avg = allPrices.length ? allPrices.reduce((s, p) => s + p, 0) / allPrices.length : 0;
    $('mck4') && ($('mck4').textContent = fmt(avg));
}

