const VENDOR_CATEGORIES = {
    general: '📦 عام', concrete: '🏗️ خرسانة', steel: '🔩 حديد', cement: '🧱 إسمنت',
    electric: '⚡ كهرباء', plumbing: '🚿 سباكة', finishing: '🎨 تشطيبات', paint: '🖌️ دهانات',
    ceramic: '🧱 سيراميك', wood: '🪵 أخشاب', hvac: '❄️ تكييف', equipment: '🚜 معدات', services: '🔧 خدمات'
};

const VENDOR_STATUS = {
    new: { label: '🆕 جديد', color: '#3498db', bg: '#ebf5fb' },
    approved: { label: '⭐ معتمد', color: '#27ae60', bg: '#e8f8f5' },
    suspended: { label: '🚫 موقوف', color: '#e67e22', bg: '#fef5e7' },
    blacklisted: { label: '⚠️ قائمة سوداء', color: '#c0392b', bg: '#fadbd8' }
};

// التبويبات داخل مودال الموردين
window.vendTab = function (tabId, btn) {
    document.querySelectorAll('#mVendCat .pt-pane').forEach(p => p.classList.remove('act'));
    document.querySelectorAll('#mVendCat .pt-btn').forEach(b => b.classList.remove('act'));
    $(tabId)?.classList.add('act');
    btn?.classList.add('act');
};

// تحديث التقييم الإجمالي للمورد
window.updateVendorOverallRating = function () {
    const q = parseFloat($('vcRateQuality').value) || 5;
    const d = parseFloat($('vcRateDelivery').value) || 5;
    const p = parseFloat($('vcRatePrice').value) || 5;
    const s = parseFloat($('vcRateService').value) || 5;
    const avg = (q + d + p + s) / 4;
    const box = $('vcOverallRating');
    if (box) {
        const color = avg >= 8 ? '#27ae60' : avg >= 6 ? '#2d6a9f' : avg >= 4 ? '#f39c12' : '#c0392b';
        box.innerHTML = `
            <div style="font-size:11px;color:#666;margin-bottom:4px">التقييم الإجمالي</div>
            <div style="font-size:32px;font-weight:900;color:${color};line-height:1">${avg.toFixed(1)}</div>
            <div style="font-size:11px;color:#666;margin-top:4px">من 10</div>
        `;
    }
};

// فتح مودال مورد
window.openVendorCatalog = function (vendKey = null) {
    $('vcK').value = vendKey || '';
    $('mVendCatT').textContent = vendKey ? '✏️ تعديل مورد' : '🏭 إضافة مورد للكتالوج';
    $('vcDelBtn').style.display = vendKey ? '' : 'none';
    // Reset to first tab
    document.querySelectorAll('#mVendCat .pt-pane').forEach(p => p.classList.remove('act'));
    document.querySelectorAll('#mVendCat .pt-btn').forEach(b => b.classList.remove('act'));
    $('vt1')?.classList.add('act');
    document.querySelectorAll('#mVendCat .pt-btn')[0]?.classList.add('act');

    if (vendKey && sup[vendKey]) {
        const v = sup[vendKey];
        // Basic
        $('vcName').value = v.name || '';
        $('vcCode').value = v.code || '';
        $('vcType').value = v.type || 'company';
        $('vcStatus').value = v.status || 'new';
        $('vcContactPerson').value = v.contactPerson || '';
        $('vcContactRole').value = v.contactRole || '';
        $('vcPhone').value = v.phone || '';
        $('vcPhone2').value = v.phone2 || '';
        $('vcEmail').value = v.email || '';
        $('vcWebsite').value = v.website || '';
        $('vcAddress').value = v.address || '';
        // Legal
        $('vcCR').value = v.cr || '';
        $('vcCRExpiry').value = v.crExpiry || '';
        $('vcVAT').value = v.vat || '';
        $('vcLicense').value = v.license || '';
        $('vcLicenseExpiry').value = v.licenseExpiry || '';
        $('vcZakat').value = v.zakat || '';
        $('vcGosi').value = v.gosi || '';
        // Commercial
        $('vcPaymentMethod').value = v.paymentMethod || '';
        $('vcCreditDays').value = v.creditDays || 0;
        $('vcCreditLimit').value = v.creditLimit || 0;
        $('vcCurrency').value = v.currency || 'SAR';
        $('vcIban').value = v.iban || '';
        $('vcBank').value = v.bank || '';
        $('vcNotes').value = v.notes || '';
        // Categories
        const sel = $('vcCategories');
        if (sel) {
            Array.from(sel.options).forEach(o => o.selected = false);
            (v.categories || []).forEach(c => {
                const opt = Array.from(sel.options).find(o => o.value === c);
                if (opt) opt.selected = true;
            });
        }
        // Rating
        $('vcRateQuality').value = v.rating?.quality || 5;
        $('vcRateDelivery').value = v.rating?.delivery || 5;
        $('vcRatePrice').value = v.rating?.price || 5;
        $('vcRateService').value = v.rating?.service || 5;
        $('vcRateQualityVal').textContent = $('vcRateQuality').value;
        $('vcRateDeliveryVal').textContent = $('vcRateDelivery').value;
        $('vcRatePriceVal').textContent = $('vcRatePrice').value;
        $('vcRateServiceVal').textContent = $('vcRateService').value;
        $('vcRatingNotes').value = v.ratingNotes || '';
        updateVendorOverallRating();
    } else {
        // Reset all fields
        ['vcName','vcCode','vcContactPerson','vcContactRole','vcPhone','vcPhone2','vcEmail','vcWebsite','vcAddress',
         'vcCR','vcCRExpiry','vcVAT','vcLicense','vcLicenseExpiry','vcIban','vcBank','vcNotes','vcRatingNotes'].forEach(id => $(id) && ($(id).value = ''));
        $('vcType').value = 'company';
        $('vcStatus').value = 'new';
        $('vcZakat').value = '';
        $('vcGosi').value = '';
        $('vcPaymentMethod').value = '';
        $('vcCreditDays').value = 0;
        $('vcCreditLimit').value = 0;
        $('vcCurrency').value = 'SAR';
        const catSel = $('vcCategories');
        if (catSel) Array.from(catSel.options).forEach(o => o.selected = false);
        ['vcRateQuality','vcRateDelivery','vcRatePrice','vcRateService'].forEach(id => $(id).value = 5);
        ['vcRateQualityVal','vcRateDeliveryVal','vcRatePriceVal','vcRateServiceVal'].forEach(id => $(id).textContent = 5);
        updateVendorOverallRating();
    }
    ov('mVendCat');
};

// حفظ المورد
window.saveVendorCatalog = async function () {
    const name = $('vcName').value.trim();
    const phone = $('vcPhone').value.trim();
    if (!name) { toast('اسم المورد مطلوب', 'er'); $('vcName').focus(); return }
    if (!phone) { toast('رقم الجوال مطلوب', 'er'); vendTab('vt1', document.querySelector('#mVendCat .pt-btn')); $('vcPhone').focus(); return }

    const vendKey = $('vcK').value;
    // Categories
    const catSel = $('vcCategories');
    const categories = catSel ? Array.from(catSel.selectedOptions).map(o => o.value) : [];

    // Rating
    const q = parseFloat($('vcRateQuality').value) || 5;
    const d = parseFloat($('vcRateDelivery').value) || 5;
    const p = parseFloat($('vcRatePrice').value) || 5;
    const s = parseFloat($('vcRateService').value) || 5;
    const avgRating = parseFloat(((q + d + p + s) / 4).toFixed(2));

    const data = {
        name,
        code: $('vcCode').value.trim(),
        type: $('vcType').value,
        status: $('vcStatus').value,
        contactPerson: $('vcContactPerson').value.trim(),
        contactRole: $('vcContactRole').value.trim(),
        phone, phone2: $('vcPhone2').value.trim(),
        email: $('vcEmail').value.trim(),
        website: $('vcWebsite').value.trim(),
        address: $('vcAddress').value.trim(),
        // Legal
        cr: $('vcCR').value.trim(),
        crExpiry: $('vcCRExpiry').value,
        vat: $('vcVAT').value.trim(),
        license: $('vcLicense').value.trim(),
        licenseExpiry: $('vcLicenseExpiry').value,
        zakat: $('vcZakat').value,
        gosi: $('vcGosi').value,
        // Commercial
        categories,
        paymentMethod: $('vcPaymentMethod').value,
        creditDays: parseInt($('vcCreditDays').value) || 0,
        creditLimit: parseFloat($('vcCreditLimit').value) || 0,
        currency: $('vcCurrency').value,
        iban: $('vcIban').value.trim(),
        bank: $('vcBank').value.trim(),
        notes: $('vcNotes').value.trim(),
        // Rating
        rating: { quality: q, delivery: d, price: p, service: s, overall: avgRating },
        ratingNotes: $('vcRatingNotes').value.trim(),
        updatedAt: new Date().toISOString()
    };
    try {
        if (vendKey) {
            await update(ref(db, `ledger/suppliers/${vendKey}`), data);
            toast('✅ تم تحديث المورد', 'ok');
        } else {
            data.createdAt = new Date().toISOString();
            data.createdBy = myP?.name || '';
            await push(R.sup, data);
            toast('✅ تم إضافة المورد للكتالوج', 'ok');
        }
        cov('mVendCat');
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// حذف مورد
window.deleteVendorCatalog = function () {
    const vendKey = $('vcK').value;
    if (!vendKey) return;
    const v = sup[vendKey];
    cf2(`حذف المورد "${v?.name||''}" نهائياً؟`, async () => {
        try {
            await remove(ref(db, `ledger/suppliers/${vendKey}`));
            cov('mVendCat');
            toast('🗑️ تم الحذف', 'ok');
        } catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

// عرض كتالوج الموردين
window.renderVendorsCatalog = function () {
    const container = $('vendCatList'); if (!container) return;
    const search = ($('vendSearch')?.value || '').toLowerCase();
    const catF = $('vendCategoryFilter')?.value || '';
    const statusF = $('vendStatusFilter')?.value || '';
    let items = Object.entries(sup);
    if (search) items = items.filter(([, v]) => (v.name||'').toLowerCase().includes(search) || (v.code||'').toLowerCase().includes(search) || (v.contactPerson||'').toLowerCase().includes(search));
    if (catF) items = items.filter(([, v]) => (v.categories || []).includes(catF));
    if (statusF) items = items.filter(([, v]) => (v.status || 'new') === statusF);
    items.sort((a, b) => (a[1].name||'').localeCompare(b[1].name||'', 'ar'));

    if (!items.length) {
        container.innerHTML = '<div class="empty"><div class="ei">🏭</div><p>لا يوجد موردون يطابقون الفلتر</p></div>';
        return;
    }

    container.innerHTML = `<div style="display:grid;gap:12px;grid-template-columns:repeat(auto-fill,minmax(380px,1fr));margin-top:10px">${items.map(([vk, v]) => {
        const status = VENDOR_STATUS[v.status || 'new'];
        const overall = v.rating?.overall || 0;
        const ratingColor = overall >= 8 ? '#27ae60' : overall >= 6 ? '#2d6a9f' : overall >= 4 ? '#f39c12' : overall > 0 ? '#c0392b' : '#999';
        const catBadges = (v.categories || []).slice(0, 4).map(c =>
            `<span style="background:#f0f5fa;color:#1a3a5c;padding:2px 8px;border-radius:6px;font-size:10px;font-weight:600;margin-left:4px">${esc(VENDOR_CATEGORIES[c]||c)}</span>`
        ).join('');
        return `<div style="background:white;border:1.5px solid #e0e8f0;border-radius:12px;padding:14px;border-right:4px solid ${status.color}">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;margin-bottom:10px">
                <div style="flex:1;min-width:0">
                    <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;margin-bottom:4px">
                        <span style="font-size:14px;font-weight:800;color:#1a3a5c">${esc(v.name)}</span>
                        <span style="background:${status.bg};color:${status.color};padding:2px 8px;border-radius:8px;font-size:10px;font-weight:700">${esc(status.label)}</span>
                    </div>
                    ${v.code ? `<div style="font-size:10px;color:#888">كود: ${esc(v.code)}</div>` : ''}
                    ${v.contactPerson ? `<div style="font-size:11px;color:#555;margin-top:4px">👤 ${esc(v.contactPerson)}${v.contactRole?' — '+esc(v.contactRole):''}</div>` : ''}
                    <div style="font-size:11px;color:#555;margin-top:2px">📞 ${esc(v.phone)||'-'}${v.email?' · '+esc(v.email):''}</div>
                    ${catBadges ? `<div style="margin-top:6px">${catBadges}${v.categories?.length > 4 ? `<span style="font-size:10px;color:#888">+${v.categories.length-4}</span>` : ''}</div>` : ''}
                </div>
                ${overall > 0 ? `<div style="text-align:center;background:#f8fafc;border-radius:8px;padding:6px 10px;min-width:54px">
                    <div style="font-size:9px;color:#888">تقييم</div>
                    <div style="font-size:18px;font-weight:900;color:${ratingColor}">${overall.toFixed(1)}</div>
                </div>` : ''}
            </div>
            <div style="background:#f8fafc;border-radius:8px;padding:8px;display:grid;grid-template-columns:1fr 1fr 1fr;gap:4px;text-align:center;font-size:11px;margin-top:8px">
                <div><div style="color:#888">السجل</div><div style="font-weight:700;color:${v.cr?'#27ae60':'#999'}">${v.cr?'✅':'—'}</div></div>
                <div style="border-right:1px solid #e0e8f0;border-left:1px solid #e0e8f0"><div style="color:#888">ضريبي</div><div style="font-weight:700;color:${v.vat?'#27ae60':'#999'}">${v.vat?'✅':'—'}</div></div>
                <div><div style="color:#888">أجل</div><div style="font-weight:700;color:#1a3a5c">${v.creditDays||0}ي</div></div>
            </div>
            <div style="display:flex;gap:6px;margin-top:10px">
                <button class="btn b-b" style="flex:1;padding:5px 10px;font-size:11px" onclick="openVendorCatalog('${vk}')">✏️ تعديل / تفاصيل</button>
            </div>
        </div>`;
    }).join('')}</div>`;
};

// KPIs الموردين
function updateVendorsKPIs() {
    const items = Object.values(sup);
    $('vck1') && ($('vck1').textContent = items.length);
    $('vck2') && ($('vck2').textContent = items.filter(v => v.status === 'approved').length);
    $('vck3') && ($('vck3').textContent = items.filter(v => (v.status || 'new') === 'new').length);
    $('vck4') && ($('vck4').textContent = items.filter(v => v.status === 'suspended' || v.status === 'blacklisted').length);
}

