const MR_STATUS = {
    draft: { label: '📝 مسودة', color: '#7f8c8d', bg: '#ecf0f1' },
    submitted: { label: '📤 قيد المراجعة', color: '#f39c12', bg: '#fef9e7' },
    pm_approved: { label: '✅ معتمد من مدير المشروع', color: '#27ae60', bg: '#e8f8f5' },
    forwarded_purchasing: { label: '📦 محوّل للمشتريات', color: '#9b59b6', bg: '#f4ecf7' },
    quotations: { label: '💼 يجمع عروض الأسعار', color: '#8e44ad', bg: '#f4ecf7' },
    po_pending: { label: '⏳ بانتظار اعتماد أمر الشراء', color: '#e67e22', bg: '#fef5e7' },
    po_issued: { label: '📄 صدر أمر شراء', color: '#2d6a9f', bg: '#ebf5fb' },
    received: { label: '📥 تم الاستلام', color: '#1e8449', bg: '#d5f5e3' },
    rejected: { label: '❌ مرفوض', color: '#c0392b', bg: '#fadbd8' },
    cancelled: { label: '🚫 ملغى', color: '#7f8c8d', bg: '#ecf0f1' }
};

const MR_URGENCY = {
    urgent: { label: '🔴 عاجل', color: '#c0392b' },
    normal: { label: '🟡 عادي', color: '#f39c12' },
    low: { label: '🟢 غير عاجل', color: '#27ae60' }
};

// ── تعبئة قائمة المشاريع في فلتر الطلبات
function fillMrProjectFilter() {
    const sel = $('mrProjectFilter'); if (!sel) return;
    const cur = sel.value;
    sel.innerHTML = '<option value="">-- جميع المشاريع --</option>';
    Object.entries(projects).sort((a, b) => (a[1].name||'').localeCompare(b[1].name||'', 'ar'))
        .forEach(([k, p]) => sel.innerHTML += `<option value="${k}">${p.name}</option>`);
    if (cur) sel.value = cur;
}

// ── State للمواد المختارة في الطلب الحالي
let mrSelectedItems = {}; // { matBudgetKey: { matName, unit, plannedQty, estPrice, qty, note } }

// ── فتح مودال الطلب
window.openMatRequestM = function (reqKey = null) {
    if (myP?.role !== 'admin' && !can('request_material') && !can('approve_material_request')) {
        toast('ليس لديك صلاحية لإنشاء طلبات', 'er'); return;
    }
    $('mrK').value = reqKey || '';
    $('mMatReqT').textContent = reqKey ? '✏️ تعديل طلب مواد' : '📨 طلب مواد جديد';
    $('mrDelBtn').style.display = reqKey ? '' : 'none';
    mrSelectedItems = {};

    // ملء قائمة المشاريع
    const prjSel = $('mrProject');
    prjSel.innerHTML = '<option value="">-- اختر المشروع --</option>';
    // إذا المهندس مرتبط بمشروع، فلتر المشاريع
    const myEmp = findCurrentEmpRecord();
    const isAdmin = myP?.role === 'admin';
    let availableProjects = Object.entries(projects)
        .filter(([, p]) => ['active', 'planning', 'awarded'].includes(p.status));
    // إذا الموظف مرتبط بمشروع، اعرضه افتراضياً
    if (!isAdmin && myEmp?.data?.affiliationType === 'project' && myEmp.data.projectId) {
        availableProjects = availableProjects.filter(([k]) => k === myEmp.data.projectId);
    }
    availableProjects
        .sort((a, b) => (a[1].name||'').localeCompare(b[1].name||'', 'ar'))
        .forEach(([k, p]) => prjSel.innerHTML += `<option value="${k}">${p.name}${p.code?' ('+p.code+')':''}</option>`);

    if (reqKey && matRequests[reqKey]) {
        const r = matRequests[reqKey];
        $('mrProject').value = r.projectId || '';
        $('mrUrgency').value = r.urgency || 'normal';
        $('mrNeededDate').value = r.neededDate || '';
        $('mrDeliveryLocation').value = r.deliveryLocation || '';
        $('mrReason').value = r.reason || '';
        // أعد بناء المواد المختارة
        if (r.items) {
            Object.entries(r.items).forEach(([k, item]) => {
                mrSelectedItems[item.matBudgetKey || k] = {
                    matBudgetKey: item.matBudgetKey || k,
                    matName: item.matName,
                    matCategory: item.matCategory,
                    unit: item.unit,
                    plannedQty: item.plannedQty,
                    estPrice: item.estPrice,
                    qty: item.qty,
                    note: item.note
                };
            });
        }
        loadProjectBudgetMaterials();
    } else {
        $('mrUrgency').value = 'normal';
        $('mrNeededDate').value = today();
        $('mrDeliveryLocation').value = '';
        $('mrReason').value = '';
        // إذا الموظف مرتبط بمشروع واحد فقط، اختره تلقائياً
        if (availableProjects.length === 1) {
            $('mrProject').value = availableProjects[0][0];
            loadProjectBudgetMaterials();
        } else {
            $('mrBudgetSection').style.display = 'none';
            $('mrSelectedSection').style.display = 'none';
            $('mrApprovalPreview').style.display = 'none';
            $('mrProjectInfo').innerHTML = '';
        }
    }
    ov('mMatReq');
};

// ── تحميل مواد المشروع من الميزانية
window.loadProjectBudgetMaterials = async function () {
    const pid = $('mrProject').value;
    const infoEl = $('mrProjectInfo');
    const section = $('mrBudgetSection');
    const selectedSec = $('mrSelectedSection');
    if (!pid || !projects[pid]) {
        section.style.display = 'none';
        selectedSec.style.display = 'none';
        $('mrApprovalPreview').style.display = 'none';
        if (infoEl) infoEl.innerHTML = '';
        return;
    }
    // ✅ قراءة مباشرة من Firebase لضمان الحصول على أحدث matBudget
    let project = projects[pid];
    try {
        const snap = await get(ref(db, `ledger/projects/${pid}`));
        if (snap.exists()) {
            project = snap.val();
            // حدّث state المحلي
            projects[pid] = project;
        }
    } catch (e) {
        console.warn('Failed to fetch latest project, using cached:', e);
    }
    const matBudget = (project.matBudget && typeof project.matBudget === 'object') ? project.matBudget : {};
    const budgetCount = Object.keys(matBudget).length;
    const limits = project.approvalLimits || { projectManager: 5000, purchasing: 20000, operations: 50000 };

    // عرض معلومات المشروع
    infoEl.innerHTML = `📊 ميزانية المواد: <strong>${budgetCount}</strong> مادة | حد مدير المشروع: <strong>${fmt(limits.projectManager)} ر</strong>`;

    if (budgetCount === 0) {
        section.style.display = 'block';
        $('mrBudgetMatList').innerHTML = `<div style="padding:30px;text-align:center;color:#999">
            <div style="font-size:28px;margin-bottom:8px">📦</div>
            <p style="font-size:13px">لا توجد مواد في ميزانية هذا المشروع</p>
            <p style="font-size:11px;color:#888;margin-top:6px">مدير المشروع بحاجة لإضافة المواد المتوقعة من تبويب "ميزانية المواد" في المشروع</p>
        </div>`;
        selectedSec.style.display = 'none';
        return;
    }

    // ملء فلتر التصنيف
    const catFilter = $('mrMatCategoryFilter');
    const cats = [...new Set(Object.values(matBudget).map(m => m.category).filter(Boolean))];
    catFilter.innerHTML = '<option value="">الكل</option>' +
        cats.map(c => `<option value="${c}">${MAT_CATEGORIES[c]||c}</option>`).join('');

    section.style.display = 'block';
    renderProjectBudgetMaterials();
    renderSelectedItems();
};

// ── عرض مواد الميزانية للاختيار
window.renderProjectBudgetMaterials = function () {
    const pid = $('mrProject').value; if (!pid) return;
    const project = projects[pid];
    const matBudget = (project?.matBudget && typeof project.matBudget === 'object') ? project.matBudget : {};
    const container = $('mrBudgetMatList');
    const search = ($('mrMatSearch')?.value || '').toLowerCase();
    const catF = $('mrMatCategoryFilter')?.value || '';

    // احسب الكميات المطلوبة سابقاً لكل مادة في الميزانية (من الطلبات السابقة)
    const previouslyRequested = {};
    Object.values(matRequests || {}).forEach(r => {
        if (r.projectId !== pid || ['rejected','cancelled'].includes(r.status)) return;
        if (r.items) {
            Object.values(r.items).forEach(it => {
                const key = it.matBudgetKey;
                if (key) previouslyRequested[key] = (previouslyRequested[key] || 0) + (parseFloat(it.qty) || 0);
            });
        }
    });

    let items = Object.entries(matBudget);
    if (search) items = items.filter(([, m]) => (m.name||'').toLowerCase().includes(search));
    if (catF) items = items.filter(([, m]) => m.category === catF);
    // ترتيب حسب التصنيف ثم الاسم
    items.sort((a, b) => {
        const c = (a[1].category||'').localeCompare(b[1].category||'');
        if (c !== 0) return c;
        return (a[1].name||'').localeCompare(b[1].name||'', 'ar');
    });

    if (!items.length) {
        container.innerHTML = '<div style="padding:30px;text-align:center;color:#999;font-size:13px">لا توجد مواد تطابق الفلتر</div>';
        return;
    }

    container.innerHTML = `<table style="width:100%;border-collapse:collapse;font-size:12px">
        <thead style="background:#f0f5fa;position:sticky;top:0">
            <tr>
                <th style="padding:8px;text-align:right;border-bottom:2px solid #d5e3eb">المادة</th>
                <th style="padding:8px;text-align:center;border-bottom:2px solid #d5e3eb">التصنيف</th>
                <th style="padding:8px;text-align:center;border-bottom:2px solid #d5e3eb">الوحدة</th>
                <th style="padding:8px;text-align:center;border-bottom:2px solid #d5e3eb">المخططة</th>
                <th style="padding:8px;text-align:center;border-bottom:2px solid #d5e3eb">المطلوبة سابقاً</th>
                <th style="padding:8px;text-align:center;border-bottom:2px solid #d5e3eb">المتاحة</th>
                <th style="padding:8px;text-align:center;border-bottom:2px solid #d5e3eb">سعر متوقع</th>
                <th style="padding:8px;text-align:center;border-bottom:2px solid #d5e3eb;width:120px">الكمية المطلوبة</th>
            </tr>
        </thead>
        <tbody>${items.map(([mk, m], i) => {
            const reqBefore = previouslyRequested[mk] || 0;
            const available = Math.max(0, (m.qty || 0) - reqBefore);
            const isSelected = !!mrSelectedItems[mk];
            const selQty = mrSelectedItems[mk]?.qty || '';
            const rowBg = isSelected ? 'background:#fff8e1' : (i%2 ? 'background:#fafbfc' : '');
            return `<tr style="${rowBg};border-bottom:1px solid #eef2f7">
                <td style="padding:7px"><strong>${m.name}</strong></td>
                <td style="padding:7px;text-align:center;font-size:10px">${MAT_CATEGORIES[m.category]||'-'}</td>
                <td style="padding:7px;text-align:center">${m.unit||'-'}</td>
                <td style="padding:7px;text-align:center;font-weight:600;color:#1a3a5c">${m.qty}</td>
                <td style="padding:7px;text-align:center;color:${reqBefore>0?'#e67e22':'#bbb'};font-weight:${reqBefore>0?'700':'400'}">${reqBefore || '—'}</td>
                <td style="padding:7px;text-align:center;font-weight:700;color:${available>0?'#27ae60':'#c0392b'}">${available}</td>
                <td style="padding:7px;text-align:center;color:#666">${fmt(m.unitPrice||0)}</td>
                <td style="padding:7px;text-align:center">
                    <input type="number" min="0" step="0.01" max="${available + (selQty||0)}" value="${selQty}" placeholder="0" data-mk="${mk}" 
                        onchange="updateSelectedItem('${mk}',this.value)"
                        style="width:90px;padding:5px 6px;border:1.5px solid ${isSelected?'#27ae60':'#d0d7e0'};border-radius:6px;font-size:12px;text-align:center;font-weight:${isSelected?'700':'400'}">
                </td>
            </tr>`;
        }).join('')}</tbody>
    </table>`;
};

// ── تحديث المادة المختارة
window.updateSelectedItem = function (mk, qtyStr) {
    const pid = $('mrProject').value;
    const matBudget = projects[pid]?.matBudget || {};
    const m = matBudget[mk]; if (!m) return;
    const qty = parseFloat(qtyStr) || 0;

    if (qty <= 0) {
        delete mrSelectedItems[mk];
    } else {
        // تحذير عند تجاوز المتاح (لكن نسمح)
        const previouslyRequested = Object.values(matRequests || {})
            .filter(r => r.projectId === pid && !['rejected','cancelled'].includes(r.status))
            .reduce((s, r) => {
                if (r.items) {
                    Object.values(r.items).forEach(it => {
                        if (it.matBudgetKey === mk) s += parseFloat(it.qty) || 0;
                    });
                }
                return s;
            }, 0);
        const available = Math.max(0, (m.qty || 0) - previouslyRequested);
        if (qty > available && !mrSelectedItems[mk]) {
            toast(`⚠️ الكمية المطلوبة (${qty}) تتجاوز المتاحة (${available}) — سيُرسل الطلب ولكن قد يحتاج موافقة خاصة`, 'wn', 5000);
        }
        mrSelectedItems[mk] = {
            matBudgetKey: mk,
            matName: m.name,
            matCategory: m.category,
            unit: m.unit,
            plannedQty: m.qty,
            estPrice: m.unitPrice,
            qty,
            note: ''
        };
    }
    renderSelectedItems();
    renderProjectBudgetMaterials(); // لتحديث الألوان
};

// ── عرض المواد المختارة
function renderSelectedItems() {
    const container = $('mrSelectedList');
    const section = $('mrSelectedSection');
    const summary = $('mrTotalSummary');
    const keys = Object.keys(mrSelectedItems);

    if (!keys.length) {
        section.style.display = 'none';
        $('mrApprovalPreview').style.display = 'none';
        return;
    }
    section.style.display = 'block';
    $('mrSelCount').textContent = keys.length;

    container.innerHTML = `<table style="width:100%;border-collapse:collapse;font-size:12px;background:white;border-radius:6px;overflow:hidden">
        <thead style="background:#fff3e0"><tr>
            <th style="padding:7px;text-align:right">المادة</th>
            <th style="padding:7px;text-align:center">الكمية</th>
            <th style="padding:7px;text-align:center">السعر</th>
            <th style="padding:7px;text-align:center">الإجمالي</th>
            <th style="padding:7px;text-align:right">ملاحظة</th>
            <th style="padding:7px;text-align:center"></th>
        </tr></thead>
        <tbody>${keys.map(mk => {
            const it = mrSelectedItems[mk];
            const total = (it.qty || 0) * (it.estPrice || 0);
            return `<tr style="border-bottom:1px solid #fef5e7">
                <td style="padding:7px"><strong>${it.matName}</strong></td>
                <td style="padding:7px;text-align:center;font-weight:700;color:#27ae60">${it.qty} ${it.unit||''}</td>
                <td style="padding:7px;text-align:center;color:#666">${fmt(it.estPrice||0)}</td>
                <td style="padding:7px;text-align:center;font-weight:800;color:#1a3a5c">${fmt(total)}</td>
                <td style="padding:7px">
                    <input type="text" placeholder="ملاحظة (اختيارية)" value="${it.note||''}" onchange="mrSelectedItems['${mk}'].note=this.value"
                        style="width:100%;padding:4px 8px;border:1px solid #ffe082;border-radius:4px;font-size:11px">
                </td>
                <td style="padding:7px;text-align:center">
                    <button class="btn b-r" style="padding:3px 8px;font-size:10px" onclick="removeMrItem('${mk}')">🗑️</button>
                </td>
            </tr>`;
        }).join('')}</tbody>
    </table>`;

    // ملخص
    const totItems = keys.length;
    const totValue = keys.reduce((s, k) => s + ((mrSelectedItems[k].qty || 0) * (mrSelectedItems[k].estPrice || 0)), 0);
    $('mrTotItems').textContent = totItems;
    $('mrTotValue').textContent = fmt(totValue);
    summary.style.display = 'block';

    // معاينة الموافقة
    renderApprovalPreview(totValue);
}

// ── إزالة مادة من المختارة
window.removeMrItem = function (mk) {
    delete mrSelectedItems[mk];
    renderSelectedItems();
    renderProjectBudgetMaterials();
};

// ── معاينة مسار الموافقة
function renderApprovalPreview(totalValue) {
    const pid = $('mrProject').value;
    if (!pid || totalValue <= 0) { $('mrApprovalPreview').style.display = 'none'; return }
    const project = projects[pid];
    if (!project?.approvalLimits) { $('mrApprovalPreview').style.display = 'none'; return }
    const limits = project.approvalLimits;
    const preview = $('mrApprovalSteps');
    let steps = '<div style="display:flex;flex-direction:column;gap:6px">';
    steps += '<div style="display:flex;align-items:center;gap:8px;padding:6px 10px;background:white;border-radius:6px"><span style="background:#27ae60;color:white;width:24px;height:24px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:11px">1</span><span style="font-size:11px;color:#1a3a5c;flex:1">🔧 المهندس بالموقع — يقدّم الطلب</span><span style="color:#27ae60;font-size:11px;font-weight:700">▶ أنت</span></div>';

    if (totalValue <= limits.projectManager) {
        steps += `<div style="display:flex;align-items:center;gap:8px;padding:6px 10px;background:#e8f8f5;border-radius:6px"><span style="background:#27ae60;color:white;width:24px;height:24px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:11px">2</span><span style="font-size:11px;color:#1a3a5c;flex:1">📋 مدير المشروع — يعتمد مباشرة (≤ ${fmt(limits.projectManager)})</span><span style="color:#27ae60;font-size:11px;font-weight:700">✅ نهائي</span></div>`;
    } else {
        steps += `<div style="display:flex;align-items:center;gap:8px;padding:6px 10px;background:#fef5e7;border-radius:6px"><span style="background:#e67e22;color:white;width:24px;height:24px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:11px">2</span><span style="font-size:11px;color:#1a3a5c;flex:1">📋 مدير المشروع — يراجع ويحوّل (تجاوز ${fmt(limits.projectManager)})</span></div>`;
        steps += `<div style="display:flex;align-items:center;gap:8px;padding:6px 10px;background:#f4ecf7;border-radius:6px"><span style="background:#9b59b6;color:white;width:24px;height:24px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:11px">3</span><span style="font-size:11px;color:#1a3a5c;flex:1">🛒 المشتريات — يطلب عروض الأسعار</span></div>`;
        if (totalValue <= limits.purchasing) {
            steps += `<div style="display:flex;align-items:center;gap:8px;padding:6px 10px;background:#e8f8f5;border-radius:6px"><span style="background:#27ae60;color:white;width:24px;height:24px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:11px">4</span><span style="font-size:11px;color:#1a3a5c;flex:1">🛒 المشتريات — تعتمد (≤ ${fmt(limits.purchasing)})</span><span style="color:#27ae60;font-size:11px;font-weight:700">✅ نهائي</span></div>`;
        } else if (totalValue <= limits.operations) {
            steps += `<div style="display:flex;align-items:center;gap:8px;padding:6px 10px;background:#fef9e7;border-radius:6px"><span style="background:#f39c12;color:white;width:24px;height:24px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:11px">4</span><span style="font-size:11px;color:#1a3a5c;flex:1">👔 مدير العمليات — يعتمد (≤ ${fmt(limits.operations)})</span><span style="color:#27ae60;font-size:11px;font-weight:700">✅ نهائي</span></div>`;
        } else {
            steps += `<div style="display:flex;align-items:center;gap:8px;padding:6px 10px;background:#fadbd8;border-radius:6px"><span style="background:#c0392b;color:white;width:24px;height:24px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:11px">4</span><span style="font-size:11px;color:#1a3a5c;flex:1">👑 المدير التنفيذي — اعتماد نهائي (تجاوز ${fmt(limits.operations)})</span><span style="color:#27ae60;font-size:11px;font-weight:700">✅ نهائي</span></div>`;
        }
    }
    steps += '</div>';
    preview.innerHTML = steps;
    $('mrApprovalPreview').style.display = 'block';
}

// ── حفظ الطلب
window.saveMatRequest = async function (status = 'submitted') {
    const projectId = $('mrProject').value;
    if (!projectId) { toast('اختر المشروع', 'er'); return }
    const itemKeys = Object.keys(mrSelectedItems);
    if (!itemKeys.length) { toast('اختر مادة واحدة على الأقل', 'er'); return }
    // تحقق من الكميات
    const invalidItems = itemKeys.filter(k => !(mrSelectedItems[k].qty > 0));
    if (invalidItems.length) { toast('أدخل كميات صحيحة لكل المواد المختارة', 'er'); return }
    if (status === 'submitted' && !$('mrNeededDate').value) { toast('أدخل تاريخ الحاجة', 'er'); return }

    const reqKey = $('mrK').value;
    const project = projects[projectId];
    const limits = project.approvalLimits || { projectManager: 5000, purchasing: 20000, operations: 50000 };

    // احسب الإجمالي
    const items = {};
    let estTotal = 0;
    itemKeys.forEach(mk => {
        const it = mrSelectedItems[mk];
        const itemTotal = (it.qty || 0) * (it.estPrice || 0);
        estTotal += itemTotal;
        items[mk] = { ...it, total: itemTotal };
    });

    const needsPurchasing = estTotal > limits.projectManager;

    const data = {
        projectId, projectName: project?.name || '',
        items, itemsCount: itemKeys.length,
        estTotal,
        urgency: $('mrUrgency').value,
        neededDate: $('mrNeededDate').value,
        deliveryLocation: $('mrDeliveryLocation').value.trim(),
        reason: $('mrReason').value.trim(),
        status,
        approvalLimits: limits,
        needsPurchasing,
        history: [],
        updatedAt: new Date().toISOString()
    };

    try {
        if (reqKey) {
            const existing = matRequests[reqKey];
            data.history = existing.history || [];
            data.requestedBy = existing.requestedBy;
            data.requestedByName = existing.requestedByName;
            data.requestedAt = existing.requestedAt;
            data.reqNumber = existing.reqNumber;
            if (status === 'submitted' && existing.status === 'draft') {
                data.history.push({ action: 'submitted', actor: myP?.name || '', at: new Date().toISOString(), note: 'تم إرسال الطلب للمراجعة' });
            }
            await update(ref(db, `ledger/materialRequests/${reqKey}`), data);
            toast('✅ تم تحديث الطلب', 'ok');
        } else {
            const reqCount = Object.keys(matRequests).length + 1;
            data.reqNumber = 'MR-' + new Date().getFullYear() + '-' + String(reqCount).padStart(4, '0');
            data.requestedBy = curU?.uid || '';
            data.requestedByName = myP?.name || '';
            data.requestedAt = new Date().toISOString();
            data.createdAt = new Date().toISOString();
            data.history.push({
                action: status === 'submitted' ? 'submitted' : 'created',
                actor: myP?.name || '', at: new Date().toISOString(),
                note: status === 'submitted' ? `تم إنشاء وإرسال طلب يضم ${itemKeys.length} مادة بقيمة ${fmt(estTotal)} ر` : 'تم إنشاء الطلب كمسودة'
            });
            await push(R.mreq, data);
            toast(status === 'submitted' ? `✅ تم إرسال طلب بـ ${itemKeys.length} مادة` : '💾 تم حفظ المسودة', 'ok');
            if (typeof logAudit === 'function') logAudit(status === 'submitted' ? 'إرسال' : 'حفظ مسودة', 'طلبات المواد', `${data.reqNumber} — ${project?.name || ''} — ${itemKeys.length} مادة بقيمة ${fmt(estTotal)} ر`);
        }
        cov('mMatReq');
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// ── حذف طلب
window.deleteMatRequest = function () {
    const reqKey = $('mrK').value; if (!reqKey) return;
    const r = matRequests[reqKey];
    if (r.status !== 'draft' && r.status !== 'submitted') {
        toast('لا يمكن حذف طلب في هذه المرحلة - يمكن إلغاؤه فقط', 'er'); return;
    }
    cf2(`حذف الطلب ${r.reqNumber}؟`, async () => {
        try {
            await remove(ref(db, `ledger/materialRequests/${reqKey}`));
            cov('mMatReq');
            toast('🗑️ تم الحذف', 'ok');
            if (typeof logAudit === 'function') logAudit('حذف', 'طلبات المواد', `حذف طلب المواد ${r.reqNumber}`);
        } catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

// ── عرض قائمة الطلبات
window.renderMatRequests = function () {
    const container = $('mrList'); if (!container) return;
    const pf = $('mrProjectFilter')?.value || '';
    const sf = $('mrStatusFilter')?.value || '';
    const uf = $('mrUrgencyFilter')?.value || '';
    let items = Object.entries(matRequests);
    if (pf) items = items.filter(([, r]) => r.projectId === pf);
    // ✅ بدون فلتر حالة: أخفِ الملغاة والمرفوضة افتراضياً (لا تشغل المساحة)
    // مع فلتر حالة محدد: اعرض ما اختاره فقط
    if (sf) items = items.filter(([, r]) => r.status === sf);
    else items = items.filter(([, r]) => r.status !== 'cancelled' && r.status !== 'rejected');
    if (uf) items = items.filter(([, r]) => r.urgency === uf);
    // ترتيب: العاجل أولاً، ثم الأقدم في الانتظار
    items.sort((a, b) => {
        const urgencyOrder = { urgent: 0, normal: 1, low: 2 };
        const uo = (urgencyOrder[a[1].urgency] || 1) - (urgencyOrder[b[1].urgency] || 1);
        if (uo !== 0) return uo;
        return (b[1].requestedAt || '').localeCompare(a[1].requestedAt || '');
    });

    // عدد الطلبات المُلغاة/المرفوضة المخفية
    const hiddenCount = !sf ? Object.values(matRequests).filter(r => r.status === 'cancelled' || r.status === 'rejected').length : 0;

    if (!items.length) {
        container.innerHTML = `<div class="empty"><div class="ei">📨</div><p>لا توجد طلبات نشطة</p>${hiddenCount?`<p style="font-size:12px;color:#888;margin-top:8px">يوجد ${hiddenCount} طلب ملغى/مرفوض — اختر "مرفوض" أو "ملغى" من فلتر الحالة لعرضها</p>`:''}</div>`;
        return;
    }

    const isAdmin = myP?.role === 'admin';
    const canApprove = isAdmin || can('approve_material_request');
    const canManageQuotations = isAdmin || can('manage_quotations');

    const hiddenBanner = hiddenCount > 0 ? `<div style="background:#fef9e7;border:1.5px solid #f9e79f;border-radius:8px;padding:8px 14px;margin-top:10px;font-size:12px;color:#7d4e00">ℹ️ يوجد <strong>${hiddenCount}</strong> طلب ملغى/مرفوض مخفي — اختر "مرفوض" أو "ملغى" من فلتر الحالة لعرضها</div>` : '';

    container.innerHTML = hiddenBanner + `<div style="display:grid;gap:10px;margin-top:10px">${items.map(([rk, r]) => {
        const status = MR_STATUS[r.status] || MR_STATUS.draft;
        const urgency = MR_URGENCY[r.urgency] || MR_URGENCY.normal;
        const needsAttention = (r.status === 'submitted' && canApprove) || (r.status === 'forwarded_purchasing' && canManageQuotations);
        const reqItems = r.items ? Object.entries(r.items) : [];
        const itemCount = reqItems.length || (r.materialId ? 1 : 0);

        // عرض المواد - دعم البنية القديمة (مادة واحدة) والجديدة (متعددة)
        let itemsHtml = '';
        if (reqItems.length > 0) {
            itemsHtml = `<div style="background:#f8fafc;border-radius:6px;padding:8px;margin-bottom:8px">
                <details ${reqItems.length <= 3 ? 'open' : ''}>
                    <summary style="cursor:pointer;font-size:12px;color:#1a3a5c;font-weight:700;margin-bottom:6px">
                        📋 المواد المطلوبة (${reqItems.length})
                    </summary>
                    <table style="width:100%;font-size:11px;border-collapse:collapse;margin-top:6px">
                        <thead style="background:#eef2f7"><tr>
                            <th style="padding:5px;text-align:right">المادة</th>
                            <th style="padding:5px;text-align:center">الكمية</th>
                            <th style="padding:5px;text-align:center">السعر</th>
                            <th style="padding:5px;text-align:center">الإجمالي</th>
                        </tr></thead>
                        <tbody>${reqItems.map(([, it]) => `<tr style="border-bottom:1px solid #eef2f7">
                            <td style="padding:5px"><strong>${it.matName}</strong>${it.note?'<br><span style="font-size:10px;color:#888">— '+it.note+'</span>':''}</td>
                            <td style="padding:5px;text-align:center;font-weight:700;color:#27ae60">${it.qty} ${it.unit||''}</td>
                            <td style="padding:5px;text-align:center">${fmt(it.estPrice||0)}</td>
                            <td style="padding:5px;text-align:center;font-weight:700">${fmt(it.total||0)}</td>
                        </tr>`).join('')}</tbody>
                    </table>
                </details>
            </div>`;
        } else if (r.materialName) {
            // البنية القديمة
            itemsHtml = `<div style="background:#f8fafc;border-radius:6px;padding:6px 10px;margin-bottom:8px;font-size:11px;color:#444">
                📦 <strong>${r.materialName}</strong> — <strong>${r.qty}</strong> ${r.unit||''} × ${fmt(r.estPrice||0)} = <strong style="color:#27ae60">${fmt(r.estTotal||0)} ر</strong>
            </div>`;
        }

        return `<div style="background:white;border:1.5px solid ${needsAttention?status.color:'#e0e8f0'};border-radius:12px;padding:14px;border-right:4px solid ${status.color};${needsAttention?'box-shadow:0 2px 12px '+status.color+'33':''}">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;flex-wrap:wrap;margin-bottom:10px">
                <div style="flex:1;min-width:200px">
                    <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:4px">
                        <span style="font-weight:800;color:#1a3a5c;font-size:14px">${r.reqNumber||'-'}</span>
                        <span style="background:${status.bg};color:${status.color};padding:3px 10px;border-radius:10px;font-size:11px;font-weight:700">${status.label}</span>
                        <span style="color:${urgency.color};font-size:11px;font-weight:700">${urgency.label}</span>
                        ${itemCount > 0 ? `<span style="background:#e8f4fd;color:#0d4f7c;padding:2px 8px;border-radius:8px;font-size:11px;font-weight:700">${itemCount} مادة</span>` : ''}
                    </div>
                    <div style="font-size:11px;color:#666">
                        📁 <strong>${r.projectName||'-'}</strong> · 👤 ${r.requestedByName||'-'} · ${r.requestedAt?new Date(r.requestedAt).toLocaleDateString('ar-SA'):'-'}
                    </div>
                </div>
                <div style="text-align:center;background:#f8fafc;border-radius:8px;padding:6px 12px;min-width:120px">
                    <div style="font-size:10px;color:#888">القيمة الإجمالية</div>
                    <div style="font-size:18px;font-weight:900;color:#27ae60">${fmt(r.estTotal||0)}</div>
                    ${r.approvedTotal ? `<div style="font-size:10px;color:#27ae60;margin-top:2px">✅ معتمد: ${fmt(r.approvedTotal)}</div>` : ''}
                </div>
            </div>

            ${itemsHtml}

            ${r.reason?`<div style="background:#fff8e1;border-radius:6px;padding:6px 10px;margin-bottom:8px;font-size:11px;color:#7d4e00"><strong>📝</strong> ${r.reason}</div>`:''}

            <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(150px,1fr));gap:6px;font-size:11px;color:#555;margin-bottom:8px">
                <div>📅 الحاجة: <strong>${r.neededDate?new Date(r.neededDate).toLocaleDateString('ar-SA'):'-'}</strong></div>
                ${r.deliveryLocation?`<div>📍 ${r.deliveryLocation}</div>`:''}
            </div>

            ${r.rejectionReason?`<div style="background:#fadbd8;color:#c0392b;border-radius:6px;padding:8px 10px;margin-bottom:8px;font-size:11px"><strong>❌ سبب الرفض:</strong> ${r.rejectionReason}</div>`:''}

            <!-- History -->
            ${r.history && r.history.length > 0 ? `<details style="margin-bottom:8px">
                <summary style="cursor:pointer;font-size:11px;color:#666;font-weight:600">📜 سجل الإجراءات (${r.history.length})</summary>
                <div style="margin-top:6px;background:#fafbfc;border-radius:6px;padding:8px;font-size:10px">
                    ${r.history.map(h => `<div style="border-bottom:1px solid #eef2f7;padding:4px 0">
                        <span style="color:#666">${new Date(h.at).toLocaleString('ar-SA')}</span> · 
                        <strong style="color:#1a3a5c">${h.actor}</strong> · 
                        <span style="color:#444">${h.note}</span>
                    </div>`).join('')}
                </div>
            </details>` : ''}

            <!-- Action buttons -->
            <div style="display:flex;gap:6px;flex-wrap:wrap;margin-top:8px">
                ${r.status === 'draft' && (isAdmin || r.requestedBy === curU?.uid) ? `
                    <button class="btn b-b" style="padding:5px 12px;font-size:11px" onclick="openMatRequestM('${rk}')">✏️ تعديل</button>
                    <button class="btn b-g" style="padding:5px 12px;font-size:11px" onclick="submitDraftRequest('${rk}')">📤 إرسال للمراجعة</button>
                ` : ''}

                ${r.status === 'submitted' && canApprove ? `
                    ${(r.estTotal||0) <= (r.approvalLimits?.projectManager || 5000) ?
                        `<button class="btn b-g" style="padding:5px 12px;font-size:11px" onclick="openMatReqAction('${rk}','approve_pm')">✅ اعتماد نهائي</button>` :
                        `<button class="btn" style="background:#9b59b6;color:white;padding:5px 12px;font-size:11px" onclick="openMatReqAction('${rk}','forward')">📦 تحويل للمشتريات</button>`
                    }
                    <button class="btn b-r" style="padding:5px 12px;font-size:11px" onclick="openMatReqAction('${rk}','reject')">❌ رفض</button>
                ` : ''}

                ${r.status === 'pm_approved' || r.status === 'forwarded_purchasing' || r.status === 'quotations' ? `
                    <button class="btn b-pu" style="padding:5px 12px;font-size:11px" onclick="openPurchaseOrderPrint('${rk}')">🖨️ طباعة طلب الشراء</button>
                    <button class="btn b-b" style="padding:5px 12px;font-size:11px" onclick="openQuotationM('${rk}')">💼 إدارة عروض الأسعار</button>
                ` : ''}

                ${r.status === 'po_pending' || r.status === 'po_issued' || r.status === 'received' ? `
                    <button class="btn b-pu" style="padding:5px 12px;font-size:11px" onclick="openPurchaseOrderPrint('${rk}')">🖨️ طباعة</button>
                    ${r.poId ? `<button class="btn b-b" style="padding:5px 12px;font-size:11px" onclick="openPODetail('${r.poId}')">📄 عرض أمر الشراء</button>` : ''}
                ` : ''}

                ${r.status !== 'received' && r.status !== 'cancelled' && r.status !== 'rejected' && (isAdmin || r.requestedBy === curU?.uid) ? `
                    <button class="btn b-gr" style="padding:5px 12px;font-size:11px" onclick="cancelMatRequest('${rk}')">🚫 إلغاء</button>
                ` : ''}

                ${(r.status === 'po_issued' || r.status === 'received') && (isAdmin || can('manage_inventory')) ? `
                    <button class="btn" style="background:#16a085;color:white;padding:5px 12px;font-size:11px" onclick="quickCreateInvMovementFromMatRequest('${rk}')">⚡ إنشاء حركة مخزون</button>
                ` : ''}
            </div>
        </div>`;
    }).join('')}</div>`;
};

// ── إرسال مسودة
window.submitDraftRequest = function (rk) {
    const r = matRequests[rk]; if (!r) return;
    cf2(`إرسال الطلب ${r.reqNumber} للمراجعة؟`, async () => {
        const history = r.history || [];
        history.push({ action: 'submitted', actor: myP?.name || '', at: new Date().toISOString(), note: 'تم إرسال الطلب للمراجعة' });
        try {
            const updates = { status: 'submitted', history, submittedAt: new Date().toISOString() };
            await update(ref(db, `ledger/materialRequests/${rk}`), updates);
            // ✅ تحديث state المحلي + render فوراً
            matRequests[rk] = { ...r, ...updates };
            if ($('pg-matrequests')?.classList.contains('act')) {
                renderMatRequests();
                updateMrKPIs();
            }
            updateMrBadge();
            toast('✅ تم الإرسال', 'ok');
        } catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

// ── فتح مودال الإجراء
window.openMatReqAction = function (rk, action) {
    const r = matRequests[rk]; if (!r) return;
    $('mraK').value = rk;
    $('mraAction').value = action;

    const reqItems = r.items ? Object.entries(r.items) : [];
    let itemsHtml = '';
    if (reqItems.length > 0) {
        itemsHtml = `<div style="margin-top:8px;background:white;border-radius:6px;padding:8px;max-height:200px;overflow-y:auto">
            <div style="font-size:11px;font-weight:700;color:#1a3a5c;margin-bottom:6px">📦 المواد المطلوبة (${reqItems.length}):</div>
            <table style="width:100%;font-size:11px;border-collapse:collapse">
                <tbody>${reqItems.map(([, it]) => `<tr style="border-bottom:1px solid #eef2f7">
                    <td style="padding:4px"><strong>${it.matName}</strong></td>
                    <td style="padding:4px;text-align:center">${it.qty} ${it.unit||''}</td>
                    <td style="padding:4px;text-align:left;font-weight:700;color:#27ae60">${fmt(it.total||0)}</td>
                </tr>`).join('')}</tbody>
            </table>
        </div>`;
    } else if (r.materialName) {
        itemsHtml = `<div style="font-size:11px;color:#444;margin-top:5px">📦 ${r.materialName} — ${r.qty} ${r.unit||''}</div>`;
    }

    $('mraInfo').innerHTML = `<strong>${r.reqNumber}</strong> — قيمة تقديرية: <strong style="color:#27ae60">${fmt(r.estTotal)} ر</strong><br>📁 ${r.projectName} · 👤 ${r.requestedByName}${itemsHtml}`;
    $('mraApproveFields').style.display = 'none';
    $('mraRejectFields').style.display = 'none';
    $('mraForwardFields').style.display = 'none';
    $('mraApproveNote').value = '';
    $('mraRejectReason').value = '';
    $('mraForwardNote').value = '';

    if (action === 'approve_pm') {
        $('mMatReqActionT').textContent = '✅ اعتماد طلب المواد';
        $('mraApproveFields').style.display = '';
        // في الطلبات متعددة المواد، نعتمد الكل دفعة واحدة
        if (reqItems.length > 0) {
            $('mraQty').parentElement.style.display = 'none';
            $('mraPrice').parentElement.style.display = 'none';
        } else {
            $('mraQty').parentElement.style.display = '';
            $('mraPrice').parentElement.style.display = '';
            $('mraQty').value = r.qty;
            $('mraPrice').value = r.estPrice;
        }
        $('mraConfirmBtn').textContent = '✅ اعتماد نهائي';
        $('mraConfirmBtn').className = 'btn b-g';
        $('mraConfirmBtn').style.background = '';
        $('mraConfirmBtn').style.color = '';
    } else if (action === 'reject') {
        $('mMatReqActionT').textContent = '❌ رفض الطلب';
        $('mraRejectFields').style.display = '';
        $('mraConfirmBtn').textContent = '❌ تأكيد الرفض';
        $('mraConfirmBtn').className = 'btn b-r';
        $('mraConfirmBtn').style.background = '';
        $('mraConfirmBtn').style.color = '';
    } else if (action === 'forward') {
        $('mMatReqActionT').textContent = '📦 تحويل لقسم المشتريات';
        $('mraForwardFields').style.display = '';
        $('mraConfirmBtn').textContent = '📦 تحويل';
        $('mraConfirmBtn').className = 'btn';
        $('mraConfirmBtn').style.background = '#9b59b6';
        $('mraConfirmBtn').style.color = 'white';
    }
    ov('mMatReqAction');
};

// ── تأكيد الإجراء
window.confirmMatReqAction = async function () {
    const rk = $('mraK').value;
    const action = $('mraAction').value;
    const r = matRequests[rk]; if (!r) return;
    const history = r.history || [];
    const updates = { updatedAt: new Date().toISOString() };

    try {
        if (action === 'approve_pm') {
            const reqItems = r.items ? Object.entries(r.items) : [];
            if (reqItems.length > 0) {
                // طلب متعدد المواد: اعتمد القيم الإجمالية من items
                const totalQty = reqItems.reduce((s, [, it]) => s + (parseFloat(it.qty) || 0), 0);
                const totalAmount = reqItems.reduce((s, [, it]) => s + (parseFloat(it.total) || 0), 0);
                updates.status = 'pm_approved';
                updates.approvedTotal = totalAmount;
                updates.approvedQty = totalQty;
                // احفظ المواد المعتمدة كاملة
                updates.approvedItems = r.items;
            } else {
                // طلب مادة واحدة: اقرأ من الحقول
                const aQty = parseFloat($('mraQty').value) || 0;
                const aPrice = parseFloat($('mraPrice').value) || 0;
                if (aQty <= 0 || aPrice <= 0) { toast('أدخل الكمية والسعر', 'er'); return }
                const aTotal = aQty * aPrice;
                updates.status = 'pm_approved';
                updates.approvedQty = aQty;
                updates.approvedUnitPrice = aPrice;
                updates.approvedTotal = aTotal;
            }
            updates.approvedBy = curU?.uid || '';
            updates.approvedByName = myP?.name || '';
            updates.approvedAt = new Date().toISOString();
            updates.approvalNote = $('mraApproveNote').value.trim();
            history.push({ action: 'approved', actor: myP?.name || '', at: new Date().toISOString(), note: `✅ اعتمد الطلب${$('mraApproveNote').value?' — '+$('mraApproveNote').value:''}` });
        } else if (action === 'reject') {
            const reason = $('mraRejectReason').value.trim();
            if (!reason) { toast('أدخل سبب الرفض', 'er'); return }
            updates.status = 'rejected';
            updates.rejectionReason = reason;
            updates.rejectedBy = curU?.uid || '';
            updates.rejectedByName = myP?.name || '';
            updates.rejectedAt = new Date().toISOString();
            history.push({ action: 'rejected', actor: myP?.name || '', at: new Date().toISOString(), note: `❌ رفض — ${reason}` });
        } else if (action === 'forward') {
            updates.status = 'forwarded_purchasing';
            updates.forwardNote = $('mraForwardNote').value.trim();
            updates.forwardedBy = curU?.uid || '';
            updates.forwardedByName = myP?.name || '';
            updates.forwardedAt = new Date().toISOString();
            history.push({ action: 'forwarded', actor: myP?.name || '', at: new Date().toISOString(), note: `📦 حُوّل للمشتريات${$('mraForwardNote').value?' — '+$('mraForwardNote').value:''}` });
        }
        updates.history = history;
        await update(ref(db, `ledger/materialRequests/${rk}`), updates);
        // ✅ تحديث state المحلي مباشرة + إعادة render فوراً
        matRequests[rk] = { ...r, ...updates };
        if ($('pg-matrequests')?.classList.contains('act')) {
            renderMatRequests();
            updateMrKPIs();
        }
        updateMrBadge();
        cov('mMatReqAction');
        toast('✅ تم تنفيذ الإجراء', 'ok');
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// ── إلغاء طلب
window.cancelMatRequest = function (rk) {
    const r = matRequests[rk];
    if (!r) { toast('الطلب غير موجود', 'er'); return }
    cf2(`إلغاء الطلب ${r.reqNumber}؟`, async () => {
        const history = r.history || [];
        history.push({ action: 'cancelled', actor: myP?.name || '', at: new Date().toISOString(), note: 'تم إلغاء الطلب' });
        try {
            const updates = {
                status: 'cancelled', history, cancelledAt: new Date().toISOString()
            };
            await update(ref(db, `ledger/materialRequests/${rk}`), updates);
            // ✅ تحديث state المحلي مباشرة + إعادة render فوراً
            matRequests[rk] = { ...r, ...updates };
            if ($('pg-matrequests')?.classList.contains('act')) {
                renderMatRequests();
                updateMrKPIs();
            }
            updateMrBadge();
            toast('🚫 تم الإلغاء', 'ok');
        } catch (e) {
            toast('خطأ: ' + e.message, 'er');
        }
    });
};

