// ─── KPIs ───
function updateGRNKPIs() {
    const items = Object.values(goodsReceipts);
    $('grnk1') && ($('grnk1').textContent = items.length);
    const pendingPOs = Object.values(purchaseOrders).filter(po => ['sent', 'partial_received'].includes(po.status)).length;
    $('grnk2') && ($('grnk2').textContent = pendingPOs);
    $('grnk3') && ($('grnk3').textContent = items.filter(g => g.status === 'partial').length);
    const totalValue = items.reduce((s, g) => s + (g.totalValue || 0), 0);
    $('grnk4') && ($('grnk4').textContent = fmt(totalValue));
}

