// ─── عرض GRNs بدون فواتير ───
window.renderPendingGRNsForInvoice = function () {
    const container = $('invPendingGRNs'); if (!container) return;
    // GRNs التي ليس لها فاتورة بعد
    const invoicedGRNs = new Set(Object.values(supplierInvoices).map(i => i.grnId));
    const pending = Object.entries(goodsReceipts).filter(([gk, g]) =>
        !invoicedGRNs.has(gk) && g.status !== 'rejected'
    ).sort((a, b) => (b[1].createdAt || '').localeCompare(a[1].createdAt || ''));

    if (!pending.length) {
        container.innerHTML = '<div class="empty"><div class="ei">📥</div><p>كل الاستلامات لها فواتيرها 🎉</p></div>';
        return;
    }

    container.innerHTML = `<div style="display:grid;gap:10px;margin-top:10px">${pending.map(([gk, g]) => {
        const status = GRN_STATUS[g.status] || GRN_STATUS.received;
        return `<div style="background:white;border:1.5px solid #abebc6;border-radius:12px;padding:14px;border-right:4px solid #27ae60">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;flex-wrap:wrap;margin-bottom:8px">
                <div style="flex:1;min-width:200px">
                    <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:4px">
                        <span style="font-weight:800;color:#1a3a5c;font-size:14px">📥 ${g.grnNumber}</span>
                        <span style="background:${status.bg};color:${status.color};padding:2px 8px;border-radius:8px;font-size:10px;font-weight:700">${status.label}</span>
                    </div>
                    <div style="font-size:12px;color:#555">
                        <strong>${g.materialName}</strong> · 🏭 ${g.supplierName}
                    </div>
                    <div style="font-size:11px;color:#666;margin-top:2px">
                        📅 ${new Date(g.grnDate).toLocaleDateString('ar-SA')} · 📁 ${g.projectName}
                    </div>
                </div>
                <div style="text-align:center;background:#f8fafc;border-radius:8px;padding:6px 12px;min-width:120px">
                    <div style="font-size:10px;color:#888">القيمة المتوقعة</div>
                    <div style="font-size:17px;font-weight:900;color:#27ae60">${fmt(g.totalValue || 0)}</div>
                </div>
            </div>
            <button class="btn b-g" style="padding:5px 14px;font-size:11px" onclick="openInvoiceFromGRN('${gk}')">🧾 تسجيل الفاتورة</button>
        </div>`;
    }).join('')}</div>`;
};

// ─── فتح مودال الفاتورة ───
window.openInvoiceFromGRN = function (grnKey) {
    const g = goodsReceipts[grnKey]; if (!g) return;
    if (myP?.role !== 'admin' && !can('match_invoice')) { toast('ليس لديك صلاحية تسجيل الفواتير', 'er'); return }

    const po = purchaseOrders[g.poId] || {};
    const s = sup[g.supplierId] || {};

    $('invGRNKey').value = grnKey;
    $('invK').value = '';
    $('mInvoiceT').textContent = `🧾 تسجيل فاتورة للاستلام ${g.grnNumber}`;

    $('invGRNInfo').innerHTML = `
        <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;flex-wrap:wrap">
            <div style="flex:1;min-width:200px">
                <div style="font-size:14px;font-weight:800;color:#1a3a5c;margin-bottom:4px">📥 ${g.grnNumber} ← 📄 ${g.poNumber || ''}</div>
                <div style="font-size:12px;color:#555">${g.materialName} · ${g.totalReceivedQty} ${g.unit || ''}</div>
                <div style="font-size:11px;color:#666">🏭 ${g.supplierName} · 📁 ${g.projectName}</div>
            </div>
            <div style="text-align:center;background:white;border-radius:8px;padding:8px 14px;border:1.5px solid #abebc6">
                <div style="font-size:10px;color:#888">القيمة المتوقعة</div>
                <div style="font-size:18px;font-weight:900;color:#27ae60">${fmt(g.totalValue || 0)}</div>
                <div style="font-size:10px;color:#666">قبل الضريبة</div>
            </div>
        </div>
    `;

    // Default values
    $('invNumber').value = '';
    $('invDate').value = today();
    // Auto-set due date based on supplier payment terms
    const dueDate = new Date();
    const days = s.creditDays || 0;
    dueDate.setDate(dueDate.getDate() + days);
    $('invDueDate').value = dueDate.toISOString().substring(0, 10);
    $('invVATNum').value = s.vat || '';

    // Set amounts to match GRN by default
    const subtotal = g.totalValue || 0;
    $('invSubtotal').value = subtotal.toFixed(2);
    $('invDiscount').value = '0';
    $('invShipping').value = '0';
    $('invVATPct').value = '15';
    $('invNotes').value = '';

    calcInvoiceTotal();
    renderInvoiceMatching();
    ov('mInvoice');
};

// ─── حساب الإجمالي ───
window.calcInvoiceTotal = function () {
    const subtotal = parseFloat($('invSubtotal').value) || 0;
    const discount = parseFloat($('invDiscount').value) || 0;
    const shipping = parseFloat($('invShipping').value) || 0;
    const vatPct = parseFloat($('invVATPct').value) || 0;

    const afterDiscount = subtotal - discount;
    const beforeVAT = afterDiscount + shipping;
    const vatAmount = beforeVAT * (vatPct / 100);
    const grandTotal = beforeVAT + vatAmount;

    $('invVATAmount').value = vatAmount.toFixed(2);
    $('invGrandTotal').value = grandTotal.toFixed(2);

    renderInvoiceMatching();
};

// ─── مطابقة 3-Way ───
function renderInvoiceMatching() {
    const grnKey = $('invGRNKey').value;
    const g = goodsReceipts[grnKey]; if (!g) return;
    const po = purchaseOrders[g.poId] || {};

    const invSubtotal = parseFloat($('invSubtotal').value) || 0;
    const invGrand = parseFloat($('invGrandTotal').value) || 0;
    const invVATAmt = parseFloat($('invVATAmount').value) || 0;

    const poSubtotal = (po.qty || 0) * (po.unitPrice || 0);
    const grnSubtotal = g.totalValue || 0;

    // المطابقة على 3 مستويات
    const rows = [
        {
            label: 'الكمية',
            po: `${po.qty || 0} ${po.unit || ''}`,
            grn: `${g.totalReceivedQty} ${g.unit || ''}`,
            inv: `${g.totalReceivedQty} ${g.unit || ''}`,
            diff: g.totalReceivedQty - (po.qty || 0),
            isMatch: g.totalReceivedQty === (po.qty || 0)
        },
        {
            label: 'سعر الوحدة',
            po: fmt(po.unitPrice || 0) + ' ر',
            grn: fmt(po.unitPrice || 0) + ' ر',
            inv: g.totalReceivedQty > 0 ? fmt(invSubtotal / g.totalReceivedQty) + ' ر' : '0 ر',
            diff: (invSubtotal / (g.totalReceivedQty || 1)) - (po.unitPrice || 0),
            isMatch: Math.abs((invSubtotal / (g.totalReceivedQty || 1)) - (po.unitPrice || 0)) < 0.01
        },
        {
            label: 'المجموع الفرعي',
            po: fmt(poSubtotal) + ' ر',
            grn: fmt(grnSubtotal) + ' ر',
            inv: fmt(invSubtotal) + ' ر',
            diff: invSubtotal - grnSubtotal,
            isMatch: Math.abs(invSubtotal - grnSubtotal) < 0.01
        },
        {
            label: 'الإجمالي شامل الضريبة',
            po: fmt(po.grandTotal || 0) + ' ر',
            grn: '—',
            inv: fmt(invGrand) + ' ر',
            diff: invGrand - (po.grandTotal || 0),
            isMatch: Math.abs(invGrand - (po.grandTotal || 0)) < 0.01
        }
    ];

    $('invMatchingTable').innerHTML = rows.map(r => {
        const diffColor = r.isMatch ? '#27ae60' : '#e67e22';
        const diffText = r.isMatch ? '0' : (r.diff > 0 ? '+' : '') + (typeof r.diff === 'number' ? r.diff.toFixed(2) : r.diff);
        const statusIcon = r.isMatch ? '✅' : '⚠️';
        return `<tr style="background:${r.isMatch ? '#f8fafc' : '#fef5e7'}">
            <td style="padding:8px;font-weight:700;color:#1a3a5c">${r.label}</td>
            <td style="padding:8px;text-align:center">${r.po}</td>
            <td style="padding:8px;text-align:center">${r.grn}</td>
            <td style="padding:8px;text-align:center;font-weight:700">${r.inv}</td>
            <td style="padding:8px;text-align:center;font-weight:700;color:${diffColor}">${diffText}</td>
            <td style="padding:8px;text-align:center;font-size:16px">${statusIcon}</td>
        </tr>`;
    }).join('');

    const allMatch = rows.every(r => r.isMatch);
    const result = $('invMatchResult');
    if (allMatch) {
        result.style.background = '#e8f8f5';
        result.style.color = '#0e6655';
        result.style.border = '1.5px solid #abebc6';
        result.innerHTML = '✅ <strong>كل المطابقات صحيحة!</strong> الفاتورة جاهزة للاعتماد والدفع.';
    } else {
        result.style.background = '#fef5e7';
        result.style.color = '#7d4e00';
        result.style.border = '1.5px solid #f5cba7';
        result.innerHTML = '⚠️ <strong>يوجد اختلافات.</strong> راجع الفروق قبل الموافقة. يمكن حفظها لمراجعة الإدارة.';
    }
}

// ─── حفظ الفاتورة ───
window.saveInvoice = async function () {
    const grnKey = $('invGRNKey').value;
    const g = goodsReceipts[grnKey]; if (!g) return;
    const po = purchaseOrders[g.poId] || {};

    const invNumber = $('invNumber').value.trim();
    if (!invNumber) { toast('أدخل رقم الفاتورة', 'er'); return }
    if (!$('invDate').value) { toast('أدخل تاريخ الفاتورة', 'er'); return }

    const subtotal = parseFloat($('invSubtotal').value) || 0;
    const grandTotal = parseFloat($('invGrandTotal').value) || 0;
    if (grandTotal <= 0) { toast('أدخل المبلغ', 'er'); return }

    // Determine matching status
    const grnSubtotal = g.totalValue || 0;
    const poGrand = po.grandTotal || 0;
    const hasDiscrepancy = Math.abs(subtotal - grnSubtotal) > 0.01 || Math.abs(grandTotal - poGrand) > 0.01;
    const status = hasDiscrepancy ? 'discrepancy' : 'matched';

    try {
        const invCount = Object.keys(supplierInvoices).length + 1;
        const internalNumber = 'INV-' + new Date().getFullYear() + '-' + String(invCount).padStart(4, '0');

        const data = {
            internalNumber,
            invoiceNumber: invNumber,
            grnId: grnKey, grnNumber: g.grnNumber,
            poId: g.poId, poNumber: g.poNumber,
            projectId: g.projectId, projectName: g.projectName,
            supplierId: g.supplierId, supplierName: g.supplierName,
            materialId: g.materialId, materialName: g.materialName,
            qty: g.totalReceivedQty, unit: g.unit,
            invoiceDate: $('invDate').value,
            dueDate: $('invDueDate').value || '',
            vatNumber: $('invVATNum').value.trim() || '',
            subtotal,
            discount: parseFloat($('invDiscount').value) || 0,
            shipping: parseFloat($('invShipping').value) || 0,
            vatPct: parseFloat($('invVATPct').value) || 0,
            vatAmount: parseFloat($('invVATAmount').value) || 0,
            grandTotal,
            // Expected values for matching
            expectedSubtotal: grnSubtotal,
            expectedGrandTotal: poGrand,
            discrepancyAmount: grandTotal - poGrand,
            status,
            notes: $('invNotes').value.trim() || '',
            history: [{
                action: 'created', actor: myP?.name || '',
                at: new Date().toISOString(),
                note: `تسجيل فاتورة بقيمة ${fmt(grandTotal)} ر${hasDiscrepancy ? ' — يوجد فرق' : ' — مطابقة كاملة'}`
            }],
            createdBy: curU?.uid || '',
            createdByName: myP?.name || '',
            createdAt: new Date().toISOString()
        };

        await push(R.invs, data);

        // Update GRN status
        await update(ref(db, `ledger/goodsReceipts/${grnKey}`), {
            status: 'invoiced',
            invoicedAt: new Date().toISOString()
        });

        toast(`✅ تم تسجيل الفاتورة ${internalNumber}${hasDiscrepancy ? ' — يوجد فرق' : ''}`, 'ok', 4000);
        if (typeof logAudit === 'function') logAudit('تسجيل فاتورة', 'فواتير الموردين', `${internalNumber} — بقيمة ${fmt(grandTotal)} ر${hasDiscrepancy ? ' — يوجد فرق' : ''}`);
        cov('mInvoice');
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// ─── عرض الفواتير ───
window.renderInvoices = function () {
    const container = $('invList'); if (!container) return;
    const sf = $('invStatusFilter')?.value || '';

    let items = Object.entries(supplierInvoices);
    if (sf) items = items.filter(([, i]) => i.status === sf);
    items.sort((a, b) => (b[1].createdAt || '').localeCompare(a[1].createdAt || ''));

    if (!items.length) {
        container.innerHTML = '<div class="empty"><div class="ei">🧾</div><p>لا توجد فواتير</p></div>';
        return;
    }

    container.innerHTML = `<div style="display:grid;gap:10px;margin-top:10px">${items.map(([ik, inv]) => {
        const status = INV_STATUS[inv.status] || INV_STATUS.pending_match;
        const dueDate = inv.dueDate ? new Date(inv.dueDate) : null;
        const today_ = new Date();
        const daysToDue = dueDate ? Math.ceil((dueDate - today_) / (1000 * 60 * 60 * 24)) : null;
        const isOverdue = daysToDue !== null && daysToDue < 0 && inv.status !== 'paid';
        return `<div style="background:white;border:1.5px solid #e0e8f0;border-radius:12px;padding:14px;border-right:4px solid ${status.color}">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;flex-wrap:wrap;margin-bottom:8px">
                <div style="flex:1;min-width:200px">
                    <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:4px">
                        <span style="font-weight:800;color:#1a3a5c;font-size:14px">🧾 ${inv.invoiceNumber}</span>
                        <span style="background:${status.bg};color:${status.color};padding:3px 10px;border-radius:10px;font-size:11px;font-weight:700">${status.label}</span>
                        ${isOverdue ? '<span style="background:#fadbd8;color:#c0392b;padding:2px 8px;border-radius:8px;font-size:10px;font-weight:700">⏰ تجاوز الاستحقاق</span>' : ''}
                    </div>
                    <div style="font-size:11px;color:#666;margin-bottom:2px">داخلي: ${inv.internalNumber}</div>
                    <div style="font-size:12px;color:#555">
                        <strong>${inv.materialName}</strong> · 🏭 ${inv.supplierName}
                    </div>
                    <div style="font-size:11px;color:#666;margin-top:2px">
                        📅 ${new Date(inv.invoiceDate).toLocaleDateString('ar-SA')} · 📁 ${inv.projectName}${dueDate ? ' · ⏰ يستحق: ' + dueDate.toLocaleDateString('ar-SA') : ''}
                    </div>
                </div>
                <div style="text-align:center;background:#f8fafc;border-radius:8px;padding:6px 12px;min-width:130px">
                    <div style="font-size:10px;color:#888">الإجمالي</div>
                    <div style="font-size:17px;font-weight:900;color:${status.color}">${fmt(inv.grandTotal || 0)}</div>
                    <div style="font-size:10px;color:#666">شامل الضريبة</div>
                </div>
            </div>
            ${Math.abs(inv.discrepancyAmount || 0) > 0.01 ? `<div style="background:#fef5e7;border-radius:6px;padding:6px 10px;margin-bottom:8px;font-size:11px;color:#7d4e00">
                ⚠️ فرق عن المتوقع: <strong>${inv.discrepancyAmount > 0 ? '+' : ''}${fmt(inv.discrepancyAmount)} ر</strong>
            </div>` : ''}
            <div style="display:flex;gap:6px;flex-wrap:wrap;margin-top:8px">
                <button class="btn b-b" style="padding:5px 12px;font-size:11px" onclick="openInvoiceView('${ik}')">👁️ تفاصيل + طباعة</button>
                ${inv.status === 'matched' && (myP?.role === 'admin' || can('match_invoice')) ? `<button class="btn b-g" style="padding:5px 12px;font-size:11px" onclick="markInvoicePaid('${ik}')">💰 تأكيد الدفع</button>` : ''}
                ${inv.status === 'discrepancy' && (myP?.role === 'admin' || can('match_invoice')) ? `<button class="btn b-g" style="padding:5px 12px;font-size:11px" onclick="acceptInvoiceDiscrepancy('${ik}')">✅ قبول الفرق</button>` : ''}
            </div>
        </div>`;
    }).join('')}</div>`;
};

