// ─────────────────────────────────────────────────────────
// تقرير مقارنة الإيرادات الفعلية vs التكاليف الفعلية
// ─────────────────────────────────────────────────────────
function renderRevenueCostReport(projectFilter, from, to) {
    const container = $('prjReportContent'); if (!container) return;
    destroyReportChart('rcRevCostChart');
    destroyReportChart('rcMarginChart');

    const fmt = window.fmt || (n => n.toLocaleString('ar-SA', { minimumFractionDigits: 2, maximumFractionDigits: 2 }));

    // ─── جمع إيرادات كل مشروع من فواتير المبيعات المرحّلة ───
    const projRevenue = {};  // { projectId: number }
    Object.values(window.salesInvoices || {}).forEach(inv => {
        if (inv.status !== 'posted') return;
        if (!inv.projectId) return;
        if (projectFilter && inv.projectId !== projectFilter) return;
        const d = new Date(inv.date || '');
        if (!inPeriod(d, from, to)) return;
        projRevenue[inv.projectId] = (projRevenue[inv.projectId] || 0) +
            Math.round((parseFloat(inv.subtotal || inv.netBeforeVat || inv.grandTotal) || 0) * 100) / 100;
    });

    // ─── جمع تكاليف كل مشروع ───
    const projCost = {};     // { projectId: { pmc, payroll, supplier, other } }
    const ensureCost = id => {
        if (!projCost[id]) projCost[id] = { pmc: 0, payroll: 0, supplier: 0, other: 0 };
        return projCost[id];
    };

    // تكاليف المشاريع الشهرية (PMC)
    Object.values(window.projectMonthlyCosts || {}).forEach(c => {
        if (!c.projectId) return;
        if (projectFilter && c.projectId !== projectFilter) return;
        const d = new Date((c.month || '') + '-01');
        if (!inPeriod(d, from, to)) return;
        ensureCost(c.projectId).pmc += parseFloat(c.amount) || 0;
    });

    // فواتير الموردين
    Object.values(supplierInvoices || {}).forEach(inv => {
        if (!inv.projectId) return;
        if (projectFilter && inv.projectId !== projectFilter) return;
        const payDate = inv.paymentDate || inv.invoiceDate;
        if (!inPeriod(payDate, from, to)) return;
        ensureCost(inv.projectId).supplier += parseFloat(inv.totalAmount || inv.grandTotal) || 0;
    });

    // الرواتب
    Object.values(payrolls || {}).forEach(p => {
        if (p.status !== 'approved') return;
        if (!inPeriod(p.month + '-01', from, to)) return;
        Object.values(p.items || {}).forEach(it => {
            const empData = emp[it.empKey];
            if (!empData || !empData.projectId) return;
            if (projectFilter && empData.projectId !== projectFilter) return;
            ensureCost(empData.projectId).payroll += parseFloat(it.netPay) || 0;
        });
    });

    // معاملات أخرى (transactions)
    Object.values(tr || {}).forEach(t => {
        if (!t.projectId) return;
        if (projectFilter && t.projectId !== projectFilter) return;
        if (!inPeriod(t.date, from, to)) return;
        if (t.type === 'expense' || (t.debit && t.debit > 0)) {
            ensureCost(t.projectId).other += parseFloat(t.amount || t.debit) || 0;
        }
    });

    // ─── دمج بيانات المشاريع ───
    const allProjIds = new Set([
        ...Object.keys(projRevenue),
        ...Object.keys(projCost)
    ]);
    if (projectFilter) allProjIds.add(projectFilter);

    const rows = [...allProjIds].map(pid => {
        const p = projects[pid] || {};
        const rev  = projRevenue[pid] || 0;
        const cost = projCost[pid] || { pmc: 0, payroll: 0, supplier: 0, other: 0 };
        const totalCost = cost.pmc + cost.payroll + cost.supplier + cost.other;
        const profit = rev - totalCost;
        const margin = rev > 0 ? (profit / rev * 100) : (totalCost > 0 ? -100 : 0);
        return { pid, name: p.name || pid, rev, totalCost, profit, margin, ...cost };
    }).sort((a, b) => b.rev - a.rev);

    if (!rows.length) {
        container.innerHTML = '<div class="empty"><div class="ei">⚖️</div><p>لا توجد بيانات إيرادات أو تكاليف في هذه الفترة</p></div>';
        return;
    }

    const totalRev    = rows.reduce((s, r) => s + r.rev, 0);
    const totalCostAll = rows.reduce((s, r) => s + r.totalCost, 0);
    const totalProfit = totalRev - totalCostAll;
    const totalMargin = totalRev > 0 ? (totalProfit / totalRev * 100) : 0;

    // ─── ألوان الهامش ───
    const marginColor = m => m >= 20 ? '#1e8449' : m >= 10 ? '#27ae60' : m >= 0 ? '#f39c12' : '#c0392b';
    const marginBg    = m => m >= 20 ? '#eafaf1' : m >= 10 ? '#d5f5e3' : m >= 0 ? '#fef9e7' : '#fdedec';

    container.innerHTML = `
        <!-- KPIs -->
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:12px;margin-bottom:18px">
            <div style="background:linear-gradient(135deg,#1e8449,#27ae60);border-radius:14px;padding:16px;color:white;cursor:pointer" onclick="nav('salesinvoices')">
                <div style="font-size:11px;opacity:.85;font-weight:700">💰 إجمالي الإيرادات الفعلية</div>
                <div style="font-size:24px;font-weight:900;margin:6px 0">${fmt(totalRev)}</div>
                <div style="font-size:10px;opacity:.85">فواتير المبيعات المرحّلة ↗</div>
            </div>
            <div style="background:linear-gradient(135deg,#c0392b,#e74c3c);border-radius:14px;padding:16px;color:white;cursor:pointer" onclick="nav('projectcosts')">
                <div style="font-size:11px;opacity:.85;font-weight:700">💸 إجمالي التكاليف الفعلية</div>
                <div style="font-size:24px;font-weight:900;margin:6px 0">${fmt(totalCostAll)}</div>
                <div style="font-size:10px;opacity:.85">PMC + رواتب + موردون ↗</div>
            </div>
            <div style="background:linear-gradient(135deg,${totalProfit >= 0 ? '#1a3a5c,#2d6a9f' : '#7b241c,#c0392b'});border-radius:14px;padding:16px;color:white">
                <div style="font-size:11px;opacity:.85;font-weight:700">📊 الربح / الخسارة الفعلية</div>
                <div style="font-size:24px;font-weight:900;margin:6px 0">${totalProfit >= 0 ? '+' : ''}${fmt(totalProfit)}</div>
                <div style="font-size:10px;opacity:.85">${totalProfit >= 0 ? '✅ ربح' : '⚠️ خسارة'}</div>
            </div>
            <div style="background:linear-gradient(135deg,${marginColor(totalMargin)},${marginColor(totalMargin)+'cc'});border-radius:14px;padding:16px;color:white">
                <div style="font-size:11px;opacity:.85;font-weight:700">📈 هامش الربح الإجمالي</div>
                <div style="font-size:28px;font-weight:900;margin:6px 0">${totalMargin.toFixed(1)}%</div>
                <div style="font-size:10px;opacity:.85">${totalMargin >= 20 ? '✅ ممتاز' : totalMargin >= 10 ? '👍 جيد' : totalMargin >= 0 ? '⚠️ منخفض' : '❌ خسارة'}</div>
            </div>
        </div>

        <!-- مخطط المقارنة -->
        <div class="card" style="margin-bottom:14px">
            <div style="font-size:14px;font-weight:800;color:#1a3a5c;margin-bottom:12px">📊 مقارنة الإيرادات والتكاليف لكل مشروع</div>
            <div style="position:relative;height:${Math.max(300, rows.length * 55)}px"><canvas id="rcRevCostChart"></canvas></div>
        </div>

        <!-- مخطط هامش الربح -->
        <div class="card" style="margin-bottom:14px">
            <div style="font-size:14px;font-weight:800;color:#1a3a5c;margin-bottom:12px">📈 هامش الربح % لكل مشروع</div>
            <div style="position:relative;height:${Math.max(260, rows.length * 45)}px"><canvas id="rcMarginChart"></canvas></div>
        </div>

        <!-- الجدول التفصيلي -->
        <div class="card">
            <div style="font-size:14px;font-weight:800;color:#1a3a5c;margin-bottom:12px">📋 تفصيل كل مشروع</div>
            <div style="overflow-x:auto">
            <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:900px">
                <thead style="background:#1a3a5c;color:white">
                    <tr>
                        <th style="padding:10px;text-align:right">المشروع</th>
                        <th style="padding:10px;text-align:center;color:#7dcea0">الإيرادات</th>
                        <th style="padding:10px;text-align:center">تكاليف PMC</th>
                        <th style="padding:10px;text-align:center">رواتب</th>
                        <th style="padding:10px;text-align:center">موردون</th>
                        <th style="padding:10px;text-align:center">أخرى</th>
                        <th style="padding:10px;text-align:center;color:#f1948a">إجمالي التكاليف</th>
                        <th style="padding:10px;text-align:center">الربح / الخسارة</th>
                        <th style="padding:10px;text-align:center">الهامش%</th>
                        <th style="padding:10px;text-align:center">شريط</th>
                    </tr>
                </thead>
                <tbody>
                    ${rows.map((r, i) => {
                        const barW = totalRev > 0 ? Math.max(3, (r.rev / totalRev * 100)).toFixed(1) : 0;
                        const costBarW = totalRev > 0 ? Math.max(3, (r.totalCost / totalRev * 100)).toFixed(1) : 0;
                        return `<tr style="${i % 2 ? 'background:#fafbfc' : ''}">
                            <td style="padding:10px;font-weight:700;color:#1a3a5c">${r.name}</td>
                            <td style="padding:10px;text-align:center;color:#1e8449;font-weight:800">${fmt(r.rev)}</td>
                            <td style="padding:10px;text-align:center;color:#2d6a9f">${fmt(r.pmc)}</td>
                            <td style="padding:10px;text-align:center;color:#8e44ad">${fmt(r.payroll)}</td>
                            <td style="padding:10px;text-align:center;color:#d35400">${fmt(r.supplier)}</td>
                            <td style="padding:10px;text-align:center;color:#666">${fmt(r.other)}</td>
                            <td style="padding:10px;text-align:center;color:#c0392b;font-weight:800">${fmt(r.totalCost)}</td>
                            <td style="padding:10px;text-align:center;font-weight:800;color:${r.profit >= 0 ? '#1e8449' : '#c0392b'}">${r.profit >= 0 ? '+' : ''}${fmt(r.profit)}</td>
                            <td style="padding:10px;text-align:center">
                                <span style="background:${marginBg(r.margin)};color:${marginColor(r.margin)};padding:3px 10px;border-radius:12px;font-weight:800;font-size:11px">${r.margin.toFixed(1)}%</span>
                            </td>
                            <td style="padding:10px;min-width:120px">
                                <div style="height:8px;background:#eee;border-radius:4px;overflow:hidden;margin-bottom:3px">
                                    <div style="width:${barW}%;background:#27ae60;height:100%"></div>
                                </div>
                                <div style="height:8px;background:#eee;border-radius:4px;overflow:hidden">
                                    <div style="width:${costBarW}%;background:#e74c3c;height:100%"></div>
                                </div>
                            </td>
                        </tr>`;
                    }).join('')}
                    <tr style="background:#1a3a5c;color:white;font-weight:900">
                        <td style="padding:10px">📊 الإجمالي</td>
                        <td style="padding:10px;text-align:center">${fmt(totalRev)}</td>
                        <td style="padding:10px;text-align:center">${fmt(rows.reduce((s,r)=>s+r.pmc,0))}</td>
                        <td style="padding:10px;text-align:center">${fmt(rows.reduce((s,r)=>s+r.payroll,0))}</td>
                        <td style="padding:10px;text-align:center">${fmt(rows.reduce((s,r)=>s+r.supplier,0))}</td>
                        <td style="padding:10px;text-align:center">${fmt(rows.reduce((s,r)=>s+r.other,0))}</td>
                        <td style="padding:10px;text-align:center">${fmt(totalCostAll)}</td>
                        <td style="padding:10px;text-align:center;color:${totalProfit>=0?'#7dcea0':'#f1948a'}">${totalProfit>=0?'+':''}${fmt(totalProfit)}</td>
                        <td style="padding:10px;text-align:center">${totalMargin.toFixed(1)}%</td>
                        <td></td>
                    </tr>
                </tbody>
            </table>
            </div>
        </div>
    `;

    // ── رسم المخطط الأفقي ──
    setTimeout(() => {
        const labels = rows.map(r => r.name.length > 18 ? r.name.slice(0,18) + '…' : r.name);

        reportCharts['rcRevCostChart'] = new Chart($('rcRevCostChart'), {
            type: 'bar',
            data: {
                labels,
                datasets: [
                    { label: 'الإيرادات', data: rows.map(r => r.rev),       backgroundColor: '#27ae6099', borderColor: '#1e8449', borderWidth: 2 },
                    { label: 'التكاليف', data: rows.map(r => r.totalCost), backgroundColor: '#e74c3c99', borderColor: '#c0392b', borderWidth: 2 }
                ]
            },
            options: {
                indexAxis: 'y',
                responsive: true, maintainAspectRatio: false,
                plugins: { legend: { position: 'top' } },
                scales: {
                    x: { beginAtZero: true, ticks: { callback: v => fmt(v) } }
                }
            }
        });

        reportCharts['rcMarginChart'] = new Chart($('rcMarginChart'), {
            type: 'bar',
            data: {
                labels,
                datasets: [{
                    label: 'هامش الربح %',
                    data: rows.map(r => parseFloat(r.margin.toFixed(2))),
                    backgroundColor: rows.map(r => marginColor(r.margin) + '99'),
                    borderColor: rows.map(r => marginColor(r.margin)),
                    borderWidth: 2
                }]
            },
            options: {
                indexAxis: 'y',
                responsive: true, maintainAspectRatio: false,
                plugins: { legend: { display: false } },
                scales: {
                    x: { ticks: { callback: v => v + '%' } }
                }
            }
        });
    }, 100);
}

