// الأعمدة الافتراضية لمسير الرواتب
const PAYROLL_COLUMNS = [
    { key: 'idx', label: '#', defaultWidth: 40, defaultVisible: true },
    { key: 'name', label: 'الموظف', defaultWidth: 130, defaultVisible: true },
    { key: 'job', label: 'الوظيفة', defaultWidth: 100, defaultVisible: false },
    { key: 'dept', label: 'القسم', defaultWidth: 100, defaultVisible: true },
    { key: 'iban', label: 'الآيبان', defaultWidth: 160, defaultVisible: false },
    // ── مكوّنات الراتب والبدلات (افتراضياً مخفية — للتحكم في الإظهار) ──
    { key: 'basic', label: 'الراتب الأساسي', defaultWidth: 85, defaultVisible: false },
    { key: 'house', label: 'بدل السكن', defaultWidth: 80, defaultVisible: false },
    { key: 'trans', label: 'بدل المواصلات', defaultWidth: 80, defaultVisible: false },
    { key: 'phone', label: 'بدل الاتصالات', defaultWidth: 80, defaultVisible: false },
    { key: 'nature', label: 'بدل الطبيعة/الخطورة', defaultWidth: 85, defaultVisible: false },
    { key: 'rep', label: 'بدل التمثيل/الإدارة', defaultWidth: 85, defaultVisible: false },
    { key: 'car', label: 'بدل السيارة/إضافي', defaultWidth: 85, defaultVisible: false },
    { key: 'perfFixed', label: 'مكافأة الأداء الثابتة', defaultWidth: 85, defaultVisible: false },
    { key: 'otherBonus', label: 'مكافأة أخرى/سنوية', defaultWidth: 85, defaultVisible: false },
    { key: 'overtime', label: 'العمل الإضافي', defaultWidth: 80, defaultVisible: false },
    { key: 'grossSalary', label: 'إجمالي الراتب', defaultWidth: 80, defaultVisible: true },
    { key: 'totalDeductions', label: 'خصومات الراتب', defaultWidth: 85, defaultVisible: true },
    { key: 'netSalary', label: 'الراتب الصافي', defaultWidth: 85, defaultVisible: true },
    { key: 'actualDays', label: 'أيام الحضور', defaultWidth: 60, defaultVisible: true },
    { key: 'actualHours', label: 'ساعات الحضور', defaultWidth: 70, defaultVisible: true },
    { key: 'absentDays', label: 'أيام الغياب', defaultWidth: 60, defaultVisible: true },
    { key: 'paidLeaveDays', label: 'إجازة مدفوعة', defaultWidth: 70, defaultVisible: false },
    { key: 'unpaidLeaveDays', label: 'إجازة بدون راتب', defaultWidth: 75, defaultVisible: false },
    { key: 'earnedNet', label: 'المستحق', defaultWidth: 80, defaultVisible: true },
    { key: 'monthDeductTotal', label: 'خصومات شهرية', defaultWidth: 80, defaultVisible: true },
    { key: 'loanDeductTotal', label: 'أقساط سلف', defaultWidth: 75, defaultVisible: true },
    { key: 'perfBonusAmt', label: '⭐ مكافأة الأداء', defaultWidth: 85, defaultVisible: true },
    { key: 'finalNet', label: 'الصافي النهائي', defaultWidth: 90, defaultVisible: true },
    { key: 'calcNote', label: 'ملاحظة الاحتساب', defaultWidth: 250, defaultVisible: true }
];

// قراءة إعدادات المسير (أو الافتراضية)
function getPayrollSettings(payrollKey) {
    const p = payrolls[payrollKey];
    const saved = p?.displaySettings;
    return {
        fontSize: saved?.fontSize ?? 11,
        cols: PAYROLL_COLUMNS.map(c => ({
            ...c,
            width: saved?.cols?.[c.key]?.width ?? c.defaultWidth,
            visible: saved?.cols?.[c.key]?.visible ?? c.defaultVisible
        }))
    };
}

// فتح مودال الإعدادات
window.openPayrollSettings = function (payrollKey) {
    $('mpsPayrollKey').value = payrollKey;
    const settings = getPayrollSettings(payrollKey);
    $('mpsFontSize').value = settings.fontSize;
    $('mpsFontSizeVal').textContent = settings.fontSize + 'px';
    const container = $('mpsColsList');
    container.innerHTML = settings.cols.map(c => `
        <div style="display:flex;align-items:center;gap:10px;padding:8px 12px;background:white;border:1px solid #e0e8f0;border-radius:8px">
            <label style="display:flex;align-items:center;gap:8px;flex:1;cursor:pointer">
                <input type="checkbox" data-col-key="${c.key}" class="mps-vis" ${c.visible?'checked':''} style="width:16px;height:16px;cursor:pointer">
                <span style="font-size:13px;color:#1a3a5c;font-weight:600">${c.label}</span>
            </label>
            <div style="display:flex;align-items:center;gap:6px">
                <span style="font-size:11px;color:#888">العرض:</span>
                <input type="number" data-col-key="${c.key}" class="mps-width" value="${c.width}" min="30" max="400" step="5" style="width:70px;padding:5px 8px;border:1px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;text-align:center">
                <span style="font-size:10px;color:#888">px</span>
            </div>
        </div>
    `).join('');
    ov('mPayrollSettings');
};

// حفظ الإعدادات
window.savePayrollSettings = async function () {
    const payrollKey = $('mpsPayrollKey').value; if (!payrollKey) return;
    const fontSize = parseFloat($('mpsFontSize').value) || 11;
    const cols = {};
    document.querySelectorAll('.mps-vis').forEach(inp => {
        const k = inp.dataset.colKey;
        cols[k] = { visible: inp.checked };
    });
    document.querySelectorAll('.mps-width').forEach(inp => {
        const k = inp.dataset.colKey;
        cols[k] = { ...cols[k], width: parseInt(inp.value) || 80 };
    });
    try {
        await update(ref(db, `ledger/payrolls/${payrollKey}`), { displaySettings: { fontSize, cols } });
        cov('mPayrollSettings');
        toast('✅ تم حفظ الإعدادات', 'ok');
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// إعادة الافتراضي
window.resetPayrollSettings = async function () {
    const payrollKey = $('mpsPayrollKey').value; if (!payrollKey) return;
    cf2('إعادة جميع إعدادات العرض للافتراضي؟', async () => {
        try {
            await update(ref(db, `ledger/payrolls/${payrollKey}`), { displaySettings: null });
            cov('mPayrollSettings');
            toast('🔄 تمت إعادة الافتراضي', 'ok');
        } catch (e) { toast('خطأ: ' + e.message, 'er') }
    });
};

// قيمة الخلية لعمود معين
// قيمة بند البدل من العنصر، أو اشتقاقها من بيانات الموظف الحالية للمسيرات القديمة
function prAllowVal(it, itemKey, finKey) {
    if (it[itemKey] != null) return it[itemKey];
    const e = emp[it.empKey];
    return e ? (empFinance(e)[finKey] || 0) : 0;
}
function getCellValue(col, it, idx) {
    switch (col.key) {
        case 'idx': return idx + 1;
        case 'name': return it.name || '';
        case 'job': return it.job || '';
        case 'dept': return it.dept || '';
        case 'iban': return it.iban || '';
        case 'basic': return prAllowVal(it, 'sal', 'sal');
        case 'house': return prAllowVal(it, 'house', 'house');
        case 'trans': return prAllowVal(it, 'trans', 'trans');
        case 'phone': return prAllowVal(it, 'phone', 'phone');
        case 'nature': return prAllowVal(it, 'nature', 'nature');
        case 'rep': return prAllowVal(it, 'rep', 'rep');
        case 'car': return prAllowVal(it, 'carAllow', 'car');
        case 'perfFixed': return prAllowVal(it, 'perf', 'perf');
        case 'otherBonus': return prAllowVal(it, 'bonus', 'bonus');
        case 'overtime': return prAllowVal(it, 'ot', 'ot');
        case 'grossSalary': return it.grossSalary || 0;
        case 'totalDeductions': return it.totalDeductions || 0;
        case 'netSalary': return it.netSalary || 0;
        case 'actualDays': return it.actualDays || 0;
        case 'actualHours': return it.actualHours || 0;
        case 'absentDays': return it.absentDays || 0;
        case 'paidLeaveDays': return it.paidLeaveDays || 0;
        case 'unpaidLeaveDays': return it.unpaidLeaveDays || 0;
        case 'earnedNet': return it.earnedNet || 0;
        case 'monthDeductTotal': return it.monthDeductTotal || 0;
        case 'loanDeductTotal': return it.loanDeductTotal || 0;
        case 'perfBonusAmt': return it.perfBonusAmt || 0;
        case 'finalNet': return it.finalNet != null ? it.finalNet : (it.earnedNet || 0);
        case 'calcNote': return it.calcNote || '';
        default: return '';
    }
}

// تصدير المسير إلى Excel
window.exportPayrollToExcel = function (payrollKey) {
    const p = payrolls[payrollKey]; if (!p) { toast('المسير غير موجود', 'er'); return }
    if (typeof XLSX === 'undefined') { toast('مكتبة Excel لم تُحمَّل بعد، حاول بعد ثوانٍ', 'er'); return }
    const settings = getPayrollSettings(payrollKey);
    const visibleCols = settings.cols.filter(c => c.visible);
    const items = p.items || [];

    // بناء البيانات
    const headers = visibleCols.map(c => c.label);
    const rows = items.map((it, i) => visibleCols.map(c => getCellValue(c, it, i)));
    // صف الإجمالي
    const totals = visibleCols.map(c => {
        if (c.key === 'idx') return 'الإجمالي';
        if (c.key === 'name' || c.key === 'job' || c.key === 'dept' || c.key === 'iban' || c.key === 'calcNote') return '';
        if (['grossSalary','totalDeductions','netSalary','earnedNet','monthDeductTotal','loanDeductTotal','perfBonusAmt','finalNet','actualHours','paidLeaveDays','unpaidLeaveDays','basic','house','trans','phone','nature','rep','car','perfFixed','otherBonus','overtime'].includes(c.key)) {
            return items.reduce((s, it) => s + (parseFloat(getCellValue(c, it, 0)) || 0), 0);
        }
        if (['actualDays','absentDays'].includes(c.key)) {
            return items.reduce((s, it) => s + (parseFloat(getCellValue(c, it, 0)) || 0), 0);
        }
        return '';
    });

    // ميتاداتا في الأعلى
    const metadata = [
        [`مسير رواتب ${formatMonthLabel(p.month)}`],
        [`الحالة: ${p.status === 'approved' ? 'معتمد' : p.status === 'review' ? 'قيد المراجعة' : 'مسودة'}`],
        [`عدد الموظفين: ${p.totalEmployees || items.length}`],
        [`إجمالي الرواتب: ${fmt(p.totalGross)} ريال`],
        [`الصافي النهائي: ${fmt(p.totalNet)} ريال`],
        [`أُنشئ بواسطة: ${p.createdByName || '-'} | ${p.createdAt ? new Date(p.createdAt).toLocaleDateString('ar-SA') : '-'}`],
        [`روجع بواسطة: ${p.reviewByName || 'لم تتم المراجعة'} | ${p.reviewAt ? new Date(p.reviewAt).toLocaleDateString('ar-SA') : ''}`],
        [`اعتُمد بواسطة: ${p.approvedByName || 'لم يُعتمد'} | ${p.approvedAt ? new Date(p.approvedAt).toLocaleDateString('ar-SA') : ''}`],
        []
    ];

    const aoa = [...metadata, headers, ...rows, totals];
    const ws = XLSX.utils.aoa_to_sheet(aoa);

    // ضبط عرض الأعمدة
    ws['!cols'] = visibleCols.map(c => ({ wpx: c.width }));

    // محاذاة RTL
    ws['!sheetView'] = [{ rightToLeft: true }];

    // دمج خلايا الميتاداتا (تشمل عرض كامل الجدول)
    const lastCol = visibleCols.length - 1;
    ws['!merges'] = ws['!merges'] || [];
    for (let i = 0; i < 8; i++) {
        ws['!merges'].push({ s: { r: i, c: 0 }, e: { r: i, c: lastCol } });
    }

    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, `مسير ${p.month}`);
    const filename = `مسير_رواتب_${p.month || 'unknown'}.xlsx`;
    XLSX.writeFile(wb, filename);
    toast('✅ تم تصدير الملف', 'ok');
};

// ── 📤 [HR-WPS] ملف حماية الأجور (WPS / مِدد) — من مسير معتمد ──
// يولّد ملف SIF مبسّطاً (CSV بترميز UTF-8 + BOM) يرفعه صاحب العمل لمنصّة مِدد/البنك.
window.openWpsSettings = function (payrollKey) {
    const w = (cfg && cfg.wps) || {};
    let ov = document.getElementById('wpsSetOverlay'); if (!ov) { ov = document.createElement('div'); ov.id = 'wpsSetOverlay'; document.body.appendChild(ov); }
    ov.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.5);display:flex;align-items:center;justify-content:center;z-index:99999;padding:16px';
    const inp = (id, label, val, ph) => `<div style="margin-bottom:10px"><label style="font-size:12px;font-weight:700;color:#555;display:block;margin-bottom:4px">${label}</label><input id="${id}" value="${(val || '').toString().replace(/"/g, '&quot;')}" placeholder="${ph || ''}" style="width:100%;padding:9px;border:1.5px solid #ccc;border-radius:8px;font-family:inherit"></div>`;
    ov.innerHTML = `<div dir="rtl" style="background:#fff;border-radius:16px;max-width:520px;width:100%;max-height:90vh;overflow:auto;box-shadow:0 20px 60px rgba(0,0,0,.35)">
        <div style="background:linear-gradient(135deg,#5b2c6f,#8e44ad);color:#fff;padding:15px 20px;border-radius:16px 16px 0 0;display:flex;justify-content:space-between;align-items:center"><b>📤 إعدادات ملف حماية الأجور (WPS/مِدد)</b><button onclick="document.getElementById('wpsSetOverlay').remove()" style="border:0;background:rgba(255,255,255,.2);color:#fff;width:30px;height:30px;border-radius:50%;cursor:pointer;font-size:15px">✕</button></div>
        <div style="padding:20px">
            <div style="font-size:11px;color:#888;margin-bottom:14px">بيانات المنشأة المطلوبة في ملف حماية الأجور — تُحفظ مرة واحدة وتُدرَج تلقائياً في كل ملف.</div>
            ${inp('wps-estab', 'رقم المنشأة (وزارة الموارد البشرية)', w.establishmentId, 'مثال: 1-2345678')}
            ${inp('wps-mol', 'رقم مكتب العمل (MOL)', w.molNumber, '')}
            ${inp('wps-empname', 'اسم المنشأة (كما لدى البنك)', w.employerName || (cfg && cfg.companyAr) || '', '')}
            ${inp('wps-bank', 'بنك صرف الرواتب', w.employerBank, 'مثال: الراجحي')}
            ${inp('wps-iban', 'آيبان حساب المنشأة', w.employerIban, 'SA...')}
            <div style="display:flex;gap:8px;margin-top:8px">
                <button class="btn b-g" onclick="saveWpsSettings(${payrollKey ? `'${payrollKey}'` : 'null'})" style="flex:1">💾 حفظ${payrollKey ? ' وتوليد الملف' : ''}</button>
                <button class="btn" onclick="document.getElementById('wpsSetOverlay').remove()" style="background:#ecf0f1;color:#555">إلغاء</button>
            </div>
        </div></div>`;
};
window.saveWpsSettings = async function (payrollKey) {
    const data = {
        establishmentId: document.getElementById('wps-estab')?.value.trim() || '',
        molNumber: document.getElementById('wps-mol')?.value.trim() || '',
        employerName: document.getElementById('wps-empname')?.value.trim() || '',
        employerBank: document.getElementById('wps-bank')?.value.trim() || '',
        employerIban: document.getElementById('wps-iban')?.value.trim() || '',
    };
    try {
        await update(ref(db, 'ledger/settings/wps'), data);
        cfg = cfg || {}; cfg.wps = { ...(cfg.wps || {}), ...data };
        toast('تم حفظ إعدادات WPS ✓', 'ok');
        document.getElementById('wpsSetOverlay')?.remove();
        if (payrollKey) setTimeout(() => exportPayrollWPS(payrollKey), 200);
    } catch (e) { toast('خطأ: ' + e.message, 'er'); }
};
window.exportPayrollWPS = function (payrollKey) {
    const p = payrolls[payrollKey]; if (!p) { toast('المسير غير موجود', 'er'); return; }
    const w = (cfg && cfg.wps) || {};
    if (!w.establishmentId && !w.employerIban) { toast('⚙️ أدخل بيانات المنشأة لملف WPS أولاً', 'wn'); openWpsSettings(payrollKey); return; }
    const items = p.items || [];
    if (!items.length) { toast('لا يوجد موظفون في هذا المسير', 'er'); return; }

    const r1 = v => Math.round((parseFloat(v) || 0) * 100) / 100;
    const missing = [];
    const recs = items.map((it, i) => {
        const e = (emp || {})[it.empKey] || {};
        const basic = r1(e.salary), housing = r1(e.houseAllow);
        const gross = r1(it.grossSalary);
        const other = r1(gross - basic - housing);
        const ded = r1(it.totalDeductions);
        const net = r1(it.finalNet != null ? it.finalNet : it.netSalary);
        const iban = (it.iban || e.iban || '').replace(/\s/g, '');
        const natId = e.natId || '';
        if (!iban || !natId) missing.push(it.name || e.name || `#${i + 1}`);
        return [i + 1, natId, it.name || e.name || '', iban, e.bankName || '', basic, housing, other, gross, ded, net, it.actualDays != null ? it.actualDays : ''];
    });
    const totNet = recs.reduce((s, r) => s + (parseFloat(r[10]) || 0), 0);

    const meta = [
        ['ملف حماية الأجور (WPS) — ' + (w.employerName || (cfg && cfg.companyAr) || 'المنشأة')],
        ['رقم المنشأة (وزارة الموارد)', w.establishmentId || ''],
        ['رقم مكتب العمل (MOL)', w.molNumber || ''],
        ['بنك المنشأة', w.employerBank || ''],
        ['آيبان المنشأة', w.employerIban || ''],
        ['شهر الرواتب', p.month || ''],
        ['عدد الموظفين', recs.length],
        ['إجمالي صافي الرواتب', r1(totNet)],
        ['تاريخ التوليد', new Date().toISOString().slice(0, 10)],
        [],
    ];
    const header = ['م', 'رقم الهوية/الإقامة', 'اسم الموظف', 'آيبان الموظف', 'البنك', 'الراتب الأساسي', 'بدل السكن', 'بدلات/تعديلات أخرى', 'إجمالي المستحقات', 'الاستقطاعات', 'صافي الراتب', 'أيام العمل'];
    const aoa = [...meta, header, ...recs];
    const csv = aoa.map(r => r.map(c => `"${String(c == null ? '' : c).replace(/"/g, '""')}"`).join(',')).join('\r\n');
    const blob = new Blob(['﻿' + csv], { type: 'text/csv;charset=utf-8' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `WPS_حماية_الأجور_${p.month || 'unknown'}.csv`;
    a.click();
    if (typeof logAudit === 'function') logAudit('wps_export', 'payroll', `توليد ملف WPS لمسير ${p.month}`, { count: recs.length });
    if (missing.length) toast(`⚠️ تم التوليد — لكن ${missing.length} موظف بلا آيبان/هوية: ${missing.slice(0, 3).join('، ')}${missing.length > 3 ? '…' : ''}`, 'wn', 8000);
    else toast('✅ تم توليد ملف حماية الأجور (WPS)', 'ok');
};

