// إظهار بطاقة المسؤول
function initAttendanceAdminCard() {
    if (myP?.role === 'admin' || can('manage_attendance')) {
        const card = $('atAdminCard');
        if (card) card.style.display = 'block';
        const bulkCard = $('atBulkCard');
        if (bulkCard) bulkCard.style.display = 'block';
        fillAtAdminEmpSelect();
        fillBulkEmpsList();
        const d = $('atAdminDate'); if (d && !d.value) d.value = today();
        const bm = $('atBulkMonth'); if (bm && !bm.value) {
            const n = new Date();
            bm.value = `${n.getFullYear()}-${String(n.getMonth() + 1).padStart(2, '0')}`;
        }
    }
}

// ── التحضير الشهري الجماعي ─────────────────
function fillBulkEmpsList() {
    const container = $('atBulkEmpsList'); if (!container) return;
    const activeEmps = Object.entries(emp).filter(([, e]) => e.status !== 'inactive');
    if (!activeEmps.length) {
        container.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:20px;color:#888;font-size:13px">لا يوجد موظفون نشطون</div>';
        return;
    }
    activeEmps.sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar'));
    container.innerHTML = activeEmps.map(([k, e]) => `
        <label style="display:flex;align-items:center;gap:8px;padding:8px 10px;background:white;border-radius:6px;border:1px solid #e0e8f0;cursor:pointer;transition:all .15s" onmouseover="this.style.borderColor='#9b59b6'" onmouseout="this.style.borderColor='#e0e8f0'">
            <input type="checkbox" data-emp-id="${k}" data-emp-name="${(e.name||'').replace(/"/g,'&quot;')}" class="bulk-emp-cb" onchange="updateBulkSelectedCount()" style="width:16px;height:16px;cursor:pointer">
            <div style="flex:1;min-width:0;overflow:hidden">
                <div style="font-size:13px;font-weight:700;color:#1a3a5c;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${e.name || '-'}</div>
                <div style="font-size:10px;color:#888;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${e.job || ''}${e.dept ? ' · ' + e.dept : ''}</div>
            </div>
        </label>
    `).join('');
    updateBulkSelectedCount();
}

window.updateBulkSelectedCount = function () {
    const cnt = document.querySelectorAll('.bulk-emp-cb:checked').length;
    const lbl = $('bulkSelectedCount');
    if (lbl) lbl.textContent = `${cnt} موظف محدد`;
};

window.bulkSelectAllEmps = function (selectAll) {
    document.querySelectorAll('.bulk-emp-cb').forEach(cb => cb.checked = selectAll);
    updateBulkSelectedCount();
};

window.doBulkMonthlyAttendance = async function () {
    const month = $('atBulkMonth')?.value;
    const ci = $('atBulkCheckIn')?.value;
    const co = $('atBulkCheckOut')?.value;
    const skipMode = $('atBulkSkipWeekend')?.value || 'fri_sat';
    const status = $('atBulkStatus');
    if (!month) { status.textContent = '⚠️ اختر الشهر'; return }
    if (!ci || !co) { status.textContent = '⚠️ أدخل وقتي الدخول والخروج'; return }
    const selected = Array.from(document.querySelectorAll('.bulk-emp-cb:checked'));
    if (!selected.length) { status.textContent = '⚠️ اختر موظفاً واحداً على الأقل'; return }

    // حساب أيام الشهر
    const [y, m] = month.split('-').map(Number);
    const lastDay = new Date(y, m, 0).getDate();
    const dates = [];
    for (let d = 1; d <= lastDay; d++) {
        const dt = new Date(y, m - 1, d);
        const dow = dt.getDay(); // 0=Sun, 5=Fri, 6=Sat
        let skip = false;
        if (skipMode === 'fri_sat' && (dow === 5 || dow === 6)) skip = true;
        else if (skipMode === 'fri' && dow === 5) skip = true;
        else if (skipMode === 'sat_sun' && (dow === 6 || dow === 0)) skip = true;
        if (!skip) dates.push(`${y}-${String(m).padStart(2,'0')}-${String(d).padStart(2,'0')}`);
    }

    // تأكيد
    const totalOps = selected.length * dates.length;
    const confirmed = await new Promise(resolve => {
        cf2(`سيتم محاولة تحضير ${selected.length} موظف لـ ${dates.length} يوم عمل (إجمالي ${totalOps} عملية محتملة). متابعة؟`,
            () => resolve(true), () => resolve(false));
    });
    if (!confirmed) { status.textContent = ''; return }

    status.textContent = '⏳ جارٍ التنفيذ... قد يستغرق ثوانٍ';
    let created = 0, skipped = 0, errors = 0;
    // تجهيز batch update
    const batchUpd = {};
    for (const cb of selected) {
        const empId = cb.dataset.empId;
        const empName = cb.dataset.empName;
        // اجلب إجازات الموظف المعتمدة في هذا الشهر
        const empLeaves = Object.values(leaves).filter(lv =>
            lv.empKey === empId && lv.status === 'approved'
        );
        for (const dateStr of dates) {
            // تخطي إذا يوجد سجل حضور
            const exists = Object.values(attendance).some(a => a.employeeId === empId && a.date === dateStr);
            if (exists) { skipped++; continue }
            // تخطي إذا الموظف في إجازة معتمدة في هذا اليوم
            const onLeave = empLeaves.some(lv => dateStr >= lv.from && dateStr <= lv.to);
            if (onLeave) { skipped++; continue }
            // أنشئ السجل
            const ciISO = new Date(dateStr + 'T' + ci).toISOString();
            const coISO = new Date(dateStr + 'T' + co).toISOString();
            const hrs = parseFloat(((new Date(coISO) - new Date(ciISO)) / (1000 * 60 * 60)).toFixed(2));
            const newKey = push(R.att).key;
            batchUpd['ledger/attendance/' + newKey] = {
                employeeId: empId, employeeName: empName,
                date: dateStr, checkIn: ciISO, checkOut: coISO,
                totalHours: hrs, bulkGenerated: true,
                addedBy: curU?.uid || '', addedByName: myP?.name || ''
            };
            created++;
        }
    }
    try {
        if (Object.keys(batchUpd).length) await update(ref(db), batchUpd);
        status.innerHTML = `✅ تم بنجاح: <strong>${created}</strong> سجل جديد | ⏭️ تخطي: <strong>${skipped}</strong>${errors>0?` | ❌ أخطاء: <strong>${errors}</strong>`:''}`;
        toast(`✅ تم إنشاء ${created} سجل حضور`, 'ok', 5000);
        bulkSelectAllEmps(false);
    } catch (e) {
        status.textContent = '❌ خطأ: ' + e.message;
        toast('خطأ: ' + e.message, 'er');
    }
};

