// ملء قائمة الموظفين في بطاقة الإضافة اليدوية
function fillAtAdminEmpSelect() {
    const sel = $('atAdminEmp'); if (!sel) return;
    const cur = sel.value;
    sel.innerHTML = '<option value="">-- اختر موظفاً --</option>';
    Object.entries(emp).sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar'))
        .forEach(([id, e]) => {
            if (e.status !== 'inactive')
                sel.innerHTML += `<option value="${id}|${e.name || ''}">${e.name || id}</option>`;
        });
    if (cur) sel.value = cur;
}

// تسجيل حضور موظف يدوياً بواسطة المسؤول
window.doAdminAddAttendance = async function () {
    const empVal = $('atAdminEmp')?.value;
    const dateVal = $('atAdminDate')?.value;
    const ciVal = $('atAdminCheckIn')?.value;
    const coVal = $('atAdminCheckOut')?.value;
    const statusDiv = $('atAdminStatus');
    if (!empVal) { statusDiv.textContent = '⚠️ اختر موظفاً'; return }
    if (!dateVal) { statusDiv.textContent = '⚠️ اختر التاريخ'; return }
    if (!ciVal) { statusDiv.textContent = '⚠️ أدخل وقت الدخول'; return }
    const [empId, empName] = empVal.split('|');
    const dup = Object.values(attendance).find(a => a.employeeId === empId && a.date === dateVal);
    if (dup) { statusDiv.textContent = '⚠️ يوجد سجل مسبق لهذا الموظف في هذا التاريخ'; return }
    const checkInISO = new Date(dateVal + 'T' + ciVal).toISOString();
    let checkOutISO = null, totalHours = 0;
    if (coVal) {
        checkOutISO = new Date(dateVal + 'T' + coVal).toISOString();
        totalHours = parseFloat(((new Date(checkOutISO) - new Date(checkInISO)) / (1000 * 60 * 60)).toFixed(2));
        if (totalHours < 0) { statusDiv.textContent = '⚠️ وقت الخروج قبل وقت الدخول!'; return }
    }
    try {
        await push(R.att, { employeeId: empId, employeeName: empName, date: dateVal, checkIn: checkInISO, checkOut: checkOutISO, totalHours, addedBy: curU?.uid || '', addedByName: myP?.name || '' });
        statusDiv.textContent = `✅ تم تسجيل حضور ${empName} بنجاح`;
        toast(`✅ تم تسجيل حضور ${empName}`, 'ok');
        if ($('atAdminCheckIn')) $('atAdminCheckIn').value = '';
        if ($('atAdminCheckOut')) $('atAdminCheckOut').value = '';
        if ($('atAdminEmp')) $('atAdminEmp').value = '';
    } catch (e) { statusDiv.textContent = '❌ خطأ: ' + e.message; toast('خطأ: ' + e.message, 'er') }
};

// تسجيل دخول المستخدم الحالي
// البحث عن سجل الموظف المرتبط بالمستخدم الحالي
function findCurrentEmpRecord() {
    if (!curU) return null;
    // ابحث بـ userId أو بالـ email
    const entry = Object.entries(emp).find(([, e]) =>
        e.userId === curU.uid || (e.email && e.email.toLowerCase() === (curU.email || '').toLowerCase())
    );
    if (!entry) return null;
    return { key: entry[0], data: entry[1] };
}

// 📍 التقاط الموقع الجغرافي (أفضل جهد — لا يعطّل التسجيل إن رُفض/تعذّر)
function getGeoLoc(timeoutMs = 8000) {
    return new Promise(resolve => {
        if (!navigator.geolocation) return resolve(null);
        navigator.geolocation.getCurrentPosition(
            pos => resolve({ lat: +pos.coords.latitude.toFixed(6), lng: +pos.coords.longitude.toFixed(6), acc: Math.round(pos.coords.accuracy || 0) }),
            () => resolve(null),
            { enableHighAccuracy: true, timeout: timeoutMs, maximumAge: 60000 }
        );
    });
}
function geoLink(loc) { return loc && loc.lat != null ? `<a href="https://www.google.com/maps?q=${loc.lat},${loc.lng}" target="_blank" rel="noopener" title="عرض موقع التسجيل على الخريطة (دقة ~${loc.acc}م)" style="color:#2980b9;font-weight:700;font-size:11px">📍</a>` : ''; }

window.doCheckIn = async function () {
    const setSt = t => { const el = $('atStatus'); if (el) el.textContent = t; };
    if (!curU) { toast('يجب تسجيل الدخول أولاً', 'er'); return }
    const myEmpRec = findCurrentEmpRecord();
    if (!myEmpRec) { setSt('⚠️ حسابك غير مرتبط بسجل موظف. تواصل مع شؤون الموظفين'); toast('⚠️ حسابك غير مرتبط بسجل موظف', 'er'); return }
    const todayStr = today();
    const existing = Object.values(attendance).find(a => a.employeeId === myEmpRec.key && a.date === todayStr);
    if (existing) { setSt('⚠️ تم تسجيل دخولك مسبقاً اليوم'); toast('⚠️ تم تسجيل دخولك مسبقاً اليوم', 'er'); return }
    try {
        setSt('📍 جارٍ تحديد الموقع...');
        const loc = await getGeoLoc();
        await push(R.att, { employeeId: myEmpRec.key, employeeName: myEmpRec.data.name || myP?.name || '', date: todayStr, checkIn: new Date().toISOString(), checkOut: null, totalHours: 0, checkInLoc: loc || null });
        setSt('✅ تم تسجيل الدخول في ' + new Date().toLocaleTimeString('ar-SA') + (loc ? ' · 📍 تم تسجيل الموقع' : ' · ⚠️ تعذّر الموقع'));
        toast('✅ تم تسجيل الدخول' + (loc ? ' مع الموقع' : ''), 'ok');
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

// تسجيل خروج المستخدم الحالي
window.doCheckOut = async function () {
    const setSt = t => { const el = $('atStatus'); if (el) el.textContent = t; };
    if (!curU) { toast('يجب تسجيل الدخول أولاً', 'er'); return }
    const myEmpRec = findCurrentEmpRecord();
    if (!myEmpRec) { setSt('⚠️ حسابك غير مرتبط بسجل موظف'); toast('⚠️ حسابك غير مرتبط بسجل موظف', 'er'); return }
    const todayStr = today();
    const entry = Object.entries(attendance).find(([, a]) => a.employeeId === myEmpRec.key && a.date === todayStr);
    if (!entry) { setSt('⚠️ لم يتم تسجيل دخولك اليوم'); toast('⚠️ لم يتم تسجيل دخولك اليوم', 'er'); return }
    const [key, data] = entry;
    if (data.checkOut) { setSt('⚠️ تم تسجيل خروجك مسبقاً اليوم'); toast('⚠️ تم تسجيل خروجك مسبقاً اليوم', 'er'); return }
    try {
        setSt('📍 جارٍ تحديد الموقع...');
        const loc = await getGeoLoc();
        const checkOutTime = new Date().toISOString();
        const hours = parseFloat(((new Date(checkOutTime) - new Date(data.checkIn)) / (1000 * 60 * 60)).toFixed(2));
        await update(ref(db, 'ledger/attendance/' + key), { checkOut: checkOutTime, totalHours: hours, checkOutLoc: loc || null });
        setSt('🚪 تم تسجيل الخروج في ' + new Date(checkOutTime).toLocaleTimeString('ar-SA') + ' | المجموع: ' + hours.toFixed(2) + ' س' + (loc ? ' · 📍' : ''));
        toast('✅ تم تسجيل الخروج', 'ok');
    } catch (e) { toast('خطأ: ' + e.message, 'er') }
};

