// تبديل تابات صفحة المشاريع
window.switchPrjDashTab = function (tab) {
    document.querySelectorAll('.prjdash-tab-btn').forEach(b => {
        const isActive = b.getAttribute('data-tab') === tab;
        b.style.background = isActive ? '#2d6a9f' : '#f8fafc';
        b.style.color = isActive ? 'white' : '#1a3a5c';
    });
    const overviewEl = document.getElementById('prjDashTab-overview');
    const docsEl = document.getElementById('prjDashTab-docs');
    if (overviewEl) overviewEl.style.display = tab === 'overview' ? '' : 'none';
    if (docsEl) docsEl.style.display = tab === 'docs' ? '' : 'none';
    if (tab === 'overview') renderProjectsDashboard();
};

window.switchProjectsTab = function (tab) {
    document.querySelectorAll('.prj-tab-btn').forEach(b => {
        const isActive = b.getAttribute('data-tab') === tab;
        b.style.background = isActive ? '#2d6a9f' : '#f8fafc';
        b.style.color = isActive ? 'white' : '#1a3a5c';
    });
    const listEl    = document.getElementById('prjTab-list');
    const accEl     = document.getElementById('prjTab-acc');
    const billAccEl = document.getElementById('prjTab-billacc');
    if (listEl)    listEl.style.display    = tab === 'list'    ? '' : 'none';
    if (accEl)     accEl.style.display     = tab === 'acc'     ? '' : 'none';
    if (billAccEl) billAccEl.style.display = tab === 'billacc' ? '' : 'none';
    if (tab === 'acc')     renderProjectsAccountingTab();
    if (tab === 'billacc') renderBillingAccTab();
};

// رسم تاب إعدادات المحاسبة
window.renderProjectsAccountingTab = function () {
    const container = $('prjTab-acc'); if (!container) return;
    const accounts = Object.values(window.chartOfAccounts || {})
        .filter(a => a.nature !== 'header' && a.active !== false)
        .sort((a, b) => (a.code || '').localeCompare(b.code || ''));

    // المشاريع
    const projs = Object.entries(window.projects || {})
        .sort((a, b) => (a[1].name || '').localeCompare(b[1].name || ''));

    // الإعدادات الحالية (من Firebase أو من window)
    const settings = window.payrollAccSettings || {};
    const defaults = settings._default || {};

    // حسابات حسب النوع لاقتراحات سريعة
    const expenseAccs = accounts.filter(a => a.type === 'expense');
    const liabAccs = accounts.filter(a => a.type === 'liability');
    const assetAccs = accounts.filter(a => a.type === 'asset');

    const buildOpts = (arr, selected) => {
        return '<option value="">-- استخدم الافتراضي --</option>' +
            arr.map(a => `<option value="${a.code}" ${a.code === selected ? 'selected' : ''}>${a.code} — ${a.nameAr}</option>`).join('');
    };
    const buildOptsAll = selected => {
        return '<option value="">-- استخدم الافتراضي --</option>' +
            accounts.map(a => `<option value="${a.code}" ${a.code === selected ? 'selected' : ''}>${a.code} — ${a.nameAr} <span style="font-size:9px">(${a.type})</span></option>`).join('');
    };

    container.innerHTML = `
        <!-- Hero -->
        <div style="background:linear-gradient(135deg,#5b2c6f 0%,#8e44ad 100%);border-radius:16px;padding:20px;margin-bottom:18px;color:white;box-shadow:0 6px 20px rgba(142,68,173,.25)">
            <div>
                <div style="font-size:11px;opacity:.85;letter-spacing:1px">PAYROLL ACCOUNTS MAPPING</div>
                <h1 style="margin:4px 0 0;font-size:22px;font-weight:900">🔗 إعدادات المحاسبة لمسير الرواتب</h1>
                <p style="margin:6px 0 0;font-size:12px;opacity:.95">حدد الحسابات المحاسبية المرتبطة بكل مشروع — يتم استخدامها تلقائياً عند اعتماد المسير</p>
            </div>
        </div>

        <!-- الإعدادات الافتراضية -->
        <div class="card" style="margin-bottom:14px;border-right:5px solid #f39c12">
            <div style="display:flex;align-items:center;gap:10px;margin-bottom:12px;flex-wrap:wrap">
                <div style="font-size:16px;font-weight:800;color:#7d4e00">⚙️ القاعدة الافتراضية (لكل المسيرات بدون مشروع محدد)</div>
                <span style="background:#f39c12;color:white;font-size:10px;padding:3px 8px;border-radius:6px;font-weight:700">الأهم</span>
            </div>
            <div style="background:#fef9e7;border-radius:8px;padding:14px;font-size:12px;color:#7d4e00;margin-bottom:14px">
                💡 هذه الحسابات تُستخدم للموظفين الذين <strong>ليس لديهم مشروع محدد</strong> أو إذا لم تُحدد إعدادات للمشروع المعين.
            </div>
            ${renderAccSettingsRow('_default', 'الافتراضي', defaults, expenseAccs, liabAccs, assetAccs, buildOpts, buildOptsAll)}
        </div>

        ${projs.length === 0 ? `
        <div class="card" style="text-align:center;padding:40px">
            <div style="font-size:60px;margin-bottom:12px">📁</div>
            <div style="font-size:15px;color:#888">لا توجد مشاريع — أضف مشاريع من تاب "📁 قائمة المشاريع" أولاً</div>
        </div>
        ` : `
        <!-- إعدادات كل مشروع -->
        <div class="card">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;flex-wrap:wrap;gap:10px">
                <div>
                    <div style="font-size:16px;font-weight:800;color:#1a3a5c">📁 إعدادات لكل مشروع (${projs.length} مشروع)</div>
                    <div style="font-size:11px;color:#666;margin-top:3px">اترك الحقل فارغاً لاستخدام الإعدادات الافتراضية</div>
                </div>
                <div style="display:flex;gap:6px;flex-wrap:wrap">
                    <button class="btn" onclick="savePayrollAccSettings()" style="background:#27ae60;color:white;padding:10px 20px;font-weight:800">💾 حفظ كل الإعدادات</button>
                </div>
            </div>

            ${projs.map(([pKey, p]) => {
                const projSettings = settings[pKey] || {};
                return `<div style="background:#f8fafc;border:1.5px solid #e0e8f0;border-radius:10px;padding:14px;margin-bottom:12px;border-right:4px solid #2d6a9f">
                    <div style="display:flex;align-items:center;gap:10px;margin-bottom:12px;flex-wrap:wrap">
                        <span style="background:#2d6a9f;color:white;padding:5px 12px;border-radius:8px;font-weight:800;font-size:13px">📁 ${p.name || pKey}</span>
                        ${p.status === 'active' ? '<span style="background:#27ae60;color:white;font-size:10px;padding:2px 8px;border-radius:5px;font-weight:700">⚙️ نشط</span>' : ''}
                        ${(projSettings.expenseAcc || projSettings.payableAcc || projSettings.loanAcc || projSettings.bonusAcc || projSettings.paymentAcc) ? '<span style="background:#27ae60;color:white;font-size:10px;padding:2px 8px;border-radius:5px;font-weight:700">✅ مُخصص</span>' : '<span style="background:#888;color:white;font-size:10px;padding:2px 8px;border-radius:5px">⚪ يستخدم الافتراضي</span>'}
                    </div>
                    ${renderAccSettingsRow(pKey, p.name || '', projSettings, expenseAccs, liabAccs, assetAccs, buildOpts, buildOptsAll)}
                </div>`;
            }).join('')}
        </div>
        `}

        <!-- زر حفظ كبير في الأسفل -->
        <div style="margin-top:14px;text-align:center">
            <button class="btn b-g" onclick="savePayrollAccSettings()" style="padding:14px 40px;font-size:15px;font-weight:800">💾 حفظ كل الإعدادات</button>
        </div>
    `;
};

function renderAccSettingsRow(key, label, sett, expenseAccs, liabAccs, assetAccs, buildOpts, buildOptsAll) {
    // 🆕 حسابات الصرف: الصندوق والبنوك (الأصول)
    // عادة أكواد 1110 (الصندوق) و 1120 (البنوك) و 11xx
    const paymentAccs = assetAccs.filter(a => {
        const code = a.code || '';
        // الصندوق + البنوك (1110-1199) + العهد
        return code.startsWith('111') || code.startsWith('112') || code.startsWith('113') ||
               (a.nameAr || '').includes('صندوق') ||
               (a.nameAr || '').includes('بنك') ||
               (a.nameAr || '').includes('عهدة');
    });

    return `<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:10px">
        <div>
            <label style="font-size:11px;color:#666;font-weight:700">💸 حساب مصروف الرواتب (مدين)</label>
            <select data-pas-key="${key}" data-pas-field="expenseAcc" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                ${buildOpts(expenseAccs, sett.expenseAcc)}
            </select>
        </div>
        <div>
            <label style="font-size:11px;color:#666;font-weight:700">💵 حساب الرواتب المستحقة (دائن)</label>
            <select data-pas-key="${key}" data-pas-field="payableAcc" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                ${buildOpts(liabAccs, sett.payableAcc)}
            </select>
        </div>
        <div>
            <label style="font-size:11px;color:#666;font-weight:700">💳 حساب أقساط السلف (دائن)</label>
            <select data-pas-key="${key}" data-pas-field="loanAcc" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                ${buildOpts(assetAccs, sett.loanAcc)}
            </select>
        </div>
        <div>
            <label style="font-size:11px;color:#666;font-weight:700">⭐ حساب مكافآت الأداء</label>
            <select data-pas-key="${key}" data-pas-field="bonusAcc" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                ${buildOptsAll(sett.bonusAcc)}
            </select>
        </div>
        <div style="grid-column:1/-1;background:#fef9e7;border:2px solid #f39c12;border-radius:8px;padding:10px;margin-top:6px">
            <label style="font-size:11px;color:#7d4e00;font-weight:800">🏦 حساب الدفع الافتراضي للرواتب (دائن في سند الصرف)</label>
            <select data-pas-key="${key}" data-pas-field="paymentAcc" style="width:100%;padding:8px;border:1.5px solid #f39c12;border-radius:6px;font-family:inherit;font-size:12px;margin-top:5px;background:white">
                ${buildOpts(paymentAccs, sett.paymentAcc)}
            </select>
            <div style="font-size:10px;color:#7d4e00;margin-top:5px">💡 الحساب الذي ستُسدَّد منه الرواتب (صندوق / بنك / عهدة) — يمكن تغييره عند الدفع</div>
        </div>
    </div>`;
}

// حفظ الإعدادات
window.savePayrollAccSettings = async function () {
    const selects = document.querySelectorAll('[data-pas-key]');
    const settings = {};
    selects.forEach(sel => {
        const key = sel.getAttribute('data-pas-key');
        const field = sel.getAttribute('data-pas-field');
        const val = sel.value;
        if (!settings[key]) settings[key] = {};
        if (val) settings[key][field] = val;
    });
    // إزالة الإعدادات الفارغة
    Object.keys(settings).forEach(k => {
        if (Object.keys(settings[k]).length === 0) settings[k] = null;
    });

    try {
        await set(ref(db, 'ledger/payrollAccSettings'), settings);
        toast('✅ تم حفظ الإعدادات — ستُطبَّق على القيود الجديدة', 'ok', 5000);
        window.payrollAccSettings = settings;
    } catch (e) {
        toast('❌ خطأ في الحفظ: ' + e.message, 'er');
    }
};

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🧾  BILLING → SALES INVOICE  —  تحويل المستخلص إلى فاتورة مبيعات       ║
// ╚══════════════════════════════════════════════════════════════════════════╝

// بناء بنود الفاتورة من بنود المستخلص
function buildInvoiceLinesFromBilling(b) {
    const items = (b.items || []).filter(it => (parseFloat(it.currentAmount) || 0) > 0);
    if (items.length > 0) {
        return items.map(it => ({
            description: it.description || `بند ${it.itemNo || ''}`,
            qty: parseFloat(it.currentQty) || 1,
            unit: it.unit || '',
            unitPrice: parseFloat(it.unitPrice) || 0,
            vatRate: parseFloat(b.vatPct) || 0,
            total: parseFloat(it.currentAmount) || 0
        }));
    }
    return [{
        description: `أعمال مستخلص ${b.billingNo || ''} — ${b.projectName || ''}`,
        qty: 1, unit: 'مستخلص',
        unitPrice: parseFloat(b.currentAmount) || 0,
        vatRate: parseFloat(b.vatPct) || 0,
        total: parseFloat(b.currentAmount) || 0
    }];
}

// تحويل المستخلص إلى فاتورة مبيعات
window.convertBillingToInvoice = async function (billingKey) {
    const b = window.progressBillings?.[billingKey];
    if (!b) { toast('المستخلص غير موجود', 'er'); return; }
    if (!['approved', 'paid'].includes(b.status)) { toast('اعتمد المستخلص أولاً', 'er'); return; }
    if (b.salesInvoiceKey) {
        const go = await cf2(`فاتورة موجودة (${b.salesInvoiceNumber}). فتح الفاتورة؟`);
        if (go && typeof viewSInv === 'function') viewSInv(b.salesInvoiceKey);
        return;
    }

    const proj = (window.projects || {})[b.projectId] || {};
    const now = new Date().toISOString();
    const userId = curU?.uid || '';

    // ── العميل مباشرةً من المشروع (الربط الإجباري الجديد) ──
    let customerId = proj.customerId || b.customerId || '';
    // fallback للمشاريع القديمة: ابحث بالاسم
    if (!customerId) {
        const clientName = b.clientName || proj.ownerName || proj.clientName || '';
        const customers = window.customers || {};
        customerId = Object.keys(customers).find(k =>
            (customers[k].nameAr || '').trim() === clientName.trim()
        ) || '';
    }
    const customerData = (window.customers || {})[customerId] || {};
    const clientName = customerData.nameAr || b.clientName || proj.ownerName || proj.clientName || '';

    const lines = buildInvoiceLinesFromBilling(b);
    const cur   = parseFloat(b.currentAmount) || 0;
    const vat   = parseFloat(b.vatAmount) || 0;
    const grand = cur + vat;

    const invNum = typeof generateSInvNumber === 'function'
        ? generateSInvNumber()
        : `INV-${new Date().getFullYear()}-${String(Object.keys(window.salesInvoices||{}).length+1).padStart(5,'0')}`;

    const invData = {
        number: invNum,
        date: b.billingDate || now.substring(0, 10),
        dueDate: '',
        customerId,
        customerName: clientName,
        clientAddress: customerData.address || proj.clientAddress || '',
        clientVATNumber: customerData.vatNumber || proj.clientVATNumber || '',
        projectId: b.projectId,
        reference: b.billingNo || '',
        subject: `مستخلص ${b.billingNo || ''} — ${b.projectName || proj.name || ''}`,
        lines,
        subTotal: cur, discount: 0,
        netBeforeTax: cur,
        vatTotal: vat,
        grandTotal: grand,
        paidAmount: 0,
        notes: `أُنشئت تلقائياً من مستخلص ${b.billingNo || billingKey}`,
        status: 'draft',
        billingKey,
        billingNo: b.billingNo || '',
        retentionAmount: parseFloat(b.retentionAmount) || 0,
        retentionPct: parseFloat(b.retentionPct) || 0,
        createdAt: now,
        createdBy: userId,
        updatedAt: now, updatedBy: userId
    };

    try {
        // إنشاء الفاتورة كمسودة
        const invRef = await push(R.sinv, invData);
        const invKey = invRef.key;

        // ترحيل الفاتورة فوراً (ينشئ قيد محاسبي تلقائي)
        if (typeof postSInv === 'function') {
            await postSInv(invKey);
        }

        // ربط الفاتورة بالمستخلص
        await update(ref(db, `ledger/progressBillings/${billingKey}`), {
            salesInvoiceKey: invKey,
            salesInvoiceNumber: invNum
        });

        toast(`✅ فاتورة ${invNum} أُنشئت وتم ترحيلها مع قيدها المحاسبي`, 'ok', 6000);
        if (typeof renderProgressBillings === 'function') renderProgressBillings();
    } catch (e) { toast('❌ ' + e.message, 'er'); }
};

// حذف فاتورة المستخلص مع قيدها
window.deleteBillingInvoice = async function (billingKey, invKey) {
    const inv = (window.salesInvoices || {})[invKey];
    if (!inv) { toast('الفاتورة غير موجودة', 'er'); return; }
    const confirmed = await cf2(
        `حذف فاتورة ${inv.number}؟\n\nسيتم:\n• إلغاء القيد المحاسبي ${inv.journalEntryNumber || ''}\n• حذف الفاتورة نهائياً\n• إلغاء الربط بالمستخلص`
    );
    if (!confirmed) return;
    try {
        const now = new Date().toISOString();
        // إلغاء القيد (لا نحذفه — نضع status=cancelled)
        if (inv.journalEntryKey) {
            await update(ref(db, `ledger/journalEntries/${inv.journalEntryKey}`), {
                status: 'cancelled',
                cancelledAt: now,
                cancelledBy: curU?.uid || '',
                cancelReason: `حذف فاتورة مستخلص ${inv.billingNo || ''}`
            });
        }
        // حذف الفاتورة
        await remove(ref(db, `ledger/salesInvoices/${invKey}`));
        // إلغاء الربط
        await update(ref(db, `ledger/progressBillings/${billingKey}`), {
            salesInvoiceKey: null, salesInvoiceNumber: null
        });
        toast('✅ تم حذف الفاتورة وإلغاء القيد', 'ok');
        if (typeof renderProgressBillings === 'function') renderProgressBillings();
    } catch (e) { toast('❌ ' + e.message, 'er'); }
};

// ── تاب إعدادات حسابات المستخلصات ───────────────────────────────────────
window.renderBillingAccTab = function () {
    const container = document.getElementById('prjTab-billacc'); if (!container) return;
    const projs = Object.entries(window.projects || {})
        .sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar'));
    const coa = window.chartOfAccounts || {};
    const hasCoA = Object.keys(coa).length > 0;

    container.innerHTML = `
    <div style="background:linear-gradient(135deg,#0e4d3a,#16a085);border-radius:16px;padding:20px;margin-bottom:18px;color:white">
        <div style="font-size:11px;opacity:.85;letter-spacing:1px">BILLING ACCOUNTS MAPPING</div>
        <h1 style="margin:4px 0 0;font-size:20px;font-weight:900">📒 إعدادات حسابات المستخلصات</h1>
        <p style="margin:6px 0 0;font-size:12px;opacity:.9">تُستخدم لإنشاء القيود المحاسبية تلقائياً عند اعتماد المستخلص أو تحصيله</p>
    </div>

    ${!hasCoA ? `<div class="card" style="text-align:center;padding:30px">
        <div style="font-size:40px;margin-bottom:10px">📋</div>
        <div style="font-size:14px;color:#888">شجرة الحسابات فارغة — أضف الحسابات من <button class="btn b-b" onclick="bcNav('chartofaccounts')" style="display:inline;padding:4px 10px;font-size:12px">🌳 شجرة الحسابات</button> أولاً</div>
    </div>` : ''}

    <div style="background:#e8f8f5;border:1.5px solid #16a085;border-radius:10px;padding:12px;margin-bottom:16px;font-size:12px;color:#0e6655;line-height:1.8">
        <strong>📘 القيود المُنشأة تلقائياً:</strong><br>
        <strong>عند الاعتماد:</strong> مدين ذمم مدينة + احتفاظ + استرداد دفعة مقدمة &nbsp;/&nbsp; دائن إيراد مقاولات + ضريبة قيمة مضافة<br>
        <strong>عند الدفع (paid):</strong> مدين نقدية / بنك &nbsp;/&nbsp; دائن ذمم مدينة
    </div>

    ${projs.length === 0 ? `<div class="card" style="text-align:center;padding:30px"><div style="font-size:14px;color:#888">لا توجد مشاريع</div></div>` : `
    <div style="display:flex;flex-direction:column;gap:14px">
        ${projs.map(([pKey, p]) => `
        <div class="card" style="border-right:4px solid #16a085">
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;flex-wrap:wrap">
                <span style="background:#16a085;color:white;padding:5px 14px;border-radius:8px;font-weight:800;font-size:13px">📁 ${p.name || pKey}</span>
                ${p.billingAccSettings ? '<span style="background:#27ae60;color:white;font-size:10px;padding:2px 8px;border-radius:5px;font-weight:700">✅ مُخصص</span>' : '<span style="background:#888;color:white;font-size:10px;padding:2px 8px;border-radius:5px">⚪ افتراضي</span>'}
            </div>
            <div id="bac-container-${pKey}"></div>
            <div style="margin-top:10px;display:flex;gap:8px;flex-wrap:wrap">
                <button class="btn b-g" onclick="saveBillingAccSettings('${pKey}')" style="padding:7px 18px;font-size:12px;font-weight:700">💾 حفظ</button>
                <button class="btn" onclick="renderBillingAccSettings('${pKey}','bac-container-${pKey}')" style="padding:7px 14px;font-size:12px;background:#f8fafc;color:#666;border:1.5px solid #d0d7e0">⚙️ تحميل الإعدادات</button>
            </div>
        </div>`).join('')}
    </div>`}`;

    // اعرض الإعدادات لكل مشروع
    projs.forEach(([pKey]) => {
        if (hasCoA) renderBillingAccSettings(pKey, `bac-container-${pKey}`);
    });
};

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   💸  دفع المسير وإنشاء سند صرف تلقائي                                     ║
// ╚══════════════════════════════════════════════════════════════════════════╝

window.openPayrollPaymentModal = function (payrollKey) {
    const p = window.payrolls?.[payrollKey];
    if (!p) { toast('⚠️ المسير غير موجود', 'er'); return; }
    if (p.status !== 'approved') { toast('⚠️ يجب اعتماد المسير أولاً', 'er'); return; }
    if (p.journalEntryStatus !== 'posted') {
        toast('⚠️ يجب ترحيل قيد المسير في قيود اليومية أولاً', 'wn', 6000);
        return;
    }
    if (p.paymentVoucherKey) {
        toast('⚠️ هذا المسير مدفوع بالفعل', 'wn');
        return;
    }

    // املأ المودال
    $('mPPPayrollKey').value = payrollKey;

    // توليد رقم سند صرف
    const voucherNumber = typeof generateVoucherNumber === 'function' ? generateVoucherNumber('payment') : ('PAY-' + Date.now());
    $('mPPNumber').value = voucherNumber;

    // التاريخ = اليوم
    $('mPPDate').value = new Date().toISOString().slice(0, 10);

    // 🆕 المبلغ يُقرأ من القيد الفعلي (إن وُجد) للتوافق مع أي تعديلات يدوية
    const payableInfo = getPayableAccountFromJournal(p);
    const totalNet = payableInfo.fromJournal ? payableInfo.totalCredit : (parseFloat(p.totalNet) || 0);
    $('mPPAmount').textContent = fmt(totalNet) + ' ر';
    $('mPPEmpsCount').textContent = `${p.totalEmployees || (p.items?.length || 0)} موظف${payableInfo.fromJournal && Math.abs(totalNet - (parseFloat(p.totalNet) || 0)) > 0.01 ? ' · 📝 مبلغ معدَّل من القيد' : ''}`;

    // الملخص
    const mLabel = formatMonthLabel(p.month);
    const scopeText = p.scope === 'project' ? `📁 ${p.projectName || ''}` :
                      p.scope === 'dept' ? `🏢 ${p.dept || ''}` :
                      '👥 جميع الموظفين';
    $('mPPSummary').innerHTML = `
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px">
            <div>
                <div style="font-size:11px;color:#0e6655;font-weight:700">مسير الرواتب</div>
                <div style="font-size:16px;font-weight:900;color:#1a3a5c;margin-top:3px">💵 ${mLabel}</div>
                <div style="font-size:11px;color:#0e6655;margin-top:3px">${scopeText} · ${p.totalEmployees || 0} موظف</div>
            </div>
            <div style="text-align:left">
                <div style="font-size:11px;color:#0e6655">القيد المرحَّل</div>
                <div style="font-size:13px;font-weight:800;color:#1a3a5c;font-family:monospace">${p.journalEntryNumber || ''}</div>
            </div>
        </div>
    `;

    // ملء قائمة حسابات الصرف (الصندوق + البنوك + العهد)
    const accounts = Object.values(window.chartOfAccounts || {})
        .filter(a => a.nature !== 'header' && a.active !== false && a.type === 'asset')
        .sort((a, b) => (a.code || '').localeCompare(b.code || ''));
    const paymentAccs = accounts.filter(a => {
        const code = a.code || '';
        return code.startsWith('111') || code.startsWith('112') || code.startsWith('113') ||
               (a.nameAr || '').includes('صندوق') ||
               (a.nameAr || '').includes('بنك') ||
               (a.nameAr || '').includes('عهدة');
    });

    // الحساب المقترح = حسب إعدادات المشروع
    const settings = window.payrollAccSettings || {};
    let suggestedAcc = '';
    let suggestionReason = '';
    if (p.scope === 'project' && p.projectId && settings[p.projectId]?.paymentAcc) {
        suggestedAcc = settings[p.projectId].paymentAcc;
        const acc = accounts.find(a => a.code === suggestedAcc);
        suggestionReason = `💡 الحساب المقترح حسب إعدادات مشروع "${p.projectName}": ${acc?.nameAr || ''}`;
    } else if (settings._default?.paymentAcc) {
        suggestedAcc = settings._default.paymentAcc;
        const acc = accounts.find(a => a.code === suggestedAcc);
        suggestionReason = `💡 الحساب الافتراضي للصرف: ${acc?.nameAr || ''}`;
    }

    const sel = $('mPPPaymentAccount');
    sel.innerHTML = '<option value="">-- اختر حساب الصرف --</option>' +
        paymentAccs.map(a => `<option value="${a.code}" ${a.code === suggestedAcc ? 'selected' : ''}>${a.code} — ${a.nameAr}</option>`).join('');
    sel.onchange = updatePPJournalPreview;

    if (suggestionReason) {
        $('mPPPaymentSuggestion').style.display = 'block';
        $('mPPPaymentSuggestion').textContent = suggestionReason;
    } else {
        $('mPPPaymentSuggestion').style.display = 'none';
    }

    $('mPPReference').value = '';
    $('mPPNotes').value = `سداد رواتب ${mLabel}${p.scope === 'project' ? ' - ' + p.projectName : ''}`;

    updatePPJournalPreview();
    ov('mPayrollPay');
};

// 🆕 دالة مساعدة: تقرأ حساب الرواتب المستحقة من القيد الفعلي المرحَّل
// تجمع كل السطور الدائنة في القيد (لتدعم حالة وجود حسابات مختلفة عبر مشاريع متعددة)
// ترجع: { code, name, totalCredit, lines: [...], multipleAccounts: bool }
function getPayableAccountFromJournal(p) {
    const result = {
        code: '', name: '', totalCredit: 0,
        lines: [],         // كل السطور الدائنة من القيد
        accountsMap: {},   // { accountCode: { name, total, ccBreakdown: {cc: amount} } }
        multipleAccounts: false,
        fromJournal: false  // هل قُرأت من القيد فعلاً؟
    };
    if (!p?.journalEntryKey || !window.journalEntries) return result;
    const jrn = window.journalEntries[p.journalEntryKey];
    if (!jrn || !jrn.lines || !Array.isArray(jrn.lines)) return result;

    // اجمع السطور الدائنة فقط (هي حسابات الرواتب المستحقة)
    jrn.lines.forEach(line => {
        const credit = parseFloat(line.credit) || 0;
        if (credit <= 0) return;
        const code = line.accountCode || '';
        const name = line.accountName || '';
        const cc = line.costCenter || '';
        if (!result.accountsMap[code]) {
            result.accountsMap[code] = { code, name, total: 0, ccBreakdown: {} };
        }
        result.accountsMap[code].total += credit;
        result.accountsMap[code].ccBreakdown[cc] = (result.accountsMap[code].ccBreakdown[cc] || 0) + credit;
        result.totalCredit += credit;
        result.lines.push({ code, name, costCenter: cc, credit });
    });

    const codes = Object.keys(result.accountsMap);
    result.fromJournal = codes.length > 0;
    result.multipleAccounts = codes.length > 1;

    if (codes.length === 1) {
        // حساب واحد دائن — استخدمه مباشرة
        result.code = codes[0];
        result.name = result.accountsMap[codes[0]].name;
    } else if (codes.length > 1) {
        // عدة حسابات — اختر الأكبر مبلغاً
        const sorted = Object.values(result.accountsMap).sort((a, b) => b.total - a.total);
        result.code = sorted[0].code;
        result.name = sorted[0].name;
    }
    return result;
}

function updatePPJournalPreview() {
    const payrollKey = $('mPPPayrollKey').value;
    const p = window.payrolls?.[payrollKey];
    if (!p) return;

    const paymentAccCode = $('mPPPaymentAccount').value;
    const paymentAcc = paymentAccCode ? Object.values(window.chartOfAccounts || {}).find(a => a.code === paymentAccCode) : null;

    // 🆕 اقرأ حسابات الرواتب المستحقة من القيد الفعلي (وليس من الإعدادات)
    const payableInfo = getPayableAccountFromJournal(p);
    const totalNet = parseFloat(p.totalNet) || 0;
    // المبلغ الفعلي للسداد = إجمالي الدائن في القيد (إن وُجد)، أو الصافي
    const payableTotal = payableInfo.fromJournal ? payableInfo.totalCredit : totalNet;

    let preview = '';
    if (payableInfo.fromJournal && payableInfo.lines.length > 0) {
        // اعرض السطور كما هي في القيد الفعلي
        const grouped = Object.values(payableInfo.accountsMap);
        preview += `<div style="background:#e8f4fd;padding:6px 10px;border-radius:4px;margin-bottom:6px;font-size:10px;color:#0d4f7c">✅ تم قراءة الحسابات من القيد المرحَّل (${p.journalEntryNumber})</div>`;
        grouped.forEach(g => {
            preview += `<div style="color:#2d6a9f">🔵 مدين: ${g.code} — ${g.name}: <strong>${fmt(g.total)}</strong></div>`;
        });
    } else {
        // Fallback: من الإعدادات
        const settings = window.payrollAccSettings || {};
        const projId = p.scope === 'project' ? p.projectId : null;
        const projSett = projId && settings[projId] ? settings[projId] : null;
        const payableCode = projSett?.payableAcc || settings._default?.payableAcc || '2120';
        const payableAcc = Object.values(window.chartOfAccounts || {}).find(a => a.code === payableCode);
        const projName = p.scope === 'project' ? p.projectName : '';
        if (payableAcc) {
            preview += `<div style="background:#fef5e7;padding:6px 10px;border-radius:4px;margin-bottom:6px;font-size:10px;color:#7d4e00">⚠️ القيد غير متاح — استخدام الإعدادات الافتراضية</div>`;
            preview += `<div style="color:#2d6a9f">🔵 مدين: ${payableAcc.code} — ${payableAcc.nameAr} ${projName ? `(${projName})` : ''}: <strong>${fmt(totalNet)}</strong></div>`;
        } else {
            preview += `<div style="color:#c0392b">⚠️ حساب الرواتب المستحقة غير محدد</div>`;
        }
    }
    if (paymentAcc) {
        preview += `<div style="color:#8e44ad">🟣 دائن: ${paymentAcc.code} — ${paymentAcc.nameAr}: <strong>${fmt(payableTotal)}</strong></div>`;
    } else {
        preview += `<div style="color:#888">⏸️ اختر حساب الصرف لإكمال المعاينة</div>`;
    }
    $('mPPJournalPreview').innerHTML = preview;
}

window.confirmPayrollPayment = async function () {
    const payrollKey = $('mPPPayrollKey').value;
    const p = window.payrolls?.[payrollKey];
    if (!p) { toast('⚠️ المسير غير موجود', 'er'); return; }

    const paymentAccCode = $('mPPPaymentAccount').value;
    if (!paymentAccCode) { toast('⚠️ يجب اختيار حساب الصرف', 'er'); return; }

    const date = $('mPPDate').value;
    if (!date) { toast('⚠️ يجب تحديد تاريخ الدفع', 'er'); return; }

    const reference = $('mPPReference').value.trim();
    const notes = $('mPPNotes').value.trim();

    // الحسابات
    const accounts = window.chartOfAccounts || {};
    const accountsArr = Object.values(accounts);
    const paymentAcc = accountsArr.find(a => a.code === paymentAccCode);

    // 🆕 اقرأ حسابات الرواتب المستحقة من القيد الفعلي (وليس من الإعدادات)
    const payableInfo = getPayableAccountFromJournal(p);

    let payableLinesForVoucher = []; // ستملأ بسطور المدين
    let totalToPay = 0;
    let primaryPayableAcc = null;

    if (payableInfo.fromJournal && payableInfo.lines.length > 0) {
        // استخدم الحسابات الفعلية من القيد (مع مراكز التكلفة)
        Object.values(payableInfo.accountsMap).forEach(g => {
            const acc = accountsArr.find(a => a.code === g.code);
            if (!acc) return;
            // أنشئ سطر مدين لكل (حساب + مركز تكلفة)
            Object.entries(g.ccBreakdown).forEach(([cc, amount]) => {
                payableLinesForVoucher.push({
                    accountCode: g.code,
                    accountName: g.name,
                    costCenter: cc,
                    amount: parseFloat(amount.toFixed(2))
                });
                totalToPay += amount;
            });
        });
        primaryPayableAcc = accountsArr.find(a => a.code === payableInfo.code);
    } else {
        // Fallback: من الإعدادات
        const settings = window.payrollAccSettings || {};
        const projId = p.scope === 'project' ? p.projectId : null;
        const projSett = projId && settings[projId] ? settings[projId] : null;
        const payableCode = projSett?.payableAcc || settings._default?.payableAcc || '2120';
        primaryPayableAcc = accountsArr.find(a => a.code === payableCode);
        if (!primaryPayableAcc) {
            toast('⚠️ حساب الرواتب المستحقة (' + payableCode + ') غير موجود في شجرة الحسابات', 'er', 8000);
            return;
        }
        totalToPay = parseFloat(p.totalNet) || 0;
        payableLinesForVoucher.push({
            accountCode: primaryPayableAcc.code,
            accountName: primaryPayableAcc.nameAr,
            costCenter: projId || '',
            projectId: projId || '',
            amount: totalToPay
        });
    }

    if (totalToPay <= 0) { toast('⚠️ المبلغ صفر — تحقق من القيد', 'er'); return; }
    if (!primaryPayableAcc) { toast('⚠️ تعذّر تحديد حساب الرواتب المستحقة', 'er'); return; }

    const voucherNumber = $('mPPNumber').value;
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const userName = (typeof myP !== 'undefined' && myP?.name) || userId;
    const now = new Date().toISOString();
    const mLabel = formatMonthLabel(p.month);
    const scopeLabel = p.scope === 'project' ? `(📁 ${p.projectName || ''})` :
                       p.scope === 'dept' ? `(🏢 ${p.dept || ''})` : '';

    const sourceText = payableInfo.fromJournal
        ? `\n📋 الحسابات من القيد المرحَّل (${p.journalEntryNumber}):\n   ${Object.values(payableInfo.accountsMap).map(g => `• ${g.code} ${g.name}: ${fmt(g.total)}`).join('\n   ')}`
        : `\n📋 الحسابات من الإعدادات الافتراضية`;

    cf2(`تأكيد دفع ${fmt(totalToPay)} ر من حساب "${paymentAcc.nameAr}"؟${sourceText}\n\nسيتم:\n✅ إنشاء سند صرف ${voucherNumber}\n✅ إنشاء قيد محاسبي (مرحَّل تلقائياً)\n✅ تحديث حالة المسير إلى "مدفوع"`, async () => {
        try {
            // 🆕 1. إنشاء سند الصرف
            const voucherData = {
                number: voucherNumber,
                type: 'payment',
                date,
                amount: totalToPay,
                method: 'bank_transfer',
                paymentAccountCode: paymentAccCode,
                paymentAccountName: paymentAcc.nameAr,
                debitAccountCode: primaryPayableAcc.code,
                debitAccountName: primaryPayableAcc.nameAr,
                vendorId: '',
                reference: reference || `مسير ${mLabel}`,
                description: `سداد رواتب ${mLabel}${scopeLabel ? ' ' + scopeLabel : ''} - ${p.totalEmployees || 0} موظف`,
                notes,
                allocations: [],
                sourceType: 'payroll_payment',
                sourceKey: payrollKey,
                status: 'posted',
                createdAt: now,
                createdBy: userId,
                createdByName: userName,
                postedAt: now,
                postedBy: userId
            };
            const voucherRef = await push(R.paym, voucherData);

            // 🆕 2. إنشاء قيد محاسبي تلقائي للسند (سطر مدين لكل حساب/مركز تكلفة)
            const jrnNumber = typeof generateJrnNumber === 'function' ? generateJrnNumber() : ('JV-PAY-' + Date.now());
            const jrnLines = [];
            payableLinesForVoucher.forEach(pl => {
                jrnLines.push({
                    accountCode: pl.accountCode,
                    accountName: pl.accountName,
                    description: `سداد رواتب ${mLabel} - ${pl.accountName}`,
                    costCenter: pl.costCenter,
                    projectId: pl.projectId || ((window.projects || {})[pl.costCenter] ? pl.costCenter : ''),
                    debit: pl.amount,
                    credit: 0
                });
            });
            // سطر دائن واحد لحساب الصرف
            const mainCC = payableLinesForVoucher[0]?.costCenter || '';
            jrnLines.push({
                accountCode: paymentAcc.code,
                accountName: paymentAcc.nameAr,
                description: `صرف من ${paymentAcc.nameAr} - مسير ${mLabel}`,
                costCenter: mainCC,
                projectId: (window.projects || {})[mainCC] ? mainCC : '',
                debit: 0,
                credit: totalToPay
            });

            const jrnData = {
                number: jrnNumber,
                date,
                lines: jrnLines,
                totalDebit: totalToPay,
                totalCredit: totalToPay,
                status: 'posted',
                sourceType: 'payroll_payment',
                sourceKey: payrollKey,
                sourceVoucherKey: voucherRef.key,
                sourceLabel: `سند صرف ${voucherNumber} - رواتب ${mLabel}`,
                reference: voucherNumber,
                description: `سداد رواتب ${mLabel}${scopeLabel ? ' ' + scopeLabel : ''} من ${paymentAcc.nameAr}`,
                createdAt: now,
                createdBy: userId,
                createdByName: userName,
                postedAt: now,
                postedBy: userId,
                autoGenerated: true,
                autoGeneratedFrom: 'payroll_payment'
            };
            const jrnRef = await push(R.jrn, jrnData);

            // 🆕 3. تحديث المسير بمعلومات الدفع
            await update(ref(db, 'ledger/payrolls/' + payrollKey), {
                paymentVoucherKey: voucherRef.key,
                paymentVoucherNumber: voucherNumber,
                paymentJournalKey: jrnRef.key,
                paymentJournalNumber: jrnNumber,
                paymentDate: date,
                paymentAmount: totalToPay,
                paymentAccountCode: paymentAccCode,
                paymentAccountName: paymentAcc.nameAr,
                paymentReference: reference,
                paymentStatus: 'paid',
                paidAt: now,
                paidBy: userId,
                paidByName: userName
            });

            // 🆕 4. ربط السند بالقيد
            await update(ref(db, 'ledger/payments/' + voucherRef.key), {
                journalEntryKey: jrnRef.key,
                journalEntryNumber: jrnNumber
            });

            toast(`✅ تم الدفع بنجاح! سند صرف ${voucherNumber} + قيد مرحَّل ${jrnNumber}`, 'ok', 8000);
            cov('mPayrollPay');
        } catch (e) {
            console.error('Payroll payment error:', e);
            toast('❌ خطأ: ' + e.message, 'er');
        }
    });
};

console.log('✅ Payroll Payment module loaded');

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   📈  [LABOR COST REPORT] تقرير تحليل تكلفة العمالة                          ║
// ╚══════════════════════════════════════════════════════════════════════════╝

window.laborCostState = {
    fromMonth: '',
    toMonth: '',
    activeTab: 'project',  // 'project' | 'dept' | 'monthly' | 'employee'
    includeUnapproved: false,
    projectFilter: '',
    deptFilter: ''
};

window.renderLaborCostReport = function () {
    const container = $('pg-laborcostreport'); if (!container) return;

    // تهيئة الفترة الافتراضية: آخر 12 شهراً
    if (!laborCostState.fromMonth || !laborCostState.toMonth) {
        const now = new Date();
        const to = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
        const fromDate = new Date(now.getFullYear(), now.getMonth() - 11, 1);
        const from = `${fromDate.getFullYear()}-${String(fromDate.getMonth() + 1).padStart(2, '0')}`;
        laborCostState.fromMonth = from;
        laborCostState.toMonth = to;
    }

    // 🔍 جمع البيانات من كل المسيرات
    const allPayrolls = Object.entries(window.payrolls || {});
    const validStatuses = laborCostState.includeUnapproved ? ['draft', 'review', 'approved'] : ['approved'];

    // فلترة المسيرات حسب الفترة + الحالة
    const filteredPayrolls = allPayrolls.filter(([, p]) => {
        if (p.status === 'cancelled') return false;
        if (!validStatuses.includes(p.status)) return false;
        if (p.month < laborCostState.fromMonth || p.month > laborCostState.toMonth) return false;
        return true;
    });

    // 📊 تجميع البيانات
    const dataByProject = {};   // { projectId: { name, totalGross, totalNet, empCount, monthsCount, byMonth: {} } }
    const dataByDept = {};      // { dept: { ... } }
    const dataByMonth = {};     // { month: { totalGross, totalNet, empCount, paidAmount } }
    const dataByEmp = {};       // { empKey: { name, totalGross, totalNet, monthsCount, projects } }
    const overallStats = {
        totalGross: 0, totalNet: 0, totalLoan: 0, totalDeduct: 0, totalBonus: 0,
        totalPaid: 0, totalUnpaid: 0,
        payrollsCount: filteredPayrolls.length,
        empSet: new Set(),
        monthsSet: new Set(),
        projectsSet: new Set(),
        approvedCount: 0, draftCount: 0, paidCount: 0
    };

    filteredPayrolls.forEach(([pKey, p]) => {
        overallStats.monthsSet.add(p.month);
        if (p.status === 'approved') overallStats.approvedCount++;
        else overallStats.draftCount++;
        if (p.paymentStatus === 'paid') {
            overallStats.paidCount++;
            overallStats.totalPaid += parseFloat(p.paymentAmount || p.totalNet) || 0;
        } else if (p.status === 'approved') {
            overallStats.totalUnpaid += parseFloat(p.totalNet) || 0;
        }

        (p.items || []).forEach(item => {
            const gross = parseFloat(item.earnedNet || item.grossSalary) || 0;
            const net = parseFloat(item.finalNet) || 0;
            const loan = parseFloat(item.loanDeductTotal) || 0;
            const deduct = parseFloat(item.monthDeductTotal) || 0;
            const bonus = parseFloat(item.perfBonusAmt) || 0;

            overallStats.totalGross += gross;
            overallStats.totalNet += net;
            overallStats.totalLoan += loan;
            overallStats.totalDeduct += deduct;
            overallStats.totalBonus += bonus;
            overallStats.empSet.add(item.empKey);

            // بالمشروع
            const projId = item.projectId || '_general';
            const projName = projId !== '_general' && window.projects?.[projId] ? window.projects[projId].name : 'بدون مشروع';
            if (!dataByProject[projId]) {
                dataByProject[projId] = {
                    id: projId, name: projName,
                    totalGross: 0, totalNet: 0, totalLoan: 0, totalBonus: 0,
                    empCount: new Set(), monthsSet: new Set(), payrollCount: 0,
                    budget: projId !== '_general' && window.projects?.[projId] ? (parseFloat(window.projects[projId].budget) || 0) : 0
                };
            }
            const pj = dataByProject[projId];
            pj.totalGross += gross;
            pj.totalNet += net;
            pj.totalLoan += loan;
            pj.totalBonus += bonus;
            pj.empCount.add(item.empKey);
            pj.monthsSet.add(p.month);
            if (projId !== '_general') overallStats.projectsSet.add(projId);

            // بالإدارة
            const dept = item.dept || 'بدون إدارة';
            if (!dataByDept[dept]) {
                dataByDept[dept] = { name: dept, totalGross: 0, totalNet: 0, empCount: new Set(), monthsSet: new Set() };
            }
            const dp = dataByDept[dept];
            dp.totalGross += gross;
            dp.totalNet += net;
            dp.empCount.add(item.empKey);
            dp.monthsSet.add(p.month);

            // شهرياً
            if (!dataByMonth[p.month]) {
                dataByMonth[p.month] = {
                    month: p.month, totalGross: 0, totalNet: 0, totalLoan: 0,
                    empCount: new Set(), paidAmount: 0, paidCount: 0, payrollsCount: 0
                };
            }
            const mn = dataByMonth[p.month];
            mn.totalGross += gross;
            mn.totalNet += net;
            mn.totalLoan += loan;
            mn.empCount.add(item.empKey);

            // الموظف
            if (!dataByEmp[item.empKey]) {
                dataByEmp[item.empKey] = {
                    empKey: item.empKey, name: item.name || '', job: item.job || '',
                    totalGross: 0, totalNet: 0, monthsCount: new Set(),
                    projects: new Set(), avgMonth: 0
                };
            }
            const e = dataByEmp[item.empKey];
            e.totalGross += gross;
            e.totalNet += net;
            e.monthsCount.add(p.month);
            if (item.projectName) e.projects.add(item.projectName);
        });
    });

    // شهرياً: حساب الدفعات
    filteredPayrolls.forEach(([, p]) => {
        if (p.paymentStatus === 'paid' && dataByMonth[p.month]) {
            dataByMonth[p.month].paidAmount += parseFloat(p.paymentAmount || p.totalNet) || 0;
            dataByMonth[p.month].paidCount += 1;
        }
        if (dataByMonth[p.month]) dataByMonth[p.month].payrollsCount += 1;
    });

    // حساب متوسطات للموظفين
    Object.values(dataByEmp).forEach(e => {
        e.avgMonth = e.monthsCount.size > 0 ? e.totalNet / e.monthsCount.size : 0;
    });

    // تحويل لمصفوفات مرتبة
    const projectsArr = Object.values(dataByProject).sort((a, b) => b.totalNet - a.totalNet);
    const deptsArr = Object.values(dataByDept).sort((a, b) => b.totalNet - a.totalNet);
    const monthsArr = Object.values(dataByMonth).sort((a, b) => a.month.localeCompare(b.month));
    const empsArr = Object.values(dataByEmp).sort((a, b) => b.totalNet - a.totalNet);

    // قيم رئيسية
    const avgEmpCost = overallStats.empSet.size > 0 ? overallStats.totalNet / overallStats.empSet.size : 0;
    const monthsCount = overallStats.monthsSet.size || 1;
    const avgMonthlyCost = overallStats.totalNet / monthsCount;
    const topProject = projectsArr[0];
    const paidPercent = overallStats.totalNet > 0 ? (overallStats.totalPaid / overallStats.totalNet) * 100 : 0;

    container.innerHTML = `
        <!-- Hero -->
        <div style="background:linear-gradient(135deg,#1a3a5c 0%,#2c5f87 50%,#5b2c6f 100%);border-radius:16px;padding:20px;margin-bottom:18px;color:white;box-shadow:0 6px 20px rgba(91,44,111,.25)">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:14px">
                <div>
                    <div style="font-size:11px;opacity:.85;letter-spacing:1px">LABOR COST ANALYSIS REPORT</div>
                    <h1 style="margin:4px 0 0;font-size:24px;font-weight:900">📈 تحليل تكلفة العمالة</h1>
                    <p style="margin:6px 0 0;font-size:12px;opacity:.95">تقرير استراتيجي شامل لتكاليف الرواتب — حسب المشروع / الإدارة / الفترة الزمنية</p>
                </div>
                <div style="display:flex;gap:10px;flex-wrap:wrap">
                    <button class="btn" onclick="exportLaborCostExcel()" style="background:rgba(255,255,255,.2);color:white;padding:10px 18px;font-weight:700;backdrop-filter:blur(10px)">📤 Excel</button>
                    <button class="btn" onclick="printLaborCostReport()" style="background:white;color:#5b2c6f;padding:10px 18px;font-weight:800;font-size:14px">🖨️ طباعة</button>
                </div>
            </div>
        </div>

        <!-- Filters -->
        <div class="card" style="margin-bottom:14px;padding:14px;background:linear-gradient(135deg,#f8fafc,#fff)">
            <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:12px;align-items:end">
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">📅 من شهر</label>
                    <input type="month" value="${laborCostState.fromMonth}" onchange="laborCostState.fromMonth=this.value;renderLaborCostReport()" style="width:100%;padding:9px;border:1.5px solid #d0d7e0;border-radius:8px;font-family:inherit;font-size:12px;margin-top:3px">
                </div>
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">📅 إلى شهر</label>
                    <input type="month" value="${laborCostState.toMonth}" onchange="laborCostState.toMonth=this.value;renderLaborCostReport()" style="width:100%;padding:9px;border:1.5px solid #d0d7e0;border-radius:8px;font-family:inherit;font-size:12px;margin-top:3px">
                </div>
                <div>
                    <label style="display:flex;align-items:center;gap:6px;cursor:pointer;background:#fef9e7;padding:9px;border-radius:8px;border:1.5px solid #f39c12">
                        <input type="checkbox" ${laborCostState.includeUnapproved ? 'checked' : ''} onchange="laborCostState.includeUnapproved=this.checked;renderLaborCostReport()" style="width:16px;height:16px;cursor:pointer">
                        <span style="font-size:11px;font-weight:700;color:#7d4e00">📝 شامل المسودات/قيد المراجعة</span>
                    </label>
                </div>
                <div style="display:flex;gap:6px">
                    <button class="btn" onclick="setLaborCostPeriod(3)" style="padding:9px;font-size:11px;flex:1;background:#e8f4fd;color:#0d4f7c">آخر 3 أشهر</button>
                    <button class="btn" onclick="setLaborCostPeriod(6)" style="padding:9px;font-size:11px;flex:1;background:#e8f4fd;color:#0d4f7c">6 أشهر</button>
                    <button class="btn" onclick="setLaborCostPeriod(12)" style="padding:9px;font-size:11px;flex:1;background:#e8f4fd;color:#0d4f7c">سنة</button>
                </div>
            </div>
        </div>

        ${overallStats.payrollsCount === 0 ? `
        <div class="card" style="text-align:center;padding:60px 20px">
            <div style="font-size:80px;margin-bottom:16px">📊</div>
            <div style="font-size:18px;font-weight:800;color:#888;margin-bottom:8px">لا توجد بيانات في هذه الفترة</div>
            <div style="font-size:13px;color:#888">جرّب تغيير الفترة أو تضمين المسودات</div>
        </div>
        ` : `
        <!-- KPIs -->
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:12px;margin-bottom:18px">
            <div style="background:linear-gradient(135deg,#1a3a5c,#2c5f87);border-radius:12px;padding:14px;color:white;box-shadow:0 4px 12px rgba(26,58,92,.2)">
                <div style="font-size:11px;opacity:.85">💰 إجمالي تكلفة العمالة</div>
                <div style="font-size:24px;font-weight:900;margin-top:4px">${fmt(overallStats.totalNet)}</div>
                <div style="font-size:10px;opacity:.85;margin-top:4px">صافي • ${overallStats.payrollsCount} مسير</div>
            </div>
            <div style="background:linear-gradient(135deg,#196f3d,#27ae60);border-radius:12px;padding:14px;color:white;box-shadow:0 4px 12px rgba(39,174,96,.2)">
                <div style="font-size:11px;opacity:.85">📊 المتوسط الشهري</div>
                <div style="font-size:24px;font-weight:900;margin-top:4px">${fmt(avgMonthlyCost)}</div>
                <div style="font-size:10px;opacity:.85;margin-top:4px">عبر ${monthsCount} شهر</div>
            </div>
            <div style="background:linear-gradient(135deg,#b9770e,#e67e22);border-radius:12px;padding:14px;color:white;box-shadow:0 4px 12px rgba(230,126,34,.2)">
                <div style="font-size:11px;opacity:.85">👥 متوسط تكلفة الموظف</div>
                <div style="font-size:24px;font-weight:900;margin-top:4px">${fmt(avgEmpCost)}</div>
                <div style="font-size:10px;opacity:.85;margin-top:4px">${overallStats.empSet.size} موظف فريد</div>
            </div>
            <div style="background:linear-gradient(135deg,#5b2c6f,#8e44ad);border-radius:12px;padding:14px;color:white;box-shadow:0 4px 12px rgba(142,68,173,.2)">
                <div style="font-size:11px;opacity:.85">🏆 أعلى مشروع تكلفة</div>
                <div style="font-size:16px;font-weight:900;margin-top:4px">${topProject?.name || '—'}</div>
                <div style="font-size:11px;opacity:.95;margin-top:4px">${fmt(topProject?.totalNet || 0)}</div>
            </div>
            <div style="background:linear-gradient(135deg,${paidPercent >= 80 ? '#196f3d,#27ae60' : paidPercent >= 50 ? '#b9770e,#e67e22' : '#7b2c1c,#c0392b'});border-radius:12px;padding:14px;color:white;box-shadow:0 4px 12px rgba(0,0,0,.1)">
                <div style="font-size:11px;opacity:.85">💸 نسبة المدفوع</div>
                <div style="font-size:24px;font-weight:900;margin-top:4px">${paidPercent.toFixed(1)}%</div>
                <div style="font-size:10px;opacity:.85;margin-top:4px">${fmt(overallStats.totalPaid)} / ${fmt(overallStats.totalNet)}</div>
            </div>
            ${overallStats.totalUnpaid > 0 ? `<div style="background:#fef5e7;border-radius:12px;padding:14px;border:2px solid #e67e22">
                <div style="font-size:11px;color:#7d4e00;font-weight:700">⏳ مستحقات لم تُدفع</div>
                <div style="font-size:24px;font-weight:900;margin-top:4px;color:#e67e22">${fmt(overallStats.totalUnpaid)}</div>
                <div style="font-size:10px;color:#7d4e00;margin-top:4px">${overallStats.approvedCount - overallStats.paidCount} مسير بانتظار الدفع</div>
            </div>` : ''}
        </div>

        <!-- إحصائيات إضافية -->
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:10px;margin-bottom:18px">
            <div style="background:white;border-radius:10px;padding:10px;box-shadow:0 2px 6px rgba(0,0,0,.05);border-right:4px solid #2d6a9f">
                <div style="font-size:10px;color:#666">إجمالي الراتب الأساسي</div>
                <div style="font-size:16px;font-weight:800;color:#2d6a9f">${fmt(overallStats.totalGross)}</div>
            </div>
            ${overallStats.totalLoan > 0 ? `<div style="background:white;border-radius:10px;padding:10px;box-shadow:0 2px 6px rgba(0,0,0,.05);border-right:4px solid #d68910">
                <div style="font-size:10px;color:#666">💳 أقساط السلف</div>
                <div style="font-size:16px;font-weight:800;color:#d68910">${fmt(overallStats.totalLoan)}</div>
            </div>` : ''}
            ${overallStats.totalDeduct > 0 ? `<div style="background:white;border-radius:10px;padding:10px;box-shadow:0 2px 6px rgba(0,0,0,.05);border-right:4px solid #c0392b">
                <div style="font-size:10px;color:#666">🚫 الخصومات</div>
                <div style="font-size:16px;font-weight:800;color:#c0392b">${fmt(overallStats.totalDeduct)}</div>
            </div>` : ''}
            ${overallStats.totalBonus !== 0 ? `<div style="background:white;border-radius:10px;padding:10px;box-shadow:0 2px 6px rgba(0,0,0,.05);border-right:4px solid ${overallStats.totalBonus > 0 ? '#27ae60' : '#c0392b'}">
                <div style="font-size:10px;color:#666">⭐ مكافآت الأداء</div>
                <div style="font-size:16px;font-weight:800;color:${overallStats.totalBonus > 0 ? '#27ae60' : '#c0392b'}">${overallStats.totalBonus > 0 ? '+' : ''}${fmt(overallStats.totalBonus)}</div>
            </div>` : ''}
            <div style="background:white;border-radius:10px;padding:10px;box-shadow:0 2px 6px rgba(0,0,0,.05);border-right:4px solid #8e44ad">
                <div style="font-size:10px;color:#666">📁 عدد المشاريع</div>
                <div style="font-size:16px;font-weight:800;color:#8e44ad">${overallStats.projectsSet.size}</div>
            </div>
        </div>

        <!-- Tabs -->
        <div style="background:white;border-radius:12px;padding:8px;margin-bottom:14px;display:flex;gap:6px;flex-wrap:wrap;box-shadow:0 2px 8px rgba(0,0,0,.04)">
            <button class="lc-tab-btn" data-tab="project" onclick="switchLaborCostTab('project')" style="padding:10px 18px;border-radius:8px;border:none;background:${laborCostState.activeTab === 'project' ? '#2d6a9f' : '#f8fafc'};color:${laborCostState.activeTab === 'project' ? 'white' : '#1a3a5c'};font-weight:800;cursor:pointer;font-size:13px">📁 تحليل بالمشروع</button>
            <button class="lc-tab-btn" data-tab="dept" onclick="switchLaborCostTab('dept')" style="padding:10px 18px;border-radius:8px;border:none;background:${laborCostState.activeTab === 'dept' ? '#2d6a9f' : '#f8fafc'};color:${laborCostState.activeTab === 'dept' ? 'white' : '#1a3a5c'};font-weight:700;cursor:pointer;font-size:13px">🏢 تحليل بالإدارة</button>
            <button class="lc-tab-btn" data-tab="monthly" onclick="switchLaborCostTab('monthly')" style="padding:10px 18px;border-radius:8px;border:none;background:${laborCostState.activeTab === 'monthly' ? '#2d6a9f' : '#f8fafc'};color:${laborCostState.activeTab === 'monthly' ? 'white' : '#1a3a5c'};font-weight:700;cursor:pointer;font-size:13px">📅 تحليل شهري</button>
            <button class="lc-tab-btn" data-tab="employee" onclick="switchLaborCostTab('employee')" style="padding:10px 18px;border-radius:8px;border:none;background:${laborCostState.activeTab === 'employee' ? '#2d6a9f' : '#f8fafc'};color:${laborCostState.activeTab === 'employee' ? 'white' : '#1a3a5c'};font-weight:700;cursor:pointer;font-size:13px">👤 أعلى التكاليف</button>
        </div>

        <!-- TAB Content -->
        <div id="lcTabContent">${renderLaborCostTabContent(laborCostState.activeTab, projectsArr, deptsArr, monthsArr, empsArr, overallStats)}</div>
        `}
    `;
};

function renderLaborCostTabContent(tab, projectsArr, deptsArr, monthsArr, empsArr, stats) {
    if (tab === 'project') return renderLaborCostByProject(projectsArr, stats);
    if (tab === 'dept') return renderLaborCostByDept(deptsArr, stats);
    if (tab === 'monthly') return renderLaborCostMonthly(monthsArr, stats);
    if (tab === 'employee') return renderLaborCostByEmployee(empsArr, stats);
    return '';
}

window.switchLaborCostTab = function (tab) {
    laborCostState.activeTab = tab;
    renderLaborCostReport();
};

window.setLaborCostPeriod = function (months) {
    const now = new Date();
    const to = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
    const fromDate = new Date(now.getFullYear(), now.getMonth() - (months - 1), 1);
    const from = `${fromDate.getFullYear()}-${String(fromDate.getMonth() + 1).padStart(2, '0')}`;
    laborCostState.fromMonth = from;
    laborCostState.toMonth = to;
    renderLaborCostReport();
};

// ─── تاب 1: تحليل بالمشروع ───
function renderLaborCostByProject(arr, stats) {
    if (!arr.length) return '<div class="card" style="padding:30px;text-align:center;color:#888">لا توجد بيانات مشاريع</div>';
    const totalAll = arr.reduce((s, p) => s + p.totalNet, 0);
    const maxVal = Math.max(...arr.map(p => p.totalNet));

    return `<div class="card">
        <div style="font-size:15px;font-weight:800;color:#1a3a5c;margin-bottom:14px">📁 توزيع تكلفة العمالة حسب المشروع</div>

        <!-- Bar Chart -->
        <div style="background:#f8fafc;border-radius:10px;padding:14px;margin-bottom:14px">
            <div style="font-size:11px;color:#666;margin-bottom:10px;font-weight:700">📊 المقارنة المرئية</div>
            ${arr.map((p, i) => {
                const pct = maxVal > 0 ? (p.totalNet / maxVal) * 100 : 0;
                const sharePct = totalAll > 0 ? (p.totalNet / totalAll) * 100 : 0;
                const colors = ['#2d6a9f', '#27ae60', '#e67e22', '#8e44ad', '#16a085', '#d68910', '#34495e', '#c0392b'];
                const c = colors[i % colors.length];
                return `<div style="margin-bottom:10px">
                    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">
                        <div style="font-size:12px;font-weight:700;color:#1a3a5c">${p.name}</div>
                        <div style="font-size:11px;color:#666"><strong style="color:${c}">${fmt(p.totalNet)}</strong> · ${sharePct.toFixed(1)}%</div>
                    </div>
                    <div style="height:14px;background:#e0e8f0;border-radius:7px;overflow:hidden">
                        <div style="height:100%;background:linear-gradient(90deg,${c},${c}cc);width:${pct}%;transition:width .4s ease"></div>
                    </div>
                </div>`;
            }).join('')}
        </div>

        <!-- Table -->
        <div style="overflow-x:auto">
            <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:900px">
                <thead style="background:#1a3a5c;color:white">
                    <tr>
                        <th style="padding:10px;text-align:center;width:40px">#</th>
                        <th style="padding:10px;text-align:right">المشروع</th>
                        <th style="padding:10px;text-align:center">عدد الموظفين</th>
                        <th style="padding:10px;text-align:center">عدد الأشهر</th>
                        <th style="padding:10px;text-align:left">إجمالي الراتب</th>
                        <th style="padding:10px;text-align:left">الصافي</th>
                        <th style="padding:10px;text-align:left">المتوسط الشهري</th>
                        <th style="padding:10px;text-align:center">% من الإجمالي</th>
                        <th style="padding:10px;text-align:center">⚖️ مقابل الميزانية</th>
                    </tr>
                </thead>
                <tbody>
                    ${arr.map((p, i) => {
                        const sharePct = totalAll > 0 ? (p.totalNet / totalAll) * 100 : 0;
                        const monthsCnt = p.monthsSet.size;
                        const avgMonthly = monthsCnt > 0 ? p.totalNet / monthsCnt : 0;
                        const budgetPct = p.budget > 0 ? (p.totalNet / p.budget) * 100 : 0;
                        const budgetColor = budgetPct < 30 ? '#27ae60' : budgetPct < 60 ? '#e67e22' : '#c0392b';
                        return `<tr style="${i % 2 ? 'background:#fafbfc' : ''}">
                            <td style="padding:8px;text-align:center;font-weight:800;color:#888">${i + 1}</td>
                            <td style="padding:8px;font-weight:800;color:#1a3a5c">${p.id === '_general' ? '📊 ' + p.name : '📁 ' + p.name}</td>
                            <td style="padding:8px;text-align:center"><span style="background:#e8f4fd;color:#0d4f7c;padding:3px 8px;border-radius:5px;font-weight:700">${p.empCount.size}</span></td>
                            <td style="padding:8px;text-align:center">${monthsCnt}</td>
                            <td style="padding:8px;text-align:left;color:#666">${fmt(p.totalGross)}</td>
                            <td style="padding:8px;text-align:left;font-weight:800;color:#2d6a9f">${fmt(p.totalNet)}</td>
                            <td style="padding:8px;text-align:left;color:#0e6655">${fmt(avgMonthly)}</td>
                            <td style="padding:8px;text-align:center"><strong>${sharePct.toFixed(1)}%</strong></td>
                            <td style="padding:8px;text-align:center">
                                ${p.budget > 0 ? `<div style="font-weight:800;color:${budgetColor}">${budgetPct.toFixed(1)}%</div><div style="font-size:9px;color:#666">من ${fmt(p.budget)}</div>` : '<span style="color:#bbb">—</span>'}
                            </td>
                        </tr>`;
                    }).join('')}
                </tbody>
                <tfoot>
                    <tr style="background:#1a3a5c;color:white;font-weight:900">
                        <td colspan="4" style="padding:10px;text-align:right">📊 الإجمالي</td>
                        <td style="padding:10px;text-align:left">${fmt(arr.reduce((s, p) => s + p.totalGross, 0))}</td>
                        <td style="padding:10px;text-align:left">${fmt(totalAll)}</td>
                        <td colspan="3"></td>
                    </tr>
                </tfoot>
            </table>
        </div>
    </div>`;
}

// ─── تاب 2: تحليل بالإدارة ───
function renderLaborCostByDept(arr, stats) {
    if (!arr.length) return '<div class="card" style="padding:30px;text-align:center;color:#888">لا توجد بيانات إدارات</div>';
    const totalAll = arr.reduce((s, p) => s + p.totalNet, 0);
    const maxVal = Math.max(...arr.map(p => p.totalNet));

    return `<div class="card">
        <div style="font-size:15px;font-weight:800;color:#1a3a5c;margin-bottom:14px">🏢 توزيع تكلفة العمالة حسب الإدارة</div>

        <div style="background:#f8fafc;border-radius:10px;padding:14px;margin-bottom:14px">
            ${arr.map((d, i) => {
                const pct = maxVal > 0 ? (d.totalNet / maxVal) * 100 : 0;
                const sharePct = totalAll > 0 ? (d.totalNet / totalAll) * 100 : 0;
                const colors = ['#5b2c6f', '#16a085', '#d68910', '#34495e', '#27ae60', '#2d6a9f'];
                const c = colors[i % colors.length];
                return `<div style="margin-bottom:10px">
                    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">
                        <div style="font-size:12px;font-weight:700;color:#1a3a5c">🏢 ${d.name}</div>
                        <div style="font-size:11px;color:#666"><strong style="color:${c}">${fmt(d.totalNet)}</strong> · ${sharePct.toFixed(1)}%</div>
                    </div>
                    <div style="height:14px;background:#e0e8f0;border-radius:7px;overflow:hidden">
                        <div style="height:100%;background:linear-gradient(90deg,${c},${c}cc);width:${pct}%;transition:width .4s ease"></div>
                    </div>
                </div>`;
            }).join('')}
        </div>

        <div style="overflow-x:auto">
            <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:700px">
                <thead style="background:#1a3a5c;color:white">
                    <tr>
                        <th style="padding:10px;text-align:center;width:40px">#</th>
                        <th style="padding:10px;text-align:right">الإدارة</th>
                        <th style="padding:10px;text-align:center">عدد الموظفين</th>
                        <th style="padding:10px;text-align:left">الإجمالي</th>
                        <th style="padding:10px;text-align:left">الصافي</th>
                        <th style="padding:10px;text-align:left">متوسط الموظف</th>
                        <th style="padding:10px;text-align:center">%</th>
                    </tr>
                </thead>
                <tbody>
                    ${arr.map((d, i) => {
                        const empCount = d.empCount.size;
                        const avgEmp = empCount > 0 ? d.totalNet / empCount : 0;
                        const sharePct = totalAll > 0 ? (d.totalNet / totalAll) * 100 : 0;
                        return `<tr style="${i % 2 ? 'background:#fafbfc' : ''}">
                            <td style="padding:8px;text-align:center;font-weight:800;color:#888">${i + 1}</td>
                            <td style="padding:8px;font-weight:800;color:#1a3a5c">🏢 ${d.name}</td>
                            <td style="padding:8px;text-align:center"><span style="background:#e8f4fd;color:#0d4f7c;padding:3px 8px;border-radius:5px;font-weight:700">${empCount}</span></td>
                            <td style="padding:8px;text-align:left;color:#666">${fmt(d.totalGross)}</td>
                            <td style="padding:8px;text-align:left;font-weight:800;color:#2d6a9f">${fmt(d.totalNet)}</td>
                            <td style="padding:8px;text-align:left;color:#0e6655">${fmt(avgEmp)}</td>
                            <td style="padding:8px;text-align:center"><strong>${sharePct.toFixed(1)}%</strong></td>
                        </tr>`;
                    }).join('')}
                </tbody>
                <tfoot>
                    <tr style="background:#1a3a5c;color:white;font-weight:900">
                        <td colspan="3" style="padding:10px;text-align:right">📊 الإجمالي</td>
                        <td style="padding:10px;text-align:left">${fmt(arr.reduce((s, p) => s + p.totalGross, 0))}</td>
                        <td style="padding:10px;text-align:left">${fmt(totalAll)}</td>
                        <td colspan="2"></td>
                    </tr>
                </tfoot>
            </table>
        </div>
    </div>`;
}

// ─── تاب 3: تحليل شهري + Trend ───
function renderLaborCostMonthly(arr, stats) {
    if (!arr.length) return '<div class="card" style="padding:30px;text-align:center;color:#888">لا توجد بيانات</div>';
    const maxVal = Math.max(...arr.map(m => m.totalNet));
    const avgMonth = arr.length > 0 ? arr.reduce((s, m) => s + m.totalNet, 0) / arr.length : 0;

    return `<div class="card">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;flex-wrap:wrap;gap:8px">
            <div style="font-size:15px;font-weight:800;color:#1a3a5c">📅 الاتجاه الشهري لتكلفة العمالة</div>
            <div style="font-size:11px;color:#666">المتوسط: <strong style="color:#0e6655">${fmt(avgMonth)}</strong></div>
        </div>

        <!-- Chart -->
        <div style="background:linear-gradient(135deg,#f8fafc,#fff);border-radius:10px;padding:16px;margin-bottom:14px;border:1px solid #e0e8f0">
            <div style="display:flex;align-items:flex-end;gap:8px;height:200px;border-bottom:2px solid #d0d7e0;padding-bottom:8px">
                ${arr.map(m => {
                    const h = maxVal > 0 ? (m.totalNet / maxVal) * 180 : 0;
                    const vsAvg = m.totalNet - avgMonth;
                    const color = m.totalNet >= avgMonth ? '#2d6a9f' : '#e67e22';
                    return `<div style="flex:1;display:flex;flex-direction:column;align-items:center;min-width:50px">
                        <div style="font-size:10px;font-weight:800;color:#1a3a5c;margin-bottom:4px">${fmt(m.totalNet)}</div>
                        <div style="width:100%;height:${h}px;background:linear-gradient(180deg,${color},${color}cc);border-radius:6px 6px 0 0;position:relative" title="${formatMonthLabel(m.month)}: ${fmt(m.totalNet)}"></div>
                    </div>`;
                }).join('')}
            </div>
            <div style="display:flex;gap:8px;margin-top:6px">
                ${arr.map(m => `<div style="flex:1;text-align:center;font-size:10px;color:#666;min-width:50px">${formatMonthLabel(m.month).substring(0, 6)}</div>`).join('')}
            </div>
        </div>

        <!-- Table -->
        <div style="overflow-x:auto">
            <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:900px">
                <thead style="background:#1a3a5c;color:white">
                    <tr>
                        <th style="padding:10px;text-align:right">الشهر</th>
                        <th style="padding:10px;text-align:center">عدد المسيرات</th>
                        <th style="padding:10px;text-align:center">عدد الموظفين</th>
                        <th style="padding:10px;text-align:left">الإجمالي</th>
                        <th style="padding:10px;text-align:left">الصافي</th>
                        <th style="padding:10px;text-align:left">المدفوع</th>
                        <th style="padding:10px;text-align:center">حالة الدفع</th>
                        <th style="padding:10px;text-align:center">📈 vs المتوسط</th>
                    </tr>
                </thead>
                <tbody>
                    ${arr.map((m, i) => {
                        const prevMonth = i > 0 ? arr[i - 1] : null;
                        const change = prevMonth ? ((m.totalNet - prevMonth.totalNet) / prevMonth.totalNet) * 100 : 0;
                        const vsAvg = avgMonth > 0 ? ((m.totalNet - avgMonth) / avgMonth) * 100 : 0;
                        const paidPct = m.totalNet > 0 ? (m.paidAmount / m.totalNet) * 100 : 0;
                        return `<tr style="${i % 2 ? 'background:#fafbfc' : ''}">
                            <td style="padding:8px;font-weight:800;color:#1a3a5c">📅 ${formatMonthLabel(m.month)}</td>
                            <td style="padding:8px;text-align:center">${m.payrollsCount}</td>
                            <td style="padding:8px;text-align:center"><span style="background:#e8f4fd;color:#0d4f7c;padding:3px 8px;border-radius:5px;font-weight:700">${m.empCount.size}</span></td>
                            <td style="padding:8px;text-align:left;color:#666">${fmt(m.totalGross)}</td>
                            <td style="padding:8px;text-align:left;font-weight:800;color:#2d6a9f">${fmt(m.totalNet)}</td>
                            <td style="padding:8px;text-align:left;color:#196f3d;font-weight:700">${fmt(m.paidAmount)}</td>
                            <td style="padding:8px;text-align:center">
                                <span style="background:${paidPct >= 90 ? '#27ae60' : paidPct >= 50 ? '#e67e22' : '#c0392b'};color:white;padding:3px 8px;border-radius:5px;font-size:10px;font-weight:700">${paidPct.toFixed(0)}% مدفوع</span>
                            </td>
                            <td style="padding:8px;text-align:center">
                                ${i > 0 ? `<span style="color:${change >= 0 ? '#27ae60' : '#c0392b'};font-weight:700">${change >= 0 ? '▲' : '▼'} ${Math.abs(change).toFixed(1)}%</span>` : '<span style="color:#bbb">—</span>'}
                                <div style="font-size:9px;color:${vsAvg >= 0 ? '#27ae60' : '#e67e22'};margin-top:2px">vs المتوسط: ${vsAvg >= 0 ? '+' : ''}${vsAvg.toFixed(1)}%</div>
                            </td>
                        </tr>`;
                    }).join('')}
                </tbody>
                <tfoot>
                    <tr style="background:#1a3a5c;color:white;font-weight:900">
                        <td colspan="3" style="padding:10px;text-align:right">📊 الإجمالي</td>
                        <td style="padding:10px;text-align:left">${fmt(arr.reduce((s, m) => s + m.totalGross, 0))}</td>
                        <td style="padding:10px;text-align:left">${fmt(arr.reduce((s, m) => s + m.totalNet, 0))}</td>
                        <td style="padding:10px;text-align:left">${fmt(arr.reduce((s, m) => s + m.paidAmount, 0))}</td>
                        <td colspan="2"></td>
                    </tr>
                </tfoot>
            </table>
        </div>
    </div>`;
}

// ─── تاب 4: أعلى التكاليف بالموظف ───
function renderLaborCostByEmployee(arr, stats) {
    if (!arr.length) return '<div class="card" style="padding:30px;text-align:center;color:#888">لا توجد بيانات</div>';
    const top20 = arr.slice(0, 20);
    const totalTop = top20.reduce((s, e) => s + e.totalNet, 0);
    const totalAll = arr.reduce((s, e) => s + e.totalNet, 0);
    const topPct = totalAll > 0 ? (totalTop / totalAll) * 100 : 0;

    return `<div class="card">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;flex-wrap:wrap;gap:8px">
            <div>
                <div style="font-size:15px;font-weight:800;color:#1a3a5c">👤 أعلى 20 موظف من حيث التكلفة</div>
                <div style="font-size:11px;color:#666;margin-top:3px">يمثلون ${topPct.toFixed(1)}% من إجمالي تكلفة العمالة</div>
            </div>
        </div>

        <div style="overflow-x:auto">
            <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:900px">
                <thead style="background:#1a3a5c;color:white">
                    <tr>
                        <th style="padding:10px;text-align:center;width:40px">#</th>
                        <th style="padding:10px;text-align:right">الموظف</th>
                        <th style="padding:10px;text-align:right">الوظيفة</th>
                        <th style="padding:10px;text-align:right">المشاريع</th>
                        <th style="padding:10px;text-align:center">عدد الأشهر</th>
                        <th style="padding:10px;text-align:left">إجمالي الصافي</th>
                        <th style="padding:10px;text-align:left">المتوسط الشهري</th>
                        <th style="padding:10px;text-align:center">% من الإجمالي</th>
                    </tr>
                </thead>
                <tbody>
                    ${top20.map((e, i) => {
                        const sharePct = totalAll > 0 ? (e.totalNet / totalAll) * 100 : 0;
                        const projsArr = [...e.projects];
                        const projsLabel = projsArr.length > 0 ? projsArr.slice(0, 2).join('، ') + (projsArr.length > 2 ? ` +${projsArr.length - 2}` : '') : '—';
                        const rank = i + 1;
                        const rankColor = rank === 1 ? '#d4af37' : rank === 2 ? '#c0c0c0' : rank === 3 ? '#cd7f32' : '#888';
                        return `<tr style="${i % 2 ? 'background:#fafbfc' : ''}">
                            <td style="padding:8px;text-align:center"><span style="background:${rankColor};color:white;padding:3px 10px;border-radius:50%;font-weight:900;display:inline-block;min-width:24px">${rank}</span></td>
                            <td style="padding:8px;font-weight:800;color:#1a3a5c">${e.name}</td>
                            <td style="padding:8px;color:#666">${e.job || '—'}</td>
                            <td style="padding:8px;font-size:11px;color:#666">${projsLabel}</td>
                            <td style="padding:8px;text-align:center">${e.monthsCount.size}</td>
                            <td style="padding:8px;text-align:left;font-weight:800;color:#2d6a9f">${fmt(e.totalNet)}</td>
                            <td style="padding:8px;text-align:left;color:#0e6655">${fmt(e.avgMonth)}</td>
                            <td style="padding:8px;text-align:center;font-weight:800">${sharePct.toFixed(2)}%</td>
                        </tr>`;
                    }).join('')}
                </tbody>
            </table>
        </div>

        ${arr.length > 20 ? `<div style="background:#f8fafc;padding:10px;border-radius:8px;margin-top:10px;text-align:center;font-size:11px;color:#666">
            + ${arr.length - 20} موظف آخرين بإجمالي ${fmt(totalAll - totalTop)} ر (${((totalAll - totalTop) / totalAll * 100).toFixed(1)}%)
        </div>` : ''}
    </div>`;
}

// 🖨️ طباعة التقرير
window.printLaborCostReport = function () {
    const period = `${formatMonthLabel(laborCostState.fromMonth)} → ${formatMonthLabel(laborCostState.toMonth)}`;
    // إعادة جمع البيانات للطباعة
    const allPayrolls = Object.entries(window.payrolls || {});
    const validStatuses = laborCostState.includeUnapproved ? ['draft', 'review', 'approved'] : ['approved'];
    const filteredPayrolls = allPayrolls.filter(([, p]) => {
        if (p.status === 'cancelled') return false;
        if (!validStatuses.includes(p.status)) return false;
        if (p.month < laborCostState.fromMonth || p.month > laborCostState.toMonth) return false;
        return true;
    });
    const dataByProject = {};
    let totalNet = 0, totalGross = 0;
    const empSet = new Set();
    filteredPayrolls.forEach(([, p]) => {
        (p.items || []).forEach(item => {
            const projId = item.projectId || '_general';
            const projName = projId !== '_general' && window.projects?.[projId] ? window.projects[projId].name : 'بدون مشروع';
            if (!dataByProject[projId]) {
                dataByProject[projId] = { name: projName, totalGross: 0, totalNet: 0, empCount: new Set() };
            }
            const gross = parseFloat(item.earnedNet || item.grossSalary) || 0;
            const net = parseFloat(item.finalNet) || 0;
            dataByProject[projId].totalGross += gross;
            dataByProject[projId].totalNet += net;
            dataByProject[projId].empCount.add(item.empKey);
            totalGross += gross;
            totalNet += net;
            empSet.add(item.empKey);
        });
    });
    const arr = Object.values(dataByProject).sort((a, b) => b.totalNet - a.totalNet);

    const html = `<!DOCTYPE html><html dir="rtl"><head><meta charset="UTF-8"><title>تقرير تحليل تكلفة العمالة</title>
    <style>* { -webkit-print-color-adjust: exact !important; } body { font-family: Tahoma; padding: 20px; color: #1a3a5c; direction: rtl; }
    h1 { text-align: center; border-bottom: 3px solid #5b2c6f; padding-bottom: 10px; color:#5b2c6f }
    .info { background:#f4ecf7; padding:14px; border-radius:8px; margin:14px 0; display:grid; grid-template-columns:1fr 1fr 1fr; gap:10px; font-size:12px }
    table { width: 100%; border-collapse: collapse; font-size: 11px; margin-top: 14px; }
    th { background: #1a3a5c; color: white; padding: 8px; } td { padding: 7px; border: 1px solid #ddd; }
    tfoot td { background: #5b2c6f; color: white; font-weight: 900; }
    @page { size: A4 landscape; margin: 1.5cm; }</style></head><body>
    <h1>📈 تقرير تحليل تكلفة العمالة</h1>
    <div class="info">
        <div><strong>📅 الفترة:</strong> ${period}</div>
        <div><strong>👥 إجمالي الموظفين:</strong> ${empSet.size}</div>
        <div><strong>💰 إجمالي التكلفة:</strong> ${fmt(totalNet)} ر</div>
    </div>
    <h2>📁 التوزيع حسب المشروع</h2>
    <table><thead><tr><th>#</th><th>المشروع</th><th>عدد الموظفين</th><th>الإجمالي</th><th>الصافي</th><th>%</th></tr></thead>
    <tbody>${arr.map((p, i) => {
        const pct = totalNet > 0 ? (p.totalNet / totalNet) * 100 : 0;
        return `<tr>
            <td style="text-align:center">${i + 1}</td>
            <td style="font-weight:700">${p.name}</td>
            <td style="text-align:center">${p.empCount.size}</td>
            <td style="text-align:left">${fmt(p.totalGross)}</td>
            <td style="text-align:left;font-weight:700">${fmt(p.totalNet)}</td>
            <td style="text-align:center">${pct.toFixed(1)}%</td>
        </tr>`;
    }).join('')}</tbody>
    <tfoot><tr><td colspan="3" style="text-align:right;padding:10px">📊 الإجمالي</td>
    <td style="text-align:left;padding:10px">${fmt(totalGross)}</td>
    <td style="text-align:left;padding:10px">${fmt(totalNet)}</td>
    <td>100%</td></tr></tfoot>
    </table></body></html>`;
    const w = window.open('', '_blank'); w.document.write(html); w.document.close();
    setTimeout(() => { try { w.print(); } catch (e) { } }, 500);
};

// 📤 Excel
window.exportLaborCostExcel = function () {
    const allPayrolls = Object.entries(window.payrolls || {});
    const validStatuses = laborCostState.includeUnapproved ? ['draft', 'review', 'approved'] : ['approved'];
    const filteredPayrolls = allPayrolls.filter(([, p]) => {
        if (p.status === 'cancelled') return false;
        if (!validStatuses.includes(p.status)) return false;
        if (p.month < laborCostState.fromMonth || p.month > laborCostState.toMonth) return false;
        return true;
    });

    const rows = [];
    filteredPayrolls.forEach(([, p]) => {
        (p.items || []).forEach(item => {
            rows.push({
                'الشهر': p.month,
                'الموظف': item.name || '',
                'الوظيفة': item.job || '',
                'الإدارة': item.dept || '',
                'المشروع': item.projectName || (item.projectId && window.projects?.[item.projectId]?.name) || 'بدون مشروع',
                'إجمالي الراتب': parseFloat(item.earnedNet || item.grossSalary) || 0,
                'الصافي': parseFloat(item.finalNet) || 0,
                'أقساط السلف': parseFloat(item.loanDeductTotal) || 0,
                'الخصومات': parseFloat(item.monthDeductTotal) || 0,
                'مكافآت الأداء': parseFloat(item.perfBonusAmt) || 0,
                'حالة الدفع': p.paymentStatus === 'paid' ? 'مدفوع' : 'غير مدفوع'
            });
        });
    });
    if (!rows.length) { toast('⚠️ لا توجد بيانات للتصدير', 'wn'); return; }
    try {
        const ws = XLSX.utils.json_to_sheet(rows);
        ws['!cols'] = Array(11).fill({ wch: 15 });
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'تكلفة العمالة');
        XLSX.writeFile(wb, `تحليل_تكلفة_العمالة_${new Date().toISOString().substring(0, 10)}.xlsx`);
        toast('✅ تم التصدير', 'ok');
    } catch (e) { toast('❌ ' + e.message, 'er'); }
};

