// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   ✅  [PRJ-TASKS]  متابعة المهام عبر كل المشاريع                          ║
// ╚══════════════════════════════════════════════════════════════════════════╝
const PT_COL_LABELS = { todo: '📋 قيد الانتظار', doing: '🚧 قيد التنفيذ', review: '🔍 مراجعة', done: '✅ مكتملة' };
const PT_PRIORITY_LABELS = { low: ['منخفضة', '#7f8c8d'], normal: ['عادية', '#2980b9'], high: ['عالية', '#e67e22'], urgent: ['عاجلة', '#c0392b'] };

window.updatePrjTasksBadge = function () {
    const badge = $('prjTasksBadge'); if (!badge) return;
    const today = new Date().toISOString().slice(0, 10);
    let n = 0;
    Object.values(window.projectTasks || {}).forEach(tasks => {
        Object.values(tasks || {}).forEach(t => { if (t.status !== 'done' && t.dueDate && t.dueDate < today) n++; });
    });
    if (n) { badge.textContent = n; badge.style.display = 'inline-flex'; } else badge.style.display = 'none';
};

window.renderAllProjectTasks = function () {
    const content = $('ptAllContent'); if (!content) return;
    const projSel = $('ptAllProject'), empSel = $('ptAllAssignee');

    // تعبئة قوائم الفلترة (مرة واحدة بدون فقدان التحديد الحالي)
    if (projSel && projSel.options.length <= 1) {
        Object.entries(window.projects || {}).sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar'))
            .forEach(([k, p]) => projSel.insertAdjacentHTML('beforeend', `<option value="${k}">${p.name || '-'}</option>`));
    }
    if (empSel && empSel.options.length <= 1) {
        Object.entries(window.emp || {}).sort((a, b) => (a[1].name || '').localeCompare(b[1].name || '', 'ar'))
            .forEach(([k, e]) => empSel.insertAdjacentHTML('beforeend', `<option value="${k}">${e.name}</option>`));
    }
    enhanceLongSelects($('pg-prjtasks'));

    const fProject = projSel?.value || '';
    const fAssignee = empSel?.value || '';
    const fPriority = $('ptAllPriority')?.value || '';
    const overdueOnly = $('ptAllOverdueOnly')?.checked || false;
    const today = new Date().toISOString().slice(0, 10);

    let rows = [];
    Object.entries(window.projectTasks || {}).forEach(([pid, tasks]) => {
        if (fProject && pid !== fProject) return;
        Object.entries(tasks || {}).forEach(([tk, t]) => {
            if (fAssignee && t.assigneeId !== fAssignee) return;
            if (fPriority && (t.priority || 'normal') !== fPriority) return;
            const overdue = t.status !== 'done' && t.dueDate && t.dueDate < today;
            if (overdueOnly && !overdue) return;
            rows.push({ pid, tk, t, overdue });
        });
    });

    if (!rows.length) {
        content.innerHTML = `<div class="empty"><div class="ei">✅</div><p>لا توجد مهام مطابقة للفلاتر الحالية</p></div>`;
        return;
    }

    // ترتيب: المتأخرة أولاً، ثم حسب تاريخ التسليم
    rows.sort((a, b) => (b.overdue - a.overdue) || (a.t.dueDate || '9999').localeCompare(b.t.dueDate || '9999'));

    const totalOpen = rows.filter(r => r.t.status !== 'done').length;
    const totalOverdue = rows.filter(r => r.overdue).length;

    if ((window._ptAllView || 'list') === 'gantt') {
        content.innerHTML = ptAllRenderGantt(rows, today);
        return;
    }

    content.innerHTML = `
    <div style="display:flex;gap:10px;margin-bottom:14px;flex-wrap:wrap">
        <span style="background:#eef3f8;color:#1a3a5c;padding:5px 14px;border-radius:8px;font-size:12px;font-weight:700">إجمالي المهام: ${rows.length}</span>
        <span style="background:#fef9e7;color:#7d6608;padding:5px 14px;border-radius:8px;font-size:12px;font-weight:700">مفتوحة: ${totalOpen}</span>
        ${totalOverdue ? `<span style="background:#fdecea;color:#c0392b;padding:5px 14px;border-radius:8px;font-size:12px;font-weight:700">⚠️ متأخرة: ${totalOverdue}</span>` : ''}
    </div>
    <div class="card" style="padding:0;overflow-x:auto">
        <table style="width:100%;border-collapse:collapse;font-size:12.5px">
            <thead><tr style="background:#f8fafc">
                <th style="padding:10px;text-align:right">المهمة</th>
                <th style="padding:10px;text-align:right">المشروع</th>
                <th style="padding:10px;text-align:center">الحالة</th>
                <th style="padding:10px;text-align:center">الأولوية</th>
                <th style="padding:10px;text-align:center">المسؤول</th>
                <th style="padding:10px;text-align:center">تاريخ التسليم</th>
                <th style="padding:10px;text-align:center">إجراء</th>
            </tr></thead>
            <tbody>
            ${rows.map(({ pid, tk, t, overdue }) => {
                const proj = (window.projects || {})[pid];
                const assignee = (window.emp || {})[t.assigneeId];
                const [plLabel, plColor] = PT_PRIORITY_LABELS[t.priority] || PT_PRIORITY_LABELS.normal;
                return `<tr style="border-bottom:1px solid #f5f5f5">
                    <td style="padding:8px 10px;font-weight:700;color:#1a3a5c">${t.title || ''}${t.desc ? `<div style="font-size:10.5px;color:#999;font-weight:400;margin-top:2px">${t.desc}</div>` : ''}</td>
                    <td style="padding:8px 10px;color:#2d6a9f;cursor:pointer" onclick="openProjectDetail('${pid}')">${proj?.name || '-'}</td>
                    <td style="padding:8px 10px;text-align:center">${PT_COL_LABELS[t.status] || t.status || '-'}</td>
                    <td style="padding:8px 10px;text-align:center"><span style="background:${plColor}1a;color:${plColor};padding:2px 8px;border-radius:6px;font-size:11px;font-weight:700">${plLabel}</span></td>
                    <td style="padding:8px 10px;text-align:center">${assignee ? assignee.name : '-'}</td>
                    <td style="padding:8px 10px;text-align:center;${overdue ? 'color:#c0392b;font-weight:700' : ''}">${t.dueDate || '-'}${overdue ? ' ⚠️' : ''}</td>
                    <td style="padding:8px 10px;text-align:center"><button class="btn b-b" style="padding:4px 10px;font-size:11px" onclick="openProjectDetail('${pid}');window._pd.tab='tasks';pdSwitchTab('tasks')">↗ فتح</button></td>
                </tr>`;
            }).join('')}
            </tbody>
        </table>
    </div>`;
};

window.ptAllSetView = function (view) {
    window._ptAllView = view;
    const lb = $('ptAllViewList'), gb = $('ptAllViewGantt');
    if (lb && gb) {
        lb.className = 'btn' + (view === 'list' ? ' b-b' : '');
        gb.className = 'btn' + (view === 'gantt' ? ' b-b' : '');
        lb.style.background = view === 'list' ? '' : 'transparent';
        lb.style.color = view === 'list' ? '' : '#666';
        gb.style.background = view === 'gantt' ? '' : 'transparent';
        gb.style.color = view === 'gantt' ? '' : '#666';
    }
    renderAllProjectTasks();
};

// ── عرض جانت لكل مهام المشاريع (مجمّعة) ─────────────────
function ptAllRenderGantt(rows, today) {
    const dated = rows.filter(r => r.t.dueDate);
    if (!dated.length) {
        return `<div class="card"><div class="empty"><div class="ei">📅</div><p>لا توجد مهام بتواريخ تسليم لعرضها في الجدول الزمني</p></div></div>`;
    }

    let allDates = [];
    dated.forEach(r => {
        if (r.t.startDate) allDates.push(r.t.startDate);
        allDates.push(r.t.dueDate);
    });
    allDates.push(today);
    let minD = new Date(allDates.reduce((a, b) => a < b ? a : b));
    let maxD = new Date(allDates.reduce((a, b) => a > b ? a : b));
    minD.setDate(minD.getDate() - 1);
    maxD.setDate(maxD.getDate() + 1);
    const totalDays = Math.max(1, Math.round((maxD - minD) / 86400000));
    const todayPct = Math.min(100, Math.max(0, ((new Date(today) - minD) / 86400000) / totalDays * 100));

    const sorted = dated.slice().sort((a, b) => (a.t.startDate || a.t.dueDate).localeCompare(b.t.startDate || b.t.dueDate));

    return `<div class="card" style="overflow-x:auto">
        <div style="font-size:12px;color:#888;margin-bottom:10px">📅 من ${minD.toISOString().slice(0,10)} إلى ${maxD.toISOString().slice(0,10)}</div>
        <div style="min-width:700px;position:relative">
            <div style="position:absolute;top:0;bottom:0;right:${todayPct}%;width:2px;background:#c0392b;z-index:1" title="اليوم"></div>
            ${sorted.map(({ pid, tk, t, overdue }) => {
                const proj = (window.projects || {})[pid];
                const [, plColor] = PT_PRIORITY_LABELS[t.priority] || PT_PRIORITY_LABELS.normal;
                const start = new Date(t.startDate || t.dueDate);
                const end = new Date(t.dueDate);
                const offsetPct = Math.max(0, ((start - minD) / 86400000) / totalDays * 100);
                const durDays = Math.max(1, Math.round((end - start) / 86400000) + 1);
                const widthPct = Math.max(2, durDays / totalDays * 100);
                const barColor = t.status === 'done' ? '#27ae60' : overdue ? '#c0392b' : plColor;
                return `<div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;cursor:pointer" onclick="openProjectDetail('${pid}');window._pd.tab='tasks';pdSwitchTab('tasks')" title="${t.title}">
                    <div style="width:140px;flex-shrink:0;font-size:11px;font-weight:700;color:#1a3a5c;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${t.title || ''}</div>
                    <div style="width:110px;flex-shrink:0;font-size:10px;color:#2d6a9f;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${proj?.name || '-'}</div>
                    <div style="flex:1;background:#f4f6f8;border-radius:6px;height:20px;position:relative">
                        <div style="position:absolute;right:${offsetPct}%;width:${widthPct}%;height:100%;background:${barColor};border-radius:6px;display:flex;align-items:center;justify-content:center;color:white;font-size:9px;font-weight:700;min-width:24px">${durDays}ي</div>
                    </div>
                    <div style="width:90px;flex-shrink:0;font-size:10px;color:${overdue ? '#c0392b' : '#888'};text-align:left">${t.dueDate}${overdue ? ' ⚠️' : ''}</div>
                </div>`;
            }).join('')}
        </div>
    </div>`;
}

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🔍  [UI-SEARCHSELECT]  تحويل القوائم المنسدلة الطويلة إلى قوائم بحث     ║
// ╚══════════════════════════════════════════════════════════════════════════╝
// أي <select> يحتوي أكثر من 8 خيارات (وليس multiple، وغير مستثنى عبر data-no-search)
// يُستبدل بصندوق بحث + قائمة منسدلة، مع إبقاء <select> الأصلي مخفياً كمصدر للقيمة
// بحيث تستمر كل الأكواد القديمة (onchange, .value, fillXSelect...) بالعمل بدون تعديل.
window.enhanceLongSelects = function (root) {
    root = root || document;
    root.querySelectorAll('select').forEach(sel => {
        if (sel.multiple || sel.dataset.noSearch) return;
        if (sel.dataset.esEnhanced) { esSyncDisplay(sel); return; }
        if (sel.options.length <= 8) return;
        sel.dataset.esEnhanced = '1';

        const wrap = document.createElement('span');
        wrap.className = 'es-wrap';
        wrap.style.cssText = 'position:relative;display:inline-block;width:' + (sel.style.width || (sel.style.flex ? '' : '100%'));
        if (sel.style.flex) wrap.style.flex = sel.style.flex;
        if (sel.style.minWidth) wrap.style.minWidth = sel.style.minWidth;

        const input = document.createElement('input');
        input.type = 'text';
        input.placeholder = '🔍 بحث...';
        input.autocomplete = 'off';
        input.style.cssText = (sel.getAttribute('style') || '') + ';width:100%;box-sizing:border-box;cursor:pointer';

        const dd = document.createElement('div');
        dd.style.cssText = 'display:none;position:absolute;top:calc(100% + 4px);right:0;left:0;background:white;border:1.5px solid #d0d7e0;border-radius:8px;max-height:280px;overflow-y:auto;z-index:200;box-shadow:0 6px 20px rgba(0,0,0,.12)';

        function buildList(filter) {
            const f = (filter || '').trim();
            const opts = [...sel.options].filter(o => !f || o.textContent.includes(f));
            dd.innerHTML = opts.length ? opts.map(o => `<div data-v="${o.value.replace(/"/g, '&quot;')}" style="padding:8px 12px;font-size:13px;cursor:pointer;border-bottom:1px solid #f5f5f5${o.value === sel.value ? ';background:#eef3f8;font-weight:700' : ''}" onmouseover="this.style.background='#f0f6ff'" onmouseout="this.style.background='${o.value === sel.value ? '#eef3f8' : 'white'}'">${o.textContent}</div>`).join('')
                : `<div style="padding:10px;color:#999;text-align:center;font-size:12px">لا توجد نتائج</div>`;
        }
        input.addEventListener('input', () => { buildList(input.value); dd.style.display = 'block'; });
        input.addEventListener('focus', () => { input.select(); buildList(''); dd.style.display = 'block'; });
        dd.addEventListener('mousedown', e => {
            const item = e.target.closest('[data-v]'); if (!item) return;
            sel.value = item.dataset.v;
            sel.dispatchEvent(new Event('change', { bubbles: true }));
            esSyncDisplay(sel);
            dd.style.display = 'none';
        });
        document.addEventListener('click', e => { if (!wrap.contains(e.target)) dd.style.display = 'none'; });

        sel.style.display = 'none';
        sel.parentNode.insertBefore(wrap, sel);
        wrap.appendChild(input); wrap.appendChild(dd); wrap.appendChild(sel);
        sel._esInput = input;
        esSyncDisplay(sel);
    });
};

function esSyncDisplay(sel) {
    if (sel._esInput) sel._esInput.value = sel.options[sel.selectedIndex]?.textContent || '';
}

// ── Close overlays ─────────────────────────
document.querySelectorAll(".ov").forEach(o => o.addEventListener("click", e => { if (e.target === o) o.classList.remove("show") }));

// ══════════════════════════════════════════════════════
// [SUB1] مقاولو الباطن — قائمة المقاولين
// ══════════════════════════════════════════════════════
window.renderSubcontractors = function() {
    const subs = window.subcontractors || {};
    const trans = window.subcontractorTrans || {};
    const q = ($('subcSearch')?.value || '').trim().toLowerCase();
    const balFilter = $('subcFilterBal')?.value || '';

    function totals(id) {
        const rows = Object.values(trans).filter(t => t.subId === id);
        const dr = rows.reduce((a,t) => a + (t.type==='debit'  ? +t.amount : 0), 0);
        const cr = rows.reduce((a,t) => a + (t.type==='credit' ? +t.amount : 0), 0);
        return { dr, cr, bal: dr - cr };
    }

    const allEntries = Object.entries(subs).map(([id,s]) => ({ id, s, ...totals(id) }));

    // KPIs
    const kpiEl = $('subcKpis');
    if (kpiEl) {
        const totalDr = allEntries.reduce((a,e) => a+e.dr, 0);
        const totalCr = allEntries.reduce((a,e) => a+e.cr, 0);
        const netBal  = allEntries.reduce((a,e) => a+e.bal, 0);
        const debtors = allEntries.filter(e => e.bal > 0).length;
        kpiEl.innerHTML = `
          <div class="kpi k1"><div class="kpi-ic">👷</div><div class="kpi-lb">المقاولون</div><div class="kpi-vl">${allEntries.length}</div><div class="kpi-sb">مقاول مسجل</div></div>
          <div class="kpi k3" style="--kc:#c0392b"><div class="kpi-ic">📌</div><div class="kpi-lb">إجمالي المستحقات</div><div class="kpi-vl" style="font-size:15px">${fmt(totalDr)}</div><div class="kpi-sb">ريال مستحق</div></div>
          <div class="kpi k2" style="--kc:#27ae60"><div class="kpi-ic">💸</div><div class="kpi-lb">إجمالي المدفوعات</div><div class="kpi-vl" style="font-size:15px">${fmt(totalCr)}</div><div class="kpi-sb">ريال مدفوع</div></div>
          <div class="kpi k4" style="--kc:${netBal>0?'#c0392b':'#27ae60'}"><div class="kpi-ic">⚖️</div><div class="kpi-lb">صافي الرصيد</div><div class="kpi-vl" style="font-size:15px">${fmt(Math.abs(netBal))}</div><div class="kpi-sb">${netBal>0?'مستحق إجمالي':'دائن إجمالي'}</div></div>
          <div class="kpi k1"><div class="kpi-ic">🔴</div><div class="kpi-lb">مقاولون مديونون</div><div class="kpi-vl">${debtors}</div><div class="kpi-sb">بأرصدة مستحقة</div></div>
        `;
    }

    let list = allEntries.filter(({s, dr, cr, bal}) => {
        if (q && !s.name?.toLowerCase().includes(q) && !s.specialty?.toLowerCase().includes(q) && !s.phone?.includes(q)) return false;
        if (balFilter === 'debit'  && bal <= 0) return false;
        if (balFilter === 'credit' && bal >= 0) return false;
        if (balFilter === 'zero'   && bal !== 0) return false;
        return true;
    });

    // تنبيهات الرصيد
    const alertBanner = $('subcAlertBanner');
    if (alertBanner) {
        const alerts = allEntries.filter(e => e.s.alertThreshold && e.bal > +e.s.alertThreshold);
        alertBanner.innerHTML = alerts.length ? `<div style="background:#fdedec;border:1.5px solid #e74c3c;border-radius:10px;padding:12px 16px">
            <div style="font-weight:700;color:#c0392b;margin-bottom:6px">🔔 تنبيهات الرصيد — ${alerts.length} مقاول تجاوز حد التنبيه</div>
            ${alerts.map(e=>`<div style="font-size:12px;padding:3px 0;border-bottom:1px solid #fad7d7">
                <strong>${esc(e.s.name)}</strong> — الرصيد: <span style="color:#c0392b">${fmt(e.bal)}</span> ريال (الحد: ${fmt(+e.s.alertThreshold)} ريال)
            </div>`).join('')}
        </div>` : '';
    }

    const tbody = $('subcTbody');
    if (!tbody) return;
    if (!list.length) { tbody.innerHTML = `<tr><td colspan="10" style="text-align:center;padding:24px;color:#aaa">لا توجد نتائج</td></tr>`; return; }

    tbody.innerHTML = list.map(({id, s, dr, cr, bal}, i) => {
        const balColor = bal > 0 ? '#c0392b' : bal < 0 ? '#27ae60' : '#888';
        const balLabel = bal > 0 ? `مستحق ${fmt(bal)}` : bal < 0 ? `دائن ${fmt(Math.abs(bal))}` : 'متوازن';
        const rating = +s.rating || 0;
        const starsHtml = [1,2,3,4,5].map(n=>`<span style="color:${n<=rating?'#f0a500':'#ddd'};font-size:14px">★</span>`).join('');
        const alertFlag = s.alertThreshold && bal > +s.alertThreshold ? '<span title="تجاوز حد التنبيه" style="color:#e74c3c;margin-right:4px">🔔</span>' : '';
        return `<tr style="cursor:pointer;transition:background .15s" onmouseover="this.style.background='#fdf8e8'" onmouseout="this.style.background=''" onclick="openSubStatement('${id}')">
            <td style="text-align:center;padding:10px 8px">${i+1}</td>
            <td style="padding:10px 8px">${alertFlag}<strong>${esc(s.name)||''}</strong>${s.projectId?`<div style="font-size:10px;color:#8e44ad">🏗️ ${esc((window.projects||[]).find(p=>p.id===s.projectId)?.name||s.projectId)}</div>`:''}${s.iban?`<div style="font-size:10px;color:#aaa;direction:ltr">${esc(s.iban)}</div>`:''}</td>
            <td style="padding:10px 8px">${esc(s.specialty)||'-'}</td>
            <td style="padding:10px 8px;text-align:center">${starsHtml}</td>
            <td style="padding:10px 8px;direction:ltr;text-align:right">${esc(s.phone)||'-'}</td>
            <td style="padding:10px 8px">${esc(s.crNumber)||'-'}</td>
            <td style="padding:10px 8px;color:#c0392b;font-weight:600">${dr ? fmt(dr) : '-'}</td>
            <td style="padding:10px 8px;color:#27ae60;font-weight:600">${cr ? fmt(cr) : '-'}</td>
            <td style="padding:10px 8px"><strong style="color:${balColor}">${balLabel}</strong></td>
            <td style="padding:10px 8px;text-align:center;white-space:nowrap">
                <button onclick="event.stopPropagation();openSubStatement('${id}')" style="background:#d4a017;color:white;border:none;border-radius:6px;padding:4px 9px;cursor:pointer;font-size:11px;margin-left:3px" title="كشف الحساب">📋</button>
                <button onclick="event.stopPropagation();openSubEdit('${id}')" style="background:#2980b9;color:white;border:none;border-radius:6px;padding:4px 9px;cursor:pointer;font-size:11px;margin-left:3px" title="تعديل">✏️</button>
                <button onclick="event.stopPropagation();deleteSubcontractor('${id}')" style="background:#e74c3c;color:white;border:none;border-radius:6px;padding:4px 9px;cursor:pointer;font-size:11px" title="حذف">🗑️</button>
            </td>
        </tr>`;
    }).join('');
};

window.exportSubcExcel = function() {
    const subs = window.subcontractors || {};
    const trans = window.subcontractorTrans || {};
    function totals(id) {
        const rows = Object.values(trans).filter(t => t.subId === id);
        const dr = rows.reduce((a,t) => a+(t.type==='debit'?+t.amount:0),0);
        const cr = rows.reduce((a,t) => a+(t.type==='credit'?+t.amount:0),0);
        return { dr, cr, bal: dr-cr };
    }
    const rows = [['م','اسم المقاول','التخصص','الجوال','السجل التجاري','IBAN','إجمالي المستحقات','إجمالي المدفوعات','الرصيد']];
    Object.entries(subs).forEach(([id,s],i) => {
        const {dr,cr,bal} = totals(id);
        rows.push([i+1, s.name||'', s.specialty||'', s.phone||'', s.crNumber||'', s.iban||'', dr, cr, bal]);
    });
    const csv = rows.map(r => r.map(c => `"${String(c).replace(/"/g,'""')}"`).join(',')).join('\n');
    const BOM = '﻿';
    const blob = new Blob([BOM+csv], {type:'text/csv;charset=utf-8'});
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `مقاولو_الباطن_${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    toast('تم تصدير الملف', 's');
};

window.printSubcList = function() {
    const subs = window.subcontractors || {};
    const trans = window.subcontractorTrans || {};
    function totals(id) {
        const rows = Object.values(trans).filter(t => t.subId === id);
        const dr = rows.reduce((a,t) => a+(t.type==='debit'?+t.amount:0),0);
        const cr = rows.reduce((a,t) => a+(t.type==='credit'?+t.amount:0),0);
        return { dr, cr, bal: dr-cr };
    }
    const rows = Object.entries(subs).map(([id,s],i) => {
        const {dr,cr,bal} = totals(id);
        const balLabel = bal>0?`مستحق ${fmt(bal)}`:bal<0?`دائن ${fmt(Math.abs(bal))}`:'متوازن';
        return `<tr><td>${i+1}</td><td>${esc(s.name)||''}</td><td>${esc(s.specialty)||'-'}</td><td>${esc(s.phone)||'-'}</td><td>${esc(s.crNumber)||'-'}</td><td>${fmt(dr)}</td><td>${fmt(cr)}</td><td style="color:${bal>0?'#c0392b':bal<0?'#27ae60':'#555'}">${balLabel}</td></tr>`;
    }).join('');
    const w = window.open('','_blank');
    w.document.write(`<html dir="rtl"><head><meta charset="utf-8"><title>قائمة مقاولي الباطن</title>
    <style>body{font-family:Arial,sans-serif;font-size:12px}table{width:100%;border-collapse:collapse}td,th{border:1px solid #ccc;padding:7px 9px}th{background:#7d5a00;color:white}@media print{button{display:none}}h2{text-align:center}</style>
    </head><body><h2>قائمة مقاولي الباطن</h2><p style="text-align:center;color:#888">تاريخ الطباعة: ${new Date().toLocaleDateString('ar')}</p>
    <table><thead><tr><th>م</th><th>الاسم</th><th>التخصص</th><th>الجوال</th><th>السجل التجاري</th><th>المستحقات</th><th>المدفوعات</th><th>الرصيد</th></tr></thead><tbody>${rows}</tbody></table>
    <br><button onclick="window.print()">🖨️ طباعة</button></body></html>`);
    w.document.close();
};

window.setSubcRating = function(val) {
    $('subcEditRating').value = val;
    const stars = $('subcEditRatingStars')?.querySelectorAll('span') || [];
    stars.forEach((s,i) => { s.style.opacity = i < val ? '1' : '.3'; s.style.color = i < val ? '#f0a500' : ''; });
};

window.openSubEdit = function(id) {
    const s = id ? (window.subcontractors||{})[id] : {};
    $('subcEditId').value = id || '';
    $('subcEditName').value = s?.name || '';
    $('subcEditSpecialty').value = s?.specialty || '';
    $('subcEditPhone').value = s?.phone || '';
    $('subcEditCR').value = s?.crNumber || '';
    $('subcEditIBAN').value = s?.iban || '';
    $('subcEditNotes').value = s?.notes || '';
    $('subcEditAlert').value = s?.alertThreshold || '';
    setSubcRating(+s?.rating || 0);
    // populate projects dropdown
    const prjSel = $('subcEditProject');
    if (prjSel) {
        const projs = Object.entries(window.projects || {});
        prjSel.innerHTML = '<option value="">— بدون تحديد —</option>' +
            projs.map(([pid,p])=>`<option value="${esc(pid)}" ${s?.projectId===pid?'selected':''}>${esc(p.name||pid)}</option>`).join('');
    }
    $('ovSubcEdit').classList.add('show');
};

window.saveSubcontractor = async function() {
    const id = $('subcEditId').value || push(R.subc).key;
    const name = $('subcEditName').value.trim();
    if (!name) { toast('أدخل اسم المقاول', 'e'); return; }
    const alertVal = parseFloat($('subcEditAlert').value) || 0;
    await set(ref(db, `ledger/subcontractors/${id}`), {
        name, specialty: $('subcEditSpecialty').value.trim(),
        phone: $('subcEditPhone').value.trim(), crNumber: $('subcEditCR').value.trim(),
        iban: $('subcEditIBAN').value.trim(), notes: $('subcEditNotes').value.trim(),
        rating: +$('subcEditRating').value || 0,
        projectId: $('subcEditProject').value || '',
        alertThreshold: alertVal || 0,
        createdAt: $('subcEditId').value ? (window.subcontractors||{})[id]?.createdAt || Date.now() : Date.now()
    });
    $('ovSubcEdit').classList.remove('show');
    toast('تم حفظ بيانات المقاول', 's');
};

window.deleteSubcontractor = async function(id) {
    const s = (window.subcontractors||{})[id];
    if (!confirm(`حذف المقاول "${s?.name}"؟ سيتم حذف جميع معاملاته أيضاً.`)) return;
    await remove(ref(db, `ledger/subcontractors/${id}`));
    // حذف المعاملات المرتبطة
    const trans = window.subcontractorTrans || {};
    await Promise.all(Object.entries(trans).filter(([,t]) => t.subId===id).map(([k]) => remove(ref(db,`ledger/subcontractorTrans/${k}`))));
    toast('تم الحذف', 's');
};

// ══════════════════════════════════════════════════════
// [SUB2] كشف حساب المقاول
// ══════════════════════════════════════════════════════
window.openSubStatement = function(id) {
    window._subActiveId = id;
    nav('substatement', $('n-subst'));
    renderSubStatement();
};

window.renderSubStatement = function() {
    const id = window._subActiveId;
    if (!id) return;
    const s = (window.subcontractors||{})[id] || {};
    const trans = window.subcontractorTrans || {};
    const q = ($('subStSearch')?.value||'').trim().toLowerCase();
    const from = $('subStFrom')?.value;
    const to = $('subStTo')?.value;

    let rows = Object.entries(trans)
        .filter(([,t]) => t.subId === id)
        .filter(([,t]) => {
            if (from && t.date < from) return false;
            if (to   && t.date > to)   return false;
            if (q && !t.notes?.toLowerCase().includes(q) && !String(t.projectRef||'').includes(q)) return false;
            return true;
        })
        .sort((a,b) => a[1].date?.localeCompare(b[1].date));

    // رصيد متراكم
    let running = 0;
    const rowsHtml = rows.map(([key, t], i) => {
        const dr = t.type === 'debit'  ? +t.amount : 0;
        const cr = t.type === 'credit' ? +t.amount : 0;
        running += dr - cr;
        const balColor = running > 0 ? '#c0392b' : running < 0 ? '#27ae60' : '#555';
        return `<tr>
            <td style="text-align:center">${i+1}</td>
            <td>${esc(t.date)||''}</td>
            <td>${esc(t.projectRef)||'-'}</td>
            <td style="text-align:left;direction:ltr">${dr ? fmt(dr) : ''}</td>
            <td style="text-align:left;direction:ltr">${cr ? fmt(cr) : ''}</td>
            <td style="font-weight:700;color:${balColor};text-align:left;direction:ltr">${fmt(Math.abs(running))} ${running>0?'م':running<0?'د':''}</td>
            <td>${esc(t.notes)||'-'}</td>
            <td style="text-align:center">
                <button onclick="deleteSubTr('${key}')" style="background:#e74c3c;color:white;border:none;border-radius:5px;padding:3px 8px;cursor:pointer;font-size:11px">✕</button>
            </td>
        </tr>`;
    }).join('');

    const totalDr = rows.reduce((a,[,t])=>a+(t.type==='debit'?+t.amount:0),0);
    const totalCr = rows.reduce((a,[,t])=>a+(t.type==='credit'?+t.amount:0),0);
    const net = totalDr - totalCr;

    const nameEl = $('subStName');
    const summaryEl = $('subStSummary');
    const tbody = $('subStTbody');
    if (nameEl) nameEl.textContent = `كشف حساب: ${s.name||''}`;
    if (tbody) tbody.innerHTML = rowsHtml || `<tr><td colspan="8" style="text-align:center;padding:20px;color:#aaa">لا توجد معاملات</td></tr>`;
    if (summaryEl) summaryEl.innerHTML = `
        <div style="background:#fdedec;border-radius:8px;padding:10px 16px;text-align:center"><div style="font-size:11px;color:#888">إجمالي المستحقات</div><div style="font-size:18px;font-weight:800;color:#c0392b">${fmt(totalDr)}</div></div>
        <div style="background:#eafaf1;border-radius:8px;padding:10px 16px;text-align:center"><div style="font-size:11px;color:#888">إجمالي المدفوعات</div><div style="font-size:18px;font-weight:800;color:#27ae60">${fmt(totalCr)}</div></div>
        <div style="background:${net>0?'#fdedec':net<0?'#eafaf1':'#f8f9fa'};border-radius:8px;padding:10px 16px;text-align:center"><div style="font-size:11px;color:#888">الرصيد</div><div style="font-size:18px;font-weight:800;color:${net>0?'#c0392b':net<0?'#27ae60':'#555'}">${fmt(Math.abs(net))} ${net>0?'مستحق':net<0?'دائن':''}</div></div>
    `;
};

window.openSubTrForm = function(type) {
    $('subTrType').value = type;
    $('subTrTypeLabel').textContent = type === 'debit' ? '📌 تسجيل مستحق على المقاول' : '💸 تسجيل دفعة للمقاول';
    $('subTrTypeLabel').style.color = type === 'debit' ? '#c0392b' : '#27ae60';
    $('subTrDate').value = new Date().toISOString().split('T')[0];
    $('subTrAmount').value = '';
    $('subTrRef').value = '';
    $('subTrNotes').value = '';
    // populate projects + pre-select contractor's main project
    const prjSel = $('subTrProject');
    if (prjSel) {
        const projs = Object.entries(window.projects || {});
        const activeSubc = (window.subcontractors||{})[window._subActiveId] || {};
        prjSel.innerHTML = '<option value="">— بدون تحديد —</option>' +
            projs.map(([pid,p])=>`<option value="${esc(pid)}" ${activeSubc.projectId===pid?'selected':''}>${esc(p.name||pid)}</option>`).join('');
    }
    $('ovSubTr').classList.add('show');
};

window.saveSubTr = async function() {
    const id = window._subActiveId;
    if (!id) return;
    const amount = parseFloat($('subTrAmount').value);
    const date   = $('subTrDate').value;
    if (!amount || amount <= 0) { toast('أدخل مبلغاً صحيحاً', 'e'); return; }
    if (!date) { toast('أدخل التاريخ', 'e'); return; }
    const key = push(R.subTr).key;
    await set(ref(db, `ledger/subcontractorTrans/${key}`), {
        subId: id, type: $('subTrType').value, amount,
        date, projectRef: $('subTrRef').value.trim(),
        projectId: $('subTrProject')?.value || '',
        notes: $('subTrNotes').value.trim(), createdAt: Date.now()
    });
    $('ovSubTr').classList.remove('show');
    toast('تم التسجيل', 's');
};

window.deleteSubTr = async function(key) {
    if (!confirm('حذف هذه المعاملة؟')) return;
    await remove(ref(db, `ledger/subcontractorTrans/${key}`));
    toast('تم الحذف', 's');
};

window.printSubStatement = function() {
    const id = window._subActiveId;
    const s  = (window.subcontractors||{})[id]||{};
    const trans = window.subcontractorTrans || {};
    let rows = Object.entries(trans).filter(([,t])=>t.subId===id).sort((a,b)=>a[1].date?.localeCompare(b[1].date));
    let running = 0;
    const rowsHtml = rows.map(([,t],i) => {
        const dr = t.type==='debit'?+t.amount:0;
        const cr = t.type==='credit'?+t.amount:0;
        running += dr-cr;
        return `<tr><td>${i+1}</td><td>${esc(t.date)||''}</td><td>${esc(t.projectRef)||'-'}</td><td>${dr?fmt(dr):''}</td><td>${cr?fmt(cr):''}</td><td style="color:${running>0?'#c0392b':running<0?'#27ae60':'#555'}">${fmt(Math.abs(running))} ${running>0?'م':running<0?'د':''}</td><td>${esc(t.notes)||''}</td></tr>`;
    }).join('');
    const totalDr = rows.reduce((a,[,t])=>a+(t.type==='debit'?+t.amount:0),0);
    const totalCr = rows.reduce((a,[,t])=>a+(t.type==='credit'?+t.amount:0),0);
    const net = totalDr-totalCr;
    const w = window.open('','_blank');
    w.document.write(`<html dir="rtl"><head><meta charset="utf-8"><title>كشف حساب ${esc(s.name)||''}</title>
    <style>body{font-family:Arial,sans-serif;font-size:12px;direction:rtl;padding:20px}h2,h3{text-align:center}table{width:100%;border-collapse:collapse;margin-top:14px}td,th{border:1px solid #ccc;padding:7px 9px}th{background:#7d5a00;color:white}.summary{display:flex;gap:20px;justify-content:center;margin:14px 0}.sum-box{border:1px solid #ccc;border-radius:6px;padding:10px 20px;text-align:center}.sum-label{font-size:11px;color:#888}.sum-val{font-size:17px;font-weight:800;margin-top:4px}@media print{button{display:none}}</style>
    </head><body>
    <h2>كشف حساب: ${esc(s.name)||''}</h2>
    <h3 style="font-weight:400;color:#888">التخصص: ${esc(s.specialty)||'-'} | الجوال: ${esc(s.phone)||'-'} | IBAN: ${esc(s.iban)||'-'}</h3>
    <div class="summary">
      <div class="sum-box"><div class="sum-label">إجمالي المستحقات</div><div class="sum-val" style="color:#c0392b">${fmt(totalDr)}</div></div>
      <div class="sum-box"><div class="sum-label">إجمالي المدفوعات</div><div class="sum-val" style="color:#27ae60">${fmt(totalCr)}</div></div>
      <div class="sum-box"><div class="sum-label">الرصيد</div><div class="sum-val" style="color:${net>0?'#c0392b':net<0?'#27ae60':'#555'}">${fmt(Math.abs(net))} ${net>0?'مستحق':net<0?'دائن':''}</div></div>
    </div>
    <table><thead><tr><th>م</th><th>التاريخ</th><th>رقم العهدة</th><th>مستحق (مدين)</th><th>مدفوع (دائن)</th><th>الرصيد المتراكم</th><th>ملاحظات</th></tr></thead><tbody>${rowsHtml}</tbody></table>
    <br><button onclick="window.print()">🖨️ طباعة</button></body></html>`);
    w.document.close();
};

window.exportSubStExcel = function() {
    const id = window._subActiveId;
    if (!id) return;
    const s  = (window.subcontractors||{})[id]||{};
    const trans = window.subcontractorTrans || {};
    let rows = Object.entries(trans).filter(([,t])=>t.subId===id).sort((a,b)=>a[1].date?.localeCompare(b[1].date));
    let running = 0;
    const data = [['م','التاريخ','رقم العهدة','مستحق','مدفوع','الرصيد المتراكم','ملاحظات']];
    rows.forEach(([,t],i) => {
        const dr = t.type==='debit'?+t.amount:0;
        const cr = t.type==='credit'?+t.amount:0;
        running += dr-cr;
        data.push([i+1, t.date||'', t.projectRef||'', dr||'', cr||'', running, t.notes||'']);
    });
    const csv = data.map(r=>r.map(c=>`"${String(c).replace(/"/g,'""')}"`).join(',')).join('\n');
    const blob = new Blob(['﻿'+csv],{type:'text/csv;charset=utf-8'});
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `كشف_حساب_${s.name||'مقاول'}_${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    toast('تم تصدير الكشف', 's');
};

