// [SUB3] إحصائيات مقاولي الباطن
// ══════════════════════════════════════════════════════
window.renderSubcAnalytics = function() {
    const el = $('subcAnaContent');
    if (!el) return;
    const subs  = window.subcontractors || {};
    const trans = window.subcontractorTrans || {};

    function totals(id) {
        const rows = Object.values(trans).filter(t => t.subId === id);
        const dr = rows.reduce((a,t) => a+(t.type==='debit'?+t.amount:0),0);
        const cr = rows.reduce((a,t) => a+(t.type==='credit'?+t.amount:0),0);
        return { dr, cr, bal: dr-cr, count: rows.length };
    }

    const entries = Object.entries(subs).map(([id,s]) => ({id, s, ...totals(id)}));
    if (!entries.length) { el.innerHTML = '<div style="text-align:center;padding:40px;color:#aaa">لا توجد بيانات بعد</div>'; return; }

    const totalDr = entries.reduce((a,e)=>a+e.dr,0);
    const totalCr = entries.reduce((a,e)=>a+e.cr,0);
    const netBal  = totalDr - totalCr;
    const avgRating = entries.reduce((a,e)=>a+(+e.s.rating||0),0) / entries.length;

    // ترتيب حسب الرصيد تنازلياً
    const byBal = [...entries].sort((a,b)=>b.bal-a.bal);
    const maxBal = Math.max(...entries.map(e=>e.bal), 1);

    // توزيع التقييمات
    const ratingDist = [0,0,0,0,0];
    entries.forEach(e=>{ if(e.s.rating>=1 && e.s.rating<=5) ratingDist[+e.s.rating-1]++; });

    // نسبة السداد لأكثر 5 مقاولين
    const top5 = [...entries].sort((a,b)=>b.dr-a.dr).slice(0,8);

    // المشاريع المرتبطة
    const byProject = {};
    Object.values(trans).forEach(t => {
        const key = t.projectId || '_none';
        if (!byProject[key]) byProject[key] = {dr:0,cr:0};
        if (t.type==='debit')  byProject[key].dr += +t.amount;
        if (t.type==='credit') byProject[key].cr += +t.amount;
    });

    const projs = window.projects || {};
    const projName = id => projs[id]?.name || (id==='_none'?'غير محدد':id);

    el.innerHTML = `
    <!-- KPIs -->
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:12px;margin-bottom:20px">
        <div class="kpi k1"><div class="kpi-ic">👷</div><div class="kpi-lb">المقاولون</div><div class="kpi-vl">${entries.length}</div></div>
        <div class="kpi k3" style="--kc:#c0392b"><div class="kpi-ic">📌</div><div class="kpi-lb">إجمالي المستحقات</div><div class="kpi-vl" style="font-size:14px">${fmt(totalDr)}</div></div>
        <div class="kpi k2" style="--kc:#27ae60"><div class="kpi-ic">💸</div><div class="kpi-lb">إجمالي المدفوعات</div><div class="kpi-vl" style="font-size:14px">${fmt(totalCr)}</div></div>
        <div class="kpi k4" style="--kc:${netBal>0?'#c0392b':'#27ae60'}"><div class="kpi-ic">⚖️</div><div class="kpi-lb">صافي الرصيد</div><div class="kpi-vl" style="font-size:14px">${fmt(Math.abs(netBal))}</div></div>
        <div class="kpi k1"><div class="kpi-ic">⭐</div><div class="kpi-lb">متوسط التقييم</div><div class="kpi-vl">${avgRating.toFixed(1)}</div><div class="kpi-sb">من 5</div></div>
        <div class="kpi k2" style="--kc:#8e44ad"><div class="kpi-ic">📊</div><div class="kpi-lb">نسبة السداد</div><div class="kpi-vl">${totalDr?Math.round(totalCr/totalDr*100):0}%</div></div>
    </div>

    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:16px">
        <!-- أعلى المقاولين بالرصيد -->
        <div class="card" style="padding:16px">
            <div style="font-weight:700;color:#7d5a00;margin-bottom:12px;font-size:14px">📊 أعلى المقاولين بالرصيد المستحق</div>
            ${byBal.slice(0,7).map(e=>{
                const pct = maxBal>0 ? Math.max(0,e.bal)/maxBal*100 : 0;
                const col = e.bal>0?'#c0392b':e.bal<0?'#27ae60':'#aaa';
                return `<div style="margin-bottom:10px">
                    <div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px">
                        <span style="font-weight:600">${esc(e.s.name)||'—'}</span>
                        <span style="color:${col};font-weight:700">${fmt(Math.abs(e.bal))}</span>
                    </div>
                    <div style="height:7px;background:#f0f0f0;border-radius:4px;overflow:hidden">
                        <div style="width:${pct}%;height:100%;background:${col};border-radius:4px;transition:width .4s"></div>
                    </div>
                </div>`;
            }).join('')}
        </div>

        <!-- نسبة السداد لأكبر المقاولين -->
        <div class="card" style="padding:16px">
            <div style="font-weight:700;color:#7d5a00;margin-bottom:12px;font-size:14px">💸 نسبة السداد للمقاولين</div>
            ${top5.map(e=>{
                const pct = e.dr>0 ? Math.min(100,Math.round(e.cr/e.dr*100)) : 0;
                const col = pct>=80?'#27ae60':pct>=50?'#f0a500':'#c0392b';
                return `<div style="margin-bottom:10px">
                    <div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px">
                        <span style="font-weight:600">${e.s.name||'—'}</span>
                        <span style="color:${col};font-weight:700">${pct}%</span>
                    </div>
                    <div style="height:7px;background:#f0f0f0;border-radius:4px;overflow:hidden">
                        <div style="width:${pct}%;height:100%;background:${col};border-radius:4px;transition:width .4s"></div>
                    </div>
                </div>`;
            }).join('')}
        </div>
    </div>

    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px">
        <!-- توزيع التقييمات -->
        <div class="card" style="padding:16px">
            <div style="font-weight:700;color:#7d5a00;margin-bottom:12px;font-size:14px">⭐ توزيع تقييمات المقاولين</div>
            ${[5,4,3,2,1].map(n=>{
                const cnt = ratingDist[n-1];
                const pct = entries.length>0 ? cnt/entries.length*100 : 0;
                return `<div style="display:flex;align-items:center;gap:8px;margin-bottom:8px">
                    <span style="font-size:12px;width:60px;color:#f0a500">${'★'.repeat(n)}${'☆'.repeat(5-n)}</span>
                    <div style="flex:1;height:10px;background:#f0f0f0;border-radius:5px;overflow:hidden">
                        <div style="width:${pct}%;height:100%;background:#f0a500;border-radius:5px"></div>
                    </div>
                    <span style="font-size:11px;color:#888;width:20px">${cnt}</span>
                </div>`;
            }).join('')}
        </div>

        <!-- المعاملات حسب المشروع -->
        <div class="card" style="padding:16px">
            <div style="font-weight:700;color:#7d5a00;margin-bottom:12px;font-size:14px">🏗️ المعاملات حسب المشروع</div>
            ${Object.entries(byProject).length ? Object.entries(byProject).sort((a,b)=>b[1].dr-a[1].dr).slice(0,6).map(([pid,v])=>`
                <div style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;border-bottom:1px solid #f0f0f0;font-size:12px">
                    <span style="font-weight:600">${esc(projName(pid))}</span>
                    <span><span style="color:#c0392b">${fmt(v.dr)}</span> / <span style="color:#27ae60">${fmt(v.cr)}</span></span>
                </div>`).join('') : '<div style="color:#aaa;text-align:center;padding:20px">لا توجد معاملات مرتبطة بمشاريع</div>'}
        </div>
    </div>`;
};

// ══════════════════════════════════════════════════════
// [AST1] إدارة الأصول الثابتة — سجل الأصول + الإهلاك التلقائي
// ══════════════════════════════════════════════════════
// طرق الإهلاك المدعومة (احترافية مثل البرامج العالمية)
const ASSET_DEP_METHODS = {
    straight:     { ar: 'القسط الثابت', en: 'Straight-Line' },
    declining:    { ar: 'القسط المتناقص', en: 'Declining Balance' },
    double:       { ar: 'المتناقص المضاعف', en: 'Double-Declining' },
    sum_of_years: { ar: 'مجموع أرقام السنوات', en: 'Sum-of-Years-Digits' },
    units:        { ar: 'وحدات الإنتاج', en: 'Units of Production' }
};
window.ASSET_DEP_METHODS = ASSET_DEP_METHODS;

// جدول الإهلاك السنوي حسب الطريقة — يرجع [{year, dep, accum, bookValue}]
function assetYearlySchedule(a) {
    const cost = +a.cost || 0;
    const salvage = Math.min(+a.salvageValue || 0, cost);
    const life = Math.max(1, Math.round(+a.usefulLifeYears || 1));
    const depreciable = Math.max(0, cost - salvage);
    const method = a.depMethod || 'straight';
    const rows = [];
    let accum = 0;
    if (method === 'declining' || method === 'double') {
        const rate = method === 'double' ? (2 / life) : (((+a.depRate || 0) / 100) || (1.5 / life));
        let bv = cost;
        for (let y = 1; y <= life; y++) {
            let dep = bv * rate;
            // القسط المتبقي بالقسط الثابت لضمان الوصول للقيمة التخريدية
            const slRemain = (depreciable - accum) / (life - y + 1);
            if (slRemain > dep) dep = slRemain;
            if (accum + dep > depreciable) dep = depreciable - accum;
            if (y === life) dep = Math.max(0, depreciable - accum);
            accum += dep; bv = cost - accum;
            rows.push({ year: y, dep, accum, bookValue: bv });
        }
    } else if (method === 'sum_of_years') {
        // مجموع أرقام السنوات: قسط السنة k = القابل للإهلاك × (العمر − k + 1) ÷ مجموع الأرقام
        const syd = life * (life + 1) / 2;
        for (let y = 1; y <= life; y++) {
            let dep = depreciable * (life - y + 1) / syd;
            if (y === life) dep = Math.max(0, depreciable - accum); // تسوية فروق التقريب
            accum += dep;
            rows.push({ year: y, dep, accum, bookValue: cost - accum });
        }
    } else { // straight / units (units يُحسب بالاستهلاك الفعلي لكن الجدول الزمني تقديري بالقسط الثابت)
        const annual = depreciable / life;
        for (let y = 1; y <= life; y++) {
            let dep = Math.min(annual, depreciable - accum);
            accum += dep;
            rows.push({ year: y, dep, accum, bookValue: cost - accum });
        }
    }
    return rows;
}
window.assetYearlySchedule = assetYearlySchedule;

function assetCalc(a, asOfDate) {
    const cost = +a.cost || 0;
    const life = Math.max(1, +a.usefulLifeYears || 1);
    const method = a.depMethod || 'straight';
    const ref = asOfDate || today();
    // 🏗️ أصل تحت الإنشاء (CWIP): لا إهلاك — القيمة الدفترية = التكلفة المتراكمة
    if ((a.status || 'active') === 'cwip') {
        return { cost, salvage: 0, life, depreciable: 0, annualDep: 0, monthlyDep: 0, monthsElapsed: 0, accumDep: 0, bookValue: cost, method, cwip: true };
    }
    // ♻️ بعد إعادة التقييم / انخفاض القيمة: إهلاك القسط الثابت من القيمة الجديدة على العمر المتبقي
    const rb = a.revalBasis;
    if (rb && rb.date && ref >= rb.date) {
        const salvage2 = Math.min(+a.salvageValue || 0, +rb.bookValue || 0);
        const depreciable2 = Math.max(0, (+rb.bookValue || 0) - salvage2);
        const lifeMonths = Math.max(1, +rb.lifeMonthsRemaining || 1);
        const d1 = new Date(rb.date + 'T00:00:00'); const d2 = new Date(ref + 'T00:00:00');
        let m = (d2.getFullYear() - d1.getFullYear()) * 12 + (d2.getMonth() - d1.getMonth());
        m = Math.max(0, Math.min(m, lifeMonths));
        const depSince = depreciable2 * (m / lifeMonths);
        const bookValue2 = (+rb.bookValue || 0) - depSince;
        return { cost, salvage: salvage2, life: lifeMonths / 12, depreciable: depreciable2, annualDep: depreciable2 / (lifeMonths / 12), monthlyDep: depreciable2 / lifeMonths, monthsElapsed: m, accumDep: cost - bookValue2, bookValue: bookValue2, method, revalued: true };
    }
    const salvage = Math.min(+a.salvageValue || 0, cost);
    const depreciable = Math.max(0, cost - salvage);
    let monthsElapsed = 0;
    if (a.purchaseDate) {
        const d1 = new Date(a.purchaseDate + 'T00:00:00');
        const d2 = new Date(ref + 'T00:00:00');
        monthsElapsed = (d2.getFullYear() - d1.getFullYear()) * 12 + (d2.getMonth() - d1.getMonth());
        monthsElapsed = Math.max(0, Math.min(monthsElapsed, life * 12));
    }
    let accumDep, annualDep, monthlyDep;
    if (method === 'units') {
        // إهلاك بوحدات الإنتاج: حسب الوحدات المستهلكة فعلياً
        const totalUnits = Math.max(1, +a.totalUnits || 1);
        const unitsUsed = Math.min(totalUnits, Math.max(0, +a.unitsUsed || 0));
        const depPerUnit = depreciable / totalUnits;
        accumDep = depPerUnit * unitsUsed;
        annualDep = 0; monthlyDep = depPerUnit; // monthlyDep هنا = إهلاك الوحدة الواحدة
    } else {
        const sched = assetYearlySchedule(a);
        const fullYears = Math.floor(monthsElapsed / 12);
        const partialMonths = monthsElapsed % 12;
        accumDep = 0;
        for (let y = 0; y < fullYears && y < sched.length; y++) accumDep += sched[y].dep;
        if (partialMonths > 0 && fullYears < sched.length) accumDep += sched[fullYears].dep * (partialMonths / 12);
        accumDep = Math.min(accumDep, depreciable);
        annualDep = sched[Math.min(fullYears, sched.length - 1)]?.dep || (depreciable / life);
        monthlyDep = annualDep / 12;
    }
    const bookValue = cost - accumDep;
    return { cost, salvage, life, depreciable, annualDep, monthlyDep, monthsElapsed, accumDep, bookValue, method };
}
window.assetCalc = assetCalc;

function syncAssetStatusFromMaintenance(assetId, maintsMap) {
    const a = (window.assets || {})[assetId];
    if (!a || a.status === 'disposed') return;
    const hasOpen = Object.values(maintsMap || {}).some(m => m.assetId === assetId && m.status !== 'done');
    const newStatus = hasOpen ? 'maintenance' : 'active';
    if ((a.status || 'active') !== newStatus) update(ref(db, `ledger/assets/${assetId}`), { status: newStatus });
}

window.renderAssets = function() {
    const assets = window.assets || {};
    const q = ($('assetSearch')?.value || '').trim().toLowerCase();
    const statusFilter = $('assetFilterStatus')?.value || '';
    const projectFilter = $('assetFilterProject')?.value || '';

    renderAssetAlerts();
    renderAssetDepRunsLog();
    if ($('astDepRunPeriod') && !$('astDepRunPeriod').value) $('astDepRunPeriod').value = today().slice(0, 7);

    const projSel = $('assetFilterProject');
    if (projSel && projSel.children.length <= 1) {
        const projs = Object.entries(window.projects || {});
        projSel.innerHTML = '<option value="">كل المشاريع</option>' + projs.map(([pid, p]) => `<option value="${esc(pid)}">${esc(p.name || pid)}</option>`).join('');
    }

    const entries = Object.entries(assets).map(([id, a]) => ({ id, a, calc: assetCalc(a, a.status === 'disposed' ? a.disposal?.date : undefined) }));

    const kpiEl = $('assetsKpis');
    if (kpiEl) {
        const total = entries.length;
        const maint = entries.filter(e => e.a.status === 'maintenance').length;
        const disposed = entries.filter(e => e.a.status === 'disposed').length;
        const totalCost = entries.reduce((s, e) => s + (+e.a.cost || 0), 0);
        const live = entries.filter(e => e.a.status !== 'disposed');
        const totalBook = live.reduce((s, e) => s + e.calc.bookValue, 0);
        const totalAccumDep = live.reduce((s, e) => s + e.calc.accumDep, 0);
        kpiEl.innerHTML = `
          <div class="kpi k1"><div class="kpi-ic">🏭</div><div class="kpi-lb">عدد الأصول</div><div class="kpi-vl">${total}</div><div class="kpi-sb">أصل مسجل</div></div>
          <div class="kpi k4"><div class="kpi-ic">💰</div><div class="kpi-lb">إجمالي التكلفة</div><div class="kpi-vl" style="font-size:15px">${fmt(totalCost)}</div><div class="kpi-sb">ريال</div></div>
          <div class="kpi k3" style="--kc:#e67e22"><div class="kpi-ic">📉</div><div class="kpi-lb">الإهلاك المتراكم</div><div class="kpi-vl" style="font-size:15px">${fmt(totalAccumDep)}</div><div class="kpi-sb">ريال</div></div>
          <div class="kpi k2" style="--kc:#27ae60"><div class="kpi-ic">📒</div><div class="kpi-lb">القيمة الدفترية الحالية</div><div class="kpi-vl" style="font-size:15px">${fmt(totalBook)}</div><div class="kpi-sb">ريال</div></div>
          <div class="kpi k1" style="--kc:#e67e22"><div class="kpi-ic">🛠️</div><div class="kpi-lb">قيد الصيانة</div><div class="kpi-vl">${maint}</div><div class="kpi-sb">أصل</div></div>
          <div class="kpi k1" style="--kc:#95a5a6"><div class="kpi-ic">🗑️</div><div class="kpi-lb">مخرّد/مُباع</div><div class="kpi-vl">${disposed}</div><div class="kpi-sb">أصل</div></div>
        `;
    }

    let list = entries.filter(({ a }) => {
        if (q && !(a.name || '').toLowerCase().includes(q) && !(a.code || '').toLowerCase().includes(q) && !(a.category || '').toLowerCase().includes(q)) return false;
        if (statusFilter && (a.status || 'active') !== statusFilter) return false;
        if (projectFilter && a.projectId !== projectFilter) return false;
        return true;
    });

    const tbody = $('assetsTbody');
    if (!tbody) return;
    if (!list.length) { tbody.innerHTML = `<tr><td colspan="9" style="text-align:center;padding:24px;color:#aaa">لا توجد نتائج</td></tr>`; return; }

    const statusMap = { active: ['نشط', '#27ae60'], maintenance: ['قيد الصيانة', '#e67e22'], cwip: ['تحت الإنشاء', '#2980b9'], disposed: ['مخرّد/مُباع', '#95a5a6'] };
    tbody.innerHTML = list.map(({ id, a, calc }, i) => {
        const st = statusMap[a.status || 'active'] || statusMap.active;
        const projName = a.projectId ? (window.projects || {})[a.projectId]?.name : '';
        const empName = a.employeeId ? (window.emp || {})[a.employeeId]?.name : '';
        const who = [projName, empName].filter(Boolean).map(esc).join(' / ') || '-';
        return `<tr style="cursor:pointer;transition:background .15s" onmouseover="this.style.background='#f4f6f7'" onmouseout="this.style.background=''" onclick="openAssetView('${id}')">
            <td style="text-align:center;padding:10px 8px">${i + 1}</td>
            <td style="padding:10px 8px"><strong>${esc(a.name) || ''}</strong>${a.code ? `<div style="font-size:10px;color:#888">${esc(a.code)}</div>` : ''}</td>
            <td style="padding:10px 8px">${esc(a.category) || '-'}</td>
            <td style="padding:10px 8px">${who}</td>
            <td style="padding:10px 8px">${esc(a.purchaseDate) || '-'}</td>
            <td style="padding:10px 8px">${fmt(+a.cost || 0)}</td>
            <td style="padding:10px 8px;font-weight:700;color:${a.status === 'disposed' ? '#95a5a6' : '#2c3e50'}">${a.status === 'disposed' ? '-' : fmt(calc.bookValue)}</td>
            <td style="padding:10px 8px;text-align:center"><span style="background:${st[1]}1a;color:${st[1]};padding:3px 8px;border-radius:6px;font-size:11px;font-weight:700">${st[0]}</span></td>
            <td style="padding:10px 8px;text-align:center;white-space:nowrap">
                <button onclick="event.stopPropagation();openAssetView('${id}')" style="background:#34495e;color:white;border:none;border-radius:6px;padding:4px 9px;cursor:pointer;font-size:11px;margin-left:3px" title="التفاصيل">📄</button>
                <button onclick="event.stopPropagation();openAssetLabel('${id}')" style="background:#16a085;color:white;border:none;border-radius:6px;padding:4px 9px;cursor:pointer;font-size:11px;margin-left:3px" title="ملصق باركود">🏷️</button>
                <button onclick="event.stopPropagation();openAssetEdit('${id}')" style="background:#2980b9;color:white;border:none;border-radius:6px;padding:4px 9px;cursor:pointer;font-size:11px;margin-left:3px" title="تعديل">✏️</button>
                <button onclick="event.stopPropagation();deleteAsset('${id}')" style="background:#e74c3c;color:white;border:none;border-radius:6px;padding:4px 9px;cursor:pointer;font-size:11px" title="حذف">🗑️</button>
            </td>
        </tr>`;
    }).join('');
};

window.exportAssetsExcel = function() {
    const assets = window.assets || {};
    const rows = [['م', 'اسم الأصل', 'الكود', 'الفئة', 'تاريخ الشراء', 'التكلفة', 'القيمة الدفترية', 'الحالة']];
    Object.entries(assets).forEach(([id, a], i) => {
        const calc = assetCalc(a, a.status === 'disposed' ? a.disposal?.date : undefined);
        const statusLabel = a.status === 'disposed' ? 'مخرّد/مُباع' : a.status === 'maintenance' ? 'قيد الصيانة' : 'نشط';
        rows.push([i + 1, a.name || '', a.code || '', a.category || '', a.purchaseDate || '', +a.cost || 0, a.status === 'disposed' ? '-' : Math.round(calc.bookValue), statusLabel]);
    });
    const csv = rows.map(r => r.map(c => `"${String(c).replace(/"/g, '""')}"`).join(',')).join('\n');
    const BOM = '﻿';
    const blob = new Blob([BOM + csv], { type: 'text/csv;charset=utf-8' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `سجل_الأصول_${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    toast('تم تصدير الملف', 's');
};

window.printAssetsList = function() {
    const assets = window.assets || {};
    const rows = Object.entries(assets).map(([id, a], i) => {
        const calc = assetCalc(a, a.status === 'disposed' ? a.disposal?.date : undefined);
        const statusLabel = a.status === 'disposed' ? 'مخرّد/مُباع' : a.status === 'maintenance' ? 'قيد الصيانة' : 'نشط';
        return `<tr><td>${i + 1}</td><td>${esc(a.name) || ''}</td><td>${esc(a.category) || '-'}</td><td>${esc(a.purchaseDate) || '-'}</td><td>${fmt(+a.cost || 0)}</td><td>${a.status === 'disposed' ? '-' : fmt(calc.bookValue)}</td><td>${statusLabel}</td></tr>`;
    }).join('');
    const w = window.open('', '_blank');
    w.document.write(`<html dir="rtl"><head><meta charset="utf-8"><title>سجل الأصول</title>
    <style>body{font-family:Arial,sans-serif;font-size:12px}table{width:100%;border-collapse:collapse}td,th{border:1px solid #ccc;padding:7px 9px}th{background:#34495e;color:white}@media print{button{display:none}}h2{text-align:center}</style>
    </head><body><h2>سجل الأصول الثابتة</h2><p style="text-align:center;color:#888">تاريخ الطباعة: ${new Date().toLocaleDateString('ar')}</p>
    <table><thead><tr><th>م</th><th>الاسم</th><th>الفئة</th><th>تاريخ الشراء</th><th>التكلفة</th><th>القيمة الدفترية</th><th>الحالة</th></tr></thead><tbody>${rows}</tbody></table>
    <br><button onclick="window.print()">🖨️ طباعة</button></body></html>`);
    w.document.close();
};

function fillAssetProjectSelect(sel, selectedId) {
    if (!sel) return;
    const projs = Object.entries(window.projects || {});
    sel.innerHTML = '<option value="">— بدون تحديد —</option>' + projs.map(([pid, p]) => `<option value="${esc(pid)}" ${selectedId === pid ? 'selected' : ''}>${esc(p.name || pid)}</option>`).join('');
}
function fillAssetEmployeeSelect(sel, selectedId) {
    if (!sel) return;
    const emps = Object.entries(window.emp || {});
    sel.innerHTML = '<option value="">— بدون تحديد —</option>' + emps.map(([eid, e]) => `<option value="${esc(eid)}" ${selectedId === eid ? 'selected' : ''}>${esc(e.name || eid)}</option>`).join('');
}
// قائمة حسابات شجرة الحسابات (التفصيلية فقط) لاختيار حساب الأصل/المجمع/المصروف
function fillAssetAccountSelect(sel, selectedCode, defaultHint) {
    if (!sel) return;
    const accs = Object.values(window.chartOfAccounts || {}).filter(a => a.nature !== 'header').sort((x, y) => (x.code || '').localeCompare(y.code || ''));
    sel.innerHTML = `<option value="">— افتراضي${defaultHint ? `: ${esc(defaultHint)}` : ''} —</option>` +
        accs.map(a => `<option value="${esc(a.code)}" ${selectedCode === a.code ? 'selected' : ''}>${esc(a.code)} — ${esc(a.nameAr)}</option>`).join('');
}

// إظهار/إخفاء حقول الطريقة حسب الاختيار
window.onAssetMethodChange = function() {
    const m = $('assetEditMethod')?.value || 'straight';
    if ($('assetEditRateWrap')) $('assetEditRateWrap').style.display = (m === 'declining') ? '' : 'none';
    if ($('assetEditUnitsWrap')) $('assetEditUnitsWrap').style.display = (m === 'units') ? '' : 'none';
    if ($('assetEditUnitsUsedWrap')) $('assetEditUnitsUsedWrap').style.display = (m === 'units') ? '' : 'none';
};

window.openAssetEdit = function(id) {
    const a = id ? (window.assets || {})[id] : {};
    $('assetEditId').value = id || '';
    $('assetEditName').value = a?.name || '';
    $('assetEditCode').value = a?.code || '';
    fillAssetCategorySelect($('assetEditCategory'), a?.category || 'معدات ثقيلة');
    $('assetEditSupplier').value = a?.supplierName || '';
    $('assetEditDate').value = a?.purchaseDate || today();
    $('assetEditCost').value = a?.cost || '';
    $('assetEditLife').value = a?.usefulLifeYears || 5;
    $('assetEditSalvage').value = a?.salvageValue || 0;
    $('assetEditMethod').value = a?.depMethod || 'straight';
    $('assetEditRate').value = a?.depRate || '';
    $('assetEditTotalUnits').value = a?.totalUnits || '';
    $('assetEditUnitsUsed').value = a?.unitsUsed || '';
    $('assetEditWarranty').value = a?.warrantyEnd || '';
    $('assetEditInsurance').value = a?.insuranceEnd || '';
    $('assetEditNextMaint').value = a?.nextMaintDate || '';
    $('assetEditPolicy').value = a?.insurancePolicy || '';
    $('assetEditMeterUnit').value = a?.meterUnit || '';
    $('assetEditMeter').value = a?.meterReading || '';
    $('assetEditPmEvery').value = a?.pmEveryMonths || '';
    $('assetEditNotes').value = a?.notes || '';
    // 🏗️ خيار «تحت الإنشاء» يظهر فقط عند إضافة أصل جديد
    const cwipWrap = $('assetEditCwipWrap');
    const isNew = !id;
    if (cwipWrap) cwipWrap.style.display = isNew ? '' : 'none';
    if ($('assetEditCwip')) $('assetEditCwip').checked = false;
    onAssetMethodChange();
    fillAssetProjectSelect($('assetEditProject'), a?.projectId);
    fillAssetEmployeeSelect($('assetEditEmployee'), a?.employeeId);
    // 🔗 حسابات الربط المحاسبي لهذا الأصل (مع توضيح الافتراضي حسب الفئة)
    const def = assetGLAccounts({ category: a?.category || 'معدات ثقيلة' });
    const defName = code => { const acc = assetFindAcc(code); return acc ? `${acc.code} — ${acc.nameAr}` : code; };
    fillAssetAccountSelect($('assetEditGlAsset'), a?.glAssetAcc, defName(def.assetCode));
    fillAssetAccountSelect($('assetEditGlAccum'), a?.glAccumDepAcc, defName(def.accumCode));
    fillAssetAccountSelect($('assetEditGlExpense'), a?.glExpenseAcc, defName(def.expenseCode));
    $('ovAssetEdit').classList.add('show');
};

window.saveAsset = async function() {
    const id = $('assetEditId').value || push(R.assets).key;
    const name = $('assetEditName').value.trim();
    const purchaseDate = $('assetEditDate').value;
    const cost = parseFloat($('assetEditCost').value) || 0;
    const isNew = !$('assetEditId').value;
    const isCwip = isNew && $('assetEditCwip')?.checked;
    if (!name) { toast('أدخل اسم الأصل', 'e'); return; }
    if (!purchaseDate) { toast('أدخل تاريخ الشراء', 'e'); return; }
    if (!isCwip && cost <= 0) { toast('أدخل تكلفة الشراء', 'e'); return; } // الأصل تحت الإنشاء يبدأ بتكلفة صفر وتُجمَّع لاحقاً
    const method = $('assetEditMethod').value || 'straight';
    if (method === 'units' && (parseInt($('assetEditTotalUnits').value) || 0) <= 0) { toast('أدخل إجمالي الوحدات الإنتاجية', 'e'); return; }
    const existing = (window.assets || {})[id] || {};
    await update(ref(db, `ledger/assets/${id}`), {
        name, code: $('assetEditCode').value.trim(),
        category: $('assetEditCategory').value,
        supplierName: $('assetEditSupplier').value.trim(),
        purchaseDate, cost,
        usefulLifeYears: parseInt($('assetEditLife').value) || 1,
        salvageValue: parseFloat($('assetEditSalvage').value) || 0,
        depMethod: method,
        depRate: parseFloat($('assetEditRate').value) || 0,
        totalUnits: parseInt($('assetEditTotalUnits').value) || 0,
        unitsUsed: parseInt($('assetEditUnitsUsed').value) || 0,
        warrantyEnd: $('assetEditWarranty').value || '',
        insuranceEnd: $('assetEditInsurance').value || '',
        nextMaintDate: $('assetEditNextMaint').value || '',
        insurancePolicy: $('assetEditPolicy').value.trim(),
        pmEveryMonths: parseInt($('assetEditPmEvery').value) || 0,
        meterUnit: $('assetEditMeterUnit').value || '',
        meterReading: parseFloat($('assetEditMeter').value) || 0,
        glAssetAcc: $('assetEditGlAsset').value || '',
        glAccumDepAcc: $('assetEditGlAccum').value || '',
        glExpenseAcc: $('assetEditGlExpense').value || '',
        projectId: $('assetEditProject').value || '',
        employeeId: $('assetEditEmployee').value || '',
        notes: $('assetEditNotes').value.trim(),
        status: isCwip ? 'cwip' : (existing.status || 'active'),
        createdAt: existing.createdAt || Date.now()
    });
    $('ovAssetEdit').classList.remove('show');
    toast(isCwip ? 'تم إنشاء أصل تحت الإنشاء — أضف تكاليفه ثم رسمِله' : 'تم حفظ بيانات الأصل', 's');
    if (typeof logAudit === 'function') logAudit(isNew ? 'إضافة' : 'تعديل', 'الأصول', `${isNew ? 'إضافة' : 'تعديل'} أصل: ${name}${isCwip ? ' (تحت الإنشاء)' : ''}`);
    // 🆕 قيد اقتناء تلقائي لأصل جاهز فقط (الأصل تحت الإنشاء يُرحّل قيده عند الرسملة)
    if (isNew && !isCwip) { try { await postAssetAcquisitionJournal(id); } catch (e) { console.warn('acquisition journal skipped', e); } }
    if ($('pg-assetdetail')?.classList.contains('act') && window._assetActiveId === id) renderAssetDetail();
};

window.deleteAsset = async function(id) {
    const a = (window.assets || {})[id];
    if (!confirm(`حذف الأصل "${a?.name}"؟ سيتم حذف سجلات الصيانة والنقل المرتبطة أيضاً.`)) return;
    await remove(ref(db, `ledger/assets/${id}`));
    const maint = window.assetMaintenance || {};
    await Promise.all(Object.entries(maint).filter(([, m]) => m.assetId === id).map(([k]) => remove(ref(db, `ledger/assetMaintenance/${k}`))));
    const trs = window.assetTransfers || {};
    await Promise.all(Object.entries(trs).filter(([, t]) => t.assetId === id).map(([k]) => remove(ref(db, `ledger/assetTransfers/${k}`))));
    if (typeof logAudit === 'function') logAudit('حذف', 'الأصول', `حذف أصل: ${a?.name || id}`);
    toast('تم الحذف', 's');
};

// ══════════════════════════════════════════════════════
// [AST2] ملف الأصل — النقل، الصيانة، التخريد/البيع
// ══════════════════════════════════════════════════════
window.openAssetView = function(id) {
    window._assetActiveId = id;
    nav('assetdetail', $('n-assets'));
    renderAssetDetail();
};

// ⏱️ تحديث قراءة العدّاد — وفي طريقة وحدات الإنتاج يحدّث الوحدات المستهلكة أيضاً
window.updateAssetMeter = async function(id) {
    const a = (window.assets || {})[id]; if (!a) return;
    const unitLabel = a.meterUnit === 'hours' ? 'ساعة' : a.meterUnit === 'km' ? 'كم' : 'وحدة';
    const val = prompt(`القراءة الجديدة للعدّاد (${unitLabel}):`, a.meterReading || 0);
    if (val === null) return;
    const reading = parseFloat(val); if (isNaN(reading) || reading < 0) { toast('قيمة غير صحيحة', 'e'); return; }
    const patch = { meterReading: reading };
    if ((a.depMethod || 'straight') === 'units') patch.unitsUsed = reading; // ربط الاستهلاك بالإهلاك
    await update(ref(db, `ledger/assets/${id}`), patch);
    toast('تم تحديث قراءة العدّاد', 's');
    if ($('pg-assetdetail')?.classList.contains('act') && window._assetActiveId === id) renderAssetDetail();
};

window.renderAssetDetail = function() {
    const id = window._assetActiveId;
    if (!id) return;
    const a = (window.assets || {})[id] || {};
    $('adName').textContent = `🏭 ${a.name || ''}`;
    const projName = a.projectId ? (window.projects || {})[a.projectId]?.name : '';
    const empName = a.employeeId ? (window.emp || {})[a.employeeId]?.name : '';
    $('adSub').textContent = [a.category, a.code, projName ? `🏗️ ${projName}` : '', empName ? `👤 ${empName}` : ''].filter(Boolean).join(' — ') || '-';

    // 🏗️ CWIP / ♻️ إعادة التقييم — لوحات وأزرار حسب الحالة
    const isCwip = (a.status || 'active') === 'cwip';
    if ($('adRevalBtn')) $('adRevalBtn').style.display = (isCwip || a.status === 'disposed') ? 'none' : '';
    renderAssetCwipPanel(id);
    renderAssetRevalHistory(id);
    renderAssetDocuments(id);

    const disposed = a.status === 'disposed';
    const disposeBtn = $('adDisposeBtn');
    if (disposeBtn) disposeBtn.style.display = disposed ? 'none' : '';

    const calc = assetCalc(a, disposed ? a.disposal?.date : undefined);

    // 💵 إجمالي تكلفة الملكية (TCO) = تكلفة الشراء + إجمالي الصيانة
    const maintTotal = Object.values(window.assetMaintenance || {}).filter(m => m.assetId === id).reduce((s, m) => s + (+m.cost || 0), 0);
    const tco = calc.cost + maintTotal;
    // ⏱️ قراءة العدّاد
    const meterUnitLabel = a.meterUnit === 'hours' ? 'ساعة' : a.meterUnit === 'km' ? 'كم' : '';

    const kpiEl = $('adDepKpis');
    if (kpiEl) {
        kpiEl.innerHTML = `
        <div class="kpi k1"><div class="kpi-ic">💰</div><div class="kpi-lb">تكلفة الشراء</div><div class="kpi-vl" style="font-size:14px">${fmt(calc.cost)}</div></div>
        <div class="kpi k3" style="--kc:#e67e22"><div class="kpi-ic">📉</div><div class="kpi-lb">إهلاك متراكم</div><div class="kpi-vl" style="font-size:14px">${fmt(calc.accumDep)}</div></div>
        <div class="kpi k2" style="--kc:${disposed ? '#95a5a6' : '#27ae60'}"><div class="kpi-ic">📒</div><div class="kpi-lb">القيمة الدفترية${disposed ? ' (وقت التخريد)' : ''}</div><div class="kpi-vl" style="font-size:14px">${fmt(calc.bookValue)}</div></div>
        <div class="kpi k4"><div class="kpi-ic">📆</div><div class="kpi-lb">إهلاك سنوي</div><div class="kpi-vl" style="font-size:14px">${fmt(calc.annualDep)}</div></div>
        <div class="kpi k1" style="--kc:#8e44ad"><div class="kpi-ic">💵</div><div class="kpi-lb">تكلفة الملكية (TCO)</div><div class="kpi-vl" style="font-size:14px">${fmt(tco)}</div><div class="kpi-sb">شراء + صيانة ${fmt(maintTotal)}</div></div>
        ${meterUnitLabel ? `<div class="kpi k1" style="--kc:#16a085"><div class="kpi-ic">⏱️</div><div class="kpi-lb">قراءة العدّاد</div><div class="kpi-vl" style="font-size:14px">${fmt(+a.meterReading || 0)} ${meterUnitLabel}</div><div class="kpi-sb"><span style="cursor:pointer;color:#16a085;text-decoration:underline" onclick="updateAssetMeter('${id}')">تحديث القراءة</span></div></div>` : ''}
        `;
    }

    const dBox = $('adDisposalBox');
    if (dBox) {
        if (disposed && a.disposal) {
            const gain = (+a.disposal.amount || 0) - calc.bookValue;
            dBox.innerHTML = `<div class="card" style="border-right:4px solid #c0392b;background:#fdf2f1">
                <div style="font-weight:800;color:#c0392b;margin-bottom:6px">🗑️ ${a.disposal.type === 'sale' ? 'تم بيع هذا الأصل' : 'تم تخريد هذا الأصل'}</div>
                <div style="font-size:12.5px;color:#555;display:grid;grid-template-columns:repeat(auto-fill,minmax(170px,1fr));gap:8px">
                    <div>التاريخ: <strong>${esc(a.disposal.date) || '-'}</strong></div>
                    <div>المبلغ المستلم: <strong>${fmt(+a.disposal.amount || 0)}</strong></div>
                    <div>القيمة الدفترية حينها: <strong>${fmt(calc.bookValue)}</strong></div>
                    <div>${gain >= 0 ? 'ربح' : 'خسارة'} التخريد: <strong style="color:${gain >= 0 ? '#27ae60' : '#c0392b'}">${fmt(Math.abs(gain))}</strong></div>
                </div>
                ${a.disposal.notes ? `<div style="margin-top:6px;font-size:12px;color:#777">${esc(a.disposal.notes)}</div>` : ''}
            </div>`;
        } else dBox.innerHTML = '';
    }

    const sched = $('adDepSchedule');
    if (sched) {
        const schedRows = assetYearlySchedule(a);
        const rows = schedRows.map(r => `<tr><td style="text-align:center">${r.year}</td><td>${fmt(r.dep)}</td><td>${fmt(r.accum)}</td><td>${fmt(r.bookValue)}</td></tr>`);
        sched.innerHTML = rows.join('') || '<tr><td colspan="4" style="text-align:center;padding:18px;color:#aaa">-</td></tr>';
    }
    const methEl = $('adDepMethod');
    if (methEl) methEl.textContent = (ASSET_DEP_METHODS[a.depMethod || 'straight'] || ASSET_DEP_METHODS.straight).ar;
    // 🔗 الحسابات المحاسبية المرتبطة بهذا الأصل
    const glEl = $('adGLInfo');
    if (glEl) {
        const gl = assetGLAccounts(a);
        const nm = code => { const acc = assetFindAcc(code); return acc ? `${esc(acc.code)} — ${esc(acc.nameAr)}` : esc(code); };
        const tag = (a.glAssetAcc || a.glAccumDepAcc || a.glExpenseAcc) ? '<span style="color:#2980b9">مخصّص</span>' : '<span style="color:#aaa">افتراضي حسب الفئة</span>';
        glEl.innerHTML = `🔗 الربط المحاسبي (${tag}): الأصل <strong>${nm(gl.assetCode)}</strong> · مجمع الإهلاك <strong>${nm(gl.accumCode)}</strong> · المصروف <strong>${nm(gl.expenseCode)}</strong>`;
    }

    const trLog = $('adTransferLog');
    if (trLog) {
        const trs = Object.values(window.assetTransfers || {}).filter(t => t.assetId === id).sort((x, y) => (y.date || '').localeCompare(x.date || ''));
        trLog.innerHTML = trs.length ? trs.map(t => {
            const toProj = t.toProjectId ? (window.projects || {})[t.toProjectId]?.name : '';
            const toEmp = t.toEmployeeId ? (window.emp || {})[t.toEmployeeId]?.name : '';
            const dest = [toProj, toEmp].filter(Boolean).join(' / ') || 'بدون تحديد';
            return `<div style="padding:8px 0;border-bottom:1px solid #f0f0f0;font-size:12px">
                <div style="font-weight:700">${esc(t.date) || ''}</div>
                <div style="color:#555">إلى: ${esc(dest)}</div>
                ${t.notes ? `<div style="color:#888;font-size:11px">${esc(t.notes)}</div>` : ''}
            </div>`;
        }).join('') : '<div style="color:#aaa;text-align:center;padding:18px">لا توجد عمليات نقل</div>';
    }

    const mTbody = $('adMaintTbody');
    if (mTbody) {
        const maints = Object.entries(window.assetMaintenance || {}).filter(([, m]) => m.assetId === id).sort((x, y) => (y[1].date || '').localeCompare(x[1].date || ''));
        mTbody.innerHTML = maints.length ? maints.map(([key, m], i) => {
            const typeLabel = m.type === 'breakdown' ? '🔧 عطل' : '🛠️ دورية';
            const stColor = m.status === 'done' ? '#27ae60' : '#e67e22';
            const stLabel = m.status === 'done' ? 'منتهية' : 'قيد التنفيذ';
            return `<tr>
                <td style="text-align:center">${i + 1}</td>
                <td>${esc(m.date) || ''}</td>
                <td>${typeLabel}</td>
                <td>${esc(m.desc) || '-'}</td>
                <td>${esc(m.vendor) || '-'}</td>
                <td>${fmt(+m.cost || 0)}</td>
                <td style="text-align:center"><span style="color:${stColor};font-weight:700">${stLabel}</span></td>
                <td style="text-align:center"><button onclick="deleteAssetMaint('${key}')" style="background:#e74c3c;color:white;border:none;border-radius:6px;padding:3px 7px;cursor:pointer;font-size:10px">🗑️</button></td>
            </tr>`;
        }).join('') : '<tr><td colspan="8" style="text-align:center;padding:18px;color:#aaa">لا توجد سجلات صيانة</td></tr>';
    }
};

window.openAssetTransfer = function(id) {
    const a = (window.assets || {})[id] || {};
    $('atrAssetId').value = id;
    $('atrDate').value = today();
    $('atrNotes').value = '';
    fillAssetProjectSelect($('atrProject'), a.projectId);
    fillAssetEmployeeSelect($('atrEmployee'), a.employeeId);
    $('ovAssetTransfer').classList.add('show');
};

window.saveAssetTransfer = async function() {
    const id = $('atrAssetId').value;
    const a = (window.assets || {})[id];
    if (!a) return;
    const date = $('atrDate').value;
    if (!date) { toast('أدخل تاريخ النقل', 'e'); return; }
    const toProjectId = $('atrProject').value || '';
    const toEmployeeId = $('atrEmployee').value || '';
    const key = push(R.assetTransfers).key;
    await set(ref(db, `ledger/assetTransfers/${key}`), {
        assetId: id, date,
        fromProjectId: a.projectId || '', toProjectId,
        fromEmployeeId: a.employeeId || '', toEmployeeId,
        notes: $('atrNotes').value.trim(),
        at: Date.now()
    });
    await update(ref(db, `ledger/assets/${id}`), { projectId: toProjectId, employeeId: toEmployeeId });
    $('ovAssetTransfer').classList.remove('show');
    toast('تم تسجيل النقل', 's');
};

window.openAssetMaint = function(id) {
    $('amAssetId').value = id;
    $('amId').value = '';
    $('amDate').value = today();
    $('amType').value = 'scheduled';
    $('amDesc').value = '';
    $('amVendor').value = '';
    $('amCost').value = '';
    $('amStatus').value = 'open';
    $('ovAssetMaint').classList.add('show');
};

window.saveAssetMaint = async function() {
    const assetId = $('amAssetId').value;
    const date = $('amDate').value;
    const desc = $('amDesc').value.trim();
    if (!date) { toast('أدخل التاريخ', 'e'); return; }
    if (!desc) { toast('أدخل وصف الصيانة', 'e'); return; }
    const key = $('amId').value || push(R.assetMaint).key;
    const rec = {
        assetId, date, type: $('amType').value,
        desc, vendor: $('amVendor').value.trim(),
        cost: parseFloat($('amCost').value) || 0,
        status: $('amStatus').value
    };
    await set(ref(db, `ledger/assetMaintenance/${key}`), rec);
    const maintsMap = { ...(window.assetMaintenance || {}), [key]: rec };
    syncAssetStatusFromMaintenance(assetId, maintsMap);
    // 🔁 صيانة وقائية متكررة: عند إنهاء صيانة دورية، احسب تاريخ الصيانة القادمة تلقائياً
    const a = (window.assets || {})[assetId];
    if (a && rec.type === 'scheduled' && rec.status === 'done' && (+a.pmEveryMonths || 0) > 0) {
        const d = new Date(date + 'T00:00:00');
        d.setMonth(d.getMonth() + (+a.pmEveryMonths));
        const next = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
        await update(ref(db, `ledger/assets/${assetId}`), { nextMaintDate: next });
        toast(`✅ تم حفظ الصيانة — الصيانة القادمة: ${next}`, 's', 5000);
    } else {
        toast('تم حفظ سجل الصيانة', 's');
    }
    $('ovAssetMaint').classList.remove('show');
};

window.deleteAssetMaint = async function(key) {
    const m = (window.assetMaintenance || {})[key];
    if (!m) return;
    if (!confirm('حذف سجل الصيانة؟')) return;
    await remove(ref(db, `ledger/assetMaintenance/${key}`));
    const maintsMap = { ...(window.assetMaintenance || {}) };
    delete maintsMap[key];
    syncAssetStatusFromMaintenance(m.assetId, maintsMap);
    toast('تم الحذف', 's');
};

window.openAssetDispose = function(id) {
    const a = (window.assets || {})[id] || {};
    if (a.status === 'disposed') { toast('هذا الأصل مخرّد بالفعل', 'e'); return; }
    const calc = assetCalc(a);
    $('adpAssetId').value = id;
    $('adpDate').value = today();
    $('adpType').value = 'sale';
    $('adpAmount').value = 0;
    $('adpNotes').value = '';
    $('adpBookValueBox').innerHTML = `القيمة الدفترية الحالية: <strong>${fmt(calc.bookValue)}</strong> ريال — التكلفة الأصلية: ${fmt(calc.cost)} ريال`;
    $('ovAssetDispose').classList.add('show');
};

window.saveAssetDispose = async function() {
    const id = $('adpAssetId').value;
    const a = (window.assets || {})[id];
    if (!a) return;
    const date = $('adpDate').value;
    if (!date) { toast('أدخل التاريخ', 'e'); return; }
    const type = $('adpType').value;
    const amount = parseFloat($('adpAmount').value) || 0;
    if (!confirm(`تأكيد ${type === 'sale' ? 'بيع' : 'تخريد'} الأصل "${a.name}"؟`)) return;
    await update(ref(db, `ledger/assets/${id}`), {
        status: 'disposed',
        disposal: { date, type, amount, notes: $('adpNotes').value.trim() }
    });
    $('ovAssetDispose').classList.remove('show');
    toast('تم تسجيل التخريد/البيع', 's');
    if (typeof logAudit === 'function') logAudit(type === 'sale' ? 'بيع أصل' : 'تخريد أصل', 'الأصول', `${type === 'sale' ? 'بيع' : 'تخريد'} أصل: ${a.name} بمبلغ ${fmt(amount)}`);
    // 🆕 قيد محاسبي تلقائي للتخريد/البيع (الربح/الخسارة)
    try { await postAssetDisposalJournal(id); } catch (e) { console.warn('disposal journal skipped', e); }
    if ($('pg-assetdetail')?.classList.contains('act') && window._assetActiveId === id) renderAssetDetail();
};

// ══════════════════════════════════════════════════════
// [AST3] الربط المحاسبي — قيود الاقتناء والإهلاك الشهري والتخريد
// ══════════════════════════════════════════════════════
// حسابات افتراضية حسب فئة الأصل (تطابق شجرة الحسابات الافتراضية)
const ASSET_CATEGORY_GL = {
    'معدات ثقيلة': '1210', 'مركبات': '1220', 'أدوات وعدد': '1210',
    'أجهزة مكتبية': '1230', 'مباني ومنشآت': '1240', 'أخرى': '1210'
};
// إعدادات الربط المحاسبي مع القيم الافتراضية
function assetGLCfg() {
    const c = window.assetAccCfg || {};
    return {
        enabled: c.enabled !== false,                 // مُفعّل افتراضياً
        accumDepAcc: c.accumDepAcc || '1290',         // مجمع إهلاك الأصول الثابتة
        depExpenseAcc: c.depExpenseAcc || '5370',     // مصروف الإهلاك
        disposalGainAcc: c.disposalGainAcc || '4310', // أرباح بيع الأصول الثابتة
        disposalLossAcc: c.disposalLossAcc || '5530', // خسائر بيع الأصول الثابتة
        clearingAcc: c.clearingAcc || '2110',         // الموردون (الدائنون) عند الاقتناء
        proceedsAcc: c.proceedsAcc || '1110',         // النقدية بالصندوق عند البيع
        revalSurplusAcc: c.revalSurplusAcc || '3300', // فائض إعادة التقييم (حقوق ملكية/OCI)
        impairmentAcc: c.impairmentAcc || '5370',     // خسارة انخفاض القيمة (مصروف)
        categoryGL: { ...ASSET_CATEGORY_GL, ...(c.categoryGL || {}) }
    };
}
window.assetGLCfg = assetGLCfg;

function assetFindAcc(code) {
    return Object.values(window.chartOfAccounts || {}).find(a => a.code === code);
}
function assetCategoryDef(name) {
    return Object.values(window.assetCategories || {}).find(c => c.name === name) || null;
}
window.assetCategoryDef = assetCategoryDef;
function assetAssetGLCode(a) {
    const cfg = assetGLCfg();
    const custom = assetCategoryDef(a.category);
    if (custom && custom.glAssetAcc) return custom.glAssetAcc;
    return cfg.categoryGL[a.category] || '1210';
}
// 🔗 الحسابات المحاسبية لأصل بعينه: تخصيص لكل أصل، وإلا الافتراضي (الفئة للأصل، والعام لمجمع الإهلاك والمصروف)
function assetGLAccounts(a) {
    const cfg = assetGLCfg();
    return {
        assetCode:   a.glAssetAcc   || assetAssetGLCode(a),
        accumCode:   a.glAccumDepAcc || cfg.accumDepAcc || '1290',
        expenseCode: a.glExpenseAcc || cfg.depExpenseAcc || '5370'
    };
}
window.assetGLAccounts = assetGLAccounts;

// قيد اقتناء أصل: من ح/ الأصل (مدين) إلى ح/ الموردين أو النقدية (دائن)
async function postAssetAcquisitionJournal(id) {
    const cfg = assetGLCfg();
    if (!cfg.enabled) return;
    const a = (window.assets || {})[id]; if (!a) return;
    if (a.acquisitionJournalKey) return; // لا تُكرّر
    const cost = +a.cost || 0; if (cost <= 0) return;
    const assetAcc = assetFindAcc(assetGLAccounts(a).assetCode);
    const credAcc = assetFindAcc(cfg.clearingAcc);
    if (!assetAcc || !credAcc) { toast('⚠️ لم يُنشأ قيد الاقتناء: تحقق من حسابات الأصول في شجرة الحسابات', 'wn', 7000); return; }
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const now = new Date().toISOString();
    const num = typeof generateJrnNumber === 'function' ? generateJrnNumber() : ('JV-AST-' + Date.now());
    const lines = [
        { accountCode: assetAcc.code, accountName: assetAcc.nameAr, description: `اقتناء أصل: ${a.name}`, costCenter: a.projectId || '', projectId: (window.projects || {})[a.projectId] ? a.projectId : '', debit: cost, credit: 0 },
        { accountCode: credAcc.code, accountName: credAcc.nameAr, description: `استحقاق ثمن أصل: ${a.name}${a.supplierName ? ' - ' + a.supplierName : ''}`, costCenter: a.projectId || '', projectId: (window.projects || {})[a.projectId] ? a.projectId : '', debit: 0, credit: cost }
    ];
    const jrnRef = await push(R.jrn, {
        number: num, date: a.purchaseDate || today(), lines, totalDebit: cost, totalCredit: cost,
        status: 'posted', sourceType: 'asset_acquisition', sourceKey: id,
        reference: a.code || '', description: `اقتناء أصل ثابت: ${a.name}`,
        createdAt: now, createdBy: userId, postedAt: now, postedBy: userId,
        autoGenerated: true, autoGeneratedFrom: 'asset_acquisition'
    });
    await update(ref(db, `ledger/assets/${id}`), { acquisitionJournalKey: jrnRef.key, acquisitionJournalNumber: num });
    toast(`✅ تم ترحيل قيد اقتناء الأصل (${num})`, 's');
}
window.postAssetAcquisitionJournal = postAssetAcquisitionJournal;

// قيد تخريد/بيع: مدين مجمع الإهلاك + النقدية، دائن حساب الأصل، والفرق ربح/خسارة
async function postAssetDisposalJournal(id) {
    const cfg = assetGLCfg();
    if (!cfg.enabled) return;
    const a = (window.assets || {})[id]; if (!a || a.status !== 'disposed' || !a.disposal) return;
    if (a.disposalJournalKey) return;
    const calc = assetCalc(a, a.disposal.date);
    const cost = calc.cost, accum = calc.accumDep, bookValue = calc.bookValue;
    const proceeds = +a.disposal.amount || 0;
    const gain = proceeds - bookValue; // موجب = ربح
    const gl = assetGLAccounts(a);
    const assetAcc = assetFindAcc(gl.assetCode);
    const accumAcc = assetFindAcc(gl.accumCode);
    const cashAcc = assetFindAcc(cfg.proceedsAcc);
    if (!assetAcc || !accumAcc) { toast('⚠️ لم يُنشأ قيد التخريد: تحقق من حسابات الأصول', 'wn', 7000); return; }
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const now = new Date().toISOString();
    const cc = a.projectId || ''; const pj = (window.projects || {})[a.projectId] ? a.projectId : '';
    const lines = [];
    if (accum > 0) lines.push({ accountCode: accumAcc.code, accountName: accumAcc.nameAr, description: `إلغاء مجمع إهلاك: ${a.name}`, costCenter: cc, projectId: pj, debit: accum, credit: 0 });
    if (proceeds > 0 && cashAcc) lines.push({ accountCode: cashAcc.code, accountName: cashAcc.nameAr, description: `متحصلات بيع: ${a.name}`, costCenter: cc, projectId: pj, debit: proceeds, credit: 0 });
    if (gain < 0) { const lossAcc = assetFindAcc(cfg.disposalLossAcc); if (lossAcc) lines.push({ accountCode: lossAcc.code, accountName: lossAcc.nameAr, description: `خسارة ${a.disposal.type === 'sale' ? 'بيع' : 'تخريد'}: ${a.name}`, costCenter: cc, projectId: pj, debit: Math.abs(gain), credit: 0 }); }
    lines.push({ accountCode: assetAcc.code, accountName: assetAcc.nameAr, description: `استبعاد أصل: ${a.name}`, costCenter: cc, projectId: pj, debit: 0, credit: cost });
    if (gain > 0) { const gainAcc = assetFindAcc(cfg.disposalGainAcc); if (gainAcc) lines.push({ accountCode: gainAcc.code, accountName: gainAcc.nameAr, description: `ربح بيع أصل: ${a.name}`, costCenter: cc, projectId: pj, debit: 0, credit: gain }); }
    const totalDebit = lines.reduce((s, l) => s + l.debit, 0);
    const totalCredit = lines.reduce((s, l) => s + l.credit, 0);
    const num = typeof generateJrnNumber === 'function' ? generateJrnNumber() : ('JV-ASTD-' + Date.now());
    const jrnRef = await push(R.jrn, {
        number: num, date: a.disposal.date || today(), lines, totalDebit, totalCredit,
        status: 'posted', sourceType: 'asset_disposal', sourceKey: id,
        reference: a.code || '', description: `${a.disposal.type === 'sale' ? 'بيع' : 'تخريد'} أصل ثابت: ${a.name}`,
        createdAt: now, createdBy: userId, postedAt: now, postedBy: userId,
        autoGenerated: true, autoGeneratedFrom: 'asset_disposal'
    });
    await update(ref(db, `ledger/assets/${id}`), { disposalJournalKey: jrnRef.key, disposalJournalNumber: num });
    toast(`✅ تم ترحيل قيد ${a.disposal.type === 'sale' ? 'البيع' : 'التخريد'} (${num})`, 's');
}
window.postAssetDisposalJournal = postAssetDisposalJournal;

// إهلاك الفترة لأصل واحد (الشهر) — يحترم الطريقة وحدود الإهلاك المتبقي
function assetMonthlyDepForPeriod(a, period) {
    // period = 'YYYY-MM'
    if ((a.status || 'active') === 'disposed') {
        // لا إهلاك بعد تاريخ التخريد
        if (a.disposal?.date && a.disposal.date.slice(0, 7) < period) return 0;
    }
    if (!a.purchaseDate || a.purchaseDate.slice(0, 7) > period) return 0; // لم يُقتنَ بعد
    const endOfPeriod = period + '-28';
    const calcEnd = assetCalc(a, endOfPeriod);
    // الإهلاك المتراكم حتى نهاية الشهر السابق
    const [y, m] = period.split('-').map(Number);
    const prev = new Date(y, m - 2, 28);
    const prevStr = `${prev.getFullYear()}-${String(prev.getMonth() + 1).padStart(2, '0')}-28`;
    const calcPrev = assetCalc(a, prevStr);
    const monthDep = Math.max(0, calcEnd.accumDep - calcPrev.accumDep);
    return monthDep;
}
window.assetMonthlyDepForPeriod = assetMonthlyDepForPeriod;

// يبني بيانات جولة الإهلاك لشهر معيّن (قيد + تفاصيل) — مصدر واحد للمعاينة والترحيل
function buildAssetDepRun(period) {
    const assets = window.assets || {};
    const perAsset = {}; let total = 0;
    Object.entries(assets).forEach(([id, a]) => {
        const dep = assetMonthlyDepForPeriod(a, period);
        if (dep > 0.005) { perAsset[id] = dep; total += dep; }
    });
    const lines = [];
    const accumByCode = {}; // كود حساب المجمع → { acc, total }
    const missing = [];
    const detail = []; // صف لكل أصل للمعاينة
    Object.entries(perAsset).forEach(([id, dep]) => {
        const a = assets[id];
        const gl = assetGLAccounts(a);
        const expAcc = assetFindAcc(gl.expenseCode);
        const accAcc = assetFindAcc(gl.accumCode);
        if (!expAcc || !accAcc) { missing.push({ name: a.name || id, gl }); return; }
        const cc = a.projectId || ''; const pj = (window.projects || {})[a.projectId] ? a.projectId : '';
        lines.push({ accountCode: expAcc.code, accountName: expAcc.nameAr, description: `إهلاك ${period}: ${a.name}`, costCenter: cc, projectId: pj, debit: dep, credit: 0 });
        const e = (accumByCode[accAcc.code] = accumByCode[accAcc.code] || { acc: accAcc, total: 0 });
        e.total += dep;
        detail.push({ id, a, dep, expAcc, accAcc, cc });
    });
    Object.values(accumByCode).forEach(e => {
        lines.push({ accountCode: e.acc.code, accountName: e.acc.nameAr, description: `مجمع إهلاك شهر ${period}`, costCenter: '', projectId: '', debit: 0, credit: e.total });
    });
    return { period, perAsset, total, lines, missing, detail, accumByCode };
}
window.buildAssetDepRun = buildAssetDepRun;

// 📉 معاينة احترافية لجولة الإهلاك قبل الترحيل (بدل رسالة المتصفح)
window.openAssetDepRunPreview = function(period) {
    const cfg = assetGLCfg();
    if (!cfg.enabled) { toast('الربط المحاسبي غير مُفعّل — فعّله من إعدادات الأصول', 'wn'); return; }
    period = period || ($('astDepRunPeriod')?.value) || today().slice(0, 7);
    if (!/^\d{4}-\d{2}$/.test(period)) { toast('اختر الشهر بصيغة صحيحة', 'e'); return; }
    if ((window.assetDepRuns || {})[period]) { toast(`تم ترحيل إهلاك ${period} مسبقاً — يمكنك إلغاؤه من سجل الجولات`, 'wn'); return; }
    const data = buildAssetDepRun(period);
    if (data.total <= 0 && !data.missing.length) { toast('لا يوجد إهلاك مستحق لهذا الشهر', 'wn'); return; }
    window._pendingDepRunPeriod = period;

    const methodAr = a => (ASSET_DEP_METHODS[a.depMethod || 'straight'] || ASSET_DEP_METHODS.straight).ar;
    const ccName = cc => cc ? ((window.projects || {})[cc]?.name || cc) : '—';
    const num = typeof generateJrnNumber === 'function' ? generateJrnNumber() : '—';
    const nLines = data.lines.length;

    const detailRows = data.detail.map((d, i) => `<tr>
        <td style="padding:6px 8px;text-align:center;border-bottom:1px solid #f0f0f0">${i + 1}</td>
        <td style="padding:6px 8px;border-bottom:1px solid #f0f0f0"><strong>${esc(d.a.name) || ''}</strong>${d.a.code ? `<span style="color:#aaa;font-size:10px"> ${esc(d.a.code)}</span>` : ''}</td>
        <td style="padding:6px 8px;border-bottom:1px solid #f0f0f0">${esc(methodAr(d.a))}</td>
        <td style="padding:6px 8px;border-bottom:1px solid #f0f0f0">${esc(ccName(d.cc))}</td>
        <td style="padding:6px 8px;border-bottom:1px solid #f0f0f0;font-size:11px">${esc(d.expAcc.code)} → ${esc(d.accAcc.code)}</td>
        <td style="padding:6px 8px;border-bottom:1px solid #f0f0f0;text-align:left;font-weight:700">${fmt(d.dep)}</td>
    </tr>`).join('');

    const jrnRows = data.lines.map(l => `<tr>
        <td style="padding:6px 8px;border-bottom:1px solid #f0f0f0">${esc(l.accountCode)} — ${esc(l.accountName)}${l.costCenter ? `<span style="color:#8e44ad;font-size:10px"> ⟵ ${esc(ccName(l.costCenter))}</span>` : ''}</td>
        <td style="padding:6px 8px;border-bottom:1px solid #f0f0f0;text-align:left;color:#c0392b">${l.debit ? fmt(l.debit) : ''}</td>
        <td style="padding:6px 8px;border-bottom:1px solid #f0f0f0;text-align:left;color:#27ae60">${l.credit ? fmt(l.credit) : ''}</td>
    </tr>`).join('');

    const missingBox = data.missing.length ? `<div style="background:#fdecea;border:1.5px solid #e74c3c;border-radius:10px;padding:10px 14px;margin-bottom:12px">
        <div style="font-weight:800;color:#c0392b;margin-bottom:4px">⚠️ ${data.missing.length} أصل تنقصه حسابات إهلاك/مصروف صحيحة — لن يُدرج في القيد</div>
        <div style="font-size:12px;color:#922b21">${data.missing.slice(0, 6).map(m => esc(m.name)).join('، ')}${data.missing.length > 6 ? '…' : ''}</div>
        <div style="font-size:11px;color:#a04000;margin-top:4px">عدّل الأصل وحدد حساباته من قسم «الربط المحاسبي»، أو راجع شجرة الحسابات.</div>
    </div>` : '';

    $('astDepRunTitle').textContent = `📉 معاينة ترحيل إهلاك شهر ${period}`;
    $('astDepRunPreview').innerHTML = `
        ${missingBox}
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(150px,1fr));gap:10px;margin-bottom:14px">
            <div class="kpi k1"><div class="kpi-ic">🏭</div><div class="kpi-lb">عدد الأصول</div><div class="kpi-vl">${data.detail.length}</div></div>
            <div class="kpi k3" style="--kc:#e67e22"><div class="kpi-ic">📉</div><div class="kpi-lb">إجمالي الإهلاك</div><div class="kpi-vl" style="font-size:15px">${fmt(data.total)}</div><div class="kpi-sb">ريال</div></div>
            <div class="kpi k2" style="--kc:#27ae60"><div class="kpi-ic">⚖️</div><div class="kpi-lb">القيد متوازن</div><div class="kpi-vl" style="font-size:14px">نعم ✓</div><div class="kpi-sb">${nLines} سطر</div></div>
            <div class="kpi k4"><div class="kpi-ic">🧾</div><div class="kpi-lb">رقم القيد المتوقع</div><div class="kpi-vl" style="font-size:13px">${esc(num)}</div><div class="kpi-sb">${period}-28</div></div>
        </div>

        <div style="font-weight:800;color:#2c3e50;font-size:13px;margin:6px 0 6px">📋 تفاصيل إهلاك الأصول</div>
        <div style="overflow:auto;border:1px solid #eee;border-radius:8px;margin-bottom:16px">
            <table style="width:100%;border-collapse:collapse;font-size:12.5px">
                <thead><tr style="background:#f4f6f7"><th style="padding:7px 8px;text-align:center">م</th><th style="padding:7px 8px;text-align:right">الأصل</th><th style="padding:7px 8px;text-align:right">الطريقة</th><th style="padding:7px 8px;text-align:right">مركز التكلفة</th><th style="padding:7px 8px;text-align:right">المصروف → المجمع</th><th style="padding:7px 8px;text-align:left">إهلاك الشهر</th></tr></thead>
                <tbody>${detailRows || `<tr><td colspan="6" style="text-align:center;padding:16px;color:#aaa">لا يوجد</td></tr>`}</tbody>
            </table>
        </div>

        <div style="font-weight:800;color:#2c3e50;font-size:13px;margin:6px 0 6px">🧾 معاينة القيد المحاسبي</div>
        <div style="overflow:auto;border:1px solid #d6e4f0;border-radius:8px">
            <table style="width:100%;border-collapse:collapse;font-size:12.5px">
                <thead><tr style="background:#eaf2fb"><th style="padding:7px 8px;text-align:right">الحساب</th><th style="padding:7px 8px;text-align:left">مدين</th><th style="padding:7px 8px;text-align:left">دائن</th></tr></thead>
                <tbody>${jrnRows}</tbody>
                <tfoot><tr style="font-weight:800;background:#f4f6f7"><td style="padding:7px 8px">الإجمالي</td><td style="padding:7px 8px;text-align:left;color:#c0392b">${fmt(data.total)}</td><td style="padding:7px 8px;text-align:left;color:#27ae60">${fmt(data.total)}</td></tr></tfoot>
            </table>
        </div>`;

    const btn = $('astDepRunConfirmBtn');
    if (btn) { btn.disabled = (data.total <= 0); btn.style.opacity = (data.total <= 0) ? '.5' : '1'; btn.style.cursor = (data.total <= 0) ? 'not-allowed' : 'pointer'; }
    $('ovAssetDepRun').classList.add('show');
};

// تأكيد الترحيل: إنشاء القيد المحاسبي وتسجيل الجولة
window.confirmAssetDepRun = async function() {
    const period = window._pendingDepRunPeriod;
    if (!period) return;
    if ((window.assetDepRuns || {})[period]) { toast(`تم ترحيل إهلاك ${period} مسبقاً`, 'wn'); $('ovAssetDepRun').classList.remove('show'); return; }
    const data = buildAssetDepRun(period);
    if (data.total <= 0) { toast('لا يوجد إهلاك مستحق', 'wn'); return; }
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const now = new Date().toISOString();
    const num = typeof generateJrnNumber === 'function' ? generateJrnNumber() : ('JV-DEP-' + Date.now());
    const jrnRef = await push(R.jrn, {
        number: num, date: period + '-28', lines: data.lines, totalDebit: data.total, totalCredit: data.total,
        status: 'posted', sourceType: 'asset_depreciation', sourceKey: period,
        reference: `DEP-${period}`, description: `إهلاك الأصول الثابتة لشهر ${period}`,
        createdAt: now, createdBy: userId, postedAt: now, postedBy: userId,
        autoGenerated: true, autoGeneratedFrom: 'asset_depreciation'
    });
    await set(ref(db, `ledger/assetDepRuns/${period}`), {
        period, postedAt: now, postedBy: userId, journalKey: jrnRef.key, journalNumber: num,
        total: data.total, lines: data.perAsset
    });
    $('ovAssetDepRun').classList.remove('show');
    window._pendingDepRunPeriod = null;
    toast(`✅ تم ترحيل إهلاك ${period} (${num}) — ${fmt(data.total)} ريال`, 's', 6000);
    if (typeof logAudit === 'function') logAudit('ترحيل إهلاك', 'الأصول', `ترحيل إهلاك شهر ${period} بمبلغ ${fmt(data.total)} (${num})`);
    renderAssets();
};

// توافق خلفي: أي استدعاء قديم يفتح المعاينة
window.runAssetDepreciation = function(period) { return openAssetDepRunPreview(period); };

// إلغاء جولة إهلاك (وحذف قيدها)
window.reverseAssetDepRun = async function(period) {
    const run = (window.assetDepRuns || {})[period]; if (!run) return;
    if (!confirm(`إلغاء ترحيل إهلاك ${period}؟ سيتم حذف القيد المحاسبي المرتبط (${run.journalNumber || ''}).`)) return;
    if (run.journalKey) await remove(ref(db, `ledger/journalEntries/${run.journalKey}`));
    await remove(ref(db, `ledger/assetDepRuns/${period}`));
    toast(`تم إلغاء إهلاك ${period}`, 's');
    renderAssets();
};

// إعدادات الربط المحاسبي — فتح/حفظ
window.openAssetAccSettings = function() {
    const cfg = assetGLCfg();
    const accs = Object.values(window.chartOfAccounts || {}).filter(a => a.nature !== 'header').sort((x, y) => (x.code || '').localeCompare(y.code || ''));
    const opts = (sel) => '<option value="">— اختر —</option>' + accs.map(a => `<option value="${esc(a.code)}" ${sel === a.code ? 'selected' : ''}>${esc(a.code)} — ${esc(a.nameAr)}</option>`).join('');
    $('astCfgEnabled').checked = cfg.enabled;
    $('astCfgAssetEquip').innerHTML = opts(cfg.categoryGL['معدات ثقيلة'] || '1210');
    $('astCfgAssetVeh').innerHTML = opts(cfg.categoryGL['مركبات'] || '1220');
    $('astCfgAssetOffice').innerHTML = opts(cfg.categoryGL['أجهزة مكتبية'] || '1230');
    $('astCfgAssetBuild').innerHTML = opts(cfg.categoryGL['مباني ومنشآت'] || '1240');
    $('astCfgAccumDep').innerHTML = opts(cfg.accumDepAcc);
    $('astCfgDepExp').innerHTML = opts(cfg.depExpenseAcc);
    $('astCfgGain').innerHTML = opts(cfg.disposalGainAcc);
    $('astCfgLoss').innerHTML = opts(cfg.disposalLossAcc);
    $('astCfgClearing').innerHTML = opts(cfg.clearingAcc);
    $('astCfgProceeds').innerHTML = opts(cfg.proceedsAcc);
    $('ovAssetAccCfg').classList.add('show');
};
window.saveAssetAccSettings = async function() {
    const cfg = {
        enabled: $('astCfgEnabled').checked,
        accumDepAcc: $('astCfgAccumDep').value, depExpenseAcc: $('astCfgDepExp').value,
        disposalGainAcc: $('astCfgGain').value, disposalLossAcc: $('astCfgLoss').value,
        clearingAcc: $('astCfgClearing').value, proceedsAcc: $('astCfgProceeds').value,
        categoryGL: {
            'معدات ثقيلة': $('astCfgAssetEquip').value, 'أدوات وعدد': $('astCfgAssetEquip').value, 'أخرى': $('astCfgAssetEquip').value,
            'مركبات': $('astCfgAssetVeh').value, 'أجهزة مكتبية': $('astCfgAssetOffice').value, 'مباني ومنشآت': $('astCfgAssetBuild').value
        }
    };
    await set(R.assetAccCfg, cfg);
    $('ovAssetAccCfg').classList.remove('show');
    toast('تم حفظ إعدادات الربط المحاسبي', 's');
};

// ══════════════════════════════════════════════════════
// [AST4] التنبيهات (ضمان/تأمين/صيانة) + سجل جولات الإهلاك
// ══════════════════════════════════════════════════════
// يرجع قائمة التنبيهات المستحقة خلال nDays يوماً
function collectAssetAlerts(nDays) {
    nDays = nDays || 30;
    const assets = window.assets || {};
    const now = new Date(today() + 'T00:00:00');
    const out = [];
    const daysTo = (d) => Math.round((new Date(d + 'T00:00:00') - now) / 86400000);
    Object.entries(assets).forEach(([id, a]) => {
        if ((a.status || 'active') === 'disposed') return;
        const checks = [
            { f: a.warrantyEnd, lbl: 'انتهاء الضمان', icon: '🛡️' },
            { f: a.insuranceEnd, lbl: 'انتهاء التأمين', icon: '📄' },
            { f: a.nextMaintDate, lbl: 'صيانة دورية مستحقة', icon: '🛠️' }
        ];
        checks.forEach(c => {
            if (!c.f) return;
            const dd = daysTo(c.f);
            if (dd <= nDays) out.push({ id, name: a.name, code: a.code, lbl: c.lbl, icon: c.icon, date: c.f, days: dd });
        });
    });
    return out.sort((x, y) => x.days - y.days);
}
window.collectAssetAlerts = collectAssetAlerts;

window.renderAssetAlerts = function() {
    const box = $('assetsAlerts'); if (!box) return;
    const alerts = collectAssetAlerts(30);
    if (!alerts.length) { box.innerHTML = ''; return; }
    box.innerHTML = `<div class="card" style="padding:12px 16px;border-right:4px solid #e74c3c;background:#fdf3f2">
        <div style="font-weight:800;color:#c0392b;font-size:13px;margin-bottom:8px">🔔 تنبيهات الأصول (${alerts.length}) — خلال 30 يوماً</div>
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:8px">
            ${alerts.map(al => {
                const overdue = al.days < 0;
                const col = overdue ? '#c0392b' : al.days <= 7 ? '#e67e22' : '#7d6608';
                const txt = overdue ? `متأخر ${Math.abs(al.days)} يوم` : al.days === 0 ? 'اليوم' : `خلال ${al.days} يوم`;
                return `<div onclick="openAssetView('${al.id}')" style="cursor:pointer;background:white;border:1px solid #f0d6d3;border-radius:8px;padding:8px 10px;font-size:12px">
                    <div style="font-weight:700;color:#2c3e50">${al.icon} ${esc(al.name) || ''}${al.code ? ` <span style="color:#aaa;font-size:10px">${esc(al.code)}</span>` : ''}</div>
                    <div style="color:#666;margin-top:2px">${al.lbl}: ${esc(al.date)} — <strong style="color:${col}">${txt}</strong></div>
                </div>`;
            }).join('')}
        </div></div>`;
};

window.renderAssetDepRunsLog = function() {
    const box = $('astDepRunsLog'); if (!box) return;
    const runs = Object.values(window.assetDepRuns || {}).sort((a, b) => (b.period || '').localeCompare(a.period || ''));
    if (!runs.length) { box.innerHTML = '<div style="color:#aaa;font-size:12px;padding:6px 0">لم يُرحّل أي إهلاك بعد.</div>'; return; }
    box.innerHTML = `<div style="display:flex;flex-wrap:wrap;gap:8px">
        ${runs.slice(0, 12).map(r => `<div style="background:#fef5e7;border:1px solid #f5d28a;border-radius:8px;padding:6px 10px;font-size:12px;display:flex;align-items:center;gap:8px">
            <span style="font-weight:800;color:#7d5a00">${esc(r.period)}</span>
            <span style="color:#555">${fmt(r.total || 0)} ريال</span>
            <span style="color:#999;font-size:10px">${esc(r.journalNumber || '')}</span>
            <button onclick="reverseAssetDepRun('${esc(r.period)}')" title="إلغاء" style="background:none;border:none;color:#c0392b;cursor:pointer;font-size:12px">✕</button>
        </div>`).join('')}
    </div>`;
};

// ══════════════════════════════════════════════════════
// [AST5] التقارير الاحترافية + ملصقات الباركود
// ══════════════════════════════════════════════════════
window.openAssetReports = function() {
    if ($('astRepPeriod') && !$('astRepPeriod').value) $('astRepPeriod').value = today().slice(0, 7);
    $('ovAssetReports').classList.add('show');
    renderAssetReport();
};

function assetReportHTML() {
    const type = $('astRepType')?.value || 'register';
    const period = $('astRepPeriod')?.value || today().slice(0, 7);
    const assets = Object.entries(window.assets || {});
    const projName = (pid) => pid ? ((window.projects || {})[pid]?.name || '-') : '-';
    const empName = (eid) => eid ? ((window.emp || {})[eid]?.name || '-') : '-';
    const th = 'style="padding:8px 10px;text-align:right;background:#34495e;color:white;font-size:12px;white-space:nowrap"';
    const td = 'style="padding:7px 10px;border-bottom:1px solid #eee;font-size:12px"';

    if (type === 'depreciation') {
        const rows = assets.map(([id, a]) => {
            const dep = assetMonthlyDepForPeriod(a, period);
            const calc = assetCalc(a, period + '-28');
            return { a, dep, accum: calc.accumDep, bv: calc.bookValue };
        }).filter(r => r.dep > 0.005 || (r.a.status !== 'disposed' && (+r.a.cost || 0) > 0));
        const totDep = rows.reduce((s, r) => s + r.dep, 0);
        return `<h3 style="margin:0 0 8px">📉 إهلاك شهر ${period}</h3>
        <table style="width:100%;border-collapse:collapse"><thead><tr>
        <th ${th}>الأصل</th><th ${th}>الفئة</th><th ${th}>الطريقة</th><th ${th}>إهلاك الشهر</th><th ${th}>الإهلاك المتراكم</th><th ${th}>القيمة الدفترية</th></tr></thead><tbody>
        ${rows.map(r => `<tr><td ${td}><strong>${esc(r.a.name) || ''}</strong></td><td ${td}>${esc(r.a.category) || '-'}</td><td ${td}>${(ASSET_DEP_METHODS[r.a.depMethod || 'straight'] || {}).ar || ''}</td><td ${td}>${fmt(r.dep)}</td><td ${td}>${fmt(r.accum)}</td><td ${td}>${fmt(r.bv)}</td></tr>`).join('')}
        </tbody><tfoot><tr style="font-weight:800;background:#f4f6f7"><td ${td} colspan="3">الإجمالي</td><td ${td}>${fmt(totDep)}</td><td ${td} colspan="2"></td></tr></tfoot></table>`;
    }
    if (type === 'disposal') {
        const rows = assets.filter(([, a]) => a.status === 'disposed' && a.disposal).map(([id, a]) => {
            const calc = assetCalc(a, a.disposal.date);
            const gain = (+a.disposal.amount || 0) - calc.bookValue;
            return { a, bv: calc.bookValue, proceeds: +a.disposal.amount || 0, gain };
        });
        const totGain = rows.reduce((s, r) => s + r.gain, 0);
        return `<h3 style="margin:0 0 8px">🗑️ أرباح/خسائر التخريد والبيع</h3>
        <table style="width:100%;border-collapse:collapse"><thead><tr>
        <th ${th}>الأصل</th><th ${th}>التاريخ</th><th ${th}>النوع</th><th ${th}>القيمة الدفترية</th><th ${th}>المتحصلات</th><th ${th}>الربح/الخسارة</th></tr></thead><tbody>
        ${rows.length ? rows.map(r => `<tr><td ${td}><strong>${esc(r.a.name) || ''}</strong></td><td ${td}>${esc(r.a.disposal.date) || '-'}</td><td ${td}>${r.a.disposal.type === 'sale' ? 'بيع' : 'تخريد'}</td><td ${td}>${fmt(r.bv)}</td><td ${td}>${fmt(r.proceeds)}</td><td ${td} style="color:${r.gain >= 0 ? '#27ae60' : '#c0392b'};font-weight:700">${fmt(r.gain)}</td></tr>`).join('') : `<tr><td ${td} colspan="6" style="text-align:center;color:#aaa">لا توجد أصول مخرّدة</td></tr>`}
        </tbody><tfoot><tr style="font-weight:800;background:#f4f6f7"><td ${td} colspan="5">صافي الربح/الخسارة</td><td ${td} style="color:${totGain >= 0 ? '#27ae60' : '#c0392b'}">${fmt(totGain)}</td></tr></tfoot></table>`;
    }
    if (type === 'location') {
        const groups = {};
        assets.forEach(([id, a]) => {
            if (a.status === 'disposed') return;
            const key = a.projectId ? `🏗️ ${projName(a.projectId)}` : (a.employeeId ? `👤 ${empName(a.employeeId)}` : '🏢 غير محدد');
            (groups[key] = groups[key] || []).push(a);
        });
        return `<h3 style="margin:0 0 8px">📍 الأصول حسب الموقع/المسؤول</h3>
        ${Object.entries(groups).map(([g, items]) => {
            const tot = items.reduce((s, a) => s + assetCalc(a, a.status === 'disposed' ? a.disposal?.date : undefined).bookValue, 0);
            return `<div style="margin-bottom:12px"><div style="font-weight:800;color:#2c3e50;background:#eef2f7;padding:6px 10px;border-radius:6px">${esc(g)} — ${items.length} أصل — قيمة دفترية: ${fmt(tot)}</div>
            <table style="width:100%;border-collapse:collapse;margin-top:4px"><tbody>
            ${items.map(a => `<tr><td ${td}>${esc(a.name) || ''}</td><td ${td}>${esc(a.category) || '-'}</td><td ${td}>${fmt(+a.cost || 0)}</td></tr>`).join('')}
            </tbody></table></div>`;
        }).join('') || '<div style="color:#aaa">لا توجد أصول</div>'}`;
    }
    if (type === 'forecast') {
        // توقّع الإهلاك المستقبلي: إسقاط مصروف الإهلاك للسنوات القادمة (للموازنة)
        const startYear = parseInt($('astRepYear')?.value) || new Date().getFullYear();
        const N = 5;
        const years = []; for (let i = 0; i < N; i++) years.push(startYear + i);
        const live = assets.filter(([, a]) => a.status !== 'disposed' && a.status !== 'cwip');
        const yearTotals = {}; const catYear = {};
        years.forEach(y => { yearTotals[y] = 0; });
        live.forEach(([, a]) => {
            const cat = a.category || 'أخرى';
            catYear[cat] = catYear[cat] || {};
            years.forEach(y => {
                const dep = Math.max(0, assetCalc(a, `${y}-12-31`).accumDep - assetCalc(a, `${y - 1}-12-31`).accumDep);
                yearTotals[y] += dep;
                catYear[cat][y] = (catYear[cat][y] || 0) + dep;
            });
        });
        const grand = years.reduce((s, y) => s + yearTotals[y], 0);
        return `<h3 style="margin:0 0 4px">🔮 توقّع الإهلاك المستقبلي — ${startYear} إلى ${startYear + N - 1}</h3>
        <div style="font-size:11px;color:#888;margin-bottom:8px">إسقاط مصروف الإهلاك السنوي للأصول النشطة (يستثني المخرّدة وتحت الإنشاء) — لإعداد الموازنة.</div>
        <table style="width:100%;border-collapse:collapse"><thead><tr>
        <th ${th}>الفئة</th>${years.map(y => `<th ${th}>${y}</th>`).join('')}<th ${th}>الإجمالي</th></tr></thead><tbody>
        ${Object.keys(catYear).length ? Object.entries(catYear).map(([cat, yv]) => {
            const rowTot = years.reduce((s, y) => s + (yv[y] || 0), 0);
            return `<tr><td ${td}><strong>${esc(cat)}</strong></td>${years.map(y => `<td ${td}>${fmt(yv[y] || 0)}</td>`).join('')}<td ${td}><strong>${fmt(rowTot)}</strong></td></tr>`;
        }).join('') : `<tr><td ${td} colspan="${years.length + 2}" style="text-align:center;color:#aaa">لا توجد أصول نشطة</td></tr>`}
        </tbody><tfoot><tr style="font-weight:800;background:#f4f6f7"><td ${td}>الإجمالي</td>${years.map(y => `<td ${td}>${fmt(yearTotals[y])}</td>`).join('')}<td ${td}>${fmt(grand)}</td></tr></tfoot></table>`;
    }
    if (type === 'rollforward') {
        // تقرير حركة الأصول: رصيد أول المدة + الإضافات − الاستبعادات − الإهلاك = رصيد آخر المدة
        const year = parseInt($('astRepYear')?.value) || new Date().getFullYear();
        const start = `${year}-01-01`, end = `${year}-12-31`, prevEnd = `${year - 1}-12-31`;
        const cats = {};
        assets.forEach(([id, a]) => {
            const disposed = a.status === 'disposed' && a.disposal;
            // تجاهل الأصول المستبعدة في سنوات سابقة، والأصول التي لم تُقتنَ بعد نهاية السنة
            if (disposed && a.disposal.date < start) return;
            if ((a.purchaseDate || '9999') > end) return;
            const cost = +a.cost || 0;
            const isAddition = a.purchaseDate >= start && a.purchaseDate <= end;
            const isDisposedInYear = disposed && a.disposal.date >= start && a.disposal.date <= end;
            const openingCost = isAddition ? 0 : cost;
            const addCost = isAddition ? cost : 0;
            const dispCost = isDisposedInYear ? cost : 0;
            const openingAccum = isAddition ? 0 : assetCalc(a, prevEnd).accumDep;
            const effEnd = isDisposedInYear ? a.disposal.date : end;
            const accumEff = assetCalc(a, effEnd).accumDep;
            const depYear = Math.max(0, accumEff - openingAccum);
            const dispAccum = isDisposedInYear ? accumEff : 0;
            const closingCost = openingCost + addCost - dispCost;
            const closingAccum = openingAccum + depYear - dispAccum;
            const c = (cats[a.category || 'أخرى'] = cats[a.category || 'أخرى'] || { openingCost: 0, addCost: 0, dispCost: 0, depYear: 0, closingCost: 0, closingAccum: 0 });
            c.openingCost += openingCost; c.addCost += addCost; c.dispCost += dispCost;
            c.depYear += depYear; c.closingCost += closingCost; c.closingAccum += closingAccum;
        });
        const tot = { openingCost: 0, addCost: 0, dispCost: 0, depYear: 0, closingCost: 0, closingAccum: 0 };
        Object.values(cats).forEach(c => { Object.keys(tot).forEach(k => tot[k] += c[k]); });
        const rowFor = (label, c, rowStyle) => `<tr${rowStyle ? ` style="${rowStyle}"` : ''}><td ${td}><strong>${esc(label)}</strong></td><td ${td}>${fmt(c.openingCost)}</td><td ${td} style="color:#27ae60">${c.addCost ? '+' + fmt(c.addCost) : '-'}</td><td ${td} style="color:#c0392b">${c.dispCost ? '−' + fmt(c.dispCost) : '-'}</td><td ${td}><strong>${fmt(c.closingCost)}</strong></td><td ${td} style="color:#e67e22">${fmt(c.depYear)}</td><td ${td}>${fmt(c.closingAccum)}</td><td ${td}><strong>${fmt(c.closingCost - c.closingAccum)}</strong></td></tr>`;
        return `<h3 style="margin:0 0 4px">🔄 حركة الأصول الثابتة (Roll-forward) — سنة ${year}</h3>
        <div style="font-size:11px;color:#888;margin-bottom:8px">التكلفة الافتتاحية + الإضافات − الاستبعادات = التكلفة الختامية. صافي القيمة الدفترية = التكلفة الختامية − مجمع الإهلاك الختامي.</div>
        <table style="width:100%;border-collapse:collapse"><thead><tr>
        <th ${th}>الفئة</th><th ${th}>ت. افتتاحية</th><th ${th}>+ إضافات</th><th ${th}>− استبعادات</th><th ${th}>ت. ختامية</th><th ${th}>إهلاك السنة</th><th ${th}>مجمع إهلاك ختامي</th><th ${th}>صافي دفتري ختامي</th></tr></thead><tbody>
        ${Object.keys(cats).length ? Object.entries(cats).map(([k, c]) => rowFor(k, c)).join('') : `<tr><td ${td} colspan="8" style="text-align:center;color:#aaa">لا توجد حركة أصول في هذه السنة</td></tr>`}
        </tbody><tfoot>${rowFor('الإجمالي', tot, 'font-weight:800;background:#f4f6f7')}</tfoot></table>`;
    }
    // register (default)
    const live = assets.filter(([, a]) => a.status !== 'disposed');
    const totCost = live.reduce((s, [, a]) => s + (+a.cost || 0), 0);
    const totBV = live.reduce((s, [, a]) => s + assetCalc(a).bookValue, 0);
    return `<h3 style="margin:0 0 8px">📋 سجل الأصول الثابتة (Asset Register)</h3>
    <table style="width:100%;border-collapse:collapse"><thead><tr>
    <th ${th}>الكود</th><th ${th}>الأصل</th><th ${th}>الفئة</th><th ${th}>الموقع/المسؤول</th><th ${th}>تاريخ الشراء</th><th ${th}>التكلفة</th><th ${th}>الإهلاك المتراكم</th><th ${th}>القيمة الدفترية</th></tr></thead><tbody>
    ${assets.map(([id, a]) => { const c = assetCalc(a, a.status === 'disposed' ? a.disposal?.date : undefined); const who = a.projectId ? projName(a.projectId) : (a.employeeId ? empName(a.employeeId) : '-'); return `<tr><td ${td}>${esc(a.code) || '-'}</td><td ${td}><strong>${esc(a.name) || ''}</strong></td><td ${td}>${esc(a.category) || '-'}</td><td ${td}>${esc(who)}</td><td ${td}>${esc(a.purchaseDate) || '-'}</td><td ${td}>${fmt(+a.cost || 0)}</td><td ${td}>${fmt(c.accumDep)}</td><td ${td}>${a.status === 'disposed' ? '<span style="color:#95a5a6">مخرّد</span>' : fmt(c.bookValue)}</td></tr>`; }).join('')}
    </tbody><tfoot><tr style="font-weight:800;background:#f4f6f7"><td ${td} colspan="5">الإجمالي (النشطة)</td><td ${td}>${fmt(totCost)}</td><td ${td}></td><td ${td}>${fmt(totBV)}</td></tr></tfoot></table>`;
}

window.renderAssetReport = function() {
    const body = $('astReportBody'); if (!body) return;
    // إظهار/إخفاء حقول الفترة حسب نوع التقرير
    const type = $('astRepType')?.value || 'register';
    const perEl = $('astRepPeriod'), yrEl = $('astRepYear');
    if (perEl) perEl.style.display = (type === 'depreciation') ? '' : 'none';
    if (yrEl) {
        yrEl.style.display = (type === 'rollforward' || type === 'forecast') ? '' : 'none';
        if ((type === 'rollforward' || type === 'forecast') && !yrEl.value) yrEl.value = new Date().getFullYear();
    }
    body.innerHTML = assetReportHTML();
};
window.printAssetReport = function() {
    const w = window.open('', '_blank');
    w.document.write(`<html dir="rtl"><head><meta charset="utf-8"><title>تقرير الأصول</title>
    <style>body{font-family:Arial,sans-serif;padding:20px}table{width:100%;border-collapse:collapse}td,th{padding:7px 9px}@media print{button{display:none}}</style>
    </head><body>${assetReportHTML()}<br><button onclick="window.print()">🖨️ طباعة</button></body></html>`);
    w.document.close();
};

// 🏷️ ملصق الأصل مع QR/باركود
window.openAssetLabel = function(id) {
    const a = (window.assets || {})[id]; if (!a) return;
    const payload = `ASSET|${id}|${a.code || ''}|${a.name || ''}`;
    const qr = `https://api.qrserver.com/v1/create-qr-code/?size=160x160&data=${encodeURIComponent(payload)}`;
    $('astLabelBody').innerHTML = `
        <div id="astLabelPrintable" style="border:2px solid #2c3e50;border-radius:10px;padding:16px;display:inline-block;min-width:260px">
            <div style="font-weight:800;font-size:16px;color:#2c3e50">${esc(a.name) || ''}</div>
            <div style="font-size:12px;color:#666;margin:2px 0 8px">${esc(a.category) || ''}${a.code ? ' — ' + esc(a.code) : ''}</div>
            <img src="${qr}" alt="QR" style="width:160px;height:160px" crossorigin="anonymous">
            <div style="font-size:11px;color:#888;margin-top:8px">${cfg.companyAr || 'بنيان للمقاولات'} — سجل الأصول الثابتة</div>
        </div>`;
    $('ovAssetLabel').classList.add('show');
};
window.printAssetLabel = function() {
    const el = $('astLabelPrintable'); if (!el) return;
    const w = window.open('', '_blank');
    w.document.write(`<html dir="rtl"><head><meta charset="utf-8"><title>ملصق الأصل</title>
    <style>body{font-family:Arial,sans-serif;text-align:center;padding:30px}</style></head><body>${el.outerHTML}<br><br><button onclick="window.print()">🖨️ طباعة</button></body></html>`);
    w.document.close();
};


// ══════════════════════════════════════════════════════
// [AST6] الأصول تحت الإنشاء (CWIP) — تجميع التكاليف ثم الرسملة
// ══════════════════════════════════════════════════════
function assetCwipEntries(id) {
    return Object.entries((window.assetCwipCosts || {})[id] || {}).sort((a, b) => (b[1].date || '').localeCompare(a[1].date || ''));
}
function assetCwipTotal(id) {
    return assetCwipEntries(id).reduce((s, [, c]) => s + (+c.amount || 0), 0);
}
window.assetCwipTotal = assetCwipTotal;

window.renderAssetCwipPanel = function(id) {
    const box = $('adCwipPanel'); if (!box) return;
    const a = (window.assets || {})[id] || {};
    if ((a.status || 'active') !== 'cwip') { box.innerHTML = ''; return; }
    const entries = assetCwipEntries(id);
    const total = assetCwipTotal(id);
    box.innerHTML = `<div class="card" style="border-right:4px solid #2980b9;background:#f4f9fd">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px">
            <div>
                <div style="font-weight:800;color:#1f6391">🏗️ أصل تحت الإنشاء — إجمالي التكاليف المتراكمة: ${fmt(total)} ريال</div>
                <div style="font-size:11px;color:#888;margin-top:2px">سجّل تكاليف الإنشاء، ثم اضغط «رسملة وتشغيل» لتحويله لأصل نشط يبدأ إهلاكه</div>
            </div>
            <div style="display:flex;gap:8px;flex-wrap:wrap">
                <button onclick="openAssetCwipCost('${id}')" style="background:#2980b9;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px">+ تكلفة إنشاء</button>
                <button onclick="capitalizeAsset('${id}')" style="background:#27ae60;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:800;cursor:pointer;font-size:12px">✅ رسملة وتشغيل الأصل</button>
            </div>
        </div>
        <div style="overflow:auto;margin-top:10px">
            <table style="width:100%;border-collapse:collapse;font-size:12.5px">
                <thead><tr style="background:#eaf2fb"><th style="padding:7px 8px;text-align:center;width:36px">م</th><th style="padding:7px 8px;text-align:right">التاريخ</th><th style="padding:7px 8px;text-align:right">البيان</th><th style="padding:7px 8px;text-align:right">المورد</th><th style="padding:7px 8px;text-align:left">المبلغ</th><th style="padding:7px 8px;text-align:center;width:40px"></th></tr></thead>
                <tbody>${entries.length ? entries.map(([k, c], i) => `<tr>
                    <td style="padding:6px 8px;text-align:center">${i + 1}</td>
                    <td style="padding:6px 8px">${esc(c.date) || ''}</td>
                    <td style="padding:6px 8px">${esc(c.desc) || '-'}</td>
                    <td style="padding:6px 8px">${esc(c.supplier) || '-'}</td>
                    <td style="padding:6px 8px;text-align:left;font-weight:700">${fmt(+c.amount || 0)}</td>
                    <td style="padding:6px 8px;text-align:center"><button onclick="deleteAssetCwipCost('${id}','${k}')" style="background:#e74c3c;color:white;border:none;border-radius:6px;padding:3px 7px;cursor:pointer;font-size:10px">🗑️</button></td>
                </tr>`).join('') : `<tr><td colspan="6" style="text-align:center;padding:16px;color:#aaa">لا توجد تكاليف بعد</td></tr>`}</tbody>
            </table>
        </div>
    </div>`;
};

window.openAssetCwipCost = function(id) {
    $('acwAssetId').value = id;
    $('acwDate').value = today();
    $('acwAmount').value = '';
    $('acwDesc').value = '';
    $('acwSupplier').value = '';
    $('ovAssetCwip').classList.add('show');
};
window.saveAssetCwipCost = async function() {
    const id = $('acwAssetId').value;
    const amount = parseFloat($('acwAmount').value) || 0;
    const desc = $('acwDesc').value.trim();
    if (!$('acwDate').value) { toast('أدخل التاريخ', 'e'); return; }
    if (amount <= 0) { toast('أدخل المبلغ', 'e'); return; }
    if (!desc) { toast('أدخل البيان', 'e'); return; }
    const key = push(R.assetCwip).key;
    await set(ref(db, `ledger/assetCwipCosts/${id}/${key}`), { date: $('acwDate').value, amount, desc, supplier: $('acwSupplier').value.trim() });
    $('ovAssetCwip').classList.remove('show');
    toast('تمت إضافة تكلفة الإنشاء', 's');
};
window.deleteAssetCwipCost = async function(id, key) {
    if (!confirm('حذف هذه التكلفة؟')) return;
    await remove(ref(db, `ledger/assetCwipCosts/${id}/${key}`));
    toast('تم الحذف', 's');
};
window.capitalizeAsset = async function(id) {
    const a = (window.assets || {})[id]; if (!a) return;
    const total = assetCwipTotal(id);
    if (total <= 0) { toast('لا توجد تكاليف لرسملتها', 'e'); return; }
    const inService = prompt(`تاريخ التشغيل (بدء الإهلاك):`, today());
    if (inService === null) return;
    if (!/^\d{4}-\d{2}-\d{2}$/.test(inService)) { toast('تاريخ غير صحيح', 'e'); return; }
    if (!confirm(`رسملة الأصل "${a.name}" بتكلفة ${fmt(total)} ريال وبدء إهلاكه من ${inService}؟`)) return;
    await update(ref(db, `ledger/assets/${id}`), { status: 'active', cost: total, purchaseDate: inService, capitalizedAt: Date.now() });
    toast(`✅ تم تشغيل الأصل بتكلفة ${fmt(total)} ريال`, 's', 6000);
    if (typeof logAudit === 'function') logAudit('رسملة أصل', 'الأصول', `رسملة وتشغيل أصل: ${a.name} بتكلفة ${fmt(total)}`);
    try { await postAssetAcquisitionJournal(id); } catch (e) { console.warn('acquisition journal skipped', e); }
    if ($('pg-assetdetail')?.classList.contains('act') && window._assetActiveId === id) renderAssetDetail();
};

// ══════════════════════════════════════════════════════
// [AST7] إعادة التقييم وانخفاض القيمة (IAS 16 / 36)
// ══════════════════════════════════════════════════════
window.onRevalTypeChange = function() { revalPreviewDiff(); };
window.revalPreviewDiff = function() {
    const id = $('arvAssetId').value; const a = (window.assets || {})[id]; if (!a) return;
    const bv = assetCalc(a).bookValue;
    const nv = parseFloat($('arvNewValue').value);
    const box = $('arvDiffBox'); if (!box) return;
    if (isNaN(nv)) { box.innerHTML = ''; return; }
    const diff = nv - bv;
    const isUp = diff >= 0;
    box.innerHTML = `<div style="padding:8px 10px;border-radius:8px;background:${isUp ? '#eafaf1' : '#fdedec'};color:${isUp ? '#196f3d' : '#922b21'};font-weight:700">
        الفرق: ${isUp ? '➕ زيادة' : '➖ انخفاض'} بمقدار ${fmt(Math.abs(diff))} ريال (من ${fmt(bv)} إلى ${fmt(nv)})</div>`;
};
window.openAssetReval = function(id) {
    const a = (window.assets || {})[id]; if (!a) return;
    if ((a.status || 'active') === 'cwip') { toast('لا يمكن إعادة تقييم أصل تحت الإنشاء', 'e'); return; }
    if (a.status === 'disposed') { toast('هذا الأصل مخرّد', 'e'); return; }
    const calc = assetCalc(a);
    $('arvAssetId').value = id;
    $('arvDate').value = today();
    $('arvType').value = 'revaluation';
    $('arvNewValue').value = '';
    $('arvNotes').value = '';
    $('arvDiffBox').innerHTML = '';
    const lifeMonthsLeft = Math.max(0, Math.round((+a.usefulLifeYears || 1) * 12 - calc.monthsElapsed));
    $('arvBookBox').innerHTML = `القيمة الدفترية الحالية: <strong>${fmt(calc.bookValue)}</strong> ريال — العمر المتبقي: <strong>${lifeMonthsLeft}</strong> شهر`;
    $('arvNewValue').oninput = revalPreviewDiff;
    $('ovAssetReval').classList.add('show');
};
window.saveAssetReval = async function() {
    const id = $('arvAssetId').value; const a = (window.assets || {})[id]; if (!a) return;
    const date = $('arvDate').value;
    const newValue = parseFloat($('arvNewValue').value);
    if (!date) { toast('أدخل التاريخ', 'e'); return; }
    if (isNaN(newValue) || newValue < 0) { toast('أدخل القيمة الجديدة', 'e'); return; }
    const calc = assetCalc(a, date);
    const oldBook = calc.bookValue;
    const adjustment = newValue - oldBook; // موجب = إعادة تقييم بالرفع، سالب = انخفاض
    const type = $('arvType').value;
    if (Math.abs(adjustment) < 0.005) { toast('لا يوجد فرق للتقييم', 'wn'); return; }
    const lifeMonthsRemaining = Math.max(1, Math.round((+a.usefulLifeYears || 1) * 12 - calc.monthsElapsed));
    if (!confirm(`تطبيق ${type === 'impairment' ? 'انخفاض القيمة' : 'إعادة التقييم'} للأصل "${a.name}"؟\nمن ${fmt(oldBook)} إلى ${fmt(newValue)} ريال`)) return;
    // سجل الحدث
    const key = push(R.assetReval).key;
    const rec = { date, type, oldBook, newBook: newValue, adjustment, notes: $('arvNotes').value.trim(), at: Date.now() };
    await set(ref(db, `ledger/assetRevaluations/${id}/${key}`), rec);
    // حدّث أساس الإهلاك الجديد على الأصل
    await update(ref(db, `ledger/assets/${id}`), { revalBasis: { date, bookValue: newValue, lifeMonthsRemaining } });
    $('ovAssetReval').classList.remove('show');
    toast('✅ تم تطبيق التقييم وإعادة احتساب الإهلاك', 's', 5000);
    if (typeof logAudit === 'function') logAudit(type === 'impairment' ? 'انخفاض قيمة' : 'إعادة تقييم', 'الأصول', `${type === 'impairment' ? 'انخفاض قيمة' : 'إعادة تقييم'} أصل: ${a.name} من ${fmt(oldBook)} إلى ${fmt(newValue)}`);
    try { await postAssetRevalJournal(id, key, { ...rec, lifeMonthsRemaining }); } catch (e) { console.warn('reval journal skipped', e); }
    if ($('pg-assetdetail')?.classList.contains('act') && window._assetActiveId === id) renderAssetDetail();
};
async function postAssetRevalJournal(id, key, rec) {
    const cfg = assetGLCfg(); if (!cfg.enabled) return;
    const a = (window.assets || {})[id]; if (!a) return;
    const gl = assetGLAccounts(a);
    const assetAcc = assetFindAcc(gl.assetCode);
    if (!assetAcc) { toast('⚠️ لم يُنشأ قيد التقييم: تحقق من حساب الأصل', 'wn', 7000); return; }
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const now = new Date().toISOString();
    const cc = a.projectId || ''; const pj = (window.projects || {})[a.projectId] ? a.projectId : '';
    const amt = Math.abs(rec.adjustment);
    const lines = [];
    let desc;
    if (rec.adjustment >= 0) {
        // زيادة: مدين الأصل / دائن فائض إعادة التقييم
        const surAcc = assetFindAcc(cfg.revalSurplusAcc);
        lines.push({ accountCode: assetAcc.code, accountName: assetAcc.nameAr, description: `إعادة تقييم (زيادة): ${a.name}`, costCenter: cc, projectId: pj, debit: amt, credit: 0 });
        if (surAcc) lines.push({ accountCode: surAcc.code, accountName: surAcc.nameAr, description: `فائض إعادة تقييم: ${a.name}`, costCenter: cc, projectId: pj, debit: 0, credit: amt });
        else { toast('⚠️ حساب فائض إعادة التقييم (3300) غير موجود — أُنشئ القيد بدون الطرف الدائن', 'wn', 7000); }
        desc = `إعادة تقييم أصل (زيادة): ${a.name}`;
    } else {
        // انخفاض: مدين خسارة انخفاض القيمة / دائن الأصل
        const impAcc = assetFindAcc(cfg.impairmentAcc);
        if (impAcc) lines.push({ accountCode: impAcc.code, accountName: impAcc.nameAr, description: `خسارة انخفاض قيمة: ${a.name}`, costCenter: cc, projectId: pj, debit: amt, credit: 0 });
        lines.push({ accountCode: assetAcc.code, accountName: assetAcc.nameAr, description: `انخفاض قيمة أصل: ${a.name}`, costCenter: cc, projectId: pj, debit: 0, credit: amt });
        desc = `انخفاض قيمة أصل: ${a.name}`;
    }
    const totalDebit = lines.reduce((s, l) => s + l.debit, 0);
    const totalCredit = lines.reduce((s, l) => s + l.credit, 0);
    const num = typeof generateJrnNumber === 'function' ? generateJrnNumber() : ('JV-RVL-' + Date.now());
    const jrnRef = await push(R.jrn, {
        number: num, date: rec.date, lines, totalDebit, totalCredit,
        status: 'posted', sourceType: 'asset_revaluation', sourceKey: id,
        reference: a.code || '', description: desc,
        createdAt: now, createdBy: userId, postedAt: now, postedBy: userId,
        autoGenerated: true, autoGeneratedFrom: 'asset_revaluation'
    });
    await update(ref(db, `ledger/assetRevaluations/${id}/${key}`), { journalKey: jrnRef.key, journalNumber: num });
    toast(`✅ تم ترحيل قيد التقييم (${num})`, 's');
}
window.renderAssetRevalHistory = function(id) {
    const box = $('adRevalBox'); if (!box) return;
    const events = Object.values((window.assetRevaluations || {})[id] || {}).sort((a, b) => (b.date || '').localeCompare(a.date || ''));
    if (!events.length) { box.innerHTML = ''; return; }
    box.innerHTML = `<div class="card" style="border-right:4px solid #16537e">
        <div class="c-tl">♻️ سجل إعادة التقييم وانخفاض القيمة</div>
        <div style="overflow:auto;margin-top:8px"><table style="width:100%;border-collapse:collapse;font-size:12.5px">
            <thead><tr style="background:#eaf0f5"><th style="padding:7px 8px;text-align:right">التاريخ</th><th style="padding:7px 8px;text-align:right">النوع</th><th style="padding:7px 8px;text-align:left">قبل</th><th style="padding:7px 8px;text-align:left">بعد</th><th style="padding:7px 8px;text-align:left">الفرق</th><th style="padding:7px 8px;text-align:right">القيد</th></tr></thead>
            <tbody>${events.map(e => `<tr>
                <td style="padding:6px 8px">${esc(e.date) || ''}</td>
                <td style="padding:6px 8px">${e.type === 'impairment' ? '📉 انخفاض' : '📈 إعادة تقييم'}</td>
                <td style="padding:6px 8px;text-align:left">${fmt(e.oldBook)}</td>
                <td style="padding:6px 8px;text-align:left">${fmt(e.newBook)}</td>
                <td style="padding:6px 8px;text-align:left;color:${(+e.adjustment) >= 0 ? '#27ae60' : '#c0392b'};font-weight:700">${(+e.adjustment) >= 0 ? '+' : ''}${fmt(e.adjustment)}</td>
                <td style="padding:6px 8px;font-size:11px;color:#888">${esc(e.journalNumber || '—')}</td>
            </tr>${e.notes ? `<tr><td colspan="6" style="padding:2px 8px 8px;color:#999;font-size:11px">${esc(e.notes)}</td></tr>` : ''}`).join('')}</tbody>
        </table></div>
    </div>`;
};

// ══════════════════════════════════════════════════════
// [AST8] تقويم الصيانة الوقائية
// ══════════════════════════════════════════════════════
window.openAssetMaintCalendar = function() {
    const assets = window.assets || {};
    const now = new Date(today() + 'T00:00:00');
    const items = [];
    Object.entries(assets).forEach(([id, a]) => {
        if ((a.status || 'active') === 'disposed') return;
        if (!a.nextMaintDate) return;
        const days = Math.round((new Date(a.nextMaintDate + 'T00:00:00') - now) / 86400000);
        items.push({ id, a, date: a.nextMaintDate, days });
    });
    items.sort((x, y) => x.days - y.days);
    const body = $('astMaintCalBody');
    if (!items.length) { body.innerHTML = '<div style="text-align:center;padding:30px;color:#aaa">لا توجد صيانات مجدولة. حدّد «الصيانة الدورية القادمة» أو «تكرار الصيانة» في بيانات الأصل.</div>'; $('ovAssetMaintCal').classList.add('show'); return; }
    // تجميع حسب الشهر
    const groups = {};
    items.forEach(it => { const m = it.date.slice(0, 7); (groups[m] = groups[m] || []).push(it); });
    body.innerHTML = Object.entries(groups).map(([m, list]) => `
        <div style="font-weight:800;color:#16a085;background:#eafaf6;padding:6px 12px;border-radius:6px;margin:10px 0 6px">📅 ${m} — ${list.length} صيانة</div>
        ${list.map(it => {
            const overdue = it.days < 0;
            const col = overdue ? '#c0392b' : it.days <= 7 ? '#e67e22' : '#16a085';
            const txt = overdue ? `متأخرة ${Math.abs(it.days)} يوم` : it.days === 0 ? 'اليوم' : `خلال ${it.days} يوم`;
            const recur = (+it.a.pmEveryMonths || 0) > 0 ? ` 🔁 كل ${it.a.pmEveryMonths} شهر` : '';
            return `<div onclick="$('ovAssetMaintCal').classList.remove('show');openAssetView('${it.id}')" style="cursor:pointer;display:flex;justify-content:space-between;align-items:center;padding:8px 12px;border:1px solid #eee;border-radius:8px;margin-bottom:6px">
                <div><strong>${esc(it.a.name) || ''}</strong>${it.a.code ? ` <span style="color:#aaa;font-size:10px">${esc(it.a.code)}</span>` : ''}<span style="color:#888;font-size:11px">${recur}</span></div>
                <div style="text-align:left"><div style="font-size:12px">${esc(it.date)}</div><div style="font-size:11px;font-weight:700;color:${col}">${txt}</div></div>
            </div>`;
        }).join('')}
    `).join('');
    $('ovAssetMaintCal').classList.add('show');
};

// ══════════════════════════════════════════════════════
// [AST9] الجرد الميداني بالباركود (Stock-take)
// ══════════════════════════════════════════════════════
window.openAssetStockTake = function() {
    window._stockSession = { found: {}, startedAt: Date.now() };
    $('astStockInput').value = '';
    renderStockTake();
    $('ovAssetStock').classList.add('show');
    setTimeout(() => $('astStockInput')?.focus(), 200);
};
window.closeAssetStockTake = function() { $('ovAssetStock').classList.remove('show'); };
window.assetStockScan = function() {
    const inp = $('astStockInput'); const raw = (inp.value || '').trim(); if (!raw) return;
    // يدعم محتوى QR: ASSET|id|code|name  أو كود/اسم مباشر
    let id = null;
    const assets = window.assets || {};
    if (raw.startsWith('ASSET|')) { const pid = raw.split('|')[1]; if (assets[pid]) id = pid; }
    if (!id) { const m = Object.entries(assets).find(([k, a]) => (a.code && a.code.toLowerCase() === raw.toLowerCase()) || k === raw); if (m) id = m[0]; }
    if (!id) { const m = Object.entries(assets).find(([, a]) => (a.name || '').toLowerCase() === raw.toLowerCase()); if (m) id = m[0]; }
    if (!id) { toast('لم يُعثر على أصل بهذا الكود/الاسم', 'e'); inp.select(); return; }
    if ((assets[id].status || 'active') === 'disposed') { toast('هذا الأصل مخرّد', 'wn'); }
    window._stockSession.found[id] = { at: Date.now() };
    toast(`✓ ${assets[id].name}`, 's', 1500);
    inp.value = ''; inp.focus();
    renderStockTake();
};
function renderStockTake() {
    const s = window._stockSession || { found: {} };
    const assets = Object.entries(window.assets || {}).filter(([, a]) => (a.status || 'active') !== 'disposed');
    const total = assets.length;
    const foundIds = Object.keys(s.found);
    const foundCount = foundIds.length;
    const missing = assets.filter(([id]) => !s.found[id]);
    const pct = total ? Math.round(foundCount / total * 100) : 0;
    const prog = $('astStockProgress');
    if (prog) prog.innerHTML = `<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px">
        <div class="kpi k1"><div class="kpi-ic">📦</div><div class="kpi-lb">إجمالي الأصول</div><div class="kpi-vl">${total}</div></div>
        <div class="kpi k2" style="--kc:#27ae60"><div class="kpi-ic">✅</div><div class="kpi-lb">تم جردها</div><div class="kpi-vl">${foundCount}</div><div class="kpi-sb">${pct}%</div></div>
        <div class="kpi k3" style="--kc:#c0392b"><div class="kpi-ic">❓</div><div class="kpi-lb">مفقودة</div><div class="kpi-vl">${missing.length}</div></div>
    </div>`;
    const body = $('astStockBody');
    if (body) body.innerHTML = `
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:6px">
            <div><div style="font-weight:800;color:#27ae60;margin-bottom:6px">✅ تم جردها (${foundCount})</div>
                ${foundCount ? foundIds.map(id => { const a = (window.assets || {})[id] || {}; return `<div style="font-size:12px;padding:5px 8px;border-bottom:1px solid #f0f0f0">${esc(a.name) || ''}${a.code ? ` <span style="color:#aaa;font-size:10px">${esc(a.code)}</span>` : ''}</div>`; }).join('') : '<div style="color:#aaa;font-size:12px">—</div>'}
            </div>
            <div><div style="font-weight:800;color:#c0392b;margin-bottom:6px">❓ لم تُجرد بعد (${missing.length})</div>
                ${missing.length ? missing.map(([id, a]) => `<div style="font-size:12px;padding:5px 8px;border-bottom:1px solid #f0f0f0">${esc(a.name) || ''}${a.code ? ` <span style="color:#aaa;font-size:10px">${esc(a.code)}</span>` : ''}</div>`).join('') : '<div style="color:#27ae60;font-size:12px">كل الأصول مجرودة ✓</div>'}
            </div>
        </div>`;
}
window.finishAssetStockTake = async function() {
    const s = window._stockSession; if (!s) return;
    const foundIds = Object.keys(s.found);
    if (!foundIds.length) { toast('لم تُجرد أي أصل بعد', 'wn'); return; }
    const assets = Object.entries(window.assets || {}).filter(([, a]) => (a.status || 'active') !== 'disposed');
    if (!confirm(`إنهاء الجرد؟\nتم جرد ${foundIds.length} من ${assets.length} أصل.\nسيتم توثيق تاريخ الجرد للأصول الموجودة.`)) return;
    const now = today();
    await Promise.all(foundIds.map(id => update(ref(db, `ledger/assets/${id}`), { lastVerified: now })));
    const key = push(R.assetStock).key;
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    await set(ref(db, `ledger/assetStockTakes/${key}`), {
        date: now, by: userId, status: 'completed',
        totalCount: assets.length, foundCount: foundIds.length,
        found: Object.fromEntries(foundIds.map(id => [id, true]))
    });
    toast(`✅ تم توثيق الجرد — ${foundIds.length} أصل`, 's', 6000);
    closeAssetStockTake();
};


// ══════════════════════════════════════════════════════
// [AST10] الفئات المخصّصة + قائمة الفئات في النماذج
// ══════════════════════════════════════════════════════
const ASSET_BASE_CATEGORIES = ['معدات ثقيلة', 'مركبات', 'أدوات وعدد', 'أجهزة مكتبية', 'مباني ومنشآت', 'أخرى'];
function fillAssetCategorySelect(sel, selected) {
    if (!sel) return;
    const custom = Object.values(window.assetCategories || {}).map(c => c.name).filter(Boolean);
    const all = [...ASSET_BASE_CATEGORIES.filter(c => c !== 'أخرى'), ...custom, 'أخرى'];
    const seen = new Set();
    sel.innerHTML = all.filter(c => !seen.has(c) && seen.add(c)).map(c => `<option value="${esc(c)}" ${selected === c ? 'selected' : ''}>${esc(c)}</option>`).join('');
}
window.fillAssetCategorySelect = fillAssetCategorySelect;

window.openAssetCategories = function() {
    // ملء قائمة حساب الأصل الافتراضي
    const sel = $('acatGl');
    if (sel) {
        const accs = Object.values(window.chartOfAccounts || {}).filter(a => a.nature !== 'header' && a.type === 'asset').sort((x, y) => (x.code || '').localeCompare(y.code || ''));
        sel.innerHTML = '<option value="">— بدون —</option>' + accs.map(a => `<option value="${esc(a.code)}">${esc(a.code)} — ${esc(a.nameAr)}</option>`).join('');
    }
    $('acatName').value = ''; $('acatLife').value = ''; $('acatMethod').value = 'straight';
    renderAssetCatsList();
    $('ovAssetCats').classList.add('show');
};
window.saveAssetCategory = async function() {
    const name = $('acatName').value.trim();
    if (!name) { toast('أدخل اسم الفئة', 'e'); return; }
    if (ASSET_BASE_CATEGORIES.includes(name) || Object.values(window.assetCategories || {}).some(c => c.name === name)) { toast('هذه الفئة موجودة بالفعل', 'e'); return; }
    const key = push(R.assetCats).key;
    await set(ref(db, `ledger/settings/assetCategories/${key}`), {
        name, defaultLifeYears: parseInt($('acatLife').value) || 0,
        defaultMethod: $('acatMethod').value, glAssetAcc: $('acatGl').value || ''
    });
    $('acatName').value = ''; $('acatLife').value = '';
    toast('تمت إضافة الفئة', 's');
};
window.deleteAssetCategory = async function(key) {
    if (!confirm('حذف هذه الفئة؟ (لن تتأثر الأصول المسجلة بها)')) return;
    await remove(ref(db, `ledger/settings/assetCategories/${key}`));
    toast('تم الحذف', 's');
};
window.renderAssetCatsList = function() {
    const box = $('assetCatsList'); if (!box) return;
    const cats = Object.entries(window.assetCategories || {});
    const methodAr = m => (ASSET_DEP_METHODS[m] || ASSET_DEP_METHODS.straight).ar;
    box.innerHTML = `<div style="font-size:12px;font-weight:800;color:#555;margin-bottom:6px">الفئات المخصّصة (${cats.length})</div>
        ${cats.length ? cats.map(([k, c]) => `<div style="display:flex;justify-content:space-between;align-items:center;padding:8px 10px;border:1px solid #eee;border-radius:8px;margin-bottom:6px;font-size:12.5px">
            <div><strong>${esc(c.name)}</strong> <span style="color:#888;font-size:11px">— ${c.defaultLifeYears || '?'} سنة · ${esc(methodAr(c.defaultMethod))}${c.glAssetAcc ? ' · ح/ ' + esc(c.glAssetAcc) : ''}</span></div>
            <button onclick="deleteAssetCategory('${k}')" style="background:#e74c3c;color:white;border:none;border-radius:6px;padding:3px 8px;cursor:pointer;font-size:11px">🗑️</button>
        </div>`).join('') : '<div style="color:#aaa;font-size:12px;padding:10px">لا توجد فئات مخصّصة بعد — الفئات الأساسية متاحة دائماً.</div>'}
        <div style="font-size:11px;color:#888;margin-top:8px">الفئات الأساسية: ${ASSET_BASE_CATEGORIES.join('، ')}</div>`;
};

// ══════════════════════════════════════════════════════
// [AST11] وثائق ومرفقات الأصل (روابط)
// ══════════════════════════════════════════════════════
window.renderAssetDocuments = function(id) {
    const box = $('adDocsBox'); if (!box) return;
    const docs = Object.entries((window.assetDocuments || {})[id] || {}).sort((a, b) => (b[1].addedAt || 0) - (a[1].addedAt || 0));
    box.innerHTML = `<div class="card">
        <div style="display:flex;justify-content:space-between;align-items:center">
            <div class="c-tl" style="margin:0">🗂️ وثائق ومرفقات الأصل (${docs.length})</div>
            <button onclick="openAssetDoc('${id}')" style="background:#2980b9;color:white;border:none;border-radius:8px;padding:7px 12px;font-weight:700;cursor:pointer;font-size:12px">+ إضافة وثيقة</button>
        </div>
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:10px;margin-top:10px">
            ${docs.length ? docs.map(([k, d]) => `<div style="background:#f8fafc;border:1px solid #e6ecf2;border-radius:10px;padding:10px">
                <div style="display:flex;justify-content:space-between;align-items:start;gap:6px">
                    <a href="${esc(d.url)}" target="_blank" rel="noopener" style="font-weight:700;font-size:12.5px;color:#1f6391;text-decoration:none;word-break:break-word">🔗 ${esc(d.name)}</a>
                    <button onclick="deleteAssetDoc('${id}','${k}')" style="background:none;border:none;color:#c0392b;cursor:pointer;font-size:13px">✕</button>
                </div>
                <div style="font-size:10.5px;color:#888;margin-top:3px">${esc(d.category || '')}</div>
            </div>`).join('') : '<div style="color:#aaa;font-size:12px;padding:8px">لا توجد وثائق — أضف فاتورة الشراء أو صور الأصل أو كتيب التشغيل عبر رابط.</div>'}
        </div>
    </div>`;
};
window.openAssetDoc = function(id) {
    $('adocAssetId').value = id;
    $('adocName').value = ''; $('adocCategory').value = 'فاتورة'; $('adocUrl').value = '';
    $('ovAssetDoc').classList.add('show');
};
window.saveAssetDoc = async function() {
    const id = $('adocAssetId').value;
    const name = $('adocName').value.trim();
    const url = $('adocUrl').value.trim();
    if (!name) { toast('أدخل اسم الوثيقة', 'e'); return; }
    if (!/^https?:\/\//i.test(url)) { toast('أدخل رابطاً صحيحاً يبدأ بـ http', 'e'); return; }
    const key = push(R.assetDocs).key;
    await set(ref(db, `ledger/assetDocuments/${id}/${key}`), {
        name, category: $('adocCategory').value, url,
        addedAt: Date.now(), addedBy: (typeof curU !== 'undefined' && curU?.uid) || ''
    });
    $('ovAssetDoc').classList.remove('show');
    toast('تمت إضافة الوثيقة', 's');
};
window.deleteAssetDoc = async function(id, key) {
    if (!confirm('حذف هذه الوثيقة؟')) return;
    await remove(ref(db, `ledger/assetDocuments/${id}/${key}`));
    toast('تم الحذف', 's');
};

// ══════════════════════════════════════════════════════
// [AST12] لوحة تحليلات الأصول
// ══════════════════════════════════════════════════════
window.renderAssetDashboard = function() {
    const assets = Object.entries(window.assets || {});
    const live = assets.filter(([, a]) => a.status !== 'disposed');
    const calc = a => assetCalc(a, a.status === 'disposed' ? a.disposal?.date : undefined);
    const totalCost = live.reduce((s, [, a]) => s + (+a.cost || 0), 0);
    const totalBook = live.reduce((s, [, a]) => s + calc(a).bookValue, 0);
    const totalAccum = live.reduce((s, [, a]) => s + calc(a).accumDep, 0);
    const byStatus = { active: 0, maintenance: 0, cwip: 0, disposed: 0 };
    assets.forEach(([, a]) => { byStatus[a.status || 'active'] = (byStatus[a.status || 'active'] || 0) + 1; });

    const kpi = $('assetDashKpis');
    if (kpi) kpi.innerHTML = `
        <div class="kpi k1"><div class="kpi-ic">🏭</div><div class="kpi-lb">إجمالي الأصول</div><div class="kpi-vl">${assets.length}</div></div>
        <div class="kpi k4"><div class="kpi-ic">💰</div><div class="kpi-lb">إجمالي التكلفة</div><div class="kpi-vl" style="font-size:15px">${fmt(totalCost)}</div></div>
        <div class="kpi k2" style="--kc:#27ae60"><div class="kpi-ic">📒</div><div class="kpi-lb">القيمة الدفترية</div><div class="kpi-vl" style="font-size:15px">${fmt(totalBook)}</div></div>
        <div class="kpi k3" style="--kc:#e67e22"><div class="kpi-ic">📉</div><div class="kpi-lb">الإهلاك المتراكم</div><div class="kpi-vl" style="font-size:15px">${fmt(totalAccum)}</div></div>
        <div class="kpi k1" style="--kc:#2980b9"><div class="kpi-ic">🔧</div><div class="kpi-lb">نشط/صيانة/إنشاء</div><div class="kpi-vl" style="font-size:14px">${byStatus.active}/${byStatus.maintenance}/${byStatus.cwip}</div></div>
    `;

    // حسب الفئة
    const byCat = {};
    live.forEach(([, a]) => { const c = a.category || 'أخرى'; const o = (byCat[c] = byCat[c] || { count: 0, cost: 0, book: 0 }); o.count++; o.cost += (+a.cost || 0); o.book += calc(a).book || calc(a).bookValue; });
    const catEntries = Object.entries(byCat).sort((x, y) => y[1].cost - x[1].cost);
    const maxCatCost = Math.max(1, ...catEntries.map(([, v]) => v.cost));

    // حسب المشروع (الإهلاك المتراكم)
    const byProj = {};
    live.forEach(([, a]) => { const p = a.projectId ? ((window.projects || {})[a.projectId]?.name || a.projectId) : 'غير مخصّص'; byProj[p] = (byProj[p] || 0) + calc(a).accumDep; });
    const projEntries = Object.entries(byProj).sort((x, y) => y[1] - x[1]).slice(0, 8);
    const maxProj = Math.max(1, ...projEntries.map(([, v]) => v));

    // الأعمار
    const buckets = { 'أقل من سنة': 0, '1-3 سنوات': 0, '3-5 سنوات': 0, 'أكثر من 5': 0 };
    live.forEach(([, a]) => { const m = calc(a).monthsElapsed || 0; const y = m / 12; if (y < 1) buckets['أقل من سنة']++; else if (y < 3) buckets['1-3 سنوات']++; else if (y < 5) buckets['3-5 سنوات']++; else buckets['أكثر من 5']++; });
    const maxBucket = Math.max(1, ...Object.values(buckets));

    const bar = (label, val, max, color, valTxt) => `<div style="margin-bottom:10px">
        <div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px"><span style="font-weight:600">${esc(label)}</span><span style="color:${color};font-weight:700">${valTxt}</span></div>
        <div style="height:8px;background:#f0f0f0;border-radius:4px;overflow:hidden"><div style="width:${max ? Math.max(2, val / max * 100) : 0}%;height:100%;background:${color};border-radius:4px"></div></div>
    </div>`;

    const body = $('assetDashBody');
    if (body) body.innerHTML = `<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px">
        <div class="card" style="padding:16px"><div style="font-weight:700;color:#2c3e50;margin-bottom:12px;font-size:14px">🏷️ الأصول حسب الفئة (بالتكلفة)</div>
            ${catEntries.length ? catEntries.map(([c, v]) => bar(`${c} (${v.count})`, v.cost, maxCatCost, '#34495e', fmt(v.cost))).join('') : '<div style="color:#aaa;text-align:center;padding:20px">لا توجد بيانات</div>'}
        </div>
        <div class="card" style="padding:16px"><div style="font-weight:700;color:#2c3e50;margin-bottom:12px;font-size:14px">📒 القيمة الدفترية حسب الفئة</div>
            ${catEntries.length ? catEntries.map(([c, v]) => bar(c, v.book, Math.max(1, ...catEntries.map(([, x]) => x.book)), '#27ae60', fmt(v.book))).join('') : '<div style="color:#aaa;text-align:center;padding:20px">لا توجد بيانات</div>'}
        </div>
        <div class="card" style="padding:16px"><div style="font-weight:700;color:#2c3e50;margin-bottom:12px;font-size:14px">🏗️ الإهلاك المتراكم حسب المشروع</div>
            ${projEntries.length ? projEntries.map(([p, v]) => bar(p, v, maxProj, '#e67e22', fmt(v))).join('') : '<div style="color:#aaa;text-align:center;padding:20px">لا توجد بيانات</div>'}
        </div>
        <div class="card" style="padding:16px"><div style="font-weight:700;color:#2c3e50;margin-bottom:12px;font-size:14px">📅 أعمار الأصول</div>
            ${Object.entries(buckets).map(([b, v]) => bar(b, v, maxBucket, '#8e44ad', `${v} أصل`)).join('')}
        </div>
    </div>`;
};

// ══════════════════════════════════════════════════════
// [AST13] استيراد الأصول من Excel/CSV
// ══════════════════════════════════════════════════════
window.openAssetImport = function() {
    $('assetImportText').value = '';
    $('assetImportPreview').innerHTML = '';
    $('ovAssetImport').classList.add('show');
};
window.downloadAssetImportTemplate = function() {
    const header = 'name,code,category,purchaseDate,cost,usefulLifeYears,salvageValue,depMethod';
    const sample = 'مولد كهرباء,GEN-01,معدات ثقيلة,2025-01-15,80000,10,5000,straight';
    const BOM = '﻿';
    const blob = new Blob([BOM + header + '\n' + sample], { type: 'text/csv;charset=utf-8' });
    const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'قالب_استيراد_الأصول.csv'; a.click();
};
window.loadAssetCsvFile = function(ev) {
    const f = ev.target.files?.[0]; if (!f) return;
    const reader = new FileReader();
    reader.onload = e => { $('assetImportText').value = String(e.target.result || '').replace(/^﻿/, ''); previewAssetImport(); };
    reader.readAsText(f, 'utf-8');
};
function parseAssetCsv(text) {
    const lines = String(text || '').split(/\r?\n/).map(l => l.trim()).filter(Boolean);
    if (!lines.length) return { rows: [], errors: [] };
    // تخطّي صف العناوين إن وُجد
    let start = 0;
    if (/name/i.test(lines[0]) && /cost/i.test(lines[0])) start = 1;
    const rows = []; const errors = [];
    const methods = ['straight', 'declining', 'double', 'sum_of_years', 'units'];
    for (let i = start; i < lines.length; i++) {
        const parts = lines[i].split(',').map(s => s.trim());
        const [name, code, category, purchaseDate, cost, life, salvage, method] = parts;
        if (!name) { errors.push(`السطر ${i + 1}: الاسم مفقود`); continue; }
        if (!/^\d{4}-\d{2}-\d{2}$/.test(purchaseDate || '')) { errors.push(`السطر ${i + 1} (${name}): تاريخ غير صحيح`); continue; }
        if (!(parseFloat(cost) > 0)) { errors.push(`السطر ${i + 1} (${name}): تكلفة غير صحيحة`); continue; }
        rows.push({
            name, code: code || '', category: category || 'أخرى', purchaseDate,
            cost: parseFloat(cost), usefulLifeYears: parseInt(life) || 5,
            salvageValue: parseFloat(salvage) || 0,
            depMethod: methods.includes(method) ? method : 'straight'
        });
    }
    return { rows, errors };
}
window.previewAssetImport = function() {
    const { rows, errors } = parseAssetCsv($('assetImportText').value);
    const box = $('assetImportPreview');
    const btn = $('assetImportBtn');
    if (!$('assetImportText').value.trim()) { box.innerHTML = ''; if (btn) btn.disabled = false; return; }
    box.innerHTML = `<div style="padding:8px 10px;border-radius:8px;background:${rows.length ? '#eafaf1' : '#fdedec'}">
        <strong>${rows.length}</strong> أصل جاهز للاستيراد${errors.length ? ` — <span style="color:#c0392b">${errors.length} سطر به أخطاء</span>` : ''}
        ${errors.length ? `<div style="font-size:11px;color:#c0392b;margin-top:4px">${errors.slice(0, 5).map(esc).join('<br>')}${errors.length > 5 ? '…' : ''}</div>` : ''}
    </div>`;
    if (btn) btn.disabled = !rows.length;
};
window.runAssetImport = async function() {
    const { rows } = parseAssetCsv($('assetImportText').value);
    if (!rows.length) { toast('لا توجد صفوف صالحة', 'e'); return; }
    if (!confirm(`استيراد ${rows.length} أصل؟ سيُنشأ لكل أصل قيد اقتناء تلقائي إن كان الربط المحاسبي مُفعّلاً.`)) return;
    let ok = 0;
    for (const r of rows) {
        const id = push(R.assets).key;
        await set(ref(db, `ledger/assets/${id}`), {
            ...r, projectId: '', employeeId: '', notes: 'مستورد', status: 'active', createdAt: Date.now()
        });
        try { await postAssetAcquisitionJournal(id); } catch (e) { /* تجاهل */ }
        ok++;
    }
    if (typeof logAudit === 'function') logAudit('استيراد', 'الأصول', `استيراد ${ok} أصل دفعة واحدة`);
    $('ovAssetImport').classList.remove('show');
    toast(`✅ تم استيراد ${ok} أصل`, 's', 6000);
};
